require('dotenv').config();
const pool = require('../db');
const fs = require('fs');

const questions = [{"id": 1, "area": "Snowflake Data Cloud Features & Architecture", "question": "Snowflake provides a mechanism for its customers to override its natural clustering algorithms. This method is:", "options": ["A) Micro-partitions", "B) Clustering keys", "C) Key partitions", "D) Clustered partitions"], "chooseN": 1, "correct": ["Clustering keys"], "explanation": "- Clustering keys: Snowflake permite a los usuarios definir 'Clustering keys' para anular manualmente su proceso natural de clustering. Esto ayuda a optimizar el rendimiento de las consultas al agrupar los datos de manera más eficiente en función de las columnas clave especificadas.\n- Micro-partitions: Micro-partitions son unidades de almacenamiento automáticas en Snowflake, pero no son un mecanismo para controlar el clustering.\n- Key partitions: Esta no es una característica de Snowflake; no utiliza key partitions para el clustering.\n- Clustered partitions: Aunque suena similar a clustering keys, no es una funcionalidad reconocida de Snowflake y no permite el control manual del clustering.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-keys.html"}, {"id": 2, "area": "Performance Concepts", "question": "Which of the following are valid Snowflake Virtual Warehouse Scaling Policies? (Choose two.)", "options": ["A) Custom", "B) Economy", "C) Optimized", "D) Standard"], "chooseN": 2, "correct": ["Economy", "Standard"], "explanation": "- Economy, Standard: Las políticas de escalado válidas para los Virtual Warehouses en Snowflake son 'Economy' y 'Standard'. Estas políticas permiten gestionar los recursos computacionales del warehouse, equilibrando el rendimiento y los costos. 'Economy' es una opción que reduce los costos en situaciones de menor demanda, mientras que 'Standard' es la política predeterminada que proporciona un balance general de recursos.\n- Custom: No es una política de escalado válida en Snowflake.\n- Optimized: Aunque suena como una opción válida, no es una política de escalado reconocida en Snowflake.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-multicluster#setting-the-scaling-policy-for-a-multi-cluster-warehouse"}, {"id": 3, "area": "Snowflake Data Cloud Features & Architecture", "question": "True or False: A single database can exist in more than one Snowflake account.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["True"], "explanation": "True. Snowflake supports database replication across multiple accounts, so the same database can exist as a primary database in one account and as secondary replica(s) in other account(s).", "reference": "https://docs.snowflake.com/en/user-guide/databases.html"}, {"id": 4, "area": "Account Access and Security", "question": "Which of the following roles is recommended to be used to create and manage users and roles?", "options": ["A) SYSADMIN", "B) SECURITYADMIN", "C) PUBLIC", "D) ACCOUNTADMIN"], "chooseN": 1, "correct": ["SECURITYADMIN"], "explanation": "The 'SECURITYADMIN' role is recommended for creating and managing users and roles in Snowflake. This role has the necessary privileges for user and role administration.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-overview.html#predefined-roles"}, {"id": 5, "area": "Data Loading and Unloading", "question": "True or False: Bulk unloading of data from Snowflake supports the use of a SELECT statement.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["True"], "explanation": "It is true that bulk unloading of data from Snowflake supports the use of a SELECT statement. This feature allows for the specific selection of data during the unloading process.", "reference": "https://docs.snowflake.com/en/user-guide/data-unload-overview.html"}, {"id": 6, "area": "Data Loading and Unloading", "question": "Select the different types of Internal Stages: (Choose three.)", "options": ["A) Named Stage", "B) User Stage", "C) Table Stage", "D) Schema Stage"], "chooseN": 3, "correct": ["Named Stage", "User Stage", "Table Stage"], "explanation": "The different types of Internal Stages in Snowflake include 'Named Stage', 'User Stage', and 'Table Stage'. These stages are used for data loading and unloading purposes.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-local-file-system-create-stage.html"}, {"id": 7, "area": "Account Access and Security", "question": "True or False: A customer using SnowSQL / native connectors will be unable to also use the Snowflake Web Interface (UI) unless access to the UI is explicitly granted by support.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["False"], "explanation": "This statement is false. Customers using SnowSQL or native connectors can also use the Snowflake Web Interface (UI) without needing explicit permission from support.", "reference": "https://docs.snowflake.com/en/user-guide/snowsql.html"}, {"id": 8, "area": "Data Protection and Data Sharing", "question": "Account-level storage usage can be monitored via:", "options": ["A) The Snowflake Web Interface (UI) in the Databases section", "B) The Snowflake Web Interface (UI) in the Account -> Billing & Usage section", "C) The Information Schema -> ACCOUNT_USAGE_HISTORY View", "D) The Account Usage Schema -> ACCOUNT_USAGE_METRICS View"], "chooseN": 1, "correct": ["The Snowflake Web Interface (UI) in the Account -> Billing & Usage section"], "explanation": "Account-level storage usage in Snowflake can be monitored via the Snowflake Web Interface (UI) in the 'Account -> Billing & Usage' section. This feature provides insights into storage consumption and associated costs.", "reference": "https://docs.snowflake.com/en/user-guide/admin-account-usage.html"}, {"id": 9, "area": "Performance Concepts", "question": "Credit Consumption by the Compute Layer (Virtual Warehouses) is based on: (Choose two.)", "options": ["A) Number of users", "B) Warehouse size", "C) Amount of data processed", "D) The number of clusters for the Warehouse"], "chooseN": 2, "correct": ["Warehouse size", "The number of clusters for the Warehouse"], "explanation": "Credit consumption by the Compute Layer in Snowflake, particularly for Virtual Warehouses, is primarily based on the size of the warehouse and the number of clusers for the Warehouse. The number of users and Amount of data processed are not direct factors in credit consumption. Another consideration is the length of time the compute resources in each cluster runs, although this is not covered in these factors.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-considerations.html#credit-usage-and-warehouse-size"}, {"id": 10, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which statement best describes 'clustering'?", "options": ["A) Clustering represents the way data is grouped together and stored within Snowflake's micro-partitions", "B) The database administrator must define the clustering methodology for each Snowflake table", "C) The clustering key must be included on the COPY command when loading data into Snowflake", "D) Clustering can be disabled within a Snowflake account"], "chooseN": 1, "correct": ["Clustering represents the way data is grouped together and stored within Snowflake's micro-partitions"], "explanation": "Clustering in Snowflake refers to how data is organized within micro-partitions. Snowflake automatically clusters data to optimize query performance, and users can influence this through clustering keys. The other options do not accurately describe Snowflake's clustering feature.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-keys.html"}, {"id": 11, "area": "Data Loading and Unloading", "question": "True or False: The COPY command must specify a File Format in order to execute.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["False"], "explanation": "It is not mandatory to specify a File Format in the COPY command in Snowflake. If no file format is specified, Snowflake uses the default file format settings.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-table.html#optional-parameters"}, {"id": 12, "area": "Account Access and Security", "question": "Which of the following commands sets the Virtual Warehouse for a session?", "options": ["A) COPY WAREHOUSE FROM <<config file>>;", "B) SET WAREHOUSE = <<warehouse name>>;", "C) USE WAREHOUSE <<warehouse name>>;", "D) USE VIRTUAL_WAREHOUSE <<warehouse name>>;"], "chooseN": 1, "correct": ["USE WAREHOUSE <<warehouse name>>;"], "explanation": "The command 'USE WAREHOUSE <<warehouse name>>;' is used to set the Virtual Warehouse for a session in Snowflake. This command specifies which warehouse should be used for executing queries in the current session.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/use-warehouse.html"}, {"id": 13, "area": "Data Protection and Data Sharing", "question": "Which of the following objects can be cloned? (Choose four.)", "options": ["A) Tables", "B) Named File Formats", "C) Schemas", "D) Shares", "E) Databases", "F) Users"], "chooseN": 4, "correct": ["Tables", "Named File Formats", "Schemas", "Databases"], "explanation": "In Snowflake, the objects that can be cloned include tables, schemas, databases, and named file formats. Shares and Users cannot be cloned. Cloning creates a zero-copy snapshot of the object at a specific point in time.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/create-clone"}, {"id": 14, "area": "Account Access and Security", "question": "Which object allows you to limit the number of credits consumed within a Snowflake account?", "options": ["A) Account Usage Tracking", "B) Resource Monitor", "C) Warehouse Limit Parameter", "D) Credit Consumption Tracker"], "chooseN": 1, "correct": ["Resource Monitor"], "explanation": "The 'Resource Monitor' in Snowflake is the tool that allows account administrators to set limits on the number of credits consumed. It is used for monitoring and controlling the usage of compute resources to avoid unexpected expenses.", "reference": "https://docs.snowflake.com/en/user-guide/resource-monitors.html"}, {"id": 15, "area": "Snowflake Data Cloud Features & Architecture", "question": "Snowflake is designed for which type of workloads? (Choose two.)", "options": ["A) OLAP (Analytics) workloads", "B) OLTP (Transactional) workloads", "C) Concurrent workloads", "D) On-premise workloads"], "chooseN": 2, "correct": ["OLAP (Analytics) workloads", "Concurrent workloads"], "explanation": "Snowflake is specifically designed for OLAP (Online Analytical Processing) workloads and concurrent workloads, where it can handle multiple queries simultaneously without performance degradation. It is not optimized for OLTP (Online Transaction Processing) or on-premise workloads.", "reference": "https://docs.snowflake.com/en/user-guide/intro-key-concepts.html"}, {"id": 16, "area": "Snowflake Data Cloud Features & Architecture", "question": "What are the three layers that make up Snowflake's architecture? (Choose three.)", "options": ["A) Compute", "B) Tri-Secret Secure", "C) Storage", "D) Cloud Services"], "chooseN": 3, "correct": ["Compute", "Storage", "Cloud Services"], "explanation": "Snowflake's architecture consists of three layers: the Compute layer, the Storage layer, and the Cloud Services layer. These layers work together to provide a fully managed, scalable, and secure data platform.", "reference": "https://docs.snowflake.com/en/user-guide/intro-key-concepts.html#cloud-data-platform"}, {"id": 17, "area": "Performance Concepts", "question": "Why would a customer size a Virtual Warehouse from an X-Small to a Medium?", "options": ["A) To accommodate more queries", "B) To accommodate more users", "C) To accommodate fluctuations in workload", "D) To accommodate a more complex workload"], "chooseN": 1, "correct": ["To accommodate a more complex workload"], "explanation": "Resizing a Virtual Warehouse (scaling up) from X-Small to Medium increases compute resources per cluster, which improves performance for larger, more complex queries. The Snowflake documentation explicitly states that 'warehouse resizing is not intended for handling concurrency issues; instead, use additional warehouses to handle the workload or use a multi-cluster warehouse.' For accommodating more concurrent queries or users, multi-cluster warehouses (scaling out) are the recommended approach.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-considerations.html#resizing-a-warehouse"}, {"id": 18, "area": "Data Protection and Data Sharing", "question": "True or False: Reader Accounts incur no additional Compute costs to the Data Provider since they are simply reading the shared data without making changes.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["False"], "explanation": "This statement is false. Reader accounts in Snowflake can incur additional compute costs to the data provider. While the reader accounts are used for accessing shared data, the compute resources used by these accounts can lead to additional costs.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-reader-create"}, {"id": 19, "area": "Account Access and Security", "question": "Which of the following connectors allow Multi-Factor Authentication (MFA) authorization when connecting? (Choose all that apply.)", "options": ["A) JDBC", "B) SnowSQL", "C) Snowflake Web Interface (UI)", "D) ODBC", "E) Python"], "chooseN": 5, "correct": ["JDBC", "SnowSQL", "Snowflake Web Interface (UI)", "ODBC", "Python"], "explanation": "Multi-Factor Authentication (MFA) is supported by Snowflake for JDBC, SnowSQL, the Snowflake Web Interface (UI), Python and ODBC connectors. These methods enhance security by requiring multiple forms of verification when accessing Snowflake.", "reference": "https://docs.snowflake.com/en/user-guide/security-mfa"}, {"id": 20, "area": "Snowflake Data Cloud Features & Architecture", "question": "True or False: Snowflake charges a premium for storing semi-structured data.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["False"], "explanation": "Snowflake does not charge a premium for storing semi-structured data such as JSON, XML, or Avro. Snowflake's architecture allows it to handle semi-structured data efficiently without additional costs.", "reference": "https://docs.snowflake.com/en/user-guide/semistructured-intro.html"}, {"id": 21, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which of the following statements describes a benefit of Snowflake's separation of compute and storage? (Choose all that apply.)", "options": ["A) Growth of storage and compute are tightly coupled together", "B) Storage expands without the requirement to add more compute", "C) Compute can be scaled up or down without the requirement to add more storage", "D) Multiple compute clusters can access stored data without contention"], "chooseN": 3, "correct": ["Storage expands without the requirement to add more compute", "Compute can be scaled up or down without the requirement to add more storage", "Multiple compute clusters can access stored data without contention"], "explanation": "One of the key benefits of Snowflake's architecture is the separation of storage and compute. This separation allows for independent scaling of storage and compute resources and enables multiple compute clusters to access the same stored data without contention.", "reference": "https://docs.snowflake.com/en/user-guide/intro-key-concepts.html#cloud-data-architecture"}, {"id": 22, "area": "Data Loading and Unloading", "question": "True or False: It is possible to unload structured data to semi-structured formats such as JSON and Parquet.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["True"], "explanation": "It is true that Snowflake supports unloading structured data into semi-structured formats like JSON and Parquet. This flexibility allows for a wide range of data interchange and integration scenarios.", "reference": "https://docs.snowflake.com/en/user-guide/data-unload-considerations.html"}, {"id": 23, "area": "Snowflake Data Cloud Features & Architecture", "question": "In which layer of its architecture does Snowflake store its metadata statistics?", "options": ["A) Storage Layer", "B) Compute Layer", "C) Database Layer", "D) Cloud Services Layer"], "chooseN": 1, "correct": ["Cloud Services Layer"], "explanation": "Snowflake stores its metadata statistics in the Cloud Services Layer. This layer acts as the brain of the Snowflake architecture, managing all aspects of data storage, optimization, and security.", "reference": "https://docs.snowflake.com/en/user-guide/intro-key-concepts.html#cloud-services-layer"}, {"id": 24, "area": "Data Protection and Data Sharing", "question": "True or False: Data in fail-safe can be deleted by a user or the Snowflake team before it expires.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["False"], "explanation": "It is false that data in fail-safe can be deleted before it expires. Fail-safe is an automatic feature in Snowflake that provides a 7-day window of data protection beyond the Time Travel period and cannot be manually altered.", "reference": "https://docs.snowflake.com/en/user-guide/data-failsafe"}, {"id": 25, "area": "Snowflake Data Cloud Features & Architecture", "question": "True or False: Snowflake's data warehouse was built from the ground up for the cloud in lieu of using an existing database or a platform, like Hadoop, as a base.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["True"], "explanation": "It is true that Snowflake's data warehouse was built from the ground up specifically for the cloud. It was not based on an existing database or platform like Hadoop, but rather designed to leverage the full capabilities and advantages of cloud computing.", "reference": "https://docs.snowflake.com/en/user-guide/intro-key-concepts.html#built-for-the-cloud"}, {"id": 26, "area": "Performance Concepts", "question": "Which of the following statements are true of Virtual Warehouses? (Choose all that apply.)", "options": ["A) Customers can change the size of the Warehouse after creation", "B) A Warehouse can be resized while running", "C) A Warehouse can be configured to suspend after a period of inactivity", "D) A Warehouse can be configured to auto-resume when new queries are submitted"], "chooseN": 4, "correct": ["Customers can change the size of the Warehouse after creation", "A Warehouse can be resized while running", "A Warehouse can be configured to suspend after a period of inactivity", "A Warehouse can be configured to auto-resume when new queries are submitted"], "explanation": "All the provided statements are true of Virtual Warehouses in Snowflake. Customers have the flexibility to change the warehouse size, resize it while it's running, and configure it to suspend after inactivity and auto-resume for new queries, optimizing both performance and cost.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-overview.html"}, {"id": 27, "area": "Data Loading and Unloading", "question": "The PUT command: (Choose two.)", "options": ["A) Automatically creates a File Format object", "B) Automatically uses the last Stage created", "C) Automatically compresses files using Gzip", "D) Automatically encrypts files"], "chooseN": 2, "correct": ["Automatically compresses files using Gzip", "Automatically encrypts files"], "explanation": "The PUT command in Snowflake automatically compresses files using Gzip and encrypts them using AES-256 for secure transfer to Snowflake-managed storage (internal stages). It does not automatically create a File Format object nor use the last stage created unless explicitly specified.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/put.html"}, {"id": 28, "area": "Data Loading and Unloading", "question": "Which type of table corresponds to a single Snowflake session?", "options": ["A) Temporary", "B) Transient", "C) Provisional", "D) Permanent"], "chooseN": 1, "correct": ["Temporary"], "explanation": "Temporary tables in Snowflake are session-specific. They exist only during the life of the session that created them, and they are automatically dropped at the end of the session.", "reference": "https://docs.snowflake.com/en/user-guide/tables-temp-transient.html#temporary-tables"}, {"id": 29, "area": "Data Loading and Unloading", "question": "Which interfaces can be used to create and/or manage Virtual Warehouses?", "options": ["A) The Snowflake Web Interface (UI)", "B) SQL commands", "C) Data integration tools", "D) All of the above"], "chooseN": 1, "correct": ["All of the above"], "explanation": "Virtual Warehouses in Snowflake can be created and managed using the Snowflake Web Interface (UI), SQL commands, and data integration tools. All these interfaces provide mechanisms for warehouse management.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-overview.html"}, {"id": 30, "area": "Data Loading and Unloading", "question": "When a Pipe is recreated using the CREATE OR REPLACE PIPE command:", "options": ["A) The Pipe load history is reset to empty", "B) The REFRESH parameter is set to TRUE", "C) Previously loaded files will be ignored", "D) All of the above"], "chooseN": 1, "correct": ["The Pipe load history is reset to empty"], "explanation": "- The Pipe load history is reset to empty: Al recrear un Pipe usando el comando CREATE OR REPLACE PIPE, el historial de carga del Pipe se reinicia. Esto significa que Snowflake ya no tendrá un registro de los archivos que fueron procesados previamente por ese Pipe.\n- The REFRESH parameter is set to TRUE: El parámetro REFRESH es parte del comando ALTER PIPE, no del comando CREATE OR REPLACE PIPE.\n- Previously loaded files will be ignored: Al recrear un Pipe, los archivos previamente cargados pueden ser procesados de nuevo si se ejecuta el comando ALTER PIPE ... REFRESH.\n- All of the above: No todos los elementos mencionados son correctos; solamente la opción A es la respuesta correcta.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-snowpipe-manage.html#label-snowpipe-management-recreate-pipes, https://docs.snowflake.com/en/sql-reference/sql/alter-pipe.html, https://docs.snowflake.com/en/sql-reference/sql/create-pipe.html"}, {"id": 31, "area": "Data Loading and Unloading", "question": "What is the minimum Snowflake edition that customers planning on storing protected information in Snowflake should consider for regulatory compliance?", "options": ["A) Standard", "B) Premier", "C) Enterprise", "D) Business Critical Edition"], "chooseN": 1, "correct": ["Business Critical Edition"], "explanation": "For customers needing to store protected information in Snowflake, the Business Critical Edition (or higher) is recommended for regulatory compliance. This edition offers enhanced security features such as end-to-end encryption and additional compliance certifications.", "reference": "https://docs.snowflake.com/en/user-guide/intro-editions#security-governance-data-protection"}, {"id": 32, "area": "Data Loading and Unloading", "question": "Select the three types of tables that exist within Snowflake. (Choose three.)", "options": ["A) Temporary", "B) Transient", "C) Provisional", "D) Permanent"], "chooseN": 3, "correct": ["Temporary", "Transient", "Permanent"], "explanation": "Snowflake supports three main types of tables: Temporary, Transient, and Permanent. Each type serves different use cases and has unique characteristics in terms of data persistence and performance.", "reference": "https://docs.snowflake.com/en/user-guide/tables-temp-transient.html"}, {"id": 33, "area": "Data Loading and Unloading", "question": "True or False: Snowpipe via REST API can only reference External Stages as source.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["False"], "explanation": "Snowpipe via REST API in Snowflake can reference both internal and external stages as sources for data loading. This allows for greater flexibility in data integration from various sources.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-snowpipe-rest-apis.html"}, {"id": 34, "area": "Data Loading and Unloading", "question": "True or False: A third-party tool that supports standard JDBC or ODBC but has no Snowflake-specific driver will be unable to connect to Snowflake.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["False"], "explanation": "A third-party tool that supports standard JDBC or ODBC protocols can connect to Snowflake, even if it does not have a Snowflake-specific driver. Snowflake provides JDBC and ODBC drivers to facilitate these connections.", "reference": "https://docs.snowflake.com/developer-guide/jdbc/jdbc"}, {"id": 35, "area": "Data Loading and Unloading", "question": "True or False: It is possible to load data into Snowflake without creating a named File Format object.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["True"], "explanation": "It is true that data can be loaded into Snowflake without creating a named File Format object. Snowflake allows users to specify file format options directly in the COPY INTO command, eliminating the need for a separate File Format object.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-table.html#file-format-options-file_format_options"}, {"id": 36, "area": "Performance Concepts", "question": "True or False: A table in Snowflake can only be queried using the Virtual Warehouse that was used to load the data.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["False"], "explanation": "This statement is false. In Snowflake, a table can be queried using any Virtual Warehouse, not just the one that was used to load the data. This flexibility is a part of Snowflake's architecture, where storage and compute are separate.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses.html"}, {"id": 37, "area": "Data Loading and Unloading", "question": "Which of the following statements are true of Snowflake data loading? (Choose three.)", "options": ["A) VARIANT ‘null’ values are not the same as SQL NULL values", "B) It is recommended to do frequent, single row DMLs", "C) It is recommended to validate the data before loading into the Snowflake target table", "D) It is recommended to use staging tables to manage MERGE statements"], "chooseN": 3, "correct": ["VARIANT ‘null’ values are not the same as SQL NULL values", "It is recommended to validate the data before loading into the Snowflake target table", "It is recommended to use staging tables to manage MERGE statements"], "explanation": "In Snowflake, VARIANT 'null' values are different from SQL NULL values. Validating data before loading and using staging tables for managing MERGE statements are recommended practices for efficient and accurate data loading.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-considerations.html"}, {"id": 38, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which statements are true of micro-partitions? (Choose two.)", "options": ["A) They are approximately 16MB in size", "B) They are stored compressed only if COMPRESS=TRUE on Table", "C) They are immutable", "D) They are only encrypted in the Enterprise edition and above"], "chooseN": 2, "correct": ["They are approximately 16MB in size", "They are immutable"], "explanation": "Micro-partitions in Snowflake are approximately 16MB in size and are immutable, meaning once written, they cannot be modified. This immutability is a key aspect of Snowflake's architecture. Encryption of micro-partitions is standard across all editions of Snowflake, not just the Enterprise edition.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions.html"}, {"id": 39, "area": "Data Loading and Unloading", "question": "True or False: Query ID's are unique across all Snowflake deployments and can be used in communication with Snowflake Support to help troubleshoot issues.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["True"], "explanation": "Query IDs in Snowflake are unique across all deployments. They are a valuable tool for identifying specific queries, especially when communicating with Snowflake Support to troubleshoot issues.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/show-queries.html"}, {"id": 40, "area": "Data Loading and Unloading", "question": "A deterministic query is run at 8am, takes 5 minutes, and the results are cached. Which of the following statements are true? (Choose two.)", "options": ["A) The exact query will ALWAYS return the precomputed result set for the RESULT_CACHE_ACTIVE = time period", "B) The same exact query will return the precomputed results if the underlying data hasn't changed and the results were last accessed within previous 24 hour period", "C) The same exact query will return the precomputed results even if the underlying data has changed as long as the results were last accessed within the previous 24 hour period", "D) The €24ג hourג€ timer on the precomputed results gets renewed every time the exact query is executed"], "chooseN": 1, "correct": ["The same exact query will return the precomputed results if the underlying data hasn't changed and the results were last accessed within previous 24 hour period"], "explanation": "Snowflake caches the results of deterministic queries. These cached results are reused if the same query is executed again, provided the underlying data has not changed and the cache is still active, typically within a 24-hour period. The cache timer is reset every time the query is executed.", "reference": "https://docs.snowflake.com/en/user-guide/querying-persisted-results.html"}, {"id": 41, "area": "Data Loading and Unloading", "question": "Increasing the maximum number of clusters in a Multi-Cluster Warehouse is an example of:", "options": ["A) Scaling rhythmically", "B) Scaling max", "C) Scaling out", "D) Scaling up"], "chooseN": 1, "correct": ["Scaling out"], "explanation": "Increasing the maximum number of clusters in a Multi-Cluster Warehouse in Snowflake is an example of 'scaling out'. This involves adding more clusters to handle larger loads, rather than increasing the resources (like CPU or memory) of existing clusters, which would be 'scaling up'.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-multicluster.html"}, {"id": 42, "area": "Data Loading and Unloading", "question": "Which statement best describes Snowflake tables?", "options": ["A) Snowflake tables are logical representations of underlying physical data", "B) Snowflake tables are the physical instantiation of data loaded into Snowflake", "C) Snowflake tables require that clustering keys be defined to perform optimally", "D) Snowflake tables are owned by a user"], "chooseN": 1, "correct": ["Snowflake tables are logical representations of underlying physical data"], "explanation": "Snowflake tables are best described as logical representations of the underlying physical data. They provide a structured view of the data, but do not represent the physical storage of data in Snowflake, which is handled differently to optimize performance and storage efficiency.", "reference": "https://docs.snowflake.com/en/user-guide/tables-intro.html"}, {"id": 43, "area": "Data Loading and Unloading", "question": "Which item in the Data Warehouse migration process does not apply in Snowflake?", "options": ["A) Migrate Users", "B) Migrate Schemas", "C) Migrate Indexes", "D) Build the Data Pipeline"], "chooseN": 1, "correct": ["Migrate Indexes"], "explanation": "In Snowflake, migrating indexes is not applicable because Snowflake does not use traditional database indexes. Snowflake's architecture automatically optimizes data storage and query performance without the need for manual index maintenance.", "reference": "https://docs.snowflake.com/en/user-guide/intro-key-concepts.html#automatic-clustering"}, {"id": 44, "area": "Snowflake Data Cloud Features & Architecture", "question": "Snowflake provides two mechanisms to reduce data storage costs for short-lived tables. These mechanisms are: (Choose two.)", "options": ["A) Temporary Tables", "B) Transient Tables", "C) Provisional Tables", "D) Permanent Tables"], "chooseN": 2, "correct": ["Temporary Tables", "Transient Tables"], "explanation": "Snowflake offers Temporary and Transient Tables as mechanisms to reduce data storage costs, especially for short-lived data. Temporary Tables are session-specific and deleted after the session ends, while Transient Tables have a longer life but do not support Time Travel and Fail-safe, thus reducing storage costs.", "reference": "https://docs.snowflake.com/en/user-guide/tables-temp-transient.html"}, {"id": 45, "area": "Snowflake Data Cloud Features & Architecture", "question": "What is the maximum compressed row size in Snowflake?", "options": ["A) 8KB", "B) 16MB", "C) 50MB", "D) 4000GB"], "chooseN": 1, "correct": ["16MB"], "explanation": "The maximum compressed row size in Snowflake is 16MB. This size limitation is related to the maximum size of micro-partitions, which are the fundamental storage units in Snowflake's architecture.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions.html"}, {"id": 46, "area": "Account Access and Security", "question": "Which of the following are main sections of the top navigation of the Snowflake Web Interface (UI)? (Choose three.)", "options": ["A) Databases", "B) Tables", "C) Warehouses", "D) Worksheets"], "chooseN": 3, "correct": ["Databases", "Warehouses", "Worksheets"], "explanation": "The main sections of the top navigation of the Snowflake Web Interface (UI) include 'Databases', 'Warehouses', and 'Worksheets'. These sections provide easy access to the respective features and functionalities within the Snowflake environment.", "reference": "https://docs.snowflake.com/en/user-guide/ui-overview.html"}, {"id": 47, "area": "Data Loading and Unloading", "question": "What is the recommended Snowflake data type to store semi-structured data like JSON?", "options": ["A) VARCHAR", "B) RAW", "C) LOB", "D) VARIANT"], "chooseN": 1, "correct": ["VARIANT"], "explanation": "The VARIANT data type in Snowflake is specifically designed to store semi-structured data like JSON, XML, and Avro. It can store values up to a maximum size of 16 MB and is ideal for handling flexible schemas inherent in semi-structured data.", "reference": "https://docs.snowflake.com/en/sql-reference/data-types-semistructured.html#variant"}, {"id": 48, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which of the following statements are true of Snowflake releases: (Choose two.)", "options": ["A) They happen approximately weekly", "B) They roll up and release approximately monthly, but customers can request early release application", "C) During a release, new customer requests/queries/connections transparently move over to the newer version", "D) A customer is assigned a 30 minute window (that can be moved anytime within a week) during which the system will be unavailable and customer is upgraded"], "chooseN": 2, "correct": ["They happen approximately weekly", "During a release, new customer requests/queries/connections transparently move over to the newer version"], "explanation": "Snowflake's releases happen approximately weekly and During a release, new customer requests/queries/connections transparently move over to the newer version.", "reference": "https://docs.snowflake.com/en/user-guide/intro-releases"}, {"id": 49, "area": "Data Protection and Data Sharing", "question": "Which of the following are common use cases for zero-copy cloning? (Choose three.)", "options": ["A) Quick provisioning of Dev and Test/QA environments", "B) Data backups", "C) Point in time snapshots", "D) Performance optimization"], "chooseN": 3, "correct": ["Quick provisioning of Dev and Test/QA environments", "Data backups", "Point in time snapshots"], "explanation": "Zero-copy cloning in Snowflake is commonly used for quickly provisioning development and test/QA environments, creating data backups, and taking point-in-time snapshots. This feature allows for the creation of full data set clones almost instantly without duplicating the physical storage, thereby saving time and resources.", "reference": "https://docs.snowflake.com/en/user-guide/object-clone"}, {"id": 50, "area": "Performance Concepts", "question": "If a Small Warehouse is made up of 2 servers/cluster, how many servers/cluster make up a Medium Warehouse?", "options": ["A) 4", "B) 16", "C) 32"], "chooseN": 1, "correct": ["4"], "explanation": "In Snowflake, the size of a Virtual Warehouse is determined by the number of servers per cluster. A Small Warehouse comprises 2 servers per cluster, and the size doubles with each increment. Therefore, a Medium Warehouse consists of 4 servers per cluster.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-considerations.html#warehouse-size"}, {"id": 51, "area": "Data Protection and Data Sharing", "question": "True or False: When a data share is established between a Data Provider and a Data Consumer, the Data Consumer can extend that data share to other Data Consumers.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["False"], "explanation": "It is false that a Data Consumer can extend a data share to other Data Consumers. In Snowflake, only the Data Provider has the ability to share data. Data Consumers cannot re-share the data they receive with other accounts.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-intro.html"}, {"id": 52, "area": "Account Access and Security", "question": "Which is true of Snowflake network policies? A Snowflake network policy: (Choose two.)", "options": ["A) Is available to all Snowflake Editions", "B) Is only available to customers with Business Critical Edition", "C) Restricts or enables access to specific IP addresses", "D) Is activated using an ‘ALTER DATABASE’ command"], "chooseN": 2, "correct": ["Is available to all Snowflake Editions", "Restricts or enables access to specific IP addresses"], "explanation": "Snowflake network policies, which are available to all Snowflake Editions, allow administrators to restrict or enable access to specific IP addresses, enhancing the security of the Snowflake environment.", "reference": "https://docs.snowflake.com/en/user-guide/network-policies"}, {"id": 53, "area": "Data Protection and Data Sharing", "question": "True or False: Snowflake charges additional fees to Data Providers for each Share they create.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["False"], "explanation": "It is false that Snowflake charges additional fees to Data Providers for each Share they create. Snowflake does not charge for creating and maintaining data shares. However, costs can be incurred for the compute resources used by Data Consumers when accessing shared data.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-provider"}, {"id": 54, "area": "Performance Concepts", "question": "Query results are stored in the Result Cache for how long after they are last accessed, assuming no data changes have occurred?", "options": ["A) 1 Hour", "B) 3 Hours", "C) 12 hours", "D) 24 hours"], "chooseN": 1, "correct": ["24 hours"], "explanation": "In Snowflake, query results are stored in the Result Cache for 24 hours after they are last accessed, assuming no changes have occurred to the underlying data. This feature improves performance by reusing the results of previous queries.", "reference": "https://docs.snowflake.com/en/user-guide/querying.html#query-result-reuse"}, {"id": 55, "area": "Account Access and Security", "question": "A role is created and owns 2 tables. This role is then dropped. Who will now own the two tables?", "options": ["A) The tables are now orphaned", "B) The user that deleted the role", "C) SYSADMIN", "D) The assumed role that dropped the role"], "chooseN": 1, "correct": ["The assumed role that dropped the role"], "explanation": "When a role that owns objects such as tables is dropped in Snowflake, the ownership of these objects is automatically transferred to role that dropped the role. This prevents the objects from becoming orphaned and ensures that they remain manageable within the system.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-privileges.html#dropping-roles"}, {"id": 56, "area": "Data Loading and Unloading", "question": "Which of the following connectors are available in the Downloads section of the Snowflake Web Interface (UI)? (Choose two.)", "options": ["A) SnowSQL", "B) ODBC", "C) R", "D) HIVE"], "chooseN": 2, "correct": ["SnowSQL", "ODBC"], "explanation": "In the Downloads section of the Snowflake Web Interface, users can find connectors for SnowSQL and ODBC. These connectors enable users to connect to and interact with Snowflake using various client applications and programming languages.", "reference": "https://docs.snowflake.com/en/user-guide/snowflake-client-repository"}, {"id": 57, "area": "Data Transformations", "question": "Which of the following DML commands isn't supported by Snowflake?", "options": ["A) UPSERT", "B) MERGE", "C) UPDATE", "D) TRUNCATE TABLE"], "chooseN": 1, "correct": ["UPSERT"], "explanation": "Snowflake does not support the UPSERT DML command. However, it does support MERGE, UPDATE, and TRUNCATE TABLE commands. The MERGE command in Snowflake can be used to achieve similar functionality as UPSERT in other database systems.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/merge.html"}, {"id": 58, "area": "Data Protection and Data Sharing", "question": "Which of the following statements is true of zero-copy cloning?", "options": ["A) Zero-copy clones increase storage costs as cloning the table requires storing its data twice", "B) All zero-copy clone objects inherit the privileges of their original objects", "C) Zero-copy cloning is licensed as an additional Snowflake feature", "D) At the instance/instant a clone is created, all micro-partitions in the original table and the clone are fully shared"], "chooseN": 1, "correct": ["At the instance/instant a clone is created, all micro-partitions in the original table and the clone are fully shared"], "explanation": "Zero-copy cloning in Snowflake creates a clone of a table or database without duplicating the underlying data. At the time of cloning, all micro-partitions are fully shared between the original and the clone, thus not increasing storage costs. This feature leverages Snowflake's unique architecture to provide efficient data duplication.", "reference": "https://docs.snowflake.com/en/user-guide/object-clone"}, {"id": 59, "area": "Account Access and Security", "question": "True or False: When a user creates a role, they are initially assigned ownership of the role and they maintain ownership until it is transferred to another user.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["True"], "explanation": "In Snowflake, when a user creates a role, they are initially assigned the CREATE_ROLE privilege on the role. However, they do not automatically become the owner of the role. The ownership of the role is initially set to the SYSADMIN role.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-overview.html#role-ownership"}, {"id": 60, "area": "Account Access and Security", "question": "The Query History in the Snowflake Web Interface (UI) is kept for approximately:", "options": ["A) 60 minutes", "B) 24 hours", "C) 14 days", "D) 30 days", "E) 1 year"], "chooseN": 1, "correct": ["14 days"], "explanation": "Query History page available under Activity menu on Web UI, holds query data for 14 days. And you can Query_history view available in Account_Usage schema holds query data for 365 days", "reference": "https://docs.snowflake.com/en/user-guide/ui-snowsight-activity#query-history"}, {"id": 61, "area": "Performance Concepts", "question": "To run a Multi-Cluster Warehouse in auto-scale mode, a user would:", "options": ["A) Configure the Maximum Clusters setting to ‘Auto-Scale’", "B) Set the Warehouse type to ‘Auto’", "C) Set the Minimum Clusters and Maximum Clusters settings to the same value", "D) Set the Minimum Clusters and Maximum Clusters settings to the different values"], "chooseN": 1, "correct": ["Set the Minimum Clusters and Maximum Clusters settings to the different values"], "explanation": "To enable auto-scaling in a Multi-Cluster Warehouse, a user must set the Minimum Clusters and Maximum Clusters settings to different values. This configuration allows the warehouse to automatically scale out or in based on the workload.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-multicluster.html"}, {"id": 62, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which of the following terms best describes Snowflake's database architecture?", "options": ["A) Columnar shared nothing", "B) Shared disk", "C) Multi-cluster, shared data", "D) Cloud-native shared memory"], "chooseN": 1, "correct": ["Multi-cluster, shared data"], "explanation": "Snowflake's database architecture is best described as 'Multi-cluster, shared data'. This architecture allows multiple compute clusters to operate on the same set of data, enabling high performance and concurrency.", "reference": "https://docs.snowflake.com/en/user-guide/intro-key-concepts.html#multi-cluster-shared-data-architecture"}, {"id": 63, "area": "Performance Concepts", "question": "Which of the following are options when creating a Virtual Warehouse? (Choose two.)", "options": ["A) Auto-drop", "B) Auto-resize", "C) Auto-resume", "D) Auto-suspend"], "chooseN": 2, "correct": ["Auto-resume", "Auto-suspend"], "explanation": "When creating a Virtual Warehouse in Snowflake, the options include 'Auto-resume' and 'Auto-suspend'. These features allow the warehouse to automatically resume operations when queries are submitted and suspend after a period of inactivity, optimizing resource usage and cost.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-considerations.html#auto-suspend-and-auto-resume"}, {"id": 64, "area": "Performance Concepts", "question": "A Virtual Warehouse's auto-suspend and auto-resume settings apply to:", "options": ["A) The primary cluster in the Virtual Warehouse", "B) The entire Virtual Warehouse", "C) The database the Virtual Warehouse resides in", "D) The queries currently being run by the Virtual Warehouse"], "chooseN": 1, "correct": ["The entire Virtual Warehouse"], "explanation": "Auto-suspend and auto-resume settings in Snowflake apply to the entire Virtual Warehouse, not just the primary cluster or the specific queries. These settings help manage warehouse resources efficiently by automatically suspending the warehouse when it's idle and resuming it when needed.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-tasks.html#auto-suspend-and-auto-resume"}, {"id": 65, "area": "Data Protection and Data Sharing", "question": "Fail-safe is unavailable on which table types? (Choose two.)", "options": ["A) Temporary", "B) Transient", "C) Provisional", "D) Permanent"], "chooseN": 2, "correct": ["Temporary", "Transient"], "explanation": "Fail-safe, a feature in Snowflake for data recovery, is not available for Temporary and Transient tables. Fail-safe provides an additional layer of protection by retaining historical data for a period after the Time Travel retention period ends, but it doesn't apply to these two types of tables.", "reference": "https://docs.snowflake.com/en/user-guide/data-protection-failsafe.html"}, {"id": 66, "area": "Data Protection and Data Sharing", "question": "Which of the following objects is not covered by Time Travel?", "options": ["A) Tables", "B) Schemas", "C) Databases", "D) Stages"], "chooseN": 1, "correct": ["Stages"], "explanation": "In Snowflake, Time Travel allows users to access historical data within a specified retention period, but it does not cover 'Stages'. Time Travel applies to objects like Tables, Schemas, and Databases, enabling point-in-time recovery and data analysis.", "reference": "https://docs.snowflake.com/en/user-guide/data-time-travel.html"}, {"id": 67, "area": "Performance Concepts", "question": "True or False: Micro-partition metadata enables some operations to be completed without requiring Compute.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["True"], "explanation": "True. Micro-partition metadata in Snowflake enables certain operations to be completed without the need for active compute resources. This metadata, which includes information about the data stored in micro-partitions, allows Snowflake to perform operations like pruning during query execution efficiently.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions.html"}, {"id": 68, "area": "Data Loading and Unloading", "question": "Which of the following commands are not blocking operations? (Choose two.)", "options": ["A) UPDATE", "B) INSERT", "C) MERGE", "D) COPY"], "chooseN": 2, "correct": ["INSERT", "COPY"], "explanation": "In Snowflake, both 'INSERT' and 'COPY' commands are typically non-blocking operations. They can be executed concurrently with other transactions, unlike 'UPDATE' and 'MERGE' commands, which may require locks on the tables and can block other operations.", "reference": "https://docs.snowflake.com/en/user-guide/transactions.html"}, {"id": 69, "area": "Data Loading and Unloading", "question": "Which of the following is true of Snowpipe via REST API? (Choose two.)", "options": ["A) You can only use it on Internal Stages", "B) All COPY INTO options are available during pipe creation", "C) Snowflake automatically manages the compute required to execute the Pipe's COPY INTO commands", "D) Snowpipe keeps track of which files it has loaded"], "chooseN": 2, "correct": ["Snowflake automatically manages the compute required to execute the Pipe's COPY INTO commands", "Snowpipe keeps track of which files it has loaded"], "explanation": "When using Snowpipe via REST API, Snowflake automatically manages the compute resources required for the Pipe's COPY INTO commands. Additionally, Snowpipe tracks which files have been loaded, preventing duplicate loading.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-snowpipe-rest-apis.html"}, {"id": 70, "area": "Account Access and Security", "question": "Snowflake recommends, as a minimum, that all users with the following role(s) should be enrolled in Multi-Factor Authentication (MFA):", "options": ["A) SECURITYADMIN, ACCOUNTADMIN, PUBLIC, SYSADMIN", "B) SECURITYADMIN, ACCOUNTADMIN, SYSADMIN", "C) SECURITYADMIN, ACCOUNTADMIN", "D) ACCOUNTADMIN"], "chooseN": 1, "correct": ["ACCOUNTADMIN"], "explanation": "Snowflake strongly recommends requiring MFA for users with the ACCOUNTADMIN role. The documentation states that this recommendation applies particularly to ACCOUNTADMIN users, and can also be expanded to users with the SECURITYADMIN and SYSADMIN roles.", "reference": "https://docs.snowflake.com/en/user-guide/security-mfa.html"}, {"id": 71, "area": "Performance Concepts", "question": "When can a Virtual Warehouse start running queries?", "options": ["A) 12am-5am", "B) Only during administrator defined time slots", "C) When its provisioning is complete", "D) After replication"], "chooseN": 1, "correct": ["When its provisioning is complete"], "explanation": "A Virtual Warehouse in Snowflake can start running queries as soon as its provisioning is complete. Provisioning includes the allocation of compute resources, after which the warehouse is ready to execute queries.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-overview.html"}, {"id": 72, "area": "Account Access and Security", "question": "True or False: Users are able to see the result sets of queries executed by other users that share their same role.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["False"], "explanation": "It is false that users can see the result sets of queries executed by other users sharing the same role. In Snowflake, query results are specific to the user session and are not shared across different users, even if they have the same role.", "reference": "https://docs.snowflake.com/en/user-guide/querying.html#query-results"}, {"id": 73, "area": "Performance Concepts", "question": "True or False: The user has to specify which cluster a query will run on in a multi-cluster Warehouse.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["False"], "explanation": "It is false that users need to specify which cluster a query will run on in a multi-cluster Warehouse. In Snowflake, the system automatically manages query distribution across clusters within a multi-cluster warehouse.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-multicluster.html"}, {"id": 74, "area": "Data Loading and Unloading", "question": "True or False: Pipes can be suspended and resumed.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["True"], "explanation": "True. In Snowflake, Pipes, which are used for continuous data loading, can indeed be suspended and later resumed. This feature allows for better control and management of data loading processes, especially in cases where data loading needs to be temporarily halted for maintenance or cost management.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-snowpipe-manage.html#suspending-and-resuming-pipes"}, {"id": 75, "area": "Data Transformations", "question": "Which of the following languages can be used to implement Snowflake User Defined Functions (UDFs)? (Choose three.)", "options": ["A) Java", "B) Javascript", "C) SQL", "D) Python"], "chooseN": 3, "correct": ["Javascript", "SQL", "Python"], "explanation": "In Snowflake, User Defined Functions (UDFs) can be implemented using Javascript,SQL and Python. These languages provide the necessary flexibility and capability for creating custom functions to handle various data processing and transformation tasks within Snowflake.", "reference": "https://docs.snowflake.com/en/sql-reference/udf-overview.html"}, {"id": 76, "area": "Performance Concepts", "question": "When should you consider disabling auto-suspend for a Virtual Warehouse? (Choose two.)", "options": ["A) When users will be using compute at different times throughout a 24/7 period", "B) When managing a steady workload", "C) When the compute must be available with no delay or lag time", "D) When you do not want to have to manually turn on the Warehouse each time a user needs it"], "chooseN": 2, "correct": ["When managing a steady workload", "When the compute must be available with no delay or lag time"], "explanation": "Disabling auto-suspend for a Virtual Warehouse in Snowflake is advisable when immediate compute availability is critical (i.e., no delay or lag time is acceptable) and when consistent accessibility is needed without the need for manual intervention to resume the warehouse.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-tasks.html#disabling-auto-suspend"}, {"id": 77, "area": "Data Loading and Unloading", "question": "Which of the following are valid approaches to loading data into a Snowflake table? (Choose all that apply.)", "options": ["A) Bulk copy from an External Stage", "B) Continuous load using Snowpipe REST API", "C) The Snowflake Web Interface (UI) data loading wizard", "D) Bulk copy from an Internal Stage"], "chooseN": 4, "correct": ["Bulk copy from an External Stage", "Continuous load using Snowpipe REST API", "The Snowflake Web Interface (UI) data loading wizard", "Bulk copy from an Internal Stage"], "explanation": "Snowflake supports a variety of data loading methods, including bulk copying from both external and internal stages, using the Snowpipe REST API for continuous loading, and utilizing the Snowflake Web Interface's data loading wizard. These methods offer flexibility in handling different data loading requirements.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-overview.html"}, {"id": 78, "area": "Performance Concepts", "question": "If auto-suspend is enabled for a Virtual Warehouse, the Warehouse is automatically suspended when:", "options": ["A) All Snowflakes sessions using the Warehouse are terminated.", "B) The last query using the Warehouse completes.", "C) There are no users logged into Snowflake.", "D) The Warehouse is inactive for a specified period of time."], "chooseN": 1, "correct": ["The Warehouse is inactive for a specified period of time."], "explanation": "If auto-suspend is enabled for a Virtual Warehouse in Snowflake, the warehouse will automatically suspend itself after being inactive for a user-defined period of time. This period is configurable and helps in optimizing resource usage and cost.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-tasks.html#auto-suspend"}, {"id": 79, "area": "Account Access and Security", "question": "True or False: Multi-Factor Authentication (MFA) in Snowflake is only supported in conjunction with Single Sign-On (SSO).", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["False"], "explanation": "It is false that Multi-Factor Authentication (MFA) in Snowflake is only supported in conjunction with Single Sign-On (SSO). MFA in Snowflake can be used independently of SSO, providing an additional layer of security for user authentication.", "reference": "https://docs.snowflake.com/en/user-guide/security-mfa.html"}, {"id": 80, "area": "Performance Concepts", "question": "The number of queries that a Virtual Warehouse can concurrently process is determined by (Choose two.):", "options": ["A) The complexity of each query", "B) The CONCURRENT_QUERY_LIMIT parameter set on the Snowflake account", "C) The size of the data required for each query", "D) The tool that is executing the query"], "chooseN": 2, "correct": ["The complexity of each query", "The size of the data required for each query"], "explanation": "Snowflake documentation states that the number of queries a warehouse can concurrently process is determined by the size and complexity of each query. So the best choices are the complexity option and the size-related option. The docs do not mention CONCURRENT_QUERY_LIMIT; the documented concurrency-related parameter is MAX_CONCURRENCY_LEVEL.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-considerations.html#concurrency-and-warehouses"}, {"id": 81, "area": "Data Loading and Unloading", "question": "Which of the following statements are true of VALIDATION_MODE in Snowflake? (Choose two.)", "options": ["A) The VALIDATION_MODE option is used when creating an Internal Stage", "B) VALIDATION_MODE=RETURN_ALL_ERRORS is a parameter of the COPY command", "C) The VALIDATION_MODE option will validate data to be loaded by the COPY statement while completing the load and will return the rows that could not be loaded without error", "D) The VALIDATION_MODE option will validate data to be loaded by the COPY statement without completing the load and will return possible errors"], "chooseN": 2, "correct": ["VALIDATION_MODE=RETURN_ALL_ERRORS is a parameter of the COPY command", "The VALIDATION_MODE option will validate data to be loaded by the COPY statement without completing the load and will return possible errors"], "explanation": "VALIDATION_MODE is a parameter of the COPY command, which can be set to RETURN_ALL_ERRORS to validate data without completing the load. This option allows Snowflake to return potential errors, helping users to identify and fix data issues before the load is finalized.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-table.html#validation-mode-validation_mode"}, {"id": 82, "area": "Data Transformations", "question": "What privileges are required to create a task?", "options": ["A) The GLOBAL privilege CREATE TASK is required to create a new task.", "B) Tasks are created at the Application level and can only be created by the Account Admin role.", "C) Many Snowflake DDLs are metadata operations only, and CREATE TASK DDL can be executed without virtual warehouse requirement or task specific grants.", "D) The role must have access to the target schema and the CREATE TASK privilege on the schema itself."], "chooseN": 1, "correct": ["The role must have access to the target schema and the CREATE TASK privilege on the schema itself."], "explanation": "To create a task in Snowflake, the role must have access to the target schema and possess the CREATE TASK privilege on that schema. This ensures that only authorized users can set up and manage tasks within a specific schema.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/create-task.html"}, {"id": 83, "area": "Snowflake Data Cloud Features & Architecture", "question": "What are the three things customers want most from their enterprise data warehouse solution? (Choose three.)", "options": ["A) On-premise availability", "B) Simplicity", "C) Open source based", "D) Concurrency", "E) Performance"], "chooseN": 3, "correct": ["Simplicity", "Concurrency", "Performance"], "explanation": "Customers typically seek simplicity, concurrency, and performance in their enterprise data warehouse solutions. They desire an easy-to-use platform that can handle multiple concurrent queries efficiently and deliver high performance.", "reference": "https://docs.snowflake.com/en/user-guide/intro-key-concepts.html"}, {"id": 84, "area": "Performance Concepts", "question": "True or False: Some queries can be answered through the metadata cache and do not require an active Virtual Warehouse.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["True"], "explanation": "True. In Snowflake, certain queries can be answered directly from the metadata cache, which contains information about the structure and contents of the stored data. This means that these queries do not require an active Virtual Warehouse, thus saving on compute resources.", "reference": "https://docs.snowflake.com/en/user-guide/queries-optimization.html"}, {"id": 85, "area": "Performance Concepts", "question": "When scaling out by adding clusters to a multi-cluster warehouse, you are primarily scaling for improved:", "options": ["A) Concurrency", "B) Performance"], "chooseN": 1, "correct": ["Concurrency"], "explanation": "When you scale out a multi-cluster warehouse in Snowflake by adding more clusters, the primary goal is to improve concurrency. This means enabling more queries to be run simultaneously without degradation in performance.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-multicluster.html"}, {"id": 86, "area": "Data Protection and Data Sharing", "question": "What is the minimum Snowflake edition that provides data sharing?", "options": ["A) Standard", "B) Premier", "C) Enterprise", "D) Business Critical Edition"], "chooseN": 1, "correct": ["Standard"], "explanation": "The minimum Snowflake edition that provides data sharing capabilities is the Standard edition. This allows organizations to share data across different Snowflake accounts, facilitating collaboration and data exchange.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-intro.html"}, {"id": 87, "area": "Account Access and Security", "question": "True or False: Each worksheet in the Snowflake Web Interface (UI) can be associated with different roles, databases, schemas, and Virtual Warehouses.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["True"], "explanation": "True. In the Snowflake Web Interface, each worksheet can be associated with different roles, databases, schemas, and Virtual Warehouses. This allows for a flexible and customizable environment where different contexts can be set for different worksheets.", "reference": "https://docs.snowflake.com/en/user-guide/ui-worksheet.html"}, {"id": 88, "area": "Data Loading and Unloading", "question": "True or False: You can query the files in an External Stage directly without having to load the data into a table.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["True"], "explanation": "True. In Snowflake, it is possible to query files stored in an External Stage directly, without the need to first load the data into a table. This feature allows users to perform queries on external data sets efficiently.", "reference": "https://docs.snowflake.com/en/user-guide/querying-stage.html"}, {"id": 89, "area": "Data Transformations", "question": "The FLATTEN function is used to query which type of data in Snowflake?", "options": ["A) Structured data", "B) Semi-structured data", "C) Both of the above", "D) None of the above"], "chooseN": 1, "correct": ["Both of the above"], "explanation": "FLATTEN can be used with semi-structured data and also with structured ARRAY, OBJECT, and MAP values in Snowflake, so \"Both of the above\" is the best answer.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/flatten.html"}, {"id": 90, "area": "Data Loading and Unloading", "question": "True or False: An active warehouse is required to run a COPY INTO statement.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["True"], "explanation": "It is true that an active warehouse is required to run a COPY INTO statement in Snowflake. The COPY INTO command requires compute resources, provided by a running virtual warehouse, to execute.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-table.html"}, {"id": 91, "area": "Account Access and Security", "question": "True or False: AWS Private Link provides a secure connection from the Customer's on-premise data center to the Snowflake.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["True"], "explanation": "It is true that AWS Private Link provides a secure connection from a customer's on-premise data center to Snowflake. This service enables private connectivity between AWS VPCs and Snowflake, enhancing security and data privacy.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-private-link.html"}, {"id": 92, "area": "Snowflake Data Cloud Features & Architecture", "question": "True or False: Snowflake's Global Services Layer gathers and maintains statistics on all columns in all micro-partitions.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["True"], "explanation": "It is true that Snowflake's Global Services Layer gathers and maintains statistics on all columns in all micro-partitions. This layer is responsible for metadata management and optimization, among other functions.", "reference": "https://docs.snowflake.com/en/user-guide/admin-security-privatelink"}, {"id": 93, "area": "Performance Concepts", "question": "True or False: It is best practice to define a clustering key on every table.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["False"], "explanation": "It is false that defining a clustering key on every table is a best practice in Snowflake. While clustering keys can improve performance on large tables, they are not always necessary and can be counterproductive on smaller tables.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-keys.html"}, {"id": 94, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which of the following statements is true of Snowflake?", "options": ["A) It was built specifically for the cloud", "B) It was built as an on-premises solution and then ported to the cloud", "C) It was designed as a hybrid database to allow customers to store data either on premises or in the cloud", "D) It was built for Hadoop architecture", "E) It's based on an Oracle Architecture"], "chooseN": 1, "correct": ["It was built specifically for the cloud"], "explanation": "Snowflake was built specifically for the cloud, leveraging cloud architecture to provide scalability, flexibility, and cost-effective data storage and analytics. It was not an on-premises solution ported to the cloud, nor was it designed for Hadoop or based on Oracle architecture.", "reference": "https://docs.snowflake.com/en/user-guide/intro-key-concepts"}, {"id": 95, "area": "Snowflake Data Cloud Features & Architecture", "question": "What is the minimum Snowflake edition that provides multi-cluster warehouses and up to 90 days of Time Travel?", "options": ["A) Standard", "B) Premier", "C) Enterprise", "D) Business Critical Edition"], "chooseN": 1, "correct": ["Enterprise"], "explanation": "The Enterprise edition of Snowflake provides the capabilities of multi-cluster warehouses and up to 90 days of Time Travel. This edition offers advanced features needed for larger-scale, more complex, and mission-critical operations.", "reference": "https://docs.snowflake.com/en/user-guide/intro-editions"}, {"id": 96, "area": "Data Protection and Data Sharing", "question": "How many shares can be consumed by a single Data Consumer?", "options": ["A) 1", "B) 10", "C) 100, but can be increased by contacting support", "D) Unlimited"], "chooseN": 1, "correct": ["Unlimited"], "explanation": "A single Data Consumer in Snowflake can consume an unlimited number of shares. This flexibility allows organizations to access and analyze data from multiple sources without restrictions on the number of shares they can use.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-intro.html"}, {"id": 97, "area": "Snowflake Data Cloud Features & Architecture", "question": "What is the lowest Snowflake edition that offers Time Travel up to 90 days?", "options": ["A) Standard Edition", "B) Premier Edition", "C) Enterprise Edition", "D) Business Critical Edition"], "chooseN": 1, "correct": ["Enterprise Edition"], "explanation": "The Enterprise Edition of Snowflake is the lowest edition that offers the Time Travel feature for up to 90 days. This feature allows users to access historical data over an extended period, providing significant flexibility for data recovery and analysis.", "reference": "https://docs.snowflake.com/en/user-guide/intro-editions"}, {"id": 98, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which of the following statements are true about Schemas in Snowflake? (Choose two.)", "options": ["A) A Schema may contain one or more Databases", "B) A Database may contain one or more Schemas", "C) A Schema is a logical grouping of Database Objects", "D) Each Schema is contained within a Warehouse"], "chooseN": 2, "correct": ["A Database may contain one or more Schemas", "A Schema is a logical grouping of Database Objects"], "explanation": "In Snowflake, a Schema is a logical grouping of database objects like tables, views, and functions, and each database can contain one or more schemas. However, a schema does not contain databases, nor is it contained within a warehouse.", "reference": "https://docs.snowflake.com/en/sql-reference/ddl-database"}, {"id": 99, "area": "Performance Concepts", "question": "True or False: You can resize a Virtual Warehouse while queries are running.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["True"], "explanation": "It is true that you can resize a Virtual Warehouse in Snowflake while queries are running. Snowflake allows on-the-fly resizing of warehouses to scale compute resources up or down without interrupting running queries.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-tasks.html#resizing-a-warehouse"}, {"id": 100, "area": "Data Protection and Data Sharing", "question": "What is the most granular object that the Time Travel retention period can be defined on?", "options": ["A) Account", "B) Database", "C) Schema", "D) Table"], "chooseN": 1, "correct": ["Table"], "explanation": "The most granular object that the Time Travel retention period can be defined on in Snowflake is a 'Table'. Time Travel settings can be specified at the table level, allowing for fine-grained control over data retention.", "reference": "https://docs.snowflake.com/en/user-guide/data-time-travel.html#table-considerations"}, {"id": 101, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which of the following statements is true of Snowflake micro-partitioning?", "options": ["A) Micro-partitioning has been known to introduce data skew", "B) Micro-partitioning: requires a partitioning schema to be defined up front", "C) Micro-partitioning is transparently completed using the ordering that occurs when the data is inserted/loaded", "D) Micro-partitioning can be disabled within a Snowflake account"], "chooseN": 1, "correct": ["Micro-partitioning is transparently completed using the ordering that occurs when the data is inserted/loaded"], "explanation": "Snowflake's micro-partitioning is transparently completed based on the order in which data is inserted or loaded. This automatic process optimizes data storage and query performance without requiring a predefined partitioning schema.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions.html"}, {"id": 102, "area": "Account Access and Security", "question": "True or False: Snowflake bills for a minimum of five minutes each time a Virtual Warehouse is started.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["False"], "explanation": "It is False Because Snowflake utilizes per-second billing (with a 60-second minimum each time the warehouse starts), warehouses are billed only for the credits they actually consume when they are actively working.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-considerations.html#billing-and-usage"}, {"id": 103, "area": "Performance Concepts", "question": "When scaling up Virtual Warehouses by increasing Virtual Warehouse t-shirt size, you are primarily scaling for improved:", "options": ["A) Concurrency", "B) Performance"], "chooseN": 1, "correct": ["Performance"], "explanation": "When scaling up Virtual Warehouses by increasing their size (e.g., from X-Small to Large), the primary goal is to improve performance. Larger warehouse sizes offer more compute resources, leading to faster query execution.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-considerations.html#scaling-warehouses"}, {"id": 104, "area": "Performance Concepts", "question": "As a best practice, clustering keys should only be defined on tables of which minimum size?", "options": ["A) Multi-Kilobyte (KB) Range", "B) Multi-Megabyte (MB) Range", "C) Multi-Gigabyte (GB) Range", "D) Multi-Terabyte (TB) Range"], "chooseN": 1, "correct": ["Multi-Terabyte (TB) Range"], "explanation": "As a best practice in Snowflake, clustering keys should generally be defined on tables that are in the multi-terabyte (TB) range. For smaller tables, the benefits of clustering may not be significant enough to justify the overhead.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-keys.html"}, {"id": 105, "area": "Data Loading and Unloading", "question": "How are Snowpipe charges calculated?", "options": ["A) Per-second/per Warehouse size", "B) Per-second/per-core granularity", "C) Number of Pipes in account", "D) Total storage bucket size"], "chooseN": 1, "correct": ["Per-second/per-core granularity"], "explanation": "Snowpipe charges in Snowflake are calculated based on a per-second, per-core granularity. This means that charges are incurred based on the amount of compute resources utilized and the time those resources are used.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-snowpipe-pricing.html"}, {"id": 106, "area": "Data Loading and Unloading", "question": "True or False: A Snowflake account is charged for data stored in both Internal and External Stages.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["False"], "explanation": "False. In Snowflake, while there are storage charges for data stored in Internal Stages, there are no storage charges for data in External Stages. External Stages refer to cloud storage locations outside of Snowflake, like Amazon S3, Google Cloud Storage, or Azure Blob Storage.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-external-stage.html"}, {"id": 107, "area": "Data Loading and Unloading", "question": "True or False: When active, a Pipe requires a dedicated Virtual Warehouse to execute.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["False"], "explanation": "False. A Snowpipe in Snowflake does not require a dedicated Virtual Warehouse to execute. Snowpipe automatically provisions and manages the compute resources required for loading data, separate from Virtual Warehouses.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-snowpipe-intro.html"}, {"id": 108, "area": "Account Access and Security", "question": "True or False: Snowflake supports federated authentication in all editions.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["True"], "explanation": "True. Snowflake supports federated authentication across all of its editions. Federated authentication allows users to leverage their existing identity provider to authenticate with Snowflake, enhancing security and simplifying user management.", "reference": "https://docs.snowflake.com/en/user-guide/admin-security-fed-auth-use.html"}, {"id": 109, "area": "Account Access and Security", "question": "True or False: When a new Snowflake object is created, it is automatically owned by the user who created it.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["False"], "explanation": "False. When a new Snowflake object is created, it is automatically owned by the active primary ROLE of the session, not by the user. The OWNERSHIP privilege is granted to the role used to create the object. Users interact with the object through that role. This is a core principle of Snowflake's Discretionary Access Control (DAC) model.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-overview.html#object-ownership"}, {"id": 110, "area": "Performance Concepts", "question": "True or False: A Virtual Warehouse consumes Snowflake credits even when inactive.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["False"], "explanation": "It is false that a Virtual Warehouse consumes Snowflake credits when inactive. Snowflake credits are only consumed when the warehouse is active and performing queries or other compute operations.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-considerations.html#billing-and-usage"}, {"id": 111, "area": "Data Loading and Unloading", "question": "True or False: During data unloading, only JSON and CSV files can be compressed.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["False"], "explanation": "It is false that only JSON and CSV files can be compressed during data unloading in Snowflake. Snowflake supports compression for various file formats, not limited to JSON and CSV, when unloading data.", "reference": "https://docs.snowflake.com/en/user-guide/data-unload-considerations.html#compression"}, {"id": 112, "area": "Performance Concepts", "question": "Which of the following are options when creating a Virtual Warehouse? (Choose two.)", "options": ["A) Auto-suspend", "B) Auto-resume", "C) Local SSD size", "D) User count"], "chooseN": 2, "correct": ["Auto-suspend", "Auto-resume"], "explanation": "When creating a Virtual Warehouse in Snowflake, 'Auto-suspend' and 'Auto-resume' are two key options. They allow the warehouse to automatically suspend after a period of inactivity and resume when queries are submitted, optimizing resource usage and cost.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-considerations.html#auto-suspend-and-auto-resume"}, {"id": 113, "area": "Data Loading and Unloading", "question": "Which formats are supported for unloading data from Snowflake? (Choose two.)", "options": ["A) Delimited (CSV, TSV, etc.)", "B) Avro", "C) JSON", "D) ORC"], "chooseN": 2, "correct": ["Delimited (CSV, TSV, etc.)", "JSON"], "explanation": "Snowflake supports unloading data in Delimited formats (like CSV, TSV) for structured data and JSON for semi-structured data.", "reference": "https://docs.snowflake.com/en/user-guide/data-unload-prepare"}, {"id": 114, "area": "Data Protection and Data Sharing", "question": "True or False: Data Providers can share data with only the Data Consumer.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["False"], "explanation": "False. In Snowflake, Data Providers can share data with Data Consumers and Data Readers. Data readers are users who have Reader accounts without requiring to become a Snowflake customer.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-intro.html"}, {"id": 115, "area": "Data Protection and Data Sharing", "question": "The fail-safe retention period is how many days?", "options": ["A) 1 day", "B) 7 days", "C) 45 days", "D) 90 days"], "chooseN": 1, "correct": ["7 days"], "explanation": "The fail-safe retention period in Snowflake is 7 days. Fail-safe is an additional layer of data protection that provides a 7-day window to recover data after the Time Travel period has expired.", "reference": "https://docs.snowflake.com/en/user-guide/data-protection-failsafe.html"}, {"id": 116, "area": "Data Loading and Unloading", "question": "True or False: Once created, a micro-partition will never be changed.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["True"], "explanation": "True. In Snowflake, all data is stored in micro-partitions, which are contiguous units of storage that are immutable.", "reference": "https://interworks.com/blog/kbridges/2019/03/12/time-travel-with-snowflake/"}, {"id": 117, "area": "Snowflake Data Cloud Features & Architecture", "question": "What services does Snowflake automatically provide for customers that they may have been responsible for with their on-premise system? (Choose all that apply.)", "options": ["A) Installing and configuring hardware", "B) Patching software", "C) Physical security", "D) Maintaining metadata and statistics"], "chooseN": 2, "correct": ["Patching software", "Maintaining metadata and statistics"], "explanation": "In a cloud-based system like Snowflake, services such as patching software, and maintaining metadata and statistics are automatically handled by the platform. Customers do not need to install and configure hardware as it is a cloud service.", "reference": "https://docs.snowflake.com/en/user-guide/intro-key-concepts"}, {"id": 118, "area": "Data Loading and Unloading", "question": "Which of the following statements would be used to export/unload data from Snowflake?", "options": ["A) COPY INTO @stage", "B) EXPORT TO @stage", "C) INSERT INTO @stage", "D) EXPORT_TO_STAGE(stage => @stage, select => 'select * from t1');"], "chooseN": 1, "correct": ["COPY INTO @stage"], "explanation": "The correct statement to export or unload data from Snowflake is 'COPY INTO @stage'. This command allows for data to be copied from Snowflake tables to stages (external storage locations), facilitating data export.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-location.html"}, {"id": 119, "area": "Performance Concepts", "question": "True or False: A 4X-Large Warehouse may, at times, take longer to provision than a X-Small Warehouse.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["True"], "explanation": "It is true that a 4X-Large Warehouse might take longer to provision than a X-Small Warehouse in Snowflake, because larger is not necessarily faster for smaller and more basic queries.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-considerations"}, {"id": 120, "area": "Performance Concepts", "question": "How would you determine the size of the virtual warehouse used for a task?", "options": ["A) Root task may be executed concurrently (i.e., multiple instances), it is recommended to leave some margins in the execution window to avoid missing instances of execution", "B) Querying (SELECT) the size of the stream content would help determine the warehouse size. For example, if querying large stream content, use a larger warehouse size", "C) If using the stored procedure to execute multiple SQL statements, it's best to test run the stored procedure separately to size the compute resource first", "D) Since task infrastructure is based on running the task body on schedule, it's recommended to configure the virtual warehouse for automatic concurrency handling using Multi-cluster warehouse (MCW) to match the task schedule"], "chooseN": 1, "correct": ["If using the stored procedure to execute multiple SQL statements, it's best to test run the stored procedure separately to size the compute resource first"], "explanation": "To determine the right warehouse size, Snowflake recommends starting with the task and workload, then comparing performance across multiple warehouse sizes. For task bodies that use stored procedures, testing the procedure separately is the closest available way to estimate the compute resources required. More generally, the documentation advises analyzing average task run times using different warehouses and clustering to choose an appropriate size.", "reference": "https://docs.snowflake.com/en/user-guide/tasks-intro.html"}, {"id": 121, "area": "Data Protection and Data Sharing", "question": "The Information Schema and Account Usage Share provide storage information for which of the following objects? (Choose three.)", "options": ["A) Users", "B) Tables", "C) Databases", "D) Internal Stages"], "chooseN": 3, "correct": ["Tables", "Databases", "Internal Stages"], "explanation": "The Information Schema and Account Usage Share in Snowflake provide storage information for objects like Tables, Databases, and Internal Stages. These tools offer insights into the storage usage of these objects within Snowflake.", "reference": "https://docs.snowflake.com/en/sql-reference/info-schema.html"}, {"id": 122, "area": "Data Loading and Unloading", "question": "What is the default File Format used in the COPY command if one is not specified?", "options": ["A) CSV", "B) JSON", "C) Parquet", "D) XML"], "chooseN": 1, "correct": ["CSV"], "explanation": "If no specific file format is defined in the COPY command in Snowflake, the default file format used is CSV. This is a commonly used format for data exchange and is the default setting for data loading operations.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-table.html"}, {"id": 123, "area": "Data Protection and Data Sharing", "question": "True or False: Reader Accounts are able to extract data from shared data objects for use outside of Snowflake.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["True"], "explanation": "It is true that Reader Accounts are able to extract data from shared data objects for use outside of Snowflake. They can use the COPY INTO <location> command with their connection credentials to unload data into a cloud storage location.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-reader-create"}, {"id": 124, "area": "Data Transformations", "question": "True or False: You can define multiple columns within a clustering key on a table.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["True"], "explanation": "True. In Snowflake, it is possible to define a clustering key on a table that includes multiple columns. This allows for more complex clustering strategies that can improve query performance on large tables.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-keys.html"}, {"id": 125, "area": "Data Transformations", "question": "True or False: Snowflake enforces unique, primary key, and foreign key constraints during DML operations.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["False"], "explanation": "False. Snowflake does not enforce unique, primary key, and foreign key constraints during DML (Data Manipulation Language) operations. While these constraints can be defined for documentation and compatibility purposes, they are not enforced by Snowflake. Only NOT NULL constraints are always enforced.", "reference": "https://docs.snowflake.com/en/sql-reference/constraints-overview.html"}, {"id": 126, "area": "Data Loading and Unloading", "question": "True or False: Loading data into Snowflake requires that source data files be no larger than 16MB.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["False"], "explanation": "False. Snowflake does not have a strict size limit of 16MB for source data files when loading data. Larger files can be loaded, but for efficiency, it's often recommended to break them into smaller chunks.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-considerations-prepare.html"}, {"id": 127, "area": "Performance Concepts", "question": "True or False: A Virtual Warehouse can be resized while suspended.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["True"], "explanation": "True. A Virtual Warehouse in Snowflake can be resized even when it is suspended. This feature provides flexibility in managing the warehouse size according to varying workloads without the need for the warehouse to be active.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-tasks.html#resizing-a-warehouse"}, {"id": 128, "area": "Account Access and Security", "question": "True or False: When you create a custom role, it is a best practice to immediately grant that role to ACCOUNTADMIN.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["False"], "explanation": "False. The custom role must be granted to the ACCOUNTADMIN role directly or, preferably, to another role in a hierarchy with the SYSADMIN role as the parent.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-overview.html#best-practices-for-managing-access-control"}, {"id": 129, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which of the following accurately represents how a table fits into Snowflake's logical container hierarchy?", "options": ["A) Account -> Schema -> Database -> Table", "B) Account -> Database -> Schema -> Table", "C) Database -> Schema -> Table -> Account", "D) Database -> Table -> Schema -> Account"], "chooseN": 1, "correct": ["Account -> Database -> Schema -> Table"], "explanation": "In Snowflake, the logical container hierarchy for a table is: Account -> Database -> Schema -> Table. This hierarchy starts with the account, under which multiple databases can exist. Each database can have multiple schemas, and under each schema, there can be multiple tables.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-overview"}, {"id": 130, "area": "Data Protection and Data Sharing", "question": "True or False: All Snowflake table types include fail-safe storage.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["False"], "explanation": "Not all Snowflake table types include fail-safe storage. Fail-safe is a data protection feature that provides a seven-day immutable storage layer beyond the Time Travel retention period. However, it is not applicable to all table types, such as temporary tables and transient tables.", "reference": "https://docs.snowflake.com/en/user-guide/tables-temp-transient"}, {"id": 131, "area": "Data Protection and Data Sharing", "question": "What are two ways to create and manage Data Shares in Snowflake? (Choose two.)", "options": ["A) Via the Snowflake Web Interface (UI)", "B) Via the DATA_SHARE=TRUE parameter", "C) Via SQL commands", "D) Via Virtual Warehouses"], "chooseN": 2, "correct": ["Via the Snowflake Web Interface (UI)", "Via SQL commands"], "explanation": "Data Shares in Snowflake can be created and managed via the Snowflake Web Interface (UI) and through SQL commands. These methods provide the necessary functionality to establish and control data sharing between different Snowflake accounts.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-provider"}, {"id": 132, "area": "Data Protection and Data Sharing", "question": "True or False: Fail-safe can be disabled within a Snowflake account.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["False"], "explanation": "It is false that Fail-safe can be disabled within a Snowflake account. Fail-safe is a non-configurable, built-in feature in Snowflake that provides a 7-day data recovery window beyond the Time Travel retention period for protection against accidental data loss.", "reference": "https://docs.snowflake.com/en/user-guide/data-failsafe"}, {"id": 133, "area": "Performance Concepts", "question": "True or False: It is possible for a user to run a query against the query result cache without requiring an active Warehouse.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["True"], "explanation": "It is true that a user can run a query against the query result cache in Snowflake without requiring an active Warehouse. If the results of a previous query are available in the cache, Snowflake can return these results without needing to re-run the query on an active warehouse.", "reference": "https://docs.snowflake.com/en/user-guide/querying.html#query-results"}, {"id": 134, "area": "Account Access and Security", "question": "True or False: When Snowflake is configured to use Single Sign-On (SSO), Snowflake receives the usernames and credentials from the SSO service and loads them into the customer's Snowflake account.", "options": ["A) True", "B) False"], "chooseN": 1, "correct": ["False"], "explanation": "False. When configured for Single Sign-On (SSO), Snowflake does not receive or load usernames and credentials from the SSO service into the Snowflake account. Instead, authentication is managed by the SSO service, and Snowflake relies on assertions provided by the SSO service to authenticate users.", "reference": "https://docs.snowflake.com/en/user-guide/admin-security-fed-auth-use.html"}, {"id": 135, "area": "Data Loading and Unloading", "question": "Which of the following are best practices for loading data into Snowflake? (Choose three.)", "options": ["A) Aim to produce data files that are between 100 MB and 250 MB in size, compressed.", "B) Load data from files in a cloud storage service in a different region or cloud platform from the service or region containing the Snowflake account, to save on cost.", "C) Enclose fields that contain delimiter characters in single or double quotes.", "D) Split large files into a greater number of smaller files to distribute the load among the compute resources in an active warehouse.", "E) When planning which warehouse(s) to use for data loading, start with the largest warehouse possible.", "F) Partition the staged data into large folders with random paths, allowing Snowflake to determine the best way to load each file."], "chooseN": 3, "correct": ["Aim to produce data files that are between 100 MB and 250 MB in size, compressed.", "Enclose fields that contain delimiter characters in single or double quotes.", "Split large files into a greater number of smaller files to distribute the load among the compute resources in an active warehouse."], "explanation": "Best practices for loading data into Snowflake include producing data files of optimal size (100-250 MB compressed), properly enclosing fields with delimiter characters, and splitting larger files into smaller ones to efficiently distribute the load across compute resources.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-considerations-prepare.html"}, {"id": 136, "area": "Data Protection and Data Sharing", "question": "Which Snowflake feature is used for both querying and restoring data?", "options": ["A) Cluster keys", "B) Time Travel", "C) Fail-safe", "D) Cloning"], "chooseN": 1, "correct": ["Time Travel"], "explanation": "Time Travel is a Snowflake feature that is used for both querying historical data and restoring data to a previous state. It allows users to access and revert data to earlier versions within a specified retention period.", "reference": "https://docs.snowflake.com/en/user-guide/data-time-travel.html"}, {"id": 137, "area": "Performance Concepts", "question": "What do the terms scale up and scale out refer to in Snowflake? (Choose two.)", "options": ["A) Scaling out adds clusters of the same size to a virtual warehouse to handle more concurrent queries.", "B) Scaling out adds clusters of varying sizes to a virtual warehouse.", "C) Scaling out adds additional database servers to an existing running cluster to handle more concurrent queries.", "D) Snowflake recommends using both scaling up and scaling out to handle more concurrent queries.", "E) Scaling up resizes a virtual warehouse so it can handle more complex workloads.", "F) Scaling up adds additional database servers to an existing running cluster to handle larger workloads."], "chooseN": 2, "correct": ["Scaling out adds clusters of the same size to a virtual warehouse to handle more concurrent queries.", "Scaling up resizes a virtual warehouse so it can handle more complex workloads."], "explanation": "In Snowflake, 'scaling up' refers to resizing a virtual warehouse to handle more complex workloads by increasing its computational resources, while 'scaling out' involves adding more clusters of the same size to a virtual warehouse to handle more concurrent queries.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-considerations"}, {"id": 138, "area": "Account Access and Security", "question": "What is the minimum Snowflake edition that has column-level security enabled?", "options": ["A) Standard", "B) Enterprise", "C) Business Critical", "D) Virtual Private Snowflake"], "chooseN": 1, "correct": ["Enterprise"], "explanation": "Column-level security is available starting from the Enterprise edition of Snowflake. This feature allows granular access control at the column level within tables, ensuring enhanced security and compliance.", "reference": "https://docs.snowflake.com/en/user-guide/security-column.html"}, {"id": 139, "area": "Performance Concepts", "question": "What parameter controls if the Virtual Warehouse starts immediately after the CREATE WAREHOUSE statement?", "options": ["A) INITIALLY_SUSPENDED = TRUE/FALSE", "B) START_AFTER_CREATE = TRUE/FALSE", "C) START_THE = 60 / (seconds from now)", "D) START_TIME = CURRENT_DATE()"], "chooseN": 1, "correct": ["INITIALLY_SUSPENDED = TRUE/FALSE"], "explanation": "The 'INITIALLY_SUSPENDED = TRUE/FALSE' parameter controls whether the Virtual Warehouse starts immediately after the CREATE WAREHOUSE statement. If set to TRUE, the warehouse will not start automatically; if set to FALSE, it will start immediately upon creation.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/create-warehouse.html"}, {"id": 140, "area": "Data Loading and Unloading", "question": "When cloning a database, what is cloned with the database? (Choose two.)", "options": ["A) Privileges on the database", "B) Existing child objects within the database", "C) Future child objects within the database", "D) Privileges on the schemas within the database", "E) Only schemas and tables within the database"], "chooseN": 2, "correct": ["Existing child objects within the database", "Privileges on the schemas within the database"], "explanation": "When cloning a database in Snowflake, the operation clones the existing child objects within the database and the privileges on the schemas within the database. It does not clone privileges on the database itself or future child objects.", "reference": "https://docs.snowflake.com/en/user-guide/object-clone"}, {"id": 141, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which of the following describes the Snowflake Cloud Services layer?", "options": ["A) Coordinates activities in the Snowflake account", "B) Executes queries submitted by the Snowflake account users", "C) Manages quotas on the Snowflake account storage", "D) Manages the virtual warehouse cache to speed up queries"], "chooseN": 1, "correct": ["Coordinates activities in the Snowflake account"], "explanation": "The Snowflake Cloud Services layer is responsible for coordinating activities within the Snowflake account. It serves as the central management hub for all tasks, including user authentication, query parsing and optimization, and metadata management.", "reference": "https://docs.snowflake.com/en/user-guide/intro-key-concepts.html#cloud-services-layer"}, {"id": 142, "area": "Data Protection and Data Sharing", "question": "What is the maximum total Continuous Data Protection (CDP) charges incurred for a temporary table?", "options": ["A) 30 days", "B) 7 days", "C) 48 hours", "D) 24 hours"], "chooseN": 1, "correct": ["24 hours"], "explanation": "The maximum total Continuous Data Protection (CDP) charges incurred for a temporary table in Snowflake is 24 hours. Temporary tables have a shorter CDP period compared to other table types.", "reference": "https://docs.snowflake.com/en/user-guide/tables-temp-transient.html#continuous-data-protection-cdp"}, {"id": 143, "area": "Performance Concepts", "question": "When reviewing a query profile, what is a symptom that a query is too large to fit into the memory?", "options": ["A) A single join node uses more than 50% of the query time", "B) Partitions scanned is equal to partitions total", "C) An AggregateOperator node is present", "D) The query is spilling to remote storage"], "chooseN": 1, "correct": ["The query is spilling to remote storage"], "explanation": "When reviewing a query profile in Snowflake, a symptom that a query is too large to fit into memory is when the query is spilling to remote storage. This indicates that the query's memory requirements exceed the available memory, causing Snowflake to use disk storage as an overflow.", "reference": "https://docs.snowflake.com/en/user-guide/ui-query-profile"}, {"id": 144, "area": "Performance Concepts", "question": "What type of query benefits the MOST from search optimization?", "options": ["A) A query that uses only disjunction (i.e., OR) predicates", "B) A query that includes analytical expressions", "C) A query that uses equality predicates or predicates that use IN", "D) A query that filters on semi-structured data types"], "chooseN": 1, "correct": ["A query that uses equality predicates or predicates that use IN"], "explanation": "Search optimization in Snowflake is most beneficial for queries that use equality predicates or predicates that use IN. These types of queries can efficiently leverage search optimization to quickly find relevant data, leading to faster query execution.", "reference": "https://docs.snowflake.com/en/user-guide/search-optimization-service"}, {"id": 145, "area": "Data Loading and Unloading", "question": "What transformations are supported in a CREATE PIPE ... AS COPY ... FROM (..) statement? (Choose two.)", "options": ["A) Data can be filtered by an optional WHERE clause.", "B) Incoming data can be joined with other tables.", "C) Columns can be reordered.", "D) Columns can be omitted.", "E) Row level access can be defined."], "chooseN": 2, "correct": ["Columns can be reordered.", "Columns can be omitted."], "explanation": "Using a query as the source for the COPY statement for column reordering, column omission, and casts (i.e. transforming data during a load) is supported. Note that only simple SELECT statements are supported. Filtering using a WHERE clause is not supported.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/create-pipe"}, {"id": 146, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which of the following are characteristics of Snowflake virtual warehouses? (Choose two.)", "options": ["A) Auto-resume applies only to the last warehouse that was started in a multi-cluster warehouse.", "B) The ability to auto-suspend a warehouse is only available in the Enterprise edition or above.", "C) SnowSQL supports both a configuration file and a command line option for specifying a default warehouse.", "D) A user cannot specify a default warehouse when using the ODBC driver.", "E) The default virtual warehouse size can be changed at any time."], "chooseN": 2, "correct": ["SnowSQL supports both a configuration file and a command line option for specifying a default warehouse.", "The default virtual warehouse size can be changed at any time."], "explanation": "- SnowSQL supports both a configuration file and a command line option for specifying a default warehouse.: SnowSQL permite especificar un warehouse predeterminado tanto a traves de un archivo de configuracion (~/.snowsql/config) como mediante opciones de linea de comandos (--warehouse).\n- The default virtual warehouse size can be changed at any time.: El tamano de un virtual warehouse puede modificarse en cualquier momento mediante ALTER WAREHOUSE, sin necesidad de recrearlo.\n- Auto-resume applies only to the last warehouse that was started in a multi-cluster warehouse.: Incorrecto. Auto-resume aplica a todos los clusters del warehouse, no solo al ultimo.\n- The ability to auto-suspend a warehouse is only available in the Enterprise edition or above.: Incorrecto. Auto-suspend esta disponible en todas las ediciones de Snowflake.\n- A user cannot specify a default warehouse when using the ODBC driver.: Incorrecto. El driver ODBC permite especificar un warehouse predeterminado en la configuracion de conexion.", "reference": "https://docs.snowflake.com/en/user-guide/snowsql-config, https://docs.snowflake.com/en/sql-reference/sql/alter-warehouse"}, {"id": 147, "area": "Data Loading and Unloading", "question": "Which command should be used to load data from a file, located in an external stage, into a table in Snowflake?", "options": ["A) INSERT", "B) PUT", "C) GET", "D) COPY"], "chooseN": 1, "correct": ["COPY"], "explanation": "To load data from a file located in an external stage into a Snowflake table, the COPY command is used. This command allows for efficient data loading from files stored in stages like Amazon S3, Azure Blob Storage, or Google Cloud Storage.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-local-file-system-copy.html"}, {"id": 148, "area": "Snowflake Data Cloud Features & Architecture", "question": "The Snowflake Cloud Data Platform is described as having which of the following architectures?", "options": ["A) Shared-disk", "B) Shared-nothing", "C) Multi-cluster shared data", "D) Serverless query engine"], "chooseN": 1, "correct": ["Multi-cluster shared data"], "explanation": "The architecture of the Snowflake Cloud Data Platform is best described as 'multi-cluster shared data'. This architecture allows for the separation of storage and compute resources, enabling efficient data management and scalable performance.", "reference": "https://docs.snowflake.com/en/user-guide/intro-key-concepts.html"}, {"id": 149, "area": "Account Access and Security", "question": "Which of the following is a data tokenization integration partner?", "options": ["A) Protegrity", "B) Tableau", "C) DBeaver", "D) SAP"], "chooseN": 1, "correct": ["Protegrity"], "explanation": "Protegrity is known for its data security solutions, including tokenization, and is a data tokenization integration partner with Snowflake. This partnership allows for enhanced data security within the Snowflake environment.", "reference": "https://docs.snowflake.com/en/user-guide/security-column-ext-token-use"}, {"id": 150, "area": "Data Protection and Data Sharing", "question": "What versions of Snowflake should be used to manage compliance with Personal Identifiable Information (PII) requirements? (Choose two.)", "options": ["A) Custom Edition", "B) Virtual Private Snowflake", "C) Business Critical Edition", "D) Standard Edition", "E) Enterprise Edition"], "chooseN": 2, "correct": ["Business Critical Edition", "Enterprise Edition"], "explanation": "The Business Critical Edition and Enterprise Edition of Snowflake are best suited for managing compliance with Personal Identifiable Information (PII) requirements, offering advanced security features necessary for handling sensitive data.", "reference": "https://docs.snowflake.com/en/user-guide/intro-editions"}, {"id": 151, "area": "Data Loading and Unloading", "question": "What are supported file formats for unloading data from Snowflake? (Choose three.)", "options": ["A) XML", "B) JSON", "C) Parquet", "D) ORC", "E) AVRO", "F) CSV"], "chooseN": 3, "correct": ["JSON", "Parquet", "CSV"], "explanation": "Snowflake supports various file formats for unloading data, including JSON, Parquet, and CSV.", "reference": "https://docs.snowflake.com/en/user-guide/data-unload-prepare"}, {"id": 152, "area": "Snowflake Data Cloud Features & Architecture", "question": "The Snowflake cloud services layer is responsible for which tasks? (Choose two.)", "options": ["A) Local disk caching", "B) Authentication and access control", "C) Metadata management", "D) Query processing", "E) Database storage"], "chooseN": 2, "correct": ["Authentication and access control", "Metadata management"], "explanation": "The Snowflake cloud services layer is responsible for key management activities such as authentication and access control, ensuring secure access to data, and metadata management, which involves maintaining data about the data stored in Snowflake.", "reference": "https://docs.snowflake.com/en/user-guide/intro-key-concepts.html#cloud-services-layer"}, {"id": 153, "area": "Performance Concepts", "question": "What is a key feature of Snowflake architecture?", "options": ["A) Zero-copy cloning creates a mirror copy of a database that updates with the original.", "B) Software updates are automatically applied on a quarterly basis.", "C) Snowflake eliminates resource contention with its virtual warehouse implementation.", "D) Multi-cluster warehouses allow users to run a query that spans across multiple clusters.", "E) Snowflake automatically sorts DATE columns during ingest, for fast retrieval by date."], "chooseN": 1, "correct": ["Snowflake eliminates resource contention with its virtual warehouse implementation."], "explanation": "A key feature of Snowflake architecture is its virtual warehouse implementation, which eliminates resource contention. This allows for independent scaling of compute and storage, ensuring that workloads do not compete for resources.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-compute.html"}, {"id": 154, "area": "Data Protection and Data Sharing", "question": "When publishing a Snowflake Data Marketplace listing into a remote region what should be taken into consideration? (Choose two.)", "options": ["A) There is no need to have a Snowflake account in the target region, a share will be created for each user.", "B) The listing is replicated into all selected regions automatically, the data is not.", "C) The user must have the ORGADMIN role available in at least one account to link accounts for replication.", "D) Shares attached to listings in remote regions can be viewed from any account in an organization.", "E) For a standard listing the user can wait until the first customer requests the data before replicating it to the target region."], "chooseN": 2, "correct": ["The listing is replicated into all selected regions automatically, the data is not.", "For a standard listing the user can wait until the first customer requests the data before replicating it to the target region."], "explanation": "When publishing a Snowflake Data Marketplace listing in a remote region, it's important to know that the listing is replicated across all selected regions, but the data itself is not automatically replicated. Additionally, you do not need to replicate the data to each region until a consumer requests it.", "reference": "https://docs.snowflake.com/en/user-guide/data-exchange-managing-data-listings.html#considerations-for-creating-a-listing-in-a-remote-region-and-replicating-data"}, {"id": 155, "area": "Data Loading and Unloading", "question": "When loading data into Snowflake via Snowpipe what is the compressed file size recommendation?", "options": ["A) 10-50 MB", "B) 100-250 MB", "C) 300-500 MB", "D) 1000-1500 MB"], "chooseN": 1, "correct": ["100-250 MB"], "explanation": "When using Snowpipe to load data into Snowflake, the recommended size for compressed files is between 100 and 250 MB. This size range offers an optimal balance between upload efficiency and processing speed.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-considerations-prepare"}, {"id": 156, "area": "Account Access and Security", "question": "Which Snowflake feature allows a user to substitute a randomly generated identifier for sensitive data, in order to prevent unauthorized users access to the data, before loading it into Snowflake?", "options": ["A) External Tokenization", "B) External Tables", "C) Materialized Views", "D) User-Defined Table Functions (UDTF)"], "chooseN": 1, "correct": ["External Tokenization"], "explanation": "External Tokenization is a feature in Snowflake that allows users to replace sensitive data with a randomly generated identifier before loading it into Snowflake. This process ensures that sensitive information remains secure by preventing unauthorized access.", "reference": "https://docs.snowflake.com/en/user-guide/security-column-ext-token-use"}, {"id": 157, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which of the following are examples of operations that require a Virtual Warehouse to complete, assuming no queries have been executed previously? (Choose three.)", "options": ["A) MIN(<< column value >>)", "B) COPY", "C) SUM(<< column value >>)", "D) UPDATE"], "chooseN": 4, "correct": ["MIN(<< column value >>)", "COPY", "SUM(<< column value >>)", "UPDATE"], "explanation": "According to Snowflake documentation, virtual warehouses are required for queries and all DML operations, including loading data into tables. MIN and SUM are query operations, COPY loads data, and UPDATE is DML, so all four options require a virtual warehouse.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses.html"}, {"id": 158, "area": "Data Protection and Data Sharing", "question": "What is the SNOWFLAKE.ACCOUNT_USAGE view that contains information about which objects were read by queries within the last 365 days (1 year)?", "options": ["A) VIEWS_HISTORY", "B) OBJECT_HISTORY", "C) ACCESS_HISTORY", "D) LOGIN_HISTORY"], "chooseN": 1, "correct": ["ACCESS_HISTORY"], "explanation": "The 'ACCESS_HISTORY' view within the SNOWFLAKE.ACCOUNT_USAGE schema provides information about the objects that were accessed by queries in the last 365 days. This view is instrumental in auditing and understanding data access patterns within Snowflake.", "reference": "https://docs.snowflake.com/en/sql-reference/account-usage/access_history"}, {"id": 159, "area": "Account Access and Security", "question": "Which feature is only available in the Enterprise or higher editions of Snowflake?", "options": ["A) Column-level security", "B) SOC 2 type II certification", "C) Multi-factor Authentication (MFA)", "D) Object-level access control"], "chooseN": 1, "correct": ["Column-level security"], "explanation": "Column-level security is a feature exclusive to the Enterprise or higher editions of Snowflake. It allows for granular control over access to specific columns within a table, enhancing data security and privacy.", "reference": "https://docs.snowflake.com/en/user-guide/security-column.html"}, {"id": 160, "area": "Performance Concepts", "question": "Will data cached in a warehouse be lost when the warehouse is resized?", "options": ["A) Possibly, if the warehouse is resized to a smaller size and the cache no longer fits.", "B) Yes, because the compute resource is replaced in its entirety with a new compute resource.", "C) No, because the size of the cache is independent from the warehouse size.", "D) Yes, because the new compute resource will no longer have access to the cache encryption key."], "chooseN": 1, "correct": ["Possibly, if the warehouse is resized to a smaller size and the cache no longer fits."], "explanation": "Decreasing the size of a running warehouse removes compute resources from the warehouse. When the computer resources are removed, the cache associated with those resources is dropped, which can impact performance in the same way that suspending the warehouse can impact performance after it is resumed.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-considerations#scaling-up-vs-scaling-out"}, {"id": 161, "area": "Data Loading and Unloading", "question": "Which semi-structured file formats are supported when unloading data from a table? (Choose two.)", "options": ["A) ORC", "B) XML", "C) Avro", "D) Parquet", "E) JSON"], "chooseN": 2, "correct": ["JSON", "Parquet"], "explanation": "When unloading data from a table in Snowflake, the supported semi-structured file formats include JSON and Parquet. These formats are widely used for handling semi-structured data due to their flexibility and compatibility with various data processing tools.", "reference": "https://docs.snowflake.com/en/user-guide/data-unload-considerations.html"}, {"id": 162, "area": "Performance Concepts", "question": "A running virtual warehouse is suspended. What is the MINIMUM amount of time that the warehouse will incur charges for when it is restarted?", "options": ["A) 1 second", "B) 60 seconds", "C) 5 minutes", "D) 60 minutes"], "chooseN": 1, "correct": ["60 seconds"], "explanation": "When a running virtual warehouse in Snowflake is suspended and then restarted, the minimum amount of time for which it will incur charges is 60 seconds. This is the minimum billing unit for compute resources in Snowflake.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-considerations.html#billing-and-credit-usage"}, {"id": 163, "area": "Snowflake Data Cloud Features & Architecture", "question": "What are the responsibilities of Snowflake's Cloud Service layer? (Choose three.)", "options": ["A) Authentication", "B) Resource management", "C) Virtual warehouse caching", "D) Query parsing and optimization", "E) Query execution", "F) Physical storage of micro-partitions"], "chooseN": 3, "correct": ["Authentication", "Query parsing and optimization", "Resource management"], "explanation": "Snowflake's Cloud Service layer is responsible for authentication, ensuring secure access to data; query parsing and optimization, which involves analyzing and optimizing queries for execution; and resource management, which includes managing the allocation and scaling of resources.", "reference": "https://docs.snowflake.com/en/user-guide/intro-key-concepts.html#cloud-services-layer"}, {"id": 164, "area": "Data Protection and Data Sharing", "question": "How long is the Fail-safe period for temporary and transient tables?", "options": ["A) There is no Fail-safe period for these tables.", "B) 1 day", "C) 7 days", "D) 31 days", "E) 90 days"], "chooseN": 1, "correct": ["There is no Fail-safe period for these tables."], "explanation": "Temporary and transient tables in Snowflake do not have a Fail-safe period. Fail-safe is a feature that provides additional protection for data stored in permanent tables, but it does not apply to temporary or transient tables.", "reference": "https://docs.snowflake.com/en/user-guide/tables-temp-transient.html"}, {"id": 165, "area": "Data Loading and Unloading", "question": "Which command should be used to download files from a Snowflake stage to a local folder on a client's machine?", "options": ["A) PUT", "B) GET", "C) COPY", "D) SELECT"], "chooseN": 1, "correct": ["GET"], "explanation": "To download files from a Snowflake stage to a local folder, the GET command is used. This command allows users to retrieve data from a Snowflake stage and save it to a specified local directory.", "reference": "https://docs.snowflake.com/en/user-guide/data-unload-snowflake"}, {"id": 166, "area": "Data Protection and Data Sharing", "question": "How does Snowflake Fail-safe protect data in a permanent table?", "options": ["A) Fail-safe makes data available up to 1 day, recoverable by user operations.", "B) Fail-safe makes data available for 7 days, recoverable by user operations.", "C) Fail-safe makes data available for 7 days, recoverable only by Snowflake Support.", "D) Fail-safe makes data available up to 1 day, recoverable only by Snowflake Support."], "chooseN": 1, "correct": ["Fail-safe makes data available for 7 days, recoverable only by Snowflake Support."], "explanation": "Snowflake's Fail-safe feature for permanent tables ensures that data is available for a period of 7 days after it is no longer accessible through the standard Snowflake interface. During this period, the data can only be recovered by Snowflake Support, providing an extra layer of protection against data loss.", "reference": "https://docs.snowflake.com/en/user-guide/data-failsafe"}, {"id": 167, "area": "Snowflake Data Cloud Features & Architecture", "question": "A virtual warehouse is created using the following command: Create warehouse my_WH with - warehouse_size = MEDIUM min_cluster_count = 1 max_cluster_count = 1 auto_suspend = 60 auto_resume = true; The image below is a graphical representation of the warehouse utilization across two days. What action should be taken to address this situation?", "options": ["A) Increase the warehouse size from Medium to 2XL.", "B) Increase the value for the parameter MAX_CONCURRENCY_LEVEL.", "C) Configure the warehouse to a multi-cluster warehouse.", "D) Lower the value of the parameter STATEMENT_QUEUED_TIMEOUT_IN_SECONDS."], "chooseN": 1, "correct": ["Configure the warehouse to a multi-cluster warehouse."], "explanation": "- Configure the warehouse to a multi-cluster warehouse: Permitir múltiples clústeres ayuda a manejar la carga alta de trabajo al agregar recursos dinámicamente, eliminando las colas de consultas.\n- Increase the warehouse size from Medium to 2XL: Aumentar el tamaño mejora la capacidad de un clúster, pero no resuelve problemas de concurrencia en cargas simultáneas altas.\n- Increase the value for the parameter MAX_CONCURRENCY_LEVEL: Esto aumenta las consultas concurrentes permitidas, pero sigue limitado por los recursos de un único clúster.\n- Lower the value of the parameter STATEMENT_QUEUED_TIMEOUT_IN_SECONDS: Reducir este valor haría que las consultas fallaran más rápido en lugar de resolver la congestión.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-multicluster.html"}, {"id": 168, "area": "Account Access and Security", "question": "Which minimum Snowflake edition allows for a dedicated metadata store?", "options": ["A) Standard", "B) Enterprise", "C) Business Critical", "D) Virtual Private Snowflake"], "chooseN": 1, "correct": ["Virtual Private Snowflake"], "explanation": "The Virtual Private Snowflake edition of Snowflake is the minimum level that allows for a dedicated metadata store. This feature provides enhanced security and performance, especially for organizations with large or sensitive datasets.", "reference": "https://docs.snowflake.com/en/user-guide/intro-editions.html"}, {"id": 169, "area": "Account Access and Security", "question": "Network policies can be set at which Snowflake levels? (Choose two.)", "options": ["A) Role", "B) Schema", "C) User", "D) Database", "E) Account", "F) Tables"], "chooseN": 2, "correct": ["User", "Account"], "explanation": "In Snowflake, network policies can be set at the User and Account levels. These policies define the IP address ranges that are allowed or denied access to your Snowflake account, enhancing security by restricting unauthorized network access.", "reference": "https://docs.snowflake.com/en/user-guide/network-policies.html"}, {"id": 170, "area": "Data Protection and Data Sharing", "question": "What are the correct parameters for time travel and fail-safe in the Snowflake Enterprise Edition?", "options": ["A) Default Time Travel Retention is set to 0 days. Maximum Time Travel Retention is 30 days. Fail Safe retention time is 1 day.", "B) Default Time Travel Retention is set to 1 day. Maximum Time Travel Retention is 365 days. Fail Safe retention time is 7 days.", "C) Default Time Travel Retention is set to 0 days. Maximum Time Travel Retention is 90 days. Fail Safe retention time is 7 days.", "D) Default Time Travel Retention is set to 1 day. Maximum Time Travel Retention is 90 days. Fail Safe retention time is 7 days.", "E) Default Time Travel Retention is set to 7 days. Maximum Time Travel Retention is 1 day. Fail Safe retention time is 90 days.", "F) Default Time Travel Retention is set to 90 days. Maximum Time Travel Retention is 7 days. Fail Safe retention time is 356 days."], "chooseN": 1, "correct": ["Default Time Travel Retention is set to 1 day. Maximum Time Travel Retention is 90 days. Fail Safe retention time is 7 days."], "explanation": "For the Snowflake Enterprise Edition, the default Time Travel retention is 1 day, with a maximum of 90 days. The Fail Safe period, which provides additional protection for your data, is set to 7 days.", "reference": "https://docs.snowflake.com/en/user-guide/data-time-travel.html#time-travel-and-fail-safe"}, {"id": 171, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which of the following objects are contained within a schema? (Choose two.)", "options": ["A) Role", "B) Stream", "C) Warehouse", "D) External table", "E) User", "F) Share"], "chooseN": 2, "correct": ["Stream", "External table"], "explanation": "Within a Snowflake schema, objects such as Streams and External tables are contained. Streams enable change data capture on tables, while External tables allow querying data stored in external storage without loading it into Snowflake.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-overview.html"}, {"id": 172, "area": "Performance Concepts", "question": "Which of the following statements describe features of Snowflake data caching? (Choose two.)", "options": ["A) When a virtual warehouse is suspended, the data cache is saved on the remote storage layer.", "B) When the data cache is full, the least-recently used data will be cleared to make room.", "C) A user can only access their own queries from the query result cache.", "D) A user must set USE_METADATA_CACHE to TRUE to use the metadata cache in queries.", "E) The RESULT_SCAN table function can access and filter the contents of the query result cache."], "chooseN": 2, "correct": ["When the data cache is full, the least-recently used data will be cleared to make room.", "The RESULT_SCAN table function can access and filter the contents of the query result cache."], "explanation": "In Snowflake, when the data cache is full, it automatically clears the least recently used data to make room for new data. Additionally, the RESULT_SCAN table function allows users to access and filter the contents of the query result cache, providing efficient access to recent query results.", "reference": "https://docs.snowflake.com/en/user-guide/querying-cache.html"}, {"id": 173, "area": "Data Loading and Unloading", "question": "A table needs to be loaded. The input data is in JSON format and is a concatenation of multiple JSON documents. The file size is 3 GB. A warehouse size S is being used. The following COPY INTO command was executed: COPY INTO SAMPLE FROM @~/SAMPLE.JSON (TYPE=JSON) The load failed with this error: Max LOB size (16777216) exceeded, actual size of parsed column is 17894470. How can this issue be resolved?", "options": ["A) Compress the file and load the compressed file.", "B) Split the file into multiple files in the recommended size range (100 MB - 250 MB).", "C) Use a larger-sized warehouse.", "D) Set STRIP_OUTER_ARRAY=TRUE in the COPY INTO command."], "chooseN": 1, "correct": ["Set STRIP_OUTER_ARRAY=TRUE in the COPY INTO command."], "explanation": "If the data exceeds 16 MB, enable the STRIP_OUTER_ARRAY file format option for the COPY INTO <table> command to remove the outer array structure and load the records into separate table row.", "reference": "https://docs.snowflake.com/en/user-guide/semistructured-considerations#data-size-limitations"}, {"id": 174, "area": "Data Transformations", "question": "What is a feature of a stored procedure in Snowflake?", "options": ["A) They can be created as secure and hide the underlying metadata from all users.", "B) They can access tables from a single database.", "C) They can only contain a single SQL statement.", "D) They can be created to run with a caller's rights or an owner's rights."], "chooseN": 1, "correct": ["They can be created to run with a caller's rights or an owner's rights."], "explanation": "Stored procedures in Snowflake can be created to execute with either the caller's rights or the owner's rights. This feature allows for flexibility in managing security and access control when executing stored procedures.", "reference": "https://docs.snowflake.com/developer-guide/stored-procedure/stored-procedures-rights"}, {"id": 175, "area": "Data Transformations", "question": "Which columns are part of the result set of the Snowflake LATERAL FLATTEN command? (Choose two.)", "options": ["A) CONTENT", "B) PATH", "C) BYTE_SIZE", "D) INDEX", "E) DATATYPE"], "chooseN": 2, "correct": ["PATH", "INDEX"], "explanation": "The LATERAL FLATTEN command in Snowflake produces a result set with these output columns: SEQ, KEY, PATH, INDEX, VALUE, and THIS. PATH indicates the path to each element within a semi-structured data type, and INDEX provides the positional index of each element within an array. CONTENT, BYTE_SIZE, and DATATYPE are not columns produced by FLATTEN.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/flatten.html"}, {"id": 176, "area": "Data Transformations", "question": "What is the minimum Snowflake edition required to create a materialized view?", "options": ["A) Standard Edition", "B) Enterprise Edition", "C) Business Critical Edition", "D) Virtual Private Snowflake Edition"], "chooseN": 1, "correct": ["Enterprise Edition"], "explanation": "The creation of materialized views in Snowflake requires at least the Enterprise Edition. This edition provides the necessary features and capabilities to support materialized views, which are used for performance optimization.", "reference": "https://docs.snowflake.com/en/user-guide/views-materialized.html"}, {"id": 177, "area": "Data Transformations", "question": "Which Snowflake function will interpret an input string as a JSON document, and produce a VARIANT value?", "options": ["A) parse_json()", "B) json_extract_path_text()", "C) object_construct()", "D) flatten"], "chooseN": 1, "correct": ["parse_json()"], "explanation": "The parse_json() function in Snowflake is used to interpret an input string as a JSON document and produce a VARIANT value. This function is essential for handling and querying JSON data within Snowflake.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/parse_json.html"}, {"id": 178, "area": "Snowflake Data Cloud Features & Architecture", "question": "How are serverless features billed?", "options": ["A) Per second multiplied by an automatic sizing for the job", "B) Per minute multiplied by an automatic sizing for the job, with a minimum of one minute", "C) Per second multiplied by the size, as determined by the SERVERLESS_FEATURES_SIZE account parameter", "D) Serverless features are not billed, unless the total cost for the month exceeds 10% of the warehouse credits, on the account"], "chooseN": 1, "correct": ["Per second multiplied by an automatic sizing for the job"], "explanation": "Serverless features in Snowflake are billed per second, multiplied by an automatic sizing for the job. This billing method ensures that users are charged based on the actual usage and computational resources required for serverless operations.", "reference": "https://docs.snowflake.com/en/user-guide/cost-understanding-compute#label-serverless-credit-usage"}, {"id": 179, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which Snowflake architectural layer is responsible for a query execution plan?", "options": ["A) Compute", "B) Data storage", "C) Cloud services", "D) Cloud provider"], "chooseN": 1, "correct": ["Cloud services"], "explanation": "The Cloud services layer in Snowflake's architecture is responsible for generating a query execution plan. This layer handles tasks like query parsing, optimization, and metadata management, essential for formulating an efficient execution strategy.", "reference": "https://docs.snowflake.com/en/user-guide/intro-key-concepts.html#cloud-services-layer"}, {"id": 180, "area": "Data Loading and Unloading", "question": "When unloading to a stage, which of the following is a recommended practice or approach?", "options": ["A) Set SINGLE = TRUE for larger files.", "B) Use OBJECT_CONSTRUCT(*) when using Parquet.", "C) Avoid the use of the CAST function.", "D) Define an individual file format."], "chooseN": 1, "correct": ["Define an individual file format."], "explanation": "When unloading data to a stage in Snowflake, it is recommended to define an individual file format. This ensures that the data is unloaded in a format that is optimized for the intended use, enhancing compatibility and efficiency in data handling.", "reference": "https://docs.snowflake.com/en/user-guide/data-unload-considerations.html"}, {"id": 181, "area": "Data Transformations", "question": "Which SQL commands, when committed, will consume a stream and advance the stream offset? (Choose two.)", "options": ["A) UPDATE TABLE FROM STREAM", "B) SELECT FROM STREAM", "C) INSERT INTO TABLE SELECT FROM STREAM", "D) ALTER TABLE AS SELECT FROM STREAM", "E) BEGIN COMMIT"], "chooseN": 2, "correct": ["UPDATE TABLE FROM STREAM", "INSERT INTO TABLE SELECT FROM STREAM"], "explanation": "A stream advances the offset only when it is used in a DML transaction.", "reference": "https://docs.snowflake.com/en/user-guide/streams-intro"}, {"id": 182, "area": "Data Loading and Unloading", "question": "Which methods can be used to delete staged files from a Snowflake stage? (Choose two.)", "options": ["A) Use the DROP command after the load completes.", "B) Specify the TEMPORARY option when creating the file format.", "C) Specify the PURGE copy option in the COPY INTO command.", "D) Use the REMOVE command after the load completes.", "E) Use the DELETE LOAD HISTORY command after the load completes."], "chooseN": 2, "correct": ["Specify the PURGE copy option in the COPY INTO command.", "Use the REMOVE command after the load completes."], "explanation": "To delete staged files in Snowflake, you can specify the PURGE copy option in the COPY INTO command, which deletes files immediately after successful loading, or use the REMOVE command after the load completes to manually delete the files.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/remove"}, {"id": 183, "area": "Snowflake Data Cloud Features & Architecture", "question": "On which of the following cloud platforms can a Snowflake account be hosted? (Choose three.)", "options": ["A) Amazon Web Services", "B) Private Virtual Cloud", "C) Oracle Cloud", "D) Microsoft Azure Cloud", "E) Google Cloud Platform", "F) Alibaba Cloud"], "chooseN": 3, "correct": ["Amazon Web Services", "Microsoft Azure Cloud", "Google Cloud Platform"], "explanation": "Snowflake can be hosted on Amazon Web Services, Microsoft Azure Cloud, and Google Cloud Platform. These platforms provide the necessary infrastructure and services to support Snowflake's cloud data platform, offering scalability, reliability, and a range of cloud-based capabilities.", "reference": "https://docs.snowflake.com/en/user-guide/intro-cloud-platforms.html"}, {"id": 184, "area": "Account Access and Security", "question": "What Snowflake role must be granted for a user to create and manage accounts?", "options": ["A) ACCOUNTADMIN", "B) ORGADMIN", "C) SECURITYADMIN", "D) SYSADMIN"], "chooseN": 1, "correct": ["ORGADMIN"], "explanation": "The ORGADMIN role is required to create and manage accounts. ORGADMIN manages operations at the organization level, including creating, renaming, and dropping accounts. ACCOUNTADMIN is the top-level role within a single account but cannot create new accounts. SECURITYADMIN manages users/roles and grants within an account. SYSADMIN manages warehouses and databases within an account.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-overview.html"}, {"id": 185, "area": "Performance Concepts", "question": "Assume there is a table consisting of five micro-partitions with values ranging from A to Z. Which diagram indicates a well-clustered table?", "options": ["A) A", "B) B", "C) C", "D) D"], "chooseN": 1, "correct": ["A"], "explanation": "The clustering depth for a populated table measures the average depth (1 or greater) of the overlapping micro-partitions for specified columns in a table. The smaller the average depth, the better clustered the table is with regards to the specified columns.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions.html"}, {"id": 186, "area": "Performance Concepts", "question": "What feature can be used to reorganize a very large table on one or more columns?", "options": ["A) Micro-partitions", "B) Clustering keys", "C) Key partitions", "D) Clustered partitions"], "chooseN": 1, "correct": ["Clustering keys"], "explanation": "Clustering keys in Snowflake are used to reorganize data in a table based on one or more specified columns. By defining clustering keys, Snowflake can optimize how the data is stored and accessed, improving query performance on large tables.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-keys.html"}, {"id": 187, "area": "Performance Concepts", "question": "What is an advantage of using an explain plan instead of the query profiler to evaluate the performance of a query?", "options": ["A) The explain plan output is available graphically.", "B) An explain plan can be used to conduct performance analysis without executing a query.", "C) An explain plan will handle queries with temporary tables and the query profiler will not.", "D) An explain plan's output will display automatic data skew optimization information."], "chooseN": 1, "correct": ["An explain plan can be used to conduct performance analysis without executing a query."], "explanation": "The key advantage of using an explain plan over a query profiler is that the explain plan allows for performance analysis without actually executing the query. This feature is beneficial for understanding and optimizing query plans in advance.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/explain.html"}, {"id": 188, "area": "Data Transformations", "question": "Which data types are supported by Snowflake when using semi-structured data? (Choose two.)", "options": ["A) VARIANT", "B) VARRAY", "C) STRUCT", "D) ARRAY", "E) QUEUE"], "chooseN": 2, "correct": ["VARIANT", "ARRAY"], "explanation": "Snowflake supports the VARIANT and ARRAY data types for handling semi-structured data. VARIANT is a flexible data type that can store values of any other type, including structured and semi-structured data, while ARRAY is used specifically for handling arrays in semi-structured data.", "reference": "https://docs.snowflake.com/en/sql-reference/data-types-semistructured.html"}, {"id": 189, "area": "Data Loading and Unloading", "question": "Why does Snowflake recommend file sizes of 100-250 MB compressed when loading data?", "options": ["A) Optimizes the virtual warehouse size and multi-cluster setting to economy mode", "B) Allows a user to import the files in a sequential order", "C) Increases the latency staging and accuracy when loading the data", "D) Allows optimization of parallel operations"], "chooseN": 1, "correct": ["Allows optimization of parallel operations"], "explanation": "Snowflake recommends file sizes of 100-250 MB compressed when loading data because this size range allows for the optimization of parallel operations. It ensures that multiple files can be loaded in parallel, efficiently utilizing Snowflake's distributed and scalable architecture.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-considerations-prepare.html#general-file-sizing-guidelines"}, {"id": 190, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which of the following features are available with the Snowflake Enterprise edition? (Choose two.)", "options": ["A) Database replication and failover", "B) Automated index management", "C) Customer managed keys (Tri-secret secure)", "D) Extended time travel", "E) Native support for geospatial data"], "chooseN": 2, "correct": ["Extended time travel", "Native support for geospatial data"], "explanation": "The correct answer is: Extended time travel, Native support for geospatial data. The editions matrix shows: Extended Time Travel (up to 90 days) is Enterprise+. Native geospatial data support is available in all editions including Enterprise. Database replication is Standard+ but Failover/failback is Business Critical+ only, so 'Database replication and failover' combined is NOT Enterprise. Tri-Secret Secure is Business Critical+. Correct answers are D+E. The explanation already mentions D+E but contradicts the marked A+D. Reference: https://docs.snowflake.com/en/user-guide/intro-editions#feature-and-edition-matrix", "reference": "https://docs.snowflake.com/en/user-guide/intro-editions"}, {"id": 191, "area": "Data Loading and Unloading", "question": "What is the default file size when unloading data from Snowflake using the COPY command?", "options": ["A) 5 MB", "B) 8 GB", "C) 16 MB", "D) 32 MB"], "chooseN": 1, "correct": ["16 MB"], "explanation": "When unloading data from Snowflake using the COPY command, the default file size is 16 MB. This size is determined by Snowflake to balance efficiency and manageability for common data unloading scenarios.", "reference": "https://docs.snowflake.com/en/user-guide/data-unload-considerations.html"}, {"id": 192, "area": "Data Protection and Data Sharing", "question": "What features that are part of the Continuous Data Protection (CDP) feature set in Snowflake do not require additional configuration? (Choose two.)", "options": ["A) Row level access policies", "B) Data masking policies", "C) Data encryption", "D) Time Travel", "E) External tokenization"], "chooseN": 2, "correct": ["Data encryption", "Time Travel"], "explanation": "Within Snowflake's Continuous Data Protection (CDP) feature set, Data encryption and Time Travel do not require additional configuration. Data encryption is inherent to Snowflake's security model, while Time Travel is a built-in feature enabling data access to historical states without extra setup.", "reference": "https://docs.snowflake.com/en/user-guide/data-cdp"}, {"id": 193, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which Snowflake layer is always leveraged when accessing a query from the result cache?", "options": ["A) Metadata", "B) Data Storage", "C) Compute", "D) Cloud Services"], "chooseN": 1, "correct": ["Cloud Services"], "explanation": "The Cloud Services layer manages medatadata managment.", "reference": "https://docs.snowflake.com/en/user-guide/intro-key-concepts"}, {"id": 194, "area": "Account Access and Security", "question": "Which connectors are available in the downloads section of the Snowflake web interface (UI)? (Choose two.)", "options": ["A) SnowSQL", "B) JDBC", "C) ODBC", "D) HIVE", "E) Scala"], "chooseN": 2, "correct": ["JDBC", "ODBC"], "explanation": "The Snowflake downloads pages include JDBC and ODBC among the available client drivers/connectors. The documentation lists both \"JDBC client driver\" and \"ODBC client driver\" as supported download options, while SnowSQL is documented separately as a client. Therefore, the two correct choices are JDBC and ODBC.", "reference": "https://docs.snowflake.com/en/user-guide/snowflake-client-repository"}, {"id": 195, "area": "Data Protection and Data Sharing", "question": "A Snowflake Administrator needs to ensure that sensitive corporate data in Snowflake tables is not visible to end users, but is partially visible to functional managers. How can this requirement be met?", "options": ["A) Use data encryption.", "B) Use dynamic data masking.", "C) Use secure materialized views.", "D) Revoke all roles for functional managers and end users."], "chooseN": 1, "correct": ["Use dynamic data masking."], "explanation": "Dynamic data masking in Snowflake is a feature that can be used to ensure sensitive corporate data in tables is not fully visible to end users, but can be partially visible to functional managers. This is achieved by applying masking policies that selectively reveal data based on user roles or conditions.", "reference": "https://docs.snowflake.com/en/user-guide/security-column-ddm.html"}, {"id": 196, "area": "Data Loading and Unloading", "question": "Users are responsible for data storage costs until what occurs?", "options": ["A) Data expires from Time Travel", "B) Data expires from Fail-safe", "C) Data is deleted from a table", "D) Data is truncated from a table"], "chooseN": 1, "correct": ["Data expires from Fail-safe"], "explanation": "Snowflake charges storage fees for historical data during both Time Travel and Fail-safe. Those costs stop only after the Fail-safe period ends, not when the data is deleted from a table.", "reference": "https://docs.snowflake.com/en/user-guide/data-storage.html"}, {"id": 197, "area": "Data Loading and Unloading", "question": "A user has an application that writes a new file to a cloud storage location every 5 minutes. What would be the MOST efficient way to get the files into Snowflake?", "options": ["A) Create a task that runs a COPY INTO operation from an external stage every 5 minutes.", "B) Create a task that PUTS the files in an internal stage and automate the data loading wizard.", "C) Create a task that runs a GET operation to intermittently check for new files.", "D) Set up cloud provider notifications on the file location and use Snowpipe with auto-ingest."], "chooseN": 1, "correct": ["Set up cloud provider notifications on the file location and use Snowpipe with auto-ingest."], "explanation": "The most efficient way to load new files into Snowflake, which are written to a cloud storage location every 5 minutes, is by setting up cloud provider notifications on the file location and using Snowpipe with auto-ingest. This approach automates the data ingestion process in real-time as new files are created.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-snowpipe-intro"}, {"id": 198, "area": "Performance Concepts", "question": "What affects whether the query results cache can be used?", "options": ["A) If the query contains a deterministic function", "B) If the virtual warehouse has been suspended", "C) If the referenced data in the table has changed", "D) If multiple users are using the same virtual warehouse"], "chooseN": 1, "correct": ["If the referenced data in the table has changed"], "explanation": "The usability of the query results cache in Snowflake is primarily affected by whether the referenced data in the table has changed since the last query execution. If the data has changed, the cache cannot be used, as it would lead to stale or inaccurate results.", "reference": "https://docs.snowflake.com/en/user-guide/querying-persisted-results"}, {"id": 199, "area": "Performance Concepts", "question": "Which of the following is an example of an operation that can be completed without requiring compute, assuming no queries have been executed previously?", "options": ["A) SELECT SUM (ORDER_AMT) FROM SALES;", "B) SELECT AVG(ORDER_QTY) FROM SALES;", "C) SELECT MIN(ORDER_AMT) FROM SALES;", "D) SELECT ORDER_AMT * ORDER_QTY FROM SALES;"], "chooseN": 1, "correct": ["SELECT MIN(ORDER_AMT) FROM SALES;"], "explanation": "MIN is an operation that can be completed without requiring compute.", "reference": "https://docs.snowflake.com/en/user-guide/performance-query-warehouse-cache"}, {"id": 200, "area": "Data Loading and Unloading", "question": "How many days is load history for Snowpipe retained?", "options": ["A) 1 day", "B) 7 days", "C) 14 days", "D) 64 days"], "chooseN": 1, "correct": ["14 days"], "explanation": "Snowflake retains the load history for Snowpipe for 14 days. This allows users to view and audit the history of data loads performed by Snowpipe over a two-week period.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-snowpipe-intro.html"}, {"id": 201, "area": "Snowflake Data Cloud Features & Architecture", "question": "What Snowflake features allow virtual warehouses to handle high concurrency workloads? (Choose two.)", "options": ["A) The ability to scale up warehouses", "B) The use of warehouse auto scaling", "C) The ability to resize warehouses", "D) Use of multi-clustered warehouses", "E) The use of warehouse indexing"], "chooseN": 2, "correct": ["The use of warehouse auto scaling", "Use of multi-clustered warehouses"], "explanation": "Snowflake's features that enable virtual warehouses to handle high concurrency workloads include the use of warehouse auto scaling and the use of multi-clustered warehouses. Auto scaling dynamically adjusts the compute resources based on workload demands, and multi-clustered warehouses provide additional compute clusters to manage concurrent queries effectively.", "reference": "https://docs.snowflake.com/en/sql-reference/parameters#max-concurrency-level"}, {"id": 202, "area": "Data Loading and Unloading", "question": "Which COPY INTO command outputs the data into one file?", "options": ["A) SINGLE=TRUE", "B) MAX_FILE_NUMBER=1", "C) FILE_NUMBER=1", "D) MULTIPLE=FALSE"], "chooseN": 1, "correct": ["SINGLE=TRUE"], "explanation": "The COPY INTO command with the parameter 'SINGLE=TRUE' is used in Snowflake to output the data into one file. This parameter ensures that the data is consolidated into a single file rather than being distributed across multiple files.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-location.html"}, {"id": 203, "area": "Account Access and Security", "question": "In which scenarios would a user have to pay Cloud Services costs? (Choose two.)", "options": ["A) Compute Credits = 50 Credits Cloud Services = 10", "B) Compute Credits = 80 Credits Cloud Services = 5", "C) Compute Credits = 100 Credits Cloud Services = 9", "D) Compute Credits = 120 Credits Cloud Services = 10", "E) Compute Credits = 200 Credits Cloud Services = 26"], "chooseN": 2, "correct": ["Compute Credits = 50 Credits Cloud Services = 10", "Compute Credits = 200 Credits Cloud Services = 26"], "explanation": "Usage for cloud services is charged only if the daily consumption of cloud services exceeds 10% of the daily usage of virtual warehouses.", "reference": "https://docs.snowflake.com/en/user-guide/cost-understanding-compute"}, {"id": 204, "area": "Data Protection and Data Sharing", "question": "A user created a new worksheet within the Snowsight UI and wants to share this with teammates. How can this worksheet be shared?", "options": ["A) Create a zero-copy clone of the worksheet and grant permissions to teammates.", "B) Create a private Data Exchange so that any teammate can use the worksheet.", "C) Share the worksheet with teammates within Snowsight.", "D) Create a database and grant all permissions to teammates."], "chooseN": 1, "correct": ["Share the worksheet with teammates within Snowsight."], "explanation": "In Snowflake's Snowsight UI, a user can share a worksheet directly with teammates within the same interface. This allows for easy and collaborative access to the worksheet without the need for cloning or creating separate data exchanges.", "reference": "https://docs.snowflake.com/en/user-guide/ui-snowsight-worksheets-gs#sharing-worksheets-and-folders"}, {"id": 205, "area": "Account Access and Security", "question": "How can a row access policy be applied to a table or a view? (Choose two.)", "options": ["A) Within the policy DDL", "B) Within the create table or create view DDL", "C) By future APPLY for all objects in a schema", "D) Within a control table", "E) Using the command ALTER ADD ROW ACCESS POLICY ;"], "chooseN": 2, "correct": ["Within the create table or create view DDL", "Using the command ALTER ADD ROW ACCESS POLICY ;"], "explanation": "A row access policy in Snowflake can be applied to a table or a view either within the create table or create view DDL, or by using the 'ALTER TABLE/VIEW ADD ROW ACCESS POLICY' command. These methods integrate the policy directly into the table or view's access control.", "reference": "https://docs.snowflake.com/en/user-guide/security-row.html#defining-row-access-policies"}, {"id": 206, "area": "Data Loading and Unloading", "question": "Which command can be used to load data files into a Snowflake stage?", "options": ["A) JOIN", "B) COPY INTO", "C) PUT", "D) GET"], "chooseN": 1, "correct": ["PUT"], "explanation": "The 'PUT' command in Snowflake is used to load data files into a stage. This command uploads data files from a local file system to a Snowflake stage, making them available for subsequent loading into tables.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-local-file-system-stage.html#put"}, {"id": 207, "area": "Data Protection and Data Sharing", "question": "What types of data listings are available in the Snowflake Data Marketplace? (Choose two.)", "options": ["A) Reader", "B) Consumer", "C) Vendor", "D) Standard", "E) Personalized"], "chooseN": 2, "correct": ["Standard", "Personalized"], "explanation": "The Snowflake Data Marketplace offers two types of data listings, Standard Data (Free) Listings and Personalized (Private)Data Listings. The key difference between standard and personalized listings is the ability to access the data share. Personalized listings allow you to control which consumers can access the data.", "reference": "https://other-docs.snowflake.com/en/collaboration/collaboration-marketplace-about"}, {"id": 208, "area": "Data Protection and Data Sharing", "question": "What is the maximum Time Travel retention period for a temporary Snowflake table?", "options": ["A) 90 days", "B) 1 day", "C) 7 days", "D) 45 days"], "chooseN": 1, "correct": ["1 day"], "explanation": "For a temporary table in Snowflake, the maximum and default Time Travel retention period is 1 day. This limited time travel capability is due to the temporary nature of these tables, which are designed for short-term data storage and processing.", "reference": "https://docs.snowflake.com/en/user-guide/tables-temp-transient.html#temporary-tables"}, {"id": 209, "area": "Performance Concepts", "question": "When should a multi-cluster warehouse be used in auto-scaling mode?", "options": ["A) When it is unknown how much compute power is needed", "B) If the select statement contains a large number of temporary tables or Common Table Expressions (CTEs)", "C) If the runtime of the executed query is very slow", "D) When a large number of concurrent queries are run on the same warehouse"], "chooseN": 1, "correct": ["When a large number of concurrent queries are run on the same warehouse"], "explanation": "A multi-cluster warehouse in auto-scaling mode is ideal when dealing with a large number of concurrent queries. This setup allows Snowflake to automatically scale compute resources to handle increased query loads efficiently.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-multicluster.html"}, {"id": 210, "area": "Data Protection and Data Sharing", "question": "What happens when a cloned table is replicated to a secondary database? (Choose two.)", "options": ["A) A read-only copy of the cloned tables is stored.", "B) The replication will not be successful.", "C) The physical data is replicated.", "D) Additional costs for storage are charged to a secondary account.", "E) Metadata pointers to cloned tables are replicated."], "chooseN": 2, "correct": ["The physical data is replicated.", "Additional costs for storage are charged to a secondary account."], "explanation": "When a cloned table is replicated to a secondary database, its physical data is replicated, which increases storage usage in the target account. In some cases this can lead to additional storage costs. Metadata pointers are not the documented behavior for this scenario.", "reference": "https://docs.snowflake.com/en/user-guide/account-replication-considerations"}, {"id": 211, "area": "Data Loading and Unloading", "question": "Snowflake supports the use of external stages with which cloud platforms? (Choose three.)", "options": ["A) Amazon Web Services", "B) Docker", "C) IBM Cloud", "D) Microsoft Azure Cloud", "E) Google Cloud Platform", "F) Oracle Cloud"], "chooseN": 3, "correct": ["Amazon Web Services", "Microsoft Azure Cloud", "Google Cloud Platform"], "explanation": "Snowflake supports the use of external stages with Amazon Web Services, Microsoft Azure Cloud, and Google Cloud Platform. These integrations allow Snowflake to leverage cloud storage services from these providers for staging and data processing.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/create-stage"}, {"id": 212, "area": "Data Transformations", "question": "What is a limitation of a Materialized View?", "options": ["A) A Materialized View cannot support any aggregate functions", "B) A Materialized View can only reference up to two tables", "C) A Materialized View cannot be joined with other tables", "D) A Materialized View cannot be defined with a JOIN"], "chooseN": 1, "correct": ["A Materialized View cannot be defined with a JOIN"], "explanation": "A key limitation of Materialized Views in Snowflake is that they cannot be defined with a JOIN. The underlying query of a materialized view can only reference a single table. However, materialized views themselves can be joined with other tables in regular queries. For complex queries involving multiple tables, Snowflake recommends using Dynamic Tables as an alternative.", "reference": "https://docs.snowflake.com/en/user-guide/views-materialized.html#limitations"}, {"id": 213, "area": "Account Access and Security", "question": "In the Snowflake access control model, which entity owns an object by default?", "options": ["A) The user who created the object", "B) The SYSADMIN role", "C) Ownership depends on the type of object", "D) The role used to create the object"], "chooseN": 1, "correct": ["The role used to create the object"], "explanation": "In Snowflake's access control model, the role used to create an object becomes the owner of that object by default. This ownership model ties the control and management of objects to roles, rather than individual users.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-overview.html#ownership"}, {"id": 214, "area": "Data Protection and Data Sharing", "question": "What is the minimum Snowflake edition required to use Dynamic Data Masking?", "options": ["A) Standard", "B) Enterprise", "C) Business Critical", "D) Virtual Private Snowflake (VPS)"], "chooseN": 1, "correct": ["Enterprise"], "explanation": "Dynamic Data Masking in Snowflake requires at least the Enterprise edition. This advanced feature, which allows for the dynamic obfuscation of data based on user roles and permissions, is not available in the Standard edition.", "reference": "https://docs.snowflake.com/en/user-guide/security-column-ddm.html"}, {"id": 215, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which services does the Snowflake Cloud Services layer manage? (Choose two.)", "options": ["A) Compute resources", "B) Query execution", "C) Authentication", "D) Data storage", "E) Metadata"], "chooseN": 2, "correct": ["Authentication", "Metadata"], "explanation": "- Authentication: La capa de Cloud Services gestiona la autenticacion de usuarios, verificando credenciales y controlando el acceso al sistema.\n- Metadata: La capa de Cloud Services gestiona los metadatos, incluyendo informacion sobre bases de datos, esquemas, tablas, micro-particiones y estadisticas de columnas.\n- Compute resources: Los recursos de computo son gestionados por la capa de Query Processing (Virtual Warehouses), no por Cloud Services.\n- Query execution: La ejecucion de consultas se realiza en la capa de Query Processing (Compute). Cloud Services solo maneja el parsing y la optimizacion de consultas, no su ejecucion.\n- Data storage: El almacenamiento de datos es gestionado por la capa de Database Storage, que es independiente de Cloud Services.\n\nSegun la documentacion oficial de Snowflake, la capa de Cloud Services incluye: seguridad, autenticacion, control de acceso, gestion de infraestructura, gestion de metadatos, parsing y optimizacion de consultas.", "reference": "https://docs.snowflake.com/en/user-guide/intro-key-concepts#cloud-services"}, {"id": 216, "area": "Data Protection and Data Sharing", "question": "A company needs to allow some users to see Personally Identifiable Information (PII) while limiting other users from seeing the full value of the PII. Which Snowflake feature will support this?", "options": ["A) Row access policies", "B) Data masking policies", "C) Data encryption", "D) Role-based access control"], "chooseN": 1, "correct": ["Data masking policies"], "explanation": "Data masking policies in Snowflake are designed to handle scenarios where certain users need to see full data (like PII), while others should have restricted access. These policies allow for conditional masking of data based on user roles and permissions.", "reference": "https://docs.snowflake.com/en/user-guide/security-column-ddm.html"}, {"id": 217, "area": "Data Loading and Unloading", "question": "A user has unloaded data from a Snowflake table to an external stage. Which command can be used to verify if data has been uploaded to the external stage named my_stage?", "options": ["A) view @my_stage", "B) list @my_stage", "C) show @my_stage", "D) display @my_stage"], "chooseN": 1, "correct": ["list @my_stage"], "explanation": "To verify if data has been successfully uploaded to an external stage in Snowflake, the 'list @my_stage' command is used. This command provides a list of files in the specified stage, allowing users to check the presence of their data.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/list.html"}, {"id": 218, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which tasks are performed in the Snowflake Cloud Services layer? (Choose two.)", "options": ["A) Management of metadata", "B) Computing the data", "C) Maintaining Availability Zones", "D) Infrastructure security", "E) Parsing and optimizing queries"], "chooseN": 2, "correct": ["Management of metadata", "Parsing and optimizing queries"], "explanation": "In the Snowflake Cloud Services layer, tasks like the management of metadata and parsing and optimizing queries are performed. This layer is responsible for handling aspects of data storage that are abstracted from the end-user, including optimizing the execution of queries.", "reference": "https://docs.snowflake.com/en/user-guide/intro-key-concepts.html#cloud-services-layer"}, {"id": 219, "area": "Data Protection and Data Sharing", "question": "What is true about sharing data in Snowflake? (Choose two.)", "options": ["A) The Data Consumer pays for data storage as well as for data computing.", "B) The shared data is copied into the Data Consumer account, so the Consumer can modify it without impacting the base data of the Provider.", "C) A Snowflake account can both provide and consume shared data.", "D) The Provider is charged for compute resources used by the Data Consumer to query the shared data.", "E) The Data Consumer pays only for compute resources to query the shared data."], "chooseN": 2, "correct": ["A Snowflake account can both provide and consume shared data.", "The Data Consumer pays only for compute resources to query the shared data."], "explanation": "In Snowflake data sharing, an account can act both as a provider and a consumer of shared data. Also, the Data Consumer is responsible only for the compute resources required to query the shared data, not for data storage.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-intro.html"}, {"id": 220, "area": "Data Transformations", "question": "The following JSON is stored in a VARIANT column called src of the CAR_SALES table: A user needs to extract the dealership information from the JSON. How can this be accomplished?", "options": ["A) select src:dealership from car_sales;", "B) select src.dealership from car_sales;", "C) select src:Dealership from car_sales;", "D) select dealership from car_sales;"], "chooseN": 1, "correct": ["select src:dealership from car_sales;"], "explanation": "To extract information from a JSON object stored in a VARIANT column in Snowflake, the column name followed by a colon and the JSON property name is used. In this case, 'select src:dealership from car_sales;' will correctly extract the dealership information.", "reference": "https://docs.snowflake.com/en/user-guide/json-basics.html"}, {"id": 221, "area": "Performance Concepts", "question": "Which of the following significantly improves the performance of selective point lookup queries on a table?", "options": ["A) Clustering", "B) Materialized Views", "C) Zero-copy Cloning", "D) Search Optimization Service"], "chooseN": 1, "correct": ["Search Optimization Service"], "explanation": "The Search Optimization Service in Snowflake significantly improves the performance of selective point lookup queries on a table. It creates an optimized search index, speeding up queries that access a small subset of rows.", "reference": "https://docs.snowflake.com/en/user-guide/search-optimization-service"}, {"id": 222, "area": "Data Protection and Data Sharing", "question": "Which of the following accurately describes shares?", "options": ["A) Tables, secure views, and secure UDFs can be shared", "B) Shares can be shared", "C) Data consumers can clone a new table from a share", "D) Access to a share cannot be revoked once granted"], "chooseN": 1, "correct": ["Tables, secure views, and secure UDFs can be shared"], "explanation": "In Snowflake, shares allow for sharing tables, secure views, and secure user-defined functions (UDFs). This feature enables organizations to share data securely without duplicating or moving data.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-intro.html#sharing-data-securely-with-shares"}, {"id": 223, "area": "Account Access and Security", "question": "What are best practice recommendations for using the ACCOUNTADMIN system-defined role in Snowflake? (Choose two.)", "options": ["A) Ensure all ACCOUNTADMIN roles use Multi-factor Authentication (MFA).", "B) All users granted ACCOUNTADMIN role must be owned by the ACCOUNTADMIN role.", "C) The ACCOUNTADMIN role must be granted to only one user.", "D) Assign the ACCOUNTADMIN role to at least two users, but as few as possible.", "E) All users granted ACCOUNTADMIN role must also be granted SECURITYADMIN role."], "chooseN": 2, "correct": ["Ensure all ACCOUNTADMIN roles use Multi-factor Authentication (MFA).", "Assign the ACCOUNTADMIN role to at least two users, but as few as possible."], "explanation": "Best practices for the ACCOUNTADMIN role in Snowflake include ensuring that all users with this role use Multi-factor Authentication (MFA) for added security. Also, it is advisable to assign this role to at least two users to ensure availability, but to as few users as possible to maintain strict control.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-considerations"}, {"id": 224, "area": "Performance Concepts", "question": "In the query profiler view for a query, which components represent areas that can be used to help optimize query performance? (Choose two.)", "options": ["A) Bytes scanned", "B) Bytes sent over the network", "C) Number of partitions scanned", "D) Percentage scanned from cache", "E) External bytes scanned"], "chooseN": 2, "correct": ["Bytes scanned", "Number of partitions scanned"], "explanation": "In the query profiler view, 'Bytes scanned' and 'Number of partitions scanned' are key components that can help in optimizing query performance. Reducing the amount of data scanned and minimizing the number of partitions accessed can significantly improve query efficiency and speed.", "reference": "https://docs.snowflake.com/en/user-guide/ui-query-profile"}, {"id": 225, "area": "Data Protection and Data Sharing", "question": "What is the minimum Snowflake edition required for row-level security?", "options": ["A) Standard", "B) Enterprise", "C) Business Critical", "D) Virtual Private Snowflake"], "chooseN": 1, "correct": ["Enterprise"], "explanation": "Row-level security in Snowflake requires at least the Enterprise edition. This feature allows for fine-grained access control to rows within a database table based on custom security policies.", "reference": "https://docs.snowflake.com/en/user-guide/security-row-intro"}, {"id": 226, "area": "Data Protection and Data Sharing", "question": "What is the minimum Fail-safe retention time period for transient tables?", "options": ["A) 1 day", "B) 7 days", "C) 12 hours", "D) 0 days"], "chooseN": 1, "correct": ["0 days"], "explanation": "Transient tables in Snowflake do not have a Fail-safe period. Therefore, the minimum Fail-safe retention time for transient tables is 0 days. These tables are designed for scenarios where long-term data protection is not required.", "reference": "https://docs.snowflake.com/en/user-guide/tables-temp-transient.html#transient-tables"}, {"id": 227, "area": "Snowflake Data Cloud Features & Architecture", "question": "What is a machine learning and data science partner within the Snowflake Partner Ecosystem?", "options": ["A) Informatica", "B) Power BI", "C) Adobe", "D) Data Robot"], "chooseN": 1, "correct": ["Data Robot"], "explanation": "Data Robot is a notable partner within the Snowflake Partner Ecosystem for machine learning and data science. It provides advanced machine learning capabilities that integrate with Snowflake’s data platform to enhance data-driven decision-making.", "reference": "https://www.datarobot.com/partners/technology-partners/snowflake/"}, {"id": 228, "area": "Data Protection and Data Sharing", "question": "Which statements are correct concerning the leveraging of third-party data from the Snowflake Data Marketplace? (Choose two.)", "options": ["A) Data is live, ready-to-query, and can be personalized.", "B) Data needs to be loaded into a cloud provider as a consumer account.", "C) Data is not available for copying or moving to an individual Snowflake account.", "D) Data is available without copying or moving.", "E) Data transformations are required when combining Data Marketplace datasets with existing data in Snowflake."], "chooseN": 2, "correct": ["Data is live, ready-to-query, and can be personalized.", "Data is available without copying or moving."], "explanation": "In the Snowflake Data Marketplace, data is available live and ready-to-query, and it can be personalized according to user needs. Furthermore, the data can be accessed directly without the need for copying or moving it to an individual Snowflake account, enabling seamless integration and analysis.", "reference": "https://docs.snowflake.com/en/user-guide/data-marketplace-intro.html"}, {"id": 229, "area": "Data Transformations", "question": "What impacts the credit consumption of maintaining a materialized view? (Choose two.)", "options": ["A) Whether or not it is also a secure view", "B) How often the underlying base table is queried", "C) How often the base table changes", "D) Whether the materialized view has a cluster key defined", "E) How often the materialized view is queried"], "chooseN": 2, "correct": ["How often the base table changes", "Whether the materialized view has a cluster key defined"], "explanation": "The credit consumption for maintaining a materialized view in Snowflake is impacted by how often the base table changes and how often the materialized view is queried. Changes in the base table necessitate updates to the materialized view, consuming credits for maintenance operations. The frequency of querying affects the overall cost-benefit analysis and resource utilization.", "reference": "https://docs.snowflake.com/en/user-guide/views-materialized.html#credit-usage-and-performance-considerations"}, {"id": 230, "area": "Data Loading and Unloading", "question": "What COPY INTO SQL command should be used to unload data into multiple files?", "options": ["A) SINGLE=TRUE", "B) MULTIPLE=TRUE", "C) MULTIPLE=FALSE", "D) SINGLE=FALSE"], "chooseN": 1, "correct": ["SINGLE=FALSE"], "explanation": "The 'COPY INTO' SQL command with the parameter 'SINGLE=FALSE' should be used to unload data into multiple files in Snowflake. This setting allows for the distribution of data across multiple files instead of consolidating it into a single file.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-location.html"}, {"id": 231, "area": "Data Transformations", "question": "When cloning a database containing stored procedures and regular views, that have fully qualified table references, which of the following will occur?", "options": ["A) The cloned views and the stored procedures will reference the cloned tables in the cloned database.", "B) An error will occur, as views with qualified references cannot be cloned.", "C) An error will occur, as stored objects cannot be cloned.", "D) The stored procedures and views will refer to tables in the source database."], "chooseN": 1, "correct": ["The stored procedures and views will refer to tables in the source database."], "explanation": "When cloning a database in Snowflake, stored procedures and views with fully qualified table references will continue to reference the original tables in the source database. This is because fully qualified references (database.schema.table) are preserved exactly as written, maintaining the explicit cross-database references even after cloning.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/create-clone"}, {"id": 232, "area": "Data Loading and Unloading", "question": "When loading data into Snowflake, how should the data be organized?", "options": ["A) Into single files with 100-250 MB of compressed data per file", "B) Into single files with 1-100 MB of compressed data per file", "C) Into files of maximum size of 1 GB of compressed data per file", "D) Into files of maximum size of 4 GB of compressed data per file"], "chooseN": 1, "correct": ["Into single files with 100-250 MB of compressed data per file"], "explanation": "When loading data into Snowflake, it is recommended to organize the data into single files with 100-250 MB of compressed data per file. This size range is optimal for parallel processing and efficient loading.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-considerations-prepare.html#general-file-sizing-guidelines"}, {"id": 233, "area": "Data Protection and Data Sharing", "question": "Which of the following objects can be directly restored using the UNDROP command? (Choose two.)", "options": ["A) Schema", "B) View", "C) Internal stage", "D) Table", "E) User", "F) Role"], "chooseN": 2, "correct": ["Schema", "Table"], "explanation": "The UNDROP command supports restoring schemas (UNDROP SCHEMA) and tables (UNDROP TABLE) directly, among other object types like databases and tags. Views are NOT supported by UNDROP -- there is no UNDROP VIEW command in Snowflake. Internal stages, users, and roles also cannot be restored via UNDROP. If a view is dropped, it must be recreated manually using CREATE VIEW.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/undrop.html"}, {"id": 234, "area": "Account Access and Security", "question": "Which Snowflake SQL statement would be used to determine which users and roles have access to a role called MY_ROLE?", "options": ["A) SHOW GRANTS OF ROLE MY_ROLE", "B) SHOW GRANTS TO ROLE MY_ROLE", "C) SHOW GRANTS FOR ROLE MY_ROLE", "D) SHOW GRANTS ON ROLE MY_ROLE"], "chooseN": 1, "correct": ["SHOW GRANTS TO ROLE MY_ROLE"], "explanation": "The SQL statement 'SHOW GRANTS TO ROLE MY_ROLE' is used in Snowflake to determine which users and roles have access to a specified role, in this case, MY_ROLE. This statement displays the grants of privileges to the role.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/show-grants.html"}, {"id": 235, "area": "Account Access and Security", "question": "What is the MINIMUM edition of Snowflake that is required to use a SCIM security integration?", "options": ["A) Business Critical Edition", "B) Standard Edition", "C) Virtual Private Snowflake (VPS)", "D) Enterprise Edition"], "chooseN": 1, "correct": ["Enterprise Edition"], "explanation": "The minimum edition of Snowflake required to use SCIM (System for Cross-domain Identity Management) security integration is the Enterprise Edition. This edition provides the necessary features and capabilities to support advanced security integrations like SCIM.", "reference": "https://docs.snowflake.com/en/user-guide/scim-intro"}, {"id": 236, "area": "Data Protection and Data Sharing", "question": "A user created a transient table and made several changes to it over the course of several days. Three days after the table was created, the user would like to go back to the first version of the table. How can this be accomplished?", "options": ["A) Use Time Travel, as long as DATA_RETENTION_TIME_IN_DAYS was set to at least 3 days.", "B) The transient table version cannot be retrieved after 24 hours.", "C) Contact Snowflake Support to have the data retrieved from Fail-safe storage.", "D) Use the FAIL_SAFE parameter for Time Travel to retrieve the data from Fail-safe storage."], "chooseN": 1, "correct": ["The transient table version cannot be retrieved after 24 hours."], "explanation": "Transient tables in Snowflake do not support Time Travel for more than 24 hours. Therefore, it is not possible to revert to the first version of a transient table three days after its creation as Time Travel is not available beyond a 24-hour window for these types of tables.", "reference": "https://docs.snowflake.com/en/user-guide/tables-temp-transient.html#transient-tables"}, {"id": 237, "area": "Performance Concepts", "question": "When reviewing the load for a warehouse using the load monitoring chart, the chart indicates that a high volume of queries is always queuing in the warehouse. According to recommended best practice, what should be done to reduce the queue volume? (Choose two.)", "options": ["A) Use multi-clustered warehousing to scale out warehouse capacity.", "B) Scale up the warehouse size to allow queries to execute faster.", "C) Stop and start the warehouse to clear the queued queries.", "D) Migrate some queries to a new warehouse to reduce load.", "E) Limit user access to the warehouse so fewer queries are run against it."], "chooseN": 2, "correct": ["Use multi-clustered warehousing to scale out warehouse capacity.", "Migrate some queries to a new warehouse to reduce load."], "explanation": "To address a high volume of queries queuing in a warehouse, using multi-clustered warehousing to scale out the warehouse capacity and migrating some queries to a new warehouse to distribute the load are effective strategies. These approaches help in managing query workload more efficiently and reduce queue volumes.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-multicluster.html"}, {"id": 238, "area": "Data Protection and Data Sharing", "question": "Which of the following features, associated with Continuous Data Protection (CDP), require additional Snowflake-provided data storage? (Choose two.)", "options": ["A) Tri-Secret Secure", "B) Time Travel", "C) Fail-safe", "D) Data encryption", "E) External stages"], "chooseN": 2, "correct": ["Time Travel", "Fail-safe"], "explanation": "Time Travel and Fail-safe are features associated with Continuous Data Protection in Snowflake that require additional data storage. Time Travel allows users to access historical data for a defined period, while Fail-safe provides an extra layer of protection by retaining data for a limited period even after the Time Travel period has expired.", "reference": "https://docs.snowflake.com/en/user-guide/data-cdp"}, {"id": 239, "area": "Account Access and Security", "question": "Where can a user find and review the failed logins of a specific user for the past 30 days?", "options": ["A) The USERS view in ACCOUNT_USAGE", "B) The LOGIN_HISTORY view in ACCOUNT_USAGE", "C) The ACCESS_HISTORY view in ACCOUNT_USAGE", "D) The SESSIONS view in ACCOUNT_USAGE"], "chooseN": 1, "correct": ["The LOGIN_HISTORY view in ACCOUNT_USAGE"], "explanation": "The LOGIN_HISTORY view in the ACCOUNT_USAGE schema provides information about login attempts, including failed logins, for users. This view can be used to review and analyze login activities over a specific period, such as the past 30 days.", "reference": "https://docs.snowflake.com/en/sql-reference/account-usage/login_history.html"}, {"id": 240, "area": "Data Transformations", "question": "What is the purpose of an External Function?", "options": ["A) To call code that executes outside of Snowflake", "B) To run a function in another Snowflake database", "C) To share data in Snowflake with external parties", "D) To ingest data from on-premises data sources"], "chooseN": 1, "correct": ["To call code that executes outside of Snowflake"], "explanation": "External Functions in Snowflake are designed to call code that executes outside of Snowflake. These functions enable Snowflake to integrate with external services and processes, allowing for extended functionality beyond the internal capabilities of Snowflake.", "reference": "https://docs.snowflake.com/en/sql-reference/external-functions-introduction.html"}, {"id": 241, "area": "Account Access and Security", "question": "Which of the following statements apply to Snowflake in terms of security? (Choose two.)", "options": ["A) Snowflake leverages a Role-Based Access Control (RBAC) model.", "B) Snowflake requires a user to configure an IAM user to connect to the database.", "C) All data in Snowflake is encrypted.", "D) Snowflake can run within a user's own Virtual Private Cloud (VPC).", "E) All data in Snowflake is compressed."], "chooseN": 2, "correct": ["Snowflake leverages a Role-Based Access Control (RBAC) model.", "All data in Snowflake is encrypted."], "explanation": "Snowflake's security model includes Role-Based Access Control (RBAC), which manages access and permissions through roles. Additionally, all data stored in Snowflake is encrypted, ensuring the security and privacy of the data.", "reference": "https://docs.snowflake.com/en/user-guide/security.html"}, {"id": 242, "area": "Performance Concepts", "question": "A single user of a virtual warehouse has set the warehouse to auto-resume and auto-suspend after 10 minutes. The warehouse is currently suspended and the user performs the following actions: Runs a query that takes 3 minutes to complete, Leaves for 15 minutes, Returns and runs a query that takes 10 seconds to complete, Manually suspends the warehouse as soon as the last query was completed. When the user returns, how much billable compute time will have been consumed?", "options": ["A) 4 minutes", "B) 10 minutes", "C) 14 minutes", "D) 24 minutes"], "chooseN": 1, "correct": ["14 minutes"], "explanation": "The warehouse auto-resumes for the first query (3 minutes), then auto-suspends after 10 minutes of inactivity. When the user returns and runs the second query, the warehouse resumes again. Therefore, the total billable compute time is 3 minutes (first query) + 10 minutes (idle time before auto-suspend) + 1 minute (second query and manual suspension) = 14 minutes.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-considerations.html#billing-and-credit-usage"}, {"id": 243, "area": "Performance Concepts", "question": "What can be used to view warehouse usage over time? (Choose two.)", "options": ["A) The LOAD HISTORY view", "B) The query history view", "C) The SHOW WAREHOUSES command", "D) The WAREHOUSE_METERING_HISTORY view", "E) The billing and usage tab in the Snowflake web UI"], "chooseN": 2, "correct": ["The WAREHOUSE_METERING_HISTORY view", "The billing and usage tab in the Snowflake web UI"], "explanation": "To view warehouse usage over time in Snowflake, the WAREHOUSE_METERING_HISTORY view in the ACCOUNT_USAGE schema and the billing and usage tab in the Snowflake web UI can be used. Both provide detailed information about warehouse usage and credit consumption.", "reference": "https://docs.snowflake.com/en/sql-reference/account-usage/warehouse_metering_history.html"}, {"id": 244, "area": "Performance Concepts", "question": "What actions will prevent leveraging of the ResultSet cache? (Choose two.)", "options": ["A) Removing a column from the query SELECT list", "B) Stopping the virtual warehouse that the query is running against", "C) Clustering of the data used by the query", "D) Executing the RESULTS_SCAN() table function", "E) Changing a column that is not in the cached query"], "chooseN": 2, "correct": ["Removing a column from the query SELECT list", "Clustering of the data used by the query"], "explanation": "Snowflake's result set cache requires specific conditions for reuse. (A) Removing a column from the SELECT list changes the query text, and the cache requires an exact query match -- any syntax difference prevents cache reuse. (C) Clustering (reclustering) data reorganizes the table's micro-partitions, and the docs state cache is invalidated when micro-partitions change. Stopping the warehouse (B) does not affect the result cache because it is managed by the Cloud Services layer. RESULT_SCAN (D) queries cached results and does not invalidate them.", "reference": "https://docs.snowflake.com/en/user-guide/querying-persisted-results"}, {"id": 245, "area": "Data Transformations", "question": "Which statement is true about running tasks in Snowflake?", "options": ["A) A task can be called using a CALL statement to run a set of predefined SQL commands.", "B) A task allows a user to execute a single SQL statement/command using a predefined schedule.", "C) A task allows a user to execute a set of SQL commands on a predefined schedule.", "D) A task can be executed using a SELECT statement to run a predefined SQL command."], "chooseN": 1, "correct": ["A task allows a user to execute a set of SQL commands on a predefined schedule."], "explanation": "In Snowflake, a task is used to execute a single SQL statement or command based on a predefined schedule. This feature allows for the automation of repeated SQL commands, such as data loading or transformation operations, at specified intervals.", "reference": "https://docs.snowflake.com/en/user-guide/tasks-intro.html"}, {"id": 246, "area": "Data Transformations", "question": "Which data types does Snowflake support when querying semi-structured data? (Choose two.)", "options": ["A) VARIANT", "B) VARCHAR", "C) XML", "D) ARRAY", "E) BLOB"], "chooseN": 2, "correct": ["VARIANT", "ARRAY"], "explanation": "When querying semi-structured data in Snowflake, the supported data types include VARIANT and ARRAY. VARIANT is a flexible data type capable of storing semi-structured data like JSON, XML, and Avro, while ARRAY is used for handling array data structures within semi-structured data formats.", "reference": "https://docs.snowflake.com/en/sql-reference/data-types-semistructured.html"}, {"id": 247, "area": "Snowflake Data Cloud Features & Architecture", "question": "In an auto-scaling multi-cluster virtual warehouse with the setting SCALING_POLICY = ECONOMY enabled, when is another cluster started?", "options": ["A) When the system has enough load for 2 minutes", "B) When the system has enough load for 6 minutes", "C) When the system has enough load for 8 minutes", "D) When the system has enough load for 10 minutes"], "chooseN": 1, "correct": ["When the system has enough load for 6 minutes"], "explanation": "With the SCALING_POLICY set to ECONOMY in an auto-scaling multi-cluster virtual warehouse, another cluster is started when the system has sustained enough load for 6 minutes. This policy is designed to optimize cost while providing the necessary compute resources for the workload.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-multicluster.html#scaling-policy"}, {"id": 248, "area": "Data Loading and Unloading", "question": "What is the following SQL command used for? Select * from table(validate(t1, job_id => '_last'));", "options": ["A) To validate external table files in table t1 across all sessions", "B) To validate task SQL statements against table t1 in the last 14 days", "C) To validate a file for errors before it gets executed using a COPY command", "D) To return errors from the last executed COPY command into table t1 in the current session"], "chooseN": 1, "correct": ["To return errors from the last executed COPY command into table t1 in the current session"], "explanation": "The SQL command 'Select * from table(validate(t1, job_id => '_last'))' in Snowflake is used to return errors from the last executed COPY command into table t1 in the current session. This command helps in diagnosing and understanding any issues that occurred during the last data loading operation.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/validate.html"}, {"id": 249, "area": "Performance Concepts", "question": "A sales table FCT_SALES has 100 million records. The following query was executed: SELECT COUNT (1) FROM FCT_SALES; How did Snowflake fulfill this query?", "options": ["A) Query against the result set cache", "B) Query against a virtual warehouse cache", "C) Query against the most-recently created micro-partition", "D) Query against the metadata cache"], "chooseN": 1, "correct": ["Query against the metadata cache"], "explanation": "Snowflake can fulfill a query like 'SELECT COUNT(1) FROM FCT_SALES' by querying against the metadata cache. This cache maintains metadata about tables and can quickly return aggregate information like row counts without scanning the entire table.", "reference": "https://docs.snowflake.com/en/user-guide/querying-metadata"}, {"id": 250, "area": "Performance Concepts", "question": "What happens when a virtual warehouse is resized?", "options": ["A) When increasing the size of an active warehouse the compute resource for all running and queued queries on the warehouse are affected.", "B) When reducing the size of a warehouse the compute resources are removed only when they are no longer being used to execute any current statements.", "C) The warehouse will be suspended while the new compute resource is provisioned and will resume automatically once provisioning is complete.", "D) Users who are trying to use the warehouse will receive an error message until the resizing is complete."], "chooseN": 1, "correct": ["When reducing the size of a warehouse the compute resources are removed only when they are no longer being used to execute any current statements."], "explanation": "When resizing a virtual warehouse in Snowflake, if the size is reduced, the compute resources are removed only once they are not in use for executing current statements. This ensures that ongoing operations are not abruptly interrupted.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-considerations.html#resizing-warehouses"}, {"id": 251, "area": "Data Loading and Unloading", "question": "What tasks can be completed using the COPY command? (Choose two.)", "options": ["A) Columns can be aggregated.", "B) Columns can be joined with an existing table.", "C) Columns can be reordered.", "D) Columns can be omitted.", "E) Data can be loaded without the need to spin up a virtual warehouse."], "chooseN": 2, "correct": ["Columns can be reordered.", "Columns can be omitted."], "explanation": "The COPY command in Snowflake allows for reordering columns and omitting columns during the data loading process. This provides flexibility in how data is ingested into tables from staged files.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-table.html"}, {"id": 252, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which Snowflake layer can be configured?", "options": ["A) Database Storage", "B) Cloud Services", "C) Query Processing", "D) Application Services"], "chooseN": 1, "correct": ["Query Processing"], "explanation": "In the Snowflake architecture, Query processing layer consists of Virtual Data Warehouses which can be configured (size and auto-scaling options).", "reference": "https://docs.snowflake.com/en/user-guide/intro-key-concepts.html#database-storage"}, {"id": 253, "area": "Snowflake Data Cloud Features & Architecture", "question": "Query compilation occurs in which architecture layer of the Snowflake Cloud Data Platform?", "options": ["A) Compute layer", "B) Storage layer", "C) Cloud infrastructure layer", "D) Cloud services layer"], "chooseN": 1, "correct": ["Cloud services layer"], "explanation": "In the Snowflake Cloud Data Platform, query compilation occurs in the Cloud Services layer. This layer is responsible for various management tasks, including query parsing, optimization, and compilation.", "reference": "https://docs.snowflake.com/en/user-guide/intro-key-concepts.html#cloud-services-layer"}, {"id": 254, "area": "Snowflake Data Cloud Features & Architecture", "question": "If a size Small virtual warehouse is made up of two servers, how many servers make up a Large warehouse?", "options": ["A) 4", "B) 8", "C) 16", "D) 32"], "chooseN": 1, "correct": ["8"], "explanation": "In Snowflake, each size increase in a virtual warehouse doubles the number of servers. Starting from a Small warehouse with 2 servers, a Medium would have 4, and a Large warehouse would have 8 servers.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-overview.html"}, {"id": 255, "area": "Data Transformations", "question": "A clustering key was defined on a table, but it is no longer needed. How can the key be removed?", "options": ["A) ALTER TABLE PURGE CLUSTERING KEY", "B) ALTER TABLE DELETE CLUSTERING KEY", "C) ALTER TABLE DROP CLUSTERING KEY", "D) ALTER TABLE REMOVE CLUSTERING KEY"], "chooseN": 1, "correct": ["ALTER TABLE DROP CLUSTERING KEY"], "explanation": "To remove a clustering key that is no longer needed from a table in Snowflake, the SQL command used is 'ALTER TABLE DROP CLUSTERING KEY'. This command will remove the specified clustering key from the table.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-keys#defining-clustered-tables"}, {"id": 256, "area": "Performance Concepts", "question": "What is a core benefit of clustering?", "options": ["A) To guarantee uniquely identifiable records in the database", "B) To increase scan efficiency in queries by improving pruning", "C) To improve performance by creating a separate file for point lookups", "D) To provide data redundancy by duplicating micro-partitions"], "chooseN": 1, "correct": ["To increase scan efficiency in queries by improving pruning"], "explanation": "A core benefit of clustering in Snowflake is to increase scan efficiency in queries by improving pruning. Effective clustering reduces the amount of data scanned during query execution, thereby improving performance and reducing cost.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-keys"}, {"id": 257, "area": "Account Access and Security", "question": "Which statement is true about Multi-Factor Authentication (MFA) in Snowflake?", "options": ["A) MFA can be enforced or applied for a given role.", "B) Snowflake users are automatically enrolled in MFA.", "C) Users enroll in MFA by submitting a request to Snowflake Support.", "D) MFA is an integrated Snowflake feature."], "chooseN": 1, "correct": ["MFA is an integrated Snowflake feature."], "explanation": "Multi-Factor Authentication (MFA) is an integrated feature in Snowflake, enhancing security by requiring a second form of authentication in addition to the user's password. This feature is not automatically applied and must be configured and enabled by the user or administrator.", "reference": "https://docs.snowflake.com/en/user-guide/security-mfa.html"}, {"id": 258, "area": "Data Transformations", "question": "What data type should be used to store JSON data natively in Snowflake?", "options": ["A) JSON", "B) String", "C) Object", "D) VARIANT"], "chooseN": 1, "correct": ["VARIANT"], "explanation": "The VARIANT data type should be used to store JSON data natively in Snowflake. VARIANT is a flexible data type that can hold structured and semi-structured data formats, including JSON, making it ideal for handling JSON data.", "reference": "https://docs.snowflake.com/en/sql-reference/data-types-semistructured.html#variant"}, {"id": 259, "area": "Data Protection and Data Sharing", "question": "What should be considered when deciding to use a Secure View? (Choose two.)", "options": ["A) No details of the query execution plan will be available in the query profiler.", "B) Once created there is no way to determine if a view is secure or not.", "C) Secure views do not take advantage of the same internal optimizations as standard views.", "D) It is not possible to create secure materialized views.", "E) The view definition of a secure view is still visible to users by way of the information schema."], "chooseN": 2, "correct": ["No details of the query execution plan will be available in the query profiler.", "Secure views do not take advantage of the same internal optimizations as standard views."], "explanation": "When deciding whether to use a secure view, consider that secure views do not use the same internal optimizations as standard views, which can affect performance, and that their internals are not exposed in Query Profile. Snowflake also supports secure materialized views, so it is not true that they", "reference": "https://docs.snowflake.com/en/user-guide/views-secure.html"}, {"id": 260, "area": "Snowflake Data Cloud Features & Architecture", "question": "The information schema provides storage information for which of the following objects? (Choose two.)", "options": ["A) Users", "B) Databases", "C) Internal stages", "D) Resource monitors", "E) Pipes"], "chooseN": 2, "correct": ["Databases", "Internal stages"], "explanation": "Snowflake Information Schema includes storage-related metadata for databases and internal stages. Database storage can be queried through database storage usage history information, and internal stage storage is available through stage-related storage usage metadata. Pipes are not storage objects and are not listed as one of the storage-related Information Schema object types.", "reference": "https://docs.snowflake.com/en/sql-reference/info-schema.html"}, {"id": 261, "area": "Performance Concepts", "question": "What is a responsibility of Snowflake’s virtual warehouses?", "options": ["A) Infrastructure management", "B) Metadata management", "C) Query execution", "D) Query parsing and optimization", "E) Management of the storage layer"], "chooseN": 1, "correct": ["Query execution"], "explanation": "In Snowflake, virtual warehouses are primarily responsible for the execution of queries. They provide the compute resources necessary to run queries against the data stored in Snowflake's cloud data warehouse.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses.html"}, {"id": 262, "area": "Data Protection and Data Sharing", "question": "Which data type is supported by Snowflake data classification?", "options": ["A) Binary", "B) Float", "C) Geography", "D) Variant"], "chooseN": 1, "correct": ["Float"], "explanation": "Float is supported by Snowflake data classification. The documentation explicitly excludes BINARY, GEOGRAPHY, DECFLOAT, UUID, and VECTOR from classification. Float is a standard numeric type that is fully supported. Binary and Geography are both explicitly listed as unsupported data types. JSON is the only semi-structured format supported for classification.", "reference": "https://docs.snowflake.com/en/user-guide/governance-classify-concepts"}, {"id": 263, "area": "Data Loading and Unloading", "question": "When unloading data to an external stage, which compression format can be used for Parquet files with the COPY INTO command?", "options": ["A) BROTLI", "B) GZIP", "C) LZO", "D) ZSTD"], "chooseN": 1, "correct": ["LZO"], "explanation": "For Parquet unloads with COPY INTO, Snowflake supports LZO as the compression option among the listed choices. Brotli, gzip, and Zstandard are mentioned in the docs under AUTO for loading, not as unload compression formats.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-location.html#format-type-parquet"}, {"id": 264, "area": "Account Access and Security", "question": "Which SQL command can be used to verify the privileges that are granted to a role?", "options": ["A) SHOW GRANTS ON ROLE", "B) SHOW ROLES", "C) SHOW GRANTS TO ROLE", "D) SHOW GRANTS FOR ROLE"], "chooseN": 1, "correct": ["SHOW GRANTS TO ROLE"], "explanation": "The SQL command 'SHOW GRANTS TO ROLE' is used in Snowflake to verify the privileges that are granted to a specific role. This command provides a detailed view of all the privileges assigned to the role.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/show-grants.html"}, {"id": 265, "area": "Performance Concepts", "question": "Which Query Profile result indicates that a warehouse is sized too small?", "options": ["A) There are a lot of filter nodes.", "B) Bytes are spilling to external storage.", "C) The number of processed rows is very high.", "D) The number of partitions scanned is the same as partitions total."], "chooseN": 1, "correct": ["Bytes are spilling to external storage."], "explanation": "In Snowflake's Query Profile, if bytes are spilling to external storage, it indicates that the virtual warehouse may be sized too small for the workload. This situation suggests that the warehouse does not have enough memory to handle the query, resulting in data spillover to disk.", "reference": "https://docs.snowflake.com/en/user-guide/ui-query-profile"}, {"id": 266, "area": "Data Protection and Data Sharing", "question": "What is the default Time Travel retention period?", "options": ["A) 1 day", "B) 7 days", "C) 45 days", "D) 90 days"], "chooseN": 1, "correct": ["1 day"], "explanation": "The default Time Travel retention period is 1 day (24 hours), automatically enabled for all Snowflake accounts. For Standard Edition, retention can be set to 0 or 1 day. For Enterprise Edition and higher, permanent objects support up to 90 days. The 7-day period is often confused with this but refers to the Fail-safe period, which is separate from Time Travel.", "reference": "https://docs.snowflake.com/en/user-guide/data-time-travel.html"}, {"id": 267, "area": "Data Loading and Unloading", "question": "Which of the following are best practice recommendations that should be considered when loading data into Snowflake? (Choose two.)", "options": ["A) Load files that are approximately 25 MB or smaller.", "B) Remove all dates and timestamps.", "C) Load files that are approximately 100-250 MB (or larger).", "D) Avoid using embedded characters such as commas for numeric data types.", "E) Remove semi-structured data types."], "chooseN": 2, "correct": ["Load files that are approximately 100-250 MB (or larger).", "Avoid using embedded characters such as commas for numeric data types."], "explanation": "When loading data into Snowflake, it is recommended to load files that are approximately 100-250 MB (or larger) in size for optimal performance. Also, avoiding embedded characters such as commas in numeric data types helps prevent parsing issues and improves data loading efficiency.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-considerations-prepare.html"}, {"id": 268, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which schema has the RESOURCE_MONITORS view?", "options": ["A) ACCOUNT_USAGE", "B) READER_ACCOUNT_USAGE", "C) INFORMATION_SCHEMA", "D) WAREHOUSE_USAGE_SCHEMA"], "chooseN": 2, "correct": ["ACCOUNT_USAGE", "READER_ACCOUNT_USAGE"], "explanation": "The RESOURCE_MONITORS view is documented in both SNOWFLAKE.ACCOUNT_USAGE and SNOWFLAKE.READER_ACCOUNT_USAGE. Snowflake also notes that the READER_ACCOUNT_USAGE version includes an additional READER_ACCOUNT_NAME column for reader-account-specific monitoring.", "reference": "https://docs.snowflake.com/en/sql-reference/account-usage/resource_monitors"}, {"id": 269, "area": "Account Access and Security", "question": "What is the purpose of enabling Federated Authentication on a Snowflake account?", "options": ["A) Disables the ability to use key pair and basic authentication (e.g., username/password) when connecting", "B) Allows dual Multi-Factor Authentication (MFA) when connecting to Snowflake", "C) Forces users to connect through a secure network proxy", "D) Allows users to connect using secure single sign-on (SSO) through an external identity provider"], "chooseN": 1, "correct": ["Allows users to connect using secure single sign-on (SSO) through an external identity provider"], "explanation": "The purpose of enabling Federated Authentication in Snowflake is to allow users to connect using secure single sign-on (SSO) through an external identity provider. This integration provides a streamlined and secure authentication process, leveraging existing identity management systems.", "reference": "https://docs.snowflake.com/en/user-guide/admin-security-fed-auth.html"}, {"id": 270, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which Snowflake partner category is represented at the top of this diagram (labeled 1)?", "options": ["A) Business Intelligence", "B) Machine Learning and Data Science", "C) Security and Governance", "D) Data Integration"], "chooseN": 1, "correct": ["Data Integration"], "explanation": "The Snowflake partner category at the top of the diagram, labeled 1, is typically represented by 'Data Integration'. the scope of data integration has expanded to include a wider range of operations, including: Data preparation, Data migration, movement, and management, Data warehouse automation.", "reference": "https://docs.snowflake.com/en/user-guide/ecosystem-security"}, {"id": 271, "area": "Data Protection and Data Sharing", "question": "Which object types are protected by Fail-safe? (Choose two.)", "options": ["A) Permanent Tables", "B) Temporary Tables", "C) External Tables", "D) Materialized Views", "E) Transient Tables"], "chooseN": 2, "correct": ["Permanent Tables", "Materialized Views"], "explanation": "In Snowflake, Fail-safe protection applies to Permanent Tables and Materialized Views. Fail-safe provides a seven-day immutable storage layer beyond the Time Travel retention period, offering additional protection for these types of objects.", "reference": "https://docs.snowflake.com/en/user-guide/data-failsafe"}, {"id": 272, "area": "Account Access and Security", "question": "Snowflake's approach to the management of system access combines which of the following models? (Choose two.)", "options": ["A) Security Assertion Markup Language (SAML)", "B) Role-Based Access Control (RBAC)", "C) Identity Access Management (IAM)", "D) Create, Read, Update, and Delete (CRUD)", "E) Discretionary Access Control (DAC)", "F) Mandatory Access Control (MAC)"], "chooseN": 2, "correct": ["Role-Based Access Control (RBAC)", "Discretionary Access Control (DAC)"], "explanation": "Snowflake's approach to system access management combines Role-Based Access Control (RBAC) and Discretionary Access Control (DAC). RBAC defines access based on roles and their privileges, while DAC allows the owner of an object to control access to it.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-overview.html"}, {"id": 273, "area": "Account Access and Security", "question": "According to Snowflake best practice recommendations, which role should be used to create databases?", "options": ["A) ACCOUNTADMIN", "B) SYSADMIN", "C) SECURITYADMIN", "D) USERADMIN"], "chooseN": 1, "correct": ["SYSADMIN"], "explanation": "According to Snowflake best practice recommendations, the SYSADMIN role should be used to create databases. This role is typically responsible for managing databases and other objects within Snowflake, while other administrative roles have different primary responsibilities.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-overview"}, {"id": 274, "area": "Performance Concepts", "question": "To add or remove search optimization for a table, a user must have which of the following privileges or roles? (Choose two.)", "options": ["A) The MODIFY privilege on the table", "B) The OWNERSHIP privilege on the table", "C) A SECURITYADMIN role", "D) The ADD SEARCH OPTIMIZATION privilege on the schema that contains the table", "E) The SELECT privilege on the table"], "chooseN": 2, "correct": ["The OWNERSHIP privilege on the table", "The ADD SEARCH OPTIMIZATION privilege on the schema that contains the table"], "explanation": "To add, configure, or remove search optimization for a table, you must have the following privileges: You must have OWNERSHIP privilege on the table. You must have ADD SEARCH OPTIMIZATION privilege on the schema that contains the table.", "reference": "https://docs.snowflake.com/en/user-guide/search-optimization-service.html#what-access-control-privileges-are-needed-for-the-search-optimization-service"}, {"id": 275, "area": "Data Loading and Unloading", "question": "While using a COPY command with a Validation_mode parameter, which of the following statements will return an error?", "options": ["A) Statements that insert a duplicate record during a load", "B) Statements that have a specific data type in the source", "C) Statements that have duplicate file names", "D) Statements that transform data during a load"], "chooseN": 1, "correct": ["Statements that transform data during a load"], "explanation": "With VALIDATION_MODE, Snowflake supports only standard data loading. COPY statements that transform data during loading are not supported and therefore return an error. This corresponds to option 4.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-transform.html#validation-mode-parameter"}, {"id": 276, "area": "Performance Concepts", "question": "When is the result set cache no longer available? (Choose two.)", "options": ["A) When another warehouse is used to execute the query", "B) When another user executes the query", "C) When the underlying data has changed", "D) When the warehouse used to execute the query is suspended", "E) When it has been 24 hours since the last query"], "chooseN": 2, "correct": ["When the underlying data has changed", "When it has been 24 hours since the last query"], "explanation": "The result set cache in Snowflake is no longer available when the underlying data has changed, as this would render the cached results obsolete. Additionally, the cache expires 24 hours after the last query, after which the results need to be recomputed.", "reference": "https://docs.snowflake.com/en/user-guide/querying-persisted-results"}, {"id": 277, "area": "Data Loading and Unloading", "question": "What is the recommended file sizing for data loading using Snowpipe?", "options": ["A) A compressed file size greater than 100 MB, and up to 250 MB", "B) A compressed file size greater than 100 GB, and up to 250 GB", "C) A compressed file size greater than 10 MB, and up to 100 MB", "D) A compressed file size greater than 1 GB, and up to 2 GB"], "chooseN": 1, "correct": ["A compressed file size greater than 100 MB, and up to 250 MB"], "explanation": "For data loading using Snowpipe, the recommended file size is a compressed file greater than 100 MB, and up to 250 MB. This file size range is optimal for balancing load efficiency and processing performance.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-snowpipe-intro.html"}, {"id": 278, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which statements are true concerning Snowflake’s underlying cloud infrastructure? (Choose three.)", "options": ["A) Snowflake data and services are deployed in a single availability zone within a cloud provider’s region.", "B) Snowflake data and services are available in a single cloud provider and a single region; the use of multiple cloud providers is not supported.", "C) Snowflake can be deployed in a customer’s private cloud using the customer’s own compute and storage resources for Snowflake compute and storage.", "D) Snowflake uses the core compute and storage services of each cloud provider for its own compute and storage.", "E) All three layers of Snowflake’s architecture (storage, compute, and cloud services) are deployed and managed entirely on a selected cloud platform.", "F) Snowflake data and services are deployed in at least three availability zones within a cloud provider’s region."], "chooseN": 3, "correct": ["Snowflake uses the core compute and storage services of each cloud provider for its own compute and storage.", "All three layers of Snowflake’s architecture (storage, compute, and cloud services) are deployed and managed entirely on a selected cloud platform.", "Snowflake data and services are deployed in at least three availability zones within a cloud provider’s region."], "explanation": "Snowflake's architecture is designed to use the core compute and storage services provided by each cloud platform, ensuring seamless integration and optimization. All three layers of its architecture are entirely deployed and managed on the chosen cloud platform. Additionally, for high availability and resilience, Snowflake services are typically deployed across at least three availability zones within a cloud provider’s region.", "reference": "https://docs.snowflake.com/en/user-guide/intro-key-concepts.html#architecture"}, {"id": 279, "area": "Data Loading and Unloading", "question": "A user unloaded a Snowflake table called mytable to an internal stage called mystage. Which command can be used to view the list of files that has been uploaded to the stage?", "options": ["A) list @mytable;", "B) list @%mytable;", "C) list @%mystage;", "D) list @mystage;"], "chooseN": 1, "correct": ["list @mystage;"], "explanation": "To view the list of files uploaded to an internal stage in Snowflake, the command 'list @mystage;' should be used. This command displays the files available in the specified stage, in this case, 'mystage'.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/list.html"}, {"id": 280, "area": "Account Access and Security", "question": "What is a best practice after creating a custom role?", "options": ["A) Create the custom role using the SYSADMIN role.", "B) Assign the custom role to the SYSADMIN role.", "C) Assign the custom role to the PUBLIC role.", "D) Add _CUSTOM to all custom role names."], "chooseN": 1, "correct": ["Assign the custom role to the SYSADMIN role."], "explanation": "A best practice after creating a custom role in Snowflake is to assign the custom role to the SYSADMIN role. This practice allows the SYSADMIN role to manage the custom role, ensuring proper oversight and control over role assignments and privileges.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-overview.html#custom-roles"}, {"id": 281, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which is the MINIMUM required Snowflake edition that a user must have if they want to use AWS/Azure Privatelink or Google Cloud Private Service Connect?", "options": ["A) Standard", "B) Premium", "C) Enterprise", "D) Business Critical"], "chooseN": 1, "correct": ["Business Critical"], "explanation": "To use AWS/Azure Privatelink or Google Cloud Private Service Connect with Snowflake, the minimum required edition is the Business Critical edition. This edition provides advanced security and networking features, including Privatelink and Private Service Connect.", "reference": "https://docs.snowflake.com/en/user-guide/network-policies.html#using-privatelink-with-snowflake"}, {"id": 282, "area": "Performance Concepts", "question": "Which of the following query profiler variables will indicate that a virtual warehouse is not sized correctly for the query being executed?", "options": ["A) Bytes sent over the network", "B) Synchronization", "C) Initialization", "D) Remote spillage"], "chooseN": 1, "correct": ["Remote spillage"], "explanation": "In the query profiler, 'Remote spillage' indicates that a virtual warehouse is not sized correctly for the query being executed. It suggests that the warehouse does not have enough memory to process the query efficiently, leading to data spilling over to remote storage.", "reference": "https://docs.snowflake.com/en/user-guide/ui-query-profile.html#query-profile"}, {"id": 283, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which of the following Snowflake capabilities are available in all Snowflake editions? (Choose two.)", "options": ["A) Customer-managed encryption keys through Tri-Secret Secure", "B) Automatic encryption of all data", "C) Up to 90 days of data recovery through Time Travel", "D) Object-level access control", "E) Column-level security to apply data masking policies to tables and views"], "chooseN": 2, "correct": ["Automatic encryption of all data", "Object-level access control"], "explanation": "- Automatic encryption of all data: Snowflake cifra automaticamente todos los datos en reposo y en transito utilizando AES-256 en todas las ediciones, sin configuracion adicional.\n- Object-level access control: El control de acceso basado en roles (RBAC) a nivel de objeto esta disponible en todas las ediciones de Snowflake, permitiendo gestionar permisos granulares.\n- Customer-managed encryption keys through Tri-Secret Secure: Tri-Secret Secure requiere la edicion Business Critical o superior.\n- Up to 90 days of data recovery through Time Travel: Time Travel de hasta 90 dias requiere la edicion Enterprise o superior. La edicion Standard solo ofrece 1 dia de Time Travel.\n- Column-level security to apply data masking policies to tables and views: Dynamic Data Masking requiere la edicion Enterprise o superior.", "reference": "https://docs.snowflake.com/en/user-guide/intro-editions, https://docs.snowflake.com/en/user-guide/security-encryption"}, {"id": 284, "area": "Data Loading and Unloading", "question": "A PUT command can be used to stage local files from which Snowflake interface?", "options": ["A) SnowSQL", "B) Snowflake classic web interface (UI)", "C) Snowsight", "D) .NET driver"], "chooseN": 1, "correct": ["SnowSQL"], "explanation": "The PUT command in Snowflake is used to stage local files and is available through the SnowSQL command-line interface. This command enables users to upload files from their local machine to Snowflake's internal stage.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/put?utm_source=snowscope&utm_medium=serp&utm_term=PUT"}, {"id": 285, "area": "Performance Concepts", "question": "Which of the following indicates that it may be appropriate to use a clustering key for a table? (Choose two.)", "options": ["A) The table contains a column that has very low cardinality.", "B) DML statements that are being issued against the table are blocked.", "C) The table has a small number of micro-partitions.", "D) Queries on the table are running slower than expected.", "E) The clustering depth for the table is large."], "chooseN": 2, "correct": ["Queries on the table are running slower than expected.", "The clustering depth for the table is large."], "explanation": "Using a clustering key may be appropriate when queries on a table are running slower than expected, and when the clustering depth for the table is large. These indicators suggest that re-clustering might improve the performance by optimizing how data is stored and accessed.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-keys.html"}, {"id": 286, "area": "Performance Concepts", "question": "Which cache type is used to cache data output from SQL queries?", "options": ["A) Metadata cache", "B) Result cache", "C) Remote cache", "D) Local file cache"], "chooseN": 1, "correct": ["Result cache"], "explanation": "The Result cache in Snowflake is used to cache the data output from SQL queries. This cache stores the results of queries and can be leveraged for subsequent executions of the same query to improve performance.", "reference": "https://docs.snowflake.com/en/user-guide/querying-caching.html"}, {"id": 287, "area": "Performance Concepts", "question": "Which of the following describes how clustering keys work in Snowflake?", "options": ["A) Clustering keys update the micro-partitions in place with a full sort, and impact the DML operations.", "B) Clustering keys sort the designated columns over time, without blocking DML operations.", "C) Clustering keys create a distributed, parallel data structure of pointers to a table's rows and columns.", "D) Clustering keys establish a hashed key on each node of a virtual warehouse to optimize joins at run-time."], "chooseN": 1, "correct": ["Clustering keys sort the designated columns over time, without blocking DML operations."], "explanation": "Clustering keys in Snowflake work by sorting the designated columns over time, without blocking DML (Data Manipulation Language) operations. This sorting optimizes the storage of data, improving the performance of queries that access these columns.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-keys"}, {"id": 288, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which of the following operations require the use of a running virtual warehouse? (Choose two.)", "options": ["A) Downloading data from an internal stage", "B) Listing files in a stage", "C) Executing a stored procedure", "D) Altering a table", "E) Querying data from a materialized view"], "chooseN": 2, "correct": ["Executing a stored procedure", "Querying data from a materialized view"], "explanation": "In Snowflake, executing a stored procedure and querying data from a materialized view require the use of a running virtual warehouse. These operations involve data processing and computation that necessitate the computational resources provided by a virtual warehouse.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses.html"}, {"id": 289, "area": "Performance Concepts", "question": "What is used to limit the credit usage of a virtual warehouse within a Snowflake account?", "options": ["A) Load monitor", "B) Resource monitor", "C) Query Profile", "D) Stream"], "chooseN": 1, "correct": ["Resource monitor"], "explanation": "Resource monitors in Snowflake are used to track and limit the amount of compute credits that virtual warehouses consume. They help in managing and controlling the cost associated with the compute resources.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-considerations.html#using-resource-monitors-to-control-warehouse-credit-usage"}, {"id": 290, "area": "Data Protection and Data Sharing", "question": "What are the benefits of the replication feature in Snowflake? (Choose two.)", "options": ["A) Disaster recovery", "B) Time Travel", "C) Fail-safe", "D) Database failover and failback", "E) Data security"], "chooseN": 2, "correct": ["Disaster recovery", "Database failover and failback"], "explanation": "The replication feature in Snowflake provides benefits such as disaster recovery and database failover and failback. It allows for the continuous copying of data to other regions or accounts, ensuring data availability and business continuity in case of disasters.", "reference": "https://docs.snowflake.com/en/user-guide/database-replication-intro.html"}, {"id": 291, "area": "Account Access and Security", "question": "Which of the following roles are recommended to create and manage users and roles? (Choose two.)", "options": ["A) SYSADMIN", "B) SECURITYADMIN", "C) PUBLIC", "D) ACCOUNTADMIN", "E) USERADMIN"], "chooseN": 2, "correct": ["SECURITYADMIN", "USERADMIN"], "explanation": "SECURITYADMIN (aka Security Administrator) Role that can manage any object grant globally, as well as create, monitor, and manage users and roles. More specifically, this role: Is granted the MANAGE GRANTS security privilege to be able to modify any grant, including revoking it. Inherits the privileges of the USERADMIN role via the system role hierarchy (i.e. USERADMIN role is granted to SECURITYADMIN). USERADMIN (aka User and Role Administrator) Role that is dedicated to user and role management only. More specifically, this role: Is granted the CREATE USER and CREATE ROLE security privileges. Can create users and roles in the account. This role can also manage users and roles that it owns. Only the role with the OWNERSHIP privilege on an object (i.e. user or role), or a higher role, can modify the object properties.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-overview#roles"}, {"id": 292, "area": "Performance Concepts", "question": "When can a newly configured virtual warehouse start running SQL queries?", "options": ["A) After 50% of the warehouse provisioning has completed", "B) During the time slots defined by the ACCOUNTADMIN", "C) When the warehouse provisioning is completed", "D) After the warehouse replication is completed"], "chooseN": 1, "correct": ["When the warehouse provisioning is completed"], "explanation": "A newly configured virtual warehouse in Snowflake can start running SQL queries once the provisioning process is completed. This ensures that the necessary compute resources are allocated and ready for query execution.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses.html"}, {"id": 293, "area": "Data Loading and Unloading", "question": "What actions will prevent leveraging of the ResultSet cache?", "options": ["A) Removing a column from the query SELECT list", "B) Stopping the virtual warehouse that the query is running against", "C) If the result has not been reused within the last 12 hours", "D) Executing the RESULTS_SCAN() table function"], "chooseN": 1, "correct": ["Removing a column from the query SELECT list"], "explanation": "Changing the SELECT list changes the query text, which prevents 100% persisted result reuse. The other marked choices are not supported by the documentation.", "reference": "https://docs.snowflake.com/en/user-guide/querying-persisted-results"}, {"id": 294, "area": "Performance Concepts", "question": "Which of the following are benefits of micro-partitioning? (Choose two.)", "options": ["A) Micro-partitions cannot overlap in their range of values.", "B) Micro-partitions are immutable objects that support the use of Time Travel.", "C) Micro-partitions can reduce the amount of I/O from object storage to virtual warehouses.", "D) Rows are automatically stored in sorted order within micro-partitions.", "E) Micro-partitions can be defined on a schema-by-schema basis."], "chooseN": 2, "correct": ["Micro-partitions are immutable objects that support the use of Time Travel.", "Micro-partitions can reduce the amount of I/O from object storage to virtual warehouses."], "explanation": "Micro-partitions in Snowflake are immutable, which enables the use of Time Travel. They also help in reducing I/O from object storage to virtual warehouses by efficiently managing data storage and retrieval.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions.html"}, {"id": 295, "area": "Data Transformations", "question": "Which data type can be used to store geospatial data in Snowflake? (Choose two.)", "options": ["A) Variant", "B) Object", "C) Geometry", "D) Geography"], "chooseN": 2, "correct": ["Geometry", "Geography"], "explanation": "Snowflake provides the following data types for geospatial data: The GEOGRAPHY data type, which models Earth as though it were a perfect sphere. The GEOMETRY data type, which represents features in a planar (Euclidean, Cartesian) coordinate system.", "reference": "https://docs.snowflake.com/en/user-guide/geospatial-data.html"}, {"id": 296, "area": "Performance Concepts", "question": "If all virtual warehouse resources are maximized while processing a query workload, what will happen to new queries that are submitted to the warehouse?", "options": ["A) All queries will terminate when the resources are maximized.", "B) The warehouse will scale out automatically", "C) The warehouse will move to a suspended state.", "D) New queries will be queued and executed when capacity is available."], "chooseN": 1, "correct": ["New queries will be queued and executed when capacity is available."], "explanation": "In Snowflake, if all resources of a virtual warehouse are maximized, new queries will be queued. These queries will be executed once the capacity becomes available, ensuring continuous processing without termination or automatic scaling.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-considerations.html#resource-usage-and-warehouses"}, {"id": 297, "area": "Data Protection and Data Sharing", "question": "Masking policies can be applied to which of the following Snowflake objects? (Choose two.)", "options": ["A) A materialized view", "B) A stored procedure", "C) A table", "D) A stream", "E) A pipe"], "chooseN": 2, "correct": ["A materialized view", "A table"], "explanation": "In Snowflake, masking policies can be applied to tables and materialized views. These policies allow for the dynamic data masking of sensitive information, enhancing data protection and privacy.", "reference": "https://docs.snowflake.com/en/user-guide/security-column-ddm.html"}, {"id": 298, "area": "Account Access and Security", "question": "What actions are supported by Snowflake resource monitors? (Choose two.)", "options": ["A) Alert", "B) Notify", "C) Notify and suspend", "D) Abort", "E) Suspend immediately"], "chooseN": 2, "correct": ["Notify", "Notify and suspend"], "explanation": "Resource monitors in Snowflake support actions such as 'Notify', which sends an alert when usage reaches a specified threshold, and 'Notify & Suspend', which Send a notification (to all account administrators with notifications enabled) and suspend all assigned warehouses after all statements being executed by the warehouse(s) have completed.", "reference": "https://docs.snowflake.com/en/user-guide/resource-monitors.html"}, {"id": 299, "area": "Data Loading and Unloading", "question": "A user executes the following SQL query: create table SALES_BKP like SALES; What are the cost implications for processing this query?", "options": ["A) Processing costs will be generated based on how long the query takes.", "B) Storage costs will be generated based on the size of the data.", "C) No costs will be incurred as the query will use metadata.", "D) The cost for running the virtual warehouse will be charged by the second."], "chooseN": 1, "correct": ["No costs will be incurred as the query will use metadata."], "explanation": "The 'CREATE TABLE ... LIKE' statement in Snowflake duplicates the structure of an existing table without copying the data. This operation uses metadata only and does not incur any processing or storage costs.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/create-table"}, {"id": 300, "area": "Data Protection and Data Sharing", "question": "What is the maximum length of time travel available in the Snowflake Standard Edition?", "options": ["A) 1 Day", "B) 7 Days", "C) 30 Days", "D) 90 Days"], "chooseN": 1, "correct": ["1 Day"], "explanation": "The maximum Time Travel retention period in Snowflake Standard Edition is 1 day (24 hours). The docs state the default retention is 1 day for all editions, and Standard Edition can only set it to 0 or 1 day. Extended retention periods of up to 90 days are available only on Enterprise Edition (and higher) for permanent databases, schemas, and tables.", "reference": "https://docs.snowflake.com/en/user-guide/data-time-travel.html#time-travel-and-editions"}, {"id": 301, "area": "Data Loading and Unloading", "question": "What happens when an external or an internal stage is dropped? (Choose two.)", "options": ["A) When dropping an external stage, the files are not removed and only the stage is dropped.", "B) When dropping an external stage, both the stage and the files within the stage are removed.", "C) When dropping an internal stage, the files are deleted with the stage and the files are recoverable.", "D) When dropping an internal stage, the files are deleted with the stage and the files are not recoverable.", "E) When dropping an internal stage, only selected files are deleted with the stage and are not recoverable."], "chooseN": 2, "correct": ["When dropping an external stage, the files are not removed and only the stage is dropped.", "When dropping an internal stage, the files are deleted with the stage and the files are not recoverable."], "explanation": "When an external stage is dropped in Snowflake, only the stage reference is removed, but the actual files in the external storage remain untouched. In contrast, when an internal stage is dropped, both the stage and the files stored within it are deleted and are not recoverable.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-local-file-system-create-stage.html#deleting-stages"}, {"id": 302, "area": "Data Loading and Unloading", "question": "A user has 10 files in a stage containing new customer data. The ingest operation completes with no errors, using the following command: COPY INTO my_table FROM @my_stage; The next day the user adds 10 files to the stage so that now the stage contains a mixture of new customer data and updates to the previous data. The user did not remove the 10 original files. If the user runs the same COPY INTO command what will happen?", "options": ["A) All data from all of the files on the stage will be appended to the table.", "B) Only data about new customers from the new files will be appended to the table.", "C) The operation will fail with the error UNCERTAIN FILES IN STAGE.", "D) All data from only the newly-added files will be appended to the table."], "chooseN": 1, "correct": ["All data from only the newly-added files will be appended to the table."], "explanation": "When the COPY INTO command is run again in Snowflake, only the new files added to the stage will be loaded into the table. Snowflake's COPY INTO command is designed to be idempotent, meaning it will ignore files that have already been successfully loaded.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-considerations-load#executing-parallel-copy-statements-that-reference-the-same-data-files"}, {"id": 303, "area": "Data Loading and Unloading", "question": "Which parameter can be used to instruct a COPY command to verify data files instead of loading them into a specified table?", "options": ["A) STRIP_NULL_VALUES", "B) SKIP_BYTE_ORDER_MARK", "C) REPLACE_INVALID_CHARACTERS", "D) VALIDATION_MODE"], "chooseN": 1, "correct": ["VALIDATION_MODE"], "explanation": "The VALIDATION_MODE parameter in the COPY command is used to verify the format and structure of the data files without actually loading them into the table. This is useful for validating the data before the actual data load.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-table.html#optional-parameters"}, {"id": 304, "area": "Account Access and Security", "question": "Which of the following SQL statements will list the version of the drivers currently being used?", "options": ["A) Execute SELECT CURRENT_ODBC_CLIENT(); from the Web UI", "B) Execute SELECT CURRENT_JDBC_VERSION(); from SnowSQL", "C) Execute SELECT CURRENT_CLIENT(); from an application", "D) Execute SELECT CURRENT_VERSION(); from the Python Connector"], "chooseN": 1, "correct": ["Execute SELECT CURRENT_CLIENT(); from an application"], "explanation": "CURRENT_CLIENT Returns the version of the client from which the function was called. If called from an application using the JDBC or ODBC driver to connect to Snowflake, returns the version of the driver.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/current_client"}, {"id": 305, "area": "Performance Concepts", "question": "Which Snowflake technique can be used to improve the performance of a query?", "options": ["A) Clustering", "B) Indexing", "C) Fragmenting", "D) Using INDEX_HINTS"], "chooseN": 1, "correct": ["Clustering"], "explanation": "In Snowflake, Clustering is used to improve query performance. It organizes the data in a table into micro-partitions based on the values of one or more columns (cluster keys), which can significantly enhance the efficiency of query processing.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-keys.html"}, {"id": 306, "area": "Data Protection and Data Sharing", "question": "What happens to the shared objects for users in a consumer account from a share, once a database has been created in that account?", "options": ["A) The shared objects are transferred.", "B) The shared objects are copied.", "C) The shared objects become accessible.", "D) The shared objects can be re-shared."], "chooseN": 1, "correct": ["The shared objects become accessible."], "explanation": "When a database is created in a consumer account from a share in Snowflake, the shared objects become accessible in that account. These objects are not physically transferred or copied, but are made available for access and use within the consumer account.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-intro.html"}, {"id": 307, "area": "Data Transformations", "question": "Using variables in Snowflake is denoted by using which SQL character?", "options": ["A) @", "B) &", "C) $", "D) #"], "chooseN": 1, "correct": ["$"], "explanation": "In Snowflake, variables are denoted using the '$' character. Because the $ sign is the prefix used to identify variables in SQL statements, it is treated as a special character when used in identifiers. Identifiers (database names, table names, column names, etc.) cannot start with special characters unless the entire name is enclosed in double quotes.", "reference": "https://docs.snowflake.com/en/sql-reference/session-variables.html#variable-identifiers"}, {"id": 308, "area": "Account Access and Security", "question": "Which commands should be used to grant the privilege allowing a role to select data from all current tables and any tables that will be created later in a schema? (Choose two.)", "options": ["A) grant USAGE on all tables in schema DB1.SCHEMA to role MYROLE;", "B) grant USAGE on future tables in schema DB1.SCHEMA to role MYROLE;", "C) grant SELECT on all tables in schema DB1.SCHEMA to role MYROLE;", "D) grant SELECT on future tables in schema DB1.SCHEMA to role MYROLE;", "E) grant SELECT on all tables in database DB1 to role MYROLE;", "F) grant SELECT on future tables in database DB1 to role MYROLE;"], "chooseN": 2, "correct": ["grant SELECT on all tables in schema DB1.SCHEMA to role MYROLE;", "grant SELECT on future tables in schema DB1.SCHEMA to role MYROLE;"], "explanation": "To grant a role the privilege to select data from all current and future tables in a schema, the commands 'grant SELECT on all tables in schema DB1.SCHEMA to role MYROLE;' and 'grant SELECT on future tables in schema DB1.SCHEMA to role MYROLE;' should be used. These commands ensure that the role has access to existing tables and will automatically have access to any new tables created in the schema.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/grant-privilege.html"}, {"id": 309, "area": "Data Transformations", "question": "How can a user change which columns are referenced in a view?", "options": ["A) Modify the columns in the underlying table", "B) Use the ALTER VIEW command to update the view", "C) Recreate the view with the required changes", "D) Materialize the view to perform the changes"], "chooseN": 1, "correct": ["Recreate the view with the required changes"], "explanation": "To change which columns are referenced in a view in Snowflake, the user needs to recreate the view with the required changes. Snowflake does not support altering the column structure of a view directly, so the view must be dropped and then recreated with the new column definitions.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/create-view.html"}, {"id": 310, "area": "Performance Concepts", "question": "Which statement describes pruning?", "options": ["A) The filtering or disregarding of micro-partitions that are not needed to return a query.", "B) The return of micro-partitions values that overlap with each other to reduce a query's runtime.", "C) A service that is handled by the Snowflake Cloud Services layer to optimize caching.", "D) The ability to allow the result of a query to be accessed as if it were a table."], "chooseN": 1, "correct": ["The filtering or disregarding of micro-partitions that are not needed to return a query."], "explanation": "Pruning in Snowflake refers to the process of filtering or disregarding micro-partitions that are not needed to return a query. This optimization technique reduces the amount of data scanned during query execution, thereby improving performance.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions"}, {"id": 311, "area": "Account Access and Security", "question": "Which SQL command can be used to see the CREATE definition of a masking policy?", "options": ["A) SHOW MASKING POLICIES", "B) DESCRIBE MASKING POLICY", "C) GET_DDL", "D) LIST MASKING POLICIES"], "chooseN": 1, "correct": ["GET_DDL"], "explanation": "The GET_DDL function in Snowflake is used to retrieve the CREATE statement (definition) of various database objects, including masking policies. It provides the SQL command that can be used to recreate the object.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/get_ddl.html"}, {"id": 312, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which of the following is the Snowflake Account_Usage.Metering_History view used for?", "options": ["A) Gathering the hourly credit usage for an account", "B) Compiling an account's average cloud services cost over the previous month", "C) Summarizing the throughput of Snowpipe costs for an account", "D) Calculating the funds left on an account's contract"], "chooseN": 1, "correct": ["Gathering the hourly credit usage for an account"], "explanation": "The Snowflake Account_Usage.Metering_History view is primarily used for gathering the hourly credit usage for an account. It provides detailed information about the consumption of virtual warehouse credits, helping in cost analysis and management.", "reference": "https://docs.snowflake.com/en/sql-reference/account-usage/metering_history.html"}, {"id": 313, "area": "Snowflake Data Cloud Features & Architecture", "question": "Query parsing and compilation occurs in which architecture layer of the Snowflake Cloud Data Platform?", "options": ["A) Cloud services layer", "B) Compute layer", "C) Storage layer", "D) Cloud agnostic layer"], "chooseN": 1, "correct": ["Cloud services layer"], "explanation": "In the Snowflake Cloud Data Platform, query parsing and compilation occur in the cloud services layer. This layer is responsible for query optimization, transaction management, metadata management, and other services essential for efficient query processing.", "reference": "https://docs.snowflake.com/en/user-guide/intro-key-concepts.html#snowflake-architecture"}, {"id": 314, "area": "Data Protection and Data Sharing", "question": "Which of the following Snowflake objects can be shared using a secure share? (Choose two.)", "options": ["A) Materialized views", "B) Sequences", "C) Procedures", "D) Tables", "E) Secure User Defined Functions (UDFs)"], "chooseN": 2, "correct": ["Tables", "Secure User Defined Functions (UDFs)"], "explanation": "In Snowflake, tables and secure user-defined functions (UDFs) can be shared using a secure share. Secure shares allow for the safe and controlled sharing of data across different Snowflake accounts.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-intro.html"}, {"id": 315, "area": "Performance Concepts", "question": "What happens to the underlying table data when a CLUSTER BY clause is added to a Snowflake table?", "options": ["A) Data is hashed by the cluster key to facilitate fast searches for common data values", "B) Larger micro-partitions are created for common data values to reduce the number of partitions that must be scanned", "C) Smaller micro-partitions are created for common data values to allow for more parallelism", "D) Data may be colocated by the cluster key within the micro-partitions to improve pruning performance"], "chooseN": 1, "correct": ["Data may be colocated by the cluster key within the micro-partitions to improve pruning performance"], "explanation": "Adding a CLUSTER BY clause to a Snowflake table leads to the colocation of data by the cluster key within micro-partitions. This improves pruning performance during query execution, as it allows the system to efficiently locate and access the relevant data.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-keys.html"}, {"id": 316, "area": "Performance Concepts", "question": "Which of the following conditions must be met in order to return results from the results cache? (Choose two.)", "options": ["A) The user has the appropriate privileges on the objects associated with the query.", "B) Micro-partitions have been reclustered since the query was last run.", "C) The new query is run using the same virtual warehouse as the previous query.", "D) The query includes a User Defined Function (UDF).", "E) The query has been run within 24 hours of the previously-run query."], "chooseN": 2, "correct": ["The user has the appropriate privileges on the objects associated with the query.", "The query has been run within 24 hours of the previously-run query."], "explanation": "To retrieve results from Snowflake's results cache, the user must have the appropriate privileges on the objects associated with the query. Additionally, The query has been run within 24 hours of the previously-run query.", "reference": "https://docs.snowflake.com/en/user-guide/querying-persisted-results#retrieval-optimization"}, {"id": 317, "area": "Account Access and Security", "question": "Which statement about billing applies to Snowflake credits?", "options": ["A) Credits are billed per-minute with a 60-minute minimum.", "B) Credits are used to pay for cloud data storage usage.", "C) Credits are consumed based on the number of credits billed for each hour that a warehouse runs.", "D) Credits are consumed based on the warehouse size and the time the warehouse is running."], "chooseN": 1, "correct": ["Credits are consumed based on the warehouse size and the time the warehouse is running."], "explanation": "In Snowflake, credits are consumed based on the size of the warehouse and the duration for which it is running. This approach aligns costs with the scale and performance needs of the user, charging for compute resources based on their actual usage.", "reference": "https://docs.snowflake.com/en/user-guide/credits.html"}, {"id": 318, "area": "Data Transformations", "question": "A user needs to create a materialized view in the schema MYDB.MYSCHEMA. Which statements will provide this access?", "options": ["A) GRANT CREATE MATERIALIZED VIEW ON SCHEMA MYDB.MYSCHEMA TO ROLE MYROLE;", "B) GRANT CREATE MATERIALIZED VIEW ON SCHEMA MYDB.MYSCHEMA TO USER USER1;", "C) GRANT USAGE ON SCHEMA MYDB.MYSCHEMA TO ROLE MYROLE; GRANT CREATE MATERIALIZED VIEW ON SCHEMA MYDB.MYSCHEMA TO ROLE MYROLE;", "D) GRANT USAGE ON SCHEMA MYDB.MYSCHEMA TO USER USER1; GRANT CREATE MATERIALIZED VIEW ON SCHEMA MYDB.MYSCHEMA TO USER USER1;"], "chooseN": 1, "correct": ["GRANT CREATE MATERIALIZED VIEW ON SCHEMA MYDB.MYSCHEMA TO ROLE MYROLE;"], "explanation": "Snowflake documentation says creating a materialized view requires CREATE MATERIALIZED VIEW on the schema, and the grant is made to a ROLE. The only clearly correct option is the direct GRANT CREATE MATERIALIZED VIEW statement to ROLE MYROLE.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/grant-privilege.html"}, {"id": 319, "area": "Performance Concepts", "question": "What is the purpose of multi-cluster virtual warehouses?", "options": ["A) To create separate data warehouses to increase query optimization", "B) To allow users the ability to choose the type of compute nodes that make up a virtual warehouse cluster", "C) To eliminate or reduce queuing of concurrent queries", "D) To allow the warehouse to resize automatically"], "chooseN": 1, "correct": ["To eliminate or reduce queuing of concurrent queries"], "explanation": "The purpose of multi-cluster virtual warehouses in Snowflake is to eliminate or reduce the queuing of concurrent queries. Multi-cluster warehouses can automatically scale out to handle increasing concurrency demands, ensuring queries are processed efficiently without excessive waiting times.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-multicluster.html"}, {"id": 320, "area": "Data Loading and Unloading", "question": "Which of the following is a valid source for an external stage when the Snowflake account is located on Microsoft Azure?", "options": ["A) An FTP server with TLS encryption", "B) An HTTPS server with WebDAV", "C) A Google Cloud storage bucket", "D) A Windows server file share on Azure"], "chooseN": 1, "correct": ["A Windows server file share on Azure"], "explanation": "When using Snowflake on Microsoft Azure, a valid source for an external stage can be a Windows server file share on Azure. Snowflake supports various cloud storage options as stages for data loading and unloading, with specific compatibility depending on the cloud platform.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-azure-stages.html"}, {"id": 321, "area": "Data Protection and Data Sharing", "question": "Which database objects can be shared with the Snowflake secure data sharing feature? (Choose two.)", "options": ["A) Files", "B) External tables", "C) Secure User-Defined Functions (UDFs)", "D) Sequences", "E) Streams"], "chooseN": 2, "correct": ["External tables", "Secure User-Defined Functions (UDFs)"], "explanation": "With Snowflake's secure data sharing feature, users can share database objects like external tables and secure user-defined functions (UDFs). This feature enables organizations to share data sets securely and in real-time without the need to copy or transfer the data.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-intro.html"}, {"id": 322, "area": "Data Protection and Data Sharing", "question": "Which statements reflect key functionalities of a Snowflake Data Exchange? (Choose two.)", "options": ["A) If an account is enrolled with a Data Exchange, it will lose its access to the Snowflake Marketplace.", "B) A Data Exchange allows groups of accounts to share data privately among the accounts.", "C) A Data Exchange allows accounts to share data with third, non-Snowflake parties.", "D) Data Exchange functionality is available by default in accounts using the Enterprise edition or higher.", "E) The sharing of data in a Data Exchange is bidirectional. An account can be a provider for some datasets and a consumer for others."], "chooseN": 2, "correct": ["A Data Exchange allows groups of accounts to share data privately among the accounts.", "The sharing of data in a Data Exchange is bidirectional. An account can be a provider for some datasets and a consumer for others."], "explanation": "Snowflake Data Exchange facilitates private data sharing among groups of accounts. It allows an account to be both a data provider and a consumer, enabling bidirectional data sharing. This feature enhances collaboration and data exchange between different Snowflake accounts.", "reference": "https://docs.snowflake.com/en/user-guide/data-exchange-intro.html"}, {"id": 323, "area": "Performance Concepts", "question": "A Snowflake user executed a query and received the results. Another user executed the same query 4 hours later. The data had not changed. What will occur?", "options": ["A) No virtual warehouse will be used, data will be read from the result cache.", "B) No virtual warehouse will be used, data will be read from the local disk cache.", "C) The default virtual warehouse will be used to read all data.", "D) The virtual warehouse that is defined at the session level will be used to read all data."], "chooseN": 1, "correct": ["No virtual warehouse will be used, data will be read from the result cache."], "explanation": "If the data has not changed since the first execution of the query, Snowflake utilizes its result cache. The second user's query will return the results from this cache, without using any virtual warehouse. This feature enhances query performance and reduces compute costs.", "reference": "https://docs.snowflake.com/en/user-guide/querying-cache.html"}, {"id": 324, "area": "Performance Concepts", "question": "Which feature allows a user the ability to control the organization of data in a micro-partition?", "options": ["A) Range Partitioning", "B) Search Optimization Service", "C) Automatic Clustering", "D) Horizontal Partitioning"], "chooseN": 1, "correct": ["Automatic Clustering"], "explanation": "Automatic Clustering in Snowflake allows users to control the organization of data within micro-partitions. This feature automatically reorganizes data in a table’s micro-partitions based on specified clustering keys, optimizing data storage and access for query performance.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions.html"}, {"id": 325, "area": "Data Protection and Data Sharing", "question": "Which privilege must be granted to a share to allow secure views the ability to reference data in multiple databases?", "options": ["A) CREATE_SHARE on the account", "B) SHARE on databases and schemas", "C) SELECT on tables used by the secure view", "D) REFERENCE_USAGE on databases"], "chooseN": 1, "correct": ["REFERENCE_USAGE on databases"], "explanation": "The 'REFERENCE_USAGE' privilege on databases must be granted to a share to enable secure views to reference data across multiple databases. This privilege allows the shared secure views to access the necessary data while maintaining security and control.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-reader-sharing-objects.html"}, {"id": 326, "area": "Account Access and Security", "question": "In which use case does Snowflake apply egress charges?", "options": ["A) Data sharing within a specific region", "B) Query result retrieval", "C) Database replication", "D) Loading data into Snowflake"], "chooseN": 1, "correct": ["Database replication"], "explanation": "Snowflake applies egress charges in the case of database replication, especially when replicating data across different regions or cloud platforms. This involves transferring data out of Snowflake’s hosted storage, incurring egress charges.", "reference": "https://docs.snowflake.com/en/user-guide/database-replication-intro.html"}, {"id": 327, "area": "Performance Concepts", "question": "Which of the following compute resources or features are managed by Snowflake? (Choose two.)", "options": ["A) Execute a COPY command", "B) Updating data", "C) Snowpipe", "D) AUTOMATIC_CLUSTERING", "E) Scaling up a warehouse"], "chooseN": 2, "correct": ["Snowpipe", "AUTOMATIC_CLUSTERING"], "explanation": "In Snowflake, both Snowpipe and AUTOMATIC_CLUSTERING are managed features. Snowpipe automates data loading into Snowflake, and AUTOMATIC_CLUSTERING continuously and automatically reorganizes data in tables to optimize query performance.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-snowpipe-intro.html, https://docs.snowflake.com/en/user-guide/tables-clustering-keys.html"}, {"id": 328, "area": "Data Transformations", "question": "A materialized view should be created when which of the following occurs? (Choose two.)", "options": ["A) There is minimal cost associated with running the query.", "B) The query consumes many compute resources every time it runs.", "C) The base table gets updated frequently.", "D) The query is highly optimized and does not consume many compute resources.", "E) The results of the query do not change often and are used frequently."], "chooseN": 2, "correct": ["The query consumes many compute resources every time it runs.", "The results of the query do not change often and are used frequently."], "explanation": "Creating a materialized view in Snowflake is beneficial when a query consumes substantial compute resources each time it runs, and when the results of the query are relatively static and accessed frequently. Materialized views store precomputed results, reducing computational load and accelerating data retrieval.", "reference": "https://docs.snowflake.com/en/user-guide/views-materialized.html"}, {"id": 329, "area": "Account Access and Security", "question": "What privilege should a user be granted to change permissions for new objects in a managed access schema?", "options": ["A) Grant the OWNERSHIP privilege on the schema.", "B) Grant the OWNERSHIP privilege on the database.", "C) Grant the MANAGE GRANTS global privilege.", "D) Grant ALL privileges on the schema."], "chooseN": 1, "correct": ["Grant the OWNERSHIP privilege on the schema."], "explanation": "To change permissions for new objects in a managed access schema, a user should be granted the OWNERSHIP privilege on the schema. This privilege allows the user to manage access and permissions for objects within the schema.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-privileges.html"}, {"id": 330, "area": "Data Protection and Data Sharing", "question": "What happens when a Data Provider revokes privileges to a share on an object in their source database?", "options": ["A) The object immediately becomes unavailable for all Data Consumers.", "B) Any additional data arriving after this point in time will not be visible to Data Consumers.", "C) The Data Consumers stop seeing data updates and become responsible for storage charges for the object.", "D) A static copy of the object at the time the privilege was revoked is created in the Data Consumers account."], "chooseN": 1, "correct": ["The object immediately becomes unavailable for all Data Consumers."], "explanation": "When a Data Provider revokes privileges to a share on an object in their source database, the object immediately becomes unavailable for all Data Consumers. This means that Data Consumers lose access to the object and cannot view or query its data.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-provider.html#revoking-sharing-privileges"}, {"id": 331, "area": "Data Loading and Unloading", "question": "Which command can be used to load data into an internal stage?", "options": ["A) LOAD", "B) COPY", "C) GET", "D) PUT"], "chooseN": 1, "correct": ["PUT"], "explanation": "The 'PUT' command is used in Snowflake to load data into an internal stage. This command uploads data files from a local file system to an internal stage in Snowflake, preparing them for further processing or loading into tables.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-local-file-system-stage.html"}, {"id": 332, "area": "Data Protection and Data Sharing", "question": "What is the MINIMUM Snowflake edition required to use the periodic rekeying of micro-partitions?", "options": ["A) Enterprise", "B) Business Critical", "C) Standard", "D) Virtual Private Snowflake"], "chooseN": 1, "correct": ["Enterprise"], "explanation": "The minimum Snowflake edition required to use the periodic rekeying of micro-partitions is the 'Enterprise' edition. According to Snowflake's official documentation, periodic rekeying of encrypted data is available in both Enterprise and Business Critical editions, with Enterprise being the minimum required edition.", "reference": "https://docs.snowflake.com/en/user-guide/security-encryption-manage.html#label-periodic-rekeying"}, {"id": 333, "area": "Data Loading and Unloading", "question": "Which stage type can be altered and dropped?", "options": ["A) Database stage", "B) External stage", "C) Table stage", "D) User stage"], "chooseN": 1, "correct": ["External stage"], "explanation": "In Snowflake, only Named stages (Internal Named stages and External stages) can be altered and dropped using ALTER STAGE and DROP STAGE commands. User stages (@~) and Table stages (@%table) are automatically created and managed by Snowflake and cannot be altered or dropped. Note: 'Database stage' is not a standard Snowflake term. Among the available options, only External stage (a type of Named stage referencing external cloud storage) can be altered and dropped.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/drop-stage"}, {"id": 334, "area": "Data Loading and Unloading", "question": "Which Snowflake object enables loading data from files as soon as they are available in a cloud storage location?", "options": ["A) Pipe", "B) External stage", "C) Task", "D) Stream"], "chooseN": 1, "correct": ["Pipe"], "explanation": "In Snowflake, a 'Pipe' is used for continuous, automated loading of data from files as soon as they become available in a cloud storage location. Pipes leverage Snowpipe, Snowflake's service that automates the loading of data and efficiently manages the ingestion process.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-snowpipe-intro.html"}, {"id": 335, "area": "Data Transformations", "question": "A user is loading JSON documents composed of a huge array containing multiple records into Snowflake. The user enables the STRIP_OUTER_ARRAY file format option. What does the STRIP_OUTER_ARRAY file format do?", "options": ["A) It removes the last element of the outer array.", "B) It removes the outer array structure and loads the records into separate table rows.", "C) It removes the trailing spaces in the last element of the outer array and loads the records into separate table columns.", "D) It removes the NULL elements from the JSON object eliminating invalid data and enables the ability to load the records."], "chooseN": 1, "correct": ["It removes the outer array structure and loads the records into separate table rows."], "explanation": "The STRIP_OUTER_ARRAY file format option in Snowflake is used when loading JSON data. It removes the outer array structure of the JSON document, allowing the individual records within the array to be loaded into separate rows in a Snowflake table.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-transform.html#loading-semi-structured-data-json-avro-xml"}, {"id": 336, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which of the following describes how multiple Snowflake accounts in a single organization relate to various cloud providers?", "options": ["A) Each Snowflake account can be hosted in a different cloud vendor and region.", "B) Each Snowflake account must be hosted in a different cloud vendor and region.", "C) All Snowflake accounts must be hosted in the same cloud vendor and region.", "D) Each Snowflake account can be hosted in a different cloud vendor, but must be in the same region."], "chooseN": 1, "correct": ["Each Snowflake account can be hosted in a different cloud vendor and region."], "explanation": "Snowflake's architecture allows flexibility in deployment. Each Snowflake account in an organization can be hosted on different cloud vendors and in different regions, providing flexibility and control over data residency and compliance requirements.", "reference": "https://docs.snowflake.com/en/user-guide/intro-key-concepts.html#cloud-agnostic-architecture"}, {"id": 337, "area": "Performance Concepts", "question": "If a Snowflake user decides a table should be clustered, what should be used as the cluster key?", "options": ["A) The columns that are queried in the select clause.", "B) The columns with very high cardinality.", "C) The columns with many different values.", "D) The columns most actively used in the select filters."], "chooseN": 1, "correct": ["The columns most actively used in the select filters."], "explanation": "When determining a cluster key for a Snowflake table, it is best to use columns that are most actively used in the select filters. This approach aligns the physical organization of the table with common query patterns, improving query performance by reducing the amount of data scanned.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-keys.html"}, {"id": 338, "area": "Data Transformations", "question": "What are value types that a VARIANT column can store? (Choose two.)", "options": ["A) STRUCT", "B) OBJECT", "C) BINARY", "D) ARRAY", "E) CLOB"], "chooseN": 2, "correct": ["OBJECT", "ARRAY"], "explanation": "In Snowflake, a VARIANT column can store semi-structured data types. The two primary value types it can hold are OBJECT and ARRAY. OBJECT is used for JSON-like structures, and ARRAY can store ordered lists of values.", "reference": "https://docs.snowflake.com/en/sql-reference/data-types-semistructured.html#variant"}, {"id": 339, "area": "Data Loading and Unloading", "question": "A company needs to read multiple terabytes of data for an initial load as part of a Snowflake migration. The company can control the number and size of CSV extract files. How does Snowflake recommend maximizing the load performance?", "options": ["A) Use auto-ingest Snowpipes to load large files in a serverless model.", "B) Produce the largest files possible, reducing the overall number of files to process.", "C) Produce a larger number of smaller files and process the ingestion with size Small virtual warehouses.", "D) Use an external tool to issue batched row-by-row inserts within BEGIN TRANSACTION and COMMIT commands."], "chooseN": 1, "correct": ["Produce a larger number of smaller files and process the ingestion with size Small virtual warehouses."], "explanation": "Snowflake recommends producing a larger number of smaller files for the initial load of multiple terabytes of data. Processing these smaller files with size Small virtual warehouses can maximize the load performance by enabling parallel processing and efficient data ingestion.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-considerations-prepare.html"}, {"id": 340, "area": "Data Protection and Data Sharing", "question": "For non-materialized views, what column in Information Schema and Account Usage identifies whether a view is secure or not?", "options": ["A) CHECK_OPTION", "B) IS_SECURE", "C) IS_UPDATEABLE", "D) TABLE_NAME"], "chooseN": 1, "correct": ["IS_SECURE"], "explanation": "For non-materialized views in Snowflake, the 'IS_SECURE' column in the Information Schema and Account Usage identifies whether a view is secure or not. This column provides information on the security status of the view.", "reference": "https://docs.snowflake.com/en/sql-reference/info-schema/views.html"}, {"id": 341, "area": "Data Loading and Unloading", "question": "The bulk data load history that is available upon completion of the COPY statement is stored where and for how long?", "options": ["A) In the metadata of the target table for 14 days", "B) In the metadata of the pipe for 14 days", "C) In the metadata of the target table for 64 days", "D) In the metadata of the pipe for 64 days"], "chooseN": 1, "correct": ["In the metadata of the target table for 64 days"], "explanation": "Bulk data load history (via COPY statement) is stored in the metadata of the target table for 64 days. This is distinct from Snowpipe load history, which is stored in the metadata of the pipe for 14 days. The 14-day retention applies only to Snowpipe continuous loading, not to bulk COPY operations.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-snowpipe-monitor.html#viewing-load-history-for-a-pipe"}, {"id": 342, "area": "Account Access and Security", "question": "User INQUISITIVE_PERSON has been granted the role DATA_SCIENCE. The role DATA_SCIENCE has privileges OWNERSHIP on the schema MARKETING of the database ANALYTICS_DW. Which command will show all privileges granted to that schema?", "options": ["A) SHOW GRANTS ON ROLE DATA_SCIENCE", "B) SHOW GRANTS ON SCHEMA ANALYTICS_DW.MARKETING", "C) SHOW GRANTS TO USER INQUISITIVE_PERSON", "D) SHOW GRANTS OF ROLE DATA_SCIENCE"], "chooseN": 1, "correct": ["SHOW GRANTS ON SCHEMA ANALYTICS_DW.MARKETING"], "explanation": "To view all privileges granted to the schema 'MARKETING' of the database 'ANALYTICS_DW', the command 'SHOW GRANTS ON SCHEMA ANALYTICS_DW.MARKETING' should be used. This command displays the permissions associated with the specified schema.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/show-grants.html"}, {"id": 343, "area": "Data Protection and Data Sharing", "question": "Which of the following are characteristics of security in Snowflake?", "options": ["A) Account and user authentication is only available with the Snowflake Business Critical edition.", "B) Support for HIPAA and GDPR compliance is available for UI Snowflake editions.", "C) Periodic rekeying of encrypted data is available with the Snowflake Enterprise edition and higher", "D) Private communication to internal stages is allowed in the Snowflake Enterprise edition and higher."], "chooseN": 1, "correct": ["Periodic rekeying of encrypted data is available with the Snowflake Enterprise edition and higher"], "explanation": "A key characteristic of security in Snowflake is the periodic rekeying of encrypted data, which is available with the Snowflake Enterprise edition and higher. This feature enhances data security by periodically changing the encryption keys used to protect stored data.", "reference": "https://docs.snowflake.com/en/user-guide/security-encryption.html#encryption-key-rotation"}, {"id": 344, "area": "Data Protection and Data Sharing", "question": "Which of the following objects can be shared through secure data sharing?", "options": ["A) Masking policy", "B) Stored procedure", "C) Task", "D) External table"], "chooseN": 1, "correct": ["External table"], "explanation": "In Snowflake's secure data sharing, external tables can be shared with consumers. Secure data sharing allows sharing of database objects like tables and views, including external tables, without copying or moving data.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-intro.html"}, {"id": 345, "area": "Data Transformations", "question": "Which formats does Snowflake store unstructured data in? (Choose two.)", "options": ["A) GeoJSON", "B) Array", "C) XML", "D) Object", "E) BLOB"], "chooseN": 1, "correct": ["XML"], "explanation": "Snowflake supports XML as one of its semi-structured file formats. Semi-structured data is typically stored in ARRAY, OBJECT, or VARIANT data types, while unstructured data such as documents, images, and audio has no inherent schema.", "reference": "https://docs.snowflake.com/en/sql-reference/data-types-semistructured.html"}, {"id": 346, "area": "Data Loading and Unloading", "question": "A user is preparing to load data from an external stage. Which practice will provide the MOST efficient loading performance?", "options": ["A) Organize files into logical paths", "B) Store the files on the external stage to ensure caching is maintained", "C) Use pattern matching for regular expression execution", "D) Load the data in one large file"], "chooseN": 1, "correct": ["Organize files into logical paths"], "explanation": "Organizing files into logical paths is an efficient practice for loading data from an external stage in Snowflake. This helps in managing and categorizing the files effectively, making the data load process more streamlined and efficient.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-considerations-stage.html"}, {"id": 347, "area": "Performance Concepts", "question": "What effect does WAIT_FOR_COMPLETION = TRUE have when running an ALTER WAREHOUSE command and changing the warehouse size?", "options": ["A) The warehouse size does not change until all queries currently running in the warehouse have completed.", "B) The warehouse size does not change until all queries currently in the warehouse queue have completed.", "C) The warehouse size does not change until the warehouse is suspended and restarted.", "D) It does not return from the command until the warehouse has finished changing its size."], "chooseN": 1, "correct": ["It does not return from the command until the warehouse has finished changing its size."], "explanation": "Setting WAIT_FOR_COMPLETION = TRUE in the ALTER WAREHOUSE command in Snowflake means that the command will not return until the warehouse has finished changing its size. This ensures that the resize operation is completed before the command returns control.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/alter-warehouse.html"}, {"id": 348, "area": "Data Loading and Unloading", "question": "Which of the following can be used when unloading data from Snowflake? (Choose two.)", "options": ["A) When unloading semi-structured data, it is recommended that the STRIP_OUTER_ARRAY option be used.", "B) Use the ENCODING file format option to change the encoding from the default UTF-8.", "C) The OBJECT_CONSTRUCT function can be used to convert relational data to semi-structured data.", "D) By using the SINGLE = TRUE parameter, a single file up to 5 GB in size can be exported to the storage layer.", "E) Use the PARSE_JSON function to ensure structured data will be unloaded into the VARIANT data type."], "chooseN": 2, "correct": ["When unloading semi-structured data, it is recommended that the STRIP_OUTER_ARRAY option be used.", "By using the SINGLE = TRUE parameter, a single file up to 5 GB in size can be exported to the storage layer."], "explanation": "When unloading data from Snowflake, the ENCODING file format option allows users to change the character encoding from the default UTF-8. The SINGLE = TRUE parameter facilitates exporting data as a single file up to 5 GB in size, which can be useful for large data sets.", "reference": "https://docs.snowflake.com/en/user-guide/data-unload-considerations.html"}, {"id": 349, "area": "Snowflake Data Cloud Features & Architecture", "question": "What data is stored in the Snowflake storage layer? (Choose two.)", "options": ["A) Snowflake parameters", "B) Micro-partitions", "C) Query history", "D) Persisted query results", "E) Standard and secure view results"], "chooseN": 1, "correct": ["Micro-partitions"], "explanation": "Snowflake table data is automatically divided into micro-partitions, which are the contiguous units of storage in the database storage layer. Snowflake uses separate cloud services and compute layers for metadata, optimization, and caching behavior. Parameters, query history, and view output are not", "reference": "https://docs.snowflake.com/en/user-guide/snowflake-architecture.html"}, {"id": 350, "area": "Data Protection and Data Sharing", "question": "A data provider wants to share data with a consumer who does not have a Snowflake account. The provider creates a reader account for the consumer following these steps: Based on this configuration what is true of the reader account?", "options": ["A) Created a user called 'CONSUMER'", "B) Created a database to hold the share and an extra-small warehouse to query the data", "C) Granted the role PUBLIC the following privileges: Usage on the warehouse, database, and schema, and SELECT on all the objects in the share", "D) The reader account will automatically use the Standard edition of Snowflake.", "E) The reader account compute will be billed to the provider account.", "F) The reader account can clone data the provider has shared, but cannot re-share it.", "G) The reader account can create a copy of the shared data using CREATE TABLE AS..."], "chooseN": 1, "correct": ["The reader account compute will be billed to the provider account."], "explanation": "In Snowflake, when a data provider creates a reader account for a consumer, the compute resources used by the reader account are billed to the provider's account. Additionally, the reader account can clone the shared data but is not allowed to re-share it.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-reader-accounts.html"}, {"id": 351, "area": "Performance Concepts", "question": "Which of the following activities consume virtual warehouse credits in the Snowflake environment? (Choose two.)", "options": ["A) Caching query results", "B) Running EXPLAIN and SHOW commands", "C) Cloning a database", "D) Running a custom query", "E) Running COPY commands"], "chooseN": 2, "correct": ["Running a custom query", "Running COPY commands"], "explanation": "In the Snowflake environment, running a custom query and running COPY commands consume virtual warehouse credits. These activities require computational resources, and thus, the credits are used as a measure of the compute time consumed.", "reference": "https://docs.snowflake.com/en/user-guide/credits.html"}, {"id": 352, "area": "Data Loading and Unloading", "question": "When loading data into Snowflake, the COPY command supports which of the following?", "options": ["A) Joins", "B) Filters", "C) Column reordering", "D) Aggregates"], "chooseN": 1, "correct": ["Column reordering"], "explanation": "When using the COPY command to load data into Snowflake, it supports column reordering. This feature allows the data being loaded to be reordered to match the column order of the target table, facilitating flexible data loading.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-table.html"}, {"id": 353, "area": "Performance Concepts", "question": "What is cached during a query on a virtual warehouse?", "options": ["A) All columns in a micro-partition", "B) Any columns accessed during the query", "C) The columns in the result set of the query", "D) All rows accessed during the query"], "chooseN": 1, "correct": ["Any columns accessed during the query"], "explanation": "During a query on a virtual warehouse in Snowflake, any columns accessed during the query are cached. This caching mechanism helps improve performance by reducing the need to access the same data repeatedly from the storage layer.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-considerations.html#data-caching"}, {"id": 354, "area": "Data Loading and Unloading", "question": "What is the default character set used when loading CSV files into Snowflake?", "options": ["A) UTF-8", "B) UTF-16"], "chooseN": 1, "correct": ["UTF-8"], "explanation": "When loading CSV files into Snowflake, the default character set used is UTF-8. This character encoding supports a wide range of characters and is commonly used for text data.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-considerations-prepare.html#file-formats"}, {"id": 355, "area": "Data Transformations", "question": "Which of the following describes external functions in Snowflake?", "options": ["A) They are a type of User-defined Function (UDF).", "B) They contain their own SQL code.", "C) They call code that is stored inside of Snowflake.", "D) They can return multiple rows for each row received."], "chooseN": 1, "correct": ["They are a type of User-defined Function (UDF)."], "explanation": "External functions in Snowflake are a type of User-Defined Function (UDF). Unlike regular UDFs, external functions do not contain their own code within Snowflake. Instead, they call code executed outside of Snowflake through a proxy service (such as AWS API Gateway or Azure API Management) that relays requests to a remote service (like AWS Lambda or Azure Functions). They are scalar functions that return one row for each row received.", "reference": "https://docs.snowflake.com/en/sql-reference/external-functions-introduction.html"}, {"id": 356, "area": "Account Access and Security", "question": "Which of the following are valid methods for authenticating users for access into Snowflake? (Choose three.)", "options": ["A) SCIM", "B) Federated authentication", "C) TLS 1.2", "D) Key-pair authentication", "E) OAuth", "F) OCSP authentication"], "chooseN": 3, "correct": ["Federated authentication", "Key-pair authentication", "OAuth"], "explanation": "For authenticating users into Snowflake, federated authentication, key-pair authentication, and OAuth are valid methods. Federated authentication allows integration with identity providers, key-pair authentication uses cryptographic keys, and OAuth is a standard for access delegation.", "reference": "https://docs.snowflake.com/en/user-guide/admin-security-fed-auth-use.html"}, {"id": 357, "area": "Performance Concepts", "question": "A user has a standard multi-cluster warehouse auto-scaling policy in place. Which condition will trigger a cluster to shut-down?", "options": ["A) When after 2-3 consecutive checks the system determines that the load on the most-loaded cluster could be redistributed.", "B) When after 5-6 consecutive checks the system determines that the load on the most-loaded cluster could be redistributed.", "C) When after 5-6 consecutive checks the system determines that the load on the least-loaded cluster could be redistributed.", "D) When after 2-3 consecutive checks the system determines that the load on the least-loaded cluster could be redistributed."], "chooseN": 1, "correct": ["When after 2-3 consecutive checks the system determines that the load on the most-loaded cluster could be redistributed."], "explanation": "In Snowflake's standard multi-cluster warehouse auto-scaling policy, a cluster will shut down when, after 5-6 consecutive checks, the system determines that the load on the least-loaded cluster could be redistributed to other clusters. This helps in optimizing resource usage and cost.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-multicluster.html"}, {"id": 358, "area": "Data Protection and Data Sharing", "question": "What is the minimum Snowflake edition needed for database failover and fail-back between Snowflake accounts for business continuity and disaster recovery?", "options": ["A) Standard", "B) Enterprise", "C) Business Critical", "D) Virtual Private Snowflake"], "chooseN": 1, "correct": ["Business Critical"], "explanation": "The minimum Snowflake edition required for database failover and fail-back between Snowflake accounts, which are crucial for business continuity and disaster recovery, is the Business Critical edition. This edition provides advanced features for high availability and security.", "reference": "https://docs.snowflake.com/en/user-guide/database-replication-failover.html"}, {"id": 359, "area": "Data Transformations", "question": "How would a user execute a series of SQL statements using a task?", "options": ["A) Include the SQL statements in the body of the task CREATE TASK mytask .. AS INSERT INTO target1 SELECT .. FROM stream_s1 WHERE .. INSERT INTO target2 SELECT .. FROM stream_s1 WHERE ..", "B) A stored procedure can have only one DML statement per stored procedure invocation and therefore the user should sequence stored procedure calls in the task definition CREATE TASK mytask \tAS call stored_proc1(); call stored_proc2();", "C) Use a stored procedure executing multiple SQL statements and invoke the stored procedure from the task. CREATE TASK mytask", "D) Create a task for each SQL statement (e.g. resulting in task1, task2, etc.) and string the series of SQL statements by having a control task calling task1, task2, etc. sequentially."], "chooseN": 1, "correct": ["Use a stored procedure executing multiple SQL statements and invoke the stored procedure from the task. CREATE TASK mytask"], "explanation": "To execute a series of SQL statements using a task in Snowflake, a user should use a stored procedure that executes multiple SQL statements and then invoke this stored procedure from the task. This method allows multiple statements to be executed in sequence within a single task.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/create-task.html"}, {"id": 360, "area": "Account Access and Security", "question": "How many resource monitors can be assigned at the account level?", "options": ["A) 1", "B) 2", "C) 3", "D) 4"], "chooseN": 1, "correct": ["1"], "explanation": "At the account level in Snowflake, only one resource monitor can be assigned. This resource monitor is used to track and manage the overall resource usage and credits consumption for the entire Snowflake account.", "reference": "https://docs.snowflake.com/en/user-guide/resource-monitors.html"}, {"id": 361, "area": "Performance Concepts", "question": "Data storage for individual tables can be monitored using which commands and/or objects? (Choose two.)", "options": ["A) SHOW STORAGE BY TABLE;", "B) SHOW TABLES;", "C) Information Schema -> TABLE_HISTORY", "D) Information Schema -> TABLE_FUNCTION", "E) Information Schema -> TABLE_STORAGE_METRICS"], "chooseN": 2, "correct": ["SHOW STORAGE BY TABLE;", "Information Schema -> TABLE_STORAGE_METRICS"], "explanation": "To monitor data storage for individual tables in Snowflake, the 'SHOW STORAGE BY TABLE;' command and the 'TABLE_STORAGE_METRICS' object in the Information Schema can be used. These tools provide detailed insights into the storage utilization of each table.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/show-storage.html"}, {"id": 362, "area": "Performance Concepts", "question": "How would a user run a multi-cluster warehouse in maximized mode?", "options": ["A) Configure the maximum clusters setting to 'Maximum.'", "B) Turn on the additional clusters manually after starting the warehouse.", "C) Set the minimum Clusters and maximum Clusters settings to the same value.", "D) Set the minimum clusters and maximum clusters settings to different values."], "chooseN": 1, "correct": ["Set the minimum Clusters and maximum Clusters settings to the same value."], "explanation": "To run a multi-cluster warehouse in maximized mode in Snowflake, the user should set both the minimum and maximum clusters settings to the same value. This configuration ensures that the maximum number of clusters are always running, providing maximized compute resources.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-multicluster.html"}, {"id": 363, "area": "Data Loading and Unloading", "question": "What internal stages are available in Snowflake? (Choose three.)", "options": ["A) Schema stage", "B) Named stage", "C) User stage", "D) Stream stage", "E) Table stage", "F) Database stage"], "chooseN": 3, "correct": ["Named stage", "User stage", "Table stage"], "explanation": "In Snowflake, the internal stages available are Named stage, User stage, and Table stage. These stages are used for different purposes: Named stage for storing files temporarily, User stage for individual user file storage, and Table stage for storing files associated with a specific table.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-local-file-system-create-stage.html"}, {"id": 364, "area": "Data Loading and Unloading", "question": "Which stages are used with the Snowflake PUT command to upload files from a local file system? (Choose three.)", "options": ["A) Schema Stage", "B) User Stage", "C) Database Stage", "D) Table Stage", "E) External Named Stage", "F) Internal Named Stage"], "chooseN": 3, "correct": ["User Stage", "Internal Named Stage", "Table Stage"], "explanation": "The PUT command in Snowflake is used to upload files from a local file system to Snowflake. This command can be used with a User Stage, Table Stage, or an Internal Named Stage. These stages are designed to temporarily store files before they are loaded into Snowflake tables.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/put.html"}, {"id": 365, "area": "Data Transformations", "question": "Which data type can store more than one type of data structure?", "options": ["A) JSON", "B) BINARY", "C) VARCHAR", "D) VARIANT"], "chooseN": 1, "correct": ["VARIANT"], "explanation": "The VARIANT data type in Snowflake is capable of storing multiple types of data structures. It is used for semi-structured data and can store JSON, XML, AVRO, or other formats in a single column.", "reference": "https://docs.snowflake.com/en/sql-reference/data-types-semistructured.html#variant"}, {"id": 366, "area": "Account Access and Security", "question": "User-level network policies can be created by which of the following roles? (Choose two.)", "options": ["A) ROLEADMIN", "B) ACCOUNTADMIN", "C) SYSADMIN", "D) SECURITYADMIN", "E) USERADMIN"], "chooseN": 2, "correct": ["ACCOUNTADMIN", "SECURITYADMIN"], "explanation": "In Snowflake, user-level network policies can be created and managed by the ACCOUNTADMIN and SECURITYADMIN roles. These roles have the necessary privileges to manage security and access settings, including network policies.", "reference": "https://docs.snowflake.com/en/user-guide/security-network-policies.html#managing-network-policies"}, {"id": 367, "area": "Account Access and Security", "question": "What SQL command would be used to view all roles that were granted to USER1?", "options": ["A) show grants to user USER1;", "B) show grants user USER1;", "C) describe user USER1;", "D) show grants on user USER1;"], "chooseN": 1, "correct": ["show grants to user USER1;"], "explanation": "The command 'show grants to user USER1;' is used in Snowflake to display all roles that have been granted to a specific user, in this case, USER1. This command provides information about user permissions and role assignments.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/show-grants.html"}, {"id": 368, "area": "Data Protection and Data Sharing", "question": "Which ACCOUNT_USAGE views are used to evaluate the details of dynamic data masking? (Choose two.)", "options": ["A) ROLES", "B) POLICY_REFERENCES", "C) QUERY_HISTORY", "D) RESOURCE_MONITORS", "E) ACCESS_HISTORY", "F) MASKING_POLICIES"], "chooseN": 2, "correct": ["POLICY_REFERENCES", "MASKING_POLICIES"], "explanation": "The ACCOUNT_USAGE views 'POLICY_REFERENCES' and 'MASKING_POLICIES' in Snowflake are used to evaluate the details of dynamic data masking. These views provide information about the masking policies applied and their references across the database.", "reference": "https://docs.snowflake.com/en/sql-reference/account-usage.html"}, {"id": 369, "area": "Data Loading and Unloading", "question": "Which of the following are considerations when using a directory table when working with unstructured data? (Choose two.)", "options": ["A) A directory table is a separate database object.", "B) Directory tables store data file metadata.", "C) A directory table will be automatically added to a stage.", "D) Directory tables do not have their own grantable privileges.", "E) Directory table data cannot be refreshed manually."], "chooseN": 2, "correct": ["Directory tables store data file metadata.", "Directory tables do not have their own grantable privileges."], "explanation": "Directory tables are implicit objects layered on stages, store file-level metadata about staged files, and have no grantable privileges of their own. Therefore, the two correct considerations are that they store data file metadata and that they do not have their own grantable privileges.", "reference": "https://docs.snowflake.com/en/user-guide/tables-external-tables.html"}, {"id": 370, "area": "Account Access and Security", "question": "The first user assigned to a new account, ACCOUNTADMIN, should create at least one additional user with which administrative privilege?", "options": ["A) USERADMIN", "B) PUBLIC", "C) ORGADMIN", "D) SYSADMIN"], "chooseN": 1, "correct": ["USERADMIN"], "explanation": "For a new Snowflake account, the first user assigned as ACCOUNTADMIN should create at least one additional user with the USERADMIN privilege. This administrative privilege is essential for managing users and roles within the Snowflake environment.", "reference": "https://docs.snowflake.com/en/user-guide/admin-user-management.html"}, {"id": 371, "area": "Data Protection and Data Sharing", "question": "Which statement describes how Snowflake supports reader accounts?", "options": ["A) A reader account can consume data from the provider account that created it and combine it with its own data.", "B) A consumer needs to become a licensed Snowflake customer as data sharing is only supported between Snowflake accounts.", "C) The users in a reader account can query data that has been shared with the reader account and can perform DML tasks.", "D) The SHOW MANAGED ACCOUNTS command will view all the reader accounts that have been created for an account."], "chooseN": 1, "correct": ["The SHOW MANAGED ACCOUNTS command will view all the reader accounts that have been created for an account."], "explanation": "The SHOW MANAGED ACCOUNTS command is used to view all reader accounts created for a provider account. (A) is incorrect because reader accounts can only consume data from the provider -- they cannot upload new data, modify existing data, or perform DML operations (INSERT, UPDATE, DELETE, MERGE), so they cannot 'combine with its own data.' (B) is incorrect because reader accounts exist precisely so consumers do NOT need a Snowflake license. (C) is incorrect because reader accounts cannot perform DML tasks -- they are restricted to querying shared data.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-reader-accounts.html"}, {"id": 372, "area": "Data Protection and Data Sharing", "question": "How does Snowflake allow a data provider with an Azure account in central Canada to share data with a data consumer on AWS in Australia?", "options": ["A) The data provider in Azure Central Canada can create a direct share to AWS Asia Pacific, if they are both in the same organization.", "B) The data consumer and data provider can form a Data Exchange within the same organization to create a share from Azure Central Canada to AWS Asia Pacific.", "C) The data provider uses the GET DATA workflow in the Snowflake Data Marketplace to create a share between Azure Central Canada and AWS Asia Pacific.", "D) The data provider must replicate the database to a secondary account in AWS Asia Pacific within the same organization then create a share to the data consumer's account"], "chooseN": 1, "correct": ["The data provider must replicate the database to a secondary account in AWS Asia Pacific within the same organization then create a share to the data consumer's account"], "explanation": "In Snowflake, a data provider with an Azure account in Central Canada can share data with a data consumer on AWS in Australia by replicating the database to a secondary account in AWS Asia Pacific within the same organization. After replication, they can create a share to the data consumer's account, enabling cross-cloud data sharing.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-intro.html"}, {"id": 373, "area": "Data Protection and Data Sharing", "question": "Which Snowflake objects can be shared with other Snowflake accounts? (Choose three.)", "options": ["A) Schemas", "B) Roles", "C) Secure Views", "D) Stored Procedures", "E) Tables", "F) Secure User-Defined Functions (UDFs)"], "chooseN": 4, "correct": ["Schemas", "Secure Views", "Tables", "Secure User-Defined Functions (UDFs)"], "explanation": "Snowflake secure data sharing supports sharing schemas, tables, secure views, and secure UDFs with other Snowflake accounts. The documentation states that providers can add schemas, tables, and secure views to a share, and that secure UDFs are also supported. When tables or views are shared, the con", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-using-shares.html"}, {"id": 374, "area": "Data Loading and Unloading", "question": "Which Snowflake feature will allow small volumes of data to continuously load into Snowflake and will incrementally make the data available for analysis?", "options": ["A) COPY INTO", "B) CREATE PIPE", "C) INSERT INTO", "D) TABLE STREAM"], "chooseN": 1, "correct": ["CREATE PIPE"], "explanation": "The CREATE PIPE command in Snowflake is used to create a Snowpipe, which allows for the continuous and incremental loading of data into Snowflake. Snowpipe automatically loads data as soon as it becomes available in a cloud storage location, making it suitable for small and continuous data loads.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-snowpipe-intro.html"}, {"id": 375, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which Snowflake partner specializes in data catalog solutions?", "options": ["A) Alation", "B) DataRobot", "C) dbt", "D) Tableau"], "chooseN": 1, "correct": ["Alation"], "explanation": "Alation is a Snowflake partner that specializes in data catalog solutions. Alation provides a collaborative data catalog platform that helps organizations find, understand, and govern their data.", "reference": "https://www.snowflake.com/en/why-snowflake/partners/all-partners/alation/"}, {"id": 376, "area": "Data Loading and Unloading", "question": "Which of the following can be executed/called with Snowpipe?", "options": ["A) A User Defined Function (UDF)", "B) A stored procedure", "C) A single COPY_INTO statement", "D) A single INSERT_INTO statement"], "chooseN": 1, "correct": ["A single COPY_INTO statement"], "explanation": "Snowpipe in Snowflake is designed to work with a single COPY INTO statement. This command is used to load data from a file stage (like an S3 bucket) into a Snowflake table. Snowpipe automates this process by continuously checking for new files in the stage and loading them as they arrive.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-snowpipe-create-pipe.html"}, {"id": 377, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which Snowflake objects will incur both storage and cloud compute charges? (Choose two.)", "options": ["A) Materialized view", "B) Sequence", "C) Secure view", "D) Transient table", "E) Clustered table"], "chooseN": 2, "correct": ["Materialized view", "Transient table"], "explanation": "In Snowflake, both materialized views and transient tables incur storage and compute charges. Materialized views store query results physically, thereby incurring storage costs. Transient tables, like other tables, incur storage costs for the data they hold and compute costs when they are accessed or manipulated.", "reference": "https://docs.snowflake.com/en/user-guide/tables-materialized-views.html"}, {"id": 378, "area": "Data Transformations", "question": "What file formats does Snowflake support for loading semi-structured data? (Choose three.)", "options": ["A) TSV", "B) JSON", "C) PDF", "D) Avro", "E) Parquet", "F) JPEG"], "chooseN": 3, "correct": ["JSON", "Avro", "Parquet"], "explanation": "Snowflake supports several file formats for loading semi-structured data, including JSON, Avro, and Parquet. These formats allow for efficient storage and querying of semi-structured data within Snowflake.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-prepare.html#semi-structured-file-formats"}, {"id": 379, "area": "Data Protection and Data Sharing", "question": "Which of the following statements about data sharing are true? (Choose two.)", "options": ["A) New objects created by a Data Provider are automatically shared with existing Data Consumers and Reader Accounts.", "B) All database objects can be included in a shared database.", "C) Reader Accounts are created by Data Providers.", "D) Shared databases are read-only.", "E) Reader Accounts are charged for warehouse usage."], "chooseN": 2, "correct": ["Reader Accounts are created by Data Providers.", "Shared databases are read-only."], "explanation": "In Snowflake data sharing, Reader Accounts are created by Data Providers to share data with consumers who don't have a Snowflake account. Shared databases are read-only to ensure data integrity and security, preventing Data Consumers from modifying the shared data.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-intro.html"}, {"id": 380, "area": "Performance Concepts", "question": "Credit charges for Snowflake virtual warehouses are calculated based on which of the following considerations? (Choose two.)", "options": ["A) The number of queries executed", "B) The number of active users assigned to the warehouse", "C) The size of the virtual warehouse", "D) The length of time the warehouse is running", "E) The duration of the queries that are executed"], "chooseN": 2, "correct": ["The size of the virtual warehouse", "The length of time the warehouse is running"], "explanation": "Credit charges for Snowflake virtual warehouses are determined by the size of the virtual warehouse and the length of time the warehouse is running. Larger warehouses and longer run times will consume more credits.", "reference": "https://docs.snowflake.com/en/user-guide/credits.html"}, {"id": 381, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which of the following are handled by the cloud services layer of the Snowflake architecture? (Choose two.)", "options": ["A) Query execution", "B) Data loading", "C) Time Travel data", "D) Security", "E) Authentication and access control"], "chooseN": 2, "correct": ["Security", "Authentication and access control"], "explanation": "The cloud services layer of the Snowflake architecture handles security and authentication and access control. This layer ensures secure data storage, processing, and access, managing user authentication and enforcing security policies.", "reference": "https://docs.snowflake.com/en/user-guide/snowflake-architecture.html"}, {"id": 382, "area": "Performance Concepts", "question": "What is a responsibility of Snowflake’s virtual warehouses?", "options": ["A) Infrastructure management", "B) Metadata management", "C) Query execution", "D) Query parsing and optimization", "E) Permanent storage of micro-partitions"], "chooseN": 1, "correct": ["Query execution"], "explanation": "In Snowflake, the primary responsibility of virtual warehouses is query execution. These warehouses are compute clusters that execute data processing tasks and queries, separate from storage and other management functions.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-overview.html"}, {"id": 383, "area": "Data Protection and Data Sharing", "question": "What features does Snowflake Time Travel enable?", "options": ["A) Querying data-related objects that were created within the past 365 days", "B) Restoring data-related objects that have been deleted within the past 90 days", "C) Conducting point-in-time analysis for BI reporting", "D) Analyzing data usage/manipulation over all periods of time"], "chooseN": 2, "correct": ["Restoring data-related objects that have been deleted within the past 90 days", "Conducting point-in-time analysis for BI reporting"], "explanation": "Snowflake Time Travel enables users to restore data-related objects that have been deleted within the past 90 days and conduct point-in-time analysis for BI reporting. This feature allows accessing historical data states for analysis and recovery purposes.", "reference": "https://docs.snowflake.com/en/user-guide/data-time-travel.html"}, {"id": 384, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which of the following statements describes a schema in Snowflake?", "options": ["A) A logical grouping of objects that belongs to a single database", "B) A logical grouping of objects that belongs to multiple databases", "C) A named Snowflake object that includes all the information required to share a database", "D) A uniquely identified Snowflake account within a business entity"], "chooseN": 1, "correct": ["A logical grouping of objects that belongs to a single database"], "explanation": "In Snowflake, a schema is a logical grouping of database objects such as tables, views, and functions, and it belongs to a single database. Schemas help organize and manage these objects within the database.", "reference": "https://docs.snowflake.com/en/user-guide/tables-intro.html#schemas"}, {"id": 385, "area": "Data Loading and Unloading", "question": "What is the recommended compressed file size range for continuous data loads using Snowpipe?", "options": ["A) 8-16 MB", "B) 16-24 MB", "C) 10-99 MB", "D) 100-250 MB"], "chooseN": 1, "correct": ["100-250 MB"], "explanation": "The recommended compressed file size for data loads (including Snowpipe) is 100-250 MB or larger. This applies to both bulk data loads and Snowpipe continuous loading. Files of this size optimize parallel processing and reduce per-file overhead costs. Smaller files increase overhead, while very large files risk long load times.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-snowpipe-best-practices.html"}, {"id": 386, "area": "Data Loading and Unloading", "question": "How long is Snowpipe data load history retained?", "options": ["A) As configured in the CREATE PIPE settings", "B) Until the pipe is dropped", "C) 64 days", "D) 14 days"], "chooseN": 1, "correct": ["14 days"], "explanation": "Snowpipe load history metadata is retained for 14 days. The Snowflake documentation states that pipes only maintain the load history metadata for 14 days, so the correct option is 14 days.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-snowpipe-manage.html#viewing-pipe-load-history"}, {"id": 387, "area": "Account Access and Security", "question": "A company strongly encourages all Snowflake users to self-enroll in Snowflake's default Multi-Factor Authentication (MFA) service to provide increased login security for users connecting to Snowflake. Which application will the Snowflake users need to install on their devices in order to connect with MFA?", "options": ["A) Okta Verify", "B) Duo Mobile", "C) Microsoft Authenticator", "D) Google Authenticator"], "chooseN": 1, "correct": ["Duo Mobile"], "explanation": "Snowflake's default Multi-Factor Authentication (MFA) service uses Duo Security. Therefore, Snowflake users looking to connect with MFA should install the Duo Mobile application on their devices to complete the MFA process.", "reference": "https://docs.snowflake.com/en/user-guide/admin-security-mfa.html"}, {"id": 388, "area": "Data Loading and Unloading", "question": "Which URL type allows users to access unstructured data without authenticating into Snowflake or passing an authorization token?", "options": ["A) Pre-signed URL", "B) Scoped URL", "C) Signed URL", "D) File URL"], "chooseN": 1, "correct": ["Pre-signed URL"], "explanation": "A pre-signed URL allows users to access unstructured data stored in cloud storage without the need for authenticating into Snowflake or passing an authorization token. This URL includes a signature that grants temporary access to the data.", "reference": "https://docs.snowflake.com/en/user-guide/data-unload-s3.html#specifying-an-aws-s3-bucket-and-location"}, {"id": 389, "area": "Account Access and Security", "question": "Where would a Snowflake user find information about query activity from 90 days ago?", "options": ["A) account_usage.query_history view", "B) account_usage.query_history_archive view", "C) information_schema.query_history view", "D) information_schema.query_history_by_session view"], "chooseN": 1, "correct": ["account_usage.query_history view"], "explanation": "Snowflake users would find query activity from 90 days ago in the ACCOUNT_USAGE.QUERY_HISTORY view, because it retains query history for the last 365 days (1 year).", "reference": "https://docs.snowflake.com/en/sql-reference/account-usage/query_history.html"}, {"id": 390, "area": "Account Access and Security", "question": "A marketing co-worker has requested the ability to change a warehouse size on their medium virtual warehouse called MKTG_WH. Which of the following statements will accommodate this request?", "options": ["A) ALLOW RESIZE ON WAREHOUSE MKTG_WH TO USER MKTG_LEAD;", "B) GRANT MODIFY ON WAREHOUSE MKTG_WH TO ROLE MARKETING;", "C) GRANT MODIFY ON WAREHOUSE MKTG_WH TO USER MKTG_LEAD;", "D) GRANT OPERATE ON WAREHOUSE MKTG_WH TO ROLE MARKET;"], "chooseN": 1, "correct": ["GRANT MODIFY ON WAREHOUSE MKTG_WH TO ROLE MARKETING;"], "explanation": "To accommodate the request to change the warehouse size for MKTG_WH, the statement 'GRANT MODIFY ON WAREHOUSE MKTG_WH TO ROLE MARKETING;' should be used. This grants the necessary privileges to the marketing role, allowing users with this role to modify the warehouse size.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/grant-privilege.html"}, {"id": 391, "area": "Data Protection and Data Sharing", "question": "Which of the following commands cannot be used within a reader account?", "options": ["A) CREATE SHARE", "B) ALTER WAREHOUSE", "C) DROP ROLE", "D) SHOW SCHEMAS", "E) DESCRIBE TABLE"], "chooseN": 1, "correct": ["CREATE SHARE"], "explanation": "Within a reader account in Snowflake, the command 'CREATE SHARE' cannot be used. Reader accounts are typically limited in terms of data sharing capabilities, and they cannot create shares to distribute data to other accounts.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-reader-accounts.html"}, {"id": 392, "area": "Data Transformations", "question": "Which TABLE function helps to convert semi-structured data to a relational representation?", "options": ["A) CHECK_JSON", "B) TO_JSON", "C) FLATTEN", "D) PARSE_JSON"], "chooseN": 1, "correct": ["FLATTEN"], "explanation": "The 'FLATTEN' TABLE function in Snowflake is used to convert semi-structured data into a relational format. This function is particularly useful for unpacking nested data structures like JSON arrays and objects into a format that can be easily queried with SQL.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/flatten.html"}, {"id": 393, "area": "Performance Concepts", "question": "Which query profile statistics help determine if efficient pruning is occurring? (Choose two.)", "options": ["A) Bytes sent over network", "B) Percentage scanned from cache", "C) Partitions total", "D) Bytes spilled to local storage", "E) Partitions scanned"], "chooseN": 2, "correct": ["Partitions total", "Partitions scanned"], "explanation": "To determine if efficient pruning is occurring in Snowflake, the 'Partitions total' and 'Partitions scanned' statistics in the query profile are helpful. These statistics indicate how many partitions exist and how many were actually scanned, reflecting the efficiency of pruning in reducing the amount of data processed.", "reference": "https://docs.snowflake.com/en/user-guide/ui-query-profile.html"}, {"id": 394, "area": "Data Protection and Data Sharing", "question": "What are the default Time Travel and Fail-safe retention periods for transient tables?", "options": ["A) Time Travel - 1 day, Fail-safe - 1 day", "B) Time Travel - 0 days, Fail-safe - 1 day", "C) Time Travel - 1 day, Failsafe - 0 days", "D) Transient tables are retained in neither Fail-safe nor Time Travel."], "chooseN": 1, "correct": ["Time Travel - 1 day, Failsafe - 0 days"], "explanation": "For transient tables in Snowflake, the default Time Travel retention period is 1 day. However, transient tables do not have a Fail-safe period. This means that they are only protected by Time Travel for the specified duration.", "reference": "https://docs.snowflake.com/en/user-guide/tables-temp-transient.html#comparison-of-table-types"}, {"id": 395, "area": "Data Loading and Unloading", "question": "Which command is used to unload data from a Snowflake table into a file in a stage?", "options": ["A) COPY INTO", "B) GET", "C) WRITE", "D) EXTRACT INTO"], "chooseN": 1, "correct": ["COPY INTO"], "explanation": "The 'COPY INTO' command in Snowflake is used to unload data from a table and export it to a file in a stage. This command enables data extraction and storage in a specified file format in an external stage or cloud storage location.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-location.html"}, {"id": 396, "area": "Data Transformations", "question": "What are advantages clones have over tables created with CREATE TABLE AS SELECT statement? (Choose two.)", "options": ["A) The clone always stays in sync with the original table.", "B) The clone has better query performance.", "C) The clone is created almost instantly.", "D) The clone will have time travel history from the original table.", "E) The clone saves space by not duplicating storage."], "chooseN": 2, "correct": ["The clone is created almost instantly.", "The clone saves space by not duplicating storage."], "explanation": "Clones in Snowflake have the advantages of being created almost instantly and saving storage space, as they do not duplicate the data from the original table. Instead, clones use Snowflake's unique architecture to maintain separate metadata while sharing the same underlying data files.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clone.html"}, {"id": 397, "area": "Account Access and Security", "question": "How often are the Account and Table master keys automatically rotated by Snowflake?", "options": ["A) 30 Days", "B) 60 Days", "C) 90 Days", "D) 365 Days."], "chooseN": 1, "correct": ["30 Days"], "explanation": "Snowflake automatically rotates keys in its managed key hierarchy, including account and table master keys, every 30 days (when they are more than 30 days old).", "reference": "https://docs.snowflake.com/en/user-guide/security-encryption-at-rest.html"}, {"id": 398, "area": "Performance Concepts", "question": "Which privilege is required for a role to be able to resume a suspended warehouse if auto-resume is not enabled?", "options": ["A) USAGE", "B) OPERATE", "C) MONITOR", "D) MODIFY"], "chooseN": 1, "correct": ["OPERATE"], "explanation": "The 'OPERATE' privilege is required for a role to resume a suspended warehouse in Snowflake when auto-resume is not enabled. This privilege allows the role to start and stop the warehouse as needed.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-considerations.html#starting-and-stopping-a-virtual-warehouse"}, {"id": 399, "area": "Performance Concepts", "question": "Which statement MOST accurately describes clustering in Snowflake?", "options": ["A) The database ACCOUNTADMIN must define the clustering methodology for each Snowflake table.", "B) Clustering is the way data is grouped together and stored within Snowflake micro-partitions.", "C) The clustering key must be included in the COPY command when loading data into Snowflake.", "D) Clustering can be disabled within a Snowflake account."], "chooseN": 1, "correct": ["Clustering is the way data is grouped together and stored within Snowflake micro-partitions."], "explanation": "Clustering in Snowflake refers to how data is grouped and stored within micro-partitions. It optimizes data storage and access by organizing data based on certain key(s), known as clustering keys, but does not necessarily require involvement from the ACCOUNTADMIN or specific commands during data loading.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-keys.html"}, {"id": 400, "area": "Account Access and Security", "question": "Which of the following practices are recommended when creating a user in Snowflake? (Choose two.)", "options": ["A) Configure the user to be initially disabled.", "B) Force an immediate password change.", "C) Set a default role for the user.", "D) Set the number of minutes to unlock to 15 minutes.", "E) Set the user's access to expire within a specified timeframe."], "chooseN": 2, "correct": ["Force an immediate password change.", "Set a default role for the user."], "explanation": "When creating a user in Snowflake, it is recommended to force an immediate password change to ensure security and set a default role for ease of access and control. These practices enhance security and user experience in the Snowflake environment.", "reference": "https://docs.snowflake.com/en/user-guide/admin-user-management.html#create-user"}, {"id": 401, "area": "Account Access and Security", "question": "Network policies can be applied to which of the following Snowflake objects? (Choose two.)", "options": ["A) Roles", "B) Databases", "C) Warehouses", "D) Users", "E) Accounts"], "chooseN": 2, "correct": ["Users", "Accounts"], "explanation": "In Snowflake, network policies can be applied to 'Users' and 'Accounts'. These policies control the network addresses (IP addresses) from which users can connect to Snowflake, enhancing the security of the account and its users.", "reference": "https://docs.snowflake.com/en/user-guide/security-network-policies.html"}, {"id": 402, "area": "Snowflake Data Cloud Features & Architecture", "question": "Where is Snowflake metadata stored?", "options": ["A) Within the data files", "B) In the virtual warehouse layer", "C) In the cloud services layer", "D) In the remote storage layer"], "chooseN": 1, "correct": ["In the cloud services layer"], "explanation": "Snowflake metadata is stored in the cloud services layer. This layer is a key component of Snowflake's architecture, responsible for managing all aspects of the data warehouse, including metadata management, query compilation, and optimization.", "reference": "https://docs.snowflake.com/en/user-guide/snowflake-architecture.html"}, {"id": 403, "area": "Data Transformations", "question": "What columns are returned when performing a FLATTEN command on semi-structured data? (Choose two.)", "options": ["A) KEY", "B) NODE", "C) VALUE", "D) LEVEL", "E) ROOT"], "chooseN": 2, "correct": ["KEY", "VALUE"], "explanation": "When using the FLATTEN command on semi-structured data in Snowflake, the columns returned typically include 'KEY' and 'VALUE'. 'KEY' represents the path to the element in the semi-structured data, while 'VALUE' contains the data element from the path specified.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/flatten.html"}, {"id": 404, "area": "Data Protection and Data Sharing", "question": "Which of the following Snowflake features provide continuous data protection automatically? (Choose two.)", "options": ["A) Internal stages", "B) Incremental backups", "C) Time Travel", "D) Zero-copy clones", "E) Fail-safe"], "chooseN": 2, "correct": ["Time Travel", "Fail-safe"], "explanation": "Snowflake's Time Travel and Fail-safe are the features that provide continuous data protection automatically. Time Travel allows users to access historical data within a defined retention period. Fail-safe provides an additional layer of data protection by maintaining historical data beyond the Time Travel period for recovery by Snowflake support.", "reference": "https://docs.snowflake.com/en/user-guide/data-protection-intro.html"}, {"id": 405, "area": "Account Access and Security", "question": "A developer is granted ownership of a table that has a masking policy. The developer’s role is not able to see the masked data. Will the developer be able to modify the table to read the masked data?", "options": ["A) Yes, because a table owner has full control and can unset masking policies.", "B) Yes, because masking policies only apply to cloned tables.", "C) No, because masking policies must always reference specific access roles.", "D) No, because ownership of a table does not include the ability to change masking policies."], "chooseN": 1, "correct": ["No, because ownership of a table does not include the ability to change masking policies."], "explanation": "Even if a developer is granted ownership of a table with a masking policy, they will not be able to modify the table to read the masked data if their role does not have the required permissions. Ownership of the table does not automatically confer the ability to change or unset masking policies.", "reference": "https://docs.snowflake.com/en/user-guide/security-column-ddm.html"}, {"id": 406, "area": "Performance Concepts", "question": "How should a virtual warehouse be configured if a user wants to ensure that additional multi-clusters are resumed with no delay?", "options": ["A) Configure the warehouse to a size larger than generally required", "B) Set the minimum and maximum clusters to autoscale", "C) Use the standard warehouse scaling policy", "D) Use the economy warehouse scaling policy"], "chooseN": 1, "correct": ["Set the minimum and maximum clusters to autoscale"], "explanation": "To ensure that additional multi-clusters in a virtual warehouse are resumed with no delay, the warehouse should be configured with autoscaling by setting the minimum and maximum number of clusters. This setup allows Snowflake to automatically manage the number of clusters based on the workload.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-multicluster.html"}, {"id": 407, "area": "Performance Concepts", "question": "During periods of warehouse contention, which parameter controls the maximum length of time a warehouse will hold a query for processing?", "options": ["A) STATEMENT_TIMEOUT_IN_SECONDS", "B) STATEMENT_QUEUED_TIMEOUT_IN_SECONDS", "C) MAX_CONCURRENCY_LEVEL", "D) QUERY_TIMEOUT_IN_SECONDS"], "chooseN": 1, "correct": ["STATEMENT_QUEUED_TIMEOUT_IN_SECONDS"], "explanation": "The 'STATEMENT_QUEUED_TIMEOUT_IN_SECONDS' parameter controls the maximum length of time a warehouse will hold a query in a queued state before processing it. This parameter is important during periods of warehouse contention to manage query execution times.", "reference": "https://docs.snowflake.com/en/sql-reference/parameters.html#statement-queued-timeout-in-seconds"}, {"id": 408, "area": "Data Loading and Unloading", "question": "Files have been uploaded to a Snowflake internal stage. The files now need to be deleted. Which SQL command should be used to delete the files?", "options": ["A) PURGE", "B) MODIFY", "C) REMOVE", "D) DELETE"], "chooseN": 1, "correct": ["REMOVE"], "explanation": "To delete files from a Snowflake internal stage, the 'REMOVE' SQL command is used. This command allows users to specify the files to be deleted from the staged location.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/remove.html"}, {"id": 409, "area": "Account Access and Security", "question": "In a Snowflake role hierarchy, what is the top-level role?", "options": ["A) SYSADMIN", "B) ORGADMIN", "C) ACCOUNTADMIN", "D) SECURITYADMIN"], "chooseN": 1, "correct": ["ACCOUNTADMIN"], "explanation": "In the role hierarchy of Snowflake, the top-level role is 'ACCOUNTADMIN'. This role has the highest level of privileges, including the ability to manage all aspects of the Snowflake account, from user and role management to warehouse and database administration.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-overview.html#predefined-roles"}, {"id": 410, "area": "Data Protection and Data Sharing", "question": "By default, which Snowflake role is required to create a share?", "options": ["A) ORGADMIN", "B) SECURITYADMIN", "C) SHAREADMIN", "D) ACCOUNTADMIN"], "chooseN": 1, "correct": ["ACCOUNTADMIN"], "explanation": "By default, the 'ACCOUNTADMIN' role is required to create a share in Snowflake. This role has the necessary permissions to manage and share data across different accounts or organizations within Snowflake.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-provider.html#creating-a-share"}, {"id": 411, "area": "Data Protection and Data Sharing", "question": "What happens to historical data when the retention period for an object ends?", "options": ["A) The data is cloned into a historical object.", "B) The data moves to Fail-safe", "C) Time Travel on the historical data is dropped.", "D) The object containing the historical data is dropped."], "chooseN": 1, "correct": ["The data moves to Fail-safe"], "explanation": "When the Time Travel retention period ends, historical data moves into Fail-safe. Fail-safe provides a non-configurable 7-day period during which data may be recoverable only by Snowflake Support. The data is not dropped or cloned -- it transitions from the Time Travel state (user-accessible) to the Fail-safe state (only Snowflake can recover it). After Fail-safe expires, data is permanently purged.", "reference": "https://docs.snowflake.com/en/user-guide/data-protection-failsafe.html"}, {"id": 412, "area": "Account Access and Security", "question": "A company’s security audit requires generating a report listing all Snowflake logins (e.g., date and user) within the last 90 days. Which of the following statements will return the required information? FROM table(information_schema.login_history_by_user())", "options": ["A) SELECT LAST_SUCCESS_LOGIN, LOGIN_NAME FROM ACCOUNT_USAGE.USERS;", "B) SELECT EVENT_TIMESTAMP, USER_NAME", "C) SELECT EVENT_TIMESTAMP, USER_NAME FROM ACCOUNT_USAGE.ACCESS_HISTORY;", "D) SELECT EVENT_TIMESTAMP, USER_NAME FROM ACCOUNT_USAGE.LOGIN_HISTORY;"], "chooseN": 1, "correct": ["SELECT EVENT_TIMESTAMP, USER_NAME FROM ACCOUNT_USAGE.LOGIN_HISTORY;"], "explanation": "To generate a report listing all Snowflake logins within the last 90 days, the statement 'SELECT EVENT_TIMESTAMP, USER_NAME FROM ACCOUNT_USAGE.LOGIN_HISTORY;' should be used. This query accesses the LOGIN_HISTORY view in the ACCOUNT_USAGE schema, which contains the required login information.", "reference": "https://docs.snowflake.com/en/sql-reference/account-usage/login_history.html"}, {"id": 413, "area": "Performance Concepts", "question": "What are common issues found by using the Query Profile? (Choose two.)", "options": ["A) Identifying queries that will likely run very slowly before executing them", "B) Locating queries that consume a high amount of credits", "C) Identifying logical issues with the queries", "D) Identifying inefficient micro-partition pruning", "E) Data spilling to a local or remote disk"], "chooseN": 2, "correct": ["Identifying inefficient micro-partition pruning", "Data spilling to a local or remote disk"], "explanation": "Common issues identified by using the Query Profile in Snowflake include 'Identifying inefficient micro-partition pruning' and 'Data spilling to a local or remote disk'. These insights help in optimizing query performance by addressing data storage and processing inefficiencies.", "reference": "https://docs.snowflake.com/en/user-guide/ui-query-profile.html"}, {"id": 414, "area": "Performance Concepts", "question": "The Snowflake Search Optimization Services supports improved performance of which kind of query?", "options": ["A) Queries against large tables where frequent DML occurs", "B) Queries against tables larger than 1 TB", "C) Selective point lookup queries", "D) Queries against a subset of columns in a table"], "chooseN": 1, "correct": ["Selective point lookup queries"], "explanation": "The Snowflake Search Optimization Service is designed to enhance the performance of selective point lookup queries. These are queries that involve searching for a specific set of rows, typically using a WHERE clause with equality conditions on one or more columns.", "reference": "https://docs.snowflake.com/en/user-guide/tables-search-optimization-service.html"}, {"id": 415, "area": "Data Loading and Unloading", "question": "Which file formats are supported for unloading data from Snowflake? (Choose two.)", "options": ["A) Avro", "B) JSON", "C) ORC", "D) XML", "E) Delimited (CSV, TSV, etc.)"], "chooseN": 2, "correct": ["JSON", "Delimited (CSV, TSV, etc.)"], "explanation": "Snowflake supports unloading data to Delimited (CSV, TSV, etc.) and JSON formats (and also Parquet). Avro is supported for loading, not unloading.", "reference": "https://docs.snowflake.com/en/user-guide/data-unload-considerations.html"}, {"id": 416, "area": "Account Access and Security", "question": "Which Snowflake tool would be BEST to troubleshoot network connectivity?", "options": ["A) SnowCLI", "B) SnowUI", "C) SnowSQL", "D) SnowCD"], "chooseN": 1, "correct": ["SnowCD"], "explanation": "SnowCD (Snowflake Connectivity Diagnostic) is the tool designed specifically to troubleshoot network connectivity issues between Snowflake and client applications. It helps diagnose and resolve potential connection problems.", "reference": "https://docs.snowflake.com/en/user-guide/snowcd.html"}, {"id": 417, "area": "Performance Concepts", "question": "Increasing the size of a virtual warehouse from an X-Small to an X-Large is an example of which of the following?", "options": ["A) Right sizing", "B) Concurrent sizing", "C) Scaling out", "D) Scaling up"], "chooseN": 1, "correct": ["Scaling up"], "explanation": "Increasing the size of a virtual warehouse from X-Small to X-Large in Snowflake is an example of 'scaling up'. Scaling up involves increasing the compute resources (like CPU, memory) available to a single warehouse to enhance its processing capabilities.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-considerations?utm_source=snowscope&utm_medium=serp&utm_term=scaling+up#scaling-up-vs-scaling-out"}, {"id": 418, "area": "Data Protection and Data Sharing", "question": "What are ways to create and manage data shares in Snowflake? (Choose two.)", "options": ["A) Through the Snowflake web interface (UI)", "B) Through the DATA_SHARE=TRUE parameter", "C) Through SQL commands", "D) Through the ENABLE_SHARE=TRUE parameter", "E) Using the CREATE SHARE AS SELECT * FROM TABLE command"], "chooseN": 2, "correct": ["Through the Snowflake web interface (UI)", "Through SQL commands"], "explanation": "Data shares in Snowflake can be created and managed through the Snowflake web interface (UI) and through SQL commands. These methods allow users to share data securely and efficiently with other Snowflake accounts or consumer accounts.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-intro.html"}, {"id": 419, "area": "Performance Concepts", "question": "What is a characteristic of data micro-partitioning in Snowflake?", "options": ["A) Micro-partitioning may introduce data skew", "B) Micro-partitioning requires the definition of a partitioning schema", "C) Micro-partitioning happens when the data is loaded", "D) Micro-partitioning can be disabled within a Snowflake account"], "chooseN": 1, "correct": ["Micro-partitioning happens when the data is loaded"], "explanation": "A key characteristic of data micro-partitioning in Snowflake is that it occurs automatically when data is loaded into the system. Snowflake handles micro-partitioning internally, optimizing data storage and access without requiring user intervention for partition schema definition.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions#what-are-micro-partitions"}, {"id": 420, "area": "Account Access and Security", "question": "Users with the ACCOUNTADMIN role can execute which of the following commands on existing users?", "options": ["A) Can SHOW users DESCRIBE a given user, or ALTER or DROP a user", "B) Can DEFINE users, DESCRIBE a given user, or ALTER or DELETE a user", "C) Can SHOW users, INDEX a given user, or ALTER or DELETE a user", "D) Can SHOW users, DEFINE a given user or ALTER, DROP, or MODIFY a user"], "chooseN": 1, "correct": ["Can SHOW users DESCRIBE a given user, or ALTER or DROP a user"], "explanation": "Users with the ACCOUNTADMIN role have the ability to 'SHOW' users, 'DESCRIBE' a given user, and 'ALTER' or 'DROP' a user. This role grants the highest level of privileges in Snowflake, including comprehensive user and role management capabilities.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-overview.html#predefined-roles"}, {"id": 421, "area": "Account Access and Security", "question": "According to Snowflake best practice recommendations, which system-defined roles should be used to create custom roles? (Choose two.)", "options": ["A) ACCOUNTADMIN", "B) SYSADMIN", "C) SECURITYADMIN", "D) USERADMIN", "E) ORGADMIN"], "chooseN": 2, "correct": ["SYSADMIN", "USERADMIN"], "explanation": "Snowflake best practice recommends using USERADMIN to manage users and roles and SYSADMIN as the system role at the top of the custom-role hierarchy for owning/managing objects. SECURITYADMIN is primarily for granting/revoking privileges.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-overview.html#custom-roles"}, {"id": 422, "area": "Snowflake Data Cloud Features & Architecture", "question": "What services are provided by the cloud services layer in Snowflake? (Choose two.)", "options": ["A) Metadata management", "B) Object authorization", "C) Authentication", "D) Query execution", "E) Result caching"], "chooseN": 2, "correct": ["Metadata management", "Authentication"], "explanation": "The cloud services layer in Snowflake provides 'Metadata management' and 'Authentication' services. This layer is responsible for managing all metadata operations and ensuring secure access to Snowflake accounts and objects.", "reference": "https://docs.snowflake.com/en/user-guide/intro-key-concepts#cloud-services"}, {"id": 423, "area": "Data Loading and Unloading", "question": "Which of the following commands are valid options for the VALIDATION_MODE parameter within the Snowflake COPY_INTO command? (Choose two.)", "options": ["A) TRUE", "B) RETURN_ERROR_SUM", "C) RETURN_ALL_ERRORS", "D) RETURN_N_ROWS", "E) RETURN_FIRST__ERRORS"], "chooseN": 2, "correct": ["RETURN_ALL_ERRORS", "RETURN_N_ROWS"], "explanation": "For the VALIDATION_MODE parameter in the Snowflake COPY_INTO command, the valid options include 'RETURN_ALL_ERRORS' and 'RETURN_N_ERRORS'. These options control how Snowflake handles and reports errors encountered during the data loading process.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-table#optional-parameters"}, {"id": 424, "area": "Snowflake Data Cloud Features & Architecture", "question": "Snowflake virtual warehouses are part of which layer of the Snowflake architecture?", "options": ["A) Compute layer", "B) Storage layer", "C) Database layer", "D) Cloud services layer"], "chooseN": 1, "correct": ["Compute layer"], "explanation": "In the Snowflake architecture, virtual warehouses are part of the Compute layer. This layer is responsible for executing all data processing tasks, such as queries and data manipulation, separate from the Storage layer where data is stored.", "reference": "https://docs.snowflake.com/en/user-guide/intro-key-concepts.html#snowflake-architecture"}, {"id": 425, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which of the following are characteristics of schemas used in Snowflake? (Choose two.)", "options": ["A) A schema may contain one or more databases.", "B) A database may contain one or more schemas.", "C) A schema represents a logical grouping of database objects.", "D) Each schema is contained within a virtual warehouse.", "E) A table can span more than one schema."], "chooseN": 2, "correct": ["A database may contain one or more schemas.", "A schema represents a logical grouping of database objects."], "explanation": "In Snowflake, a schema is a logical grouping of database objects like tables, views, and functions, and each database may contain one or more schemas. Schemas help in organizing these objects within a database.", "reference": "https://docs.snowflake.com/en/sql-reference/ddl-database"}, {"id": 426, "area": "Data Loading and Unloading", "question": "Which Snowflake objects can be used to reduce data storage costs for short-lived tables? (Choose two.)", "options": ["A) Provisional tables", "B) Temporary tables", "C) Transient tables", "D) Permanent tables", "E) Lookup tables"], "chooseN": 2, "correct": ["Temporary tables", "Transient tables"], "explanation": "In Snowflake, Temporary tables and Transient tables can be used to reduce data storage costs for short-lived tables. Temporary tables are session-specific and are automatically dropped at the end of a session, while Transient tables are more durable but have reduced storage costs compared to permanent tables.", "reference": "https://docs.snowflake.com/en/user-guide/tables-temp-transient.html"}, {"id": 427, "area": "Data Loading and Unloading", "question": "A user has unloaded data from Snowflake to a stage. Which SQL command should be used to validate which data was loaded into the stage?", "options": ["A) list @ file_stage", "B) show @ file_stage", "C) view @ file_stage", "D) verify @ file_stage"], "chooseN": 1, "correct": ["list @ file_stage"], "explanation": "The 'list @file_stage' SQL command is used in Snowflake to validate which files are present in a stage after unloading data. This command provides a list of files in the specified stage.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/list.html"}, {"id": 428, "area": "Data Protection and Data Sharing", "question": "What are benefits of using the ACCESS_HISTORY view in the SNOWFLAKE database?", "options": ["A) Identification of unused data", "B) Identification of which roles have been used", "C) Tracking of network policy usage", "D) Highlighting of row access policy usage", "E) Identification of who has read data"], "chooseN": 1, "correct": ["Identification of unused data"], "explanation": "ACCESS_HISTORY is used to discover unused data and to audit access/write activity. The documented benefit relevant to the options is identification of unused data; the docs do not state a benefit of identifying who has read data.", "reference": "https://docs.snowflake.com/en/user-guide/access-history#benefits"}, {"id": 429, "area": "Data Transformations", "question": "Which of the following view types are available in Snowflake? (Choose two.)", "options": ["A) Layered view", "B) Secure view", "C) External view", "D) Embedded view", "E) Materialized view"], "chooseN": 2, "correct": ["Secure view", "Materialized view"], "explanation": "In Snowflake, the available view types include 'Secure view' and 'Materialized view'. Secure views provide controlled access to sensitive data, while materialized views store precomputed results of a query for performance optimization.", "reference": "https://docs.snowflake.com/en/user-guide/views-introduction.html"}, {"id": 430, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which of the following statements describes a benefit of Snowflake’s separation of compute and storage? (Choose two.)", "options": ["A) Growth of storage and compute are tightly coupled.", "B) Storage expands without the requirement to add more compute.", "C) Compute can be scaled up or down without the requirement to add more storage.", "D) Compute and storage can be scaled together.", "E) Use of storage avoids disk spilling."], "chooseN": 2, "correct": ["Storage expands without the requirement to add more compute.", "Compute can be scaled up or down without the requirement to add more storage."], "explanation": "The benefits of Snowflake’s separation of compute and storage include the ability to expand storage without adding more compute resources, and the flexibility to scale compute up or down independently of storage. This architecture provides scalability and cost-effectiveness.", "reference": "https://docs.snowflake.com/en/user-guide/intro-key-concepts.html#compute-and-storage"}, {"id": 431, "area": "Data Transformations", "question": "Which of the following languages can be used to implement Snowflake User Defined Functions (UDFs)? (Choose two.)", "options": ["A) Ruby", "B) Javascript", "C) SQL", "D) PERL", "E) C#"], "chooseN": 2, "correct": ["Javascript", "SQL"], "explanation": "In Snowflake, User Defined Functions (UDFs) can be implemented using 'Javascript' and 'SQL'. These languages provide the necessary capabilities to create custom functions for various data processing and analytical tasks.", "reference": "https://docs.snowflake.com/en/sql-reference/udf-overview.html"}, {"id": 432, "area": "Data Loading and Unloading", "question": "What is the default compression type when unloading data from Snowflake?", "options": ["A) Brotli", "B) bzip2", "C) Zstandard", "D) gzip"], "chooseN": 1, "correct": ["gzip"], "explanation": "When unloading data from Snowflake, the default compression type is 'gzip'. This widely-used compression format balances compression ratio and speed, providing efficient data unloading and transfer.", "reference": "https://docs.snowflake.com/en/user-guide/data-unload-considerations.html#compression"}, {"id": 433, "area": "Performance Concepts", "question": "Which statement describes when a virtual warehouse can be resized?", "options": ["A) A resize will affect running, queued, and new queries.", "B) A resize can only be completed when the warehouse is in an auto-resume status.", "C) A resize must be completed when the warehouse is suspended.", "D) A resize can be completed at any time."], "chooseN": 1, "correct": ["A resize can be completed at any time."], "explanation": "In Snowflake, a virtual warehouse can be resized at any time. This flexibility allows users to adjust the compute resources of a warehouse dynamically, according to the current workload and performance requirements.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-tasks.html#resizing-a-warehouse"}, {"id": 434, "area": "Data Loading and Unloading", "question": "What is the compressed size limit for semi-structured data loaded into a VARIANT data type using the COPY command?", "options": ["A) 8 MB", "B) 16 MB", "C) 32 MB", "D) 64 MB"], "chooseN": 1, "correct": ["16 MB"], "explanation": "The compressed size limit for semi-structured data loaded into a VARIANT data type using the COPY command in Snowflake is 16 MB. This limit ensures efficient processing and querying of semi-structured data within Snowflake.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-considerations-prepare#semi-structured-data-size-limitations"}, {"id": 435, "area": "Data Protection and Data Sharing", "question": "User A cloned a schema and overwrote a schema that User B was working on. User B no longer has access to their version of the tables. However, this all occurred within the Time Travel retention period defined at the database level. How should the missing tables be restored?", "options": ["A) Use an UNDROP TABLE statement.", "B) Use a CREATE TABLE AS SELECT statement", "C) Rename the cloned schema and use an UNDROP SCHEMA statement.", "D) Contact Snowflake Support to retrieve the data from Fail-safe"], "chooseN": 1, "correct": ["Use an UNDROP TABLE statement."], "explanation": "If User B's tables were overwritten within the Time Travel retention period, they can be restored using the 'UNDROP TABLE' statement. This command will recover the dropped tables from the Time Travel history, provided it is within the retention period.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/undrop-table.html"}, {"id": 436, "area": "Data Loading and Unloading", "question": "How does Snowflake recommend handling the bulk loading of data batches from files already available in cloud storage?", "options": ["A) Use Snowpipe.", "B) Use the INSERT command.", "C) Use an external table.", "D) Use the COPY command."], "chooseN": 1, "correct": ["Use the COPY command."], "explanation": "For the bulk loading of data batches from files already available in cloud storage, Snowflake recommends using the COPY command. This command is optimized for loading large volumes of data efficiently and supports various file formats.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-prepare.html"}, {"id": 437, "area": "Data Loading and Unloading", "question": "What is Snowflake's general guideline for files used to load data?", "options": ["A) Files can be loaded directly into a table.", "B) Any delimiter is supported: the default is a semicolon.", "C) Electronic Data Interchange (EDI) is one of the supported semi-structured formats.", "D) For delimited files, the default character set is UTF-8."], "chooseN": 1, "correct": ["For delimited files, the default character set is UTF-8."], "explanation": "Snowflake's general guideline for loading data from files, particularly delimited files, is that the default character set is UTF-8. This encoding supports a wide range of characters and is commonly used for text data.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-considerations-prepare.html#file-formats"}, {"id": 438, "area": "Data Transformations", "question": "How does a Snowflake user execute an anonymous block of code?", "options": ["A) The user must run the CALL command to execute the block.", "B) The statements that define the block must also execute the block.", "C) The SUBMIT command must run immediately after the block is defined", "D) The block must be saved to a worksheet and executed using a connector."], "chooseN": 1, "correct": ["The statements that define the block must also execute the block."], "explanation": "In Snowflake, an anonymous block of code is executed by the statements that define the block itself. This means that when the block is defined in a script or query window, it is also executed immediately without the need for a separate command.", "reference": "https://docs.snowflake.com/en/developer-guide/snowflake-scripting/blocks#using-an-anonymous-block"}, {"id": 439, "area": "Data Loading and Unloading", "question": "When unloading data from Snowflake, the user executes a COPY INTO command into an internal stage. What additional command is required to load the file onto the local file system?", "options": ["A) GET", "B) LIST", "C) PUT", "D) REMOVE"], "chooseN": 1, "correct": ["GET"], "explanation": "After unloading data to an internal stage using the COPY INTO command, the 'GET' command is used to download the files from the stage to the local file system. This enables users to export data from Snowflake to their local environment.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-location.html"}, {"id": 440, "area": "Performance Concepts", "question": "A Snowflake user has a query that is running for a long time. When the user opens the query profiler, it indicates that a lot of data is spilling to disk. What is causing this to happen?", "options": ["A) The result cache is almost full and is unable to hold the results.", "B) The cloud storage staging area is not sufficient to hold the data results.", "C) Clustering has not been applied to the table so the table is not optimized.", "D) The warehouse memory is not sufficient to hold the intermediate query results."], "chooseN": 1, "correct": ["The warehouse memory is not sufficient to hold the intermediate query results."], "explanation": "When a query in Snowflake spills data to disk, it usually indicates that the memory allocated to the warehouse is not sufficient to hold all the intermediate results of the query. Increasing the size of the warehouse can help reduce or eliminate data spilling to disk.", "reference": "https://docs.snowflake.com/en/user-guide/ui-query-profile#queries-too-large-to-fit-in-memory"}, {"id": 441, "area": "Data Loading and Unloading", "question": "What is the MOST performant file format for loading data in Snowflake?", "options": ["A) CSV (Unzipped)", "B) Parquet", "C) CSV (Gzipped)", "D) ORC"], "chooseN": 1, "correct": ["Parquet"], "explanation": "Parquet is a columnar storage file format and is generally the most performant for loading data in Snowflake. It allows for efficient compression and encoding schemes, which can reduce the amount of data scanned and speed up query performance.", "reference": "https://community.snowflake.com/s/article/How-to-Load-Terabytes-Into-Snowflake-Speeds-Feeds-and-Techniques"}, {"id": 442, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which chart type does Snowsight support to visualize worksheet data?", "options": ["A) Box plot", "B) Bubble chart", "C) Pie chart", "D) Scatterplot", "E) All of the above"], "chooseN": 1, "correct": ["Scatterplot"], "explanation": "Según la documentación oficial de Snowflake, Snowsight soporta únicamente los siguientes tipos de gráficos: Bar charts (Gráficos de barras), Line charts (Gráficos de líneas), Scatterplots (Gráficos de dispersión), Heat grids (Cuadrículas de calor), y Scorecards (Tarjetas de puntuación). De las opciones presentadas, únicamente Scatterplot está soportado. Box plot, Bubble chart y Pie chart NO están soportados por Snowsight.", "reference": "https://docs.snowflake.com/en/user-guide/ui-snowsight-visualizations"}, {"id": 443, "area": "Performance Concepts", "question": "Which result shows efficient pruning?", "options": ["A) Partitions scanned is greater than partitions total.", "B) Partitions scanned is less than partitions total.", "C) Partitions scanned is equal to the partitions total.", "D) Partitions scanned is greater than or equal to the partitions total."], "chooseN": 1, "correct": ["Partitions scanned is less than partitions total."], "explanation": "Efficient pruning is indicated when the number of partitions scanned is less than the total number of partitions. This means that Snowflake is effectively using the partitioning information to skip over irrelevant partitions, thereby reducing the amount of data scanned and improving query performance.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-keys.html#benefits-of-clustering"}, {"id": 444, "area": "Performance Concepts", "question": "Which clustering indicator will show if a large table in Snowflake will benefit from explicitly defining a clustering key?", "options": ["A) Percentage", "B) Depth", "C) Ratio", "D) Total partition count"], "chooseN": 1, "correct": ["Depth"], "explanation": "The 'Depth' clustering indicator is used in Snowflake to show if a large table will benefit from explicitly defining a clustering key. A high depth value indicates unevenly distributed data across the micro-partitions, which can be optimized by defining a clustering key.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-keys#what-is-a-clustering-key"}, {"id": 445, "area": "Data Loading and Unloading", "question": "Which file format is MOST performant in Snowflake for data loading?", "options": ["A) Parquet", "B) CSV", "C) ORC", "D) Avro"], "chooseN": 1, "correct": ["Parquet"], "explanation": "Snowflake’s documentation does not identify CSV as the most performant load format. CSV is simply the default delimited format, with a specific optimization for some large uncompressed files. Among the given choices, Parquet is the best-supported answer for high-performance loading.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-considerations-prepare#file-format"}, {"id": 446, "area": "Account Access and Security", "question": "What is to be expected when sharing worksheets in Snowsight?", "options": ["A) Worksheets can be shared with users that are internal or external to any organization.", "B) To run a shared worksheet, a user must be granted the role used for the worksheet session context.", "C) Snowsight allows users to view and refresh results but not to edit shared worksheets.", "D) Snowsight offers different sharing permissions at the worksheet, folder, and dashboard level."], "chooseN": 1, "correct": ["To run a shared worksheet, a user must be granted the role used for the worksheet session context."], "explanation": "When a worksheet is shared in Snowsight, recipients can edit or view it depending on permissions, and to run it they must have the worksheet’s role/session context.", "reference": "https://docs.snowflake.com/en/user-guide/ui-snowsight-worksheets?utm_source=snowscope&utm_medium=serp&utm_term=sharing+worksheets#sharing-worksheets-and-folders"}, {"id": 447, "area": "Data Protection and Data Sharing", "question": "Which Snowflake objects track DML changes made to tables, like inserts, updates, and deletes?", "options": ["A) Pipes", "B) Streams", "C) Tasks", "D) Procedures"], "chooseN": 1, "correct": ["Streams"], "explanation": "In Snowflake, 'Streams' are the objects that track DML (Data Manipulation Language) changes made to tables, such as inserts, updates, and deletes. Streams capture changes to a table since the last time a stream was consumed, providing a powerful mechanism for change data capture.", "reference": "https://docs.snowflake.com/en/user-guide/streams.html"}, {"id": 448, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which table type is automatically deleted after a session is closed and has no Fail-safe or Time Travel cost?", "options": ["A) Temporary", "B) Transient", "C) Permanent", "D) External"], "chooseN": 1, "correct": ["Temporary"], "explanation": "Temporary tables in Snowflake are automatically deleted after a session is closed and do not incur Fail-safe or Time Travel costs. These tables are session-specific and are ideal for transient data needs where long-term storage is not required.", "reference": "https://docs.snowflake.com/en/user-guide/tables-temp-transient.html#temporary-tables"}, {"id": 449, "area": "Account Access and Security", "question": "Which constraint type is enforced in Snowflake from the ANSI SQL standard?", "options": ["A) UNIQUE", "B) PRIMARY KEY", "C) FOREIGN KEY", "D) NOT NULL"], "chooseN": 1, "correct": ["NOT NULL"], "explanation": "In Snowflake, the 'NOT NULL' constraint is enforced as per the ANSI SQL standard. This constraint ensures that a column cannot contain null values. Other constraints like UNIQUE, PRIMARY KEY, and FOREIGN KEY are recognized but not enforced in Snowflake.", "reference": "https://docs.snowflake.com/en/sql-reference/constraints-properties#ansi-sql-constraint-properties"}, {"id": 450, "area": "Performance Concepts", "question": "Which function is used to profile warehouse credit usage?", "options": ["A) AUTOMATIC_CLUSTERING_HISTORY", "B) MATERIALIZED_VIEW_REFRESH_HISTORY", "C) WAREHOUSE_LOAD_HISTORY", "D) WAREHOUSE_METERING_HISTORY"], "chooseN": 1, "correct": ["WAREHOUSE_METERING_HISTORY"], "explanation": "The 'WAREHOUSE_METERING_HISTORY' function is used to profile warehouse credit usage in Snowflake. This function provides historical data about the credits consumed by each virtual warehouse, which is useful for understanding and managing costs.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/warehouse_metering_history.html"}, {"id": 451, "area": "Snowflake Data Cloud Features & Architecture", "question": "What is a characteristic of the Snowflake query profiler?", "options": ["A) It can provide statistics on a maximum number of 100 queries per week.", "B) It provides a graphic representation of the main components of the query processing.", "C) It provides detailed statistics about which queries are using the greatest number of compute resources.", "D) It can be used by third-party software using the query profiler API."], "chooseN": 1, "correct": ["It provides a graphic representation of the main components of the query processing."], "explanation": "One key characteristic of the Snowflake query profiler is that it provides a graphic representation of the main components of the query processing. This graphical interface helps users understand and optimize their query performance by visually displaying the different stages and resources involved in query execution.", "reference": "https://docs.snowflake.com/en/user-guide/ui-query-profile"}, {"id": 452, "area": "Data Protection and Data Sharing", "question": "A Snowflake user wants to share transactional data with retail suppliers. However, some of the suppliers do not use Snowflake. According to best practice, what should the Snowflake user do? (Choose two.)", "options": ["A) Provide each non-Snowflake supplier with their own reader account.", "B) Deploy a single reader account to be shared by all of the non-Snowflake suppliers.", "C) Create an ETL pipeline that uses select and inserts statements from the source to the target supplier accounts.", "D) Use a data share for suppliers in the same cloud region and a replicated proxy share for other cloud deployments.", "E) Extract the shared transactional data to an external stage and use cloud storage utilities to reload the suppliers' regions."], "chooseN": 2, "correct": ["Provide each non-Snowflake supplier with their own reader account.", "Use a data share for suppliers in the same cloud region and a replicated proxy share for other cloud deployments."], "explanation": "Best practices for sharing data with non-Snowflake users include providing each non-Snowflake supplier with their own reader account, which allows them access to a Snowflake account for querying shared data. Alternatively, Snowflake data providers can share data with data consumers in a different region.", "reference": "https://docs.snowflake.com/user-guide/secure-data-sharing-across-regions-platforms"}, {"id": 453, "area": "Data Protection and Data Sharing", "question": "Which statement about data sharing is true?", "options": ["A) Accounts can share with other accounts regardless of their Snowflake edition, without requiring help from Snowflake Support.", "B) Data sharing can cross regions, but not cloud providers.", "C) The Data Consumer can only see objects in the Data Provider’s source database that have been explicitly added to the share.", "D) A Data Provider can only share with other Snowflake customers."], "chooseN": 1, "correct": ["The Data Consumer can only see objects in the Data Provider’s source database that have been explicitly added to the share."], "explanation": "In Snowflake data sharing, the data consumer can only access objects in the data provider's source database that have been explicitly added to the share. This ensures that the data provider has full control over what data is shared and who has access to it.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-readers.html"}, {"id": 454, "area": "Data Loading and Unloading", "question": "Which command is used to load files into an internal stage within Snowflake?", "options": ["A) PUT", "B) COPY INTO", "C) TRANSFER", "D) INSERT"], "chooseN": 1, "correct": ["PUT"], "explanation": "The 'COPY INTO' command in Snowflake is used to load files into an internal stage. This command reads data from files in a staged location and loads it into a Snowflake table. The 'PUT' command is used to upload files to a stage, but the actual loading into tables is performed by 'COPY INTO'.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-table.html"}, {"id": 455, "area": "Account Access and Security", "question": "Which object type is granted permissions for reading a table?", "options": ["A) User", "B) Role", "C) Attribute", "D) Schema"], "chooseN": 1, "correct": ["Role"], "explanation": "In Snowflake, permissions for reading a table are granted to a 'Role'. Roles are used to manage access and privileges within Snowflake, allowing users who are assigned these roles to perform actions such as reading tables.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-overview.html"}, {"id": 456, "area": "Performance Concepts", "question": "What is the default value in the Snowflake Web Interface (UI) for auto suspending a Virtual Warehouse?", "options": ["A) 1 minute", "B) 5 minutes", "C) 10 minutes", "D) 15 minutes"], "chooseN": 1, "correct": ["10 minutes"], "explanation": "The default value for auto suspending a Virtual Warehouse in the Snowflake Web Interface (UI) is '10 minutes'. This setting determines how long a warehouse remains idle before it is automatically suspended to save on compute resources.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-tasks.html#suspending-and-resuming-warehouses"}, {"id": 457, "area": "Performance Concepts", "question": "Several users are using the same virtual warehouse. The users report that the queries are running slowly, and that many queries are being queued. What is the recommended way to resolve this issue?", "options": ["A) Reduce the warehouse STATEMENT_QUEUED_TIMEOUT_IN SECONDS parameter.", "B) Reduce the warehouse AUTO_SUSPEND parameter.", "C) Increase the warehouse MAX_CONCURRENCY_LIMIT parameter.", "D) Increase the warehouse MAX_CLUSTER_COUNT parameter."], "chooseN": 1, "correct": ["Increase the warehouse MAX_CLUSTER_COUNT parameter."], "explanation": "To resolve the issue of slow query performance and queuing in a shared virtual warehouse, it is recommended to increase the 'MAX_CLUSTER_COUNT' parameter. This will allow the warehouse to scale out and handle more concurrent queries, thereby reducing queuing and improving query performance.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-considerations#scaling-up-vs-scaling-out"}, {"id": 458, "area": "Data Transformations", "question": "Which data types are valid in Snowflake? (Choose two.)", "options": ["A) BLOB", "B) Geography", "C) JSON", "D) CLOB", "E) Variant"], "chooseN": 2, "correct": ["Geography", "Variant"], "explanation": "The 'Variant' data type can store semi-structured data such as JSON, Avro, ORC, Parquet, or XML. 'Geography' is a geospatial data type.", "reference": "https://docs.snowflake.com/en/sql-reference/intro-summary-data-types"}, {"id": 459, "area": "Performance Concepts", "question": "What happens when the size of a virtual warehouse is changed?", "options": ["A) Queries that are running on the current warehouse configuration are not impacted.", "B) Queries that are running on the current warehouse configuration are aborted and have to be resubmitted by the user.", "C) Queries that are running on the current warehouse configuration are aborted and are automatically resubmitted.", "D) Queries that are running on the current warehouse configuration are moved to the new configuration and finished there."], "chooseN": 1, "correct": ["Queries that are running on the current warehouse configuration are not impacted."], "explanation": "When the size of a virtual warehouse in Snowflake is changed, queries that are currently running on the warehouse are not impacted. They will continue to run using the original warehouse configuration until completion. Any new queries submitted after the change will use the new warehouse configuration.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-tasks.html#resizing-a-warehouse"}, {"id": 460, "area": "Account Access and Security", "question": "How often are encryption keys automatically rotated by Snowflake?", "options": ["A) 30 Days", "B) 60 Days", "C) 90 Days", "D) 365 Days"], "chooseN": 1, "correct": ["30 Days"], "explanation": "All Snowflake-managed keys are automatically rotated by Snowflake when they are more than 30 days old.", "reference": "https://docs.snowflake.com/en/user-guide/security-encryption-manage#encryption-key-rotation"}, {"id": 461, "area": "Account Access and Security", "question": "As a best practice, all custom roles should be granted to which system-defined role?", "options": ["A) ACCOUNTADMIN", "B) ORGADMIN", "C) SECURITYADMIN", "D) SYSADMIN"], "chooseN": 1, "correct": ["SYSADMIN"], "explanation": "Instead, we recommend creating a hierarchy of roles aligned with business functions in your organization and ultimately assigning these roles to the SYSADMIN role. For more information, see Aligning Object Access with Business Functions in this topic.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-considerations#avoid-using-the-accountadmin-role-to-create-objects"}, {"id": 462, "area": "Data Transformations", "question": "Which Snowflake object can be accessed in the FROM clause of a query, returning a set of rows having one or more columns?", "options": ["A) A User-Defined Table Function (UDTF)", "B) A Scalar User Defined Function (UDF)", "C) A stored procedure", "D) A task"], "chooseN": 1, "correct": ["A User-Defined Table Function (UDTF)"], "explanation": "In Snowflake, a User-Defined Table Function (UDTF) can be accessed in the FROM clause of a query. UDTFs return a set of rows with one or more columns, making them suitable for use in such queries.", "reference": "https://docs.snowflake.com/en/sql-reference/functions-table.html"}, {"id": 463, "area": "Data Loading and Unloading", "question": "How are micro-partitions typically generated in Snowflake?", "options": ["A) Automatically", "B) ORDER BY <>;", "C) PARTITION BY <>;", "D) GROUP BY <>;"], "chooseN": 1, "correct": ["Automatically"], "explanation": "In Snowflake, micro-partitions are generated automatically. As data is loaded into a table, Snowflake automatically divides the data into micro-partitions based on the size and structure of the incoming data. This process is managed internally by Snowflake and requires no explicit action from the user.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions.html"}, {"id": 464, "area": "Account Access and Security", "question": "What does Snowflake recommend regarding database object ownership? (Choose two.)", "options": ["A) Create objects with ACCOUNTADMIN and do not reassign ownership.", "B) Create objects with SYSADMIN.", "C) Create objects with SECURITYADMIN to ease granting of privileges later.", "D) Create objects with a custom role and grant this role to SYSADMIN.", "E) Use only managed access schemas for objects owned by ACCOUNTADMIN."], "chooseN": 2, "correct": ["Create objects with a custom role and grant this role to SYSADMIN.", "Use only managed access schemas for objects owned by ACCOUNTADMIN."], "explanation": "Snowflake recommends creating objects with a custom role and granting this role to SYSADMIN for better access control and organization. Also, using only managed access schemas for objects owned by ACCOUNTADMIN helps maintain security and proper access permissions.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-overview.html"}, {"id": 465, "area": "Performance Concepts", "question": "Other than ownership what privileges does a user need to view and modify resource monitors in Snowflake? (Choose two.)", "options": ["A) ALTER", "B) MONITOR", "C) MODIFY", "D) CREATE", "E) DROP"], "chooseN": 2, "correct": ["MONITOR", "MODIFY"], "explanation": "To view and modify resource monitors in Snowflake, a user needs 'MONITOR' privileges to view the resource monitor and 'MODIFY' privileges to modify it. These privileges allow the user to manage and adjust resource monitors effectively.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-privileges?utm_source=snowscope&utm_medium=serp&utm_term=RESOURCE+MONITOR+PRIVILEGES#resource-monitor-privileges"}, {"id": 466, "area": "Performance Concepts", "question": "What technique does Snowflake recommend for determining which virtual warehouse size to select?", "options": ["A) Always start with an X-Small and increase the size if the query does not complete in 2 minutes", "B) Experiment by running the same queries against warehouses of different sizes", "C) Use the default size Snowflake chooses", "D) Use X-Large or above for tables larger than 1 GB"], "chooseN": 1, "correct": ["Experiment by running the same queries against warehouses of different sizes"], "explanation": "Snowflake recommends experimenting by running the same queries against warehouses of different sizes to determine the most efficient size for a particular workload. This approach allows users to balance performance and cost by finding the warehouse size that best fits their specific use case.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-considerations.html#sizing-virtual-warehouses"}, {"id": 467, "area": "Data Loading and Unloading", "question": "Which command should be used when loading many flat files into a single table?", "options": ["A) PUT", "B) INSERT", "C) COPY INTO", "D) MERGE"], "chooseN": 1, "correct": ["COPY INTO"], "explanation": "When loading many flat files into a single table, the 'COPY INTO' command is the most efficient choice in Snowflake. This command allows for bulk loading of data from files into a table, optimizing the data loading process.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-table.html"}, {"id": 468, "area": "Data Protection and Data Sharing", "question": "How can a Snowflake user share data with another user who does not have a Snowflake account?", "options": ["A) Share the data by implementing User-Defined Functions (UDFs)", "B) Create a reader account and create a share of the data", "C) Grant the READER privilege to the database that is going to be shared", "D) Move the Snowflake account to a region where data sharing is enabled"], "chooseN": 1, "correct": ["Create a reader account and create a share of the data"], "explanation": "To share data with a user who does not have a Snowflake account, the best approach is to create a reader account and then create a share of the data. This enables external users to access the shared data through the reader account without needing a Snowflake account of their own.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-reader-create?utm_source=snowscope&utm_medium=serp&utm_term=READER+ACCOUNT"}, {"id": 469, "area": "Data Loading and Unloading", "question": "Which semi-structured data formats can be loaded into Snowflake with a COPY command? (Choose two.)", "options": ["A) CSV", "B) EDI", "C) HTML", "D) ORC", "E) XML"], "chooseN": 2, "correct": ["ORC", "XML"], "explanation": "Snowflake supports loading semi-structured data formats using the COPY command. Among the given options, ORC and XML are the semi-structured data formats that can be loaded into Snowflake. CSV, while supported, is not considered a semi-structured format, and EDI and HTML are not directly supported for loading via COPY command.", "reference": "https://docs.snowflake.com/en/user-guide/semistructured-considerations?utm_source=snowscope&utm_medium=serp&utm_term=COPY+INTO+SEMI-STRUCTURED"}, {"id": 470, "area": "Account Access and Security", "question": "Which statements reflect valid commands when using secondary roles? (Choose two.)", "options": ["A) USE SECONDARY ROLES RESUME", "B) USE SECONDARY ROLES SUSPEND", "C) USE SECONDARY ROLES ALL", "D) USE SECONDARY ROLES ADD", "E) USE SECONDARY ROLES NONE"], "chooseN": 2, "correct": ["USE SECONDARY ROLES ALL", "USE SECONDARY ROLES NONE"], "explanation": "In Snowflake, 'USE SECONDARY ROLES ALL' and 'USE SECONDARY ROLES NONE' are valid commands when managing secondary roles. 'USE SECONDARY ROLES ALL' enables all secondary roles granted to the user, while 'USE SECONDARY ROLES NONE' disables all secondary roles.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/use-secondary-roles.html"}, {"id": 471, "area": "Snowflake Data Cloud Features & Architecture", "question": "How long is a query visible in the Query History page in the Snowflake Web Interface (UI)?", "options": ["A) 60 minutes", "B) 24 hours", "C) 14 days", "D) 30 days"], "chooseN": 1, "correct": ["14 days"], "explanation": "In the Snowflake Web Interface (UI), the Query History page retains and displays queries for up to 14 days. This allows users to review and analyze queries executed within this period.", "reference": "https://docs.snowflake.com/en/user-guide/ui-history.html#query-history"}, {"id": 472, "area": "Performance Concepts", "question": "Two users share a virtual warehouse named WH_DEV_01. When one of the users loads data, the other one experiences performance issues while querying data. How does Snowflake recommend resolving this issue?", "options": ["A) Scale up the existing warehouse", "B) Create separate warehouses for each user", "C) Create separate warehouses for each workload", "D) Stop loading and querying data at the same time"], "chooseN": 1, "correct": ["Create separate warehouses for each workload"], "explanation": "Snowflake recommends creating separate virtual warehouses for different workloads to resolve performance issues. By separating the workloads (data loading and querying) into different warehouses, each user can operate without impacting the performance of the other.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-considerations#warehouse-resizing-improves-performance"}, {"id": 473, "area": "Data Transformations", "question": "What is a feature of a stored procedure in Snowflake?", "options": ["A) They can be created as secure and hide the underlying metadata from all users.", "B) They can only access tables from a single database.", "C) They can only contain a single SQL statement.", "D) They can be created to run with a caller's rights or an owner's rights."], "chooseN": 1, "correct": ["They can be created to run with a caller's rights or an owner's rights."], "explanation": "A feature of stored procedures in Snowflake is that they can be created to run with either the caller's rights or the owner's rights. This allows control over the execution context of the stored procedure, determining whether it executes with the privileges of the user who calls it or the user who created it.", "reference": "https://docs.snowflake.com/en/sql-reference/stored-procedures-usage.html#ownership-and-execution-privileges"}, {"id": 474, "area": "Account Access and Security", "question": "Which view will return users who have queried a table?", "options": ["A) SNOWFLAKE.ACCOUNT_USAGE.WAREHOUSE_EVENT_HISTORY", "B) SNOWFLAKE.ACCOUNT_USAGE.ACCESS_HISTORY", "C) SNOWFLAKE.ACCOUNT_USAGE.COLUMNS", "D) SNOWFLAKE.ACCOUNT_USAGE.OBJECT_DEPENDENCIES"], "chooseN": 1, "correct": ["SNOWFLAKE.ACCOUNT_USAGE.ACCESS_HISTORY"], "explanation": "The view 'SNOWFLAKE.ACCOUNT_USAGE.ACCESS_HISTORY' in Snowflake provides information about the access history of objects within Snowflake, including details on which users have queried a table. This view is useful for auditing and monitoring purposes.", "reference": "https://docs.snowflake.com/en/sql-reference/account-usage/access_history.html"}, {"id": 475, "area": "Performance Concepts", "question": "Why do Snowflake’s virtual warehouses have scaling policies?", "options": ["A) To help save extra storage costs", "B) To help increase the performance of serverless computing features", "C) To help control the credits consumed by a multi-cluster warehouse running in auto-scale mode", "D) To help control the credits consumed by a multi-cluster warehouse running in maximized mode"], "chooseN": 1, "correct": ["To help control the credits consumed by a multi-cluster warehouse running in auto-scale mode"], "explanation": "Snowflake's virtual warehouses have scaling policies, particularly to control the credits consumed by a multi-cluster warehouse running in auto-scale mode. This ensures efficient resource usage and cost management while maintaining performance.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-multicluster#setting-the-scaling-policy-for-a-multi-cluster-warehouse"}, {"id": 476, "area": "Data Loading and Unloading", "question": "Where can a Snowflake user find the query history in Snowsight?", "options": ["A) Admin", "B) Activity", "C) Dashboards", "D) Data"], "chooseN": 1, "correct": ["Activity"], "explanation": "In Snowsight, Snowflake's user interface, the query history can be found under the 'Activity' section. This area provides a detailed history of the queries executed, including their status, duration, and other relevant information.", "reference": "https://docs.snowflake.com/en/user-guide/ui-snowsight-activity"}, {"id": 477, "area": "Snowflake Data Cloud Features & Architecture", "question": "What is SnowSQL?", "options": ["A) Snowflake's new user interface where users can visualize data into charts and dashboards.", "B) Snowflake's proprietary extension of the ANSI SQL standard, including built-in keywords and system functions.", "C) Snowflake's command line client built on the Python connector which is used to connect to Snowflake and execute SQL.", "D) Snowflake's library that provides a programming interface for processing data on Snowflake without moving it to the system where the application code runs."], "chooseN": 1, "correct": ["Snowflake's command line client built on the Python connector which is used to connect to Snowflake and execute SQL."], "explanation": "SnowSQL is Snowflake's command line client, which is built on the Python connector. It is used to connect to Snowflake and execute SQL commands. SnowSQL offers a text-based interface for interacting with Snowflake, managing objects, and running queries.", "reference": "https://docs.snowflake.com/en/user-guide/snowsql.html"}, {"id": 478, "area": "Data Transformations", "question": "The following SQL statements have been executed: What will the output be of the last select statement?\ncreate or replace sequence seq_01 start = 1 increment = 2;\ncreate or replace table sequence_test_table (i integer);\n\nselect seq_01.nextval;\nselect seq_01.nextval;\n\ninsert into sequence_test_table (i) values (seq_01.nextval);\nselect seq_01.nextval;", "options": ["A) 3", "B) 4", "C) 7", "D) 8"], "chooseN": 1, "correct": ["7"], "explanation": "To determine the output of the last select statement, the specific SQL statements that were executed prior to it are required. Without knowing these statements, it is not possible to accurately predict the output of the select statement.", "reference": "https://docs.snowflake.com/en/user-guide/querying-sequences?utm_source=snowscope&utm_medium=serp&utm_term=sequences"}, {"id": 479, "area": "Data Protection and Data Sharing", "question": "Which statement is true of zero-copy cloning?", "options": ["A) It increases storage costs as cloning a table requires storing its data twice", "B) A cloned table includes the load history of the original source", "C) It is licensed as an additional Snowflake feature", "D) All micro-partitions between the original and cloned tables are fully shared"], "chooseN": 1, "correct": ["All micro-partitions between the original and cloned tables are fully shared"], "explanation": "Zero-copy cloning in Snowflake means that all micro-partitions between the original and cloned tables are fully shared. This approach does not require additional storage for the cloned data, as it leverages Snowflake's unique architecture to reference the same underlying data without duplicating it.", "reference": "https://docs.snowflake.com/en/user-guide/tables-storage-considerations#cloning-tables-schemas-and-databases"}, {"id": 480, "area": "Data Protection and Data Sharing", "question": "A Snowflake user has been granted the CREATE DATA EXCHANGE LISTING privilege with their role. Which tasks can this user now perform on the Data Exchange? (Choose two.)", "options": ["A) Rename listings", "B) Delete provider profiles", "C) Modify listings properties", "D) Modify incoming listing access requests", "E) Submit listings for approval/publishing"], "chooseN": 2, "correct": ["Modify listings properties", "Submit listings for approval/publishing"], "explanation": "With the CREATE DATA EXCHANGE LISTING privilege, a Snowflake user can modify listings properties and submit listings for approval or publishing on the Data Exchange. This allows them to manage and promote their data listings effectively within the Snowflake Data Exchange.", "reference": "https://docs.snowflake.com/en/user-guide/data-exchange-marketplace-privileges#global-create-data-exchange-listing-privilege"}, {"id": 481, "area": "Data Loading and Unloading", "question": "Which parameter prevents streams on tables from becoming stale?", "options": ["A) MAX_DATA_EXTENSION_TIME_IN_DAYS", "B) MIN_DATA_RETENSION_TIME_IN_DAYS", "C) LOCK_TIMEOUT", "D) STALE_AFTER"], "chooseN": 1, "correct": ["MAX_DATA_EXTENSION_TIME_IN_DAYS"], "explanation": "The MAX_DATA_EXTENSION_TIME_IN_DAYS parameter prevents streams on tables from becoming stale by extending the data retention period for the source table beyond the default DATA_RETENTION_TIME_IN_DAYS. This ensures the stream's offset does not expire before the data is consumed. STALE_AFTER is a read-only stream property that indicates when the stream will become stale, not a parameter that prevents staleness. MIN_DATA_RETENSION_TIME_IN_DAYS is not a valid Snowflake parameter.", "reference": "https://community.snowflake.com/s/article/Stream-Staleness-FAQ?utm_source=snowscope&utm_medium=serp&utm_term=stale_after"}, {"id": 482, "area": "Performance Concepts", "question": "If a virtual warehouse runs for 30 seconds after it is provisioned, how many seconds will the customer be billed for?", "options": ["A) 30 seconds", "B) 60 seconds", "C) 121 seconds", "D) 1 hour"], "chooseN": 1, "correct": ["60 seconds"], "explanation": "In Snowflake, the billing for virtual warehouse usage is done on a per-second basis, with a minimum of 60 seconds. So, even if a warehouse runs for only 30 seconds, the customer will be billed for a full 60 seconds as that is the minimum billable time unit.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-considerations.html#billing-and-cost-considerations"}, {"id": 483, "area": "Data Transformations", "question": "When should a stored procedure be created with caller's rights?", "options": ["A) When the caller needs to be prevented from viewing the source code of the stored procedure", "B) When the caller needs to run a statement that could not execute outside of the stored procedure", "C) When the stored procedure needs to run with the privileges of the role that called the stored procedure", "D) When the stored procedure needs to operate on objects that the caller does not have privileges on"], "chooseN": 1, "correct": ["When the stored procedure needs to run with the privileges of the role that called the stored procedure"], "explanation": "A stored procedure should be created with caller's rights when it needs to run with the privileges of the role that called the stored procedure. This approach ensures that the procedure operates within the security and access constraints of the calling user, respecting their permissions and privileges.", "reference": "https://docs.snowflake.com/en/sql-reference/stored-procedures-usage.html#ownership-and-execution-privileges"}, {"id": 484, "area": "Data Transformations", "question": "What JavaScript delimiters are available in Snowflake stored procedures? (Choose two.)", "options": ["A) Double quotes (“)", "B) Single quote (’)", "C) Double forward slash (/)", "D) Double backslash (\\\\)", "E) Double dollar sign ($$)"], "chooseN": 2, "correct": ["Single quote (’)", "Double dollar sign ($$)"], "explanation": "In Snowflake stored procedures written in JavaScript, two body delimiters are available: the double dollar sign ($$) and the single quote ('). The double dollar sign is recommended because it avoids escaping issues when the JavaScript code contains embedded single quotes. Double forward slashes (//) are comment delimiters in JavaScript, not procedure body delimiters.", "reference": "https://docs.snowflake.com/en/developer-guide/stored-procedure/stored-procedures-javascript#javascript-delimiters"}, {"id": 485, "area": "Data Transformations", "question": "What type of function can be used to estimate the approximate number of distinct values from a table that has trillions of rows?", "options": ["A) MD5", "B) Window", "C) External", "D) HyperLogLog (HLL)"], "chooseN": 1, "correct": ["HyperLogLog (HLL)"], "explanation": "The HyperLogLog (HLL) function in Snowflake can be used to estimate the approximate number of distinct values in a very large dataset, such as a table with trillions of rows. HLL is an algorithm designed for efficient approximation of the count of distinct values.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/hll.html"}, {"id": 486, "area": "Data Protection and Data Sharing", "question": "Which Data Definition Language (DDL) commands are supported by Snowflake to manage tags? (Choose two.)", "options": ["A) ALTER TAG", "B) DESCRIBE TAG", "C) DROP TAG", "D) GRANT ... TO TAG", "E) GRANT TAG"], "chooseN": 2, "correct": ["ALTER TAG", "DROP TAG"], "explanation": "In Snowflake, the 'ALTER TAG' and 'DROP TAG' commands are supported as Data Definition Language (DDL) commands to manage tags. These commands allow users to modify and delete tags, respectively, for managing metadata associated with Snowflake objects.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/alter-tag.html"}, {"id": 487, "area": "Data Protection and Data Sharing", "question": "What Snowflake objects can be added to a share? (Choose two.)", "options": ["A) Views", "B) Tables", "C) Stored procedures", "D) Streams", "E) Secure views"], "chooseN": 2, "correct": ["Tables", "Secure views"], "explanation": "In Snowflake, both 'Tables' and 'Secure views' can be added to a share. These objects can be shared with other Snowflake accounts or with external entities through reader accounts, facilitating data sharing and collaboration.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-intro.html"}, {"id": 488, "area": "Performance Concepts", "question": "A Query Profile shows a UnionAll operator with an extra Aggregate operator on top. What does this signify?", "options": ["A) Exploding joins", "B) Inefficient pruning", "C) UNION without ALL", "D) Queries that are too large to fit in memory"], "chooseN": 1, "correct": ["UNION without ALL"], "explanation": "In a Snowflake Query Profile, if a UnionAll operator is shown with an extra Aggregate operator on top, it typically signifies the use of 'UNION' without the 'ALL' keyword. This extra Aggregate operator is used to remove duplicates, which is the default behavior of the UNION operator.", "reference": "https://docs.snowflake.com/en/user-guide/ui-query-profile#union-without-all"}, {"id": 489, "area": "Account Access and Security", "question": "Which data governance control has Snowflake embedded in the application?", "options": ["A) Network policies", "B) Credit computation", "C) Data storage", "D) Attribute-based access control"], "chooseN": 1, "correct": ["Attribute-based access control"], "explanation": "Snowflake has embedded 'Attribute-based access control' as a data governance control in the application. This control allows fine-grained access permissions based on attributes like user roles, data tags, and more, enabling organizations to implement robust data governance policies.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-considerations.html#attribute-based-access-control"}, {"id": 490, "area": "Data Loading and Unloading", "question": "What actions does the use of the PUT command do automatically? (Choose two.)", "options": ["A) It creates a file format object.", "B) It uses the last stage created.", "C) It compresses all files using GZIP.", "D) It encrypts the file data in transit.", "E) It creates an empty target table."], "chooseN": 2, "correct": ["It compresses all files using GZIP.", "It encrypts the file data in transit."], "explanation": "The PUT command in Snowflake automatically compresses files using GZIP and encrypts the file data in transit. These actions optimize file transfer to stages and enhance security, respectively.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/put.html"}, {"id": 491, "area": "Data Loading and Unloading", "question": "Which command should a Snowflake user execute to load data into a table?", "options": ["A) copy into mytable purge_mode = TRUE;", "B) copy into mytable from @my_int_stage;", "C) copy into mytable file_format = (format_name);", "D) copy into mytable validation = ‘RETURN_ERRORS’;"], "chooseN": 1, "correct": ["copy into mytable from @my_int_stage;"], "explanation": "To load data into a table in Snowflake, the user should execute the command 'copy into mytable from @my_int_stage;'. This command specifies the table and the stage (location of files) from which to load the data.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-table.html"}, {"id": 492, "area": "Data Loading and Unloading", "question": "Which function returns the URL of a stage using the stage name as the input?", "options": ["A) BUILD_STAGE_FILE_URL", "B) BUILD_SCOPED_FILE_URL", "C) GET_PRESIGNED_URL", "D) GET_STAGE_LOCATION"], "chooseN": 1, "correct": ["GET_STAGE_LOCATION"], "explanation": "The 'GET_STAGE_LOCATION' function in Snowflake returns the URL of a stage, given the stage name as input. This function is useful for retrieving the location of a specific stage in Snowflake.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/get_stage_location.html"}, {"id": 493, "area": "Performance Concepts", "question": "What is the MAXIMUM number of clusters that can be provisioned with a multi-cluster virtual warehouse? D. 100", "options": ["A) 1", "B) 5", "C) 10"], "chooseN": 1, "correct": ["10"], "explanation": "A multi-cluster warehouse must have a maximum cluster count greater than 1. In Snowsight, the highest Max Clusters value you can select is 10, and the SQL maximum varies by warehouse size. Among the provided options, 10 is the correct choice.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-multicluster.html"}, {"id": 494, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which Snowflake table supports unstructured data?", "options": ["A) Directory", "B) Transient", "C) Temporary", "D) Permanent"], "chooseN": 1, "correct": ["Directory"], "explanation": "- Directory: Las Directory Tables (tablas de directorio) son el mecanismo de Snowflake para gestionar datos no estructurados. Se asocian a stages internos o externos y proporcionan un catalogo de los archivos almacenados (imagenes, PDFs, videos, etc.), incluyendo URLs para acceder a ellos.\n- Transient: Las tablas transitorias almacenan datos estructurados/semi-estructurados temporales. No estan disenadas para datos no estructurados.\n- Temporary: Las tablas temporales existen solo durante la sesion del usuario. No soportan datos no estructurados.\n- Permanent: Las tablas permanentes almacenan datos estructurados y semi-estructurados (VARIANT), pero no datos no estructurados como archivos binarios.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-dirtables, https://docs.snowflake.com/en/user-guide/unstructured-intro"}, {"id": 495, "area": "Data Loading and Unloading", "question": "When unloading data, which file format preserves the data values for floating-point number columns?", "options": ["A) Avro", "B) CSV", "C) JSON", "D) Parquet"], "chooseN": 1, "correct": ["Parquet"], "explanation": "The Parquet file format is the most effective for preserving the data values of floating-point number columns when unloading data from Snowflake. Parquet is a columnar storage format that efficiently handles different data types, including floating-point numbers, with high fidelity.", "reference": "https://docs.snowflake.com/en/user-guide/data-unload-considerations#explicitly-converting-numeric-columns-to-parquet-data-types"}, {"id": 496, "area": "Performance Concepts", "question": "Which virtual warehouse privilege is required to view a load-monitoring chart?", "options": ["A) MONITOR", "B) MODIFY", "C) OPERATE", "D) USAGE"], "chooseN": 1, "correct": ["MONITOR"], "explanation": "To view a load-monitoring chart of a virtual warehouse in Snowflake, the 'MONITOR' privilege is required. This privilege allows users to observe and assess the performance and usage of the virtual warehouse.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-load-monitoring#viewing-the-load-monitoring-chart"}, {"id": 497, "area": "Data Transformations", "question": "Which use case will always cause an exploding join in Snowflake?", "options": ["A) A query that has more than 10 left outer joins.", "B) A query that is using a UNION without an ALL.", "C) A query that has not specified join criteria for tables.", "D) A query that has requested too many columns of data."], "chooseN": 1, "correct": ["A query that has not specified join criteria for tables."], "explanation": "An exploding join in Snowflake typically occurs when a query does not specify join criteria for tables. This lack of criteria can lead to a Cartesian product, where each row of one table is joined to every row of another, causing an exponential increase in the number of rows returned.", "reference": "https://docs.snowflake.com/en/user-guide/ui-snowsight-activity#label-exploding-join"}, {"id": 498, "area": "Performance Concepts", "question": "How many resource monitors can be applied to a single virtual warehouse?", "options": ["A) Zero", "B) One", "C) Eight", "D) Unlimited"], "chooseN": 1, "correct": ["One"], "explanation": "In Snowflake, only one resource monitor can be applied to a single virtual warehouse at a time. This monitor is used to track and control the credits consumed by the warehouse, ensuring efficient and cost-effective operation.", "reference": "https://docs.snowflake.com/en/user-guide/resource-monitors.html"}, {"id": 499, "area": "Snowflake Data Cloud Features & Architecture", "question": "What are the main differences between the account usage views and the information schema views? (Choose two.)", "options": ["A) No active warehouse is needed to query account usage views but one is needed to query information schema views.", "B) Account usage views do not contain data about tables but information schema views do.", "C) Account usage views contain dropped objects but information schema views do not.", "D) Data retention for account usage views is 1 year but is 7 days to 6 months for information schema views, depending on the view.", "E) Information schema views are read-only but account usage views are not."], "chooseN": 2, "correct": ["Account usage views contain dropped objects but information schema views do not.", "Data retention for account usage views is 1 year but is 7 days to 6 months for information schema views, depending on the view."], "explanation": "The main differences between account usage views and information schema views in Snowflake are that account usage views contain data about dropped objects, which information schema views do not, and account usage views have a data retention period of 1 year, while information schema views retain data for a period ranging from 7 days to 6 months, depending on the specific view.", "reference": "https://docs.snowflake.com/en/user-guide/views-account-usage.html"}, {"id": 500, "area": "Data Loading and Unloading", "question": "Which file function provides a URL with access to a file on a stage without the need for authentication and authorization?", "options": ["A) GET_RELATIVE_PATH", "B) GET_PRESIGNED_URL", "C) BUILD_STAGE_FILE_URL", "D) BUILD_SCOPED_FILE_URL"], "chooseN": 1, "correct": ["GET_PRESIGNED_URL"], "explanation": "The 'GET_PRESIGNED_URL' function in Snowflake provides a URL with access to a file on a stage without the need for authentication and authorization. This function generates a presigned URL that grants temporary access to the file, simplifying the process of file sharing and access.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/get_presigned_url.html"}, {"id": 501, "area": "Data Loading and Unloading", "question": "Which view can be used to determine if a table has frequent row updates or deletes?", "options": ["A) TABLES", "B) TABLE_STORAGE_METRICS", "C) STORAGE_DAILY_HISTORY", "D) STORAGE_USAGE"], "chooseN": 1, "correct": ["TABLE_STORAGE_METRICS"], "explanation": "The 'TABLE_STORAGE_METRICS' view in Snowflake can be used to determine if a table has frequent row updates or deletes. This view provides metrics related to the storage utilization of tables, including information on micro-partition changes that can indicate frequent updates or deletions.", "reference": "https://docs.snowflake.com/en/sql-reference/account-usage/table_storage_metrics.html"}, {"id": 502, "area": "Performance Concepts", "question": "How does the Snowflake search optimization service improve query performance?", "options": ["A) It improves the performance of range searches.", "B) It defines different clustering keys on the same source table.", "C) It improves the performance of all queries running against a given table.", "D) It improves the performance of equality searches."], "chooseN": 1, "correct": ["It improves the performance of range searches."], "explanation": "The Snowflake search optimization service primarily improves the performance of range searches. By optimizing how data is stored and accessed, it reduces the time and resources needed to execute range queries, leading to faster query performance.", "reference": "https://docs.snowflake.com/en/user-guide/search-optimization-service"}, {"id": 503, "area": "Data Loading and Unloading", "question": "How is unstructured data retrieved from data storage?", "options": ["A) SQL functions like the GET command can be used to copy the unstructured data to a location on the client.", "B) SQL functions can be used to create different types of URLs pointing to the unstructured data. These URLs can be used to download the data to a client.", "C) SQL functions can be used to retrieve the data from the query results cache. When the query results are output to a client, the unstructured data will be output to the client as files.", "D) SQL functions can call on different web extensions designed to display different types of files as a web page. The web extensions will allow the files to be downloaded to the client."], "chooseN": 1, "correct": ["SQL functions can be used to create different types of URLs pointing to the unstructured data. These URLs can be used to download the data to a client."], "explanation": "In Snowflake, SQL functions can be used to create different types of URLs that point to unstructured data stored in stages. These URLs can then be used by clients to download the data directly. This approach allows easy and direct access to unstructured data without the need for complex retrieval mechanisms.", "reference": "https://docs.snowflake.com/en/user-guide/unstructured-intro"}, {"id": 504, "area": "Data Protection and Data Sharing", "question": "What is the recommended way to obtain a cloned table with the same grants as the source table?", "options": ["A) Clone the table with the COPY GRANTS command.", "B) Use an ALTER TABLE command to copy the grants.", "C) Clone the schema then drop the unwanted tables.", "D) Create a script to extract grants and apply them to the cloned table."], "chooseN": 1, "correct": ["Clone the table with the COPY GRANTS command."], "explanation": "The recommended way to obtain a cloned table with the same grants as the source table in Snowflake is to use the 'COPY GRANTS' option. When cloning a table with this option, all grants on the source table are also applied to the cloned table, preserving the access permissions.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/create-clone.html"}, {"id": 505, "area": "Performance Concepts", "question": "What common query issues can be identified using the Query Profile? (Choose two.)", "options": ["A) Data classification", "B) Exploding joins", "C) Unions", "D) Inefficient pruning", "E) Data masking"], "chooseN": 2, "correct": ["Exploding joins", "Inefficient pruning"], "explanation": "Using the Query Profile in Snowflake, common query issues such as 'exploding joins' and 'inefficient pruning' can be identified. Exploding joins occur when the join criteria lead to a large increase in the number of rows returned. Inefficient pruning refers to cases where the query engine scans more data than necessary.", "reference": "https://docs.snowflake.com/en/user-guide/ui-query-profile#common-query-problems-identified-by-query-profile"}, {"id": 506, "area": "Data Loading and Unloading", "question": "What is used to extract the content of PDF files stored in Snowflake stages?", "options": ["A) FLATTEN function", "B) Window function", "C) HyperLogLog (HLL) function", "D) Java User-Defined Function (UDF)"], "chooseN": 1, "correct": ["Java User-Defined Function (UDF)"], "explanation": "To extract the content of PDF files stored in Snowflake stages, a Java User-Defined Function (UDF) can be used. Java UDFs allow the execution of custom Java code within Snowflake, which is suitable for processing complex data types like PDF.", "reference": "https://docs.snowflake.com/en/user-guide/unstructured-data-java#process-a-pdf-with-a-udf-and-procedure"}, {"id": 507, "area": "Data Loading and Unloading", "question": "What is used to extract the content of PDF files stored in Snowflake stages?", "options": ["A) FLATTEN function", "B) Window function", "C) HyperLogLog (HLL) function", "D) Java User-Defined Function (UDF)"], "chooseN": 1, "correct": ["Java User-Defined Function (UDF)"], "explanation": "To extract the content of PDF files stored in Snowflake stages, a Java User-Defined Function (UDF) can be used. Java UDFs allow the execution of custom Java code within Snowflake, which is suitable for processing complex data types like PDF.", "reference": "https://docs.snowflake.com/en/user-guide/unstructured-data-java#process-a-pdf-with-a-udf-and-procedure"}, {"id": 508, "area": "Data Protection and Data Sharing", "question": "What happens when a database is cloned?", "options": ["A) It does not retain any privileges granted on the source object.", "B) It replicates all granted privileges on the corresponding source objects.", "C) It replicates all granted privileges on the corresponding child objects.", "D) It replicates all granted privileges on the corresponding child schema objects."], "chooseN": 1, "correct": ["It replicates all granted privileges on the corresponding child objects."], "explanation": "When a database is cloned in Snowflake, the clone inherits all granted privileges on the clones of the child objects contained in the source database. However, the database container itself does not inherit the privileges granted on the source container. In other words, grants on schemas, tables, views, and other contained objects are copied to the cloned objects, but the source database’s own privileges are not copied to the new database.", "reference": "https://docs.snowflake.com/en/user-guide/object-clone#access-control-privileges-for-cloned-objects"}, {"id": 509, "area": "Snowflake Data Cloud Features & Architecture", "question": "What does a Query Profile provide in Snowflake?", "options": ["A) A multi-step query that displays each processing step in the same panel.", "B) A pre-computed data set derived from a query specification and stored for later use.", "C) A graphical representation of the main components of the processing plan for a query.", "D) A collapsible panel in the operator tree pane that lists nodes by execution time in descending order for a query."], "chooseN": 1, "correct": ["A graphical representation of the main components of the processing plan for a query."], "explanation": "A Query Profile in Snowflake provides a graphical representation of the main components of the processing plan for a query. This visual aid helps users understand how Snowflake executes their query, displaying the execution plan's various steps and the resources utilized at each step.", "reference": "https://docs.snowflake.com/en/user-guide/ui-query-profile"}, {"id": 510, "area": "Data Loading and Unloading", "question": "When executing a COPY INTO command, performance can be negatively affected by using which optional parameter on a large number of files?", "options": ["A) FILE_FORMAT", "B) PATTERN", "C) VALIDATION_MODE", "D) FILES"], "chooseN": 1, "correct": ["PATTERN"], "explanation": "For the best performance, try to avoid applying patterns that filter on a large number of files.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-table#optional-parameters"}, {"id": 511, "area": "Data Loading and Unloading", "question": "Which URL type should be used to get a permanent URL to a file in a stage?", "options": ["A) File URL", "B) Pre-signed URL", "C) Saved URL", "D) Scoped URL"], "chooseN": 1, "correct": ["File URL"], "explanation": "Snowflake offers three URL types for accessing staged files: File URL (permanent, requires authentication via BUILD_STAGE_FILE_URL or directory table), Pre-signed URL (temporary with configurable expiration up to 7 days, no auth needed), and Scoped URL (temporary 24-hour, user-specific). For a permanent URL to a file in a stage, the File URL is the correct choice as it provides a persistent identifier that remains valid as long as the file exists and the user has appropriate stage privileges.", "reference": "https://docs.snowflake.com/en/user-guide/unstructured-intro#types-of-urls-available-to-access-files"}, {"id": 512, "area": "Account Access and Security", "question": "Which operation will produce an error in Snowflake?", "options": ["A) Inserting duplicate values into a PRIMARY KEY column", "B) Inserting a NULL into a column with a NOT NULL constraint", "C) Inserting duplicate values into a column with a UNIQUE constraint", "D) Inserting a value to FOREIGN KEY column that does not match a value in the column referenced"], "chooseN": 1, "correct": ["Inserting a NULL into a column with a NOT NULL constraint"], "explanation": "In standard Snowflake tables, NOT NULL is the only constraint that is enforced. Therefore, inserting a NULL into a NOT NULL column produces an error, while duplicate PRIMARY KEY / UNIQUE values and foreign key mismatches are not enforced as errors in this context.", "reference": "https://docs.snowflake.com/en/sql-reference/constraints-overview.html#not-null-constraint"}, {"id": 513, "area": "Data Loading and Unloading", "question": "How are URLs that access unstructured data in external stages retrieved?", "options": ["A) From the Snowsight navigation menu", "B) By querying a directory table", "C) By creating an external function", "D) By using the INFORMATION_USAGE schema"], "chooseN": 1, "correct": ["By querying a directory table"], "explanation": "URLs that access unstructured data in external stages in Snowflake are typically retrieved by querying a directory table. Directory tables in Snowflake allow users to query metadata about files in stages, including their URLs.", "reference": "https://docs.snowflake.com/en/user-guide/unstructured-intro#directory-tables"}, {"id": 514, "area": "Performance Concepts", "question": "What is the Snowflake multi-clustering feature for virtual warehouses used for?", "options": ["A) To improve the data unloading process to the cloud", "B) To improve data loading from very large data sets", "C) To improve concurrency for users and queries", "D) To speed up slow or stalled queries"], "chooseN": 1, "correct": ["To improve concurrency for users and queries"], "explanation": "The multi-clustering feature for virtual warehouses in Snowflake is used to improve concurrency for users and queries. It allows for the automatic scaling of compute resources to handle varying workloads efficiently, thereby enhancing the performance of concurrent queries and user operations.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-multicluster.html"}, {"id": 515, "area": "Performance Concepts", "question": "Which features could be used to improve the performance of queries that return a small subset of rows from a large table? (Choose two.)", "options": ["A) Search optimization service", "B) Automatic clustering", "C) Row access policies", "D) Multi-cluster virtual warehouses", "E) Secure views"], "chooseN": 2, "correct": ["Search optimization service", "Automatic clustering"], "explanation": "To improve the performance of queries that return a small subset of rows from a large table, features like the Search Optimization Service and Automatic Clustering can be used. The Search Optimization Service speeds up queries on large tables, while Automatic Clustering keeps the data optimally organized to reduce the time taken to retrieve a subset of rows.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions.html"}, {"id": 516, "area": "Data Transformations", "question": "Which command would return an empty sample?", "options": ["A) select * from testtable sample ();", "B) select * from testtable sample (0);", "C) select * from testtable sample (null);", "D) select * from testtable sample (none);"], "chooseN": 1, "correct": ["select * from testtable sample (0);"], "explanation": "The command 'select * from testtable sample (0);' will return an empty sample. This is because specifying a sample size of 0 effectively means no rows are selected from the table, resulting in an empty result set.", "reference": "https://docs.snowflake.com/en/sql-reference/constructs/sample"}, {"id": 517, "area": "Data Loading and Unloading", "question": "What Snowflake function should be used to unload relational data to JSON?", "options": ["A) BUILD_STAGE_FILE_URL()", "B) OBJECT_CONSTRUCT()", "C) PARSE_JSON()", "D) TO_VARIANT()"], "chooseN": 1, "correct": ["OBJECT_CONSTRUCT()"], "explanation": "The 'OBJECT_CONSTRUCT()' function in Snowflake should be used to unload relational data to JSON format. This function is used to create a JSON object from relational data, enabling the transformation of structured data into a JSON format.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/object_construct.html"}, {"id": 518, "area": "Data Loading and Unloading", "question": "Floating point values are truncated when unloaded to which file format?", "options": ["A) ORC", "B) CSV", "C) Avro", "D) Parquet"], "chooseN": 1, "correct": ["CSV"], "explanation": "When unloading data from Snowflake, floating point values are truncated in the CSV file format. CSV is a text-based format and may not preserve the exact precision of floating-point numbers, leading to truncation or rounding of these values.", "reference": "https://docs.snowflake.com/en/user-guide/data-unload-considerations.html"}, {"id": 519, "area": "Account Access and Security", "question": "Which levels can apply network policies? (Choose two.)", "options": ["A) Account", "B) Database", "C) Role", "D) Schema", "E) User"], "chooseN": 2, "correct": ["Account", "User"], "explanation": "In Snowflake, network policies can be applied at the Account and User levels. Account-level policies set default network access rules for the entire account, while User-level policies define network access controls for individual users.", "reference": "https://docs.snowflake.com/en/user-guide/network-policies.html"}, {"id": 520, "area": "Data Protection and Data Sharing", "question": "What causes objects in a data share to become unavailable to a consumer account?", "options": ["A) The DATA_RETENTION_IT parameter in the consumer account is set to 0.", "B) The consumer account runs the GRANT INPORTED PRIVILEGES command on the data share every 24 hours.", "C) The objects in the data share are being deleted and the grant pattern is not re-applied systematically.", "D) The consumer account acquires the data share through a private data exchange."], "chooseN": 1, "correct": ["The objects in the data share are being deleted and the grant pattern is not re-applied systematically."], "explanation": "Objects in a data share become unavailable to a consumer account if the objects in the data share are being deleted and the grant pattern is not re-applied systematically. This means if the data provider removes access or deletes the shared objects without reapplying the necessary permissions, the consumer will lose access.", "reference": "https://docs.snowflake.com/en/user-guide/data-share-consumers"}, {"id": 521, "area": "Account Access and Security", "question": "How can an administrator check for updates (for example, SCIM API requests) sent to Snowflake by the identity provider?", "options": ["A) ACCESS_HISTORY", "B) LOAD_HISTORY", "C) QUERY_HISTORY", "D) REST_EVENT_HISTORY"], "chooseN": 1, "correct": ["REST_EVENT_HISTORY"], "explanation": "An administrator can check for updates, such as SCIM API requests sent to Snowflake by the identity provider, by querying the 'REST_EVENT_HISTORY' view. This view provides information about REST API activities in Snowflake, including requests made for user and group management via the SCIM API.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/rest_event_history"}, {"id": 522, "area": "Data Transformations", "question": "A Snowflake user is writing a User-Defined Function (UDF) with some unqualified object names. How will those object names be resolved during execution?", "options": ["A) Snowflake will resolve them according to the SEARCH_PATH parameter.", "B) Snowflake will only check the schema the UDF belongs to.", "C) Snowflake will first check the current schema, and then the schema the previous query used.", "D) Snowflake will first check the current schema, and then the PUBLIC schema of the current database."], "chooseN": 1, "correct": ["Snowflake will only check the schema the UDF belongs to."], "explanation": "In queries, unqualified object names are resolved through a search path. The SEARCH_PATH is not used inside views or Writing User-Defined Functions (UDFs). All unqualified objects in a view or UDF definition will be resolved in the view’s or UDF’s schema only.", "reference": "https://docs.snowflake.com/en/sql-reference/name-resolution#name-resolution-in-queries"}, {"id": 523, "area": "Performance Concepts", "question": "Why should a user select the economy scaling policy for a multi-cluster warehouse?", "options": ["A) To prevent/minimize query queuing", "B) To increase performance of the clusters", "C) To reduce queuing concurrent user queries", "D) To conserve credits by keeping running clusters fully loaded"], "chooseN": 1, "correct": ["To conserve credits by keeping running clusters fully loaded"], "explanation": "A user should select the economy scaling policy for a multi-cluster warehouse in Snowflake to conserve credits by keeping running clusters fully loaded. The economy scaling policy prioritizes cost savings by fully utilizing existing clusters before scaling out to additional clusters.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-multicluster.html#scaling-policies"}, {"id": 524, "area": "Account Access and Security", "question": "What MINIMUM privilege is required on the external stage for any role in the GET REST API to access unstructured data files using a file URL?", "options": ["A) READ", "B) OWNERSHIP", "C) USAGE", "D) WRITE"], "chooseN": 1, "correct": ["USAGE"], "explanation": "When using the GET REST API to access unstructured data files using a file URL in Snowflake, the minimum privilege required on the external stage is the USAGE privilege. The role executing the GET command needs the USAGE privilege on the external stage that contains the file being accessed.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-snowpipe-rest-apis.html"}, {"id": 525, "area": "Account Access and Security", "question": "Which view in SNOWFLAKE.ACCOUNT_USAGE shows from which IP address a user connected to Snowflake?", "options": ["A) ACCESS_HISTORY", "B) LOGIN_HISTORY", "C) SESSIONS", "D) QUERY_HISTORY"], "chooseN": 1, "correct": ["LOGIN_HISTORY"], "explanation": "The 'LOGIN_HYSTORY' view in SNOWFLAKE.ACCOUNT_USAGE provides information about user login activities, including the IP addresses from which users have connected to Snowflake. This view is useful for auditing and monitoring user access.", "reference": "https://docs.snowflake.com/en/sql-reference/account-usage/login_history.html"}, {"id": 526, "area": "Account Access and Security", "question": "Snowflake Partner Connect is limited to users with a verified email address and which role?", "options": ["A) SYSADMIN", "B) SECURITYADMIN", "C) ACCOUNTADMIN", "D) USERADMIN"], "chooseN": 1, "correct": ["ACCOUNTADMIN"], "explanation": "Snowflake Partner Connect is limited to users who have a verified email address and the 'ACCOUNTADMIN' role. This role is necessary to ensure that the user has sufficient privileges to access and configure the integrations available through Snowflake Partner Connect.", "reference": "https://docs.snowflake.com/en/user-guide/partner-connect.html"}, {"id": 527, "area": "Snowflake Data Cloud Features & Architecture", "question": "What unit of storage supports efficient query processing in Snowflake?", "options": ["A) Blobs", "B) JSON", "C) Block storage", "D) Micro-partitions"], "chooseN": 1, "correct": ["Micro-partitions"], "explanation": "Micro-partitions are the unit of storage that supports efficient query processing in Snowflake. They are automatically managed by Snowflake and enable efficient data storage, retrieval, and processing by organizing the data into optimized, compressed units.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions.html"}, {"id": 528, "area": "Data Transformations", "question": "What is the difference between a stored procedure and a User-Defined Function (UDF)?", "options": ["A) Stored procedures can execute database operations while UDFs cannot.", "B) Returning a value is required in a stored procedure while returning values in a UDF is optional.", "C) Values returned by a stored procedure can be used directly in a SQL statement while the values returned by a UDF cannot.", "D) Multiple stored procedures can be called as part of a single executable statement while a single SQL statement can only call one UDF at a time."], "chooseN": 1, "correct": ["Stored procedures can execute database operations while UDFs cannot."], "explanation": "The key difference between a stored procedure and a User-Defined Function (UDF) in Snowflake is that stored procedures can execute database operations (such as INSERT, UPDATE, DELETE), while UDFs are limited to read-only operations and cannot perform such database modifications.", "reference": "https://docs.snowflake.com/en/sql-reference/stored-procedures.html"}, {"id": 529, "area": "Data Protection and Data Sharing", "question": "Which URL type does Snowflake recommend to use when providing unstructured data to other accounts through a share?", "options": ["A) File", "B) Pre-signed", "C) Scoped", "D) Staged"], "chooseN": 1, "correct": ["Scoped"], "explanation": "Snowflake recommends using Scoped URLs when providing unstructured data to other accounts through a share. Scoped URLs are Ideal for use in custom applications, for providing unstructured data to other accounts through a share, or for downloading and analysis of unstructured data in Snowsight.", "reference": "https://docs.snowflake.com/en/user-guide/unstructured-intro"}, {"id": 530, "area": "Data Loading and Unloading", "question": "What is the MAXIMUM Time Travel retention period for a transient table?", "options": ["A) 0 days", "B) 1 day", "C) 7 days", "D) 90 days"], "chooseN": 1, "correct": ["1 day"], "explanation": "The maximum Time Travel retention period for a transient table in Snowflake is 1 day. Transient tables are designed for temporary or staging data and thus have a shorter time travel period compared to permanent tables.", "reference": "https://docs.snowflake.com/en/user-guide/tables-temp-transient.html#transient-tables"}, {"id": 531, "area": "Data Protection and Data Sharing", "question": "What is the advantage of using a reader account?", "options": ["A) It can be used by a client that does not have a Snowflake account", "B) It is read-only and prevents the shared data from being updated by the provider.", "C) It can be connected to a Snowflake account in a different region.", "D) It provides limited access to the data share and is therefore cheaper for the data provider."], "chooseN": 1, "correct": ["It can be used by a client that does not have a Snowflake account"], "explanation": "The advantage of using a reader account in Snowflake is that it allows clients who do not have a Snowflake account to access shared data. Reader accounts enable external users to query data shares in a secure and controlled environment.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-reader-create"}, {"id": 532, "area": "Data Loading and Unloading", "question": "What command is used to export or unload data from Snowflake?", "options": ["A) PUT @mystage", "B) GET @mystage", "C) Copy INTO @mystage", "D) INSERT @mystage"], "chooseN": 1, "correct": ["Copy INTO @mystage"], "explanation": "To export or unload data from Snowflake, the 'COPY INTO @mystage' command is used. This command allows data to be exported from Snowflake tables to a specified stage, facilitating the movement of data out of Snowflake.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-location.html"}, {"id": 533, "area": "Data Protection and Data Sharing", "question": "A Snowflake user wants to share data with someone who does not have a Snowflake account. How can the Snowflake user share the data?", "options": ["A) Use the Snowflake Marketplace.", "B) Create a reader account.", "C) Create a consumer account.", "D) Use a Snowflake share."], "chooseN": 1, "correct": ["Create a reader account."], "explanation": "When a Snowflake user wants to share data with someone who does not have a Snowflake account, the best approach is to create a reader account. A reader account provides external users access to specific data shares in Snowflake without requiring them to have their own Snowflake account.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-reader-create"}, {"id": 534, "area": "Account Access and Security", "question": "A user wants to add additional privileges to the system-defined roles for their virtual warehouse. How does Snowflake recommend they accomplish this?", "options": ["A) Grant the additional privileges to a custom role.", "B) Grant the additional privileges to the ACCOUNTADMIN role.", "C) Grant the additional privileges to the SYSADMIN role.", "D) Grant the additional privileges to the ORGADMIN role."], "chooseN": 1, "correct": ["Grant the additional privileges to a custom role."], "explanation": "Snowflake recommends granting additional privileges to a custom role rather than modifying system-defined roles directly. This approach maintains the integrity and security of the predefined roles while providing the flexibility to extend privileges as needed through custom roles.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-overview.html"}, {"id": 535, "area": "Snowflake Data Cloud Features & Architecture", "question": "How does Snowflake store a table's underlying data? (Choose two.)", "options": ["A) Columnar file format", "B) Micro-partitions", "C) Text file format", "D) Uncompressed", "E) User-defined partitions"], "chooseN": 2, "correct": ["Columnar file format", "Micro-partitions"], "explanation": "Snowflake stores a table's underlying data using a columnar file format and micro-partitions. The columnar format allows for efficient data storage and retrieval, while micro-partitions enable Snowflake to manage and process the data effectively.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions.html"}, {"id": 536, "area": "Data Protection and Data Sharing", "question": "What is the MAXIMUM number of days a Snowflake-managed encryption key can be used before it gets automatically rotated?", "options": ["A) 1 day", "B) 14 days", "C) 30 days", "D) 120 days"], "chooseN": 1, "correct": ["30 days"], "explanation": "In Snowflake, the maximum number of days a Snowflake-managed encryption key can be used before it is automatically rotated is 30 days. This key rotation policy helps maintain high security standards for encrypted data.", "reference": "https://docs.snowflake.com/en/user-guide/security-encryption.html"}, {"id": 537, "area": "Account Access and Security", "question": "Which user object property requires contacting Snowflake Support in order to set a value for it?", "options": ["A) DISABLED", "B) MINS_TO_BYPASS MFA", "C) MINS_TO_BYPASS_NETWORK_POLICY", "D) MINS_TO_UNLOCK"], "chooseN": 1, "correct": ["MINS_TO_BYPASS_NETWORK_POLICY"], "explanation": "To set a value for the 'MINS_TO_BYPASS_NETWORK_POLICY' user object property in Snowflake, it is necessary to contact Snowflake Support. This property is related to network policies, and its modification may require assistance from the support team.", "reference": "https://docs.snowflake.com/en/user-guide/network-policies"}, {"id": 538, "area": "Data Loading and Unloading", "question": "How does Snowflake handle the bulk unloading of data into single or multiple files?", "options": ["A) It assigns each unloaded data file a unique name.", "B) It uses the PUT command to download the data by default.", "C) It uses COPY INTO for bulk unloading where the default option is SINGLE = TRUE.", "D) It uses COPY INTO to copy the data from a table into one or more files in an external stage only."], "chooseN": 1, "correct": ["It assigns each unloaded data file a unique name."], "explanation": "When unloading data using COPY INTO <location>, Snowflake assigns each data file a unique name. A filename prefix can be specified in the location path; if not specified, Snowflake uses the default prefix 'data_'. COPY INTO can unload to both internal and external stages, not just external stages. The default value of SINGLE is FALSE, meaning data is split into multiple files.", "reference": "https://docs.snowflake.com/en/user-guide/data-unload-overview"}, {"id": 539, "area": "Snowflake Data Cloud Features & Architecture", "question": "What information is included in the display in the Query Profile? (Choose two.)", "options": ["A) Index hints used in query", "B) Credit usage details", "C) Clustering keys details", "D) Details and statistics for the overall query", "E) Graphical representation of the query processing plan"], "chooseN": 2, "correct": ["Details and statistics for the overall query", "Graphical representation of the query processing plan"], "explanation": "The Query Profile in Snowflake includes details and statistics for the overall query and a graphical representation of the query processing plan. These elements help users understand and optimize query performance by showing the execution phases and resource usage.", "reference": "https://docs.snowflake.com/en/user-guide/ui-query-profile"}, {"id": 540, "area": "Performance Concepts", "question": "A Snowflake user wants to optimize performance for a query that queries only a small number of rows in a table. The rows require significant processing. The data in the table does not change frequently. What should the user do?", "options": ["A) Add a clustering key to the table.", "B) Add the search optimization service to the table.", "C) Create a materialized view based on the query.", "D) Enable the query acceleration service for the virtual warehouse."], "chooseN": 1, "correct": ["Create a materialized view based on the query."], "explanation": "To optimize performance for a query that involves significant processing of a small number of rows, the user should create a materialized view based on the query. Materialized views store the results of the query and can significantly improve performance, especially when the underlying data does not change frequently.", "reference": "https://docs.snowflake.com/en/user-guide/views-materialized.html"}, {"id": 541, "area": "Account Access and Security", "question": "When using the ALLOW_CLIENT_MFA_CACHING parameter, how long is a cached Multi-Factor Authentication (MFA) token valid for?", "options": ["A) 1 hour", "B) 2 hours", "C) 4 hours", "D) 8 hours"], "chooseN": 1, "correct": ["4 hours"], "explanation": "When using the ALLOW_CLIENT_MFA_CACHING parameter in Snowflake, a cached Multi-Factor Authentication (MFA) token is valid for 4 hours. This setting allows MFA authentication details to be cached for a specified duration, simplifying the login process for the duration of the token's validity.", "reference": "https://docs.snowflake.com/en/user-guide/security-mfa.html"}, {"id": 542, "area": "Data Loading and Unloading", "question": "When unloading data, which file formats are supported by the COPY INTO command? (Choose two.)", "options": ["A) Avro", "B) JSON", "C) ORC", "D) Parquet", "E) XML"], "chooseN": 2, "correct": ["JSON", "Parquet"], "explanation": "When unloading data with COPY INTO <location>, Snowflake supports only three file formats: CSV, JSON, and Parquet. The syntax definition explicitly shows TYPE = { CSV | JSON | PARQUET }. Avro, ORC, and XML are only supported for loading data into Snowflake (COPY INTO <table>), not for unloading. Among the given options, only JSON and Parquet are valid unload formats.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-location.html"}, {"id": 543, "area": "Data Transformations", "question": "A JSON object is loaded into a column named data using a Snowflake variant datatype. The root node of the object is BIKE. The child attribute for this root node is BIKEID. Which statement will allow the user to access BIKEID?", "options": ["A) select data:BIKEID", "B) select data.BIKE.BIKEID", "C) select data:BIKE.BIKEID", "D) select data:BIKE:BIKEID"], "chooseN": 1, "correct": ["select data:BIKE.BIKEID"], "explanation": "To access the BIKEID attribute from a JSON object in a variant datatype column, the correct SQL statement is 'select data:BIKE.BIKEID'. This statement uses dot notation to navigate the JSON object structure and retrieve the desired value.", "reference": "https://docs.snowflake.com/en/user-guide/querying-semistructured"}, {"id": 544, "area": "Account Access and Security", "question": "A custom role owns multiple tables. If this role is dropped from the system, who becomes the owner of these tables?", "options": ["A) ACCOUNTADMIN", "B) SYSADMIN", "C) Tables will be standalone or orphaned.", "D) The role that dropped the custom role."], "chooseN": 1, "correct": ["The role that dropped the custom role."], "explanation": "If a custom role that owns multiple tables is dropped from Snowflake, the role that dropped the custom role automatically becomes the owner of these tables. Ownership of any objects owned by the dropped role is transferred to the role that executes the DROP ROLE command.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/drop-role"}, {"id": 545, "area": "Data Transformations", "question": "Which function produces a lateral view of a VARIANT column?", "options": ["A) GET_PATH", "B) FLATTEN", "C) GET", "D) PARSE_JSON"], "chooseN": 1, "correct": ["FLATTEN"], "explanation": "The 'FLATTEN' function in Snowflake is used to produce a lateral view of a VARIANT column. This function expands array or object data within a VARIANT column into multiple rows, making the data more accessible for analysis and querying.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/flatten.html"}, {"id": 546, "area": "Account Access and Security", "question": "Snowflake strongly recommends that all users with what type of role be required to use Multi-Factor Authentication (MFA)?", "options": ["A) USERADMIN", "B) ACCOUNTADMIN", "C) SECURITYADMIN", "D) SYSADMIN"], "chooseN": 1, "correct": ["ACCOUNTADMIN"], "explanation": "Snowflake strongly recommends that all users with the 'ACCOUNTADMIN' role be required to use Multi-Factor Authentication (MFA). This is because the ACCOUNTADMIN role has extensive privileges and access across the Snowflake account, making it critical to secure with additional authentication methods.", "reference": "https://docs.snowflake.com/en/user-guide/security-mfa.html"}, {"id": 547, "area": "Data Loading and Unloading", "question": "What does it mean when the sample function uses the Bernoulli sampling method?", "options": ["A) The data is based on sampling every row.", "B) The data is based on sampling 10% of the source data.", "C) The data is based on sampling blocks of the source data.", "D) The data is based on sampling 1000 rows of the source data."], "chooseN": 1, "correct": ["The data is based on sampling every row."], "explanation": "When the sample function in Snowflake uses the Bernoulli sampling method, it means that the data is based on sampling every row in the source data. Each row has an independent probability of being included in the sample.", "reference": "https://docs.snowflake.com/en/sql-reference/constructs/sample"}, {"id": 548, "area": "Account Access and Security", "question": "What are characteristics of Snowflake network policies? (Choose two.)", "options": ["A) They can be set for any Snowflake Edition", "B) They can be applied to roles.", "C) They restrict or enable access to specific IP addresses.", "D) They are activated using ALTER DATABASE SQL commands.", "E) They can only be managed using the ORGADMIN role."], "chooseN": 2, "correct": ["They can be set for any Snowflake Edition", "They restrict or enable access to specific IP addresses."], "explanation": "Characteristics of Snowflake network policies include the ability to be set for any Snowflake Edition and the functionality to restrict or enable access to specific IP addresses. Network policies are a crucial aspect of managing access and security in Snowflake environments.", "reference": "https://docs.snowflake.com/en/user-guide/network-policies.html"}, {"id": 549, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which function should be used to find the query ID of the second query executed in a current session?", "options": ["A) Select LAST_QUERY_ID(-2)", "B) Select LAST_QUERY_ID(-1)", "C) Select LAST_QUERY_ID(1)", "D) Select LAST_QUERY_ID(2)"], "chooseN": 1, "correct": ["Select LAST_QUERY_ID(2)"], "explanation": "To find the query ID of the second query executed in the current session, use `LAST_QUERY_ID(2)`. In Snowflake, positive numbers count from the first query run in the session, while negative numbers count backward from the most recent query. `LAST_QUERY_ID(-2)` returns the second most recent query,", "reference": "https://docs.snowflake.com/en/sql-reference/functions/last_query_id.html"}, {"id": 550, "area": "Snowflake Data Cloud Features & Architecture", "question": "How is the hierarchy of database objects organized in Snowflake?", "options": ["A) A database consists of one or more schemas. A schema contains tables and views.", "B) A schema consists of one or more databases. A database contains tables and views.", "C) A schema consists of one or more databases. A database contains tables, views, and warehouses.", "D) A database consists of one of more schemas and warehouses. A schema contains tables and views."], "chooseN": 1, "correct": ["A database consists of one or more schemas. A schema contains tables and views."], "explanation": "In Snowflake, the hierarchy of database objects is organized such that a database consists of one or more schemas, and each schema contains tables and views. This structure allows for the organization and management of data in a structured manner.", "reference": "https://docs.snowflake.com/en/user-guide/intro-key-concepts.html#database-objects"}, {"id": 551, "area": "Account Access and Security", "question": "Which role can execute the SHOW ORGANIZATION ACCOUNTS command successfully?", "options": ["A) ACCOUNTADMIN", "B) SECURITYADMIN", "C) ORGADMIN", "D) USERADMIN"], "chooseN": 1, "correct": ["ORGADMIN"], "explanation": "The 'ORGADMIN' role is required to execute the SHOW ORGANIZATION ACCOUNTS command successfully in Snowflake. This role is typically granted to administrators who manage multiple accounts within an organization.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/show-organization-accounts.html"}, {"id": 552, "area": "Data Transformations", "question": "Which data types in Snowflake are synonymous for FLOAT? (Choose two.)", "options": ["A) DECIMAL", "B) DOUBLE", "C) NUMBER", "D) NUMERIC", "E) REAL"], "chooseN": 2, "correct": ["DOUBLE", "REAL"], "explanation": "In Snowflake, the data types synonymous with FLOAT are 'DOUBLE' and 'REAL'. Both of these data types are used to represent floating-point numbers, which are numbers with a fractional part.", "reference": "https://docs.snowflake.com/en/sql-reference/data-types-numeric.html#float-double-real"}, {"id": 553, "area": "Account Access and Security", "question": "What ensures that a user with the role SECURITYADMIN can activate a network policy for an individual user?", "options": ["A) A role that has been granted the EXECUTE TASK privilege", "B) A role that has been granted the global ATTACH POLICY privilege", "C) Ownership privilege on only the role that created the network policy", "D) Ownership privilege on both the user and the network policy"], "chooseN": 1, "correct": ["Ownership privilege on both the user and the network policy"], "explanation": "The user with the SECURITYADMIN role needs ownership privileges on both the specific user and the network policy to activate the network policy for that individual user.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/grant-privilege.html"}, {"id": 554, "area": "Data Transformations", "question": "Which function can be combined with the copy command to unload a relational table into a JSON file?", "options": ["A) FLATTEN", "B) LISTAGG", "C) OBJECT_CONSTRUCT", "D) PARSE_JSON"], "chooseN": 1, "correct": ["OBJECT_CONSTRUCT"], "explanation": "The 'OBJECT_CONSTRUCT' function can be combined with the copy command to unload a relational table into a JSON file. This function constructs a JSON object for each row in the table, allowing relational data to be transformed into JSON format during the unload process.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/object_construct.html"}, {"id": 555, "area": "Snowflake Data Cloud Features & Architecture", "question": "A user needs to MINIMIZE the cost of large tables that are used to store transitory data. The data does not need to be protected against failures, because the data can be reconstructed outside of Snowflake. What table type should be used?", "options": ["A) Permanent", "B) Transient", "C) Temporary", "D) External"], "chooseN": 1, "correct": ["Transient"], "explanation": "The Transient table type is designed for temporary or intermediate data that can be reconstructed outside of Snowflake. Transient tables have lower storage costs compared to permanent tables and are suitable for scenarios where the data doesn't need to be persisted in Snowflake for an extended period and can be reconstructed if necessary.", "reference": "https://docs.snowflake.com/en/user-guide/tables-temp-transient.html#temporary-tables"}, {"id": 556, "area": "Data Loading and Unloading", "question": "While loading data from a JSON file, what enables the removal of the outer array structure from the file and loads the records into separate table rows?", "options": ["A) SKIP_BYTE_ORDER_MARK", "B) STRIP_NULL_VALUE", "C) STRIP_OUTER_ARRAY", "D) STRIP_OUTER_ELEMENT"], "chooseN": 1, "correct": ["STRIP_OUTER_ARRAY"], "explanation": "The 'STRIP_OUTER_ARRAY' file format option is used when loading data from a JSON file to remove the outer array structure. This enables the individual records within the array to be loaded into separate rows in a Snowflake table.", "reference": "https://docs.snowflake.com/en/user-guide/semistructured-considerations"}, {"id": 557, "area": "Data Protection and Data Sharing", "question": "Which functions can be used to share unstructured data through a secure view? (Choose two.)", "options": ["A) BUILD_SCOPED_FILE_URL", "B) BUILD_STAGE_FILE_URL", "C) GET_ABSOLUTE_PATH", "D) GET_PRESIGNED_URL", "E) GET_RELATIVE_PATH"], "chooseN": 2, "correct": ["BUILD_SCOPED_FILE_URL", "GET_PRESIGNED_URL"], "explanation": "The functions 'BUILD_SCOPED_FILE_URL' and 'GET_PRESIGNED_URL' can be used to share unstructured data through a secure view in Snowflake. These functions generate URLs that provide scoped and time-limited access to files stored in stages, enabling secure sharing of unstructured data.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/build_scoped_file_url.html"}, {"id": 558, "area": "Data Transformations", "question": "Which function will return a row for each for each object in a VARIANT, OBJECT, or ARRAY column?", "options": ["A) CAST", "B) FLATTEN", "C) GET", "D) PARSE_JSON"], "chooseN": 1, "correct": ["FLATTEN"], "explanation": "The 'FLATTEN' function is used in Snowflake to return a row for each object in a VARIANT, OBJECT, or ARRAY column. It expands the nested or semi-structured data within these columns into individual rows, making it more accessible for querying and analysis.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/flatten.html"}, {"id": 559, "area": "Performance Concepts", "question": "What is the MINIMUM size of a table for which Snowflake recommends considering adding a clustering key?", "options": ["A) 1 Kilobyte (KB)", "B) 1 Megabyte (MB)", "C) 1 Gigabyte (GB)", "D) 1 Terabyte (TB)"], "chooseN": 1, "correct": ["1 Terabyte (TB)"], "explanation": "Snowflake recommends considering adding a clustering key for tables that are at least 1 Terabyte (TB) in size. Clustering keys can improve the performance of large tables by organizing data in a way that reduces the amount of scanning during queries.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-keys.html"}, {"id": 560, "area": "Data Protection and Data Sharing", "question": "For the ALLOWED_VALUES tag property, what is the MAXIMUM number of possible string values for a single tag?", "options": ["A) 10", "B) 50", "C) 64", "D) 300"], "chooseN": 1, "correct": ["300"], "explanation": "Snowflake documentation states that ALLOWED_VALUES defines a comma-separated list of possible string values for a tag, and that the maximum number of tag values in this list is 5,000. Therefore, the documented maximum number of possible string values for a single tag is 5,000.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/create-tag"}, {"id": 561, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which Snowflake table type is only visible to the user who creates it, can have the same name as permanent tables in the same schema, and is dropped at the end of the session?", "options": ["A) Temporary", "B) Local", "C) User", "D) Transient"], "chooseN": 1, "correct": ["Temporary"], "explanation": "In Snowflake, Temporary tables are only visible to the user who creates them, can have the same name as permanent tables in the same schema, and are dropped at the end of the session. These tables are used for temporary storage and computations during a session.", "reference": "https://docs.snowflake.com/en/user-guide/tables-temp-transient.html#temporary-tables"}, {"id": 562, "area": "Account Access and Security", "question": "What is a characteristic of a role in Snowflake?", "options": ["A) Roles cannot be granted to other roles.", "B) System-defined roles can be dropped.", "C) Privileges granted to system roles by Snowflake can be revoked.", "D) Privileges on securable objects can be granted and revoked to a role."], "chooseN": 1, "correct": ["Privileges on securable objects can be granted and revoked to a role."], "explanation": "A key characteristic of roles in Snowflake is that privileges on securable objects can be granted and revoked to a role. This allows for flexible and granular control over access and permissions within Snowflake.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-overview.html#roles"}, {"id": 563, "area": "Data Loading and Unloading", "question": "What command would a user execute to load unstructured data files into a Snowflake internal stage?", "options": ["A) PUT", "B) GET", "C) LIST", "D) COPY INTO"], "chooseN": 1, "correct": ["PUT"], "explanation": "To load unstructured data files into a Snowflake internal stage, a user would execute the 'PUT' command. The PUT command is used to upload files from a local file system to a Snowflake stage.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/put.html"}, {"id": 564, "area": "Data Protection and Data Sharing", "question": "How do managed access schemas help with data governance?", "options": ["A) They log all operations and enable fine-grained auditing.", "B) They provide centralized privilege management with the schema owner.", "C) They enforce identical privileges across all tables and views in a schema.", "D) They require the use of masking and row access policies across every table and view in the schema."], "chooseN": 1, "correct": ["They provide centralized privilege management with the schema owner."], "explanation": "Managed access schemas in Snowflake help with data governance by providing centralized privilege management with the schema owner. This means the schema owner controls access to all objects within the schema, ensuring consistent and controlled access management.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-overview.html#managed-access-schemas"}, {"id": 565, "area": "Performance Concepts", "question": "What is the default period of time the Warehouse Activity section provides a graph of Snowsight activity?", "options": ["A) 2 hours", "B) 1 week", "C) 2 weeks", "D) 1 month"], "chooseN": 1, "correct": ["2 weeks"], "explanation": "The default period of time for which the Warehouse Activity section in Snowsight provides a graph of activity is 2 weeks. This allows users to view and analyze warehouse activity and performance over a recent and relevant timeframe.", "reference": "https://docs.snowflake.com/en/user-guide/ui-snowsight-admin#warehouse-activity"}, {"id": 566, "area": "Data Loading and Unloading", "question": "A Snowflake user wants to unload data from a relational table sized 5 GB using CSV. The extract needs to be as performant as possible. What should the user do?", "options": ["A) Use Parquet as the unload file format, using Parquet's default compression feature.", "B) Use a regular expression in the stage specification of the COPY command to restrict parsing time.", "C) Increase the default MAX_FILE_SIZE to 5 GB and set SINGLE = true to produce a single file.", "D) Leave the default MAX_FILE_SIZE to 16 MB to take advantage of parallel operations."], "chooseN": 1, "correct": ["Leave the default MAX_FILE_SIZE to 16 MB to take advantage of parallel operations."], "explanation": "To achieve the most performant data unload using CSV format, the user should leave the default MAX_FILE_SIZE at 16 MB. This setting allows Snowflake to take advantage of parallel operations, where multiple smaller files are unloaded in parallel, leading to faster overall performance.", "reference": "https://docs.snowflake.com/en/user-guide/data-unload-considerations.html"}, {"id": 567, "area": "Account Access and Security", "question": "How is the MANAGE GRANTS privilege applied?", "options": ["A) Globally", "B) At the database level", "C) At the schema level", "D) At the table level"], "chooseN": 1, "correct": ["Globally"], "explanation": "The MANAGE GRANTS privilege in Snowflake is applied globally. This means it allows the user to manage privileges across the entire Snowflake environment, not restricted to any specific database, schema, or table level.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/grant-privilege.html"}, {"id": 568, "area": "Performance Concepts", "question": "What is required for a query execution to be served from the result cache?", "options": ["A) The user is the same.", "B) The SQL texts the same.", "C) The SQL query profile is the same.", "D) The virtual warehouse is the same."], "chooseN": 1, "correct": ["The SQL texts the same."], "explanation": "For a query execution to be served from Snowflake's result cache, the SQL text of the query must be the same. Snowflake's result cache stores the results of queries, and if an identical query (in terms of SQL text) is executed again, the results can be served from this cache, significantly improving performance.", "reference": "https://docs.snowflake.com/en/user-guide/querying-persisted-results"}, {"id": 569, "area": "Data Loading and Unloading", "question": "Which Snowflake URL type is used by directory tables?", "options": ["A) File", "B) Pre-signed", "C) Scoped", "D) Virtual-hosted style"], "chooseN": 1, "correct": ["File"], "explanation": "Directory tables in Snowflake use File URLs. URL that identifies the database, schema, stage, and file path to a set of files. A role that has sufficient privileges on the stage can access the files.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-dirtables"}, {"id": 570, "area": "Data Protection and Data Sharing", "question": "At which point is data encrypted when using a PUT command?", "options": ["A) When it reaches the virtual warehouse", "B) When it gets micro-partitioned", "C) Before it is sent from the user's machine", "D) After it reaches the internal stage"], "chooseN": 1, "correct": ["Before it is sent from the user's machine"], "explanation": "When using the PUT command in Snowflake, data is encrypted before it is sent from the user's machine. This ensures that the data is secure and protected during transit to the Snowflake internal stage.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/put.html"}, {"id": 571, "area": "Account Access and Security", "question": "Which privileges are required for a user to restore an object? (Choose two.)", "options": ["A) UPDATE", "B) OWNERSHIP", "C) MODIFY", "D) UNDROP", "E) CREATE"], "chooseN": 2, "correct": ["OWNERSHIP", "CREATE"], "explanation": "Similar to dropping an object, a user must have OWNERSHIP privileges for an object to restore it. In addition, the user must have CREATE privileges on the object type for the database or schema where the dropped object will be restored.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-privileges"}, {"id": 572, "area": "Performance Concepts", "question": "For a multi-cluster virtual warehouse, which parameters are used to calculate the number of credits billed? (Choose two.)", "options": ["A) Cache size", "B) Warehouse size", "C) Number of clusters", "D) Volume of data processed", "E) Number of queries executed"], "chooseN": 2, "correct": ["Warehouse size", "Number of clusters"], "explanation": "For a multi-cluster virtual warehouse in Snowflake, the number of credits billed is calculated based on the warehouse size and the number of clusters. These parameters determine the compute resources used and thus affect the overall cost.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-multicluster.html#billing-and-cost-considerations"}, {"id": 573, "area": "Account Access and Security", "question": "What happens when the values for both an ALLOWED_IP_LIST and a BLOCKED_IP_LIST are used in a network policy?", "options": ["A) Snowflake ignores the BLOCKED_IP_LIST first.", "B) Snowflake applies the BLOCKED_IP_LIST first.", "C) Snowflake applies the ALLOWED_IP_LIST first.", "D) Snowflake ignores the ALLOWED_IP_LIST first."], "chooseN": 1, "correct": ["Snowflake applies the BLOCKED_IP_LIST first."], "explanation": "In Snowflake, when both an ALLOWED_IP_LIST and a BLOCKED_IP_LIST are specified in a network policy, the BLOCKED_IP_LIST is applied first. This means that any IP addresses on the BLOCKED_IP_LIST are denied access, regardless of whether they appear on the ALLOWED_IP_LIST.", "reference": "https://docs.snowflake.com/en/user-guide/network-policies"}, {"id": 574, "area": "Performance Concepts", "question": "What does the orange bar on an operator represent when reviewing the Query Profile?", "options": ["A) A measure of progress of the operator's execution.", "B) The fraction of time that this operator consumed within the query step.", "C) The cost of the operator in terms of the virtual warehouse CPU utilization.", "D) The fraction of data scanned from cache versus remote disk for the operator."], "chooseN": 1, "correct": ["The fraction of time that this operator consumed within the query step."], "explanation": "In the Query Profile in Snowflake, the orange bar on an operator represents the fraction of time that the operator consumed within the query step. This helps in identifying which operators are taking the most time in the query execution, aiding in performance tuning.", "reference": "https://docs.snowflake.com/en/user-guide/query-profile.html"}, {"id": 575, "area": "Data Loading and Unloading", "question": "When unloading data from Snowflake, what is the default file size of each file?", "options": ["A) 16 MB", "B) 32 MB", "C) 64 MB", "D) 5 GB"], "chooseN": 1, "correct": ["16 MB"], "explanation": "When unloading data from Snowflake, the default file size for each unloaded file is 16 MB. This default size is set to optimize the balance between file management and performance in most scenarios.", "reference": "https://docs.snowflake.com/en/user-guide/data-unload-considerations.html"}, {"id": 576, "area": "Data Loading and Unloading", "question": "What is the abbreviated form to get all the files in the stage for the current user?", "options": ["A) LIST @~;", "B) LS @~;", "C) LS @usr;", "D) SHOW @%;"], "chooseN": 1, "correct": ["LS @~;"], "explanation": "The abbreviated command to list all the files in the stage for the current user in Snowflake is 'LS @~;'. This command provides a quick and efficient way to view all the files available in the user's stage.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/list.html"}, {"id": 577, "area": "Data Protection and Data Sharing", "question": "Which features make up Snowflake's column level security? (Choose two.)", "options": ["A) Continuous Data Protection (CDP)", "B) Dynamic Data Masking", "C) External Tokenization", "D) Key pair authentication", "E) Row access policies"], "chooseN": 2, "correct": ["Dynamic Data Masking", "External Tokenization"], "explanation": "Column-level Security in Snowflake consists of two features: Dynamic Data Masking and External Tokenization. Dynamic Data Masking uses masking policies to selectively mask data at query time. External Tokenization enables tokenizing data before loading and detokenizing at query time. Row access policies are a separate Row-level Security feature. Key pair authentication and Continuous Data Protection are unrelated to column-level security.", "reference": "https://docs.snowflake.com/en/user-guide/security-column"}, {"id": 578, "area": "Data Transformations", "question": "Which programming languages are supported for Snowflake User-Defined Functions (UDFs)? (Choose two.)", "options": ["A) C#", "B) JavaScript", "C) PHP", "D) Python", "E) TypeScript"], "chooseN": 2, "correct": ["JavaScript", "Python"], "explanation": "Snowflake supports JavaScript and Python for User-Defined Functions (UDFs). These programming languages can be used to create UDFs that perform custom operations on data within Snowflake, extending the capabilities of standard SQL.", "reference": "https://docs.snowflake.com/en/sql-reference/udf-overview.html"}, {"id": 579, "area": "Performance Concepts", "question": "What is the MAXIMUM number of days that Snowflake resets the 24-hour retention period for a query result every time the result is used?", "options": ["A) 1 day", "B) 10 days", "C) 31 days", "D) 60 days"], "chooseN": 1, "correct": ["31 days"], "explanation": "Snowflake resets the 24-hour retention period for a query result every time the result is used, with a maximum of 31 days. This means that each time a query result is accessed, its availability is extended for another 24 hours, up to a total of 31 days.", "reference": "https://docs.snowflake.com/en/user-guide/querying-stage.html#data-retention"}, {"id": 580, "area": "Performance Concepts", "question": "There are 300 concurrent users on a production Snowflake account using a single cluster virtual warehouse. The queries are small, but the response time is very slow. What is causing this to occur?", "options": ["A) The warehouse is queuing the queries, increasing the overall query execution time.", "B) The warehouse parameter STATEMENT_QUEUED_TIMEOUT_IN_SECONDS is set too low.", "C) The application is not using the latest native ODBC driver which is causing latency.", "D) The queries are not taking advantage of the data cache."], "chooseN": 1, "correct": ["The warehouse is queuing the queries, increasing the overall query execution time."], "explanation": "With 300 concurrent users on a single cluster virtual warehouse, the most likely cause of slow response time is that the warehouse is queuing the queries. This occurs when the warehouse's resources are insufficient to handle the volume of concurrent queries, leading to increased execution time as queries wait in the queue.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-considerations.html#considerations-for-sizing-warehouses"}, {"id": 581, "area": "Account Access and Security", "question": "Which Snowflake edition offers the highest level of security for organizations that have the strictest requirements?", "options": ["A) Standard", "B) Enterprise", "C) Business Critical", "D) Virtual Private Snowflake (VPS)"], "chooseN": 1, "correct": ["Virtual Private Snowflake (VPS)"], "explanation": "The Virtual Private Snowflake (VPS) edition offers the highest level of security for organizations with the strictest security requirements. VPS provides a dedicated and isolated instance of Snowflake with enhanced security features and compliance certifications.", "reference": "https://docs.snowflake.com/en/user-guide/intro-editions#feature-edition-matrix"}, {"id": 582, "area": "Data Transformations", "question": "What is the MAXIMUM size limit for a record of a VARIANT data type?", "options": ["A) 8 MB", "B) 16 MB", "C) 32 MB", "D) 128 MB"], "chooseN": 1, "correct": ["128 MB"], "explanation": "A VARIANT value can have a maximum size of up to 128 MB of uncompressed data in Snowflake. The 16 MB figure applies to the default size for VARCHAR columns, not VARIANT.", "reference": "https://docs.snowflake.com/en/sql-reference/data-types-semistructured.html#variant"}, {"id": 583, "area": "Account Access and Security", "question": "What criteria does Snowflake use to determine the current role when initiating a session? (Choose two.)", "options": ["A) If a role was specified as part of the connection and that role has been granted to the Snowflake user, the specified role becomes the current role.", "B) If no role was specified as part of the connection and a default role has been defined for the Snowflake user, that role becomes the current role.", "C) If no role was specified as part of the connection and a default role has not been set for the Snowflake user, the session will not be initiated and the log in will fail.", "D) If a role was specified as part of the connection and that role has not been granted to the Snowflake user, it will be ignored and the default role will become the current role.", "E) If a role was specified as part of the connection and that role has not been granted to the Snowflake user, the role is automatically granted and it becomes the current role."], "chooseN": 2, "correct": ["If a role was specified as part of the connection and that role has been granted to the Snowflake user, the specified role becomes the current role.", "If no role was specified as part of the connection and a default role has been defined for the Snowflake user, that role becomes the current role."], "explanation": "When initiating a session in Snowflake, if a role is specified as part of the connection and it has been granted to the user, this role becomes the current role. Alternatively, if no role is specified and a default role has been set for the user, the default role becomes the current role.", "reference": "https://docs.snowflake.com/en/user-guide/admin-user-management.html#setting-a-default-role"}, {"id": 584, "area": "Data Loading and Unloading", "question": "What command should be used to move data from a Snowflake database table into one or more files in an external stage?", "options": ["A) GET", "B) COPY INTO", "C) PUT", "D) SHOW"], "chooseN": 1, "correct": ["COPY INTO"], "explanation": "The 'COPY INTO' command should be used to move data from a Snowflake database table into one or more files in an external stage. This command enables the efficient export of data from tables to files in supported external storage locations.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-location.html"}, {"id": 585, "area": "Data Loading and Unloading", "question": "How does a Snowflake user reference a directory table created on stage mystage in a SQL query?", "options": ["A) SELECT * FROM @mystage::DIRECTORY", "B) SELECT * FROM DIRECTORY (@mystage)", "C) SELECT * FROM TO_TABLE (DIRECTORY @mystage)", "D) SELECT * FROM TABLE (@mystage DIRECTORY)"], "chooseN": 1, "correct": ["SELECT * FROM DIRECTORY (@mystage)"], "explanation": "To reference a directory table created on stage 'mystage' in a SQL query, the correct syntax is 'SELECT * FROM DIRECTORY (@mystage)'. This syntax retrieves all metadata columns in a directory table for a stage named mystage.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-dirtables-query"}, {"id": 586, "area": "Data Protection and Data Sharing", "question": "Why would a Snowflake user create a secure view instead of a standard view?", "options": ["A) The secure view is only available to end users with the corresponding SECURE_ACCESS property.", "B) End users are unable to see the view definition, and internal optimizations differ with a secure view.", "C) With a secure view, the underlying data is replicated to a separate storage layer with enhanced encryption.", "D) Secure views support additional functionality that is not supported for standard views, such as column masking and row level access policies."], "chooseN": 1, "correct": ["End users are unable to see the view definition, and internal optimizations differ with a secure view."], "explanation": "A secure view is created for two primary reasons: (1) the view definition (SQL text) is hidden from unauthorized users -- only users granted the owning role can see it, and (2) internal query optimizations that could indirectly expose underlying data are disabled. (A) is incorrect because there is no 'SECURE_ACCESS' property. (C) is incorrect because secure views do not replicate data. (D) is incorrect because column masking and row access policies work with both standard and secure views -- they are not specific to secure views.", "reference": "https://docs.snowflake.com/en/user-guide/views-secure.html"}, {"id": 587, "area": "Data Loading and Unloading", "question": "Which command can be added to the COPY command to make it load all files, whether or not the load status of the files is known?", "options": ["A) FORCE = TRUE", "B) FORCE = FALSE", "C) LOAD_UNCERTAIN_FILES = TRUE", "D) LOAD_UNCERTAIN_FILES = FALSE"], "chooseN": 1, "correct": ["FORCE = TRUE"], "explanation": "The 'FORCE = TRUE' option can be added to the COPY command to make it load all files, regardless of whether the load status of the files is known. This option forces the loading of files even if they have been previously loaded or their status is uncertain.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-table.html#loading-files-with-force-true"}, {"id": 588, "area": "Performance Concepts", "question": "How can a Snowflake user improve long-running query performance?", "options": ["A) Reduce the virtual warehouse size.", "B) Cluster the underlying table being queried.", "C) Disable the result cache.", "D) Add ORDER BY to the query."], "chooseN": 1, "correct": ["Cluster the underlying table being queried."], "explanation": "To improve the performance of long-running queries in Snowflake, clustering the underlying table being queried can be effective. Clustering involves reorganizing the data in a table to optimize data retrieval, thereby reducing the time taken for query execution.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-keys.html"}, {"id": 589, "area": "Data Protection and Data Sharing", "question": "Which Snowflake feature allows administrators to identify unused data that may be archived or deleted?", "options": ["A) Access history", "B) Data classification", "C) Dynamic Data Masking", "D) Object tagging"], "chooseN": 1, "correct": ["Access history"], "explanation": "The 'Access history' feature in Snowflake allows administrators to identify unused data that may be archived or deleted. This feature provides insights into how data is being accessed and utilized, helping administrators make informed decisions about data management.", "reference": "https://docs.snowflake.com/en/user-guide/access-history.html"}, {"id": 590, "area": "Data Transformations", "question": "Which SQL commands should be used to write a recursive query if the number of levels is unknown? (Choose two.)", "options": ["A) CONNECT BY", "B) LISTAGG", "C) MATCH RECOGNIZE", "D) QUALIFY", "E) WITH"], "chooseN": 2, "correct": ["CONNECT BY", "WITH"], "explanation": "To write a recursive query when the number of levels is unknown, the SQL commands 'CONNECT BY' and 'WITH' should be used. 'CONNECT BY' is used for hierarchical queries, and 'WITH' is used in common table expressions, including recursive queries.", "reference": "https://docs.snowflake.com/en/sql-reference/constructs/connect-by.html"}, {"id": 591, "area": "Account Access and Security", "question": "What information is stored in the ACCESS_HISTORY view?", "options": ["A) History of the files that have been loaded into Snowflake", "B) Names and owners of the roles that are currently enabled in the session", "C) Query details such as the objects included and the user who executed the query", "D) Details around the privileges that have been granted for all objects in an account"], "chooseN": 1, "correct": ["Query details such as the objects included and the user who executed the query"], "explanation": "The ACCESS_HISTORY view in Snowflake stores information about query details, such as the objects included in the queries and the users who executed them. This view is useful for auditing and analyzing data access patterns within Snowflake.", "reference": "https://docs.snowflake.com/en/sql-reference/account-usage/access_history.html"}, {"id": 592, "area": "Data Protection and Data Sharing", "question": "What privilege does a user need in order to receive or request data from the Snowflake Marketplace?", "options": ["A) CREATE DATA EXCHANGE LISTING", "B) CREATE SHARE", "C) IMPORT SHARE", "D) IMPORTED PRIVILEGES"], "chooseN": 1, "correct": ["IMPORT SHARE"], "explanation": "Para recibir o solicitar datos del Snowflake Marketplace, un usuario necesita el privilegio IMPORT SHARE. Este privilegio permite crear una base de datos a partir de un share recibido, habilitando el acceso a los datos compartidos. CREATE DATA EXCHANGE LISTING es para proveedores que publican listados. CREATE SHARE se usa para crear shares como proveedor. IMPORTED PRIVILEGES se usa para otorgar acceso a bases de datos compartidas a roles adicionales, no para recibir datos.", "reference": "https://docs.snowflake.com/en/user-guide/data-exchange-consumer.html"}, {"id": 593, "area": "Data Protection and Data Sharing", "question": "Which Snowflake database object can be shared with other accounts?", "options": ["A) Tasks", "B) Pipes", "C) Secure User-Defined Functions (UDFs)", "D) Stored Procedures"], "chooseN": 1, "correct": ["Secure User-Defined Functions (UDFs)"], "explanation": "In Snowflake, Secure User-Defined Functions (UDFs) can be shared with other accounts. These functions encapsulate logic that can be reused and shared across different accounts, facilitating collaboration and reuse of custom logic.", "reference": "https://docs.snowflake.com/en/user-guide/udf.html"}, {"id": 594, "area": "Account Access and Security", "question": "Which identity providers are valid type values for federated authentication on the SAML_IDENTITY_PROVIDER parameter? (Choose two.)", "options": ["A) Identity Access Management (IAM)", "B) Microsoft Active Directory Federation Services (AD FS)", "C) OAuth", "D) Okta", "E) PingFederate"], "chooseN": 2, "correct": ["Microsoft Active Directory Federation Services (AD FS)", "Okta"], "explanation": "For federated authentication using the SAML_IDENTITY_PROVIDER parameter in Snowflake, valid identity provider type values include Microsoft Active Directory Federation Services (AD FS) and Okta. These providers support the SAML 2.0 protocol, which Snowflake uses for federated authentication.", "reference": "https://docs.snowflake.com/en/user-guide/admin-security-fed-auth-use.html#setting-up-federated-authentication"}, {"id": 595, "area": "Data Protection and Data Sharing", "question": "A Snowflake user wants to share data using my_share with account xy12345. Which command should be used?", "options": ["A) grant usage on share my_share to account xy12345;", "B) grant select on share my_share to account xy12345;", "C) alter share my_share add accounts = xy12345;", "D) alter account xy12345 add share my_share;"], "chooseN": 1, "correct": ["alter share my_share add accounts = xy12345;"], "explanation": "To share data using 'my_share' with another account (xy12345) in Snowflake, the command 'alter share my_share add accounts = xy12345;' should be used. This command adds the specified account to the share, granting them access to the shared data.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/alter-share.html"}, {"id": 596, "area": "Account Access and Security", "question": "What role is required to use Partner Connect?", "options": ["A) ACCOUNTADMIN", "B) ORGADMIN", "C) SECURITYADMIN", "D) SYSADMIN"], "chooseN": 1, "correct": ["ACCOUNTADMIN"], "explanation": "To use Partner Connect in Snowflake, the 'ACCOUNTADMIN' role is required. This role has the necessary privileges to set up and manage integrations with Snowflake's partners through Partner Connect.", "reference": "https://docs.snowflake.com/en/user-guide/ecosystem-partner-connect"}, {"id": 597, "area": "Performance Concepts", "question": "How can a Snowflake user configure a virtual warehouse to support over 100 users if their company has Enterprise Edition?", "options": ["A) Add additional warehouses and configure them as a cluster.", "B) Set the auto-scale to 100.", "C) Use a multi-cluster warehouse.", "D) Use a larger warehouse."], "chooseN": 1, "correct": ["Use a multi-cluster warehouse."], "explanation": "To support over 100 users in Snowflake's Enterprise Edition, a multi-cluster warehouse should be used. Multi-cluster warehouses enable scaling out compute resources across multiple clusters, efficiently handling high concurrency and workload demands.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-multicluster.html"}, {"id": 598, "area": "Snowflake Data Cloud Features & Architecture", "question": "How is table data compressed in Snowflake?", "options": ["A) Each column is compressed as it is stored in a micro-partition.", "B) Each micro-partition is compressed as it is written into cloud storage using GZIP.", "C) The micro-partitions are stored in compressed cloud storage and the cloud storage handles compression.", "D) The text data in a micro-partition is compressed with GZIP but other types are not compressed."], "chooseN": 1, "correct": ["Each column is compressed as it is stored in a micro-partition."], "explanation": "In Snowflake, table data is compressed by storing each column in a micro-partition with its own specific compression algorithm. This columnar storage approach allows for efficient compression and performance, as different data types can be compressed using the most suitable algorithms.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions.html"}, {"id": 599, "area": "Data Loading and Unloading", "question": "What will be the output of the below query against the table name gold_data? select * from gold_data tablesample (100);", "options": ["A) It will return an empty sample.", "B) It will return a random 100 rows.", "C) It will return an entire table.", "D) It will produce an error message."], "chooseN": 1, "correct": ["It will return an entire table."], "explanation": "The TABLESAMPLE clause specifies that the result set should contain a random sample of data from the table. When the percentage is set to 100, the entire table is returned. According to Snowflake documentation: 'Return an entire table, including all rows in the table: SELECT * FROM testtable TABLESAMPLE (100);'. The probability parameter accepts values between 0 (no rows) and 100 (all rows) inclusive.", "reference": "https://docs.snowflake.com/en/sql-reference/constructs/sample"}, {"id": 600, "area": "Performance Concepts", "question": "A Snowflake query took 40 minutes to run. The results indicate that 'Bytes spilled to local storage' was a large number. What is the issue and how can it be resolved?", "options": ["A) The warehouse is too large. Decrease the size of the warehouse to reduce the spillage.", "B) The warehouse is too small. Increase the size of the warehouse to reduce the spillage.", "C) The Snowflake console has timed-out. Contact Snowflake Support.", "D) The warehouse consists of a single cluster. Use a multi-cluster warehouse to reduce the spillage."], "chooseN": 1, "correct": ["The warehouse is too small. Increase the size of the warehouse to reduce the spillage."], "explanation": "When 'Bytes spilled to local storage' is high, it indicates that the query required more memory than was available in the warehouse. Increasing the size of the warehouse provides more memory and compute resources, reducing the likelihood of spillage.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-considerations.html#monitoring-warehouse-performance"}, {"id": 601, "area": "Data Loading and Unloading", "question": "What is the MOST efficient way to load streaming data into Snowflake?", "options": ["A) Use the COPY command.", "B) Use Snowpipe.", "C) Use the Load Data Wizard.", "D) Use tasks and streams."], "chooseN": 1, "correct": ["Use Snowpipe."], "explanation": "Snowpipe is designed specifically for continuous, automated loading of streaming data into Snowflake. It's more efficient for this use case compared to the other methods, which are better suited for batch or manual data loading processes.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-snowpipe-intro.html"}, {"id": 602, "area": "Data Loading and Unloading", "question": "Which COPY INTO statement accurately describes how to unload data from a Snowflake table? file can be compressed.", "options": ["A) The default value for the SINGLE option is set to TRUE.", "B) By default, COPY INTO statements do not separate table data into a set of output files.", "C) The OBJECT_CONSTRUCT function can be combined with the COPY command to convert the rows in a relational table to a single VARIANT column.", "D) If the COMPRESSION option is set to TRUE, a file's name can be specified with the appropriate file extension so that the output"], "chooseN": 1, "correct": ["The OBJECT_CONSTRUCT function can be combined with the COPY command to convert the rows in a relational table to a single VARIANT column."], "explanation": "The correct answer is: The OBJECT_CONSTRUCT function can be combined with the COPY command to convert the rows in a relational table to a single VARIANT column.. The docs state the default for SINGLE is FALSE (data IS separated into multiple output files), contradicting answer A. The docs confirm OBJECT_CONSTRUCT can be used with COPY to convert rows to VARIANT. Correct answer is C. Reference: https://docs.snowflake.com/en/user-guide/data-unload-considerations", "reference": "https://docs.snowflake.com/en/sql-reference/functions/object_construct.html"}, {"id": 603, "area": "Data Loading and Unloading", "question": "What command is used to download data from a Snowflake stage?", "options": ["A) PUT", "B) INSERT", "C) GET", "D) COPY"], "chooseN": 1, "correct": ["GET"], "explanation": "The GET command in Snowflake is used to download data from a stage to a local file system. It's the opposite of the PUT command, which uploads data files to a Snowflake stage.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/get.html"}, {"id": 604, "area": "Account Access and Security", "question": "By default, which role has privileges to create tables and views in an account?", "options": ["A) PUBLIC", "B) SECURITYADMIN", "C) SYSADMIN", "D) USERADMIN"], "chooseN": 1, "correct": ["SYSADMIN"], "explanation": "By default, the SYSADMIN role in Snowflake has privileges to create tables and views in an account. This role is designed to perform system administrative tasks, including the management of databases, schemas, and warehouses.", "reference": "https://docs.snowflake.com/en/user-guide/admin-user-management.html"}, {"id": 605, "area": "Data Protection and Data Sharing", "question": "What does Snowflake recommend as a best practice for using secure views?", "options": ["A) Use sequence-generated values.", "B) Programmatically reveal the identifiers.", "C) Use secure views solely for query convenience.", "D) Do not expose the sequence-generated column(s)."], "chooseN": 1, "correct": ["Do not expose the sequence-generated column(s)."], "explanation": "As a best practice for using secure views, Snowflake recommends not exposing sequence-generated columns. This helps in maintaining the security and integrity of the data, especially when the views are used for data sharing or accessed by external users.", "reference": "https://docs.snowflake.com/en/user-guide/views-secure.html"}, {"id": 606, "area": "Data Protection and Data Sharing", "question": "What is the Fail-safe period for a transient table in the Snowflake Enterprise edition and higher?", "options": ["A) 0 days", "B) 1 day", "C) 7 days", "D) 14 days"], "chooseN": 1, "correct": ["0 days"], "explanation": "Transient tables are similar to permanent tables with the key difference that they do not have a Fail-safe period", "reference": "https://docs.snowflake.com/en/user-guide/tables-temp-transient#fail-safe"}, {"id": 607, "area": "Account Access and Security", "question": "How does a Snowflake user enable Multi-Factor Authentication (MFA)?", "options": ["A) The user must enroll themselves through the web interface.", "B) The user must submit their encrypted private key to Snowflake.", "C) The user must sign up with Duo Mobile for approval to use the service.", "D) The user must configure Snowflake to use Single Sign-On (SSO)."], "chooseN": 1, "correct": ["The user must enroll themselves through the web interface."], "explanation": "To enable Multi-Factor Authentication (MFA) in Snowflake, a user must enroll themselves through the web interface. This process includes setting up an authenticator app or device that generates a time-based, one-time password (TOTP) as an additional security layer.", "reference": "https://docs.snowflake.com/en/user-guide/security-mfa.html"}, {"id": 608, "area": "Performance Concepts", "question": "What allows a user to limit the number of credits consumed within a Snowflake account?", "options": ["A) Tracking account usage", "B) Creating resource monitors", "C) Automatic virtual warehouse scaling", "D) Automatic clustering"], "chooseN": 1, "correct": ["Creating resource monitors"], "explanation": "Creating resource monitors in Snowflake allows a user to limit the number of credits consumed within an account. Resource monitors can be set to trigger alerts or take actions when usage limits are approached or exceeded, helping to control costs and usage.", "reference": "https://docs.snowflake.com/en/user-guide/resource-monitors.html"}, {"id": 609, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which statement accurately describes Snowflake's architecture?", "options": ["A) It uses a local data repository for all compute nodes in the platform.", "B) It is a blend of shared-disk and shared-everything database architectures.", "C) It is a hybrid of traditional shared-disk and shared-nothing database architectures.", "D) It reorganizes loaded data into internal optimized, compressed, and row-based format."], "chooseN": 1, "correct": ["It is a hybrid of traditional shared-disk and shared-nothing database architectures."], "explanation": "Snowflake's architecture is a unique hybrid that combines the traditional shared-disk and shared-nothing database architectures. It separates compute and storage, allowing for scalable performance and storage capacity.", "reference": "https://docs.snowflake.com/en/user-guide/intro-key-concepts.html"}, {"id": 610, "area": "Data Loading and Unloading", "question": "Which Snowflake SQL command is used to get a subset of rows randomly from a table?", "options": ["A) GENERATOR", "B) LATERAL", "C) PIVOT", "D) SAMPLE"], "chooseN": 1, "correct": ["SAMPLE"], "explanation": "The SAMPLE command in Snowflake SQL is used to randomly select a subset of rows from a table. This is useful for creating samples of data for testing or analysis purposes.", "reference": "https://docs.snowflake.com/en/sql-reference/constructs/sample.html"}, {"id": 611, "area": "Performance Concepts", "question": "Which statement accurately describes how a virtual warehouse functions?", "options": ["A) Increasing the size of a virtual warehouse will always improve data loading performance.", "B) Each virtual warehouse is an independent compute cluster that shares compute resources with other warehouses.", "C) Each virtual warehouse is a compute cluster composed of multiple compute nodes allocated by Snowflake from a cloud provider.", "D) All virtual warehouses share the same compute resources so performance degradation of one warehouse can significantly affect all the other warehouses."], "chooseN": 1, "correct": ["Each virtual warehouse is a compute cluster composed of multiple compute nodes allocated by Snowflake from a cloud provider."], "explanation": "In Snowflake, each virtual warehouse is an independent compute cluster, composed of multiple compute nodes allocated from a cloud provider. These warehouses do not share compute resources, ensuring isolated workload performance.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-overview.html"}, {"id": 612, "area": "Data Transformations", "question": "Which Snowflake object can be used to record DML changes made to a table?", "options": ["A) Snowpipe", "B) Stage", "C) Stream", "D) Task"], "chooseN": 1, "correct": ["Stream"], "explanation": "A Stream in Snowflake is used to track DML changes (inserts, updates, deletes) made to a table. This allows for capturing and processing incremental changes efficiently.", "reference": "https://docs.snowflake.com/en/user-guide/streams.html"}, {"id": 613, "area": "Data Loading and Unloading", "question": "Which statistic displayed in a Query Profile is specific to external functions?", "options": ["A) Bytes written", "B) Total invocations", "C) Partitions scanned", "D) Bytes sent over the network"], "chooseN": 1, "correct": ["Total invocations"], "explanation": "In the context of Snowflake's Query Profile for external functions, 'Total invocations' is a statistic that specifically refers to the number of times an external function is called during the execution of a query.", "reference": "https://docs.snowflake.com/en/user-guide/ui-query-profile"}, {"id": 614, "area": "Performance Concepts", "question": "If there is queueing in the virtual warehouse load monitoring chart, what should a Snowflake user do?", "options": ["A) Decrease the warehouse size.", "B) Decrease the MIN_CLUSTER_COUNT parameter.", "C) Change the multi-cluster settings to add additional clusters.", "D) Start a separate warehouse and move queued queries there."], "chooseN": 1, "correct": ["Start a separate warehouse and move queued queries there."], "explanation": "If the running query load is high or there’s queuing, consider starting a separate warehouse and moving queued queries to that warehouse. Alternatively, if you are using multi-cluster warehouses, you could change your multi-cluster settings to add additional clusters to handle higher concurrency going forward.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-load-monitoring"}, {"id": 615, "area": "Data Transformations", "question": "Which command is used to generate a zero-copy 'snapshot' of any table, schema, or database?", "options": ["A) ALTER", "B) CREATE ... CLONE", "C) COPY INTO", "D) CREATE REPLICATION GROUP"], "chooseN": 1, "correct": ["CREATE ... CLONE"], "explanation": "The 'CREATE ... CLONE' command is used in Snowflake to generate a zero-copy 'snapshot' of any table, schema, or database. This command allows users to make full copies of existing objects without the additional storage costs associated with traditional data duplication.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/create-clone.html"}, {"id": 616, "area": "Data Loading and Unloading", "question": "How long is the load history stored in the metadata of the pipe in Snowpipe?", "options": ["A) 2 days", "B) 7 days", "C) 14 days", "D) 64 days"], "chooseN": 1, "correct": ["14 days"], "explanation": "In Snowpipe, the load history is stored in the metadata of the pipe for 14 days. This allows users to track and manage the data loading process over two week-long period.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-snowpipe-intro"}, {"id": 617, "area": "Snowflake Data Cloud Features & Architecture", "question": "What are the key characteristics of ACCOUNT_USAGE views? (Choose two.)", "options": ["A) There is no data latency.", "B) The data latency can vary from 45 minutes to 3 hours.", "C) The historical data is not retained.", "D) The historical data can be retained from 7 days to 6 months.", "E) Records for dropped objects are included in each view."], "chooseN": 2, "correct": ["The data latency can vary from 45 minutes to 3 hours.", "Records for dropped objects are included in each view."], "explanation": "The key characteristics of ACCOUNT_USAGE views in Snowflake include data latency that can vary from 45 minutes to 3 hours and records for dropped objects are included in each view. These views provide insights into account usage and activity but are not real-time due to the inherent latency.", "reference": "https://docs.snowflake.com/en/sql-reference/account-usage#differences-between-account-usage-and-information-schema"}, {"id": 618, "area": "Data Protection and Data Sharing", "question": "How does a scoped URL expire?", "options": ["A) When the data cache clears.", "B) When the persisted query result period ends.", "C) The encoded URL access is permanent.", "D) The length of time is specified in the expiration_time argument."], "chooseN": 1, "correct": ["When the persisted query result period ends."], "explanation": "A scoped URL expires when the persisted query result period ends, which is currently 24 hours. The Snowflake docs for BUILD_SCOPED_FILE_URL state the scoped URL 'is valid for the caller until the persisted query result period ends.' (A) is incorrect because scoped URLs are not tied to data cache clearing. (C) is incorrect because scoped URLs are NOT permanent -- they expire after 24 hours. (D) is incorrect because the expiration_time argument exists for presigned URLs (GET_PRESIGNED_URL), not scoped URLs.", "reference": "https://docs.snowflake.com/en/user-guide/unstructured-intro"}, {"id": 619, "area": "Performance Concepts", "question": "What are the available Snowflake scaling modes for configuring multi-cluster virtual warehouses? (Choose two.)", "options": ["A) Auto-Scale", "B) Economy", "C) Maximized", "D) Scale-Out", "E) Standard"], "chooseN": 2, "correct": ["Auto-Scale", "Maximized"], "explanation": "Snowflake provides different scaling modes for multi-cluster virtual warehouses. 'Auto-Scale' allows automatic adjustment based on the workload, and 'Maximized' is designed to provide maximum compute resources for the most demanding workloads.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-multicluster.html"}, {"id": 620, "area": "Data Transformations", "question": "Which loop type iterates until a condition is true?", "options": ["A) FOR", "B) LOOP", "C) REPEAT", "D) WHILE"], "chooseN": 1, "correct": ["REPEAT"], "explanation": "A REPEAT loop iterates until a condition is true. In a REPEAT loop, the condition is tested immediately after executing the body of the loop. As a result, the body of the loop always executes at least once.", "reference": "https://docs.snowflake.com/en/developer-guide/snowflake-scripting/loops"}, {"id": 621, "area": "Performance Concepts", "question": "Which property needs to be added to the ALTER WAREHOUSE command to verify the additional compute resources for a virtual warehouse have been fully provisioned?", "options": ["A) QUERY_ACCELERATION_MAX_SCALE_FACTOR", "B) RESOURCE_MONITOR", "C) SCALING_POLICY", "D) WAIT_FOR_COMPLETION"], "chooseN": 1, "correct": ["WAIT_FOR_COMPLETION"], "explanation": "The 'WAIT_FOR_COMPLETION' option in the ALTER WAREHOUSE command ensures that the command waits until the additional compute resources for a virtual warehouse are fully provisioned before it returns control to the user.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/alter-warehouse.html"}, {"id": 622, "area": "Account Access and Security", "question": "How is enhanced authentication achieved in Snowflake? (Choose two.)", "options": ["A) Snowflake-managed keys", "B) Object level access control", "C) Multi-Factor Authentication (MFA)", "D) Federated authentication and Single Sign-On (SSO)"], "chooseN": 2, "correct": ["Multi-Factor Authentication (MFA)", "Federated authentication and Single Sign-On (SSO)"], "explanation": "Enhanced authentication in Snowflake can be achieved through Multi-Factor Authentication (MFA), which adds an extra layer of security, and Federated authentication with Single Sign-On (SSO), which streamlines the login process while enhancing security.", "reference": "https://docs.snowflake.com/en/user-guide/admin-security-fed-auth-use.html"}, {"id": 623, "area": "Data Loading and Unloading", "question": "What are the native data types that Snowflake provides to store semi-structured data? (Choose two.)", "options": ["A) ARRAY", "B) JSON", "C) ORC", "D) Parquet", "E) VARIANT"], "chooseN": 2, "correct": ["ARRAY", "VARIANT"], "explanation": "A Snowflake ARRAY is similar to an array in many other programming languages (an ARRAY contains 0 or more pieces of data, and each element is accessed by specifying its position in the array). A VARIANT can store a value of any other type, including OBJECT and ARRAY.", "reference": "https://docs.snowflake.com/en/sql-reference/data-types-semistructured"}, {"id": 624, "area": "Data Protection and Data Sharing", "question": "How long is the Fail-safe period for recovering historical data from permanent tables?", "options": ["A) 1 day", "B) 3 days", "C) 7 days", "D) 14 days"], "chooseN": 1, "correct": ["7 days"], "explanation": "The Fail-safe period for recovering historical data from permanent tables in Snowflake is 7 days. During this period, Snowflake retains the data even after it is no longer accessible through Time Travel, providing an additional layer of data protection.", "reference": "https://docs.snowflake.com/en/user-guide/data-failsafe"}, {"id": 625, "area": "Performance Concepts", "question": "What does the average_overlaps in the output of SYSTEM$CLUSTERING_INFORMATION refer to?", "options": ["A) The average number of micro-partitions stored in Time Travel.", "B) The average number of partitions physically stored in the same location.", "C) The average number of micro-partitions which contain overlapping value ranges.", "D) The average number of micro-partitions in the table associated with cloned objects."], "chooseN": 1, "correct": ["The average number of micro-partitions which contain overlapping value ranges."], "explanation": "In the output of SYSTEM$CLUSTERING_INFORMATION, the average_overlaps refers to the average number of micro-partitions which contain overlapping value ranges. This metric helps in understanding the clustering of data and the efficiency of micro-partitions in terms of data storage and retrieval.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/system_clustering_information.html"}, {"id": 626, "area": "Performance Concepts", "question": "If queries start to queue in a multi-cluster virtual warehouse, an additional compute cluster starts immediately under what setting?", "options": ["A) Auto-scale mode", "B) Maximized mode", "C) Economy scaling policy", "D) Standard scaling policy"], "chooseN": 1, "correct": ["Standard scaling policy"], "explanation": "In a multi-cluster virtual warehouse, the Standard scaling policy starts an additional cluster immediately when queries begin to queue. This policy favors starting additional clusters to minimize queuing over conserving credits. The Economy scaling policy favors conserving credits and starts additional clusters only after more conservative evaluation. Auto-scale mode is the warehouse operating mode (not a scaling policy), and Maximized mode keeps all clusters running at all times.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-multicluster.html"}, {"id": 627, "area": "Data Loading and Unloading", "question": "When floating-point number columns are unloaded to CSV or JSON files, Snowflake truncates the values to approximately what? A. (12,2) B. (10,4) C. (14,8) D. (15,9)", "options": ["A) (12,2)", "B) (10,4)", "C) (14,8)", "D) (15,9)"], "chooseN": 1, "correct": ["(15,9)"], "explanation": "When unloading floating-point number columns to CSV or JSON files, Snowflake truncates the values to approximately (15,9), which means 15 digits in total with 9 digits after the decimal point. This ensures a balance between accuracy and storage efficiency.", "reference": "https://docs.snowflake.com/en/user-guide/data-unload-considerations#floating-point-numbers-truncated"}, {"id": 628, "area": "Data Protection and Data Sharing", "question": "By definition, a secure view is exposed only to users with what privilege?", "options": ["A) IMPORT SHARE", "B) OWNERSHIP", "C) REFERENCES", "D) USAGE"], "chooseN": 1, "correct": ["OWNERSHIP"], "explanation": "By definition, a secure view in Snowflake is exposed only to users with the 'OWNERSHIP' privilege. This privilege is necessary to ensure that only authorized users with the appropriate level of access can view or manipulate the data in the secure view.", "reference": "https://docs.snowflake.com/en/user-guide/views-secure.html"}, {"id": 629, "area": "Account Access and Security", "question": "What happens when a user exits Snowsight during a session that a query is running?", "options": ["A) Snowflake executes the query during the same session immediately.", "B) Snowflake cancels any queries submitted during this session that are still running.", "C) Snowflake will cancel any queries submitted during this session after 24 hours.", "D) Snowflake will continue to execute and complete upon the next login."], "chooseN": 1, "correct": ["Snowflake will continue to execute and complete upon the next login."], "explanation": "DUDOSA!!! Active queries are not canceled when the session ends and the user is logged out, even if the ABORT_DETACHED_QUERY parameter is set to true.", "reference": "https://docs.snowflake.com/en/user-guide/session-policies#snowsight-sessions"}, {"id": 630, "area": "Data Loading and Unloading", "question": "Which native data types are used for storing semi-structured data in Snowflake? (Choose two.)", "options": ["A) NUMBER", "B) OBJECT", "C) STRING", "D) VARCHAR", "E) VARIANT"], "chooseN": 2, "correct": ["OBJECT", "VARIANT"], "explanation": "In Snowflake, the native data types used for storing semi-structured data are OBJECT and VARIANT. VARIANT is particularly versatile, capable of storing different types of semi-structured data like JSON, XML, Avro, etc.", "reference": "https://docs.snowflake.com/en/sql-reference/data-types-semistructured"}, {"id": 631, "area": "Data Loading and Unloading", "question": "Which columns are available in the output of a Snowflake directory table? (Choose two.)", "options": ["A) CATALOG_NAME", "B) FILE_NAME", "C) LAST_MODIFIED", "D) RELATIVE_PATH", "E) STAGE_NAME"], "chooseN": 2, "correct": ["LAST_MODIFIED", "RELATIVE_PATH"], "explanation": "The output of a Snowflake directory table includes these columns: RELATIVE_PATH, SIZE, LAST_MODIFIED, MD5, ETAG, and FILE_URL. FILE_NAME is not a column in directory tables. LAST_MODIFIED provides the timestamp of the last file modification, and RELATIVE_PATH provides the path to access the file relative to the stage.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-dirtables-query#output"}, {"id": 632, "area": "Account Access and Security", "question": "What is used to diagnose and troubleshoot network connections to Snowflake?", "options": ["A) SnowCD", "B) Snowpark", "C) Snowsight", "D) SnowSQL"], "chooseN": 1, "correct": ["SnowCD"], "explanation": "SnowCD is a tool provided by Snowflake to diagnose and troubleshoot network connections. It helps in identifying potential connectivity issues between a client and Snowflake's services.", "reference": "https://docs.snowflake.com/en/user-guide/snowcd"}, {"id": 633, "area": "Data Transformations", "question": "What Snowflake object records Data Manipulation Language (DML) changes so that actions can be taken using the changed data?", "options": ["A) Pipe", "B) Stream", "C) Task", "D) View"], "chooseN": 1, "correct": ["Stream"], "explanation": "A Stream in Snowflake is an object that records DML changes, such as INSERT, UPDATE, and DELETE operations, on tables. This allows users to take action on the changed data efficiently.", "reference": "https://docs.snowflake.com/en/user-guide/streams.html"}, {"id": 634, "area": "Data Loading and Unloading", "question": "By default, the COPY INTO statement will separate table data into a set of output files to take advantage of which Snowflake feature?", "options": ["A) Query acceleration", "B) Query plan caching", "C) Parallel processing", "D) Time Travel"], "chooseN": 1, "correct": ["Parallel processing"], "explanation": "By default, the COPY INTO statement in Snowflake separates table data into a set of output files to take advantage of parallel processing. This feature allows Snowflake to distribute and process data across multiple compute nodes simultaneously, enhancing performance and efficiency.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-location"}, {"id": 635, "area": "Account Access and Security", "question": "Which command allows you to view the allowed and blocked IP list of a network policy?", "options": ["A) ALTER NETWORK POLICY", "B) CREATE NETWORK POLICY", "C) DESCRIBE NETWORK POLICY", "D) SHOW NETWORK POLICIES"], "chooseN": 1, "correct": ["DESCRIBE NETWORK POLICY"], "explanation": "- DESCRIBE NETWORK POLICY: Este comando en Snowflake permite ver la lista de IPs permitidas y bloqueadas de una política de red, proporcionando información detallada sobre la política.\n- ALTER NETWORK POLICY: Este comando solo permite modificar una política de red existente, pero no ofrece detalles sobre las IPs.\n- CREATE NETWORK POLICY: Utilizado para crear una nueva política de red, no para ver las IPs asociadas a una ya existente.\n- SHOW NETWORK POLICIES: Este comando muestra un listado de todas las políticas de red, pero no proporciona detalles específicos sobre las IPs permitidas o bloqueadas.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/describe-network-policy.html"}, {"id": 636, "area": "Data Loading and Unloading", "question": "Which file functions are non-deterministic? (Choose two.)", "options": ["A) BUILD_SCOPED_FILE_URL", "B) BUILD_STAGE_FILE_URL", "C) GET_ABSOLUTE_PATH", "D) GET_PRESIGNED_URL", "E) GET_RELATIVE_PATH"], "chooseN": 2, "correct": ["BUILD_SCOPED_FILE_URL", "GET_PRESIGNED_URL"], "explanation": "The 'BUILD_SCOPED_FILE_URL' and 'GET_PRESIGNED_URL' functions in Snowflake are non-deterministic. These functions generate URLs that are unique each time they are called, and their output cannot be predicted based on the input alone.", "reference": "https://docs.snowflake.com/en/sql-reference/functions-file#usage-notes"}, {"id": 637, "area": "Performance Concepts", "question": "How can a Snowflake user optimize query performance in Snowflake? (Choose two.)", "options": ["A) Create a view.", "B) Cluster a table.", "C) Enable the search optimization service.", "D) Enable Time Travel.", "E) Index a table."], "chooseN": 2, "correct": ["Cluster a table.", "Enable the search optimization service."], "explanation": "To optimize query performance in Snowflake, a user can cluster a table and enable the search optimization service. Clustering improves the efficiency of data retrieval, while the search optimization service enhances the performance of selective queries on large tables.", "reference": "https://docs.snowflake.com/en/user-guide/search-optimization-service#other-options-for-optimizing-query-performance"}, {"id": 638, "area": "Account Access and Security", "question": "What is the MINIMUM role required to set the value for the parameter ENABLE_ACCOUNT_DATABASE_REPLICATION?", "options": ["A) ACCOUNTADMIN", "B) SECURITYADMIN", "C) SYSADMIN", "D) ORGADMIN"], "chooseN": 1, "correct": ["ORGADMIN"], "explanation": "The minimum role required to set the value for the parameter ENABLE_ACCOUNT_DATABASE_REPLICATION in Snowflake is 'ORGADMIN'. This role has the necessary privileges to manage and configure account-level settings, including database replication.", "reference": "https://docs.snowflake.com/en/user-guide/account-replication-config#prerequisite-enable-replication-for-accounts-in-the-organization"}, {"id": 639, "area": "Data Loading and Unloading", "question": "Which file format will keep floating-point numbers from being truncated when data is unloaded?", "options": ["A) CSV", "B) JSON", "C) ORC", "D) Parquet"], "chooseN": 1, "correct": ["Parquet"], "explanation": "Parquet file format is efficient in handling floating-point numbers without truncation when unloading data from Snowflake. It preserves the precision and scale of the data.", "reference": "https://docs.snowflake.com/en/user-guide/data-unload-considerations.html#floating-point-considerations"}, {"id": 640, "area": "Data Loading and Unloading", "question": "A user has semi-structured data to load into Snowflake but is not sure what types of operations will need to be performed on the data. Based on this situation, what type of column does Snowflake recommend be used?", "options": ["A) ARRAY", "B) OBJECT", "C) TEXT", "D) VARIANT"], "chooseN": 1, "correct": ["VARIANT"], "explanation": "For semi-structured data where the operations on the data are not yet defined, Snowflake recommends using a VARIANT column. This data type can handle a variety of semi-structured data formats efficiently.", "reference": "https://docs.snowflake.com/en/user-guide/semistructured-considerations#storing-semi-structured-data-in-a-variant-column-vs-flattening-the-nested-structure"}, {"id": 641, "area": "Performance Concepts", "question": "Which Snowflake object helps evaluate virtual warehouse performance impacted by query queuing?", "options": ["A) Resource monitor", "B) Account_usage.query_history", "C) Information_schema.warehouse_load_history", "D) Information_schema.warehouse_metering_history"], "chooseN": 1, "correct": ["Information_schema.warehouse_load_history"], "explanation": "- Information_schema.warehouse_load_history: Esta vista del sistema proporciona información específica sobre el uso del warehouse virtual, incluyendo los tiempos de espera de las consultas en la cola. Esto permite evaluar el impacto de la cola de consultas en el rendimiento del warehouse.\n- Account_usage.query_history: Aunque mantiene un registro de todas las consultas ejecutadas en Snowflake y permite analizar su rendimiento, no proporciona información específica sobre el impacto de la cola de consultas en el warehouse.\n- Resource monitor: Es una herramienta que rastrea el uso de recursos, pero no está enfocada en el rendimiento del warehouse o las colas de consultas.\n- Information_schema.warehouse_metering_history: Proporciona datos de uso de warehouse, pero no está enfocada en las colas de consultas.", "reference": "https://docs.snowflake.com/en/sql-reference/info-schema/warehouse_load_history.html"}, {"id": 642, "area": "Data Protection and Data Sharing", "question": "Which Snowflake object can be created to be temporary?", "options": ["A) Role", "B) Stage", "C) User", "D) Storage integration"], "chooseN": 1, "correct": ["Stage"], "explanation": "In Snowflake, a Stage object can be created as a temporary stage. This means it exists only for the duration of the user session and is automatically dropped when the session ends.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/create-stage.html"}, {"id": 643, "area": "Data Transformations", "question": "Which stream type can be used for tracking the records in external tables?", "options": ["A) Append-only", "B) External", "C) Insert-only", "D) Standard"], "chooseN": 1, "correct": ["Insert-only"], "explanation": "For tracking changes in external tables in Snowflake, the 'Insert-only' stream type is used. This type of stream is specifically designed to monitor and capture data changes in external tables.", "reference": "https://docs.snowflake.com/en/user-guide/streams-intro#types-of-streams"}, {"id": 644, "area": "Data Loading and Unloading", "question": "What is the recommended approach for unloading data to a cloud storage location from Snowflake?", "options": ["A) Use a third-party tool to unload the data to cloud storage.", "B) Unload the data directly to the cloud storage location.", "C) Unload the data to a local file system, then upload it to cloud storage.", "D) Unload the data to a user stage, then upload the data to cloud storage"], "chooseN": 1, "correct": ["Unload the data directly to the cloud storage location."], "explanation": "The recommended approach for unloading data from Snowflake to a cloud storage location is to unload the data directly to the cloud storage location. This method is efficient and leverages Snowflake's native support for cloud storage integration.", "reference": "https://docs.snowflake.com/en/user-guide/data-unload-overview.html"}, {"id": 645, "area": "Data Loading and Unloading", "question": "Which command is used to unload files from an internal or external stage to a local file system?", "options": ["A) COPY INTO", "B) GET", "C) PUT", "D) TRANSFER"], "chooseN": 1, "correct": ["GET"], "explanation": "The 'GET' command is used in Snowflake to unload files from an internal or external stage to a local file system. This command facilitates the retrieval of files from Snowflake stages to the local environment.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/get.html"}, {"id": 646, "area": "Data Transformations", "question": "A tabular User-Defined Function (UDF) is defined by specifying a return clause that contains which keyword?", "options": ["A) ROW_NUMBER", "B) TABLE", "C) TABULAR", "D) VALUES"], "chooseN": 1, "correct": ["TABLE"], "explanation": "In Snowflake, a tabular User-Defined Function (UDF) is defined by specifying a return clause that contains the keyword 'TABLE'. This keyword indicates that the UDF will return a set of rows as a table.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/create-function#required-parameters"}, {"id": 647, "area": "Performance Concepts", "question": "Which SQL statement will require a virtual warehouse to run?", "options": ["A) SELECT COUNT(*) FROM TBL_EMPLOYEE;", "B) ALTER TABLE TBL_EMPLOYEE ADD COLUMN EMP_REGION VARCHAR(20);", "C) INSERT INTO TBL_EMPLOYEE(EMP_ID, EMP_NAME, EMP_SALARY, DEPT) VALUES(1, 'Adam', 20000, 'Finance');", "D) CREATE OR REPLACE TABLE TBL_EMPLOYEE (EMP_ID NUMBER, EMP_NAME VARCHAR(30), EMP_SALARY NUMBER, DEPT VARCHAR(20));"], "chooseN": 1, "correct": ["INSERT INTO TBL_EMPLOYEE(EMP_ID, EMP_NAME, EMP_SALARY, DEPT) VALUES(1, 'Adam', 20000, 'Finance');"], "explanation": "- INSERT INTO TBL_EMPLOYEE...: Cualquier operación DML (como un INSERT) requiere que un virtual warehouse esté activo para mover los datos desde la capa de cloud hacia la capa de almacenamiento en Snowflake.\n- SELECT COUNT(*): Esta consulta simplemente extrae metadatos, que pueden ser recuperados sin usar un warehouse activo.\n- ALTER TABLE: Esta operación cambia la estructura de la tabla, pero no requiere el uso de un warehouse para ejecutarse.\n- CREATE OR REPLACE TABLE: La creación de tablas no necesita computación por parte de un warehouse.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses.html"}, {"id": 648, "area": "Data Loading and Unloading", "question": "Which REST API can be used with unstructured data?", "options": ["A) insertFiles", "B) insertReport", "C) GET /api/files/", "D) loadHistoryScan"], "chooseN": 1, "correct": ["GET /api/files/"], "explanation": "The REST API 'GET /api/files/' can be used with unstructured data in Snowflake. This API endpoint allows users to interact with files stored in Snowflake, including various types of unstructured data.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-unstructured-rest-api"}, {"id": 649, "area": "Data Loading and Unloading", "question": "Which query contains a Snowflake hosted file URL in a directory table for a stage named bronzestage?", "options": ["A) list @bronzestage;", "B) select * from directory(@bronzestage);", "C) select metadata$filename from @bronzestage;", "D) select * from table(information_schema.stage_directory_file_registration_history( stage_name=>'bronzestage'));"], "chooseN": 1, "correct": ["select * from directory(@bronzestage);"], "explanation": "The query 'select * from directory(@bronzestage);' retrieves the file URLs hosted in a directory table for a stage named 'bronzestage' in Snowflake. It lists the details of files stored in the specified stage.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-dirtables-query"}, {"id": 650, "area": "Account Access and Security", "question": "Which feature is integrated to support Multi-Factor Authentication (MFA) at Snowflake?", "options": ["A) Authy", "B) Duo Security", "C) One Login", "D) RSA SecurID Access"], "chooseN": 1, "correct": ["Duo Security"], "explanation": "Duo Security is integrated with Snowflake to support Multi-Factor Authentication (MFA). It provides an additional layer of security by requiring two or more verification methods for user authentication.", "reference": "https://docs.snowflake.com/en/user-guide/security-mfa"}, {"id": 651, "area": "Snowflake Data Cloud Features & Architecture", "question": "In which Snowflake layer does Snowflake reorganize data into its internal optimized, compressed, columnar format?", "options": ["A) Cloud Services", "B) Database Storage", "C) Query Processing", "D) Metadata Management"], "chooseN": 1, "correct": ["Database Storage"], "explanation": "Snowflake reorganizes data into its internal optimized, compressed, columnar format in the Database Storage layer. This layer is responsible for the efficient storage and retrieval of structured and semi-structured data.", "reference": "https://docs.snowflake.com/en/user-guide/intro-key-concepts#database-storage"}, {"id": 652, "area": "Data Transformations", "question": "When can user session variables be accessed in a Snowflake scripting procedure?", "options": ["A) When the procedure is defined as STRICT.", "B) When the procedure is defined to execute as CALLER.", "C) When the procedure is defined to execute as OWNER.", "D) When the procedure is defined with an argument that has the same name and type as the session variable."], "chooseN": 1, "correct": ["When the procedure is defined to execute as CALLER."], "explanation": "User session variables in a Snowflake scripting procedure can be accessed when the procedure is defined to execute as CALLER. This means the procedure executes with the privileges and session settings of the user who calls it.", "reference": "https://docs.snowflake.com/en/developer-guide/stored-procedure/stored-procedures-rights"}, {"id": 653, "area": "Data Transformations", "question": "What computer language can be selected when creating User-Defined Functions (UDFs) using the Snowpark API?", "options": ["A) Swift", "B) JavaScript", "C) Python", "D) SQL"], "chooseN": 1, "correct": ["Python"], "explanation": "When creating User-Defined Functions (UDFs) using the Snowpark API, Python is one of the supported languages. Snowpark enables developers to use Python to create and execute UDFs within the Snowflake environment.", "reference": "https://docs.snowflake.com/en/developer-guide/snowpark/index.html"}, {"id": 654, "area": "Data Loading and Unloading", "question": "A user needs to ingest 1 GB of data that is available in an external stage using a COPY INTO command. How can this be done with MAXIMUM performance and the LEAST cost?", "options": ["A) Ingest the data in a compressed format as a single file.", "B) Ingest the data in an uncompressed format as a single file.", "C) Split the file into smaller files of 100-250 MB each, compress and ingest each of the smaller files.", "D) Split the file into smaller files of 100-250 MB each and ingest each of the smaller files in an uncompressed format."], "chooseN": 1, "correct": ["Split the file into smaller files of 100-250 MB each, compress and ingest each of the smaller files."], "explanation": "To achieve maximum performance and least cost when ingesting 1 GB of data in Snowflake, it is recommended to split the file into smaller files of 100-250 MB each, compress them, and then ingest each of the smaller files. This approach takes advantage of parallel processing and reduces storage and compute costs due to compression.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-considerations-prepare.html"}, {"id": 655, "area": "Data Transformations", "question": "A Snowflake user has two tables that contain numeric values and is trying to find out which values are present in both tables. Which set operator should be used?", "options": ["A) INTERSECT", "B) MERGE", "C) MINUS", "D) UNION"], "chooseN": 1, "correct": ["INTERSECT"], "explanation": "The 'INTERSECT' set operator should be used to find out which values are present in both tables. This operator returns only those records that are common to both tables, effectively finding the intersection of the two sets of data.", "reference": "https://docs.snowflake.com/en/sql-reference/operators-query.html#intersect"}, {"id": 656, "area": "Data Transformations", "question": "A view is defined on a permanent table. A temporary table with the same name is created in the same schema as the referenced table. What will the query from the view return?", "options": ["A) The data from the permanent table.", "B) The data from the temporary table.", "C) An error stating that the view could not be compiled.", "D) An error stating that the referenced object could not be uniquely identified."], "chooseN": 1, "correct": ["The data from the permanent table."], "explanation": "When a view is defined on a permanent table, and a temporary table with the same name is created in the same schema, the query from the view will return data from the permanent table. This is because views in Snowflake are bound to the table they were originally created on.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/create-view.html"}, {"id": 657, "area": "Data Loading and Unloading", "question": "Which file function generates a Snowflake-hosted file URL to a staged file using the stage name and relative file path as inputs?", "options": ["A) BUILD_STAGE_FILE_URL", "B) GET_ABSOLUTE_PATH", "C) GET_RELATIVE_PATH", "D) GET_STAGE_LOCATION"], "chooseN": 1, "correct": ["BUILD_STAGE_FILE_URL"], "explanation": "The 'BUILD_STAGE_FILE_URL' function in Snowflake generates a Snowflake-hosted file URL to a staged file using the stage name and relative file path as inputs. This function facilitates direct access to files in a stage via their URLs.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/build_stage_file_url.html"}, {"id": 658, "area": "Performance Concepts", "question": "Which service or feature in Snowflake is used to improve the performance of certain types of lookup and analytical queries that use an extensive set of WHERE conditions?", "options": ["A) Data classification", "B) Query acceleration service", "C) Search optimization service", "D) Tagging"], "chooseN": 1, "correct": ["Search optimization service"], "explanation": "The 'Search optimization service' in Snowflake is used to improve the performance of certain types of lookup and analytical queries, particularly those that use an extensive set of WHERE conditions. This service enhances query performance by optimizing the underlying data structure for efficient searches.", "reference": "https://docs.snowflake.com/en/user-guide/search-optimization-service.html"}, {"id": 659, "area": "Account Access and Security", "question": "What is the name of the SnowSQL file that can store connection information?", "options": ["A) history", "B) config", "C) snowsql.cnf", "D) snowsql.pubkey"], "chooseN": 1, "correct": ["config"], "explanation": "SnowSQL stores connection information in its configuration file named \"config\" (default path: ~/.snowsql/config or %USERPROFILE%\\.snowsql\\config).", "reference": "https://docs.snowflake.com/en/user-guide/snowsql-config.html"}, {"id": 660, "area": "Data Protection and Data Sharing", "question": "How do secure views compare to non-secure views in Snowflake?", "options": ["A) Secure views execute slowly compared to non-secure views.", "B) Non-secure views are preferred over secure views when sharing data.", "C) Secure views are similar to materialized views in that they are the most performant.", "D) There are no performance differences between secure and non-secure views."], "chooseN": 1, "correct": ["Secure views execute slowly compared to non-secure views."], "explanation": "The correct answer is: Secure views execute slowly compared to non-secure views.. The doc states: 'Secure views can execute more slowly than non-secure views.' and 'you should consider the trade-off between data privacy/security and query performance.' Answer D ('no performance differences') is wrong. Answer A ('Secure views execute slowly') matches the docs. Reference: https://docs.snowflake.com/en/user-guide/views-secure#when-should-i-use-a-secure-view", "reference": "https://docs.snowflake.com/en/user-guide/views-secure.html"}, {"id": 661, "area": "Data Transformations", "question": "Which type of join will list all rows in the specified table, even if those rows have no match in the other table?", "options": ["A) Cross join", "B) Inner join", "C) Natural join", "D) Outer join"], "chooseN": 1, "correct": ["Outer join"], "explanation": "An 'Outer join' in SQL, including in Snowflake, lists all rows from a specified table even if there is no match in the other table. It includes matched rows as well as unmatched rows from one or both tables.", "reference": "https://docs.snowflake.com/en/user-guide/querying-joins#types-of-joins"}, {"id": 662, "area": "Data Loading and Unloading", "question": "When unloading data to an external stage, what is the MAXIMUM file size supported?", "options": ["A) 1 GB", "B) 5 GB", "C) 10 GB", "D) 16 GB"], "chooseN": 1, "correct": ["5 GB"], "explanation": "The correct answer is: 5 GB. The COPY INTO <location> docs define MAX_FILE_SIZE with a maximum of 5368709120 (5 GB). The explanation already says 5 GB but the marked answer was C (10 GB). Correct answer is B (5 GB). Reference: https://docs.snowflake.com/en/sql-reference/sql/copy-into-location#copy-options-copyoptions", "reference": "https://docs.snowflake.com/en/user-guide/data-unload-considerations#unloading-to-a-single-file"}, {"id": 663, "area": "Data Protection and Data Sharing", "question": "How long does Snowflake retain information in the ACCESS_HISTORY view?", "options": ["A) 7 days", "B) 14 days", "C) 28 days", "D) 365 days"], "chooseN": 1, "correct": ["365 days"], "explanation": "Snowflake retains information in the ACCESS_HISTORY view for 365 days. This allows for a comprehensive audit and review of access patterns over an extended period.", "reference": "https://docs.snowflake.com/en/sql-reference/account-usage/access_history"}, {"id": 664, "area": "Data Protection and Data Sharing", "question": "Which encryption type will enable client-side encryption for a directory table?", "options": ["A) AES", "B) AWS_CSE", "C) SNOWFLAKE_SSE", "D) SNOWFLAKE_FULL"], "chooseN": 1, "correct": ["SNOWFLAKE_FULL"], "explanation": "For internal stages/directory-table-related staged files, SNOWFLAKE_FULL is the documented encryption type that enables client-side encryption (with server-side encryption as well). SNOWFLAKE_SSE is server-side only.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/create-stage#internal-stage-parameters-internalstageparams"}, {"id": 665, "area": "Data Loading and Unloading", "question": "If file format options are specified in multiple locations, the load operation selects which option FIRST to apply in order of precedence?", "options": ["A) Table definition", "B) Stage definition", "C) Session level", "D) COPY INTO TABLE statement"], "chooseN": 1, "correct": ["COPY INTO TABLE statement"], "explanation": "When file format options are specified in multiple locations, the load operation in Snowflake selects the options specified in the 'COPY INTO TABLE' statement first to apply, in order of precedence. This provides the most immediate control over the load operation.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-prepare#overriding-default-file-format-options"}, {"id": 666, "area": "Performance Concepts", "question": "A complex SQL query involving eight tables with joins is taking a while to execute. The Query Profile shows that all partitions are being scanned. What is causing the query performance issue?", "options": ["A) Pruning is not being performed efficiently.", "B) A huge volume of data is being fetched, with many joins applied.", "C) Incorrect joins are being used, leading to scanning and pulling too many records.", "D) The columns in the micro-partitions need granular ordering based on the dataset."], "chooseN": 1, "correct": ["Pruning is not being performed efficiently."], "explanation": "If a complex SQL query is taking a long time to execute and the Query Profile shows that all partitions are being scanned, the issue is likely that pruning is not being performed efficiently. Efficient pruning helps in reducing the amount of data scanned by eliminating irrelevant partitions.", "reference": "https://docs.snowflake.com/en/user-guide/ui-query-profile#inefficient-pruning"}, {"id": 667, "area": "Performance Concepts", "question": "What does Snowflake's search optimization service support?", "options": ["A) External tables", "B) Materialized views", "C) Tables and views that are not protected by row access policies", "D) Casts on table columns (except for fixed-point numbers cast to strings)"], "chooseN": 1, "correct": ["Tables and views that are not protected by row access policies"], "explanation": "Snowflake's search optimization service supports tables and views that are not protected by row access policies. This service enhances the performance of queries on these objects, especially those involving a large number of selective filters.", "reference": "https://docs.snowflake.com/en/user-guide/search-optimization/queries-that-benefit#queries-that-do-not-benefit-from-search-optimization"}, {"id": 668, "area": "Data Protection and Data Sharing", "question": "Which table type is no longer available after the close of the session and therefore has no Fail-safe or Time Travel recovery option?", "options": ["A) External", "B) Permanent", "C) Temporary", "D) Transient"], "chooseN": 1, "correct": ["Temporary"], "explanation": "Temporary tables in Snowflake are no longer available after the close of the session and therefore do not have Fail-safe or Time Travel recovery options. These tables are designed to be used for temporary storage and computation during a session.", "reference": "https://docs.snowflake.com/en/user-guide/tables-temp-transient.html#temporary-tables"}, {"id": 669, "area": "Account Access and Security", "question": "How many network policies can be assigned to an account or specific user at a time?", "options": ["A) One", "B) Two", "C) Three", "D) Unlimited"], "chooseN": 1, "correct": ["One"], "explanation": "Only one network policy can be assigned to an account or a specific user at a time in Snowflake. This policy governs the IP address ranges that are allowed or denied access to the account.", "reference": "https://docs.snowflake.com/en/user-guide/network-policies#overview"}, {"id": 670, "area": "Data Protection and Data Sharing", "question": "What is a characteristic of a tag associated with a masking policy?", "options": ["A) A tag can be dropped after a masking policy is assigned.", "B) A tag can have only one masking policy for each data type.", "C) A tag can have multiple masking policies for each data type.", "D) A tag can have multiple masking policies with varying data types."], "chooseN": 1, "correct": ["A tag can have only one masking policy for each data type."], "explanation": "A tag in Snowflake can have only one masking policy for each data type. For example, if a tag already has a masking policy for the NUMBER data type, you cannot assign another masking policy with the NUMBER data type to the same tag. However, a tag can have multiple masking policies if each policy is for a different data type (e.g., one for STRING, one for NUMBER).", "reference": "https://docs.snowflake.com/en/user-guide/tag-based-masking-policies#limitations"}, {"id": 671, "area": "Account Access and Security", "question": "Which clients does Snowflake support Multi-Factor Authentication (MFA) token caching for? (Choose two.)", "options": ["A) GO driver", "B) Node.js driver", "C) ODBC driver", "D) Python connector", "E) Spark connector"], "chooseN": 2, "correct": ["ODBC driver", "Python connector"], "explanation": "Snowflake supports Multi-Factor Authentication (MFA) token caching for clients such as the ODBC driver and the Python connector. This feature enhances security while also improving usability by reducing the frequency of MFA challenges.", "reference": "https://docs.snowflake.com/en/user-guide/security-mfa#using-mfa-token-caching-to-minimize-the-number-of-prompts-during-authentication-optional"}, {"id": 672, "area": "Data Loading and Unloading", "question": "What is the Snowflake recommended Parquet file size when querying from external tables to optimize the number of parallel scanning operations?", "options": ["A) 1-16 MB", "B) 16-128 MB", "C) 100-250 MB", "D) 256-512 MB"], "chooseN": 1, "correct": ["256-512 MB"], "explanation": "For querying from external tables in Snowflake, the recommended Parquet file size to optimize the number of parallel scanning operations is between 256-512 MB. This size range balances the need for parallelism with overhead considerations.", "reference": "https://docs.snowflake.com/en/user-guide/tables-external-intro#general-file-sizing-recommendations"}, {"id": 673, "area": "Data Loading and Unloading", "question": "Which data types can be used in a Snowflake table that holds semi-structured data? (Choose two.)", "options": ["A) ARRAY", "B) BINARY", "C) TEXT", "D) VARIANT", "E) VARCHAR"], "chooseN": 2, "correct": ["ARRAY", "VARIANT"], "explanation": "In Snowflake, ARRAY and VARIANT are data types that can be used for storing semi-structured data. VARIANT is particularly flexible and can store different forms of semi-structured data like JSON, while ARRAY is useful for storing array-based data structures.", "reference": "https://docs.snowflake.com/sql-reference/data-types-semistructured"}, {"id": 674, "area": "Data Transformations", "question": "Which constraint is enforced in Snowflake?", "options": ["A) FOREIGN KEY", "B) NOT NULL", "C) PRIMARY KEY", "D) UNIQUE KEY"], "chooseN": 1, "correct": ["NOT NULL"], "explanation": "In Snowflake, the 'NOT NULL' constraint is actively enforced. This constraint ensures that a column cannot have a NULL value. Other constraints like FOREIGN KEY, PRIMARY KEY, and UNIQUE KEY are recognized but not enforced.", "reference": "https://docs.snowflake.com/en/sql-reference/constraints-overview#supported-constraint-types"}, {"id": 675, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which pages are included in the Activity area of Snowsight? (Choose two.)", "options": ["A) Contacts", "B) Sharing settings", "C) Copy History", "D) Query History", "E) Automatic Clustering History"], "chooseN": 2, "correct": ["Copy History", "Query History"], "explanation": "Snowsight Activity is broken into two areas: Query History and Copy History. Query history displays details of queries executed in your Snowflake account in the last 14 days. Copy History displays data loading activity that has occurred over the last 365 days for all tables in your account.", "reference": "https://docs.snowflake.com/en/user-guide/ui-snowsight-quick-tour#activity-pages"}, {"id": 676, "area": "Performance Concepts", "question": "When should a user consider disabling auto-suspend for a virtual warehouse? (Choose two.)", "options": ["A) When users will be using compute at different times throughout a 24/7 period", "B) When managing a steady workload", "C) When the compute must be available with no delay or lag time", "D) When the user does not want to have to manually turn on the warehouse each time it is needed", "E) When the warehouse is shared across different teams"], "chooseN": 2, "correct": ["When managing a steady workload", "When the compute must be available with no delay or lag time"], "explanation": "A user should consider disabling auto-suspend for a virtual warehouse when managing a steady workload and when the compute must be available with no delay or lag time. This ensures continuous availability of the warehouse without the need for reactivation.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-considerations#automating-warehouse-suspension"}, {"id": 677, "area": "Snowflake Data Cloud Features & Architecture", "question": "What can a Snowflake user do in the Activity section in Snowsight?", "options": ["A) Create dashboards.", "B) Write and run SQL queries.", "C) Explore databases and objects.", "D) Explore executed query performance."], "chooseN": 1, "correct": ["Explore executed query performance."], "explanation": "In the Activity section of Snowsight, a Snowflake user can explore executed query performance. This section provides detailed insights into the performance of the queries that have been run, allowing users to analyze and optimize their SQL queries.", "reference": "https://docs.snowflake.com/en/user-guide/ui-snowsight-quick-tour#activity-pages"}, {"id": 678, "area": "Data Loading and Unloading", "question": "How does Snowflake reorganize data when it is loaded? (Choose two.)", "options": ["A) Binary format", "B) Columnar format", "C) Compressed format", "D) Raw format", "E) Zipped format"], "chooseN": 2, "correct": ["Columnar format", "Compressed format"], "explanation": "When data is loaded into Snowflake, it is reorganized into a columnar format and a compressed format. The columnar format optimizes analytical query performance, while compression reduces storage costs and improves I/O efficiency.", "reference": "https://docs.snowflake.com/en/user-guide/intro-key-concepts#database-storage"}, {"id": 679, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which operations are handled in the Cloud Services layer of Snowflake? (Choose two.)", "options": ["A) Security", "B) Data storage", "C) Data visualization", "D) Query computation", "E) Metadata management"], "chooseN": 2, "correct": ["Security", "Metadata management"], "explanation": "In Snowflake's Cloud Services layer, operations such as Security and Metadata Management are handled. This layer manages all aspects of data security and metadata storage, ensuring secure and efficient data management.", "reference": "https://docs.snowflake.com/en/user-guide/intro-key-concepts#snowflake-architecture"}, {"id": 680, "area": "Data Protection and Data Sharing", "question": "At which point is data encrypted when using a PUT command?", "options": ["A) When it reaches the virtual warehouse", "B) When it gets micro-partitioned", "C) Before it is sent from the user's machine", "D) After it reaches the internal stage"], "chooseN": 1, "correct": ["Before it is sent from the user's machine"], "explanation": "When using the PUT command in Snowflake, data is encrypted before it is sent from the user's machine. This ensures that data is secure and protected during transit to Snowflake's cloud storage.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/put#usage-notes"}, {"id": 681, "area": "Performance Concepts", "question": "What type of columns does Snowflake recommend to be used as clustering keys? (Choose two.)", "options": ["A) A VARIANT column", "B) A column with very low cardinality", "C) A column with very high cardinality", "D) A column that is most actively used in selective filters", "E) A column that is most actively used in join predicates"], "chooseN": 2, "correct": ["A column that is most actively used in selective filters", "A column that is most actively used in join predicates"], "explanation": "Snowflake recommends using columns that are most actively used in selective filters as clustering keys and columns that are most actively used in join predicates. This approach enhances the efficiency of query processing by optimizing data organization and access patterns.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-keys#strategies-for-selecting-clustering-keys"}, {"id": 682, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which objects together comprise a namespace in Snowflake? (Choose two.)", "options": ["A) Account", "B) Database", "C) Schema", "D) Table", "E) Virtual warehouse"], "chooseN": 2, "correct": ["Database", "Schema"], "explanation": "In Snowflake, a namespace is typically comprised of Databases and Schemas. These objects together define the logical structure in which data is stored and organized within Snowflake.", "reference": "https://docs.snowflake.com/en/sql-reference/ddl-database"}, {"id": 683, "area": "Performance Concepts", "question": "What statistical information in a Query Profile indicates that the query is too large to fit in memory? (Choose two.)", "options": ["A) Bytes spilled to local cache.", "B) Bytes spilled to local storage.", "C) Bytes spilled to remote cache.", "D) Bytes spilled to remote storage.", "E) Bytes spilled to remote metastore."], "chooseN": 2, "correct": ["Bytes spilled to local storage.", "Bytes spilled to remote storage."], "explanation": "In a Snowflake Query Profile, statistics like 'Bytes spilled to local storage' and 'Bytes spilled to remote storage' indicate that the query is too large to fit in memory. This spilling is a mechanism to handle large queries that exceed the available memory.", "reference": "https://docs.snowflake.com/en/user-guide/ui-query-profile#queries-too-large-to-fit-in-memory"}, {"id": 684, "area": "Data Protection and Data Sharing", "question": "How do Snowflake data providers share data that resides in different databases?", "options": ["A) External tables", "B) Secure views", "C) Materialized views", "D) User-Defined Functions (UDFs)"], "chooseN": 1, "correct": ["Secure views"], "explanation": "Snowflake data providers share data that resides in different databases through secure views. A secure view can reference objects (schemas, tables, views) from multiple databases within the same account. To share such a view, the provider must grant REFERENCE_USAGE on each referenced database. External tables, materialized views, and UDFs do not provide cross-database sharing capabilities.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-multiple-db"}, {"id": 685, "area": "Data Loading and Unloading", "question": "What operations can be performed while loading a simple CSV file into a Snowflake table using the COPY INTO command? (Choose two.)", "options": ["A) Performing aggregate calculations", "B) Reordering the columns", "C) Grouping by operations", "D) Converting the datatypes", "E) Selecting the first few rows"], "chooseN": 2, "correct": ["Reordering the columns", "Converting the datatypes"], "explanation": "While loading a simple CSV file into a Snowflake table using the 'COPY INTO' command, operations such as reordering the columns and converting the datatypes can be performed. These transformations help in aligning the data with the structure of the target table.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-transform"}, {"id": 686, "area": "Data Transformations", "question": "Which commands support a multiple-statement request to access and update Snowflake data? (Choose two.)", "options": ["A) CALL", "B) COMMIT", "C) GET", "D) PUT", "E) ROLLBACK"], "chooseN": 2, "correct": ["COMMIT", "ROLLBACK"], "explanation": "Snowflake’s transaction commands are COMMIT and ROLLBACK. These are the commands relevant to multi-statement transactional execution. CALL is for invoking a stored procedure, not the transaction control mechanism, and GET/PUT are file-transfer commands.", "reference": "https://docs.snowflake.com/en/sql-reference/commands-transaction"}, {"id": 687, "area": "Data Protection and Data Sharing", "question": "Why should a Snowflake user implement a secure view? (Choose two.)", "options": ["A) To store unstructured data", "B) To increase query performance", "C) To limit access to sensitive data", "D) To optimize query concurrency and queuing", "E) To hide view definition and details from unauthorized users"], "chooseN": 2, "correct": ["To limit access to sensitive data", "To hide view definition and details from unauthorized users"], "explanation": "A Snowflake user should implement a secure view to limit access to sensitive data and to hide view definition and details from unauthorized users. Secure views provide a layer of security by controlling data exposure and protecting sensitive information.", "reference": "https://docs.snowflake.com/en/user-guide/views-secure.html"}, {"id": 688, "area": "Performance Concepts", "question": "At what levels can a resource monitor be configured? (Choose two.)", "options": ["A) Account", "B) Database", "C) Organization", "D) Schema", "E) Virtual warehouse"], "chooseN": 2, "correct": ["Account", "Virtual warehouse"], "explanation": "In Snowflake, a resource monitor can be configured at the 'Account' level and the 'Virtual warehouse' level. These monitors help in tracking and controlling the consumption of compute resources at these specific levels.", "reference": "https://docs.snowflake.com/en/user-guide/resource-monitors#monitor-level"}, {"id": 689, "area": "Account Access and Security", "question": "What activities can be monitored by a user directly from Snowsight's Activity tab without using the Account_Usage views? (Choose two.)", "options": ["A) Login history", "B) Query history", "C) Copy history", "D) Event usage history", "E) Virtual warehouse metering history"], "chooseN": 2, "correct": ["Query history", "Copy history"], "explanation": "Snowsight Activity is broken into two areas: Query History and Copy History. Query history displays details of queries executed in your Snowflake account in the last 14 days. Copy History displays data loading activity that has occurred over the last 365 days for all tables in your account.", "reference": "https://docs.snowflake.com/en/user-guide/ui-snowsight-quick-tour#activity-pages"}, {"id": 690, "area": "Data Transformations", "question": "What can a Snowflake user do with the information included in the details section of a Query Profile?", "options": ["A) Determine the total duration of the query.", "B) Determine the role of the user who ran the query.", "C) Determine the source system that the queried table is from.", "D) Determine if the query was on structured or semi-structured data."], "chooseN": 1, "correct": ["Determine the total duration of the query."], "explanation": "In the details section of a Snowflake Query Profile, users can find information to determine the total duration of the query. This includes insights into various stages of query execution and their respective timings.", "reference": "https://docs.snowflake.com/en/user-guide/ui-query-profile#query-operator-details"}, {"id": 691, "area": "Data Loading and Unloading", "question": "How can a Snowflake user access a JSON object, given the following table? (Choose two.)", "options": ["A) src:salesperson.name", "B) src:salesPerson.name", "C) src:salesPerson.Name", "D) SRC:salesPerson.name", "E) SRC:salesPerson.Name"], "chooseN": 2, "correct": ["src:salesPerson.name", "SRC:salesPerson.name"], "explanation": "Regardless of which notation you use (Dot Notation or Bracket Notation), the column name is case-insensitive but element names are case-sensitive.", "reference": "https://docs.snowflake.com/en/user-guide/querying-semistructured#traversing-semi-structured-data"}, {"id": 692, "area": "Performance Concepts", "question": "Which term is used to describe information about disk usage for operations where intermediate results cannot be accommodated in a Snowflake virtual warehouse memory?", "options": ["A) Pruning", "B) Spilling", "C) Join explosion", "D) Queue overloading"], "chooseN": 1, "correct": ["Spilling"], "explanation": "The term 'Spilling' is used in Snowflake to describe situations where intermediate results of operations exceed the available memory in a virtual warehouse and are temporarily written to disk. This helps in managing large or complex queries.", "reference": "https://docs.snowflake.com/en/user-guide/performance-query-warehouse"}, {"id": 693, "area": "Data Protection and Data Sharing", "question": "There are two Snowflake accounts in the same cloud provider region: one is production and the other is non-production. How can data be easily transferred from the production account to the non-production account?", "options": ["A) Clone the data from the production account to the non-production account.", "B) Create a data share from the production account to the non-production account.", "C) Create a subscription in the production account and have it publish to the non-production account.", "D) Create a reader account using the production account and link the reader account to the non-production account."], "chooseN": 1, "correct": ["Create a data share from the production account to the non-production account."], "explanation": "Creating a data share from the production account to the non-production account is an efficient way to transfer data in Snowflake. Data sharing allows for secure and direct access to shared data without the need to copy or move it physically.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-intro.html"}, {"id": 694, "area": "Data Loading and Unloading", "question": "A user is unloading data to a stage using this command: copy into @message from (select object_construct('id', 1, 'first_name', 'Snowflake', 'last_name', 'User', 'city', 'Bozeman')) file_format = (type = json) What will the output file in the stage be?", "options": ["A) A single compressed JSON file with a single VARIANT column", "B) Multiple compressed JSON files with a single VARIANT column", "C) A single uncompressed JSON file with multiple VARIANT columns", "D) Multiple uncompressed JSON files with multiple VARIANT columns"], "chooseN": 1, "correct": ["A single compressed JSON file with a single VARIANT column"], "explanation": "The output file in the stage will be a single compressed JSON file with a single VARIANT column. The COPY INTO command with a JSON file format and the use of object_construct function will result in a single JSON file that contains the data in a VARIANT column format, and Snowflake's default behavior is to compress the file.", "reference": "https://docs.snowflake.com/en/user-guide/data-unload-considerations#unloading-a-relational-table-to-json"}, {"id": 695, "area": "Data Transformations", "question": "A JSON file that contains lots of dates and arrays needs to be processed in Snowflake. The user wants to ensure optimal performance while querying the data. How can this be achieved?", "options": ["A) Flatten the data and store it in structured data types in a flattened table. Query the table.", "B) Store the data in a table with a VARIANT data type. Query the table.", "C) Store the data in a table with a VARIANT data type and include STRIP_NULL_VALUES while loading the table. Query the table.", "D) Store the data in an external stage and create views on top of it. Query the views."], "chooseN": 1, "correct": ["Flatten the data and store it in structured data types in a flattened table. Query the table."], "explanation": "To ensure optimal performance while querying a JSON file with lots of dates and arrays in Snowflake, the user should flatten the data and store it in structured data types in a flattened table. This approach optimizes query performance by transforming the semi-structured JSON data into a structured format that is easier to query. For better pruning and less storage consumption, we recommend flattening your OBJECT and key data into separate relational columns if your semi-structured data includes: ·Dates and timestamps, especially non-ISO 8601 dates and timestamps, as string values · Numbers within strings ·Arrays", "reference": "https://docs.snowflake.com/en/user-guide/semistructured-considerations#storing-semi-structured-data-in-a-variant-column-vs-flattening-the-nested-structure"}, {"id": 696, "area": "Data Transformations", "question": "When referring to User-Defined Function (UDF) names in Snowflake, what does the term overloading mean?", "options": ["A) There are multiple SQL UDFs with the same names and the same number of arguments.", "B) There are multiple SQL UDFs with the same names and the same number of argument types.", "C) There are multiple SQL UDFs with the same names but with a different number of arguments or argument types.", "D) There are multiple SQL UDFs with different names but the same number of arguments or argument types."], "chooseN": 1, "correct": ["There are multiple SQL UDFs with the same names but with a different number of arguments or argument types."], "explanation": "In Snowflake, the term 'overloading' when referring to UDF names means that there are multiple SQL UDFs with the same names but with a different number of arguments or argument types. This allows the same function name to be used for different variations of the function, distinguished by their argument lists.", "reference": "https://docs.snowflake.com/en/developer-guide/udf-stored-procedure-naming-conventions#overloading-procedures-and-functions"}, {"id": 697, "area": "Data Protection and Data Sharing", "question": "Which key governance feature in Snowflake allows users to identify data objects that contain sensitive data and their related objects?", "options": ["A) Object tagging", "B) Data classification", "C) Row access policy", "D) Column-level security"], "chooseN": 1, "correct": ["Object tagging"], "explanation": "The key governance feature in Snowflake that allows users to identify data objects that contain sensitive data and their related objects is 'Object tagging'. Tags can be used to mark and track sensitive data across various objects in Snowflake.", "reference": "https://docs.snowflake.com/en/user-guide/object-tagging.html"}, {"id": 698, "area": "Snowflake Data Cloud Features & Architecture", "question": "What can a Snowflake user do in the Admin area of Snowsight?", "options": ["A) Analyze query performance.", "B) Write queries and execute them.", "C) Provide an overview of the listings in the Snowflake Marketplace.", "D) Connect to Snowflake partners to explore extended functionality."], "chooseN": 1, "correct": ["Analyze query performance."], "explanation": "- Analyze query performance: En el área de administración de Snowsight, los usuarios pueden analizar el rendimiento de las consultas, utilizando herramientas específicas para monitorear y optimizar el rendimiento.\n- Write queries and execute them: Esta funcionalidad está disponible en otras áreas de Snowflake, no en la zona administrativa de Snowsight.\n- Provide an overview of the listings in the Snowflake Marketplace: El acceso y manejo de Snowflake Marketplace se realiza fuera de Snowsight, no en la zona administrativa.\n- Connect to Snowflake partners to explore extended functionality: Aunque Snowflake ofrece integración con socios, esta opción no se realiza específicamente desde el área de administración de Snowsight.", "reference": "https://docs.snowflake.com/en/user-guide/ui-snowsight-admin"}, {"id": 699, "area": "Data Loading and Unloading", "question": "Which function generates a Snowflake hosted file URL to a staged file using the stage name and relative file path as inputs?", "options": ["A) BUILD_STAGE_FILE_URL", "B) BUILD_SCOPED_FILE_URL", "C) GET_PRESIGNED_URL", "D) GET_STAGE_LOCATION"], "chooseN": 1, "correct": ["BUILD_STAGE_FILE_URL"], "explanation": "DUDOSA (ya que no especifica si es por tiempo limitado el acceso al fichero 'BUILD_SCOPED_FILE_URL' o no 'BUILD_STAGE_FILE_URL', entendemos que no es necesaria esa funcionalidad, y por eso escogemos 'BUILD_STAGE_FILE_URL')!!! The BUILD_STAGE_FILE_URL function in Snowflake generates a Snowflake file URL to a staged file using the stage name and relative file path as inputs. A file URL permits prolonged access to a specified file. That is, the file URL does not expire.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/build_stage_file_url"}, {"id": 700, "area": "Data Transformations", "question": "What is the purpose of using the OBJECT_CONSTRUCT function with the COPY INTO command?", "options": ["A) Reorder the rows in a relational table and then unload the rows into a file.", "B) Convert the rows in a relational table to a single VARIANT column and then unload the rows into a file.", "C) Reorder the data columns according to a target table definition and then unload the rows into the table.", "D) Convert the rows in a source file to a single VARIANT column and then load the rows from the file to a variant table."], "chooseN": 1, "correct": ["Convert the rows in a relational table to a single VARIANT column and then unload the rows into a file."], "explanation": "The OBJECT_CONSTRUCT function is used with the COPY INTO command in Snowflake to convert rows in a relational table into a single VARIANT column. This allows for the unloading of structured data into a semi-structured format like JSON.", "reference": "https://docs.snowflake.com/en/user-guide/data-unload-considerations#unloading-a-relational-table-to-json"}, {"id": 701, "area": "Data Protection and Data Sharing", "question": "Which URL provides access to files in Snowflake without authorization?", "options": ["A) File URL", "B) Scoped URL", "C) Pre-signed URL", "D) Scoped file URL"], "chooseN": 1, "correct": ["Pre-signed URL"], "explanation": "A pre-signed URL in Snowflake provides access to files without requiring additional authorization. This URL type is generated with specific permissions and a limited lifetime for secure, controlled access to staged files.", "reference": "https://docs.snowflake.com/en/user-guide/unstructured-intro#types-of-urls-available-to-access-files"}, {"id": 702, "area": "Data Loading and Unloading", "question": "What type of NULL values are supported in semi-structured data? (Choose two.)", "options": ["A) Avro", "B) JSON", "C) ORC", "D) Parquet", "E) SQL"], "chooseN": 2, "correct": ["JSON", "SQL"], "explanation": "Snowflake soporta dos tipos de valores NULL en datos semi-estructurados (VARIANT): JSON null (el literal null en JSON, almacenado como un valor VARIANT distinto de SQL NULL) y SQL NULL (representa la ausencia de valor, aplicable tambien a columnas VARIANT). Avro, ORC y Parquet son formatos de archivo, no tipos de NULL.", "reference": "https://docs.snowflake.com/en/user-guide/semistructured-considerations#null-values"}, {"id": 703, "area": "Data Loading and Unloading", "question": "What are characteristics of transient tables in Snowflake? (Choose two.)", "options": ["A) Transient tables have a Fail-safe period of 7 days.", "B) Transient tables can be cloned to permanent tables.", "C) Transient tables persist until they are explicitly dropped.", "D) Transient tables can be altered to make them permanent tables.", "E) Transient tables have Time Travel retention periods of 0 or 1 day."], "chooseN": 2, "correct": ["Transient tables persist until they are explicitly dropped.", "Transient tables have Time Travel retention periods of 0 or 1 day."], "explanation": "Transient tables in Snowflake are designed to persist until explicitly dropped by the user and typically have Time Travel retention periods of 0 or 1 day. They are used for temporary or intermediate storage, where long-term data retention is not required.", "reference": "https://docs.snowflake.com/en/user-guide/tables-temp-transient#comparison-of-table-types"}, {"id": 704, "area": "Snowflake Data Cloud Features & Architecture", "question": "The INFORMATION_SCHEMA included in each database contains which objects? (Choose two.)", "options": ["A) Views for all the objects contained in the database", "B) Views for all the objects contained in the Snowflake account", "C) Views for historical and usage data across the Snowflake account", "D) Table functions for historical and usage data across the Snowflake account", "E) Table functions for account-level objects, such as roles, virtual warehouses, and databases"], "chooseN": 2, "correct": ["Views for all the objects contained in the database", "Table functions for historical and usage data across the Snowflake account"], "explanation": "The INFORMATION_SCHEMA in each Snowflake database contains views for all the objects contained in that specific database and table functions for historical and usage data across the Snowflake account. These views and functions provide metadata about various objects and activities within the database and account.", "reference": "https://docs.snowflake.com/en/sql-reference/info-schema#what-is-information-schema"}, {"id": 705, "area": "Performance Concepts", "question": "The use of which technique or tool will improve Snowflake query performance on very large tables?", "options": ["A) Indexing", "B) Clustering keys", "C) Multi-clustering", "D) Materialized views"], "chooseN": 1, "correct": ["Clustering keys"], "explanation": "The use of 'Clustering keys' will improve Snowflake query performance on very large tables. Clustering keys organize the data in a table into optimally ordered micro-partitions, which can significantly enhance query performance by reducing the amount of data scanned.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-keys.html"}, {"id": 706, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which Snowflake layer is associated with virtual warehouses?", "options": ["A) Cloud services", "B) Query processing", "C) Elastic memory", "D) Database storage"], "chooseN": 1, "correct": ["Query processing"], "explanation": "The 'Query processing' layer in Snowflake is associated with virtual warehouses. This layer is responsible for executing all SQL queries, with each virtual warehouse providing the computational power required for query execution.", "reference": "https://docs.snowflake.com/en/user-guide/intro-key-concepts#snowflake-architecture"}, {"id": 707, "area": "Account Access and Security", "question": "Which MINIMUM set of privileges is required to temporarily bypass an active network policy by configuring the user object property MINS_TO_BYPASS_NETWORK_POLICY?", "options": ["A) Only while in the ACCOUNTADMIN role", "B) Only while in the SECURITYADMIN role", "C) Only the role with the OWNERSHIP privilege on the network policy", "D) Only Snowflake Support can set the value for this object property"], "chooseN": 1, "correct": ["Only Snowflake Support can set the value for this object property"], "explanation": "It is possible to temporarily bypass a network policy for a set number of minutes by configuring the user object property MINS_TO_BYPASS_NETWORK_POLICY, which can be viewed by executing DESCRIBE USER. Only Snowflake can set the value for this object property. Please contact Snowflake Support to set a value for this property.", "reference": "https://docs.snowflake.com/en/user-guide/network-policies#bypassing-a-network-policy"}, {"id": 708, "area": "Data Loading and Unloading", "question": "What authentication method does the Kafka connector use within Snowflake?", "options": ["A) Key pair authentication", "B) Multi-Factor Authentication (MFA)", "C) OAuth", "D) Username and password"], "chooseN": 1, "correct": ["Key pair authentication"], "explanation": "The Kafka connector within Snowflake uses 'Key pair authentication' as its authentication method. This method involves using a public/private key pair for secure authentication, which is a common and secure method of authentication for such integrations.", "reference": "https://docs.snowflake.com/en/user-guide/kafka-connector-install#using-key-pair-authentication-key-rotation"}, {"id": 709, "area": "Data Transformations", "question": "What is the purpose of the Snowflake SPLIT_TO_TABLE function?", "options": ["A) To count the number of characters in a string", "B) To split a string into an array of sub-strings", "C) To split a string and flatten the results into rows", "D) To split a string and flatten the results into columns"], "chooseN": 1, "correct": ["To split a string and flatten the results into rows"], "explanation": "The SPLIT_TO_TABLE function in Snowflake is used to split a string into sub-strings based on a specified delimiter and then flatten these results into rows. This function is useful for transforming delimited string data into a more structured format.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/split_to_table.html"}, {"id": 710, "area": "Data Protection and Data Sharing", "question": "What feature of Snowflake Continuous Data Protection can be used for maintenance of historical data?", "options": ["A) Access control", "B) Fail-safe", "C) Network policies", "D) Time Travel"], "chooseN": 1, "correct": ["Time Travel"], "explanation": "Time Travel in Snowflake is a feature of Continuous Data Protection that allows users to access historical data within a defined retention period. This feature is essential for maintaining, recovering, and analyzing historical data.", "reference": "https://docs.snowflake.com/en/user-guide/data-time-travel.html"}, {"id": 711, "area": "Performance Concepts", "question": "What aspect of an executed query is represented by the remote disk I/O statistic of the Query Profile in Snowflake?", "options": ["A) Time spent scanning the table partitions to filter data based on the predicate", "B) Time spent caching the data to remote storage in order to buffer the data being extracted and exported", "C) Time spent reading and writing data from and to remote storage when the data being accessed does not fit into the executing virtual warehouse node memory", "D) Time spent reading and writing data from and to remote storage when the data being accessed does not fit into either the virtual warehouse memory or the local disk"], "chooseN": 1, "correct": ["Time spent reading and writing data from and to remote storage when the data being accessed does not fit into either the virtual warehouse memory or the local disk"], "explanation": "DUDA (entre la C y la D)!!! The remote disk I/O statistic in a Snowflake Query Profile indicates the time spent reading and writing data from and to remote storage, particularly when the data exceeds the memory capacity of the executing virtual warehouse node and the local disk.", "reference": "https://docs.snowflake.com/en/user-guide/ui-query-profile#execution-time"}, {"id": 712, "area": "Performance Concepts", "question": "What action can a user take to address query concurrency issues?", "options": ["A) Enable the search optimization service.", "B) Enable the query acceleration service.", "C) Add additional clusters to the virtual warehouse.", "D) Resize the virtual warehouse to a larger instance size."], "chooseN": 1, "correct": ["Add additional clusters to the virtual warehouse."], "explanation": "To address query concurrency issues in Snowflake, adding additional clusters to the virtual warehouse is an effective solution. This increases the concurrent processing capacity of the warehouse, thereby reducing queue times and improving overall query performance.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-multicluster.html"}, {"id": 713, "area": "Account Access and Security", "question": "What does the client redirect feature in Snowflake enable?", "options": ["A) A redirect of client connections to Snowflake accounts in the same regions for business continuity.", "B) A redirect of client connections to Snowflake accounts in different regions for business continuity.", "C) A redirect of client connections to Snowflake accounts in different regions for data replication.", "D) A redirect of client connections to Snowflake accounts in the same regions for data replication."], "chooseN": 1, "correct": ["A redirect of client connections to Snowflake accounts in different regions for business continuity."], "explanation": "The client redirect feature in Snowflake enables the redirection of client connections to Snowflake accounts in different regions. This is primarily used for business continuity purposes, ensuring access to data and services in the event of regional disruptions.", "reference": "https://docs.snowflake.com/en/user-guide/client-redirect"}, {"id": 714, "area": "Data Protection and Data Sharing", "question": "Which Snowflake feature can be used to find sensitive data in a table or column?", "options": ["A) Masking policies", "B) Data classification", "C) Row level policies", "D) External functions"], "chooseN": 1, "correct": ["Data classification"], "explanation": "The 'Data classification' feature in Snowflake can be used to find sensitive data in a table or column. Data classification involves categorizing and labeling data based on its sensitivity and is essential for managing access to sensitive information.", "reference": "https://docs.snowflake.com/en/user-guide/governance-classify-concepts"}, {"id": 715, "area": "Data Protection and Data Sharing", "question": "Which Snowflake feature allows a user to track sensitive data for compliance, discovery, protection, and resource usage?", "options": ["A) Tags", "B) Comments", "C) Internal tokenization", "D) Row access policies"], "chooseN": 1, "correct": ["Tags"], "explanation": "In Snowflake, 'Tags' allow users to track sensitive data for compliance, discovery, protection, and resource usage. Tags provide a way to label and categorize data objects, making it easier to manage and monitor sensitive data.", "reference": "https://docs.snowflake.com/en/user-guide/object-tagging.html"}, {"id": 716, "area": "Data Protection and Data Sharing", "question": "Snowflake’s hierarchical key mode includes which keys? (Choose two.)", "options": ["A) Account master keys", "B) Database master keys", "C) File keys", "D) Secure view keys", "E) Schema master keys"], "chooseN": 2, "correct": ["Account master keys", "File keys"], "explanation": "Snowflake's hierarchical key model includes Account master keys and File keys. The complete hierarchy is: Root Key -> Account Master Key -> Table Master Key -> File Key. Each parent key wraps (encrypts) the layer below: the account master key wraps the table master keys, which in turn encrypt the file keys that protect the data files. Database master keys, Secure view keys, and Schema master keys do not exist in Snowflake's key hierarchy.", "reference": "https://docs.snowflake.com/en/user-guide/security-encryption-manage#hierarchical-key-model"}, {"id": 717, "area": "Account Access and Security", "question": "What can the Snowflake SCIM API be used to manage? (Choose two.)", "options": ["A) Integrations", "B) Network policies", "C) Session policies", "D) Roles", "E) Users"], "chooseN": 2, "correct": ["Roles", "Users"], "explanation": "The Snowflake SCIM (System for Cross-domain Identity Management) API can be used to manage 'Roles' and 'Users'. SCIM provides a standard for automating the exchange of user identity information between identity domains or IT systems, enabling efficient user and role management.", "reference": "https://docs.snowflake.com/en/user-guide/scim.html"}, {"id": 718, "area": "Performance Concepts", "question": "Which privilege is required to use the search optimization service in Snowflake?", "options": ["A) GRANT SEARCH OPTIMIZATION ON SCHEMA TO ROLE", "B) GRANT SEARCH OPTIMIZATION ON DATABASE TO ROLE", "C) GRANT ADD SEARCH OPTIMIZATION ON SCHEMA TO ROLE", "D) GRANT ADD SEARCH OPTIMIZATION ON DATABASE TO ROLE"], "chooseN": 1, "correct": ["GRANT ADD SEARCH OPTIMIZATION ON SCHEMA TO ROLE"], "explanation": "To use the search optimization service in Snowflake, the privilege required is 'GRANT ADD SEARCH OPTIMIZATION ON SCHEMA TO ROLE'. This privilege allows a specific role to enable and use the search optimization service for an entire table or specific columns, enhancing the performance of specific types of queries.", "reference": "https://docs.snowflake.com/en/user-guide/search-optimization/enabling"}, {"id": 719, "area": "Data Loading and Unloading", "question": "What is generally the FASTEST way to bulk load data files from a stage?", "options": ["A) Specifying a list of specific files to load", "B) Loading by path (internal stages) / prefix", "C) Using the Snowpipe REST API", "D) Using pattern matching to identify specific files by pattern"], "chooseN": 1, "correct": ["Specifying a list of specific files to load"], "explanation": "Of the three options for identifying/specifying data files to load from a stage, providing a discrete list of files is generally the fastest; however, the FILES parameter supports a maximum of 1,000 files, meaning a COPY command executed with the FILES parameter can only load up to 1,000 files.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-considerations-load"}, {"id": 720, "area": "Data Loading and Unloading", "question": "How does a Snowflake user extract the URL of a directory table on an external stage for further transformation?", "options": ["A) Use the SHOW STAGES command.", "B) Use the DESCRIBE STAGE command.", "C) Use the GET_ABSOLUTE_PATH function.", "D) Use the GET_STAGE_LOCATION function."], "chooseN": 1, "correct": ["Use the GET_STAGE_LOCATION function."], "explanation": "To extract the URL of a directory table on an external stage in Snowflake, the GET_STAGE_LOCATION( @<stage_name> ) function can be used. This function helps in retrieving the URL of the stage.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/get_stage_location"}, {"id": 721, "area": "Data Protection and Data Sharing", "question": "A Snowflake user needs to share unstructured data from an internal stage to a reporting tool that does not have Snowflake access. Which file function should be used?", "options": ["A) BUILD_SCOPED_FILE_URL", "B) BUILD_STAGE_FILE_URL", "C) GET_PRESIGNED_URL", "D) GET_STAGE_LOCATION"], "chooseN": 1, "correct": ["GET_PRESIGNED_URL"], "explanation": "To share unstructured data from an internal stage to a reporting tool without Snowflake access, the GET_PRESIGNED_URL function should be used. This function generates a pre-signed URL that can be used to provide secure, temporary access to the staged files.", "reference": "https://docs.snowflake.com/en/user-guide/unstructured-intro"}, {"id": 722, "area": "Data Transformations", "question": "The use of which Snowflake table type will reduce costs when working with ETL workflows?", "options": ["A) External", "B) Permanent", "C) Temporary", "D) Transient"], "chooseN": 1, "correct": ["Temporary"], "explanation": "Using Temporary tables in Snowflake can help reduce costs when working with ETL workflows. Temporary tables are session-specific and are automatically dropped at the end of the session, thereby saving on storage costs.", "reference": "https://docs.snowflake.com/en/user-guide/tables-temp-transient.html#temporary-tables"}, {"id": 723, "area": "Data Protection and Data Sharing", "question": "What is one of the characteristics of data shares?", "options": ["A) Data shares support full DML operations.", "B) Data shares work by copying data to consumer accounts.", "C) Data shares utilize secure views for sharing view objects.", "D) Data shares are cloud agnostic and can cross regions by default."], "chooseN": 1, "correct": ["Data shares utilize secure views for sharing view objects."], "explanation": "A key characteristic of data shares in Snowflake is that they utilize secure views for sharing view objects. This ensures shared data remains secure and only authorized data is visible to consumers. Data shares are NOT cloud agnostic by default and cannot cross regions without additional database replication configuration. They do not copy data to consumer accounts and do not support full DML operations on shared data.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-intro.html"}, {"id": 724, "area": "Account Access and Security", "question": "What is the MINIMUM configurable idle timeout value for a session policy in Snowflake?", "options": ["A) 2 minutes", "B) 5 minutes", "C) 10 minutes", "D) 15 minutes"], "chooseN": 1, "correct": ["5 minutes"], "explanation": "The minimum configurable timeout value for a session policy in Snowflake is 5 minutes. This setting is used to automatically terminate sessions that have been idle for the specified duration, enhancing security by preventing unused sessions from remaining open.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/create-session-policy.html"}, {"id": 725, "area": "Data Loading and Unloading", "question": "Which command is used to unload data from a Snowflake table to an external stage?", "options": ["A) COPY INTO", "B) COPY INTO followed by GET", "C) GET", "D) COPY INTO followed by PUT"], "chooseN": 1, "correct": ["COPY INTO"], "explanation": "The 'COPY INTO' command is used for both load and unload data between a Snowflake table and an stage. This command allows users to export data from Snowflake tables or query results to files in an external stage.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-location.html"}, {"id": 726, "area": "Data Transformations", "question": "What is a characteristic of materialized views in Snowflake?", "options": ["A) Materialized views do not allow joins.", "B) Clones of materialized views can be created directly by the user.", "C) Multiple tables can be joined in the underlying query of a materialized view.", "D) Aggregate functions can be used as window functions in materialized views."], "chooseN": 1, "correct": ["Materialized views do not allow joins."], "explanation": "A materialized view can query only a single table, joins, including self-joins, are not supported.", "reference": "https://docs.snowflake.com/en/user-guide/views-materialized.html"}, {"id": 727, "area": "Data Loading and Unloading", "question": "Which Snowflake URL type allows users or applications to download or access files directly from Snowflake stage without authentication?", "options": ["A) Directory", "B) File", "C) Pre-signed", "D) Scoped"], "chooseN": 1, "correct": ["Pre-signed"], "explanation": "The 'Pre-signed' URL type in Snowflake allows users or applications to download or access files directly from a Snowflake stage without authentication. Pre-signed URLs provide a way to grant temporary access to specific files or objects in a stage.", "reference": "https://docs.snowflake.com/en/user-guide/unstructured-intro"}, {"id": 728, "area": "Data Loading and Unloading", "question": "Which SQL command will download all the data files from an internal table stage named TBL_EMPLOYEE to a local window directory or folder on a client machine in a folder named folder with space within the C drive?", "options": ["A) GET @%TBL_EMPLOYEE 'file:/ C:\\folder with space\\';", "B) GET @%TBL_EMPLOYEE 'file:/ C:/folder with space/';", "C) PUT 'file:/ C:\\folder with space\\*' @%TBL_EMPLOYEE;", "D) PUT 'file:/ C:/folder with space/*' @%TBL_EMPLOYEE;"], "chooseN": 1, "correct": ["GET @%TBL_EMPLOYEE 'file:/ C:/folder with space/';"], "explanation": "The GET command downloads files from an internal stage to a local directory. For Windows file paths enclosed in single quotes, Snowflake documentation specifies that the drive and path separator must use forward slashes (/), not backslashes. The correct syntax is: GET @%TBL_EMPLOYEE 'file:/ C:/folder with space/'; PUT is used for uploading files to a stage, not downloading.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/get.html"}, {"id": 729, "area": "Data Loading and Unloading", "question": "How can the COPY command be used to unload data from a table to an internal stage?", "options": ["A) COPY INTO @STAGE FROM TABLE", "B) COPY INTO TABLE TO STAGE", "C) COPY FROM TABLE INTO @STAGE", "D) COPY TABLE @STAGE FROM"], "chooseN": 1, "correct": ["COPY INTO @STAGE FROM TABLE"], "explanation": "La pregunta original estaba mal, esta es inventada no es de examtopics, la opción correcta es la A, se usa igual que el COPY INTO <TABLE> pero cambiando el stage y la tabla de posición.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-location.html"}, {"id": 730, "area": "Data Transformations", "question": "How does a Snowflake stored procedure compare to a User-Defined Function (UDF)?", "options": ["A) A single executable statement can call only two stored procedures. In contrast, a single SQL statement can call multiple UDFs.", "B) A single executable statement can call only one stored procedure. In contrast, a single SQL statement can call multiple UDFs.", "C) A single executable statement can call multiple stored procedures. In contrast, multiple SQL statements can call the same UDFs.", "D) Multiple executable statements can call more than one stored procedure. In contrast, a single SQL statement can call multiple UDFs."], "chooseN": 1, "correct": ["A single executable statement can call only one stored procedure. In contrast, a single SQL statement can call multiple UDFs."], "explanation": "In Snowflake, a single executable statement can call only one stored procedure due to its transactional nature. In contrast, a single SQL statement can call multiple User-Defined Functions (UDFs), which are more flexible in terms of integration within SQL queries.", "reference": "https://docs.snowflake.com/en/developer-guide/stored-procedures-vs-udfs"}, {"id": 731, "area": "Data Loading and Unloading", "question": "Which command should be used to unload all the rows from a table into one or more files in a named stage?", "options": ["A) COPY INTO", "B) GET", "C) INSERT INTO", "D) PUT"], "chooseN": 1, "correct": ["COPY INTO"], "explanation": "To unload all the rows from a table into one or more files in a named stage, the 'COPY INTO' command should be used in Snowflake. This command facilitates the unloading of table data efficiently into specified file formats at a designated stage.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-location.html"}, {"id": 732, "area": "Data Loading and Unloading", "question": "Which command is used to unload data from a table or move a query result to a stage?", "options": ["A) COPY INTO", "B) GET", "C) MERGE", "D) PUT"], "chooseN": 1, "correct": ["COPY INTO"], "explanation": "The 'COPY INTO' command in Snowflake is used to unload data from a table or to move the results of a query to a stage. This command enables the transfer of data from Snowflake to an external storage location for further processing or storage.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-location.html"}, {"id": 733, "area": "Data Protection and Data Sharing", "question": "What privileges are necessary for a consumer in the Data Exchange to make a request and receive data? (Choose two.)", "options": ["A) CREATE DATABASE", "B) IMPORT SHARE", "C) OWNERSHIP", "D) REFERENCE_USAGE", "E) USAGE"], "chooseN": 2, "correct": ["CREATE DATABASE", "IMPORT SHARE"], "explanation": "To access a listing, you must use the ACCOUNTADMIN role or another role with the CREATE DATABASE and IMPORT SHARE privileges. To pay for a paid listing, your role must also have the PURCHASE DATA EXCHANGE LISTING privilege.", "reference": "https://other-docs.snowflake.com/en/collaboration/consumer-becoming"}, {"id": 734, "area": "Snowflake Data Cloud Features & Architecture", "question": "What are benefits of using Snowpark with Snowflake? (Choose two.)", "options": ["A) Snowpark uses a Spark engine to generate optimized SQL query plans.", "B) Snowpark automatically sets up Spark within Snowflake virtual warehouses.", "C) Snowpark does not require that a separate cluster be running outside of Snowflake.", "D) Snowpark allows users to run existing Spark code on virtual warehouses without the need to reconfigure the code.", "E) Snowpark executes as much work as possible in the source databases for all operations including User-Defined Functions (UDFs)."], "chooseN": 2, "correct": ["Snowpark does not require that a separate cluster be running outside of Snowflake.", "Snowpark executes as much work as possible in the source databases for all operations including User-Defined Functions (UDFs)."], "explanation": "Two key benefits of Snowpark are: (1) It does not require a separate cluster running outside of Snowflake, as all processing runs within Snowflake's virtual warehouses. (2) It executes as much work as possible within Snowflake for all operations including User-Defined Functions (UDFs), leveraging push-down optimization. Snowpark does not use a Spark engine and does not allow running existing Spark code without modification.", "reference": "https://docs.snowflake.com/en/developer-guide/snowpark/index"}, {"id": 735, "area": "Account Access and Security", "question": "What are Snowflake best practices when assigning the ACCOUNTADMIN role to users? (Choose two.)", "options": ["A) The ACCOUNTADMIN role should be assigned to at least two users.", "B) The ACCOUNTADMIN role should be used to create Snowflake objects.", "C) The ACCOUNTADMIN role should be used for running automated scripts.", "D) The ACCOUNTADMIN role should be given to any user who needs a high level of authority.", "E) All users assigned the ACCOUNTADMIN role should use Multi-Factor Authentication (MFA)."], "chooseN": 2, "correct": ["The ACCOUNTADMIN role should be assigned to at least two users.", "All users assigned the ACCOUNTADMIN role should use Multi-Factor Authentication (MFA)."], "explanation": "Best practices for assigning the ACCOUNTADMIN role in Snowflake include ensuring that it is assigned to at least two users for redundancy and requiring all users with this role to use Multi-Factor Authentication (MFA) for enhanced security.", "reference": "https://docs.snowflake.com/en/user-guide/admin-user-management"}, {"id": 736, "area": "Performance Concepts", "question": "What is a recommended approach for optimizing query performance in Snowflake?", "options": ["A) Use subqueries whenever possible.", "B) Use a large number of joins to combine data from multiple tables.", "C) Select all columns from tables, even if they are not needed in the query.", "D) Use a smaller number of larger tables rather than a larger number of smaller tables."], "chooseN": 1, "correct": ["Use a smaller number of larger tables rather than a larger number of smaller tables."], "explanation": "A recommended approach for optimizing query performance in Snowflake is to use a smaller number of larger tables rather than a larger number of smaller tables. This approach simplifies the data model and can improve performance by reducing the complexity of queries.", "reference": "https://docs.snowflake.com/en/guides-overview-performance"}, {"id": 737, "area": "Data Loading and Unloading", "question": "When using SnowSQL, which configuration options are required when unloading data from a SQL query run on a local machine? (Choose two.)", "options": ["A) echo", "B) quiet", "C) output_file", "D) output_format", "E) force_put_overwrite"], "chooseN": 2, "correct": ["output_file", "output_format"], "explanation": "When unloading data from a SQL query run on a local machine using SnowSQL, the required configuration options are 'output_file' and 'output_format'. The 'output_file' option specifies where the data should be unloaded, and 'output_format' defines the format of the unloaded data. 'quiet' is optional.", "reference": "https://docs.snowflake.com/en/user-guide/snowsql-use#exporting-data."}, {"id": 738, "area": "Data Protection and Data Sharing", "question": "Which Snowflake view is used to support compliance auditing?", "options": ["A) ACCESS_HISTORY", "B) COPY_HISTORY", "C) QUERY_HISTORY", "D) ROW_ACCESS_POLICIES"], "chooseN": 1, "correct": ["ACCESS_HISTORY"], "explanation": "The ACCESS_HISTORY view in Snowflake is primarily used to support compliance auditing. This view contains information about historical access and usage patterns related to tables and views within your Snowflake account. It provides details on who accessed the data, when, and from which IP addresses, among other audit-related information.", "reference": "https://docs.snowflake.com/en/sql-reference/account-usage/access_history.html"}, {"id": 739, "area": "Data Loading and Unloading", "question": "How can a Snowflake user load duplicate files with a COPY INTO command?", "options": ["A) The COPY INTO options should be set to PURGE = FALSE", "B) The COPY INTO options should be set to FORCE = TRUE", "C) The COPY INTO options should be set to RETURN_FAILED_ONLY = FALSE", "D) The COPY INTO options should be set to ON_ERROR = CONTINUE"], "chooseN": 1, "correct": ["The COPY INTO options should be set to FORCE = TRUE"], "explanation": "To load duplicate files using the COPY INTO command in Snowflake, the option should be set to FORCE = TRUE. This setting allows the loading of files that may have been previously loaded or skipped, thereby allowing duplicates.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-table.html"}, {"id": 740, "area": "Data Protection and Data Sharing", "question": "What causes objects in a data share to become unavailable to a consumer account?", "options": ["A) The DATA_RETENTION_TIME_IN_DAYS parameter in the consumer account is set to 0.", "B) The consumer account runs the GRANT IMPORTED PRIVILEGES command on the data share every 24 hours.", "C) The objects in the data share are being deleted and the grant pattern is not re-applied systematically.", "D) The consumer account acquires the data share through a private data exchange."], "chooseN": 1, "correct": ["The objects in the data share are being deleted and the grant pattern is not re-applied systematically."], "explanation": "Objects shared through a Snowflake data share can become unavailable to a consumer account if the objects are deleted or if the underlying access grants are changed. To ensure continued access, the grant patterns should be applied systematically, and any changes to permissions or object deletions should be appropriately managed and synchronized between the provider and consumer accounts. Failure to re-apply grant patterns when objects are deleted or access permissions change can result in objects becoming unavailable to the consumer account.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-intro.html"}, {"id": 741, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which statement describes Snowflake tables?", "options": ["A) Snowflake tables are logical representations of underlying physical data.", "B) Snowflake tables are the physical instantiation of data loaded into Snowflake.", "C) Snowflake tables require that clustering keys be defined to perform optimally.", "D) Snowflake tables are owned by a user."], "chooseN": 1, "correct": ["Snowflake tables are logical representations of underlying physical data."], "explanation": "In Snowflake, tables are logical representations of underlying physical data. They provide a structured format for data storage and access but do not physically instantiate the data themselves.", "reference": "https://docs.snowflake.com/en/user-guide/tables-intro.html"}, {"id": 742, "area": "Performance Concepts", "question": "Which type of charts are supported by Snowsight? (Choose two.)", "options": ["A) Flowcharts", "B) Gantt charts", "C) Line charts", "D) Pie charts", "E) Scatterplots"], "chooseN": 2, "correct": ["Line charts", "Scatterplots"], "explanation": "Snow sight supports the following types of charts: Bar charts , Line charts, Scatterplots, Heat grids, Scorecards", "reference": "https://docs.snowflake.com/en/user-guide/ui-snowsight-visualizations"}, {"id": 743, "area": "Data Loading and Unloading", "question": "A user wants to upload a file to an internal Snowflake stage using a PUT command. Which tools and/or connectors could be used to execute this command? (Choose two.)", "options": ["A) SnowCD", "B) SnowSQL", "C) SQL API", "D) Python connector", "E) Snowsight worksheets"], "chooseN": 2, "correct": ["SnowSQL", "Python connector"], "explanation": "SnowCD es una herramienta de diagnóstico de conexión, con Snowsight o con SQL API no se puede https://docs.snowflake.com/en/developer-guide/sql-api/intro#label-sql-api-limitations:", "reference": "https://docs.snowflake.com/en/sql-reference/sql/put"}, {"id": 744, "area": "Data Loading and Unloading", "question": "Which Snowflake table is an implicit object layered on a stage, where the stage can be either internal or external?", "options": ["A) Directory table", "B) Temporary table", "C) Transient table", "D) A table with a materialized view"], "chooseN": 1, "correct": ["Directory table"], "explanation": "A 'Directory table' in Snowflake is an implicit object layered on a stage, which can be either internal or external. Directory tables provide a way to access and query data files directly from stages using standard SQL queries.", "reference": "https://docs.snowflake.com/en/user-guide/tables-directory.html"}, {"id": 745, "area": "Performance Concepts", "question": "(https://civicasoft0.sharepoint.com/:i:/s/EspecialidadSnowflake/EQHdSrIjURhCmjPJUt5h4y0BtMF4iCGd1bU4OHY0_8jx5g?e=rbtAEq  Image needed) The Query Profile in the image is for a query executed in Snowsight. Four of the key nodes are highlighted in yellow. Which highlighted node will be the MOST expensive?", "options": ["A) Aggregate[1]", "B) Join[5]", "C) TableScan[2]", "D) TableScan[3]"], "chooseN": 1, "correct": ["TableScan[3]"], "explanation": "Podemos ver que tiene el porcentaje mayor en la imagen", "reference": "https://docs.snowflake.com/en/user-guide/query-profile.html"}, {"id": 746, "area": "Data Transformations", "question": "What is a characteristic of the maintenance of a materialized view?", "options": ["A) Materialized views cannot be refreshed automatically.", "B) An additional set of scripts is needed to refresh data in materialized views.", "C) A materialized view is automatically refreshed by a Snowflake managed warehouse.", "D) A materialized view can be set up with the auto-refresh feature using the SQL SET command."], "chooseN": 1, "correct": ["A materialized view is automatically refreshed by a Snowflake managed warehouse."], "explanation": "Materialized views are automatically and transparently maintained by Snowflake. A background service updates the materialized view after changes are made to the base table. This is more efficient and less error-prone than manually maintaining the equivalent of a materialized view.", "reference": "https://docs.snowflake.com/en/user-guide/views-materialized.html"}, {"id": 747, "area": "Data Protection and Data Sharing", "question": "Which command should be used to implement a masking policy that was already created in Snowflake?", "options": ["A) ALTER MASKING POLICY", "B) APPLY MASKING POLICY", "C) CREATE MASKING POLICY", "D) SET MASKING POLICY"], "chooseN": 1, "correct": ["ALTER MASKING POLICY"], "explanation": "After a masking policy has already been created, Snowflake uses ALTER MASKING POLICY to manage or modify that policy. The Dynamic Data Masking DDL documentation lists CREATE MASKING POLICY and ALTER MASKING POLICY as the relevant commands for masking policy management. APPLY MASKING POLICY is a priv", "reference": "https://docs.snowflake.com/en/user-guide/security-column-ddm-use"}, {"id": 748, "area": "Data Loading and Unloading", "question": "Which command should be used to unload all the rows from a table into one or more files in a named stage?", "options": ["A) COPY INTO", "B) GET", "C) INSERT INTO", "D) PUT"], "chooseN": 1, "correct": ["COPY INTO"], "explanation": "The 'COPY INTO' command should be used to unload all the rows from a table into one or more files in a named stage in Snowflake. This command allows for efficient exporting of data from tables to files in a stage.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-location.html"}, {"id": 749, "area": "Data Transformations", "question": "Which statement accurately describes a characteristic of a materialized view?", "options": ["A) A materialized view can query only a single table.", "B) Data accessed through materialized views can be stale.", "C) Materialized view refreshes need to be maintained by the user.", "D) Querying a materialized view is slower than executing a query against the base table of the view."], "chooseN": 1, "correct": ["A materialized view can query only a single table."], "explanation": "The correct answer is: A materialized view can query only a single table.. The docs state 'A materialized view can query only a single table' and 'Joins are not supported.' The docs also say 'Data accessed through materialized views is always current.' So data is NEVER stale. The correct answer is A. Reference: https://docs.snowflake.com/en/user-guide/views-materialized#label-limitations-on-creating-materialized-views", "reference": "https://docs.snowflake.com/en/user-guide/views-materialized#label-limitations-on-creating-materialized-views"}, {"id": 750, "area": "Data Transformations", "question": "The use of which Snowflake table type will reduce costs when working with ETL workflows?", "options": ["A) External", "B) Permanent", "C) Temporary", "D) Transient"], "chooseN": 1, "correct": ["Temporary"], "explanation": "Using Temporary tables in Snowflake can help reduce costs in ETL workflows. Temporary tables are session-specific and do not incur storage costs, as they are dropped automatically at the end of the session.", "reference": "https://docs.snowflake.com/en/user-guide/tables-temp-transient.html#temporary-tables"}, {"id": 751, "area": "Data Loading and Unloading", "question": "A user wants to unload data from a relational table into a CSV file in an external stage. The table must be named exactly as specified by the user. Which file format option MUST be used to do this?", "options": ["A) encoding", "B) escape", "C) file_extension", "D) single"], "chooseN": 1, "correct": ["single"], "explanation": "When unloading data from a relational table into a CSV file with a specific name, the 'single' file format option must be used. This option ensures that the output is written to a single file named exactly as specified by the user.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-location.html"}, {"id": 752, "area": "Performance Concepts", "question": "Which account usage view in Snowflake can be used to identify the most-frequently accessed tables?", "options": ["A) Access_History", "B) Object_Dependencies", "C) Table_Storage_Metrics", "D) Tables"], "chooseN": 1, "correct": ["Access_History"], "explanation": "The 'Access_History' account usage view in Snowflake provides information on data access patterns, including the most-frequently accessed tables. This view is useful for performance analysis and optimization.", "reference": "https://docs.snowflake.com/en/sql-reference/account-usage/access_history.html"}, {"id": 753, "area": "Snowflake Data Cloud Features & Architecture", "question": "What metadata does Snowflake store concerning all rows stored in a micro-partition? (Choose two.)", "options": ["A) A count of the number of total values in the micro-partition", "B) The range of values for each partition in the micro-partition", "C) The range of values for each of the rows in the micro-partition", "D) The range of values for each of the columns in the micro-partition", "E) The number of distinct values for each column in the micro-partition"], "chooseN": 2, "correct": ["The range of values for each of the columns in the micro-partition", "The number of distinct values for each column in the micro-partition"], "explanation": "Snowflake stores metadata for micro-partitions that includes the range of values for each of the columns and the number of distinct values for each column. This metadata helps in efficient query processing and data pruning.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions.html"}, {"id": 754, "area": "Account Access and Security", "question": "What role has the privileges to create and manage data shares by default?", "options": ["A) ACCOUNTADMIN", "B) SECURITYADMIN", "C) SYSADMIN", "D) USERADMIN"], "chooseN": 1, "correct": ["ACCOUNTADMIN"], "explanation": "By default, the ACCOUNTADMIN role has the privileges to create and manage data shares in Snowflake. This role is designed for users who need full access to all features and data, including the ability to share data with other accounts.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-provider"}, {"id": 755, "area": "Data Transformations", "question": "Which function determines the kind of value stored in a VARIANT column?", "options": ["A) CHECK_JSON", "B) IS_ARRAY", "C) IS_JSON", "D) TYPEOF"], "chooseN": 1, "correct": ["TYPEOF"], "explanation": "The 'TYPEOF' function in Snowflake determines the kind of value stored in a VARIANT column. It returns a string indicating the data type of the specified expression, which is useful for understanding and handling the diverse data that can be stored in VARIANT columns.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/typeof"}, {"id": 756, "area": "Data Protection and Data Sharing", "question": "What operation can be performed using Time Travel?", "options": ["A) Restoring tables that have been dropped from a data share", "B) Extending a permanent table’s retention duration from 90 to 100 days", "C) Creating a clone of an entire table at a specific point in the past from a permanent table", "D) Disabling Time Travel for a specific object by setting DATA_RETENTION_TIME_IN_DAYS to NULL"], "chooseN": 1, "correct": ["Creating a clone of an entire table at a specific point in the past from a permanent table"], "explanation": "Using Time Travel in Snowflake, one can perform the operation of creating a clone of an entire table at a specific point in the past from a permanent table. Time Travel allows users to access historical data within a defined retention period.", "reference": "https://docs.snowflake.com/en/user-guide/data-time-travel.html"}, {"id": 757, "area": "Data Loading and Unloading", "question": "What are characteristics of Snowflake directory tables? (Choose two.)", "options": ["A) Directory tables are separate database objects.", "B) Directory tables can only be used with an external stage.", "C) Directory tables contain copies of staged files in binary format.", "D) Directory tables store file-level metadata about the data files in a stage.", "E) A directory table can be added to a stage when the stage is created, or later."], "chooseN": 2, "correct": ["Directory tables store file-level metadata about the data files in a stage.", "A directory table can be added to a stage when the stage is created, or later."], "explanation": "Characteristics of Snowflake directory tables include storing file-level metadata about the data files in a stage, and the ability to add a directory table to a stage either when the stage is created or later. Directory tables provide convenient access to metadata of staged files.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-dirtables"}, {"id": 758, "area": "Data Transformations", "question": "What does the VARIANT data type impose a 16 MB size limit on?", "options": ["A) All rows", "B) All columns", "C) Individual rows", "D) Individual columns"], "chooseN": 1, "correct": ["Individual rows"], "explanation": "Está en la documentación literal", "reference": "https://docs.snowflake.com/en/user-guide/semistructured-considerations"}, {"id": 759, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which activities are included in the Cloud Services layer? (Choose two.)", "options": ["A) Data storage", "B) Dynamic data masking", "C) Partition scanning", "D) User authentication", "E) Infrastructure management"], "chooseN": 2, "correct": ["User authentication", "Infrastructure management"], "explanation": "In Snowflake's Cloud Services layer, various activities are managed effectively. These include Authentication, Infrastructure Management, Metadata Management, Query Parsing and Optimization, Access Control, and more.", "reference": "https://docs.snowflake.com/en/user-guide/intro-key-concepts.html#cloud-services-layer"}, {"id": 760, "area": "Performance Concepts", "question": "What does the 'percentage scanned from cache' represent in the Query Profile?", "options": ["A) The percentage of data scanned from the query cache", "B) The percentage of data scanned from the result cache", "C) The percentage of data scanned from the remote disk cache", "D) The percentage of data scanned from the local disk cache"], "chooseN": 1, "correct": ["The percentage of data scanned from the local disk cache"], "explanation": "Percentage scanned from cache — the percentage of data scanned from the local disk cache.", "reference": "https://docs.snowflake.com/en/user-guide/ui-query-profile"}, {"id": 761, "area": "Data Protection and Data Sharing", "question": "Which role has the ability to create a share from a shared database by default?", "options": ["A) ACCOUNTADMIN", "B) SECURITYADMIN", "C) SYSADMIN", "D) ORGADMIN"], "chooseN": 1, "correct": ["ACCOUNTADMIN"], "explanation": "The ACCOUNTADMIN role in Snowflake has the ability to create a share from a shared database by default. This role is provided with the highest level of privileges, including the management of data sharing.", "reference": "https://docs.snowflake.com/en/user-guide/data-share-consumers"}, {"id": 762, "area": "Performance Concepts", "question": "Which object-level parameters can be set to help control query processing and concurrency? (Choose two).", "options": ["A) MAX_CONCURRENCY_LEVEL", "B) DATA_RETENTION_TIME_IN_DAYS", "C) MIN_DATA_RETENTION_TIME_IN_DAYS", "D) STATEMENT_TIMEOUT_IN_SECONDS", "E) STATEMENT_QUEUED_TIMEOUT_IN_SECONDS"], "chooseN": 2, "correct": ["STATEMENT_TIMEOUT_IN_SECONDS", "STATEMENT_QUEUED_TIMEOUT_IN_SECONDS"], "explanation": "- STATEMENT_TIMEOUT_IN_SECONDS: Este parámetro permite controlar el tiempo máximo que una consulta puede ejecutarse antes de ser terminada, ayudando a gestionar la concurrencia y procesamiento de consultas.\n- STATEMENT_QUEUED_TIMEOUT_IN_SECONDS: Este parámetro controla el tiempo máximo que una consulta puede estar en cola antes de ser descartada, gestionando la concurrencia a nivel de objeto.\n- MAX_CONCURRENCY_LEVEL: Este parámetro controla el nivel máximo de concurrencia a nivel de warehouse, no a nivel de objeto.\n- DATA_RETENTION_TIME_IN_DAYS y MIN_DATA_RETENTION_TIME_IN_DAYS: Estos parámetros se relacionan con la retención de datos, no con el procesamiento o concurrencia de consultas.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-overview"}, {"id": 763, "area": "Snowflake Data Cloud Features & Architecture", "question": "What metadata does Snowflake store for rows in micro-partitions? (Choose two.)", "options": ["A) Range of values", "B) Distinct values", "C) Index values", "D) Sorted values", "E) Null values"], "chooseN": 2, "correct": ["Range of values", "Distinct values"], "explanation": "Snowflake stores metadata for rows in micro-partitions including the 'Range of values' and 'Distinct values'. This metadata is used for optimizing query performance through efficient data pruning and access strategies.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions.html"}, {"id": 764, "area": "Data Transformations", "question": "What are valid sub-clauses to the OVER clause for a window function? (Choose two.)", "options": ["A) GROUP BY", "B) LIMIT", "C) ORDER BY", "D) PARTITION BY", "E) UNION ALL"], "chooseN": 2, "correct": ["ORDER BY", "PARTITION BY"], "explanation": "The valid sub-clauses to the OVER clause for a window function in Snowflake are 'ORDER BY' and 'PARTITION BY'. These clauses are used to define the window over which the function operates, with 'PARTITION BY' dividing the data into subsets and 'ORDER BY' specifying the order within each partition.", "reference": "https://docs.snowflake.com/en/sql-reference/functions-analytic.html"}, {"id": 765, "area": "Data Loading and Unloading", "question": "Which kind of Snowflake table stores file-level metadata for each file in a stage?", "options": ["A) Directory", "B) External", "C) Temporary", "D) Transient"], "chooseN": 1, "correct": ["Directory"], "explanation": "A 'Directory' table in Snowflake stores file-level metadata for each file in a stage. Directory tables allow users to query metadata about files stored in stages, providing insights into the data available for loading and processing.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-dirtables"}, {"id": 766, "area": "Data Transformations", "question": "Which privileges apply to stored procedures? (Choose two.)", "options": ["A) MODIFY", "B) MONITOR", "C) OPERATE", "D) OWNERSHIP", "E) USAGE"], "chooseN": 2, "correct": ["OWNERSHIP", "USAGE"], "explanation": "The privileges that apply to stored procedures in Snowflake are 'OWNERSHIP' and 'USAGE'. The 'OWNERSHIP' privilege allows a user to manage the stored procedure, while the 'USAGE' privilege allows a user to execute the stored procedure.", "reference": "https://docs.snowflake.com/en/sql-reference/stored-procedures-usage.html"}, {"id": 767, "area": "Data Transformations", "question": "What column type does a Kafka connector store formatted information in a single column?", "options": ["A) ARRAY", "B) OBJECT", "C) VARCHAR", "D) VARIANT"], "chooseN": 1, "correct": ["VARIANT"], "explanation": "A Kafka connector in Snowflake stores formatted information in a single column of type 'VARIANT'. The VARIANT data type is capable of holding semi-structured data, making it suitable for storing complex data structures like those typically handled by Kafka connectors.", "reference": "https://docs.snowflake.com/en/user-guide/kafka-connector-overview"}, {"id": 768, "area": "Performance Concepts", "question": "If a size Small virtual warehouse costs two credits per hour, what is the credit cost per hour of a size Large virtual warehouse?", "options": ["A) 4", "B) 8", "C) 16", "D) 32"], "chooseN": 1, "correct": ["8"], "explanation": "In Snowflake, the credit cost of virtual warehouses scales linearly with their size. If a size Small virtual warehouse costs two credits per hour, a size Large virtual warehouse, which is two sizes larger, would cost eight credits per hour (as each size increase doubles the credit cost).", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-considerations.html#warehouse-size-and-credit-usage"}, {"id": 769, "area": "Data Loading and Unloading", "question": "Which SQL command will list the files in a named stage?", "options": ["A) list @~;", "B) get @%mytable;", "C) list @my_stage;", "D) get @my_stage;"], "chooseN": 1, "correct": ["list @my_stage;"], "explanation": "The 'list @my_stage;' SQL command in Snowflake is used to list the files in a named stage. This command provides an overview of the files available in the specified stage for loading or other operations.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/list.html"}, {"id": 770, "area": "Performance Concepts", "question": "What is the effect of configuring a virtual warehouse auto-suspend value to '0'?", "options": ["A) The warehouse will never suspend.", "B) The warehouse will suspend immediately upon work completion.", "C) The warehouse will not resume automatically.", "D) All clusters in the multi-cluster warehouse will resume immediately."], "chooseN": 1, "correct": ["The warehouse will never suspend."], "explanation": "Setting a 0 or NULL value means the warehouse never suspends.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/alter-warehouse"}, {"id": 771, "area": "Data Loading and Unloading", "question": "Which data types can be used in Snowflake to store semi-structured data? (Choose two.)", "options": ["A) ARRAY", "B) BLOB", "C) CLOB", "D) JSON", "E) VARIANT"], "chooseN": 2, "correct": ["ARRAY", "VARIANT"], "explanation": "EN snowflake para datos semi estructurados tenemos los tipos de dato VARIANT, ARRAY y OBJECT.", "reference": "https://docs.snowflake.com/en/sql-reference/data-types-semistructured"}, {"id": 772, "area": "Data Loading and Unloading", "question": "While attempting to avoid data duplication, which COPY INTO option should be used to load files with expired load metadata?", "options": ["A) LOAD_UNCERTAIN_FILES", "B) FORCE", "C) VALIDATION_MODE", "D) LAST_MODIFIED"], "chooseN": 1, "correct": ["LOAD_UNCERTAIN_FILES"], "explanation": "To load files whose metadata has expired, set the LOAD_UNCERTAIN_FILES copy option to true. The copy option references load metadata, if available, to avoid data duplication, but also attempts to load files with expired load metadata.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-considerations-load"}, {"id": 773, "area": "Account Access and Security", "question": "What service is provided as an integrated Snowflake feature to enhance Multi-Factor Authentication (MFA) support?", "options": ["A) Duo Security", "B) OAuth", "C) Okta", "D) Single Sign-On (SSO)"], "chooseN": 1, "correct": ["Duo Security"], "explanation": "MFA provides increased login security for users connecting to Snowflake. MFA support is provided as an integrated Snowflake feature, powered by the Duo Security service, which is managed completely by Snowflake.", "reference": "https://docs.snowflake.com/en/user-guide/admin-security-mfa-duo.html"}, {"id": 774, "area": "Performance Concepts", "question": "What is the impact on queries that are being executed when a resource monitor set to the 'Notify & Suspend' threshold level is exceeded?", "options": ["A) All statements being executed are queued.", "B) All statements being executed are restarted.", "C) All statements being executed are cancelled.", "D) All statements being executed are completed."], "chooseN": 1, "correct": ["All statements being executed are completed."], "explanation": "Send a notification (to all account administrators with notifications enabled) and suspend all assigned warehouses after all statements being executed by the warehouse(s) have completed.", "reference": "https://docs.snowflake.com/en/user-guide/resource-monitors.html"}, {"id": 775, "area": "Data Protection and Data Sharing", "question": "What tasks can an account administrator perform in the Data Exchange? (Choose two.)", "options": ["A) Add and remove members.", "B) Delete data categories.", "C) Approve and deny listing approval requests.", "D) Transfer listing ownership.", "E) Transfer ownership of a provider profile."], "chooseN": 2, "correct": ["Approve and deny listing approval requests.", "Add and remove members."], "explanation": "By default, only an account administrator (a user with the ACCOUNTADMIN role) in the Data Exchange administrator account can manage a Data Exchange, which includes the following tasks: Add or remove members. Approve or deny listing approval requests. Approve or deny provider profile approval requests.", "reference": "https://docs.snowflake.com/en/user-guide/data-exchange-marketplace-privileges"}, {"id": 776, "area": "Data Transformations", "question": "Which types of subqueries does Snowflake support? (Choose two.)", "options": ["A) Uncorrelated scalar subqueries in WHERE clauses", "B) Uncorrelated scalar subqueries in any place that a value expression can be used", "C) EXISTS, ANY / ALL, and IN subqueries in WHERE clauses: these subqueries can be uncorrelated only", "D) EXISTS, ANY / ALL, and IN subqueries in WHERE clauses: these subqueries can be correlated only", "E) EXISTS, ANY / ALL, and IN subqueries in WHERE clauses: these subqueries can be correlated or uncorrelated"], "chooseN": 2, "correct": ["Uncorrelated scalar subqueries in any place that a value expression can be used", "EXISTS, ANY / ALL, and IN subqueries in WHERE clauses: these subqueries can be correlated or uncorrelated"], "explanation": "Snowflake supports uncorrelated scalar subqueries in any location where a value expression is valid, as well as EXISTS, ANY/ALL, and IN subqueries in WHERE clauses, which can be either correlated or uncorrelated. This flexibility allows for a wide range of query designs and data manipulations.", "reference": "https://docs.snowflake.com/en/user-guide/querying-subqueries"}, {"id": 777, "area": "Account Access and Security", "question": "How can network and private connectivity security be managed in Snowflake?", "options": ["A) By setting up network policies with IPv4 IP addresses", "B) By putting the Snowflake URL on the allowed list for get method responses", "C) By manually setting up vulnerability patch management policies", "D) By manually setting up an Intrusion Prevention System (IPS) on each account"], "chooseN": 1, "correct": ["By setting up network policies with IPv4 IP addresses"], "explanation": "In Snowflake, network and private connectivity security can be managed by setting up network policies that specify allowed IPv4 IP addresses. This ensures that only authorized users from specified IP addresses can access the Snowflake account, enhancing security.", "reference": "https://docs.snowflake.com/en/user-guide/network-policies.html"}, {"id": 778, "area": "Data Loading and Unloading", "question": "What consideration should be made when loading data into Snowflake?", "options": ["A) Create small data files and stage them in cloud storage frequently.", "B) Create large data files to maximize the processing overhead for each file.", "C) The number of load operations that run in parallel can exceed the number of data files to be loaded.", "D) The number of data files that are processed in parallel is determined by the virtual warehouse."], "chooseN": 1, "correct": ["The number of data files that are processed in parallel is determined by the virtual warehouse."], "explanation": "When loading data into Snowflake, it's important to understand that the number of data files processed in parallel is determined by the size and configuration of the virtual warehouse. This affects the efficiency and speed of data loading operations.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-considerations-prepare.html"}, {"id": 779, "area": "Performance Concepts", "question": "How can a user improve the performance of a single large complex query in Snowflake?", "options": ["A) Scale up the virtual warehouse.", "B) Scale out the virtual warehouse.", "C) Enable standard warehouse scaling.", "D) Enable economy warehouse scaling."], "chooseN": 1, "correct": ["Scale up the virtual warehouse."], "explanation": "Scaling up the virtual warehouse in Snowflake increases the compute resources available for processing queries, which can significantly improve the performance of a single large complex query.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-considerations"}, {"id": 780, "area": "Data Protection and Data Sharing", "question": "Who can access a referenced file through a scoped URL?", "options": ["A) Only the ACCOUNTADMIN", "B) Only the user who generates the URL", "C) Any role specified in the GET REST API call with sufficient privileges", "D) Any user specified in the GET REST API call with sufficient privileges"], "chooseN": 1, "correct": ["Only the user who generates the URL"], "explanation": "The correct answer is: Only the user who generates the URL. The scoped URL authorization docs state: 'Only the user who generates a scoped URL can use the URL to access the referenced file.' Option D describes File URL behavior. The correct answer is B. Reference: https://docs.snowflake.com/en/user-guide/unstructured-intro", "reference": "https://docs.snowflake.com/en/user-guide/unstructured-intro"}, {"id": 781, "area": "Data Protection and Data Sharing", "question": "Snowflake will return an error when a user attempts to share which object?", "options": ["A) Tables", "B) Secure views", "C) Standard views", "D) Secure materialized views"], "chooseN": 1, "correct": ["Standard views"], "explanation": "For data security and privacy reasons, only secure views are supported in shares at this time. If a standard view is added to a share, Snowflake returns an error.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-provider"}, {"id": 782, "area": "Account Access and Security", "question": "What setting in Snowsight determines the databases, tables, and other objects that can be seen and the actions that can be performed on them?", "options": ["A) Active role", "B) Masking policy", "C) Column-level security", "D) Multi-Factor Authentication (MFA)"], "chooseN": 1, "correct": ["Active role"], "explanation": "The 'Active role' setting in Snowsight determines the databases, tables, and other objects that a user can see and the actions they can perform. This setting reflects the user's current role and its associated privileges in Snowflake.", "reference": "https://docs.snowflake.com/en/user-guide/ui-snowsight-gs"}, {"id": 783, "area": "Data Transformations", "question": "Why would a Snowflake user decide to use a materialized view instead of a regular view?", "options": ["A) The base tables do not change frequently.", "B) The results of the view change often.", "C) The query is not resource intensive.", "D) The query results are not used frequently."], "chooseN": 1, "correct": ["The base tables do not change frequently."], "explanation": "A Snowflake user would choose to use a materialized view instead of a regular view when the base tables do not change frequently. Materialized views store pre-computed results and are best suited for scenarios where the underlying data remains relatively static.", "reference": "https://docs.snowflake.com/en/user-guide/views-materialized.html"}, {"id": 784, "area": "Data Protection and Data Sharing", "question": "When a database is cloned, which objects in the clone inherit all granted privileges from the source object? (Choose two.)", "options": ["A) Account", "B) Database", "C) Schemas", "D) Tables", "E) Internal named stages"], "chooseN": 2, "correct": ["Schemas", "Tables"], "explanation": "In Snowflake, when a database is cloned, the schemas and tables within the clone inherit all the granted privileges from their counterparts in the source database. This ensures consistency in access control for cloned databases.", "reference": "https://docs.snowflake.com/en/user-guide/object-clone"}, {"id": 785, "area": "Account Access and Security", "question": "How does the Access_History view enhance overall data governance pertaining to read and write operations? (Choose two.)", "options": ["A) Shows how the accessed data was moved from the source to the target objects", "B) Provides a unified picture of what data was accessed and when it was accessed", "C) Protects sensitive data from unauthorized access while allowing authorized users to access it at query runtime", "D) Identifies columns with personal information and tags them so masking policies can be applied to protect sensitive data", "E) Determines whether a given row in a table can be accessed by the user by filtering the data based on a given policy"], "chooseN": 2, "correct": ["Shows how the accessed data was moved from the source to the target objects", "Provides a unified picture of what data was accessed and when it was accessed"], "explanation": "The ACCESS_HISTORY view enhances data governance by: (1) Providing a unified picture of what data was accessed and when, through its tracking of read and write operations. (2) Showing how accessed data was moved from source to target objects through the base_objects_accessed and direct_objects_accessed columns, enabling data lineage tracking. Masking policies and row-level security are separate governance features not provided by Access History.", "reference": "https://docs.snowflake.com/en/user-guide/access-history"}, {"id": 786, "area": "Snowflake Data Cloud Features & Architecture", "question": "What does Snowflake recommend a user do if they need to connect to Snowflake with a tool or technology that is not listed in Snowflake’s partner ecosystem?", "options": ["A) Use Snowflake’s native API.", "B) Use a custom-built connector.", "C) Contact Snowflake Support for a new driver.", "D) Connect through Snowflake’s JDBC or ODBC drivers."], "chooseN": 1, "correct": ["Connect through Snowflake’s JDBC or ODBC drivers."], "explanation": "Snowflake recommends using its JDBC or ODBC drivers for connecting with tools or technologies not listed in its partner ecosystem. These drivers provide a standard method of connecting to Snowflake, ensuring compatibility and reliability.", "reference": "https://docs.snowflake.com/en/user-guide/ecosystem-all"}, {"id": 787, "area": "Data Loading and Unloading", "question": "What is the expiration period for a file URL used to access unstructured data in cloud storage?", "options": ["A) The remainder of the session", "B) An unlimited amount of time", "C) The length of time specified in the expiration_time argument", "D) The same length of time as the expiration period for the query results cache"], "chooseN": 1, "correct": ["An unlimited amount of time"], "explanation": "A File URL provides permanent access to a file on a stage and does not expire. It is generated using BUILD_STAGE_FILE_URL. To access the file, users send the File URL in a GET request to the REST API endpoint along with an authorization token. In contrast, a Pre-signed URL provides temporary access with a configurable expiration time, and a Scoped URL provides temporary user-based access for 24 hours.", "reference": "https://docs.snowflake.com/en/user-guide/unstructured-intro"}, {"id": 788, "area": "Account Access and Security", "question": "Which applications can use key pair authentication? (Choose two).", "options": ["A) Snowflake Marketplace", "B) SnowCD", "C) Snowsight", "D) SnowSQL", "E) Snowflake connector for Python"], "chooseN": 2, "correct": ["SnowSQL", "Snowflake connector for Python"], "explanation": "Key pair authentication in Snowflake can be used with SnowSQL and the Snowflake connector for Python. This method of authentication provides an additional layer of security for accessing Snowflake services through these applications.", "reference": "https://docs.snowflake.com/en/user-guide/key-pair-auth"}, {"id": 789, "area": "Data Loading and Unloading", "question": "Which commands can only be executed using SnowSQL? (Choose two.)", "options": ["A) COPY INTO", "B) GET", "C) LIST", "D) PUT", "E) REMOVE"], "chooseN": 2, "correct": ["GET", "PUT"], "explanation": "The 'GET' and 'PUT' commands are specific to SnowSQL and are used for transferring data files between local file systems and Snowflake stages. They cannot be executed through the standard Snowflake web interface or other SQL client tools.", "reference": "https://docs.snowflake.com/en/user-guide/snowsql.html"}, {"id": 790, "area": "Data Transformations", "question": "A user has enabled the STRIP_OUTER_ARRAY file format option for the COPY INTO {table} command to remove the outer array structure. What else will this format option and command do?", "options": ["A) Load the records into separate table rows.", "B) Unload the records from separate table rows.", "C) Export data files in smaller chunks.", "D) Ensure each unique element stores values of a single native data type."], "chooseN": 1, "correct": ["Load the records into separate table rows."], "explanation": "The STRIP_OUTER_ARRAY file format option in the COPY INTO command will load each element of the outer JSON array as a separate row in the target table. This is useful when dealing with JSON data structured as an array of records.", "reference": "https://docs.snowflake.com/en/user-guide/semistructured-considerations"}, {"id": 791, "area": "Data Protection and Data Sharing", "question": "Which objects will incur storage costs associated with Fail-safe?", "options": ["A) External tables", "B) Permanent tables", "C) Data files available in internal stages", "D) Data files available in external stages"], "chooseN": 1, "correct": ["Permanent tables"], "explanation": "In Snowflake, Fail-safe is a data protection feature that incurs storage costs for permanent tables. Fail-safe provides an additional layer of data protection by retaining historical data for a period beyond the Time Travel retention period.", "reference": "https://docs.snowflake.com/en/user-guide/cost-understanding-data-storage"}, {"id": 792, "area": "Performance Concepts", "question": "What technique does Snowflake use to limit the number of micro-partitions scanned by each query?", "options": ["A) B-tree", "B) Indexing", "C) Map reduce", "D) Pruning"], "chooseN": 1, "correct": ["Pruning"], "explanation": "Snowflake uses a technique called 'pruning' to limit the number of micro-partitions scanned by each query. Pruning involves using metadata about the data stored in each micro-partition to skip over partitions that do not contain relevant data, thereby improving query performance.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions"}, {"id": 793, "area": "Account Access and Security", "question": "What activities can a user with the ORGADMIN role perform? (Choose two.)", "options": ["A) Create INFORMATION_SCHEMA in a database.", "B) View usage information for all accounts in the organization.", "C) Enable database cloning for an account in the organization.", "D) Enable database replication for an account in the organization.", "E) View micro-partition information for all accounts in the organization."], "chooseN": 2, "correct": ["View usage information for all accounts in the organization.", "Enable database replication for an account in the organization."], "explanation": "A user with the ORGADMIN role in Snowflake can view usage information for all accounts in the organization and enable database replication for an account in the organization. This role is designed for managing and overseeing multiple accounts within an organization. Creating INFORMATION_SCHEMA, enabling database cloning, and viewing micro-partition information are not ORGADMIN capabilities.", "reference": "https://docs.snowflake.com/en/user-guide/organizations"}, {"id": 794, "area": "Account Access and Security", "question": "In a managed access schema, who can grant privileges on objects in the schema to other roles? (Choose two.)", "options": ["A) The schema owner role", "B) The ORGADMIN system role", "C) The USERADMIN system role", "D) The role with the MANAGE GRANTS privilege", "E) The role that owns the object in the schema"], "chooseN": 2, "correct": ["The schema owner role", "The role with the MANAGE GRANTS privilege"], "explanation": "In a managed access schema within Snowflake, the schema owner role and any role with the MANAGE GRANTS privilege have the authority to grant privileges on objects in the schema to other roles. This allows for controlled access management within the schema.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-overview"}, {"id": 795, "area": "Performance Concepts", "question": "What are the recommended steps to address poor SQL query performance due to data spilling? (Choose two.)", "options": ["A) Clone the base table.", "B) Fetch required attributes only.", "C) Use a larger virtual warehouse.", "D) Process the data in smaller batches.", "E) Add another cluster in the virtual warehouse."], "chooseN": 2, "correct": ["Use a larger virtual warehouse.", "Process the data in smaller batches."], "explanation": "To address poor SQL query performance in Snowflake due to data spilling, it's recommended to use a larger virtual warehouse and process the data in smaller batches. These steps can help manage the workload and improve query performance.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-tasks.html#managing-warehouse-performance"}, {"id": 796, "area": "Data Protection and Data Sharing", "question": "A Snowflake user wants to share unstructured data through the use of secure views. Which URL types can be used? (Choose two.)", "options": ["A) Scoped URL", "B) HTTPS URL", "C) Cloud storage URL", "D) File URL", "E) Pre-signed URL"], "chooseN": 2, "correct": ["Scoped URL", "Pre-signed URL"], "explanation": "Te da esas dos opciones en la doc", "reference": "https://docs.snowflake.com/en/user-guide/unstructured-data-sharing"}, {"id": 797, "area": "Data Protection and Data Sharing", "question": "What are characteristics of reader accounts in Snowflake? (Choose two.)", "options": ["A) Reader account users cannot add new data to the account.", "B) Reader account users can share data to other reader accounts.", "C) A single reader account can consume data from multiple provider accounts.", "D) Data consumers are responsible for reader account setup and data usage costs.", "E) Reader accounts enable data consumers to access and query data shared by the provider."], "chooseN": 2, "correct": ["Reader account users cannot add new data to the account.", "Reader accounts enable data consumers to access and query data shared by the provider."], "explanation": "Reader account belongs to the provider account who created it, it cannot consume data from multiple provider account", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-reader-create"}, {"id": 798, "area": "Data Protection and Data Sharing", "question": "Why should a Snowflake user configure a secure view? (Choose two.)", "options": ["A) To encrypt the data in transit", "B) To execute faster than a standard view", "C) To protect hidden data from other users", "D) To improve the performance of a query", "E) To hide the view definition from other users"], "chooseN": 2, "correct": ["To protect hidden data from other users", "To hide the view definition from other users"], "explanation": "Configuring a secure view in Snowflake is important to protect hidden data from other users and to hide the view definition from unauthorized access. This ensures data security and maintains the confidentiality of sensitive information.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/create-view.html#secure-views"}, {"id": 799, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which activities are managed by Snowflake’s Cloud Services layer? (Choose two.)", "options": ["A) Authentication", "B) Access delegation", "C) Data pruning", "D) Data compression", "E) Query parsing and optimization"], "chooseN": 2, "correct": ["Authentication", "Query parsing and optimization"], "explanation": "The Cloud Services layer in Snowflake manages activities including authentication and query parsing and optimization. Authentication is crucial for security, while query parsing and optimization are essential for efficient query execution.", "reference": "https://docs.snowflake.com/en/user-guide/intro-key-concepts.html"}, {"id": 800, "area": "Data Loading and Unloading", "question": "The COPY INTO command can unload data from a table directly into which locations? (Choose two.)", "options": ["A) A named internal stage", "B) A Snowpipe REST endpoint", "C) A network share on a client machine", "D) A local directory or folder on a client machine", "E) A named external stage that references an external cloud location"], "chooseN": 2, "correct": ["A named internal stage", "A named external stage that references an external cloud location"], "explanation": "The COPY INTO command in Snowflake can be used to unload data directly into a named internal stage and a named external stage that references an external cloud location. These options facilitate efficient data export and integration with cloud storage services.", "reference": "https://docs.snowflake.com/en/user-guide/data-unload-considerations.html"}, {"id": 801, "area": "Account Access and Security", "question": "What does the Activity area of Snowsight allow users to do? (Choose two.)", "options": ["A) Schedule automated data backups.", "B) Explore each step of an executed query.", "C) Monitor queries executed by users in an account.", "D) Create and manage user roles and permissions.", "E) Access Snowflake Marketplace to find and integrate datasets."], "chooseN": 2, "correct": ["Explore each step of an executed query.", "Monitor queries executed by users in an account."], "explanation": "In Snowsight's Activity area, users can explore each step of an executed query and monitor queries executed by users in an account. These features provide insights into query performance and user activity, enhancing database management and optimization.", "reference": "https://docs.snowflake.com/en/user-guide/ui-snowsight.html"}, {"id": 802, "area": "Account Access and Security", "question": "In which Snowsight section can a user switch roles, modify their profile, and access documentation?", "options": ["A) The user menu", "B) The activity page", "C) The content pane", "D) The worksheets page"], "chooseN": 1, "correct": ["The user menu"], "explanation": "In Snowsight, the user menu is the section where users can switch roles, modify their profile, and access documentation. This centralized location allows for easy navigation and management of personal and account settings.", "reference": "https://docs.snowflake.com/en/user-guide/ui-snowsight.html"}, {"id": 803, "area": "Data Loading and Unloading", "question": "What is the recommended way to change the existing file format type in my_format from CSV to JSON?", "options": ["A) ALTER FILE FORMAT my_format SET TYPE=JSON;", "B) ALTER FILE FORMAT my_format SWAP TYPE WITH JSON;", "C) CREATE OR REPLACE FILE FORMAT my_format TYPE=JSON;", "D) REPLACE FILE FORMAT my_format TYPE=JSON;"], "chooseN": 1, "correct": ["CREATE OR REPLACE FILE FORMAT my_format TYPE=JSON;"], "explanation": "The recommended way to change an existing file format type from CSV to JSON in Snowflake is to use the 'CREATE OR REPLACE FILE FORMAT my_format TYPE=JSON;' command. This command creates a new file format or replaces an existing one with the specified settings.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/create-file-format.html"}, {"id": 804, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which features are included in Snowsight? (Choose two.)", "options": ["A) Worksheet sharing", "B) Referencing SnowSQL", "C) Exploring the Snowflake Marketplace", "D) Changing the Snowflake account cloud provider", "E) Downloading query result data larger than 100 MB"], "chooseN": 2, "correct": ["Worksheet sharing", "Exploring the Snowflake Marketplace"], "explanation": "En Snowsight podemos compartir worksheets y explorar el marketplace, podemos descargar resultados de queries, pero no tan grandes.", "reference": "https://docs.snowflake.com/en/user-guide/ui-snowsight-quick-tourl"}, {"id": 805, "area": "Data Protection and Data Sharing", "question": "How long can a data consumer who has a pre-signed URL access data files using Snowflake?", "options": ["A) Indefinitely", "B) Until the result_cache expires", "C) Until the retention_time is met", "D) Until the expiration_time is exceeded"], "chooseN": 1, "correct": ["Until the expiration_time is exceeded"], "explanation": "In Snowflake, a data consumer who has a pre-signed URL can access data files until the expiration_time defined for that URL is exceeded. This allows for controlled, temporary access to the data.", "reference": "https://docs.snowflake.com/en/user-guide/unstructured-intro"}, {"id": 806, "area": "Data Loading and Unloading", "question": "What mechanisms can be used to inform Snowpipe that there are staged files available to load into a Snowflake table? (Choose two.)", "options": ["A) Cloud messaging", "B) Email integrations", "C) Error notifications", "D) REST endpoints", "E) Snowsight interactions"], "chooseN": 2, "correct": ["Cloud messaging", "REST endpoints"], "explanation": "Snowpipe can be notified of staged files available for loading into a Snowflake table through cloud messaging services and REST endpoints. These mechanisms facilitate automated and efficient data loading processes.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-snowpipe-intro"}, {"id": 807, "area": "Data Loading and Unloading", "question": "A Snowflake user needs to import a JSON file larger than 16 MB. What file format option could be used?", "options": ["A) trim_space = true", "B) compression = auto", "C) strip_outer_array = true", "D) strip_outer_array = false"], "chooseN": 1, "correct": ["strip_outer_array = true"], "explanation": "For importing a JSON file larger than 16 MB into Snowflake, using the file format option 'strip_outer_array = true' is effective. This option helps in processing large JSON files that are structured as an array of JSON objects.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-considerations-prepare#semi-structured-data-size-limitations"}, {"id": 808, "area": "Account Access and Security", "question": "What is a feature of column-level security in Snowflake?", "options": ["A) Role access policies", "B) Network policies", "C) Internal tokenization", "D) External tokenization"], "chooseN": 1, "correct": ["External tokenization"], "explanation": "Actualmente, Column-level Security en Snowflake incluye dos caracteristicas: Dynamic Data Masking y External Tokenization. La External Tokenization tokeniza datos sensibles antes de cargarlos y los desencripta en tiempo de consulta mediante politicas de enmascaramiento con funciones externas. Role access policies, Network policies e Internal tokenization no son caracteristicas de column-level security.", "reference": "https://docs.snowflake.com/user-guide/security-column-intro#what-is-column-level-security"}, {"id": 809, "area": "Performance Concepts", "question": "Which common query problems can the Query Profile help a user identify and troubleshoot? (Choose two.)", "options": ["A) When window functions are used incorrectly", "B) When there are exploding joins", "C) When there is a UNION without ALL", "D) When the SELECT DISTINCT command returns too many values", "E) When there are Common Table Expressions (CTEs) without a final SELECT statement"], "chooseN": 2, "correct": ["When there are exploding joins", "When there is a UNION without ALL"], "explanation": "The Query Profile in Snowflake can help identify and troubleshoot issues such as exploding joins, which occur when a join operation results in a large increase in row count, and also if you forget to put the UNION ALL. Many other things too, interesting blog down below.", "reference": "https://docs.snowflake.com/en/user-guide/ui-query-profile"}, {"id": 810, "area": "Data Protection and Data Sharing", "question": "What is the Fail-safe retention period for transient and temporary tables?", "options": ["A) 0 days", "B) 1 day", "C) 7 days", "D) 90 days"], "chooseN": 1, "correct": ["0 days"], "explanation": "The Fail-safe retention period for transient and temporary tables in Snowflake is 0 days. These types of tables do not have a Fail-safe period, unlike permanent tables, which have a default Fail-safe period.", "reference": "https://docs.snowflake.com/en/user-guide/tables-temp-transient"}, {"id": 811, "area": "Account Access and Security", "question": "Which Snowflake features can be enabled by calling the SYSTEM$GLOBAL_ACCOUNT_SET_PARAMETER function by a user with the ORGADMIN role? (Choose two.)", "options": ["A) Clustering", "B) Client redirect", "C) Fail-safe", "D) Search optimization service", "E) Account and database replication"], "chooseN": 2, "correct": ["Client redirect", "Account and database replication"], "explanation": "Viene directamente en la doc, esta es de aprendérsela literal", "reference": "https://docs.snowflake.com/en/sql-reference/functions/system_global_account_set_parameter"}, {"id": 812, "area": "Data Loading and Unloading", "question": "What are characteristics of directory tables when used with unstructured data? (Choose two.)", "options": ["A) Only cloud storage stages support directory tables.", "B) Each directory table has grantable privileges of its own.", "C) Directory tables store a catalog of staged files in cloud storage.", "D) A directory table can be added explicitly to a stage when the stage is created.", "E) A directory table is a separate database object that can be layered explicitly on a stage."], "chooseN": 2, "correct": ["Directory tables store a catalog of staged files in cloud storage.", "A directory table can be added explicitly to a stage when the stage is created."], "explanation": "Directory tables when used with unstructured data have these characteristics: they store a catalog of staged files in cloud storage, and they can be added explicitly to a stage when the stage is created using DIRECTORY = (ENABLE = TRUE). Directory tables are NOT separate database objects; they are implicit objects layered on a stage. Both internal and external stages support directory tables, and they do not have grantable privileges of their own.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-dirtables#what-is-a-directory-table"}, {"id": 813, "area": "Account Access and Security", "question": "Snowflake best practice recommends that which role be used to enforce a network policy on a Snowflake account?", "options": ["A) ACCOUNTADMIN", "B) SECURITYADMIN", "C) SYSADMIN", "D) USERADMIN"], "chooseN": 1, "correct": ["SECURITYADMIN"], "explanation": "Snowflake best practices recommend using the SECURITYADMIN role to enforce a network policy on a Snowflake account. This role is specifically designed to manage security-related aspects of the account, including network policies.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/create-network-policy"}, {"id": 814, "area": "Data Loading and Unloading", "question": "What is the default behavior of internal stages in Snowflake?", "options": ["A) Named internal stages are created by default.", "B) Users must manually create their own internal stages.", "C) Data files are automatically staged to a default location.", "D) Each user and table are automatically allocated an internal stage."], "chooseN": 1, "correct": ["Each user and table are automatically allocated an internal stage."], "explanation": "In Snowflake, each user and table is automatically allocated an internal stage by default. This feature simplifies the process of staging data files for loading and unloading operations.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-local-file-system-create-stage.html"}, {"id": 815, "area": "Performance Concepts", "question": "The MAXIMUM size for a serverless task run is equivalent to what size virtual warehouse?", "options": ["A) Medium", "B) Large", "C) 2X-Large", "D) 4X-Large"], "chooseN": 1, "correct": ["2X-Large"], "explanation": "The maximum size for a serverless task run in Snowflake is equivalent to a 2X-Large virtual warehouse. This provides a balance between computing power and resource allocation for optimal task execution.", "reference": "https://docs.snowflake.com/en/user-guide/tasks-intro#label-billing-task-runs"}, {"id": 816, "area": "Data Loading and Unloading", "question": "What storage cost is completely eliminated when a Snowflake table is defined as transient?", "options": ["A) Active", "B) Fail-safe", "C) Staged", "D) Time Travel"], "chooseN": 1, "correct": ["Fail-safe"], "explanation": "When a Snowflake table is defined as transient, the storage cost associated with fail-safe storage is completely eliminated. This makes transient tables a cost-effective solution for temporary or less critical data.", "reference": "https://docs.snowflake.com/en/user-guide/tables-temp-transient.html"}, {"id": 817, "area": "Data Transformations", "question": "How can a Snowflake user traverse semi-structured data?", "options": ["A) Insert a colon (:) between the VARIANT column name and any first-level element.", "B) Insert a colon (:) between the VARIANT column name and any second-level element.", "C) Insert a double colon (::) between the VARIANT column name and any first-level element.", "D) Insert a double colon (::) between the VARIANT column name and any second-level element."], "chooseN": 1, "correct": ["Insert a colon (:) between the VARIANT column name and any first-level element."], "explanation": "In Snowflake, to traverse semi-structured data, a user should insert a colon (:) between the VARIANT column name and any first-level element. This syntax allows for easy and effective querying of nested data structures.", "reference": "https://docs.snowflake.com/en/user-guide/querying-semistructured.html"}, {"id": 818, "area": "Account Access and Security", "question": "Based on Snowflake recommendations, when creating a hierarchy of custom roles, the top-most custom role should be assigned to which role?", "options": ["A) ACCOUNTADMIN", "B) SECURITYADMIN", "C) SYSADMIN", "D) USERADMIN"], "chooseN": 1, "correct": ["SYSADMIN"], "explanation": "The correct answer is: SYSADMIN. The docs state: 'Snowflake recommends creating a hierarchy of custom roles, with the top-most custom role assigned to the system role SYSADMIN.' The answer should be C (SYSADMIN), not A (ACCOUNTADMIN). Reference: https://docs.snowflake.com/en/user-guide/security-access-control-overview#custom-roles", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-overview.html#custom-roles"}, {"id": 819, "area": "Account Access and Security", "question": "What happens to the privileges granted to Snowflake system-defined roles?", "options": ["A) The privileges cannot be revoked.", "B) The privileges can be revoked by an ACCOUNTADMIN.", "C) The privileges can be revoked by an ORGADMIN.", "D) The privileges can be revoked by any user-defined role with appropriate privileges."], "chooseN": 1, "correct": ["The privileges cannot be revoked."], "explanation": "Privileges granted to Snowflake system-defined roles cannot be revoked. These roles, including roles like SYSADMIN and ACCOUNTADMIN, come with a predefined set of privileges that are integral to the operation and management of the Snowflake environment.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-overview"}, {"id": 820, "area": "Data Protection and Data Sharing", "question": "By default, which role allows a user to manage a Snowflake Data Exchange share?", "options": ["A) ACCOUNTADMIN", "B) SECURITYADMIN", "C) SYSADMIN", "D) USERADMIN"], "chooseN": 1, "correct": ["ACCOUNTADMIN"], "explanation": "By default, the ACCOUNTADMIN role in Snowflake allows a user to manage a Snowflake Data Exchange share. This role is typically used for high-level administrative tasks, including managing data sharing arrangements.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-intro.html"}, {"id": 821, "area": "Data Loading and Unloading", "question": "How does the PARTITION BY option affect an expression for a COPY INTO command?", "options": ["A) The unload operation partitions table rows into separate files unloaded to the specified table.", "B) The unload operation partitions table rows into separate files unloaded to the specified stage.", "C) A single file will be loaded with a user-defined partition key and the user can use this partition key for clustering.", "D) A single file will be loaded with a Snowflake-defined partition key and Snowflake will use this key for pruning."], "chooseN": 1, "correct": ["The unload operation partitions table rows into separate files unloaded to the specified stage."], "explanation": "The PARTITION BY option in a COPY INTO command affects the unload operation by partitioning table rows into separate files. These files are then unloaded to the specified stage, allowing for organized and efficient data export and storage.", "reference": "https://docs.snowflake.com/en/user-guide/data-unload-overview#partitioned-data-unloading"}, {"id": 822, "area": "Performance Concepts", "question": "How does Snowflake improve the performance of queries that are designed to filter out a significant amount of data?", "options": ["A) The use of indexing", "B) The use of pruning", "C) The use of TableScan", "D) By increasing the number of partitions scanned"], "chooseN": 1, "correct": ["The use of pruning"], "explanation": "Snowflake improves the performance of queries designed to filter out a significant amount of data through the use of pruning. Pruning involves using metadata about data stored in micro-partitions to skip over those partitions that do not contain relevant data, thereby reducing the amount of data scanned and improving query performance.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions.html"}, {"id": 823, "area": "Data Transformations", "question": "A JSON document is stored in the source_column of type VARIANT. The document has an array called elements. The array contains the name key that has a string value. How can a Snowflake user extract the name from the first element?", "options": ["A) source_column.elements[1]:name", "B) source_column.elements[0]:name", "C) source_column:elements[1].name", "D) source_column:elements[0].name"], "chooseN": 1, "correct": ["source_column:elements[0].name"], "explanation": "To extract the name from the first element of the array called 'elements' in a JSON document stored in a VARIANT column, the correct syntax in Snowflake is 'source_column:elements[0].name'. This syntax accesses the first element of the array (index 0) and then extracts the value of the 'name' key.", "reference": "https://docs.snowflake.com/en/user-guide/querying-semistructured"}, {"id": 824, "area": "Data Transformations", "question": "Which function should be used to insert JSON formatted string data into a VARIANT field?", "options": ["A) FLATTEN", "B) CHECK_JSON", "C) PARSE_JSON", "D) TO_VARIANT"], "chooseN": 1, "correct": ["PARSE_JSON"], "explanation": "The PARSE_JSON function should be used to insert JSON formatted string data into a VARIANT field in Snowflake. This function converts a JSON text string into a VARIANT data type, which is Snowflake's semi-structured data type.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/parse_json.html"}, {"id": 825, "area": "Account Access and Security", "question": "Which permission on a Snowflake virtual warehouse allows the role to resize the warehouse?", "options": ["A) ALTER", "B) MODIFY", "C) MONITOR", "D) USAGE"], "chooseN": 1, "correct": ["MODIFY"], "explanation": "The MODIFY permission on a Snowflake virtual warehouse allows a role to resize the warehouse. This permission is necessary for adjusting the warehouse size according to the data processing needs.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/grant-privilege"}, {"id": 826, "area": "Data Protection and Data Sharing", "question": "What is it called when a customer managed key is combined with a Snowflake managed key to create a composite key for encryption?", "options": ["A) Hierarchical key model", "B) Client-side encryption", "C) Tri-secret secure encryption", "D) Key pair authentication"], "chooseN": 1, "correct": ["Tri-secret secure encryption"], "explanation": "When a customer-managed key is combined with a Snowflake-managed key to create a composite key for encryption, it is known as Tri-secret secure encryption. This method enhances the security of data by leveraging multiple keys for encryption.", "reference": "https://docs.snowflake.com/en/user-guide/security-encryption-manage#tri-secret-secure"}, {"id": 827, "area": "Data Loading and Unloading", "question": "What is the COPY INTO command option default for unloading data into multiple files?", "options": ["A) SINGLE = 0", "B) SINGLE = NULL", "C) SINGLE = TRUE", "D) SINGLE = FALSE"], "chooseN": 1, "correct": ["SINGLE = FALSE"], "explanation": "The default setting for the COPY INTO command option when unloading data into multiple files is 'SINGLE = FALSE'. This setting enables data to be unloaded into multiple files, facilitating parallel processing and efficient data management.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-location.html"}, {"id": 828, "area": "Performance Concepts", "question": "A size 3X-Large multi-cluster warehouse runs one cluster for one full hour and then runs two clusters for the next full hour. What would be the total number of credits billed?", "options": ["A) 64", "B) 128", "C) 149", "D) 192"], "chooseN": 1, "correct": ["192"], "explanation": "For a 3X-Large multi-cluster warehouse, the credit consumption is 64 credits per hour per cluster. Running one cluster for one hour consumes 64 credits, and running two clusters for the next hour consumes 128 credits, in total 192 credits.", "reference": "https://docs.snowflake.com/en/user-guide/credits.html"}, {"id": 829, "area": "Performance Concepts", "question": "What is the impact of increasing the number of concurrent users on a Snowflake virtual warehouse?", "options": ["A) Improved performance for small, simple queries", "B) Improved performance for large, complex queries", "C) Decreased performance for large, complex queries", "D) Decreased consumption of Snowflake credits"], "chooseN": 1, "correct": ["Decreased performance for large, complex queries"], "explanation": "Increasing the number of concurrent users on a Snowflake virtual warehouse can lead to decreased performance for large, complex queries. More concurrent users can lead to increased competition for resources, potentially slowing down the execution of resource-intensive queries.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-multicluster"}, {"id": 830, "area": "Data Protection and Data Sharing", "question": "By default, how long is the standard retention period for Time Travel across all Snowflake accounts?", "options": ["A) 0 days", "B) 1 day", "C) 7 days", "D) 14 days"], "chooseN": 1, "correct": ["1 day"], "explanation": "The default standard retention period for Time Travel in Snowflake is 1 day across all accounts. Time Travel allows users to access historical data within this retention period.", "reference": "https://docs.snowflake.com/en/user-guide/data-time-travel.html"}, {"id": 831, "area": "Performance Concepts", "question": "What type of query will benefit from the query acceleration service?", "options": ["A) Queries without filters or aggregation", "B) Queries with large scans and selective filters", "C) Queries where the GROUP BY has high cardinality", "D) Queries of tables that have search optimization service enabled"], "chooseN": 1, "correct": ["Queries with large scans and selective filters"], "explanation": "The query acceleration service in Snowflake is beneficial for queries with large scans and selective filters. This service optimizes the performance of queries that require scanning a large amount of data while applying specific filters to narrow down the results.", "reference": "https://docs.snowflake.com/en/user-guide/query-acceleration-service"}, {"id": 832, "area": "Performance Concepts", "question": "How does the search optimization service help Snowflake users improve query performance?", "options": ["A) It scans the micro-partitions based on the joins used in the queries and scans only join columns.", "B) It maintains a persistent data structure that keeps track of the values of the table’s columns in each of its micro-partitions.", "C) It scans the local disk cache to avoid scans on the tables used in the query.", "D) It keeps track of running queries and their results and saves those extra scans on the table."], "chooseN": 1, "correct": ["It maintains a persistent data structure that keeps track of the values of the table’s columns in each of its micro-partitions."], "explanation": "The search optimization service in Snowflake improves query performance by maintaining a persistent data structure. This structure keeps track of the values of the table’s columns in each of its micro-partitions, allowing for more efficient query execution and faster retrieval of results.", "reference": "https://docs.snowflake.com/en/user-guide/search-optimization-service.html"}, {"id": 833, "area": "Performance Concepts", "question": "What can be done to reduce queueing on a virtual warehouse?", "options": ["A) Increase the AUTO_SUSPEND setting for the warehouse.", "B) Change the warehouse to a multi-cluster warehouse.", "C) Increase the warehouse size.", "D) Lower the MAX_CONCURRENCY_LEVEL setting for the warehouse."], "chooseN": 1, "correct": ["Change the warehouse to a multi-cluster warehouse."], "explanation": "To reduce queueing on a virtual warehouse in Snowflake, changing the warehouse to a multi-cluster warehouse can be effective. This allows for the distribution of query load across multiple clusters, reducing queue times and improving overall performance.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-multicluster.html"}, {"id": 834, "area": "Snowflake Data Cloud Features & Architecture", "question": "What are characteristics of Snowsight worksheets? (Choose two.)", "options": ["A) Worksheets can be grouped under folders, and a folder of folders.", "B) Each worksheet is a unique Snowflake session.", "C) Users are limited to running only one query on a worksheet.", "D) The Snowflake session ends when a user switches worksheets.", "E) Users can import worksheets and share them with other users."], "chooseN": 1, "correct": ["Each worksheet is a unique Snowflake session."], "explanation": "Each worksheet in Snowsight uses a unique session with a specific role and warehouse assigned in the worksheet context. This lets you work independently in separate worksheets, while the worksheet keeps its own execution context.", "reference": "https://docs.snowflake.com/en/user-guide/ui-snowsight-worksheets-gs"}, {"id": 835, "area": "Data Loading and Unloading", "question": "What are reasons for using the VALIDATE function in Snowflake after a COPY INTO command execution? (Choose two.)", "options": ["A) To validate the files that have been loaded earlier using the COPY INTO command", "B) To fix errors that were made during the execution of the COPY INTO command", "C) To return errors encountered during the execution of the COPY INTO command", "D) To identify potential issues in the COPY INTO command before it is executed", "E) To count the number of errors encountered during the execution of the COPY INTO command"], "chooseN": 2, "correct": ["To validate the files that have been loaded earlier using the COPY INTO command", "To return errors encountered during the execution of the COPY INTO command"], "explanation": "The VALIDATE function in Snowflake is used after executing the COPY INTO command to validate the files that have been loaded and to return any errors encountered during the command execution. This helps in ensuring data integrity and troubleshooting load issues.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/validate"}, {"id": 836, "area": "Data Protection and Data Sharing", "question": "Which types of URLs are provided by Snowflake to access unstructured data files? (Choose two).", "options": ["A) Absolute URL", "B) Dynamic URL", "C) File URL", "D) Relative URL", "E) Scoped URL"], "chooseN": 2, "correct": ["File URL", "Scoped URL"], "explanation": "The correct answer is: File URL, Scoped URL. The docs list three URL types for unstructured data: Scoped URL, File URL, and Pre-signed URL. From the given options, C (File URL) and E (Scoped URL) are the two valid choices. Only C was marked. Both C and E should be marked correct. Reference: https://docs.snowflake.com/en/user-guide/unstructured-intro", "reference": "https://docs.snowflake.com/en/user-guide/unstructured-intro"}, {"id": 837, "area": "Data Transformations", "question": "Which query will return a sample of a table with 1000 rows named testtable, in which each row has a 10% probability of being included in the sample?", "options": ["A) select * from testtable sample (0.1);", "B) select * from testtable sample (10);", "C) select * from testtable sample (0.1 rows);", "D) select * from testtable sample (10 rows);"], "chooseN": 1, "correct": ["select * from testtable sample (10);"], "explanation": "The correct query to return a sample of a table with a 10% probability for each row to be included is 'select * from testtable sample (10);'.", "reference": "https://docs.snowflake.com/en/sql-reference/constructs/sample.html"}, {"id": 838, "area": "Account Access and Security", "question": "Which system function can be used to manage access to the data in a share and display certain data only to paying customers?", "options": ["A) SYSTEM$ALLOWLIST", "B) SYSTEM$ALLOWLIST_PRIVATELINK", "C) SYSTEM$AUTHORIZE_PRIVATELINK", "D) SYSTEM$IS_LISTING_PURCHASED"], "chooseN": 1, "correct": ["SYSTEM$IS_LISTING_PURCHASED"], "explanation": "The SYSTEM$IS_LISTING_PURCHASED system function in Snowflake is used to manage access to data in a share, particularly for distinguishing between paying and non-paying customers. This function can identify whether a customer has purchased a particular data listing.", "reference": "https://other-docs.snowflake.com/en/collaboration/provider-listings-preparing#preparing-shares-for-a-paid-listing"}, {"id": 839, "area": "Data Protection and Data Sharing", "question": "Which Snowflake object does not consume any storage costs?", "options": ["A) Secure view", "B) Materialized view", "C) Temporary table", "D) Transient table"], "chooseN": 1, "correct": ["Secure view"], "explanation": "A Secure view does not consume any storage costs. Secure views are non-materialized views that do not store data themselves but provide a virtual view of data from underlying tables.", "reference": "https://docs.snowflake.com/en/user-guide/views-secure.html"}, {"id": 840, "area": "Data Transformations", "question": "What does the LATERAL modifier for the FLATTEN function do?", "options": ["A) Casts the values of the flattened data", "B) Extracts the path of the flattened data", "C) Joins information outside the object with the flattened data", "D) Retrieves a single instance of a repeating element in the flattened data"], "chooseN": 1, "correct": ["Joins information outside the object with the flattened data"], "explanation": "The LATERAL modifier for the FLATTEN function in Snowflake is used to join information outside the object with the flattened data. This allows the FLATTEN function to work in conjunction with other parts of a query, enhancing data analysis and extraction capabilities.", "reference": "https://docs.snowflake.com/en/user-guide/querying-semistructured#using-the-flatten-function-to-parse-arrays"}, {"id": 841, "area": "Data Loading and Unloading", "question": "How can a Snowflake user validate data that is unloaded using the COPY INTO command?", "options": ["A) Load the data into a CSV file.", "B) Load the data into a relational table.", "C) Use the VALIDATION_MODE = SQL statement.", "D) Use the VALIDATION_MODE = RETURN_ROWS statement."], "chooseN": 1, "correct": ["Use the VALIDATION_MODE = RETURN_ROWS statement."], "explanation": "To validate data that is unloaded using the COPY INTO command in Snowflake, a user can use the VALIDATION_MODE = RETURN_ROWS statement. This validation mode enables the examination of the data to ensure its correctness after the unload operation.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-table.html#optional-parameters"}, {"id": 842, "area": "Account Access and Security", "question": "What role in Snowflake separates the management of users and roles from the management of all grants?", "options": ["A) ACCOUNTADMIN", "B) SYSADMIN", "C) SECURITYADMIN", "D) USERADMIN"], "chooseN": 1, "correct": ["USERADMIN"], "explanation": "In Snowflake, the USERADMIN role is designed to separate the management of users and roles from the management of all grants. This role focuses specifically on user and role administration, distinct from broader security and system administration tasks.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-overview"}, {"id": 843, "area": "Data Loading and Unloading", "question": "Which command will unload data from a table into an external stage?", "options": ["A) PUT", "B) INSERT", "C) COPY INTO", "D) GET"], "chooseN": 1, "correct": ["COPY INTO"], "explanation": "The 'COPY INTO' command in Snowflake is used to unload data from a table into an external stage. This command allows for efficient data export to cloud storage locations defined as external stages in Snowflake.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-location.html"}, {"id": 844, "area": "Account Access and Security", "question": "Why is a federated environment used for user authentication in Snowflake?", "options": ["A) To enhance data security and privacy", "B) To provide real-time monitoring of user activities", "C) To separate user authentication from user access", "D) To enable direct integration with external databases"], "chooseN": 1, "correct": ["To separate user authentication from user access"], "explanation": "A federated environment separates user authentication from user access", "reference": "https://docs.snowflake.com/en/user-guide/admin-security-fed-auth-overview"}, {"id": 845, "area": "Performance Concepts", "question": "What will happen if a Snowflake user increases the size of a suspended virtual warehouse?", "options": ["A) The provisioning of new compute resources for the warehouse will begin immediately.", "B) The warehouse will remain suspended but new resources will be added to the query acceleration service.", "C) The provisioning of additional compute resources will be in effect when the warehouse is next resumed.", "D) The warehouse will resume immediately and start to share the compute load with other running virtual warehouses."], "chooseN": 1, "correct": ["The provisioning of additional compute resources will be in effect when the warehouse is next resumed."], "explanation": "If a Snowflake user increases the size of a suspended virtual warehouse, the provisioning of additional compute resources will only be in effect when the warehouse is next resumed. The change does not trigger an immediate resumption or provisioning of resources.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-tasks.html#resizing-a-warehouse"}, {"id": 846, "area": "Data Loading and Unloading", "question": "The VALIDATE table function has which parameter as an input argument for a Snowflake user?", "options": ["A) LAST_QUERY_ID", "B) CURRENT_STATEMENT", "C) UUID_STRING", "D) JOB_ID"], "chooseN": 1, "correct": ["JOB_ID"], "explanation": "The VALIDATE table function in Snowflake takes 'JOB_ID' as an input argument. This ID is used to specify the COPY INTO command execution whose files are to be validated.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/validate.html"}, {"id": 847, "area": "Data Protection and Data Sharing", "question": "Which Snowflake edition supports Protected Health Information (PHI) data (in accordance with HIPAA and HITRUST CSF regulations), and has a dedicated metadata store and pool of compute resources?", "options": ["A) Standard", "B) Enterprise", "C) Business Critical", "D) Virtual Private Snowflake (VPS)"], "chooseN": 1, "correct": ["Virtual Private Snowflake (VPS)"], "explanation": "The Virtual Private Snowflake (VPS) edition supports Protected Health Information (PHI) data in accordance with HIPAA and HITRUST CSF regulations. It also provides a dedicated metadata store and a separate pool of compute resources, offering enhanced security and compliance.", "reference": "https://docs.snowflake.com/en/user-guide/intro-editions"}, {"id": 848, "area": "Data Loading and Unloading", "question": "Which Snowflake table types are used to manage costs for short-lived tables? (Choose two.)", "options": ["A) External tables", "B) Permanent tables", "C) Shared tables", "D) Temporary tables", "E) Transient tables"], "chooseN": 2, "correct": ["Temporary tables", "Transient tables"], "explanation": "Temporary and Transient tables in Snowflake are used to manage costs for short-lived tables. Temporary tables exist only for the duration of a user session, and Transient tables are ideal for temporary or less critical data with reduced storage costs for Time Travel.", "reference": "https://docs.snowflake.com/en/user-guide/tables-temp-transient.html"}, {"id": 849, "area": "Snowflake Data Cloud Features & Architecture", "question": "What are key characteristics of virtual warehouses in Snowflake? (Choose two.)", "options": ["A) Warehouses that are multi-cluster can have nodes of different sizes.", "B) Warehouses can be started and stopped at any time.", "C) Warehouses can be resized at any time, even while running.", "D) Warehouses are billed on a per-minute usage basis.", "E) Warehouses can only be used for querying and cannot be used for data loading."], "chooseN": 2, "correct": ["Warehouses can be started and stopped at any time.", "Warehouses can be resized at any time, even while running."], "explanation": "Key characteristics of virtual warehouses in Snowflake include the ability to start and stop them at any time and the ability to resize them at any time, even while they are running. This provides flexibility and efficiency in managing compute resources.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-overview.html"}, {"id": 850, "area": "Performance Concepts", "question": "What strategies can be used to optimize the performance of a virtual warehouse? (Choose two.)", "options": ["A) Reduce queuing.", "B) Allow memory spillage.", "C) Increase the MAX_CONCURRENCY_LEVEL parameter.", "D) Increase the warehouse size.", "E) Suspend the warehouse frequently."], "chooseN": 2, "correct": ["Reduce queuing.", "Increase the warehouse size."], "explanation": "To optimize the performance of a virtual warehouse in Snowflake, strategies such as reducing queuing and increasing the warehouse size can be effective. Reducing queuing ensures more efficient use of resources, while a larger warehouse size allows for handling more concurrent queries and workloads.", "reference": "https://docs.snowflake.com/en/user-guide/performance-query-warehouse"}, {"id": 851, "area": "Account Access and Security", "question": "How are privileges inherited in a role hierarchy in Snowflake?", "options": ["A) Privileges are inherited by any roles above that role in the hierarchy.", "B) Privileges are inherited by any roles at the same level in the hierarchy.", "C) Privileges are only inherited by the direct parent role in the hierarchy.", "D) Privileges are only inherited by the direct child role in the hierarchy."], "chooseN": 1, "correct": ["Privileges are inherited by any roles above that role in the hierarchy."], "explanation": "In a role hierarchy in Snowflake, privileges are inherited by any roles above the role in the hierarchy. This means that higher-level roles automatically inherit the privileges of the roles beneath them, facilitating efficient and hierarchical management of access and permissions.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-overview.html#role-hierarchy"}, {"id": 852, "area": "Account Access and Security", "question": "At what level can the ALLOW_CLIENT_MFA_CACHING parameter be set?", "options": ["A) Account", "B) Role", "C) Session", "D) User"], "chooseN": 1, "correct": ["Account"], "explanation": "The ALLOW_CLIENT_MFA_CACHING parameter in Snowflake can be set at the account level. This parameter controls the caching of multi-factor authentication (MFA) credentials, impacting the security settings for the entire account.", "reference": "https://docs.snowflake.com/en/user-guide/security-mfa.html"}, {"id": 853, "area": "Data Protection and Data Sharing", "question": "What entity is responsible for hosting and sharing data in Snowflake?", "options": ["A) Data provider", "B) Data consumer", "C) Reader account", "D) Managed account"], "chooseN": 1, "correct": ["Data provider"], "explanation": "In Snowflake, the data provider is responsible for hosting and sharing data. The data provider manages the data and shares it with data consumers, who can then access and use the shared data based on the permissions granted.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-intro.html"}, {"id": 854, "area": "Account Access and Security", "question": "Which function will provide the proxy information needed to protect Snowsight?", "options": ["A) SYSTEM$GET_TAG", "B) SYSTEM$GET_PRIVATELINK", "C) SYSTEM$ALLOWLIST", "D) SYSTEM$AUTHORIZE_PRIVATELINK"], "chooseN": 1, "correct": ["SYSTEM$ALLOWLIST"], "explanation": "The SYSTEM$ALLOWLIST function in Snowflake provides the necessary proxy information to protect Snowsight.", "reference": "https://docs.snowflake.com/en/user-guide/ui-snowsight-gs#accessing-sf-web-interface-through-a-proxy-or-firewall"}, {"id": 855, "area": "Account Access and Security", "question": "The property MINS_TO_BYPASS_NETWORK_POLICY is set at which level?", "options": ["A) User", "B) Role", "C) Account", "D) Organization"], "chooseN": 1, "correct": ["User"], "explanation": "The MINS_TO_BYPASS_NETWORK_POLICY property in Snowflake is set at the User level. This setting determines the number of minutes a network policy can be bypassed", "reference": "https://docs.snowflake.com/en/user-guide/network-policies"}, {"id": 856, "area": "Data Loading and Unloading", "question": "When unloading the data for file format type specified (TYPE = 'CSV'), SQL NULL can be converted to string 'null' using which file format option?", "options": ["A) SKIP_BYTE_ORDER_MARK", "B) EMPTY_FIELD_AS_NULL", "C) NULL_IF", "D) ESCAPE_UNENCLOSED_FIELD"], "chooseN": 1, "correct": ["NULL_IF"], "explanation": "The NULL_IF file format option in Snowflake can be used to convert SQL NULL values to the string 'null' when unloading data with the CSV file format.", "reference": "https://docs.snowflake.com/en/user-guide/data-unload-considerations#empty-strings-and-null-values"}, {"id": 857, "area": "Data Transformations", "question": "Which table function should be used to view details on a Directed Acyclic Graph (DAG) run that is presently scheduled or is executing?", "options": ["A) TASK_HISTORY", "B) TASK_DEPENDENTS", "C) CURRENT_TASK_GRAPHS", "D) COMPLETE_TASK_GRAPHS"], "chooseN": 1, "correct": ["CURRENT_TASK_GRAPHS"], "explanation": "The CURRENT_TASK_GRAPHS table function in Snowflake should be used to view details on a Directed Acyclic Graph (DAG) run that is currently scheduled or executing. This function provides information about the structure and status of ongoing DAG runs.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/current_task_graphs.html"}, {"id": 858, "area": "Snowflake Data Cloud Features & Architecture", "question": "What Snowflake database object is derived from a query specification, stored for later use, and can speed up expensive aggregation on large data sets?", "options": ["A) Temporary table", "B) External table", "C) Secure view", "D) Materialized view"], "chooseN": 1, "correct": ["Materialized view"], "explanation": "A Materialized view in Snowflake is a database object derived from a query specification, stored for later use. It is specifically designed to speed up expensive aggregations on large data sets by storing the results of the query.", "reference": "https://docs.snowflake.com/en/user-guide/views-materialized"}, {"id": 859, "area": "Account Access and Security", "question": "User1, who has the SYSADMIN role, executed a query on Snowsight. User2, who is in the same Snowflake account, wants to view the result set of the query executed by User1 using the Snowsight query history. What will happen if User2 tries to access the query history?", "options": ["A) If User2 has the SYSADMIN role they will be able to see the results.", "B) If User2 has the SECURITYADMIN role they will be able to see the results.", "C) If User2 has the ACCOUNTADMIN role they will be able to see the results.", "D) User2 will be unable to view the result set of the query executed by User1."], "chooseN": 1, "correct": ["User2 will be unable to view the result set of the query executed by User1."], "explanation": "You can view results only for queries you have executed. If you have privileges to view queries executed by another user, the Query Detail page displays the details for the query, but, for data privacy reasons, the page does not display the actual query result", "reference": "https://docs.snowflake.com/en/user-guide/ui-history"}, {"id": 860, "area": "Data Loading and Unloading", "question": "A permanent table and temporary table have the same name, TBL1, in a schema. What will happen if a user executes select * from TBL1?", "options": ["A) The temporary table will take precedence over the permanent table.", "B) The permanent table will take precedence over the temporary table.", "C) An error will say there cannot be two tables with the same name in a schema.", "D) The table that was created most recently will take precedence over the older table."], "chooseN": 1, "correct": ["The temporary table will take precedence over the permanent table."], "explanation": "When a permanent table and a temporary table have the same name in Snowflake, the temporary table takes precedence over the permanent table for the session in which the temporary table exists. This means queries referencing the table name will access the temporary table.", "reference": "https://docs.snowflake.com/en/user-guide/tables-temp-transient#potential-naming-conflicts-with-other-table-types"}, {"id": 861, "area": "Performance Concepts", "question": "The effects of query pruning can be observed by evaluating which statistics? (Choose two.)", "options": ["A) Partitions scanned", "B) Partitions total", "C) Bytes scanned", "D) Bytes read from result", "E) Bytes written"], "chooseN": 2, "correct": ["Partitions scanned", "Partitions total"], "explanation": "The effects of query pruning in Snowflake can be observed by evaluating the 'Partitions scanned' and 'Partitions total' statistics. These statistics indicate how efficiently Snowflake is scanning data by reducing unnecessary data scans, which is a key aspect of query pruning.", "reference": "https://docs.snowflake.com/en/user-guide/ui-query-profile#query-operator-details"}, {"id": 862, "area": "Data Transformations", "question": "Which data types optimally store semi-structured data? (Choose two.)", "options": ["A) ARRAY", "B) CHARACTER", "C) STRING", "D) VARCHAR", "E) VARIANT"], "chooseN": 2, "correct": ["ARRAY", "VARIANT"], "explanation": "In Snowflake, the data types 'ARRAY' and 'VARIANT' are optimally used for storing semi-structured data. 'VARIANT' can store structured and semi-structured data such as JSON, AVRO, ORC, Parquet, and XML. 'ARRAY' is used to store array data types, commonly found in semi-structured data formats.", "reference": "https://docs.snowflake.com/en/user-guide/semistructured-intro.html"}, {"id": 863, "area": "Data Loading and Unloading", "question": "What compute resource is used when loading data using Snowpipe?", "options": ["A) Snowpipe uses virtual warehouses provided by the user.", "B) Snowpipe uses an Apache Kafka server for its compute resources.", "C) Snowpipe uses compute resources provided by Snowflake.", "D) Snowpipe uses cloud platform compute resources provided by the user."], "chooseN": 1, "correct": ["Snowpipe uses compute resources provided by Snowflake."], "explanation": "When loading data using Snowpipe, Snowflake provides the necessary compute resources. Snowpipe automatically manages these resources to load data in a continuous, near real-time manner without the need for manual intervention or the use of virtual warehouses provided by the user.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-snowpipe-intro.html"}, {"id": 864, "area": "Data Loading and Unloading", "question": "Which file function gives a user or application access to download unstructured data from a Snowflake stage?", "options": ["A) BUILD_SCOPED_FILE_URL", "B) BUILD_STAGE_FILE_URL", "C) GET_PRESIGNED_URL", "D) GET_STAGE_LOCATION"], "chooseN": 1, "correct": ["GET_PRESIGNED_URL"], "explanation": "The GET_PRESIGNED_URL function in Snowflake provides a user or application with a URL that can be used to download unstructured data from a Snowflake stage. This function generates a pre-signed URL for securely accessing the data.", "reference": "https://docs.snowflake.com/en/user-guide/unstructured-intro"}, {"id": 865, "area": "Account Access and Security", "question": "By default, which role can create resource monitors?", "options": ["A) ACCOUNTADMIN", "B) SECURITYADMIN", "C) SYSADMIN", "D) USERADMIN"], "chooseN": 1, "correct": ["ACCOUNTADMIN"], "explanation": "By default, the ACCOUNTADMIN role in Snowflake has the privilege to create resource monitors. This role is responsible for managing the account and its resources, including the creation and configuration of resource monitors.", "reference": "https://docs.snowflake.com/en/user-guide/resource-monitors#access-control-privileges-for-resource-monitors"}, {"id": 866, "area": "Data Protection and Data Sharing", "question": "Which DDL/DML operation is allowed on an inbound data share?", "options": ["A) ALTER TABLE", "B) INSERT INTO", "C) MERGE", "D) SELECT"], "chooseN": 1, "correct": ["SELECT"], "explanation": "For an inbound data share in Snowflake, the only allowed DDL/DML operation is SELECT. This operation permits users to query and view the shared data, while other modifications like ALTER, INSERT, and MERGE are not allowed.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-intro.html"}, {"id": 867, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which types of charts does Snowsight support? (Choose two.)", "options": ["A) Area charts", "B) Bar charts", "C) Column charts", "D) Radar charts", "E) Scorecards"], "chooseN": 2, "correct": ["Bar charts", "Scorecards"], "explanation": "The correct answer is: Bar charts, Scorecards. The docs list five supported chart types: Scorecards, Heat grids, Scatterplots, Line charts, and Bar charts. 'Column charts' is NOT listed. The correct answers are B (Bar charts) and E (Scorecards). Reference: https://docs.snowflake.com/en/user-guide/ui-snowsight-visualizations", "reference": "https://docs.snowflake.com/en/user-guide/ui-snowsight-visualizations"}, {"id": 868, "area": "Data Protection and Data Sharing", "question": "Which role in Snowflake allows a user to enable replication for multiple accounts?", "options": ["A) ACCOUNTADMIN", "B) SECURITYADMIN", "C) SYSADMIN", "D) ORGADMIN"], "chooseN": 1, "correct": ["ORGADMIN"], "explanation": "In Snowflake, the ORGADMIN role is responsible for enabling replication across multiple accounts. This role has the necessary permissions to manage and oversee replication settings and configurations at the organization level.", "reference": "https://docs.snowflake.com/en/user-guide/replication-intro.html"}, {"id": 869, "area": "Data Loading and Unloading", "question": "Which Snowflake tool is recommended for data batch processing?", "options": ["A) SnowCD", "B) SnowSQL", "C) Snowsight", "D) The Snowflake API"], "chooseN": 1, "correct": ["SnowSQL"], "explanation": "SnowSQL is the recommended tool for data batch processing in Snowflake. SnowSQL, a command-line client, provides a range of functionality for executing SQL queries, including batch data processing tasks, against the Snowflake data warehouse.", "reference": "https://docs.snowflake.com/en/user-guide/snowsql.html"}, {"id": 870, "area": "Performance Concepts", "question": "Which Snowflake mechanism is used to limit the number of micro-partitions scanned by a query?", "options": ["A) Caching", "B) Cluster depth", "C) Query pruning", "D) Retrieval optimization"], "chooseN": 1, "correct": ["Query pruning"], "explanation": "Query pruning is the mechanism used in Snowflake to limit the number of micro-partitions scanned by a query. It involves using metadata to skip over partitions that do not contain relevant data, improving query efficiency.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions.html#partition-pruning-and-cluster-keys"}, {"id": 871, "area": "Performance Concepts", "question": "While clustering a table, columns with which data types can be used as clustering keys? (Choose two.)", "options": ["A) BINARY", "B) GEOGRAPHY", "C) GEOMETRY", "D) OBJECT", "E) VARIANT"], "chooseN": 2, "correct": ["BINARY", "GEOMETRY"], "explanation": "It can be any datatype except GEOGRAPHY, VARIANT, OBJECT, ARRAY.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-keys.html"}, {"id": 872, "area": "Performance Concepts", "question": "Which use case does the search optimization service support?", "options": ["A) Disjuncts (OR) in join predicates", "B) LIKE/ILIKE/RLIKE join predicates", "C) Join predicates on VARIANT columns", "D) Conjunctions (AND) of multiple equality predicates"], "chooseN": 1, "correct": ["Conjunctions (AND) of multiple equality predicates"], "explanation": "The search optimization service in Snowflake supports use cases such as conjunctions (AND) of multiple equality predicates. This service is designed to optimize the performance of queries that involve complex predicates and need efficient data retrieval.", "reference": "https://docs.snowflake.com/en/user-guide/search-optimization-service.html"}, {"id": 873, "area": "Data Loading and Unloading", "question": "What should be used when creating a CSV file format where the columns are wrapped by single quotes or double quotes?", "options": ["A) BINARY_FORMAT", "B) ESCAPE_UNENCLOSED_FIELD", "C) FIELD_OPTIONALLY_ENCLOSED_BY", "D) SKIP_BYTE_ORDER_MARK"], "chooseN": 1, "correct": ["FIELD_OPTIONALLY_ENCLOSED_BY"], "explanation": "When creating a CSV file format in Snowflake where the columns are wrapped by single quotes or double quotes, the 'FIELD_OPTIONALLY_ENCLOSED_BY' parameter should be used. This parameter specifies a character that encloses field values, which is essential for properly parsing quoted CSV data.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/create-file-format.html"}, {"id": 874, "area": "Performance Concepts", "question": "If a multi-cluster warehouse is using an economy scaling policy, how long will queries wait in the queue before another cluster is started?", "options": ["A) 1 minute", "B) 2 minutes", "C) 6 minutes", "D) 8 minutes"], "chooseN": 1, "correct": ["6 minutes"], "explanation": "Under an economy scaling policy for a multi-cluster warehouse in Snowflake, queries will wait in the queue for 6 minutes before another cluster is started. This policy prioritizes cost savings over rapid resource scaling.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-multicluster.html#scaling-policies"}, {"id": 875, "area": "Data Transformations", "question": "What does the TableScan operator represent in the Query Profile?", "options": ["A) The access to a single table", "B) The access to data stored in stage objects", "C) The list of values provided with the VALUES clause", "D) The records generated using the TABLE(GENERATOR(...)) construct"], "chooseN": 1, "correct": ["The access to a single table"], "explanation": "In the Query Profile of Snowflake, the TableScan operator represents the access to a single table. This operator is used to identify how a table is accessed and scanned during the execution of a query.", "reference": "https://docs.snowflake.com/en/user-guide/ui-query-profile.html"}, {"id": 876, "area": "Performance Concepts", "question": "What information is found within the Statistics output in the Query Profile Overview?", "options": ["A) Operator tree", "B) Table pruning", "C) Most expensive nodes", "D) Nodes by execution time"], "chooseN": 1, "correct": ["Table pruning"], "explanation": "Dentro de la seccion Statistics del Query Profile en Snowflake, se muestra informacion sobre Table pruning, incluyendo metricas de particiones escaneadas vs. podadas (partitions scanned/total), lo que ayuda a diagnosticar la eficiencia del micro-partition pruning. Operator tree es un panel separado que muestra el plan de ejecucion. Most expensive nodes aparece en la seccion Overview, no en Statistics. Nodes by execution time no es una metrica de la seccion Statistics.", "reference": "https://docs.snowflake.com/en/user-guide/ui-query-profile.html"}, {"id": 877, "area": "Account Access and Security", "question": "Which roles can make grant decisions to objects within a managed access schema? (Choose two.)", "options": ["A) ACCOUNTADMIN", "B) SECURITYADMIN", "C) SYSADMIN", "D) ORGADMIN", "E) USERADMIN"], "chooseN": 2, "correct": ["ACCOUNTADMIN", "SECURITYADMIN"], "explanation": "In a managed access schema within Snowflake, the ACCOUNTADMIN and SECURITYADMIN roles can make grant decisions to objects. These roles have sufficient privileges to manage access and security settings within the schema.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-overview.html#managed-access-schemas"}, {"id": 878, "area": "Data Loading and Unloading", "question": "How can a Snowflake user post-process the result of SHOW FILE FORMATS?", "options": ["A) Use the RESULT_SCAN function.", "B) Create a CURSOR for the command.", "C) Put it in the FROM clause in brackets.", "D) Assign the command to RESULTSET."], "chooseN": 1, "correct": ["Use the RESULT_SCAN function."], "explanation": "To post-process the result of the SHOW FILE FORMATS command in Snowflake, a user can use the RESULT_SCAN function. This function allows users to query the results of a previous statement, such as SHOW FILE FORMATS, for further analysis or processing.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/result_scan.html"}, {"id": 879, "area": "Performance Concepts", "question": "A Snowflake account administrator has set the resource monitors as shown in the diagram, with actions defined for each resource monitor as 'Notify & Suspend Immediately'. What is the MAXIMUM limit of credits that Warehouse 2 can consume? A. 0 B. 1500 C. 3500 D. 5000", "options": ["A) 0", "B) 1500", "C) 3500", "D) 5000"], "chooseN": 1, "correct": ["5000"], "explanation": "This warehouse is controlled by policy on the account level, so 5000 credits in the best case scenario where other warehouses doesn't consume ANY resources", "reference": "https://docs.snowflake.com/en/user-guide/resource-monitors.html"}, {"id": 880, "area": "Account Access and Security", "question": "When initially creating an account in Snowflake, which settings can be specified? (Choose two.)", "options": ["A) Account name", "B) Organization name", "C) Account locator", "D) Region", "E) Snowflake edition"], "chooseN": 2, "correct": ["Region", "Snowflake edition"], "explanation": "When initially creating a Snowflake account, the settings that can be specified include the 'Region' where the account will be hosted and the 'Snowflake edition', which determines the level of features and services available.", "reference": "https://docs.snowflake.com/en/user-guide/organizations-manage-accounts-create"}, {"id": 881, "area": "Account Access and Security", "question": "What activities can a user with the ORGADMIN role perform? (Choose two.)", "options": ["A) Create an account for an organization.", "B) Edit the account data for an organization.", "C) Delete the account data for an organization.", "D) View usage information for all accounts in an organization.", "E) Select all the data in tables for all accounts in an organization."], "chooseN": 2, "correct": ["Create an account for an organization.", "View usage information for all accounts in an organization."], "explanation": "A user with the ORGADMIN role in Snowflake has the ability to create an account for an organization and view usage information for all accounts in the organization. These capabilities are part of the administrative functions associated with managing an organization's Snowflake accounts.", "reference": "https://docs.snowflake.com/en/user-guide/organizations"}, {"id": 882, "area": "Performance Concepts", "question": "What is one of the benefits of using a multi-cluster virtual warehouse?", "options": ["A) It will speed up data loading.", "B) It will reduce the cost of running the warehouse.", "C) It will automatically increase the warehouse size as needed.", "D) It will automatically start and stop additional clusters as needed."], "chooseN": 1, "correct": ["It will automatically start and stop additional clusters as needed."], "explanation": "One of the key benefits of using a multi-cluster virtual warehouse in Snowflake is that it can automatically start and stop additional clusters as needed. This feature helps in managing varying workloads efficiently by scaling resources up or down based on the demand.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-multicluster.html"}, {"id": 883, "area": "Performance Concepts", "question": "When should a multi-cluster virtual warehouse be used in Snowflake?", "options": ["A) When queuing is delaying query execution on the warehouse", "B) When there is significant disk spilling shown on the Query Profile", "C) When dynamic vertical scaling is being used in the warehouse", "D) When there are no concurrent queries running on the warehouse"], "chooseN": 1, "correct": ["When queuing is delaying query execution on the warehouse"], "explanation": "A multi-cluster virtual warehouse should be used in Snowflake when queuing is delaying query execution on the warehouse. Multi-cluster warehouses can efficiently handle high concurrency and workload spikes by providing additional computing clusters to process queries without delay.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-multicluster.html"}, {"id": 884, "area": "Data Transformations", "question": "What is used to denote a pre-computed data set derived from a SELECT query specification and stored for later use?", "options": ["A) View", "B) Secure view", "C) Materialized view", "D) External table"], "chooseN": 1, "correct": ["Materialized view"], "explanation": "A materialized view in Snowflake represents a pre-computed data set that is derived from a SELECT query specification and stored for later use. Unlike regular views, materialized views hold the query result data, thereby speeding up query performance for repeated use.", "reference": "https://docs.snowflake.com/en/user-guide/views-materialized"}, {"id": 885, "area": "Account Access and Security", "question": "A Snowflake user wants to temporarily bypass a network policy by configuring the user object property MINS_TO_BYPASS_NETWORK_POLICY. What should they do?", "options": ["A) Use the SECURITYADMIN role.", "B) Use the SYSADMIN role.", "C) Use the USERADMIN role.", "D) Contact Snowflake Support."], "chooseN": 1, "correct": ["Contact Snowflake Support."], "explanation": "To temporarily bypass a network policy by configuring the MINS_TO_BYPASS_NETWORK_POLICY property for a user in Snowflake it is necessary to contact Snowflake Support.", "reference": "https://docs.snowflake.com/en/user-guide/network-policies#bypassing-a-network-policy"}, {"id": 886, "area": "Account Access and Security", "question": "What is the default access of a securable object until other access is granted?", "options": ["A) No access", "B) Read access", "C) Write access", "D) Full access"], "chooseN": 1, "correct": ["No access"], "explanation": "In Snowflake, the default access of a securable object is 'No access' until other access permissions are explicitly granted. This is in line with the principle of least privilege, ensuring that access to data and objects is restricted and controlled.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-overview"}, {"id": 887, "area": "Data Loading and Unloading", "question": "From what stage can a Snowflake user omit the FROM clause while loading data into a table?", "options": ["A) The user stage", "B) The table stage", "C) The internal named stage", "D) The external named stage"], "chooseN": 1, "correct": ["The table stage"], "explanation": "In Snowflake, a user can omit the FROM clause while loading data into a table if they are using the table stage. The table stage is implicitly associated with the specific table, allowing the FROM clause to be omitted in this context.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-local-file-system-copy"}, {"id": 888, "area": "Performance Concepts", "question": "What is used during the FIRST execution of SELECT COUNT(*) FROM ORDER?", "options": ["A) Remote disk cache", "B) Virtual warehouse cache", "C) Cache result", "D) Metadata-based result"], "chooseN": 1, "correct": ["Metadata-based result"], "explanation": "During the first execution of a query like SELECT COUNT(*) FROM ORDER in Snowflake, a metadata-based result is used. Snowflake's metadata-driven architecture allows it to quickly return results for certain types of aggregate queries, like counting rows, without scanning the entire table.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions"}, {"id": 889, "area": "Snowflake Data Cloud Features & Architecture", "question": "What is the purpose of a resource monitor in Snowflake?", "options": ["A) To monitor the query performance of virtual warehouses", "B) To create and suspend virtual warehouses automatically", "C) To manage cloud services needed for virtual warehouses", "D) To control costs and credit usage by virtual warehouses"], "chooseN": 1, "correct": ["To control costs and credit usage by virtual warehouses"], "explanation": "The purpose of a resource monitor in Snowflake is to control costs and credit usage by virtual warehouses. Resource monitors allow administrators to set limits on the number of credits that can be consumed, helping to manage and control costs associated with warehouse usage.", "reference": "https://docs.snowflake.com/en/user-guide/resource-monitors.html"}, {"id": 890, "area": "Data Loading and Unloading", "question": "Which data formats are supported by Snowflake when unloading semi-structured data? (Choose two.)", "options": ["A) Binary file in Avro", "B) Binary file in Parquet", "C) Comma-separated JSON", "D) Newline Delimited JSON", "E) Plain text file containing XML elements"], "chooseN": 2, "correct": ["Binary file in Parquet", "Newline Delimited JSON"], "explanation": "Snowflake supports unloading semi-structured data in formats such as 'Binary file in Parquet' and 'Newline Delimited JSON'. These formats are well-suited for handling semi-structured data, enabling efficient data processing and storage.", "reference": "https://docs.snowflake.com/en/user-guide/data-unload-prepare#supported-file-formats"}, {"id": 891, "area": "Account Access and Security", "question": "In Snowflake, the use of federated authentication enables which Single Sign-On (SSO) workflow activities? (Choose two.)", "options": ["A) Authorizing users", "B) Initiating user sessions", "C) Logging into Snowflake", "D) Logging out of Snowflake", "E) Performing role authentication"], "chooseN": 2, "correct": ["Logging into Snowflake", "Logging out of Snowflake"], "explanation": "Federated authentication enables the supported SSO workflows 'Logging into Snowflake' and 'Logging out of Snowflake'. The initiation of a session occurs during the login workflow, but it is not one of the named supported SSO workflows in the documentation.", "reference": "https://docs.snowflake.com/en/user-guide/admin-security-fed-auth-overview#supported-sso-workflows"}, {"id": 892, "area": "Account Access and Security", "question": "What does the worksheet and database explorer feature in Snowsight allow users to do?", "options": ["A) Add or remove users from a worksheet.", "B) Move a worksheet to a folder or a dashboard.", "C) Combine multiple worksheets into a single worksheet.", "D) Tag frequently accessed worksheets for ease of access."], "chooseN": 1, "correct": ["Move a worksheet to a folder or a dashboard."], "explanation": "The worksheet and database explorer feature in Snowsight allows users to move a worksheet to a folder or a dashboard. This functionality provides organizational flexibility and ease of access, enabling users to efficiently manage and navigate their Snowflake environment.", "reference": "https://docs.snowflake.com/en/user-guide/ui-snowsight-worksheets"}, {"id": 893, "area": "Data Loading and Unloading", "question": "When unloading data from Snowflake to AWS, what permissions are required? (Choose two.)", "options": ["A) s3\\:DeleteObject", "B) s3\\:CopyObject", "C) s3\\:GetBucketAcl", "D) s3\\:PutObject", "E) s3\\:GetBucketLocation"], "chooseN": 2, "correct": ["s3\\:DeleteObject", "s3\\:PutObject"], "explanation": "When unloading data from Snowflake to AWS, the permissions required include 's3\\:DeleteObject' and 's3\\:PutObject'. These permissions ensure that Snowflake can correctly store and access data in the specified AWS S3 bucket.", "reference": "https://docs.snowflake.com/en/user-guide/data-unload-s3#configuring-an-s3-bucket-for-unloading-data"}, {"id": 894, "area": "Performance Concepts", "question": "What step can reduce data spilling in Snowflake?", "options": ["A) Using a larger virtual warehouse", "B) Increasing the virtual warehouse maximum timeout limit", "C) Increasing the amount of remote storage for the virtual warehouse", "D) Using a Common Table Expression (CTE) instead of a temporary table"], "chooseN": 1, "correct": ["Using a larger virtual warehouse"], "explanation": "Using a larger virtual warehouse can reduce data spilling in Snowflake. A larger warehouse provides more memory and CPU resources, reducing the likelihood of spilling data to remote storage during query execution.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-considerations.html"}, {"id": 895, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which user preferences can be set for a user profile in Snowsight? (Choose two.)", "options": ["A) Multi-Factor Authentication (MFA)", "B) Default database", "C) Default schema", "D) Notifications", "E) Username"], "chooseN": 2, "correct": ["Multi-Factor Authentication (MFA)", "Notifications"], "explanation": "In Snowsight, a user can set preferences for their profile such as the Multi-Factor Authentication (MFA) and Notifications.", "reference": "https://docs.snowflake.com/en/user-guide/ui-snowsight-gs#setting-user-details-and-preferences"}, {"id": 896, "area": "Account Access and Security", "question": "What privilege is needed for a Snowflake user to see the definition of a secure view?", "options": ["A) OWNERSHIP", "B) MODIFY", "C) CREATE", "D) USAGE"], "chooseN": 1, "correct": ["OWNERSHIP"], "explanation": "To see the definition of a secure view in Snowflake, a user must have the OWNERSHIP privilege on that view. This privilege level is required to view the underlying query or definition of the secure view.", "reference": "https://docs.snowflake.com/en/user-guide/views-secure.html"}, {"id": 897, "area": "Performance Concepts", "question": "What general guideline does Snowflake recommend when setting the auto-suspension time limit?", "options": ["A) Set tasks for immediate suspension.", "B) Set tasks for suspension after 5 minutes.", "C) Set query warehouses for suspension after 15 minutes.", "D) Set query warehouses for suspension after 30 minutes."], "chooseN": 1, "correct": ["Set tasks for immediate suspension."], "explanation": "Snowflake recommends setting warehouses used for tasks to suspend immediately (AUTO_SUSPEND = 0) after task completion. For query warehouses, the general recommendation is 5-10 minutes or less to balance resource availability and cost efficiency. Setting suspension to 15 or 30 minutes is not a recommended guideline.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-considerations#automating-warehouse-suspension"}, {"id": 898, "area": "Data Protection and Data Sharing", "question": "When does Snowflake automatically encrypt data that is loaded into Snowflake? (Choose two.)", "options": ["A) After the data is micro-partitioned.", "B) After loading the data into a table.", "C) After loading the data into an internal stage.", "D) After loading data into an external stage.", "E) Only when using an encrypted stage."], "chooseN": 2, "correct": ["After loading the data into a table.", "After loading the data into an internal stage."], "explanation": "Snowflake automatically encrypts data when it is loaded into a table and after loading the data into an internal stage. This encryption process ensures data security and confidentiality within Snowflake's storage layers.", "reference": "https://docs.snowflake.com/en/user-guide/security-encryption-end-to-end"}, {"id": 899, "area": "Data Loading and Unloading", "question": "When data is loaded into Snowflake, what formats does Snowflake use internally to store the data in cloud storage? (Choose two.)", "options": ["A) Key-value", "B) Columnar", "C) Graph", "D) Document", "E) Compressed"], "chooseN": 2, "correct": ["Columnar", "Compressed"], "explanation": "When data is loaded into Snowflake, it uses an internal storage format that is both columnar and compressed. Columnar storage is efficient for analytical processing, and compression reduces storage costs and improves performance.", "reference": "https://docs.snowflake.com/en/user-guide/intro-key-concepts.html#snowflake-architecture"}, {"id": 900, "area": "Data Protection and Data Sharing", "question": "What do temporary and transient tables have in common in Snowflake? (Choose two.)", "options": ["A) Both tables have no Fail-safe period.", "B) Both tables have data retention period maximums of one day.", "C) Both tables are visible only to a single user session.", "D) For both tables, the retention period ends when the tables are dropped.", "E) For both tables, the retention period does not end when the session ends."], "chooseN": 2, "correct": ["Both tables have no Fail-safe period.", "Both tables have data retention period maximums of one day."], "explanation": "Temporary and transient tables in Snowflake have no Fail-safe period and and have data retention periods of one day maximum. These tables differ from permanent tables in terms of data durability and availability.", "reference": "https://docs.snowflake.com/en/user-guide/tables-temp-transient#comparison-of-table-types"}, {"id": 901, "area": "Account Access and Security", "question": "What are the least privileges needed to view and modify resource monitors? (Choose two.)", "options": ["A) SELECT", "B) OWNERSHIP", "C) MONITOR", "D) MODIFY", "E) USAGE"], "chooseN": 2, "correct": ["MONITOR", "MODIFY"], "explanation": "To view and modify resource monitors in Snowflake, the least privileges required are 'MONITOR' and 'MODIFY'. These privileges ensure that the user has the necessary access to manage resource monitors.", "reference": "https://docs.snowflake.com/en/user-guide/resource-monitors.html"}, {"id": 902, "area": "Data Transformations", "question": "When does a materialized view get suspended in Snowflake?", "options": ["A) When a column is added to the base table", "B) When a column is dropped from the base table", "C) When a DML operation is run on the base table", "D) When the base table is reclustered"], "chooseN": 1, "correct": ["When a column is dropped from the base table"], "explanation": "In Snowflake, a materialized view gets suspended when a column is dropped from the base table. This is because the structure of the materialized view depends on the structure of the base table, and dropping a column can invalidate the view.", "reference": "https://docs.snowflake.com/en/user-guide/views-materialized.html"}, {"id": 903, "area": "Data Loading and Unloading", "question": "What happens when a Snowflake user changes the data retention period at the schema level?", "options": ["A) All child objects will retain data for the new retention period.", "B) All child objects that do not have an explicit retention period will automatically inherit the new retention period.", "C) All child objects with an explicit retention period will be overridden with the new retention period.", "D) All explicit child object retention periods will remain unchanged."], "chooseN": 1, "correct": ["All child objects that do not have an explicit retention period will automatically inherit the new retention period."], "explanation": "When a data retention period is changed at the schema level in Snowflake, all child objects that do not have an explicit retention period set will automatically inherit the new retention period. Objects with explicit retention periods will remain unaffected.", "reference": "https://docs.snowflake.com/en/user-guide/data-time-travel#specifying-the-data-retention-period-for-an-object"}, {"id": 904, "area": "Data Transformations", "question": "Snowpark provides libraries for which programming languages? (Choose two.)", "options": ["A) JavaScript", "B) Python", "C) Scala", "D) R", "E) C++"], "chooseN": 2, "correct": ["Python", "Scala"], "explanation": "Snowpark provides libraries specifically for Python and Scala. These libraries enable developers and data scientists to use these programming languages to interact with Snowflake, facilitating data transformations and analysis.", "reference": "https://docs.snowflake.com/en/developer-guide/snowpark/index.html"}, {"id": 905, "area": "Data Transformations", "question": "How can a Snowflake user sample 10 rows from a table named SNOWPRO? (Choose two.)", "options": ["A) SELECT * FROM SNOWPRO SAMPLE SYSTEM (10)", "B) SELECT * FROM SNOWPRO TABLESAMPLE (10 ROWS)", "C) SELECT * FROM SNOWPRO TABLESAMPLE BLOCK (10)", "D) SELECT * FROM SNOWPRO TABLESAMPLE BLOCK (10 ROWS)", "E) SELECT * FROM SNOWPRO SAMPLE BERNOULLI (10 ROWS)"], "chooseN": 2, "correct": ["SELECT * FROM SNOWPRO TABLESAMPLE (10 ROWS)", "SELECT * FROM SNOWPRO SAMPLE BERNOULLI (10 ROWS)"], "explanation": "The correct answer is: SELECT * FROM SNOWPRO TABLESAMPLE (10 ROWS), SELECT * FROM SNOWPRO SAMPLE BERNOULLI (10 ROWS). The SAMPLE doc shows fixed-size row sampling syntax: 'BERNOULLI | ROW ( num ROWS )'. Default method when unspecified is BERNOULLI. Option B 'TABLESAMPLE (10 ROWS)' uses default BERNOULLI and is valid. Option E 'SAMPLE BERNOULLI (10 ROWS)' explicitly uses BERNOULLI and is valid. BLOCK/SYSTEM does not support fixed-size sampling. The question says 'Choose two' but only E was marked. Both B and E are correct. Reference: https://docs.snowflake.com/en/sql-reference/constructs/sample", "reference": "https://docs.snowflake.com/en/sql-reference/constructs/sample.html"}, {"id": 906, "area": "Data Loading and Unloading", "question": "Why would a Snowflake user choose to use a transient table?", "options": ["A) To store data for long-term analysis", "B) To store large data files that are used frequently", "C) To create a permanent table for ongoing use in ELT", "D) To store transitory data that needs to be maintained beyond the session"], "chooseN": 1, "correct": ["To store transitory data that needs to be maintained beyond the session"], "explanation": "A Snowflake user would choose to use a transient table to store transitory data that needs to be maintained beyond the session. Transient tables are designed for temporary or intermediate datasets that do not require the full data retention capabilities of permanent tables.", "reference": "https://docs.snowflake.com/en/user-guide/tables-temp-transient.html#transient-tables"}, {"id": 907, "area": "Data Protection and Data Sharing", "question": "What does a masking policy consist of in Snowflake?", "options": ["A) A single data type, with one or more conditions, and one or more masking functions", "B) A single data type, with only one condition, and only one masking function", "C) Multiple data types, with only one condition, and one or more masking functions", "D) Multiple data types, with one or more conditions, and one or more masking functions"], "chooseN": 1, "correct": ["A single data type, with one or more conditions, and one or more masking functions"], "explanation": "A masking policy in Snowflake consists of a single data type with one or more conditions and one or more masking functions. This allows for the dynamic masking of data based on specific conditions, ensuring data security and privacy.", "reference": "https://docs.snowflake.com/en/user-guide/security-column-intro"}, {"id": 908, "area": "Data Protection and Data Sharing", "question": "What actions can be performed by a consumer account on a shared database? (Choose two.)", "options": ["A) Cloning a shared table", "B) Modifying the data in a shared table", "C) Using Time Travel on a shared table", "D) Executing the SELECT statement on a shared table", "E) Joining the data from a shared table with another table"], "chooseN": 2, "correct": ["Executing the SELECT statement on a shared table", "Joining the data from a shared table with another table"], "explanation": "In Snowflake, a consumer account can perform actions such as executing the SELECT statement on a shared table and joining the data from a shared table with another table. These actions allow consumers to query and analyze the shared data while maintaining data integrity.", "reference": "https://docs.snowflake.com/en/user-guide/data-share-consumers"}, {"id": 909, "area": "Data Transformations", "question": "What data type is used to ingest semi-structured data into a Snowflake table?", "options": ["A) BOOLEAN", "B) NUMBER", "C) VARBINARY", "D) VARIANT"], "chooseN": 1, "correct": ["VARIANT"], "explanation": "The VARIANT data type is used in Snowflake to ingest semi-structured data into a table. This type can store structured and semi-structured data, such as JSON, XML, Avro, or Parquet, in a single column.", "reference": "https://docs.snowflake.com/en/user-guide/semistructured-intro.html"}, {"id": 910, "area": "Account Access and Security", "question": "Which security feature is used to connect or log in to a Snowflake account?", "options": ["A) Network policy", "B) SCIM", "C) Role-Based Access Control (RBAC)", "D) Key pair authentication"], "chooseN": 1, "correct": ["Key pair authentication"], "explanation": "Key pair authentication is a security feature used to connect or log in to a Snowflake account. It involves the use of a private key and a corresponding public key for secure authentication, enhancing the overall security of the account.", "reference": "https://docs.snowflake.com/en/user-guide/key-pair-auth.html"}, {"id": 911, "area": "Data Protection and Data Sharing", "question": "Given the statement template below, which database objects can be added to a share? (Choose two.) GRANT ON TO SHARE ;", "options": ["A) Secure functions", "B) Stored procedures", "C) Streams", "D) Tables", "E) Tasks"], "chooseN": 2, "correct": ["Secure functions", "Tables"], "explanation": "Using the GRANT ... ON ... TO SHARE statement in Snowflake, database objects like Tables and Secure Functions (UDFs/UDTFs) can be added to a share. Additionally, Secure Views and Secure Materialized Views can also be shared. Stored procedures, streams, and tasks cannot be added to shares.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-intro.html"}, {"id": 912, "area": "Performance Concepts", "question": "Which Snowflake feature or tool helps troubleshoot issues in SQL query expressions that commonly cause performance bottlenecks?", "options": ["A) Persisted query results", "B) QUERY_HISTORY view", "C) Query acceleration service", "D) Query Profile"], "chooseN": 1, "correct": ["Query Profile"], "explanation": "The Query Profile in Snowflake is a feature that helps troubleshoot issues in SQL query expressions that commonly cause performance bottlenecks. It provides a detailed graphical representation of query execution, helping users optimize query performance.", "reference": "https://docs.snowflake.com/en/user-guide/ui-query-profile.html"}, {"id": 913, "area": "Data Protection and Data Sharing", "question": "What is a non-configurable feature that provides historical data that Snowflake may recover during a 7-day period?", "options": ["A) Fail-safe", "B) Time Travel", "C) Cloning", "D) Account replication"], "chooseN": 1, "correct": ["Fail-safe"], "explanation": "Fail-safe is a non-configurable feature in Snowflake that provides historical data recovery for a 7-day period. It is designed as a last resort to protect against data loss and is automatically included to provide additional protection beyond the Time Travel period.", "reference": "https://docs.snowflake.com/en/user-guide/data-failsafe"}, {"id": 914, "area": "Data Protection and Data Sharing", "question": "Which function should be used to authorize users to access rows in a base table when using secure views with Secure Data Sharing?", "options": ["A) CURRENT_ACCOUNT()", "B) CURRENT_ROLE()", "C) CURRENT_SESSION()", "D) CURRENT_USER()"], "chooseN": 1, "correct": ["CURRENT_ACCOUNT()"], "explanation": "When using secure views with Secure Data Sharing, use the CURRENT_ACCOUNT function to authorize users from a specific account to access rows in a base table.", "reference": "https://docs.snowflake.com/en/user-guide/views-secure#secure-views-and-data-sharing"}, {"id": 915, "area": "Performance Concepts", "question": "What is the purpose of collecting statistics on data in Snowflake?", "options": ["A) To identify data storage order correlations", "B) To enable efficient pruning based on query filters", "C) To reduce the total number of micro-partitions in a table", "D) To optimize query performance by reading all data in a table"], "chooseN": 1, "correct": ["To enable efficient pruning based on query filters"], "explanation": "Collecting statistics on data in Snowflake is primarily for enabling efficient pruning based on query filters. These statistics help Snowflake's query optimizer to determine the most efficient way to access data, often leading to performance improvements.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions"}, {"id": 916, "area": "Data Transformations", "question": "What type of function returns one value for each invocation?", "options": ["A) Aggregate", "B) Scalar", "C) Table", "D) Window"], "chooseN": 1, "correct": ["Scalar"], "explanation": "Scalar functions in Snowflake return one value for each invocation. These functions operate on a single value and return a single value, making them distinct from aggregate, table, or window functions.", "reference": "https://docs.snowflake.com/en/sql-reference/functions.html"}, {"id": 917, "area": "Data Loading and Unloading", "question": "Which file formats support unloading semi-structured data? (Choose two.)", "options": ["A) Avro", "B) JSON", "C) ORC", "D) Parquet", "E) XML"], "chooseN": 2, "correct": ["JSON", "Parquet"], "explanation": "The file formats that support unloading semi-structured data in Snowflake are JSON and Parquet. These formats are capable of handling the complex structures of semi-structured data, such as nested arrays and objects.", "reference": "https://docs.snowflake.com/en/user-guide/data-unload-considerations.html"}, {"id": 918, "area": "Account Access and Security", "question": "Which system-defined Snowflake role has permission to rename an account and specify whether the original URL can be used to access the renamed account?", "options": ["A) ACCOUNTADMIN", "B) SECURITYADMIN", "C) SYSADMIN", "D) ORGADMIN"], "chooseN": 1, "correct": ["ORGADMIN"], "explanation": "- ORGADMIN: El rol 'ORGADMIN' tiene los permisos necesarios para renombrar una cuenta y especificar si se puede usar la URL original para acceder a la cuenta renombrada. Los otros roles mencionados no tienen este permiso específico.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/alter-account"}, {"id": 919, "area": "Performance Concepts", "question": "How can a user get the MOST detailed information about individual table storage details in Snowflake?", "options": ["A) SHOW TABLES command", "B) SHOW EXTERNAL TABLES command", "C) TABLES view", "D) TABLE_STORAGE_METRICS view"], "chooseN": 1, "correct": ["TABLE_STORAGE_METRICS view"], "explanation": "- TABLE_STORAGE_METRICS view: La vista 'TABLE_STORAGE_METRICS' proporciona la información más detallada sobre el almacenamiento de tablas individuales en Snowflake. Los otros métodos como 'SHOW TABLES' y 'SHOW EXTERNAL TABLES' ofrecen información más general y no detallada sobre el almacenamiento.", "reference": "https://docs.snowflake.com/en/sql-reference/account-usage/table_storage_metrics"}, {"id": 920, "area": "Data Protection and Data Sharing", "question": "What type of account can be used to share data with a consumer who does not have a Snowflake account?", "options": ["A) Data provider", "B) Data consumer", "C) Reader", "D) Organization"], "chooseN": 1, "correct": ["Reader"], "explanation": "- Reader: Una cuenta 'Reader' se utiliza para compartir datos con consumidores que no tienen una cuenta de Snowflake. Las cuentas 'Data provider' y 'Data consumer' están relacionadas con la provisión y el consumo de datos dentro de Snowflake, mientras que 'Organization' no es un tipo de cuenta aplicable para el intercambio de datos con consumidores externos.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-intro"}, {"id": 921, "area": "Account Access and Security", "question": "By default, which role has access to the SYSTEM$GLOBAL_ACCOUNT_SET_PARAMETER function?", "options": ["A) ACCOUNTADMIN", "B) SECURITYADMIN", "C) SYSADMIN", "D) ORGADMIN"], "chooseN": 1, "correct": ["ORGADMIN"], "explanation": "- ORGADMIN: Por defecto, solo los administradores de la organización (usuarios con el rol 'ORGADMIN') tienen acceso a la función SYSTEM$GLOBAL_ACCOUNT_SET_PARAMETER. Los otros roles como 'ACCOUNTADMIN', 'SECURITYADMIN' y 'SYSADMIN' no tienen acceso a esta función específica que está relacionada con la configuración de replicación y redirección de clientes para una cuenta en una organización.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/system_global_account_set_parameter"}, {"id": 922, "area": "Performance Concepts", "question": "If a virtual warehouse is suspended, what happens to the warehouse cache?", "options": ["A) The cache is dropped when the warehouse is suspended and is no longer available upon restart.", "B) The warehouse cache persists for as long as the warehouse exists, regardless of its suspension status.", "C) The cache is maintained for up to two hours and can be restored if the warehouse is restarted within this limit.", "D) The cache is maintained for the auto_suspend duration and can be restored if the warehouse is restarted within this limit."], "chooseN": 1, "correct": ["The cache is dropped when the warehouse is suspended and is no longer available upon restart."], "explanation": "- The cache is dropped when the warehouse is suspended and is no longer available upon restart.: Cuando un almacén virtual se suspende, su caché se elimina y no está disponible cuando se reinicia. Las otras opciones no reflejan correctamente el comportamiento del caché en relación con la suspensión del almacén virtual.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-considerations, https://docs.snowflake.com/en/user-guide/performance-query-warehouse-cache"}, {"id": 923, "area": "Account Access and Security", "question": "What are the primary authentication methods that Snowflake supports for securing REST API interactions? (Choose two.)", "options": ["A) OAuth", "B) Key pair authentication", "C) Federated authentication", "D) Multi-Factor Authentication (MFA)", "E) Username and password authentication"], "chooseN": 2, "correct": ["OAuth", "Key pair authentication"], "explanation": "- OAuth: OAuth es un protocolo estándar de la industria para autorización que permite a las aplicaciones de terceros obtener acceso limitado a cuentas de usuario sin exponer credenciales. Snowflake lo admite para interacciones REST API.\n- Key pair authentication: La autenticación con pares de claves utiliza un par de claves públicas y privadas para la autenticación, lo que proporciona un método altamente seguro para el acceso programático a las APIs REST de Snowflake. \n\n- Federated authentication: No es una opción admitida para la autenticación de REST API en Snowflake.\n- Multi-Factor Authentication (MFA): MFA no es una opción de autenticación para las interacciones de la API REST de Snowflake.\n- Username and password authentication: La autenticación por nombre de usuario y contraseña se usa para accesos estándar, no para APIs REST específicas.", "reference": "https://docs.snowflake.com/en/developer-guide/sql-api/authenticating, https://docs.snowflake.com/en/user-guide/api-authentication"}, {"id": 924, "area": "Data Loading and Unloading", "question": "A Snowflake user is trying to load a 125 GB file using SnowSQL. The file continues to load for almost an entire day. What will happen at the 24-hour mark?", "options": ["A) The file will continue to load until all contents are loaded.", "B) The file will stop loading and all data up to that point will be committed.", "C) The file loading could be aborted without any portion of the file being committed.", "D) The file’s number of allowable hours to load can be programmatically controlled to load easily into Snowflake."], "chooseN": 1, "correct": ["The file loading could be aborted without any portion of the file being committed."], "explanation": "- The file loading could be aborted without any portion of the file being committed.: Si una operación de carga de datos supera la duración máxima permitida de 24 horas, puede ser abortada sin que se haya comprometido ninguna porción del archivo. Esto puede ocurrir si el archivo es muy grande y la carga toma demasiado tiempo.\n\n- The file will continue to load until all contents are loaded.: Esta opción no es correcta ya que la operación puede ser abortada si supera el tiempo máximo permitido.\n- The file will stop loading and all data up to that point will be committed.: No es cierto que los datos se comprometan hasta el punto en que se detiene la carga; puede no comprometerse nada si la carga se aborta.\n- The file’s number of allowable hours to load can be programmatically controlled to load easily into Snowflake.: No hay una configuración programática para controlar el número de horas permitidas para la carga del archivo.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-considerations-prepare"}, {"id": 925, "area": "Performance Concepts", "question": "What information does the Query Profile provide?", "options": ["A) Graphical representation of the data model", "B) Statistics for each component of the processing plan", "C) Detailed information about the database schema", "D) Real-time monitoring of the database operations"], "chooseN": 1, "correct": ["Statistics for each component of the processing plan"], "explanation": "- Statistics for each component of the processing plan: El 'Query Profile' de Snowflake ofrece detalles de ejecución para una consulta, incluyendo estadísticas para cada componente del plan de procesamiento y una representación gráfica de los componentes del plan y la consulta en general. Las otras opciones no reflejan con precisión la información proporcionada por el Query Profile.", "reference": "https://docs.snowflake.com/en/sql-reference/queries/query-profile.html"}, {"id": 926, "area": "Account Access and Security", "question": "Which command is used to start configuring Snowflake for Single Sign-On (SSO)?", "options": ["A) CREATE SESSION POLICY", "B) CREATE NETWORK RULE", "C) CREATE SECURITY INTEGRATION", "D) CREATE PASSWORD POLICY"], "chooseN": 1, "correct": ["CREATE SECURITY INTEGRATION"], "explanation": "- CREATE SECURITY INTEGRATION: El comando 'CREATE SECURITY INTEGRATION' se utiliza para configurar Snowflake para Single Sign-On (SSO) y otras integraciones de seguridad. Las otras opciones no son correctas para este propósito: 'CREATE SESSION POLICY' se usa para políticas de sesión, 'CREATE NETWORK RULE' para reglas de red, y 'CREATE PASSWORD POLICY' para políticas de contraseñas.", "reference": "https://docs.snowflake.com/en/user-guide/admin-security-fed-auth-security-integration.html"}, {"id": 927, "area": "Account Access and Security", "question": "Which sequence (order) of object privileges should be used to grant a custom role read-only access on a table?", "options": ["A) 1. Object: schema - privilege: usage 2. Object: database - privilege: usage 3. Object: table - privilege: usage", "B) 1. Object: schema - privilege: usage 2. Object: database - privilege: usage 3. Object: table - privilege: select", "C) 1. Object: database - privilege: usage 2. Object: schema - privilege: usage 3. Object: table - privilege: select", "D) 1. Object: database - privilege: usage 2. Object: schema - privilege: usage 3. Object: table - privilege: operate"], "chooseN": 1, "correct": ["1. Object: database - privilege: usage 2. Object: schema - privilege: usage 3. Object: table - privilege: select"], "explanation": "- 1. Object: database - privilege: usage 2. Object: schema - privilege: usage 3. Object: table - privilege: select: Para otorgar acceso de solo lectura a una tabla, primero debes otorgar el privilegio de uso en la base de datos, luego en el esquema y finalmente el privilegio de selección en la tabla. Las otras opciones no siguen el orden correcto para conceder acceso de solo lectura.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/grant-privilege.html"}, {"id": 928, "area": "Account Access and Security", "question": "Which command removes a role from another role or a user in Snowflake?", "options": ["A) ALTER ROLE", "B) REVOKE ROLE", "C) USE ROLE", "D) USE SECONDARY ROLES"], "chooseN": 1, "correct": ["REVOKE ROLE"], "explanation": "- REVOKE ROLE: El comando 'REVOKE ROLE' se utiliza para eliminar un rol de otro rol o de un usuario en Snowflake. Los otros comandos tienen funciones diferentes: 'ALTER ROLE' se usa para modificar atributos de un rol, 'USE ROLE' cambia el rol activo del usuario, y 'USE SECONDARY ROLES' se utiliza para habilitar roles secundarios adicionales.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/revoke-role.html"}, {"id": 929, "area": "Snowflake Data Cloud Features & Architecture", "question": "In which hierarchy is tag inheritance possible?", "options": ["A) Organization » Account » Role", "B) Account » User » Schema", "C) Database » View » Column", "D) Schema » Table » Column"], "chooseN": 1, "correct": ["Schema » Table » Column"], "explanation": "- Schema » Table » Column: En Snowflake, la herencia de etiquetas es posible en la jerarquía de 'Schema » Table » Column'. Las otras opciones no representan una jerarquía válida para la herencia de etiquetas en Snowflake: 'Organization » Account » Role' y 'Account » User » Schema' no son niveles de herencia válidos, y 'Database » View » Column' no incluye 'View' como parte de la herencia.", "reference": "https://docs.snowflake.com/en/user-guide/object-tagging.html"}, {"id": 930, "area": "Account Access and Security", "question": "What happens when a network policy includes values that appear in both the allowed and blocked IP address lists?", "options": ["A) Those IP addresses are allowed access to the Snowflake account as Snowflake applies the allowed IP address list first.", "B) Those IP addresses are denied access to the Snowflake account as Snowflake applies the blocked IP address list first.", "C) Snowflake issues an alert message and adds the duplicate IP address values to both the allowed and blocked IP address lists.", "D) Snowflake issues an error message and adds the duplicate IP address values to both the allowed and blocked IP address lists."], "chooseN": 1, "correct": ["Those IP addresses are denied access to the Snowflake account as Snowflake applies the blocked IP address list first."], "explanation": "- Those IP addresses are denied access to the Snowflake account as Snowflake applies the blocked IP address list first.: En Snowflake, si una política de red incluye valores en ambas listas, la lista de IP bloqueadas tiene prioridad sobre la lista de IP permitidas. Por lo tanto, las direcciones IP que aparecen en ambas listas serán bloqueadas. Las otras opciones no son correctas ya que Snowflake no permite la superposición de listas permitidas y bloqueadas de esta manera.", "reference": "https://docs.snowflake.com/en/user-guide/network-policies.html"}, {"id": 931, "area": "Data Loading and Unloading", "question": "For directory tables, what stage allows for automatic refreshing of metadata?", "options": ["A) User stage", "B) Table stage", "C) Named internal stage", "D) Named external stage"], "chooseN": 1, "correct": ["Named external stage"], "explanation": "- Named external stage: La opción correcta es 'Named external stage', ya que este tipo de stage permite la actualización automática de metadatos para tablas de directorio. Las otras opciones no soportan esta funcionalidad de manera automática.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-dirtables-auto"}, {"id": 932, "area": "Data Loading and Unloading", "question": "Which command is used to unload data from a Snowflake database table into one or more files in a Snowflake stage?", "options": ["A) CREATE STAGE", "B) COPY INTO [table]", "C) COPY INTO [location]", "D) CREATE PIPE"], "chooseN": 1, "correct": ["COPY INTO [location]"], "explanation": "- **COPY INTO [location]**: El comando 'COPY INTO [location]' se utiliza para descargar datos desde una tabla de Snowflake hacia uno o más archivos en un stage de Snowflake. Las otras opciones no realizan esta tarea: 'CREATE STAGE' crea un stage, 'COPY INTO [table]' no es un comando válido para esta acción, y 'CREATE PIPE' se usa para definir procesos de carga continua.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-location"}, {"id": 933, "area": "Performance Concepts", "question": "Any user with the appropriate privileges can view data storage for individual tables by using which queries? (Choose two.)", "options": ["A) METERING_HISTORY view in the ACCOUNT_USAGE schema", "B) TABLE_STORAGE_METRICS view in the ACCOUNT_USAGE schema", "C) STORAGE_USAGE view in the ACCOUNT_USAGE schema", "D) TABLE_STORAGE_METRICS view in the INFORMATION_SCHEMA schema", "E) METERING_DAILY_HISTORY view in the ORGANIZATION_USAGE schema"], "chooseN": 2, "correct": ["TABLE_STORAGE_METRICS view in the ACCOUNT_USAGE schema", "TABLE_STORAGE_METRICS view in the INFORMATION_SCHEMA schema"], "explanation": "Users with appropriate privileges can view data storage for individual tables using:\n- TABLE_STORAGE_METRICS view in the ACCOUNT_USAGE schema: Provides detailed information about data storage for specific tables at the account level.\n- TABLE_STORAGE_METRICS view in the INFORMATION_SCHEMA schema: Also provides information about data storage for tables within a specific database.\nBoth views contain metrics about active bytes, time travel bytes, and failsafe bytes for individual tables.", "reference": "https://docs.snowflake.com/en/user-guide/tables-storage-considerations"}, {"id": 934, "area": "Data Protection and Data Sharing", "question": "A user created a database and set the DATA_RETENTION_TIME_IN_DAYS to 30, but did not set the DATA_RETENTION_TIME_IN_DAYS in table T1. After 5 days, the user accidentally drops table T1. What are the considerations for recovering table T1?", "options": ["A) The user can recover the table T1 after 30 days.", "B) The table can be recovered because the table retention period default is at the database level.", "C) The table can only be recovered by contacting Snowflake Support to recover the table from Fail-safe.", "D) The table cannot be recovered because the DATA_RETENTION_TIME_IN_DAYS was not set for table T1."], "chooseN": 1, "correct": ["The table can be recovered because the table retention period default is at the database level."], "explanation": "- The table can be recovered because the table retention period default is at the database level.: En Snowflake, si no se establece un período de retención específico para una tabla, se hereda el período de retención del nivel de la base de datos. Dado que se configuró DATA_RETENTION_TIME_IN_DAYS a 30 días en la base de datos, la tabla T1 puede recuperarse dentro de ese período de retención, incluso si no se especificó un período de retención para la tabla en sí. \n- The user can recover the table T1 after 30 days.: Esto no es correcto porque, en general, el período de retención permite la recuperación solo dentro de ese período, no después. \n- The table can only be recovered by contacting Snowflake Support to recover the table from Fail-safe.: Esta opción es incorrecta ya que la recuperación en Fail-safe no es necesaria en este caso, dado que el período de retención estándar puede cubrir la recuperación. \n- The table cannot be recovered because the DATA_RETENTION_TIME_IN_DAYS was not set for table T1.: No es correcto ya que el período de retención de la base de datos se aplica por defecto.", "reference": "https://docs.snowflake.com/en/user-guide/data-time-travel#specifying-the-data-retention-period-for-an-object"}, {"id": 935, "area": "Data Loading and Unloading", "question": "What table functions in the Snowflake Information Schema can be queried to retrieve information about directory tables? (Choose two.)", "options": ["A) AUTO_REFRESH_REGISTRATION_HISTORY", "B) EXTERNAL_TABLE_FILE_REGISTRATION_HISTORY", "C) EXTERNAL_TABLE_FILES", "D) MATERIALIZED_VIEW_REFRESH_HISTORY", "E) STAGE_DIRECTORY_FILE_REGISTRATION_HISTORY"], "chooseN": 2, "correct": ["AUTO_REFRESH_REGISTRATION_HISTORY", "STAGE_DIRECTORY_FILE_REGISTRATION_HISTORY"], "explanation": "- AUTO_REFRESH_REGISTRATION_HISTORY: This table function retrieves the history of data files registered in the metadata of the specified objects, as well as the credits billed for these operations.\n- STAGE_DIRECTORY_FILE_REGISTRATION_HISTORY: This function retrieves information about the metadata history for a directory table, including any errors encountered when refreshing the metadata.\n- EXTERNAL_TABLE_FILE_REGISTRATION_HISTORY: This function is not specifically designed for directory tables; it retrieves the history of metadata for external tables.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-dirtables"}, {"id": 936, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which Snowflake table type persists until it is explicitly dropped, is available for all users with relevant privileges (across sessions), and has no Fail-safe period?", "options": ["A) External", "B) Permanent", "C) Temporary", "D) Transient"], "chooseN": 1, "correct": ["Transient"], "explanation": "- Transient: Las tablas transitorias en Snowflake persisten hasta que se eliminan explícitamente, están disponibles para todos los usuarios con privilegios relevantes (a través de sesiones) y no tienen un período de Fail-safe.\n- External: Las tablas externas se refieren a datos almacenados fuera de Snowflake, no a las características de persistencia o Fail-safe.\n- Permanent: Las tablas permanentes están diseñadas para persistir indefinidamente y tienen un período de Fail-safe para la recuperación de datos.\n- Temporary: Las tablas temporales existen solo durante la sesión en la que se crean y se eliminan automáticamente al final de la sesión.", "reference": "https://docs.snowflake.com/en/user-guide/tables-transient.html"}, {"id": 937, "area": "Account Access and Security", "question": "Snowflake’s access control framework combines which models for securing data? (Choose two.)", "options": ["A) Attribute-based Access Control (ABAC)", "B) Discretionary Access Control (DAC)", "C) Access Control List (ACL)", "D) Role-based Access Control (RBAC)", "E) Rule-based Access Control (RuBAC)"], "chooseN": 2, "correct": ["Discretionary Access Control (DAC)", "Role-based Access Control (RBAC)"], "explanation": "- Discretionary Access Control (DAC): Snowflake utiliza DAC, que permite a los propietarios de datos decidir quién tiene acceso a sus recursos.\n- Role-based Access Control (RBAC): Snowflake también emplea RBAC, donde los permisos se asignan a roles y los usuarios obtienen permisos a través de esos roles.\n- Attribute-based Access Control (ABAC): ABAC no es parte del marco de control de acceso de Snowflake; este modelo se basa en atributos para determinar los permisos.\n- Access Control List (ACL): ACL no es una técnica de control de acceso utilizada en Snowflake, se enfoca en listas de permisos específicos para recursos.\n- Rule-based Access Control (RuBAC): RuBAC tampoco es utilizado por Snowflake; este modelo se basa en reglas predefinidas para gestionar el acceso.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control.html"}, {"id": 938, "area": "Performance Concepts", "question": "Which semi-structured file format is a compressed, efficient, columnar data representation?", "options": ["A) Avro", "B) JSON", "C) TSV", "D) Parquet"], "chooseN": 1, "correct": ["Parquet"], "explanation": "- Parquet: Apache Parquet es un formato de archivo abierto, orientado a columnas, diseñado para un almacenamiento y recuperación de datos eficiente. Es conocido por su compresión y formato columnar que optimiza el rendimiento.\n- Avro: Avro es un formato de archivo binario basado en registros y no orientado a columnas, por lo tanto, no es columnar ni necesariamente el más eficiente para todas las operaciones.\n- JSON: JSON es un formato de datos basado en texto, que no es comprimido ni orientado a columnas. Es útil para datos semi-estructurados pero no es el más eficiente para el almacenamiento y recuperación de datos.\n- TSV: TSV (Tab-Separated Values) es un formato basado en texto que utiliza tabulaciones para separar valores. No está comprimido ni es columnar, lo que lo hace menos eficiente para el almacenamiento y procesamiento comparado con los formatos columnar.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-parquet.html"}, {"id": 939, "area": "Snowflake Data Cloud Features & Architecture", "question": "How does Snowflake describe its unique architecture?", "options": ["A) A single-cluster shared data architecture using a central data repository and massively parallel processing (MPP)", "B) A multi-cluster shared data architecture using a central data repository and massively parallel processing (MPP)", "C) A single-cluster shared nothing architecture using a siloed data repository and symmetric multiprocessing (SMP)", "D) A multi-cluster shared nothing architecture using a siloed data repository and symmetric multiprocessing (SMP)"], "chooseN": 1, "correct": ["A multi-cluster shared data architecture using a central data repository and massively parallel processing (MPP)"], "explanation": "- A multi-cluster shared data architecture using a central data repository and massively parallel processing (MPP): Snowflake utiliza una arquitectura de datos compartidos con múltiples clústeres, empleando un repositorio de datos central y procesamiento en paralelo masivo (MPP). Esto permite una alta escalabilidad y flexibilidad.\n- A single-cluster shared data architecture using a central data repository and massively parallel processing (MPP): Aunque usa procesamiento en paralelo masivo (MPP) y un repositorio de datos central, la arquitectura de Snowflake no se basa en un único clúster sino en múltiples clústeres.\n- A single-cluster shared nothing architecture using a siloed data repository and symmetric multiprocessing (SMP): Esta descripción no se ajusta a Snowflake, ya que no utiliza una arquitectura de 'nada compartido' ni SMP.\n- A multi-cluster shared nothing architecture using a siloed data repository and symmetric multiprocessing (SMP): Snowflake no utiliza una arquitectura de 'nada compartido' ni SMP. Su modelo es de datos compartidos con múltiples clústeres y MPP.", "reference": "https://docs.snowflake.com/en/user-guide/intro-key-concepts#snowflake-architecture"}, {"id": 940, "area": "Data Loading and Unloading", "question": "Which data type can be used to load semi-structured data files directly, without explicitly describing the hierarchical structure of the data?", "options": ["A) TEXT", "B) VARIANT", "C) VARCHAR", "D) VARBINARY"], "chooseN": 1, "correct": ["VARIANT"], "explanation": "- VARIANT: El tipo de dato 'VARIANT' en Snowflake está diseñado para manejar datos semiestructurados, como JSON, Avro, y Parquet, sin necesidad de describir explícitamente la estructura jerárquica del dato. Permite almacenar datos en su forma original y acceder a ellos de manera flexible.\n- TEXT: 'TEXT' es un tipo de dato para datos de texto plano y no está diseñado para manejar datos semiestructurados con estructuras complejas.\n- VARCHAR: Similar a 'TEXT', 'VARCHAR' maneja datos de texto con longitud variable, pero no soporta datos semiestructurados de forma nativa.\n- VARBINARY: 'VARBINARY' es usado para datos binarios y no es adecuado para datos semiestructurados como JSON o Avro.", "reference": "https://docs.snowflake.com/en/sql-reference/data-types/variant"}, {"id": 941, "area": "Data Protection and Data Sharing", "question": "The following settings are configured:\n\nTHE MIN_DATA_RETENTION_TIME_IN_DAYS is set to 5 at the account level.\nTHE DATA_RETENTION_TIME_IN_DAYS is set to 2 at the object level.\n\nFor how many days will the data be retained at the object level?", "options": ["A) 2", "B) 3", "C) 5", "D) 7"], "chooseN": 1, "correct": ["5"], "explanation": "- 5: El período de retención de datos efectivo se establece en el valor máximo entre el tiempo de retención configurado a nivel de cuenta (MIN_DATA_RETENTION_TIME_IN_DAYS) y el tiempo de retención configurado a nivel del objeto (DATA_RETENTION_TIME_IN_DAYS). En este caso, el valor máximo es 5 días.\n- 2: Aunque el tiempo de retención a nivel del objeto está configurado en 2 días, el valor efectivo será el mayor entre el valor a nivel de cuenta y el valor a nivel del objeto.\n- 3: Este valor no es correcto ya que el valor máximo entre 2 y 5 es 5, no 3.\n- 7: Este valor es incorrecto porque no hay configuración que establezca un tiempo de retención de 7 días en este escenario.", "reference": "https://docs.snowflake.com/en/release-notes/bcr-bundles/2023_04/bcr-928?utm_source=legacy&utm_medium=serp&utm_term=MIN_DATA_RETENTION_TIME_IN_DAYS"}, {"id": 942, "area": "Account Access and Security", "question": "Which key access control concept does Snowflake describe as a defined level of access to an object?", "options": ["A) Grant", "B) Privilege", "C) Role", "D) Session"], "chooseN": 1, "correct": ["Privilege"], "explanation": "- Privilege: En Snowflake, un 'Privilege' es un nivel definido de acceso a un objeto. Varios privilegios distintos pueden ser utilizados para controlar la granularidad del acceso concedido a un objeto.\n- Grant: Un 'Grant' se refiere al acto de conceder un privilegio, no al propio nivel de acceso.\n- Role: Un 'Role' es un conjunto de privilegios asignados a los usuarios, no un nivel de acceso específico.\n- Session: Una 'Session' es una instancia de acceso a Snowflake, no un nivel de acceso a un objeto.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-overview"}, {"id": 943, "area": "Performance Concepts", "question": "Which Snowflake object uses credits for maintenance?", "options": ["A) Regular table", "B) Regular view", "C) Materialized view", "D) Cached query result"], "chooseN": 1, "correct": ["Materialized view"], "explanation": "- Materialized view: Las vistas materializadas en Snowflake utilizan créditos para su mantenimiento automático, debido a la necesidad de mantener los datos actualizados.\n- Regular table: Las tablas regulares no utilizan créditos para mantenimiento continuo.\n- Regular view: Las vistas regulares no incurren en costos de mantenimiento porque son simplemente una representación de los datos.\n- Cached query result: Los resultados en caché no requieren mantenimiento continuo ni utilizan créditos.", "reference": "https://docs.snowflake.com/en/user-guide/views-materialized.html"}, {"id": 944, "area": "Performance Concepts", "question": "How many credits does a size 3X-Large virtual warehouse consume if it runs continuously for 2 hours?", "options": ["A) 32", "B) 64", "C) 128", "D) 256"], "chooseN": 1, "correct": ["128"], "explanation": "- 128: Un almacén virtual de tamaño 3X-Large consume 64 créditos por hora. Si funciona continuamente durante 2 horas, el consumo total de créditos es de 64 créditos/hora * 2 horas = 128 créditos.\n- 32: Esta cantidad de créditos se aplica a un almacén virtual de tamaño 2X-Small, no a 3X-Large.\n- 64: Esta cantidad de créditos se aplica a un almacén virtual de tamaño 3X-Small durante una hora, no al tamaño 3X-Large durante 2 horas.\n- 256: Esta cantidad de créditos se aplicaría a un almacén virtual mucho más grande o a una duración mucho mayor, no a un tamaño 3X-Large durante 2 horas.", "reference": "https://docs.snowflake.com/en/user-guide/cost-understanding-compute.html"}, {"id": 945, "area": "Performance Concepts", "question": "What is the purpose of a Query Profile?", "options": ["A) To profile how many times a particular query was executed and analyze its usage statistics over time.", "B) To profile a particular query to understand the mechanics of the query, its behavior, and performance.", "C) To profile the user and/or executing role of a query and all privileges and policies applied on the objects within the query.", "D) To profile which queries are running in each warehouse and identify proper warehouse utilization and sizing for better performance and cost balancing."], "chooseN": 1, "correct": ["To profile a particular query to understand the mechanics of the query, its behavior, and performance."], "explanation": "- To profile a particular query to understand the mechanics of the query, its behavior, and performance.: Un Query Profile en Snowflake se utiliza para analizar cómo se comporta un query en términos de mecánica, rendimiento y comportamiento, permitiendo una comprensión más profunda de su ejecución.\n- To profile how many times a particular query was executed and analyze its usage statistics over time.: Este aspecto está más relacionado con el monitoreo y análisis de uso de los queries, no con la comprensión detallada de su comportamiento y rendimiento.\n- To profile the user and/or executing role of a query and all privileges and policies applied on the objects within the query.: Esto está más relacionado con la seguridad y la gestión de accesos, no con el perfilado del rendimiento de un query.\n- To profile which queries are running in each warehouse and identify proper warehouse utilization and sizing for better performance and cost balancing.: Esto se relaciona con la administración de recursos y el rendimiento del warehouse, no con el perfilado específico de los queries.", "reference": "https://docs.snowflake.com/en/user-guide/query-profile.html"}, {"id": 946, "area": "Performance Concepts", "question": "Which common query problems are identified by the Query Profile? (Choose two.)", "options": ["A) Syntax error", "B) Inefficient pruning", "C) Ambiguous column names", "D) Queries too large to fit in memory", "E) Object does not exist or not authorized"], "chooseN": 2, "correct": ["Inefficient pruning", "Queries too large to fit in memory"], "explanation": "- Inefficient pruning: El Query Profile puede identificar si la poda (pruning) de datos durante la ejecución del query se realiza de manera ineficiente, lo que puede resultar en una exploración de más datos de los necesarios.\n- Queries too large to fit in memory: El Query Profile puede proporcionar información sobre el uso del disco para operaciones donde los resultados intermedios no caben en memoria, lo que se conoce como 'spilling'.\n- Síntax error: Los errores de sintaxis se identifican durante las fases de análisis y compilación del query, no específicamente a través del Query Profile.\n- Ambiguous column names: Los nombres de columna ambiguos también se identifican durante la fase de análisis, no en el Query Profile.\n- Object does not exist or not authorized: Los problemas relacionados con objetos inexistentes o no autorizados se identifican antes de llegar al Query Profile, durante la fase de análisis del query.", "reference": "https://docs.snowflake.com/en/user-guide/ui-query-profile.html"}, {"id": 947, "area": "Performance Concepts", "question": "While running a query on a virtual warehouse in auto-scale mode, additional clusters are started immediately if which setting is configured?", "options": ["A) MAX_CLUSTER_COUNT is increased and new_max_clusters is greater than running_clusters", "B) MAX_CLUSTER_COUNT is decreased and new_max_clusters is less than running_clusters", "C) MIN_CLUSTER_COUNT is increased and new_min_clusters is greater than running_clusters", "D) MIN_CLUSTER_COUNT is decreased and new_min_clusters is less than running_clusters"], "chooseN": 1, "correct": ["MIN_CLUSTER_COUNT is increased and new_min_clusters is greater than running_clusters"], "explanation": "- MIN_CLUSTER_COUNT is increased and new_min_clusters is greater than running_clusters: Cuando se incrementa `MIN_CLUSTER_COUNT` y `new_min_clusters` es mayor que el número actual de clusters en ejecución, se inician inmediatamente clusters adicionales para cumplir con el mínimo configurado.\n- MAX_CLUSTER_COUNT is increased and new_max_clusters is greater than running_clusters: Aumentar `MAX_CLUSTER_COUNT` no hace que se inicien clusters adicionales inmediatamente; los clusters adicionales se inician solo cuando es necesario para manejar la carga de trabajo.\n- MAX_CLUSTER_COUNT is decreased and new_max_clusters is less than running_clusters: Disminuir `MAX_CLUSTER_COUNT` hace que los clusters en exceso se apaguen cuando terminen de ejecutar las sentencias, pero no inicia clusters adicionales.\n- MIN_CLUSTER_COUNT is decreased and new_min_clusters is less than running_clusters: Disminuir `MIN_CLUSTER_COUNT` resulta en que los clusters en exceso se apagan, pero no afecta al inicio inmediato de nuevos clusters.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-multicluster.html#increasing-or-decreasing-clusters-for-a-multi-cluster-warehouse"}, {"id": 948, "area": "Account Access and Security", "question": "Which Snowflake role can manage any object grant globally, including modifying and revoking grants?", "options": ["A) USERADMIN", "B) ORGADMIN", "C) SYSADMIN", "D) SECURITYADMIN"], "chooseN": 1, "correct": ["SECURITYADMIN"], "explanation": "- SECURITYADMIN: El rol `SECURITYADMIN` (Administrador de Seguridad) tiene la capacidad de gestionar cualquier concesión de objeto a nivel global, incluyendo la modificación y revocación de concesiones. Este rol tiene el privilegio de seguridad `MANAGE GRANTS` que le permite modificar cualquier concesión, así como revocarla.\n- USERADMIN: El rol `USERADMIN` (Administrador de Usuarios) se encarga de la gestión de usuarios y roles, pero no tiene la capacidad de gestionar concesiones globalmente.\n- ORGADMIN: El rol `ORGADMIN` (Administrador de Organización) se ocupa de la administración a nivel de la organización, pero no tiene el control global sobre las concesiones de objetos.\n- SYSADMIN: El rol `SYSADMIN` (Administrador de Sistema) gestiona los objetos en una base de datos específica, pero no tiene la capacidad para gestionar concesiones de objetos a nivel global.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-considerations.html"}, {"id": 949, "area": "Data Loading and Unloading", "question": "What is the MINIMUM permission needed to access a file URL from an external stage?", "options": ["A) MODIFY", "B) READ", "C) SELECT", "D) USAGE"], "chooseN": 1, "correct": ["USAGE"], "explanation": "- USAGE: El permiso mínimo requerido para acceder a una URL de archivo desde un escenario externo en Snowflake es 'USAGE'. Este permiso permite utilizar el escenario para acceder a los archivos almacenados en él.\n- READ: El permiso 'READ' se utiliza principalmente en escenarios internos, pero no es necesario para acceder a una URL en un escenario externo.\n- MODIFY: Este permiso se usa para modificar archivos, pero no es necesario para simplemente acceder a ellos.\n- SELECT: Se usa para consultar datos en tablas, no para acceder a archivos en escenarios.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/build_stage_file_url"}, {"id": 950, "area": "Data Protection and Data Sharing", "question": "In the Data Exchange, who can get or request data from the listings? (Choose two.)", "options": ["A) Users with ACCOUNTADMIN role", "B) Users with SYSADMIN role", "C) Users with ORGADMIN role", "D) Users with IMPORT SHARE privilege", "E) Users with MANAGE GRANTS privilege"], "chooseN": 2, "correct": ["Users with ACCOUNTADMIN role", "Users with IMPORT SHARE privilege"], "explanation": "- Users with ACCOUNTADMIN role: Los usuarios con el rol 'ACCOUNTADMIN' tienen permisos amplios y pueden solicitar o obtener datos de las listas en el Data Exchange.\n- Users with IMPORT SHARE privilege: Los usuarios con el privilegio 'IMPORT SHARE' también tienen la capacidad de solicitar o obtener datos de las listas en el Data Exchange.\n- Users with SYSADMIN role: Aunque el rol 'SYSADMIN' tiene privilegios significativos, no tiene permisos específicos para obtener datos de las listas en el Data Exchange.\n- Users with ORGADMIN role: El rol 'ORGADMIN' se centra en la administración de la organización y no tiene permisos directos para solicitar datos del Data Exchange.\n- Users with MANAGE GRANTS privilege: El privilegio 'MANAGE GRANTS' está relacionado con la gestión de permisos y no con la solicitud de datos en el Data Exchange.", "reference": "https://docs.snowflake.com/en/user-guide/data-exchange-using"}, {"id": 951, "area": "Performance Concepts", "question": "What does Snowflake attempt to do if any of the compute resources for a virtual warehouse fail to provision during start-up?", "options": ["A) Repair the failed resources.", "B) Restart the failed resources.", "C) Queue the failed resources.", "D) Provision the failed resources."], "chooseN": 1, "correct": ["Repair the failed resources."], "explanation": "- Repair the failed resources: Si alguno de los recursos de cómputo para un warehouse virtual falla al provisionarse durante el inicio, Snowflake intenta reparar esos recursos fallidos para asegurar el funcionamiento del warehouse.\n- Provision the failed resources: Snowflake no intenta reprovisionar los recursos fallidos directamente, sino que primero trata de repararlos.\n- Restart the failed resources: Reiniciar los recursos fallidos no es el enfoque que Snowflake sigue en estos casos.\n- Queue the failed resources: Los recursos fallidos no se colocan en una cola; se intenta repararlos para que el warehouse pueda operar correctamente.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-tasks"}, {"id": 952, "area": "Account Access and Security", "question": "How does Snowflake define its approach to Discretionary Access Control (DAC)?", "options": ["A) A defined level of access to an object.", "B) An entity to which access can be granted.", "C) Each object has an owner, who can in turn grant access to that object.", "D) Access privileges are assigned to roles, which are in turn assigned to users."], "chooseN": 1, "correct": ["Each object has an owner, who can in turn grant access to that object."], "explanation": "- Each object has an owner, who can in turn grant access to that object.: En el control de acceso discrecional (DAC) de Snowflake, cada objeto tiene un propietario que puede otorgar acceso a ese objeto. Esto permite una gestión más flexible y granular de los permisos.\n- A defined level of access to an object.: Esto no describe DAC en su totalidad, ya que DAC se centra en la propiedad y la capacidad de otorgar acceso, no solo en definir niveles de acceso.\n- An entity to which access can be granted.: Esta descripción es más general y no captura el aspecto de propiedad que es central en DAC.\n- Access privileges are assigned to roles, which are in turn assigned to users.: Esto describe más el control de acceso basado en roles (RBAC), que es diferente del enfoque DAC donde la propiedad y la concesión de acceso son clave.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-overview?utm_source=legacy&utm_medium=serp&utm_term=DAC"}, {"id": 953, "area": "Data Loading and Unloading", "question": "Which command is used to take away staged files from a Snowflake stage after a successful data ingestion?", "options": ["A) DELETE", "B) DROP", "C) REMOVE", "D) TRUNCATE"], "chooseN": 1, "correct": ["REMOVE"], "explanation": "- REMOVE: En Snowflake, el comando 'REMOVE' se utiliza para eliminar archivos de un stage después de una carga de datos exitosa. Esto ayuda a mantener el stage limpio y libre de archivos que ya han sido procesados.\n- DELETE: 'DELETE' no se utiliza para gestionar archivos en un stage. Es más comúnmente usado para eliminar filas de tablas en bases de datos.\n- DROP: 'DROP' se usa para eliminar completamente un objeto de Snowflake, como una tabla o un stage, no solo para eliminar archivos de un stage.\n- TRUNCATE: 'TRUNCATE' se usa para eliminar todos los datos de una tabla sin eliminar la estructura de la tabla. No se aplica a la eliminación de archivos de un stage.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-considerations-manage, https://docs.snowflake.com/en/sql-reference/sql/remove"}, {"id": 954, "area": "Performance Concepts", "question": "The Snowflake VARIANT data type imposes a 16 MB size limit on what?", "options": ["A) An individual row", "B) An individual column", "C) A view", "D) A file in a stage"], "chooseN": 1, "correct": ["An individual row"], "explanation": "Snowflake documentation states that a VARIANT value can have a maximum size of up to 128 MB of uncompressed data, and that objects larger than 16 MB can be stored in VARIANT columns by default. Therefore, the 16 MB figure is not a limit on a VARIANT column, view, or staged file; the relevant storage", "reference": "https://docs.snowflake.com/en/user-guide/semistructured-considerations"}, {"id": 955, "area": "Data Transformations", "question": "Which Snowflake feature records changes made to a table so actions can be taken using that change data capture?", "options": ["A) Materialized View", "B) Pipe", "C) Stream", "D) Task"], "chooseN": 1, "correct": ["Stream"], "explanation": "- Stream: La característica de 'Stream' en Snowflake se utiliza para registrar los cambios realizados en una tabla. Permite capturar datos modificados para ser utilizados en procesos de cambio de datos y transformación posteriores.\n- Materialized View: Las 'Materialized Views' almacenan resultados precomputados de consultas, pero no registran cambios en las tablas subyacentes.\n- Pipe: Un 'Pipe' se utiliza para cargar datos automáticamente desde un stage a una tabla, pero no se ocupa de registrar cambios en la tabla.\n- Task: Los 'Tasks' en Snowflake son trabajos programados que ejecutan consultas SQL, pero no están diseñados para capturar cambios en los datos.", "reference": "https://docs.snowflake.com/en/user-guide/streams.html"}, {"id": 956, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which system-defined, read-only view displays information on column lineage that specifies how data flows from source to target in a SQL write operation?", "options": ["A) ACCESS_HISTORY", "B) LOAD_HISTORY", "C) QUERY_HISTORY", "D) COPY_HISTORY"], "chooseN": 1, "correct": ["ACCESS_HISTORY"], "explanation": "- ACCESS_HISTORY: La vista 'ACCESS_HISTORY' en Snowflake muestra el historial de acceso de los datos, incluyendo cómo fluyen los datos desde las columnas de origen hasta las columnas de destino en operaciones de escritura SQL como INSERT, UPDATE y DELETE. También proporciona información sobre cómo se mueve el dato en operaciones que implican la modificación de objetos.\n- LOAD_HISTORY: 'LOAD_HISTORY' muestra información sobre las cargas de datos realizadas, pero no sobre la línea de datos a nivel de columna.\n- QUERY_HISTORY: 'QUERY_HISTORY' proporciona detalles sobre las consultas ejecutadas, pero no específicamente sobre la línea de datos en operaciones de escritura.\n- COPY_HISTORY: 'COPY_HISTORY' detalla la información relacionada con las operaciones COPY, no la línea de datos a nivel de columna.", "reference": "https://docs.snowflake.com/en/user-guide/access-history"}, {"id": 957, "area": "Account Access and Security", "question": "Who can create network policies within Snowflake? (Choose two.)", "options": ["A) SYSADMIN only", "B) ORGADMIN only", "C) SECURITYADMIN or higher roles", "D) A role with the CREATE NETWORK POLICY privilege", "E) A role with the CREATE SECURITY INTEGRATION privilege"], "chooseN": 2, "correct": ["SECURITYADMIN or higher roles", "A role with the CREATE NETWORK POLICY privilege"], "explanation": "- SECURITYADMIN or higher roles: Solo los administradores de seguridad (es decir, usuarios con el rol SECURITYADMIN) o roles superiores pueden crear políticas de red en Snowflake. Estos roles tienen permisos adecuados para gestionar políticas de seguridad.\n- A role with the CREATE NETWORK POLICY privilege: También se puede crear políticas de red mediante un rol que tenga el privilegio global CREATE NETWORK POLICY.\n- SYSADMIN only: El rol SYSADMIN no tiene permisos específicos para crear políticas de red; necesita ser un rol de seguridad o tener el privilegio adecuado.\n- ORGADMIN only: El rol ORGADMIN no tiene el privilegio por defecto para crear políticas de red.\n- A role with the CREATE SECURITY INTEGRATION privilege: El privilegio CREATE SECURITY INTEGRATION no está relacionado con la creación de políticas de red.", "reference": "https://docs.snowflake.com/en/user-guide/network-policies"}, {"id": 958, "area": "Account Access and Security", "question": "Who can grant object privileges in a regular schema?", "options": ["A) Object owner", "B) Schema owner", "C) Database owner", "D) SYSADMIN"], "chooseN": 1, "correct": ["Object owner"], "explanation": "- Object owner: En esquemas regulares (es decir, no gestionados), el propietario de un objeto (como una tabla, vista o procedimiento) puede otorgar privilegios sobre ese objeto a otros roles o usuarios. La propiedad de un objeto le da al usuario control total sobre él, incluida la capacidad de gestionar el acceso.\n- Schema owner: Aunque el propietario del esquema tiene un control más amplio y puede gestionar los privilegios en cualquier objeto dentro de ese esquema en esquemas gestionados, en esquemas regulares el propietario del objeto tiene el control directo sobre el objeto específico.\n- Database owner: El propietario de la base de datos no tiene privilegios directos sobre objetos individuales dentro de esquemas regulares.\n- SYSADMIN: El rol SYSADMIN tiene permisos de alto nivel, pero no está directamente relacionado con la concesión de privilegios sobre objetos en un esquema regular.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-configure#label-managed-access-schemas"}, {"id": 959, "area": "Account Access and Security", "question": "Which command can be used to list all the file formats for which a user has access privileges?", "options": ["A) LIST", "B) ALTER FILE FORMAT", "C) DESCRIBE FILE FORMAT", "D) SHOW FILE FORMATS"], "chooseN": 1, "correct": ["SHOW FILE FORMATS"], "explanation": "- SHOW FILE FORMATS: El comando 'SHOW FILE FORMATS' es utilizado para listar todos los formatos de archivo a los que un usuario tiene privilegios de acceso. \n- **LIST**: El comando 'LIST' se utiliza para listar los archivos en un stage o almacenamiento externo, no para listar formatos de archivo.\n- **ALTER FILE FORMAT**: Este comando se usa para modificar un formato de archivo existente, no para listar los formatos disponibles.\n- **DESCRIBE FILE FORMAT**: 'DESCRIBE FILE FORMAT' devuelve la definición de un formato de archivo en específico, pero no lista todos los formatos disponibles.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/show-file-formats"}, {"id": 960, "area": "Data Loading and Unloading", "question": "Which Snowflake feature supports continuous, serverless data loading into tables as soon as new data arrives?", "options": ["A) Snowpark", "B) SnowSQL", "C) SnowCD", "D) Snowpipe"], "chooseN": 1, "correct": ["Snowpipe"], "explanation": "- Snowpipe: 'Snowpipe' es el servicio de Snowflake que permite la carga continua y sin servidor de datos en las tablas tan pronto como llega nueva información. Este proceso es automático y permite que los datos se carguen en lotes pequeños, facilitando cargas casi en tiempo real.\n- **Snowpark**: Snowpark es una herramienta para desarrolladores que permite escribir código en varios lenguajes dentro de Snowflake, pero no está relacionada con la carga continua de datos.\n- **SnowSQL**: SnowSQL es la interfaz de línea de comandos para ejecutar consultas y administrar Snowflake, pero no es un servicio de carga de datos.\n- **SnowCD**: No existe una funcionalidad llamada 'SnowCD' en Snowflake.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-snowpipe-intro"}, {"id": 961, "area": "Performance Concepts", "question": "What value provides information about disk usage for operations where intermediate results do not fit in memory in a Query Profile?", "options": ["A) IO", "B) Network", "C) Pruning", "D) Spilling"], "chooseN": 1, "correct": ["Spilling"], "explanation": "- Spilling: 'Spilling' se refiere a cuando los resultados intermedios de una consulta no caben en la memoria y Snowflake necesita escribir estos datos en disco. Este evento puede impactar el rendimiento, ya que el acceso a disco es más lento que el acceso a la memoria.\n- **IO**: 'IO' mide el rendimiento de entrada y salida, pero no está específicamente relacionado con el uso de disco debido a la falta de memoria durante una consulta.\n- **Network**: 'Network' mide la transferencia de datos a través de la red, no el uso de disco durante las operaciones de consulta.\n- **Pruning**: 'Pruning' se refiere a la eliminación de micro-particiones innecesarias para optimizar consultas, pero no está relacionado con el uso de disco cuando los resultados no caben en la memoria.", "reference": "https://community.snowflake.com/s/article/Performance-impact-from-local-and-remote-disk-spilling"}, {"id": 962, "area": "Data Transformations", "question": "Regardless of which notation is used, what are considerations for writing the column name and element names when traversing semi-structured data?", "options": ["A) The column name and element names are both case-sensitive.", "B) The column name and element names are both case-insensitive.", "C) The column name is case-sensitive but element names are case-insensitive.", "D) The column name is case-insensitive but element names are case-sensitive."], "chooseN": 1, "correct": ["The column name is case-insensitive but element names are case-sensitive."], "explanation": "- The column name is case-insensitive but element names are case-sensitive.: Al consultar datos semi-estructurados en Snowflake, los nombres de columnas no son sensibles a mayúsculas y minúsculas, mientras que los nombres de elementos sí lo son. Por ejemplo, 'SRC:salesperson.name' y 'src:salesperson.name' se consideran equivalentes, pero 'SRC:Salesperson.Name' no.\n- **The column name and element names are both case-sensitive.**: Solo los nombres de los elementos son sensibles a mayúsculas y minúsculas, los nombres de las columnas no lo son.\n- **The column name and element names are both case-insensitive.**: Solo los nombres de las columnas son insensibles a mayúsculas y minúsculas, mientras que los nombres de los elementos no.\n- **The column name is case-sensitive but element names are case-insensitive.**: Esto es incorrecto, ya que en Snowflake las columnas no son sensibles a mayúsculas, pero los nombres de los elementos sí lo son.", "reference": "https://docs.snowflake.com/en/user-guide/querying-semistructured"}, {"id": 963, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which Snowflake data type is used to store JSON key-value pairs?", "options": ["A) TEXT", "B) BINARY", "C) STRING", "D) VARIANT"], "chooseN": 1, "correct": ["VARIANT"], "explanation": "- VARIANT: El tipo de dato 'VARIANT' en Snowflake está diseñado para almacenar datos semiestructurados como JSON, incluyendo pares de clave-valor. Permite almacenar datos en múltiples formatos y acceder a ellos fácilmente a través de consultas SQL.\n- **TEXT**: 'TEXT' es un tipo de dato para almacenar cadenas de texto, pero no está optimizado para datos semiestructurados como JSON.\n- **BINARY**: 'BINARY' se usa para almacenar datos binarios, pero no es adecuado para datos estructurados como JSON.\n- **STRING**: Aunque 'STRING' puede almacenar texto, no tiene las capacidades específicas para manejar datos semiestructurados como JSON, a diferencia de 'VARIANT'.", "reference": "https://docs.snowflake.com/en/sql-reference/data-types-semistructured"}, {"id": 964, "area": "Account Access and Security", "question": "How are network policies defined in Snowflake?", "options": ["A) They are a set of rules that define the network routes within Snowflake.", "B) They are a set of rules that dictate how Snowflake accounts can be used between multiple users.", "C) They are a set of rules that define how data can be transferred between different Snowflake accounts within an organization.", "D) They are a set of rules that control access to Snowflake accounts by specifying the IP addresses or ranges of IP addresses that are allowed to connect to Snowflake."], "chooseN": 1, "correct": ["They are a set of rules that control access to Snowflake accounts by specifying the IP addresses or ranges of IP addresses that are allowed to connect to Snowflake."], "explanation": "- They are a set of rules that control access to Snowflake accounts...: Las políticas de red en Snowflake permiten controlar qué direcciones IP o rangos de IP pueden conectarse, asegurando un acceso seguro a los recursos de Snowflake.", "reference": "https://docs.snowflake.com/en/user-guide/network-policies.html"}, {"id": 965, "area": "Data Loading and Unloading", "question": "What is the only supported character set for loading and unloading data from all supported file formats?", "options": ["A) UTF-8", "B) UTF-16", "C) ISO-8859-1", "D) WINDOWS-1253"], "chooseN": 1, "correct": ["UTF-8"], "explanation": "- UTF-8: Snowflake solo admite UTF-8 como el conjunto de caracteres para la carga y descarga de datos, lo que garantiza compatibilidad y coherencia al manejar archivos en diferentes formatos.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-utf8.html"}, {"id": 966, "area": "Data Transformations", "question": "Which function is used to convert rows in a relational table to a single VARIANT column?", "options": ["A) ARRAY_AGG", "B) OBJECT_AGG", "C) ARRAY_CONSTRUCT", "D) OBJECT_CONSTRUCT"], "chooseN": 1, "correct": ["OBJECT_CONSTRUCT"], "explanation": "- OBJECT_CONSTRUCT: La función 'OBJECT_CONSTRUCT' se utiliza para convertir varias filas en una columna VARIANT, lo que facilita la manipulación de datos semi-estructurados como JSON.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/object_construct.html"}, {"id": 967, "area": "Data Loading and Unloading", "question": "Which command can be used to delete staged files from a Snowflake stage when the files are no longer needed?", "options": ["A) DELETE", "B) DROP", "C) REMOVE", "D) TRUNCATE TABLE"], "chooseN": 1, "correct": ["REMOVE"], "explanation": "- REMOVE: El comando 'REMOVE' se utiliza para eliminar archivos almacenados en un 'stage' de Snowflake cuando ya no son necesarios.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/remove.html"}, {"id": 968, "area": "Performance Concepts", "question": "A virtual warehouse initially suffers from poor performance as a result of queries from multiple concurrent processes that are queuing. Over time, the problem resolved. What action can be taken to prevent this from happening again?", "options": ["A) Increase the size of the virtual warehouse.", "B) Add a cluster key to the most used JOIN key.", "C) Change the multi-cluster settings to add additional clusters.", "D) Enable the search optimization service for the underlying tables."], "chooseN": 1, "correct": ["Change the multi-cluster settings to add additional clusters."], "explanation": "- Change the multi-cluster settings to add additional clusters: La configuración de múltiples clústeres en Snowflake permite escalar automáticamente para manejar más concurrencia, reduciendo el tiempo de espera en el futuro.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-multicluster.html"}, {"id": 969, "area": "Data Loading and Unloading", "question": "What action can be performed using the GET command in Snowflake?", "options": ["A) Automatically rename downloaded files.", "B) Automatically decrypt downloaded data on a client machine.", "C) Download data files from Snowflake internal stages to a local directory/folder.", "D) Download data files from Snowflake external stages to a local directory/folder."], "chooseN": 1, "correct": ["Download data files from Snowflake internal stages to a local directory/folder."], "explanation": "- Download data files from Snowflake internal stages to a local directory/folder: El comando 'GET' se utiliza específicamente para descargar archivos desde 'stages' internos de Snowflake a una carpeta local.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/get.html"}, {"id": 970, "area": "Data Loading and Unloading", "question": "Which validation option is the only one that supports the COPY INTO command?", "options": ["A) RETURN_ROWS", "B) RETURN__ROWS", "C) RETURN_ERRORS", "D) RETURN_ALL_ERRORS"], "chooseN": 1, "correct": ["RETURN_ROWS"], "explanation": "- RETURN_ROWS: Esta opción permite que el comando 'COPY INTO' devuelva las filas cargadas durante el proceso, lo que facilita la validación de la carga exitosa.\n- RETURN__ROWS: No es una opción válida en Snowflake.\n- RETURN_ERRORS y RETURN_ALL_ERRORS: Estas opciones permiten devolver errores, pero no están diseñadas para validar las filas cargadas como lo hace 'RETURN_ROWS'.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-location"}, {"id": 971, "area": "Data Transformations", "question": "What are the correct settings for column and element names, regardless of which notation is used while accessing elements in a JSON object?", "options": ["A) Both the column name and the element name are case-insensitive.", "B) Both the column name and the element name are case-sensitive.", "C) The column name is case-sensitive and the element names are case-insensitive.", "D) The column name is case-insensitive and the element name is case-sensitive."], "chooseN": 1, "correct": ["The column name is case-insensitive and the element name is case-sensitive."], "explanation": "- The column name is case-insensitive and the element name is case-sensitive: Los nombres de columnas no son sensibles a mayúsculas, pero los nombres de los elementos sí lo son al consultar datos semi-estructurados en Snowflake.", "reference": "https://docs.snowflake.com/en/user-guide/querying-semistructured"}, {"id": 972, "area": "Performance Concepts", "question": "How can the Query Profile be used to identify the costliest operator of a query?", "options": ["A) Select any node in the operator tree and look at the number of micro-partitions scanned.", "B) Find the operator node with the highest fraction of time or percentage of total time.", "C) Select the TableScan operator node and look at the percentage scanned from cache.", "D) Look at the number of rows between operator nodes across the operator tree."], "chooseN": 1, "correct": ["Find the operator node with the highest fraction of time or percentage of total time."], "explanation": "- Find the operator node with the highest fraction of time...: En el perfil de consultas de Snowflake, el nodo que consume más tiempo es generalmente el operador más costoso en términos de recursos.", "reference": "https://docs.snowflake.com/en/user-guide/querying-query-profile.html"}, {"id": 973, "area": "Data Protection and Data Sharing", "question": "In order to access Snowflake Marketplace listings, who needs to accept the Snowflake Consumer Terms of Service?", "options": ["A) SYSADMIN", "B) SECURITYADMIN", "C) ACCOUNTADMIN", "D) ORGADMIN"], "chooseN": 1, "correct": ["ORGADMIN"], "explanation": "- ORGADMIN: Los administradores de la organización (ORGADMIN) son los responsables de aceptar los Términos de Servicio de Snowflake para acceder a los listados del Snowflake Marketplace.", "reference": "https://docs.snowflake.com/en/user-guide/marketplace-getting-started.html"}, {"id": 974, "area": "Performance Concepts", "question": "Which statistics are displayed in a Query Profile that indicate that intermediate results do not fit in memory? (Choose two.)", "options": ["A) Bytes scanned", "B) Partitions scanned", "C) Bytes spilled to local storage", "D) Bytes spilled to remote storage", "E) Percentage scanned from cache"], "chooseN": 2, "correct": ["Bytes spilled to local storage", "Bytes spilled to remote storage"], "explanation": "- Bytes spilled to local storage y Bytes spilled to remote storage: Estos son indicadores clave que muestran que los resultados intermedios no caben en la memoria y deben escribirse en almacenamiento temporal (spilling). Otros parámetros como 'bytes scanned' o 'partitions scanned' no están directamente relacionados con la limitación de memoria.", "reference": "https://docs.snowflake.com/en/user-guide/querying-queries.html#interpreting-the-query-profile"}, {"id": 975, "area": "Data Loading and Unloading", "question": "How can a dropped internal stage be restored?", "options": ["A) Enable Time Travel.", "B) Clone the dropped stage.", "C) Execute the UNDROP command.", "D) Recreate the dropped stage."], "chooseN": 1, "correct": ["Recreate the dropped stage."], "explanation": "- Recreate the dropped stage: Los 'internal stages' no son elegibles para Time Travel o clonación. Una vez eliminados, deben ser recreados manualmente.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-local-file-system-stage.html#deleting-internal-stages"}, {"id": 976, "area": "Account Access and Security", "question": "Which command line flags can be used to log into a Snowflake account using SnowSQL? (Choose two.)", "options": ["A) -d", "B) -o", "C) -e", "D) -a", "E) -c"], "chooseN": 2, "correct": ["-d", "-a"], "explanation": "- -d y -a: Las banderas '-d' (para especificar el nombre de la base de datos) y '-a' (para indicar el nombre de la cuenta de Snowflake) son utilizadas para iniciar sesión en un entorno de Snowflake a través de SnowSQL.", "reference": "https://docs.snowflake.com/en/user-guide/snowsql-start.html"}, {"id": 977, "area": "Snowflake Data Cloud Features & Architecture", "question": "What is a key benefit of using organizations in Snowflake?", "options": ["A) Ability to use ACCOUNT_USAGE views", "B) Ability to use zero-copy cloning across accounts", "C) Ability to consolidate account management and billing", "D) Ability to access new releases for testing and validation purposes"], "chooseN": 1, "correct": ["Ability to consolidate account management and billing"], "explanation": "- Ability to consolidate account management and billing: El uso de 'organizations' en Snowflake permite la consolidación de la administración de cuentas y la facturación en una sola entidad organizativa, lo que mejora la gestión y visibilidad financiera.", "reference": "https://docs.snowflake.com/en/user-guide/organizations-intro.html"}, {"id": 978, "area": "Account Access and Security", "question": "Which privilege is required on a virtual warehouse to abort any existing executing queries?", "options": ["A) USAGE", "B) OPERATE", "C) MODIFY", "D) MONITOR"], "chooseN": 1, "correct": ["OPERATE"], "explanation": "- OPERATE: El privilegio 'OPERATE' permite al usuario abortar o pausar cualquier consulta en ejecución en un warehouse virtual. Otros privilegios como 'USAGE' o 'MODIFY' no otorgan este nivel de control.", "reference": "https://docs.snowflake.com/en/sql-reference/security-privileges.html"}, {"id": 979, "area": "Data Transformations", "question": "Which command should be used to look into the validity of an XML object in Snowflake?", "options": ["A) XMLGET", "B) TO_XML", "C) PARSE_XML", "D) CHECK_XML"], "chooseN": 1, "correct": ["CHECK_XML"], "explanation": "- CHECK_XML: Este comando se utiliza específicamente para verificar la validez de un objeto XML en Snowflake, asegurándose de que cumple con la estructura XML correcta.\n- PARSE_XML: Aunque PARSE_XML convierte datos en formato XML, no verifica directamente su validez.\n- XMLGET: Extrae valores de un objeto XML, pero no valida el XML completo.\n- TO_XML: Convierte datos en formato XML, pero no valida la estructura XML.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/check_xml"}, {"id": 980, "area": "Account Access and Security", "question": "Who can activate a network policy for users in a Snowflake account? (Choose two.)", "options": ["A) ACCOUNTADMIN", "B) USERADMIN", "C) PUBLIC", "D) SYSADMIN", "E) Any role that has the global ATTACH POLICY privilege"], "chooseN": 2, "correct": ["ACCOUNTADMIN", "Any role that has the global ATTACH POLICY privilege"], "explanation": "- ACCOUNTADMIN y Any role that has the global ATTACH POLICY privilege: El rol ACCOUNTADMIN o cualquier rol con el privilegio ATTACH POLICY puede activar políticas de red en Snowflake. Otros roles como PUBLIC o USERADMIN no tienen esta capacidad.", "reference": "https://docs.snowflake.com/en/user-guide/network-policies.html"}, {"id": 981, "area": "Performance Concepts", "question": "For which use cases is running a virtual warehouse required? (Choose two.)", "options": ["A) When creating a table", "B) When loading data into a table", "C) When unloading data from a table", "D) When executing a SHOW command", "E) When executing a LIST command"], "chooseN": 2, "correct": ["When loading data into a table", "When unloading data from a table"], "explanation": "- When loading data into a table y When unloading data from a table: Un warehouse virtual es necesario cuando se carga o descarga datos en una tabla. Crear tablas o ejecutar comandos SHOW y LIST no requieren un warehouse activo.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-overview.html"}, {"id": 982, "area": "Data Protection and Data Sharing", "question": "What action should be taken if a Snowflake user wants to share a newly created object in a database with consumers?", "options": ["A) Use the automatic sharing feature for seamless access.", "B) Drop the object and then re-add it to the database to trigger sharing.", "C) Recreate the object with a different name in the database before sharing.", "D) Use the GRANT privilege ... TO SHARE command to grant the necessary privileges."], "chooseN": 1, "correct": ["Use the GRANT privilege ... TO SHARE command to grant the necessary privileges."], "explanation": "- Use the GRANT privilege ... TO SHARE command to grant the necessary privileges: Para compartir objetos en Snowflake, es necesario usar el comando GRANT TO SHARE para otorgar privilegios a los consumidores. Las otras opciones no son correctas ni necesarias para compartir un objeto.", "reference": "https://docs.snowflake.com/en/user-guide/security-share-access.html"}, {"id": 983, "area": "Account Access and Security", "question": "Which Snowflake privilege is required on a pipe object to pause or resume pipes?", "options": ["A) OPERATE", "B) READ", "C) SELECT", "D) USAGE"], "chooseN": 1, "correct": ["OPERATE"], "explanation": "- OPERATE: El privilegio 'OPERATE' es necesario para pausar o reanudar pipes en Snowflake. Otros privilegios como 'READ' o 'SELECT' no otorgan este nivel de control sobre los pipes.", "reference": "https://docs.snowflake.com/en/user-guide/data-pipeline.html#managing-pipes"}, {"id": 984, "area": "Data Transformations", "question": "Which commands can a Snowflake user execute to specify a cluster key for a table? (Choose two.)", "options": ["A) CREATE", "B) UPDATE", "C) ALTER", "D) SET", "E) SHOW"], "chooseN": 2, "correct": ["CREATE", "ALTER"], "explanation": "- CREATE y ALTER: Los comandos CREATE y ALTER se utilizan para especificar o modificar un cluster key en una tabla. Comandos como UPDATE o SHOW no permiten definir un cluster key.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-keys.html"}, {"id": 985, "area": "Account Access and Security", "question": "Authorization to execute CREATE [object] statements comes only from which role?", "options": ["A) Primary role", "B) Secondary role", "C) Application role", "D) Database role"], "chooseN": 1, "correct": ["Primary role"], "explanation": "- Primary role: El rol primario del usuario es el único autorizado para ejecutar comandos CREATE. Los roles secundarios o de aplicación no tienen esta capacidad.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control.html"}, {"id": 986, "area": "Data Loading and Unloading", "question": "Which VALIDATION_MODE value will return the errors across the files specified in a COPY command, including files that were partially loaded during an earlier load?", "options": ["A) RETURN_-1_ROWS", "B) RETURN_n_ROWS", "C) RETURN_ERRORS", "D) RETURN_ALL_ERRORS"], "chooseN": 1, "correct": ["RETURN_ALL_ERRORS"], "explanation": "- RETURN_ALL_ERRORS: Esta opción en VALIDATION_MODE muestra todos los errores encontrados en los archivos, incluyendo aquellos que se cargaron parcialmente. RETURN_ERRORS solo muestra errores generales sin incluir los archivos parcialmente cargados.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-location.html#validation-mode"}, {"id": 987, "area": "Data Loading and Unloading", "question": "Which command is used to upload data files from a local directory or folder on a client machine to an internal stage, for a specified table?", "options": ["A) GET", "B) PUT", "C) CREATE STREAM", "D) COPY INTO"], "chooseN": 1, "correct": ["PUT"], "explanation": "- PUT: El comando PUT se utiliza para subir archivos desde un directorio local a un stage interno en Snowflake. Otros comandos como GET o COPY INTO se usan para otras funciones, como descargar archivos o copiar datos.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-local-file-system-put.html"}, {"id": 988, "area": "Data Protection and Data Sharing", "question": "Which governance feature is supported by all Snowflake editions?", "options": ["A) Object tags", "B) Masking policies", "C) Row access policies", "D) OBJECT_DEPENDENCIES view"], "chooseN": 1, "correct": ["OBJECT_DEPENDENCIES view"], "explanation": "- OBJECT_DEPENDENCIES view: Esta vista está disponible en todas las ediciones de Snowflake y permite consultar dependencias entre objetos. Otras características, como 'Object tags' o 'Row access policies', están limitadas a ediciones superiores.", "reference": "https://docs.snowflake.com/en/user-guide/access-control-privileges.html"}, {"id": 989, "area": "Performance Concepts", "question": "Which chart type is supported in Snowsight for Snowflake users to visualize data with dashboards?", "options": ["A) Area chart", "B) Box plot", "C) Heat grid", "D) Pie chart"], "chooseN": 1, "correct": ["Heat grid"], "explanation": "The correct answer is: Heat grid. The docs list: Scorecards, Heat grids, Scatterplots, Line charts, Bar charts. Area charts, Box plots, and Pie charts are NOT listed. The only matching option is C (Heat grid). Reference: https://docs.snowflake.com/en/user-guide/ui-snowsight-visualizations", "reference": "https://docs.snowflake.com/en/user-guide/snowsight-dashboards.html"}, {"id": 990, "area": "Data Protection and Data Sharing", "question": "At what level is the MIN_DATA_RETENTION_TIME_IN_DAYS parameter set?", "options": ["A) Account", "B) Database", "C) Schema", "D) Table"], "chooseN": 1, "correct": ["Account"], "explanation": "- Account: El parámetro 'MIN_DATA_RETENTION_TIME_IN_DAYS' se configura a nivel de cuenta (Account) para asegurar la retención mínima de datos en toda la cuenta.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/create-table.html#min_data_retention"}, {"id": 991, "area": "Performance Concepts", "question": "Which function returns an integer between 0 and 100 when used to calculate the similarity of two strings?", "options": ["A) APPROXIMATE_SIMILARITY", "B) JAROWINKLER_SIMILARITY", "C) APPROXIMATE_JACCARD_INDEX", "D) MINHASH_COMBINE"], "chooseN": 1, "correct": ["JAROWINKLER_SIMILARITY"], "explanation": "- JAROWINKLER_SIMILARITY: La función 'JAROWINKLER_SIMILARITY' devuelve un valor entero entre 0 y 100 que indica la similitud entre dos cadenas de texto.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/jarowinkler-similarity.html"}, {"id": 992, "area": "Data Protection and Data Sharing", "question": "Which Snowflake data governance feature can support auditing when a user query reads column data?", "options": ["A) Access History", "B) Data classification", "C) Column-level security", "D) Object dependencies"], "chooseN": 1, "correct": ["Access History"], "explanation": "- Access History: La funcionalidad 'Access History' permite auditar las consultas de usuarios y los accesos a datos en columnas específicas.", "reference": "https://docs.snowflake.com/en/user-guide/data-governance.html#access-history"}, {"id": 993, "area": "Performance Concepts", "question": "Which categories are included in the execution time summary in a Query Profile? (Choose two.)", "options": ["A) Pruning", "B) Spilling", "C) Initialization", "D) Local Disk I/O", "E) Percentage of data read from cache"], "chooseN": 2, "correct": ["Initialization", "Local Disk I/O"], "explanation": "- Initialization y Local Disk I/O: En el resumen de tiempo de ejecución de un perfil de consulta, las categorías 'Initialization' y 'Local Disk I/O' se incluyen para mostrar el tiempo asociado a la inicialización y el uso del disco local.", "reference": "https://docs.snowflake.com/en/user-guide/query-profile.html"}, {"id": 994, "area": "Account Access and Security", "question": "Which command can be used to list all network policies available in an account?", "options": ["A) DESCRIBE SESSION POLICY", "B) DESCRIBE NETWORK POLICY", "C) SHOW SESSION POLICIES", "D) SHOW NETWORK POLICIES"], "chooseN": 1, "correct": ["SHOW NETWORK POLICIES"], "explanation": "- SHOW NETWORK POLICIES: El comando 'SHOW NETWORK POLICIES' se utiliza para listar todas las políticas de red disponibles en una cuenta de Snowflake.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/show-network-policies.html"}, {"id": 995, "area": "Performance Concepts", "question": "Which type of loop requires a BREAK statement to stop executing?", "options": ["A) FOR", "B) LOOP", "C) REPEAT", "D) WHILE"], "chooseN": 1, "correct": ["LOOP"], "explanation": "- LOOP: El bucle 'LOOP' en Snowflake requiere una declaración 'BREAK' para detener su ejecución. Los otros bucles no necesitan esta declaración para finalizar.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/loop.html"}, {"id": 996, "area": "Performance Concepts", "question": "Which virtual warehouse consideration can help lower compute resource credit consumption?", "options": ["A) Setting up a multi-cluster virtual warehouse", "B) Resizing the virtual warehouse to a larger size", "C) Automating the virtual warehouse suspension and resumption settings", "D) Increasing the maximum cluster count parameter for a multi-cluster virtual warehouse"], "chooseN": 1, "correct": ["Automating the virtual warehouse suspension and resumption settings"], "explanation": "- Automating the virtual warehouse suspension and resumption settings: Automatizar la suspensión y reanudación del almacén virtual ayuda a reducir el consumo de créditos de recursos de cómputo al minimizar el tiempo en que los recursos están activos sin necesidad.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses.html#suspend-and-resume"}, {"id": 997, "area": "Data Loading and Unloading", "question": "To use the OVERWRITE option on INSERT, which privilege must be granted to the role?", "options": ["A) TRUNCATE", "B) DELETE", "C) UPDATE", "D) SELECT"], "chooseN": 1, "correct": ["DELETE"], "explanation": "- DELETE: Para utilizar la opción 'OVERWRITE' en una operación 'INSERT', el rol debe tener el privilegio 'DELETE', que permite reemplazar datos existentes.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/insert.html#overwrite"}, {"id": 998, "area": "Snowflake Data Cloud Features & Architecture", "question": "What happens when a suspended virtual warehouse is resized in Snowflake?", "options": ["A) It will return an error.", "B) It will return a warning.", "C) The suspended warehouse is resumed and new compute resources are provisioned immediately.", "D) The additional compute resources are provisioned when the warehouse is resumed."], "chooseN": 1, "correct": ["The additional compute resources are provisioned when the warehouse is resumed."], "explanation": "- The additional compute resources are provisioned when the warehouse is resumed.: Cuando un almacén virtual suspendido es redimensionado, los nuevos recursos de cómputo se provisionan solo cuando el almacén se reanuda.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses.html#resize"}, {"id": 999, "area": "Data Protection and Data Sharing", "question": "How does Snowflake handle the data retention period for a table if a stream has not been consumed?", "options": ["A) The data retention period is reduced to a minimum of 14 days.", "B) The data retention period is permanently extended for the table.", "C) The data retention period is temporarily extended to the stream’s offset.", "D) The data retention period is not affected by the stream consumption."], "chooseN": 1, "correct": ["The data retention period is temporarily extended to the stream’s offset."], "explanation": "- The data retention period is temporarily extended to the stream’s offset.: La retención de datos para una tabla se extiende temporalmente al offset del stream si este no ha sido consumido.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing.html#streams"}, {"id": 1000, "area": "Account Access and Security", "question": "Which task is supported by the use of Access History in Snowflake?", "options": ["A) Data backups", "B) Cost monitoring", "C) Compliance auditing", "D) Performance optimization"], "chooseN": 1, "correct": ["Compliance auditing"], "explanation": "- Compliance auditing: Access History permite auditar el acceso a los datos en Snowflake, lo que es clave para garantizar el cumplimiento normativo.\n- Data backups: Los respaldos de datos en Snowflake no están relacionados con Access History.\n- Cost monitoring: El monitoreo de costos se gestiona a través de otras funciones de Snowflake, como las tablas de costos o las vistas de uso.\n- Performance optimization: La optimización del rendimiento está fuera del alcance de Access History y se maneja mediante otras características.", "reference": "https://docs.snowflake.com/en/user-guide/access-history#benefits"}, {"id": 1001, "area": "Data Protection and Data Sharing", "question": "Which feature of Snowflake’s Continuous Data Protection (CDP) has associated costs?", "options": ["A) Fail-safe", "B) Network policies", "C) End-to-end encryption", "D) Multi-Factor Authentication (MFA)"], "chooseN": 1, "correct": ["Fail-safe"], "explanation": "- Fail-safe: El 'Fail-safe' en Snowflake es una funcionalidad que tiene costos asociados, ya que permite recuperar datos después del periodo de Time Travel. Está diseñado para la recuperación de desastres.\n- Network policies: No tiene costos asociados directos y se usa para gestionar el acceso basado en direcciones IP.\n- End-to-end encryption: Snowflake ofrece encriptación completa de manera predeterminada, sin costos adicionales.\n- Multi-Factor Authentication (MFA): MFA es una característica de seguridad que no tiene un costo adicional directo dentro de Snowflake.", "reference": "https://docs.snowflake.com/en/user-guide/data-protection-cdp.html"}, {"id": 1002, "area": "Data Loading and Unloading", "question": "When enabling access to unstructured data, which URL permits temporary access to a staged file without the need to grant privileges to the stage or to issue access tokens?", "options": ["A) File URL", "B) Scoped URL", "C) Relative URL", "D) Pre-Signed URL"], "chooseN": 1, "correct": ["Scoped URL"], "explanation": "Scoped URL. Snowflake documents scoped URLs as encoded URLs that permit temporary access to a staged file without granting privileges to the stage. Pre-signed URLs are open and are used without Snowflake authentication or an authorization token, which is a different behavior.", "reference": "https://docs.snowflake.com/en/user-guide/unstructured-intro#types-of-urls-available-to-access-files, https://docs.snowflake.com/en/sql-reference/functions/build_scoped_file_url"}, {"id": 1003, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which Snowflake function is maintained separately from the data and helps to support features such as Time Travel, Secure Data Sharing, and pruning?", "options": ["A) Column compression", "B) Data clustering", "C) Micro-partitioning", "D) Metadata management"], "chooseN": 1, "correct": ["Metadata management"], "explanation": "- Metadata management: Snowflake almacena metadatos de manera separada de los datos para respaldar funcionalidades como Time Travel, Secure Data Sharing, y pruning. Los metadatos son esenciales para estas capacidades avanzadas.\n- Column compression: La compresión de columnas ayuda a optimizar el almacenamiento, pero no soporta estas características.\n- Data clustering: Aunque el clustering mejora el rendimiento de consultas, no se usa directamente para Time Travel o Secure Data Sharing.\n- Micro-partitioning: Las micro-particiones optimizan la organización de los datos, pero la gestión de las características mencionadas se lleva a cabo a nivel de metadatos.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-keys.html, https://docs.snowflake.com/en/user-guide/data-sharing-intro.html, https://docs.snowflake.com/en/user-guide/timetravel.html"}, {"id": 1004, "area": "Data Transformations", "question": "A tag object has been assigned to a table (TABLE_A) in a schema within a Snowflake database. Which CREATE object statement will automatically assign the TABLE_A tag to a target object?", "options": ["A) CREATE TABLE LIKE TABLE_A;", "B) CREATE VIEW AS SELECT * FROM TABLE_A;", "C) CREATE TABLE AS SELECT * FROM TABLE_A;", "D) CREATE MATERIALIZED VIEW AS SELECT * FROM TABLE_A;"], "chooseN": 1, "correct": ["CREATE TABLE LIKE TABLE_A;"], "explanation": "- CREATE TABLE LIKE TABLE_A;: Al usar esta declaración, Snowflake copia no solo la estructura, sino también los metadatos del objeto, incluyendo las etiquetas (tags) asignadas.\n- CREATE VIEW AS SELECT * FROM TABLE_A;: Las vistas no heredan etiquetas ni otros metadatos de las tablas.\n- CREATE TABLE AS SELECT * FROM TABLE_A;: Aunque se copian los datos, no se heredan las etiquetas asignadas.\n- CREATE MATERIALIZED VIEW AS SELECT * FROM TABLE_A;: Similar a las vistas normales, no hereda etiquetas de la tabla base.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/create-table-like.html, https://docs.snowflake.com/en/user-guide/object-tagging.html"}, {"id": 1005, "area": "Data Protection and Data Sharing", "question": "In addition to performing all the standard steps to share data, which privilege must be granted on each database referenced by a secure view in order to be shared?", "options": ["A) READ", "B) REFERENCES", "C) REFERENCE_USAGE", "D) USAGE"], "chooseN": 1, "correct": ["REFERENCE_USAGE"], "explanation": "- REFERENCE_USAGE: Este privilegio permite que los usuarios que accedan a una vista segura puedan resolver referencias a objetos en las bases de datos subyacentes, lo que es crucial para compartir correctamente una vista segura.\n- READ: No es un privilegio que aplique a la compartición de vistas seguras.\n- REFERENCES: Este privilegio se utiliza en otros contextos, como el uso de claves externas, y no es relevante para vistas seguras.\n- USAGE: El privilegio USAGE es necesario para acceder a un esquema o base de datos, pero no es suficiente para compartir vistas seguras, donde se requiere REFERENCE_USAGE.", "reference": "https://docs.snowflake.com/en/user-guide/security-secure-views.html"}, {"id": 1006, "area": "Data Loading and Unloading", "question": "Which function can be used with the COPY INTO statement to convert rows from a relational table to a single VARIANT column, and to unload rows into a JSON file?", "options": ["A) FLATTEN", "B) OBJECT_AS", "C) OBJECT_CONSTRUCT", "D) TO_VARIANT"], "chooseN": 1, "correct": ["OBJECT_CONSTRUCT"], "explanation": "- OBJECT_CONSTRUCT: Esta función se utiliza para convertir filas de una tabla relacional en un objeto JSON, que luego puede almacenarse en una columna de tipo VARIANT o exportarse a un archivo JSON mediante la sentencia COPY INTO.\n- FLATTEN: FLATTEN convierte datos anidados dentro de una columna VARIANT, pero no se utiliza para crear un VARIANT desde una fila de tabla.\n- OBJECT_AS: Esta no es una función válida en Snowflake para esta tarea.\n- TO_VARIANT: TO_VARIANT convierte un solo valor a VARIANT, pero no crea una estructura JSON completa desde filas de tabla.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/object_construct.html, https://docs.snowflake.com/en/sql-reference/sql/copy-into-location.html"}, {"id": 1007, "area": "Data Protection and Data Sharing", "question": "Which type of role can be granted to a share?", "options": ["A) Account role", "B) Custom role", "C) Database role", "D) Secondary role"], "chooseN": 1, "correct": ["Database role"], "explanation": "- Database role: Solo las 'Database roles' pueden ser asignadas a un share en Snowflake. Estas roles están diseñadas para proporcionar acceso a nivel de base de datos y son necesarias para compartir datos de manera segura.\n- Account role: Los 'Account roles' controlan el acceso a nivel de cuenta, pero no pueden ser asignados a un share.\n- Custom role: Aunque se pueden crear roles personalizados, estos no son específicos para bases de datos y no pueden ser asignados directamente a un share.\n- Secondary role: Este no es un tipo de rol en Snowflake.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-intro.html#granting-privileges-on-objects-in-a-share"}, {"id": 1008, "area": "Data Loading and Unloading", "question": "When unloading data with the COPY INTO command, what is the purpose of the PARTITION BY parameter option?", "options": ["A) To sort the contents of the output file by the specified expression.", "B) To delimit the records in the output file using the specified expression.", "C) To include a new column in the output using the specified window function expression.", "D) To split the output into multiple files, one for each distinct value of the specified expression."], "chooseN": 1, "correct": ["To split the output into multiple files, one for each distinct value of the specified expression."], "explanation": "- To split the output into multiple files, one for each distinct value of the specified expression.: El parámetro `PARTITION BY` en el comando COPY INTO permite dividir los datos de salida en varios archivos, donde cada archivo corresponde a un valor distinto de la expresión especificada.\n- To sort the contents of the output file by the specified expression.: `PARTITION BY` no se utiliza para ordenar los datos, sino para dividir los archivos.\n- To delimit the records in the output file using the specified expression.: Este no es el propósito de `PARTITION BY`. Para delimitar registros se utilizan otras opciones, como delimitadores específicos de archivos.\n- To include a new column in the output using the specified window function expression.: Aunque `PARTITION BY` es un término común en las funciones de ventana, su uso en el comando COPY INTO es para dividir archivos, no para agregar columnas.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-location.html#copy-into-location-partition-by"}, {"id": 1009, "area": "Performance Concepts", "question": "What are potential impacts of storing non-native values like dates and timestamps in a VARIANT column in Snowflake?", "options": ["A) Faster query performance and increased storage consumption", "B) Slower query performance and increased storage consumption", "C) Faster query performance and decreased storage consumption", "D) Slower query performance and decreased storage consumption"], "chooseN": 1, "correct": ["Slower query performance and increased storage consumption"], "explanation": "- Slower query performance and increased storage consumption: Al almacenar valores no nativos como fechas y timestamps en columnas VARIANT, Snowflake necesita más recursos para interpretar y procesar estos datos, lo que puede resultar en una disminución del rendimiento de las consultas y un mayor uso de almacenamiento debido a la estructura flexible de las columnas VARIANT.\n- Faster query performance and increased storage consumption: El rendimiento de las consultas no mejora con valores no nativos en VARIANT; más bien, tiende a empeorar.\n- Faster query performance and decreased storage consumption: Al contrario, el rendimiento es más lento y el consumo de almacenamiento aumenta.\n- Slower query performance and decreased storage consumption: Aunque el rendimiento puede ser más lento, el almacenamiento aumenta debido a la estructura de los datos VARIANT.", "reference": "https://docs.snowflake.com/en/user-guide/semistructured-considerations.html"}, {"id": 1010, "area": "Data Protection and Data Sharing", "question": "Which views are included in the DATA_SHARING_USAGE schema? (Choose two.)", "options": ["A) ACCESS_HISTORY", "B) DATA_TRANSFER_HISTORY", "C) WAREHOUSE_METERING_HISTORY", "D) MONETIZED_USAGE_DAILY", "E) LISTING_TELEMETRY_DAILY"], "chooseN": 2, "correct": ["MONETIZED_USAGE_DAILY", "LISTING_TELEMETRY_DAILY"], "explanation": "- MONETIZED_USAGE_DAILY: Esta vista está incluida en el esquema `DATA_SHARING_USAGE` y se utiliza para rastrear el uso monetizado del uso compartido de datos.\n- LISTING_TELEMETRY_DAILY: También forma parte del esquema `DATA_SHARING_USAGE`, y proporciona información sobre las actividades de telemetría relacionadas con las listas.\n- ACCESS_HISTORY: Aunque es una vista importante, no pertenece al esquema `DATA_SHARING_USAGE`.\n- DATA_TRANSFER_HISTORY: No está incluida en este esquema, sino en otros contextos relacionados con la transferencia de datos.\n- WAREHOUSE_METERING_HISTORY: Tampoco está incluida en el esquema `DATA_SHARING_USAGE`.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-usage.html"}, {"id": 1011, "area": "Snowflake Data Cloud Features & Architecture", "question": "What does a table with a clustering depth of 1 mean in Snowflake?", "options": ["A) The table has only 1 micro-partition.", "B) The table has 1 overlapping micro-partition.", "C) The table has no overlapping micro-partitions.", "D) The table has no micro-partitions."], "chooseN": 1, "correct": ["The table has no overlapping micro-partitions."], "explanation": "- The table has no overlapping micro-partitions.: Un 'clustering depth' de 1 significa que no hay superposición de micro-particiones. Esto indica que la tabla está bien agrupada en función de las columnas especificadas para el clustering.\n- The table has only 1 micro-partition.: Un clustering depth de 1 no se refiere a la cantidad de micro-particiones, sino a la superposición de las mismas.\n- The table has 1 overlapping micro-partition.: Un clustering depth de 1 implica que no hay superposición, no que haya una micro-partición superpuesta.\n- The table has no micro-partitions.: Todas las tablas en Snowflake tienen micro-particiones; un clustering depth de 1 simplemente significa que están bien distribuidas.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions, https://docs.snowflake.com/en/sql-reference/functions/system_clustering_depth"}, {"id": 1012, "area": "Data Protection and Data Sharing", "question": "Which Snowflake object contains all the information required to share a database?", "options": ["A) Private listing", "B) Secure view", "C) Sequence", "D) Share"], "chooseN": 1, "correct": ["Share"], "explanation": "- Share: El objeto 'Share' en Snowflake contiene toda la información necesaria para compartir una base de datos con otros usuarios o cuentas. Es el mecanismo principal para facilitar el uso compartido de datos.\n- Private listing: Un 'Private listing' no es un objeto en Snowflake relacionado con el compartir bases de datos.\n- Secure view: Aunque las 'Secure views' son útiles para compartir datos de manera segura, no contienen la información completa necesaria para compartir una base de datos.\n- Sequence: Una 'Sequence' es un objeto numérico que genera valores únicos y no tiene relación con compartir datos.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-intro.html"}, {"id": 1013, "area": "Performance Concepts", "question": "What is the PRIMARY factor that determines the cost of using a virtual warehouse in Snowflake?", "options": ["A) The type of SQL statements executed", "B) The number of tables or databases queried", "C) The amount of data stored in the warehouse", "D) The length of time the compute resources in each cluster run"], "chooseN": 1, "correct": ["The length of time the compute resources in each cluster run"], "explanation": "- The length of time the compute resources in each cluster run: El factor principal que determina el costo de un warehouse virtual en Snowflake es el tiempo que los recursos de cómputo están activos. El costo depende de la duración de ejecución de los clústeres, lo que se refleja en las 'Snowflake credits'.\n- The type of SQL statements executed: Aunque el tipo de consulta puede influir en la duración de la ejecución, el costo no está directamente basado en el tipo de consulta.\n- The number of tables or databases queried: Consultar más tablas o bases de datos no aumenta directamente el costo; el factor clave sigue siendo el tiempo de ejecución.\n- The amount of data stored in the warehouse: El almacenamiento de datos se factura por separado y no afecta el costo de uso del warehouse virtual.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-costs.html"}, {"id": 1014, "area": "Data Loading and Unloading", "question": "Which function generates a Snowflake-hosted file URL to a staged file using the stage name and relative file path as inputs, with a file URL that does not expire?", "options": ["A) BUILD_SCOPED_FILE_URL", "B) BUILD_STAGE_FILE_URL", "C) GET_ABSOLUTE_PATH", "D) GET_PRESIGNED_URL"], "chooseN": 1, "correct": ["BUILD_STAGE_FILE_URL"], "explanation": "- BUILD_STAGE_FILE_URL: Esta función genera una URL de archivo alojada en Snowflake a un archivo en stage, utilizando el nombre del stage y la ruta de archivo relativa. La URL generada no expira, lo que la hace ideal para acceder de forma permanente.\n- BUILD_SCOPED_FILE_URL: Esta función genera una URL con un alcance limitado que generalmente expira después de un periodo corto.\n- GET_ABSOLUTE_PATH: Esta función no genera URLs; simplemente obtiene la ruta absoluta de un archivo.\n- GET_PRESIGNED_URL: Las URLs pre-firmadas permiten el acceso temporal a los archivos, lo cual es diferente de una URL que no expira.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/build_stage_file_url.html"}, {"id": 1015, "area": "Data Loading and Unloading", "question": "When a Snowflake user loads CSV data from a stage, which COPY INTO [table] command guideline should they follow?", "options": ["A) The CSV field delimiter must be a comma character (‘,’).", "B) The number of columns in each row should be consistent.", "C) The data file in the stage must be in a compressed format.", "D) The data file must have the same number of columns as the target table."], "chooseN": 1, "correct": ["The number of columns in each row should be consistent."], "explanation": "- The number of columns in each row should be consistent.: Es fundamental que el número de columnas en cada fila sea consistente para que Snowflake pueda procesar correctamente los datos del archivo CSV. Esto asegura que los datos se carguen de manera ordenada y predecible.\n- The CSV field delimiter must be a comma character (‘,’).: Aunque el delimitador por defecto es una coma, Snowflake permite cualquier carácter de delimitación válido. No es obligatorio usar una coma.\n- The data file in the stage must be in a compressed format.: La compresión de archivos no es un requisito; es solo una recomendación para cargas de grandes volúmenes de datos.\n- The data file must have the same number of columns as the target table.: Se pueden omitir columnas en el archivo de datos; Snowflake permite que el archivo tenga menos columnas que la tabla de destino.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-considerations-prepare#preparing-delimited-text-files"}, {"id": 1016, "area": "Data Loading and Unloading", "question": "A user creates a stage using the following command: CREATE STAGE mystage - DIRECTORY = (ENABLE = TRUE) FILE_FORMAT = myformat; What will be the outcome?", "options": ["A) A stage with a directory table set to automatically refresh will be created.", "B) A stage with a directory table that has metadata that must be manually refreshed will be created.", "C) An error will be received stating that the storage location for the stage must be identified when creating a stage with a directory table.", "D) The command will fail to run because the name of the directory table is not specified."], "chooseN": 1, "correct": ["A stage with a directory table that has metadata that must be manually refreshed will be created."], "explanation": "When creating an internal named stage with DIRECTORY = (ENABLE = TRUE), a directory table is created with the stage. Since this is an internal stage (no external URL specified), AUTO_REFRESH is not supported, so the directory table metadata must be manually refreshed using ALTER STAGE ... REFRESH. The stage does not require an explicit storage location because it uses Snowflake-managed internal storage.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-dirtables-manage"}, {"id": 1017, "area": "Performance Concepts", "question": "Which statistics on a Query Profile reflect the efficiency of the query pruning? (Choose two.)", "options": ["A) Partitions scanned", "B) Partitions total", "C) Bytes scanned", "D) Bytes spilled", "E) Bytes written"], "chooseN": 2, "correct": ["Partitions scanned", "Partitions total"], "explanation": "- Partitions scanned: Este valor indica cuántas particiones fueron leídas durante la ejecución de la consulta. Menos particiones escaneadas generalmente indican una mejor eficiencia en la poda de consultas.\n- Partitions total: Este valor refleja el total de particiones disponibles. Comparar este número con el número de particiones escaneadas ayuda a evaluar la efectividad de la poda.\n- Bytes scanned: Aunque los bytes escaneados pueden indicar la cantidad de datos leídos, no son un indicador directo de la eficiencia de la poda.\n- Bytes spilled: Este valor se refiere a los datos que se escriben en disco cuando la memoria es insuficiente, lo que no está relacionado con la poda de consultas.\n- Bytes written: Este valor refleja la cantidad de datos escritos en el almacenamiento, no la eficiencia de la poda de consultas.", "reference": "https://docs.snowflake.com/en/user-guide/querying-using-snowflake.html#query-profiles"}, {"id": 1018, "area": "Data Loading and Unloading", "question": "Which operation can be performed on Snowflake external tables?", "options": ["A) INSERT", "B) JOIN", "C) RENAME", "D) ALTER"], "chooseN": 1, "correct": ["JOIN"], "explanation": "- JOIN: Las tablas externas en Snowflake se pueden usar en consultas JOIN, permitiendo combinaciones de datos desde diferentes fuentes.\n- INSERT: No se pueden insertar datos directamente en las tablas externas, ya que son solo vistas sobre los datos en el almacenamiento externo.\n- RENAME: Las tablas externas no pueden ser renombradas una vez creadas.\n- ALTER: Las operaciones ALTER no son aplicables a las tablas externas como lo son en las tablas internas.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-external-tables.html"}, {"id": 1019, "area": "Data Protection and Data Sharing", "question": "A user wants to access files stored in a stage without authenticating into Snowflake. Which type of URL should be used?", "options": ["A) File URL", "B) Staged URL", "C) Scoped URL", "D) Pre-signed URL"], "chooseN": 1, "correct": ["Pre-signed URL"], "explanation": "- Pre-signed URL: Este tipo de URL permite el acceso a los archivos almacenados en un stage sin necesidad de autenticarse en Snowflake. Permite acceso temporal.\n- File URL: Este término no es correcto en el contexto de acceso sin autenticación a archivos en un stage.\n- Staged URL: No es un término estándar en Snowflake para acceder a archivos sin autenticación.\n- Scoped URL: Aunque permite el acceso a archivos, requiere que se generen tokens de acceso y no es sin autenticación.", "reference": "https://docs.snowflake.com/en/user-guide/unstructured-intro.html"}, {"id": 1020, "area": "Data Loading and Unloading", "question": "Which table function is used to view all errors encountered during a previous data load?", "options": ["A) VALIDATE", "B) INFER_SCHEMA", "C) GENERATOR", "D) QUERY_HISTORY"], "chooseN": 1, "correct": ["VALIDATE"], "explanation": "- VALIDATE: Esta función permite a los usuarios ver todos los errores que se produjeron durante una carga de datos anterior, ayudando a identificar problemas.\n- INFER_SCHEMA: Esta función se utiliza para inferir el esquema de los datos, no para visualizar errores.\n- GENERATOR: Esta función se utiliza para generar filas, no para manejar errores de carga de datos.\n- QUERY_HISTORY: Aunque permite ver el historial de consultas, no se centra específicamente en los errores de carga de datos.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-errors.html"}, {"id": 1021, "area": "Performance Concepts", "question": "What is the MINIMUM size requirement when creating a Snowpark-optimized virtual warehouse?", "options": ["A) X-Small", "B) Small", "C) Medium", "D) Large"], "chooseN": 1, "correct": ["X-Small"], "explanation": "The minimum warehouse size for a Snowpark-optimized warehouse depends on the resource constraint, and the default MEMORY_1X configuration allows X-Small. Medium is only required for MEMORY_16X configurations.", "reference": "https://docs.snowflake.com/en/user-guide/snowpark-optimization.html"}, {"id": 1022, "area": "Account Access and Security", "question": "Which role has the ability to create and manage users and roles?", "options": ["A) ORGADMIN", "B) USERADMIN", "C) SYSADMIN", "D) SECURITYADMIN"], "chooseN": 1, "correct": ["USERADMIN"], "explanation": "- USERADMIN: Este rol es específicamente responsable de la creación y gestión de usuarios y roles en Snowflake.\n- ORGADMIN: Este rol tiene privilegios más amplios que incluyen la gestión de cuentas, pero no está dedicado solo a usuarios y roles.\n- SYSADMIN: Este rol gestiona la administración de la base de datos y objetos, pero no se centra en la gestión de usuarios.\n- SECURITYADMIN: Aunque puede gestionar usuarios y roles, su enfoque es más amplio y se relaciona con la seguridad en general.", "reference": "https://docs.snowflake.com/en/user-guide/admin-user-management.html"}, {"id": 1023, "area": "Performance Concepts", "question": "What issues can be identified and troubleshooted using the Query Profile? (Choose two.)", "options": ["A) Full index scans", "B) Cartesian products", "C) Insufficient privileges", "D) Queries too large to fit in memory", "E) Virtual warehouse credit consumption"], "chooseN": 2, "correct": ["Cartesian products", "Queries too large to fit in memory"], "explanation": "- Cartesian products: Los productos cartesianos son un signo de problemas en las uniones de consultas y se pueden detectar en el perfil de consulta.\n- Queries too large to fit in memory: Consultas que son demasiado grandes para caber en la memoria pueden ser identificadas a través del perfil de consulta, ya que este muestra problemas de rendimiento relacionados con el uso de memoria.\n- Full index scans: Snowflake no utiliza índices tradicionales, por lo tanto, no es aplicable.\n- Insufficient privileges: Este problema está relacionado con la seguridad y permisos, no con el rendimiento de consultas, por lo que no es identificado por el perfil de consulta.\n- Virtual warehouse credit consumption: Este problema está más relacionado con la gestión de costos que con el rendimiento de consultas y no se identifica directamente en el perfil de consulta.", "reference": "https://docs.snowflake.com/user-guide/ui-snowsight-activity#common-query-problems-identified-by-query-profile"}, {"id": 1024, "area": "Account Access and Security", "question": "What happens to the objects in a reader account when the DROP MANAGED ACCOUNT command is executed?", "options": ["A) The objects are dropped.", "B) The objects enter the Fail-safe period.", "C) The objects enter the Time Travel period.", "D) The objects are immediately moved to the provider account."], "chooseN": 1, "correct": ["The objects are dropped."], "explanation": "- The objects are dropped.: Cuando se ejecuta el comando DROP MANAGED ACCOUNT, todos los objetos en la cuenta del lector se eliminan permanentemente.\n- The objects enter the Fail-safe period.: No hay un período de Fail-safe para los objetos en cuentas de lectores al eliminar la cuenta.\n- The objects enter the Time Travel period.: Los objetos no entran en el período de Time Travel una vez que la cuenta se elimina; se eliminan de inmediato.\n- The objects are immediately moved to the provider account.: Los objetos no se trasladan a la cuenta del proveedor, simplemente se eliminan.", "reference": "https://docs.snowflake.com/en/user-guide/manage-accounts.html#dropping-a-managed-account"}, {"id": 1025, "area": "Data Transformations", "question": "What function can be used with the recursive argument to return a list of distinct key names in all nested elements in an object?", "options": ["A) FLATTEN", "B) GET_PATH", "C) CHECK_JSON", "D) PARSE_JSON"], "chooseN": 1, "correct": ["FLATTEN"], "explanation": "- FLATTEN: Esta función permite a los usuarios descomponer estructuras de datos anidadas y devolver una lista de nombres de clave distintos.\n- GET_PATH: Esta función se utiliza para acceder a elementos específicos dentro de una estructura JSON, no para listar claves.\n- CHECK_JSON: Esta función verifica la validez de un objeto JSON, no devuelve claves.\n- PARSE_JSON: Esta función convierte cadenas en objetos JSON, pero no enumera claves en elementos anidados.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/flatten.html"}, {"id": 1026, "area": "Data Loading and Unloading", "question": "What does Snowflake recommend when planning virtual warehouse usage for a data load?", "options": ["A) Load the fewest possible number of large files.", "B) Dedicate a separate warehouse for loading data.", "C) Increase the size of the warehouse used.", "D) Use several single-cluster warehouses."], "chooseN": 1, "correct": ["Dedicate a separate warehouse for loading data."], "explanation": "- Dedicate a separate warehouse for loading data.: Snowflake recomienda dedicar un almacén separado para cargas de datos para evitar la competencia por recursos con otras cargas de trabajo.\n- Load the fewest possible number of large files.: Aunque es útil, esto no es una recomendación principal para la planificación de almacenes virtuales.\n- Increase the size of the warehouse used.: Aumentar el tamaño puede ayudar, pero dedicar un almacén separado es la recomendación más fuerte.\n- Use several single-cluster warehouses.: Esto puede ser innecesario y no es una recomendación de Snowflake.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-considerations.html"}, {"id": 1027, "area": "Data Transformations", "question": "Which Snowflake database object can be used to track data changes made to table data?", "options": ["A) Tag", "B) Task", "C) Stream", "D) Stored procedure"], "chooseN": 1, "correct": ["Stream"], "explanation": "- Stream: Los streams en Snowflake permiten rastrear cambios de datos en tablas, capturando inserciones, actualizaciones y eliminaciones.\n- Tag: Las etiquetas se utilizan para la clasificación y la gestión de objetos, no para rastrear cambios de datos.\n- Task: Las tareas programan y ejecutan operaciones en Snowflake, pero no rastrean cambios de datos.\n- Stored procedure: Las funciones almacenadas ejecutan lógica y operaciones, pero no rastrean automáticamente los cambios de datos.", "reference": "https://docs.snowflake.com/en/user-guide/streams.html"}, {"id": 1028, "area": "Account Access and Security", "question": "Who can activate and enforce a network policy for all users in a Snowflake account? (Choose two.)", "options": ["A) A user with a USERADMIN or higher role", "B) A user with a SECURITYADMIN or higher role", "C) A role that has been granted the ATTACH POLICY privilege", "D) A role that has the NETWORK_POLICY account parameter set", "E) A role that has the OWNERSHIP of the network policy"], "chooseN": 2, "correct": ["A user with a SECURITYADMIN or higher role", "A role that has been granted the ATTACH POLICY privilege"], "explanation": "- A user with a SECURITYADMIN or higher role: Solo los usuarios con el rol SECURITYADMIN o superior pueden activar y hacer cumplir políticas de red en la cuenta de Snowflake.\n- A role that has been granted the ATTACH POLICY privilege: Un rol al que se le ha concedido el privilegio ATTACH POLICY también puede activar una política de red.\n- A user with a USERADMIN or higher role: Los usuarios con este rol no tienen permiso para activar políticas de red a menos que también tengan el privilegio adecuado.\n- A role that has the NETWORK_POLICY account parameter set: Este parámetro por sí solo no permite activar políticas de red.\n- A role that has the OWNERSHIP of the network policy: La propiedad de la política no otorga automáticamente la capacidad de activarla para todos los usuarios.", "reference": "https://docs.snowflake.com/en/user-guide/network-policies"}, {"id": 1029, "area": "Data Protection and Data Sharing", "question": "How can a data provider share their Snowflake data? (Choose two.)", "options": ["A) External table", "B) Snowpark API", "C) Direct share", "D) External function", "E) Snowflake Marketplace listing"], "chooseN": 2, "correct": ["Direct share", "Snowflake Marketplace listing"], "explanation": "- Direct share: Los proveedores de datos pueden utilizar la opción de compartir directamente para compartir datos de Snowflake con otros usuarios o cuentas.\n- Snowflake Marketplace listing: También pueden listar sus datos en el mercado de Snowflake para compartir con otros usuarios.\n- External table: Aunque se pueden crear tablas externas, no son un método directo para compartir datos. \n- Snowpark API: Esta API permite la interacción con los datos, pero no es una opción para compartir datos directamente. \n- External function: Las funciones externas permiten la ejecución de lógica externa, pero no comparten datos directamente.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing.html"}, {"id": 1030, "area": "Account Access and Security", "question": "What will prevent unauthorized access to a Snowflake account from an unknown source?", "options": ["A) Network policy", "B) End-to-end encryption", "C) Multi-Factor Authentication (MFA)", "D) Role-Based Access Control (RBAC)"], "chooseN": 1, "correct": ["Network policy"], "explanation": "- Network policy: Las políticas de red limitan el acceso a la cuenta de Snowflake, permitiendo solo conexiones desde direcciones IP autorizadas.\n- End-to-end encryption: Aunque asegura los datos en tránsito y en reposo, no previene el acceso no autorizado a la cuenta.\n- Multi-Factor Authentication (MFA): Aunque aumenta la seguridad de inicio de sesión, no bloquea el acceso desde fuentes desconocidas sin una política de red.\n- Role-Based Access Control (RBAC): RBAC controla los permisos dentro de la cuenta, pero no limita las conexiones desde fuentes no autorizadas.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-overview.html"}, {"id": 1031, "area": "Performance Concepts", "question": "Which query type is supported for implementing the search optimization service?", "options": ["A) Queries with column concatenation", "B) Substring search queries on external tables", "C) String searches on columns using the COLLATE function", "D) Geography value column searches using geospatial functions"], "chooseN": 1, "correct": ["Geography value column searches using geospatial functions"], "explanation": "- Geography value column searches using geospatial functions: Las búsquedas de columnas de valores geográficos son compatibles con el servicio de optimización de búsqueda en Snowflake.\n- Queries with column concatenation: La concatenación de columnas no es una consulta soportada por este servicio.\n- Substring search queries on external tables: Las consultas de subcadena no son compatibles con el servicio de optimización de búsqueda.\n- String searches on columns using the COLLATE function: Las búsquedas de cadenas utilizando la función COLLATE no son compatibles con este servicio.", "reference": "https://docs.snowflake.com/en/user-guide/search-optimization-service.html"}, {"id": 1032, "area": "Data Protection and Data Sharing", "question": "What Snowflake feature provides a data hub for secure data collaboration, with a selected group of invited members?", "options": ["A) Data Replication", "B) Secure Data Sharing", "C) Data Exchange", "D) Snowflake Marketplace"], "chooseN": 1, "correct": ["Data Exchange"], "explanation": "- Data Exchange: La función de intercambio de datos de Snowflake permite la colaboración segura de datos entre un grupo seleccionado de miembros invitados.\n- Data Replication: La replicación de datos se utiliza para copiar datos entre cuentas, pero no es un hub de colaboración.\n- Secure Data Sharing: Aunque proporciona capacidades de compartir datos, no es específicamente un hub de colaboración como el intercambio de datos.\n- Snowflake Marketplace: El mercado es una plataforma para la compra y venta de datos, no un hub de colaboración privada.", "reference": "https://docs.snowflake.com/en/user-guide/data-exchange.html"}, {"id": 1033, "area": "Data Transformations", "question": "Which semi-structured data function interprets an input string as a JSON document that produces a VARIANT value?", "options": ["A) PARSE_JSON", "B) CHECK_JSON", "C) JSON_EXTRACT_PATH_TEXT", "D) PARSE_XML"], "chooseN": 1, "correct": ["PARSE_JSON"], "explanation": "- PARSE_JSON: La función PARSE_JSON toma una cadena de entrada y la interpreta como un documento JSON, produciendo un valor VARIANT.\n- CHECK_JSON: Esta función valida si una cadena es un JSON válido, pero no produce un valor VARIANT.\n- JSON_EXTRACT_PATH_TEXT: Esta función extrae texto de un documento JSON, pero no lo interpreta ni lo convierte a un VARIANT.\n- PARSE_XML: Esta función interpreta documentos XML, no JSON.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/parse_json.html"}, {"id": 1034, "area": "Data Transformations", "question": "Which Snowflake data types can be used to build nested hierarchical data? (Choose two.)", "options": ["A) INTEGER", "B) OBJECT", "C) VARIANT", "D) VARCHAR", "E) LIST"], "chooseN": 2, "correct": ["OBJECT", "VARIANT"], "explanation": "- OBJECT: El tipo de dato OBJECT puede contener pares clave-valor y es adecuado para datos jerárquicos.\n- VARIANT: El tipo VARIANT puede almacenar datos semi-estructurados, incluidos JSON, que permiten estructuras jerárquicas.\n- INTEGER: INTEGER es un tipo de dato escalar y no se puede usar para estructuras jerárquicas.\n- VARCHAR: Aunque VARCHAR almacena texto, no puede representar estructuras jerárquicas por sí mismo.\n- LIST: LIST puede contener una colección de elementos, pero no se utiliza para crear datos jerárquicos en el sentido de pares clave-valor.", "reference": "https://docs.snowflake.com/en/sql-reference/data-types.html"}, {"id": 1035, "area": "Performance Concepts", "question": "Which statistics can be used to identify queries that have inefficient pruning? (Choose two.)", "options": ["A) Bytes scanned", "B) Bytes written to result", "C) Partitions scanned", "D) Partitions total", "E) Percentage scanned from cache"], "chooseN": 2, "correct": ["Partitions scanned", "Partitions total"], "explanation": "- Partitions scanned: Este valor indica la cantidad de particiones que fueron escaneadas por la consulta. Un número alto aquí en comparación con las particiones totales sugiere que el pruning puede no ser eficiente.\n- Partitions total: Este valor muestra el número total de particiones en la tabla. Comparar este número con las particiones escaneadas ayuda a determinar la eficiencia del pruning.\n- Bytes scanned: Aunque indica la cantidad de datos escaneados, no proporciona información específica sobre la eficiencia del pruning en términos de particiones.\n- Bytes written to result: Mide la cantidad de datos escritos en el resultado, pero no está relacionado directamente con la eficiencia del pruning.\n- Percentage scanned from cache: Esto muestra el porcentaje de datos leídos desde la caché, no la eficiencia del pruning.", "reference": "https://docs.snowflake.com/en/user-guide/ui-query-profile#inefficient-pruning, https://select.dev/posts/snowflake-micro-partitions"}, {"id": 1036, "area": "Performance Concepts", "question": "Which element in the Query Profile interface shows the relationship between the nodes in the execution of a query?", "options": ["A) Node List", "B) Steps", "C) Overview", "D) Operator Tree"], "chooseN": 1, "correct": ["Operator Tree"], "explanation": "- Operator Tree: Este elemento muestra la estructura jerárquica del plan de ejecución de la consulta, permitiendo visualizar cómo se relacionan los diferentes nodos en la ejecución, facilitando el análisis del rendimiento.\n- Node List: Esta opción simplemente lista los nodos, pero no muestra la relación entre ellos.\n- Steps: Muestra los pasos en la ejecución, pero no las relaciones jerárquicas entre los nodos.\n- Overview: Ofrece un resumen general, pero no detalla las relaciones entre los nodos.", "reference": "https://docs.snowflake.com/en/user-guide/ui-query-profile.html"}, {"id": 1037, "area": "Data Transformations", "question": "What will happen if a Snowflake user suspends the updates to a materialized view?", "options": ["A) The queries on that view will generate an error message.", "B) The queries on that view will return the last stored data.", "C) The queries on that view will return the data using Time Travel.", "D) The queries on that view will return the data with a warning message."], "chooseN": 1, "correct": ["The queries on that view will return the last stored data."], "explanation": "- The queries on that view will return the last stored data.: Al suspender las actualizaciones de la vista materializada, las consultas seguirán devolviendo los últimos datos almacenados sin generar errores.\n- The queries on that view will generate an error message.: Esto no es correcto, ya que las consultas aún se pueden ejecutar.\n- The queries on that view will return the data using Time Travel.: No se utilizará Time Travel, ya que se devolverán los últimos datos almacenados.\n- The queries on that view will return the data with a warning message.: No se generarán advertencias, solo se devolverán los datos más recientes.", "reference": "https://docs.snowflake.com/en/user-guide/views-materialized.html#suspend-updates"}, {"id": 1038, "area": "Data Transformations", "question": "Which Snowflake function will parse a JSON-null into a SQL-null?", "options": ["A) TO_CHAR", "B) TO_VARIANT", "C) TO_VARCHAR", "D) STRIP_NULL_VALUE"], "chooseN": 1, "correct": ["STRIP_NULL_VALUE"], "explanation": "- STRIP_NULL_VALUE: Esta función convierte un valor nulo de JSON en un valor nulo de SQL, manejando correctamente los nulos en las consultas SQL.\n- TO_CHAR: Esta función convierte valores a formato de texto, pero no maneja nulos de JSON.\n- TO_VARIANT: Convierte un valor en un tipo variante, pero no aborda nulos de JSON directamente.\n- TO_VARCHAR: Similar a TO_CHAR, convierte valores a texto, sin manejo específico de nulos de JSON.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/strip_null_value.html"}, {"id": 1039, "area": "Data Loading and Unloading", "question": "Which Snowflake command can be used to unload the result of a query to a single file?", "options": ["A) Use COPY INTO followed by a GET command to download the file.", "B) Use COPY INTO followed by a PUT command to download the file.", "C) Use COPY INTO with SINGLE = TRUE followed by a GET command to download the file.", "D) Use COPY INTO with SINGLE = TRUE followed by a PUT command to download the file."], "chooseN": 1, "correct": ["Use COPY INTO with SINGLE = TRUE followed by a GET command to download the file."], "explanation": "- Use COPY INTO with SINGLE = TRUE followed by a GET command to download the file.: Esto permite que el resultado de la consulta se escriba en un solo archivo que se puede descargar utilizando el comando GET.\n- Use COPY INTO followed by a GET command to download the file.: Sin la opción SINGLE = TRUE, no garantiza un solo archivo de salida.\n- Use COPY INTO followed by a PUT command to download the file.: PUT se usa para cargar archivos en Snowflake, no para descargarlos.\n- Use COPY INTO with SINGLE = TRUE followed by a PUT command to download the file.: PUT no es correcto para la descarga, ya que es para cargar datos en Snowflake.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-location.html"}, {"id": 1040, "area": "Snowflake Data Cloud Features & Architecture", "question": "How are micro-partitions enabled on Snowflake tables?", "options": ["A) Micro-partitioning requires a cluster key on a table.", "B) Micro-partitioning is automatically performed on a table.", "C) Micro-partitioning requires the use of the search optimization service.", "D) Micro-partitioning is defined by the user when a table is created."], "chooseN": 1, "correct": ["Micro-partitioning is automatically performed on a table."], "explanation": "- Micro-partitioning is automatically performed on a table: Snowflake realiza automáticamente el micro-particionamiento en todas las tablas, sin requerir una clave de clúster o configuración manual del usuario. Esto permite un manejo eficiente de grandes volúmenes de datos.\n- Micro-partitioning requires a cluster key on a table: Los micro-partitioning no requieren una clave de clúster, esta función es automática en Snowflake.\n- Micro-partitioning requires the use of the search optimization service: El servicio de optimización de búsqueda es independiente de los micro-partitioning.\n- Micro-partitioning is defined by the user when a table is created: Los usuarios no definen los micro-partitioning al crear una tabla; Snowflake lo hace de manera automática.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions#:~:text=Micro%2Dpartitioning%20is%20automatically%20performed%20on%20all%20Snowflake%20tables.%20Tables%20are%20transparently%20partitioned%20using%20the%20ordering%20of%20the%20data%20as%20it%20is%20inserted/loaded."}, {"id": 1041, "area": "Performance Concepts", "question": "What persistent data structures are used by the search optimization service to improve the performance of point lookups?", "options": ["A) Micro-partitions", "B) Clustering keys", "C) Equality searches", "D) Search access paths"], "chooseN": 1, "correct": ["Search access paths"], "explanation": "- Search access paths: El servicio de optimización de búsqueda de Snowflake crea y mantiene una estructura de datos persistente llamada 'search access path'. Esta estructura permite rastrear qué valores de las columnas de una tabla podrían encontrarse en cada una de sus micro-particiones, permitiendo omitir algunas de ellas al escanear la tabla, mejorando así el rendimiento de las consultas.\n- Micro-partitions: Las micro-particiones son la unidad básica de almacenamiento en Snowflake, pero no son una estructura de datos persistente específica del servicio de optimización de búsqueda.\n- Clustering keys: Las claves de clúster son utilizadas para mejorar el rendimiento de ciertas consultas, pero no son utilizadas por el servicio de optimización de búsqueda de manera directa.\n- Equality searches: Las búsquedas de igualdad son un tipo de operación de consulta, pero no una estructura de datos.", "reference": "https://docs.snowflake.com/en/user-guide/search-optimization-service#how-the-search-optimization-service-works"}, {"id": 1042, "area": "Account Access and Security", "question": "Which Snowflake feature provides increased login security for users connecting to Snowflake that is powered by Duo Security service?", "options": ["A) OAuth", "B) Network policies", "C) Single Sign-On (SSO)", "D) Multi-Factor Authentication (MFA)"], "chooseN": 1, "correct": ["Multi-Factor Authentication (MFA)"], "explanation": "- Multi-Factor Authentication (MFA): Snowflake ofrece autenticación multifactor (MFA) para mejorar la seguridad de los inicios de sesión de los usuarios. Esta función está impulsada por el servicio Duo Security, y es administrada completamente por Snowflake, proporcionando una capa adicional de seguridad al requerir más de una forma de verificación para iniciar sesión.\n- OAuth: OAuth es un estándar de autorización, pero no proporciona autenticación multifactor.\n- Network policies: Las políticas de red limitan el acceso desde ciertas direcciones IP, pero no ofrecen autenticación adicional como lo hace MFA.\n- Single Sign-On (SSO): SSO permite a los usuarios iniciar sesión una sola vez para acceder a múltiples sistemas, pero no proporciona una autenticación adicional en el momento del inicio de sesión, a diferencia de MFA.", "reference": "https://docs.snowflake.com/en/user-guide/ui-snowsight-profile#enroll-in-multi-factor-authentication-mfa"}, {"id": 1043, "area": "Account Access and Security", "question": "A user with which privileges can create or manage other users in a Snowflake account? (Choose two.)", "options": ["A) GRANT", "B) SELECT", "C) MODIFY", "D) OWNERSHIP", "E) CREATE USER"], "chooseN": 2, "correct": ["OWNERSHIP", "CREATE USER"], "explanation": "- CREATE USER: The `CREATE USER` privilege allows the creation of new users in Snowflake.\n- OWNERSHIP: The `OWNERSHIP` privilege allows modifying existing users.\n- GRANT: The `GRANT` privilege is used for assigning privileges but not for managing users.\n- SELECT: The `SELECT` privilege is for querying data, not managing users.\n- MODIFY: `MODIFY` typically refers to altering objects, not users.", "reference": "https://docs.snowflake.com/en/user-guide/admin-user-management"}, {"id": 1044, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which items are considered schema objects in Snowflake? (Choose two.)", "options": ["A) Pipe", "B) File format", "C) Resource monitor", "D) Storage integration", "E) Virtual warehouse"], "chooseN": 2, "correct": ["Pipe", "File format"], "explanation": "- Pipe: Pipes are schema-level objects used for continuous data loading.\n- File format: File formats define the structure of data files and are schema objects.\n- Resource monitor: This is an account-level object, not a schema object.\n- Storage integration: This is an integration, not a schema object.\n- Virtual warehouse: Virtual warehouses are compute resources, not schema objects.", "reference": "https://www.tutorialspoint.com/snowflake/snowflake_objects.htm"}, {"id": 1045, "area": "Snowflake Data Cloud Features & Architecture", "question": "What does SnowCD help Snowflake users to do?", "options": ["A) Copy data into files.", "B) Manage different databases and schemas.", "C) Troubleshoot network connections to Snowflake.", "D) Write SELECT queries to retrieve data from external tables."], "chooseN": 1, "correct": ["Troubleshoot network connections to Snowflake."], "explanation": "- Troubleshoot network connections to Snowflake: SnowCD is a tool used to troubleshoot network connections.\n- Copy data into files: This is handled by Snowflake’s COPY INTO command, not SnowCD.\n- Manage different databases and schemas: Managing databases and schemas is a core Snowflake feature, not part of SnowCD.\n- Write SELECT queries to retrieve data from external tables: This is handled by Snowflake’s SQL querying capabilities, not SnowCD.", "reference": "https://docs.snowflake.com/en/user-guide/snowcd"}, {"id": 1046, "area": "Account Access and Security", "question": "Awarding a user which privileges on all virtual warehouses is equivalent to granting the user the global MANAGE WAREHOUSES privilege?", "options": ["A) MODIFY, MONITOR and OPERATE privileges", "B) OWNERSHIP and USAGE privileges", "C) APPLYBUDGET and AUDIT privileges", "D) MANAGE LISTING AUTOFULFILLMENT and RESOLVE ALL privileges"], "chooseN": 1, "correct": ["MODIFY, MONITOR and OPERATE privileges"], "explanation": "- MODIFY, MONITOR and OPERATE privileges: These three privileges allow users to manage virtual warehouses, equivalent to the `MANAGE WAREHOUSES` privilege.\n- OWNERSHIP and USAGE privileges: These refer to managing ownership or basic usage rights, not full warehouse management.\n- APPLYBUDGET and AUDIT privileges: These are budgeting and auditing privileges, unrelated to warehouse management.\n- MANAGE LISTING AUTOFULFILLMENT and RESOLVE ALL privileges: These are privileges related to managing listings, not warehouses.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-privileges"}, {"id": 1047, "area": "Account Access and Security", "question": "A Snowflake account has activated federated authentication. What will occur when a user with a password that was defined by Snowflake attempts to log in to Snowflake?", "options": ["A) The user will be unable to enter a password.", "B) The user will encounter an error, and will not be able to log in.", "C) The user will be able to log into Snowflake successfully.", "D) After entering the username and password, the user will be redirected to an Identity Provider (IdP) login page."], "chooseN": 1, "correct": ["The user will be able to log into Snowflake successfully."], "explanation": "- The user will be able to log into Snowflake successfully: Snowflake allows login using Snowflake credentials even with federated authentication activated.\n- The user will be unable to enter a password: Users can still enter passwords for Snowflake-based authentication.\n- The user will encounter an error, and will not be able to log in: Snowflake still accepts login credentials.\n- After entering the username and password, the user will be redirected to an Identity Provider (IdP) login page: This occurs only when using IdP credentials.", "reference": "https://docs.snowflake.com/en/user-guide/admin-security-fed-auth-use"}, {"id": 1048, "area": "Performance Concepts", "question": "Which solution improves the performance of point lookup queries that return a small number of rows from large tables using highly selective filters?", "options": ["A) Automatic clustering", "B) Materialized views", "C) Query acceleration service", "D) Search optimization service"], "chooseN": 1, "correct": ["Search optimization service"], "explanation": "- Search optimization service: This service optimizes point lookup queries with highly selective filters.\n- Automatic clustering: This improves clustering performance but does not specifically target point lookup queries.\n- Materialized views: Materialized views improve query performance, but are not specifically for point lookup queries.\n- Query acceleration service: This service accelerates general queries but is not designed specifically for point lookups.", "reference": "https://docs.snowflake.com/en/user-guide/search-optimization-service"}, {"id": 1049, "area": "Account Access and Security", "question": "What does a Notify & Suspend action for a resource monitor do?", "options": ["A) Send an alert notification to all account users who have notifications enabled.", "B) Send an alert notification to all virtual warehouse users when thresholds over 100% have been met.", "C) Send a notification to all account administrators who have notifications enabled, and suspend all assigned warehouses after all statements being executed by the warehouses have completed.", "D) Send a notification to all account administrators who have notifications enabled, and suspend all assigned warehouses immediately, canceling any statements being executed by the warehouses."], "chooseN": 1, "correct": ["Send a notification to all account administrators who have notifications enabled, and suspend all assigned warehouses after all statements being executed by the warehouses have completed."], "explanation": "- Send a notification to all account administrators who have notifications enabled, and suspend all assigned warehouses after all statements being executed by the warehouses have completed: This is the exact function of the Notify & Suspend action in resource monitors.\n- Send an alert notification to all account users who have notifications enabled: Only administrators receive notifications.\n- Send an alert notification to all virtual warehouse users when thresholds over 100% have been met: Virtual warehouse users are not notified.\n- Send a notification to all account administrators who have notifications enabled, and suspend all assigned warehouses immediately, canceling any statements being executed by the warehouses: Suspension only occurs after ongoing statements have completed.", "reference": "https://docs.snowflake.com/en/user-guide/resource-monitors"}, {"id": 1050, "area": "Account Access and Security", "question": "When working with a managed access schema, who has the OWNERSHIP privilege of any tables added to the schema?", "options": ["A) The database owner", "B) The object owner", "C) The schema owner", "D) The Snowflake user's role"], "chooseN": 1, "correct": ["The object owner"], "explanation": "- The object owner: En un esquema de acceso administrado, los propietarios de los objetos, como las tablas, retienen el privilegio de OWNERSHIP sobre esos objetos, aunque solo el propietario del esquema puede gestionar las concesiones de privilegios.\n\n- The database owner**: El propietario de la base de datos no tiene control directo sobre los objetos dentro del esquema.\n\n- The schema owner**: Aunque el propietario del esquema gestiona las concesiones de privilegios, no posee directamente los objetos creados dentro del esquema.\n\n- The Snowflake user's role**: La función de usuario de Snowflake no tiene privilegios de OWNERSHIP predeterminados sobre los objetos creados en el esquema.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/create-schema#optional-parameters, https://docs.snowflake.com/en/sql-reference/sql/create-versioned-schema#:~:text=In%20managed%20schemas%2C%20the%20schema%20owner%20manages%20all%20privilege%20grants%2C%20including%20future%20grants%2C%20on%20objects%20in%20the%20schema.%20Object%20owners%20retain%20the%20OWNERSHIP%20privileges%20on%20the%20objects%2C%20however%2C%20only%20the%20schema%20owner%20can%20manage%20privilege%20grants%20on%20the%20objects."}, {"id": 1051, "area": "Snowflake Data Cloud Features & Architecture", "question": "How can a Snowsight user change a Standard virtual warehouse to a Snowpark-optimized virtual warehouse?", "options": ["A) Use the ALTER WAREHOUSE command on an active Standard virtual warehouse.", "B) Use the ALTER WAREHOUSE command on an active Snowpark-optimized warehouse.", "C) Use the ALTER WAREHOUSE command on a suspended Standard virtual warehouse.", "D) Use the ALTER WAREHOUSE command on a suspended Snowpark-optimized warehouse."], "chooseN": 1, "correct": ["Use the ALTER WAREHOUSE command on a suspended Standard virtual warehouse."], "explanation": "- Use the ALTER WAREHOUSE command on a suspended Standard virtual warehouse: Snowflake solo permite cambiar el tipo de warehouse (de Standard a Snowpark-optimized) cuando el warehouse está en estado suspendido. No se puede hacer mientras el warehouse esté activo. \n- Use the ALTER WAREHOUSE command on an active Standard virtual warehouse: No es posible cambiar el tipo de warehouse mientras está activo. \n- Use the ALTER WAREHOUSE command on an active Snowpark-optimized warehouse: No se puede aplicar un comando ALTER WAREHOUSE en un warehouse Snowpark-optimized activo. \n- Use the ALTER WAREHOUSE command on a suspended Snowpark-optimized warehouse: Un warehouse ya Snowpark-optimized no requiere este cambio.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-snowpark-optimized"}, {"id": 1052, "area": "Snowflake Data Cloud Features & Architecture", "question": "According to best practices, which table type should be used if the data can be recreated outside of Snowflake?", "options": ["A) Permanent table", "B) Temporary table", "C) Transient table", "D) Volatile table"], "chooseN": 1, "correct": ["Transient table"], "explanation": "- Transient table: Las tablas transitorias (transient tables) son recomendadas para datos que se pueden recrear fuera de Snowflake. Estas tablas no generan costos adicionales de almacenamiento a largo plazo, y no ofrecen protección de recuperación ante fallos. \n- Permanent table: Las tablas permanentes no son recomendadas para datos recreables, ya que generan un almacenamiento a largo plazo con capacidades de recuperación. \n- Temporary table: Las tablas temporales son específicas para sesiones y solo duran hasta el final de la misma. \n- Volatile table: No es un tipo de tabla soportado en Snowflake.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/create-table"}, {"id": 1053, "area": "Data Loading and Unloading", "question": "Which function unloads data from a relational table to JSON?", "options": ["A) TO_OBJECT", "B) TO_JSON", "C) TO_VARIANT", "D) OBJECT_CONSTRUCT"], "chooseN": 1, "correct": ["OBJECT_CONSTRUCT"], "explanation": "The OBJECT_CONSTRUCT function is used to convert rows from a relational table into JSON format for unloading. According to Snowflake documentation, OBJECT_CONSTRUCT(*) combined with the COPY INTO command converts relational table rows into a single VARIANT column and unloads them as JSON files. TO_JSON converts an existing VARIANT value to a JSON string but is not the function used for the relational-to-JSON conversion during unloading.", "reference": "https://docs.snowflake.com/en/user-guide/data-unload-considerations"}, {"id": 1054, "area": "Data Loading and Unloading", "question": "What is the purpose of the STRIP_NULL_VALUES file format option when loading semi-structured data files into Snowflake?", "options": ["A) It removes null values from all columns in the data.", "B) It converts null values to empty strings during loading.", "C) It skips rows with null values during the loading process.", "D) It removes object or array elements containing null values."], "chooseN": 1, "correct": ["It removes object or array elements containing null values."], "explanation": "- It removes object or array elements containing null values: Esta opción elimina los elementos OBJECT o ARRAY que contienen valores 'null' al cargar datos semi-estructurados en Snowflake, optimizando el tamaño de los datos y eliminando información innecesaria. \n- It removes null values from all columns in the data: Esta no es la función de STRIP_NULL_VALUES, que trabaja solo con estructuras de tipo OBJECT o ARRAY, no con todas las columnas. \n- It converts null values to empty strings during loading: Esta opción no convierte valores 'null' en cadenas vacías. \n- It skips rows with null values during the loading process: STRIP_NULL_VALUES no omite filas completas, solo elementos dentro de OBJECT o ARRAY.", "reference": "https://docs.snowflake.com/en/user-guide/semistructured-considerations#label-variant-null"}, {"id": 1055, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which Snowflake edition enables data sharing only through Snowflake Support?", "options": ["A) Virtual Private Snowflake", "B) Business Critical", "C) Enterprise", "D) Standard"], "chooseN": 1, "correct": ["Virtual Private Snowflake"], "explanation": "- Virtual Private Snowflake: Snowflake's VPS edition restricts data sharing outside the VPS by default. To share data with non-VPS customers, you must contact Snowflake Support.\n- Business Critical: This edition provides data sharing without such restrictions.\n- Enterprise: Enterprise supports data sharing without involving Snowflake Support.\n- Standard: Standard allows unrestricted data sharing, unlike VPS.", "reference": "https://docs.snowflake.com/en/user-guide/intro-editions#data-sharing"}, {"id": 1056, "area": "Data Loading and Unloading", "question": "What is the primary purpose of partitioning staged data files for regular data loads?", "options": ["A) To improve the performance of data loads", "B) To compress the data for efficient storage", "C) To encrypt the data for enhanced security", "D) To organize the data into subfolders for easy browsing"], "chooseN": 1, "correct": ["To improve the performance of data loads"], "explanation": "- To improve the performance of data loads: Partitioning data files into logical paths narrows the focus during loading operations, which enhances performance.\n- To compress the data for efficient storage: Compression is unrelated to file partitioning.\n- To encrypt the data for enhanced security: Encryption addresses security, not partitioning efficiency.\n- To organize the data into subfolders for easy browsing: While partitioning does organize data, the primary purpose is performance, not browsing.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-considerations-stage#organizing-data-by-path"}, {"id": 1057, "area": "Account Access and Security", "question": "What is the minimum Snowflake Edition that supports secure storage of Protected Health Information (PHI) data?", "options": ["A) Standard Edition", "B) Enterprise Edition", "C) Business Critical Edition", "D) Virtual Private Snowflake Edition"], "chooseN": 1, "correct": ["Business Critical Edition"], "explanation": "- Business Critical Edition: This edition, formerly known as Enterprise for Sensitive Data (ESD), provides enhanced data protection for sensitive data such as PHI, and complies with HIPAA and HITRUST CSF regulations.\n- Standard Edition: The Standard Edition lacks the advanced security features needed for PHI data storage.\n- Enterprise Edition: Although more secure than Standard, Enterprise Edition does not meet the stringent requirements for PHI.\n- Virtual Private Snowflake Edition: VPS provides high security, but Business Critical is the minimum edition that explicitly supports PHI data.", "reference": "https://docs.snowflake.com/en/user-guide/intro-editions"}, {"id": 1058, "area": "Performance Concepts", "question": "What can a Snowflake user do to reduce queuing on a multi-cluster virtual warehouse?", "options": ["A) Increase the warehouse size.", "B) Use an economy scaling policy.", "C) Increase the maximum number of clusters.", "D) Convert the warehouse to a Snowpark-optimized warehouse."], "chooseN": 1, "correct": ["Increase the maximum number of clusters."], "explanation": "- Increase the maximum number of clusters: Al aumentar el número máximo de clústeres en un almacén virtual multi-cluster, Snowflake puede activar automáticamente más clústeres para manejar la carga, lo que reduce el tiempo en cola.\n- Increase the warehouse size: Aumentar el tamaño del almacén mejora el rendimiento de cada nodo, pero no reduce el tiempo en cola si la demanda de consultas es alta.\n- Use an economy scaling policy: Esta política está diseñada para ahorrar costos, no para reducir el tiempo en cola, lo que puede afectar el rendimiento.\n- Convert the warehouse to a Snowpark-optimized warehouse: Snowpark está orientado a ejecutar cargas de trabajo de ciencia de datos, no a gestionar la cola de consultas en un almacén multi-cluster.", "reference": "https://docs.snowflake.com/en/user-guide/performance-query-warehouse-queue"}, {"id": 1059, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which statements describe benefits of Snowflake's separation of compute and storage? (Choose two.)", "options": ["A) The separation allows independent scaling of computing resources.", "B) The separation ensures consistent data encryption across all virtual data warehouses.", "C) The separation supports automatic conversion of semi-structured data into structured data for advanced data analysis.", "D) Storage volume growth and compute usage growth can be tightly coupled.", "E) Compute can be scaled up or down without the requirement to add more storage."], "chooseN": 2, "correct": ["The separation allows independent scaling of computing resources.", "Compute can be scaled up or down without the requirement to add more storage."], "explanation": "- The separation allows independent scaling of computing resources: Snowflake permite escalar recursos de cómputo de manera independiente al almacenamiento, lo que brinda flexibilidad en la gestión de recursos.\n- Compute can be scaled up or down without the requirement to add more storage: Es posible escalar el cómputo sin tener que agregar más almacenamiento, lo que permite un uso más eficiente de los recursos.\n- The separation ensures consistent data encryption across all virtual data warehouses: La separación de almacenamiento y cómputo no afecta la encriptación de datos, ya que esta es gestionada de forma independiente.\n- The separation supports automatic conversion of semi-structured data into structured data: Snowflake soporta datos semiestructurados, pero esto no está relacionado con la separación de cómputo y almacenamiento.\n- Storage volume growth and compute usage growth can be tightly coupled: La separación permite que estos crecimientos no estén estrechamente vinculados.", "reference": "https://docs.snowflake.com/en/user-guide/intro-key-concepts.html"}, {"id": 1060, "area": "Data Loading and Unloading", "question": "What should be used to show the status of partial data loads and loading errors?", "options": ["A) The COPY_HISTORY function", "B) The QUERY_HISTORY function", "C) The ACCESS_HISTORY view", "D) The WAREHOUSE_LOAD_HISTORY function"], "chooseN": 1, "correct": ["The COPY_HISTORY function"], "explanation": "- The COPY_HISTORY function: Esta función devuelve el historial de cargas de datos en una tabla, incluyendo estados como 'carga parcial' o 'errores'.\n- The QUERY_HISTORY function: Esta función se utiliza para revisar el historial de consultas ejecutadas, no para cargas de datos.\n- The ACCESS_HISTORY view: Esta vista ofrece detalles sobre el acceso a los datos, pero no sobre los errores de carga.\n- The WAREHOUSE_LOAD_HISTORY function: Esta función no existe en Snowflake.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/copy_history#output"}, {"id": 1061, "area": "Data Loading and Unloading", "question": "What transformations are supported when loading data into a table using the COPY INTO [table] command? (Choose two.)", "options": ["A) Column reordering", "B) Column omission", "C) JOIN function", "D) FLATTEN function", "E) GROUP BY function"], "chooseN": 2, "correct": ["Column reordering", "Column omission"], "explanation": "- Column reordering: El comando COPY INTO [table] soporta el reordenamiento de columnas, lo que permite adaptar el orden de los datos cargados en las tablas.\n- Column omission: También es posible omitir columnas durante la carga de datos, facilitando cargas parciales.\n- JOIN function: Las uniones de tablas no son posibles durante la carga de datos; esto se realiza en la fase de consulta.\n- FLATTEN function: La función FLATTEN está diseñada para consultas de datos semiestructurados y no para la carga.\n- GROUP BY function: GROUP BY se utiliza en las consultas, no durante la carga de datos.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-transform"}, {"id": 1062, "area": "Data Protection and Data Sharing", "question": "Which object can be used with Secure Data Sharing?", "options": ["A) View", "B) Materialized view", "C) External table", "D) User-Defined Function (UDF)"], "chooseN": 1, "correct": ["View"], "explanation": "The correct answer is: View. Answer A (View) is correct. However, the explanation incorrectly says UDFs are only 'partially compatible.' The current docs list 'User-defined functions (UDFs) (secure and non-secure)' as shareable objects. The explanation needs to be corrected to reflect that UDFs are shareable, though View remains the correct single answer for this question. Reference: https://docs.snowflake.com/en/user-guide/data-sharing-intro", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-intro#granting-privileges-on-objects-in-a-share"}, {"id": 1063, "area": "Data Protection and Data Sharing", "question": "Which parameter can be set at the account level to set the minimum number of days for which Snowflake retains historical data in Time Travel?", "options": ["A) DATA_RETENTION_TIME_IN_DAYS", "B) MAX_DATA_EXTENSION_TIME_IN_DAYS", "C) MIN_DATA_RETENTION_TIME_IN_DAYS", "D) MAX_CONCURRENCY_LEVEL"], "chooseN": 1, "correct": ["MIN_DATA_RETENTION_TIME_IN_DAYS"], "explanation": "- MIN_DATA_RETENTION_TIME_IN_DAYS: Este parámetro permite definir el mínimo de días para la retención de datos históricos en Time Travel.\n- DATA_RETENTION_TIME_IN_DAYS: Este parámetro no existe como tal; el parámetro adecuado para establecer la retención mínima es 'MIN_DATA_RETENTION_TIME_IN_DAYS'.\n- MAX_DATA_EXTENSION_TIME_IN_DAYS: Este parámetro se utiliza para extender el tiempo máximo de retención de datos, no para el mínimo.\n- MAX_CONCURRENCY_LEVEL: Este parámetro controla el nivel de concurrencia, no la retención de datos históricos.", "reference": "https://docs.snowflake.com/en/sql-reference/parameters"}, {"id": 1064, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which commands are restricted in owner's rights stored procedures? (Choose two.)", "options": ["A) SHOW", "B) MERGE", "C) INSERT", "D) DELETE", "E) DESCRIBE"], "chooseN": 2, "correct": ["SHOW", "DESCRIBE"], "explanation": "- SHOW y DESCRIBE: Los procedimientos almacenados con derechos de propietario en Snowflake tienen restricciones adicionales que incluyen la imposibilidad de ejecutar comandos SHOW y DESCRIBE desde dentro del procedimiento.\n\n- **MERGE**: Incorrecto, MERGE no tiene restricciones en procedimientos almacenados con derechos de propietario.\n- **INSERT**: Incorrecto, INSERT puede ejecutarse sin restricciones.\n- **DELETE**: Incorrecto, DELETE tampoco está restringido en estos procedimientos.", "reference": "https://docs.snowflake.com/en/developer-guide/stored-procedure/stored-procedures-rights"}, {"id": 1065, "area": "Performance Concepts", "question": "What is the relationship between a Query Profile and a virtual warehouse?", "options": ["A) A Query Profile can help users right-size virtual warehouses.", "B) A Query Profile defines the hardware specifications of the virtual warehouse.", "C) A Query Profile can help determine the number of virtual warehouses available.", "D) A Query Profile automatically scales the virtual warehouse based on the query complexity."], "chooseN": 1, "correct": ["A Query Profile can help users right-size virtual warehouses."], "explanation": "- A Query Profile can help users right-size virtual warehouses: Un perfil de consulta permite identificar el tamaño adecuado del almacén virtual al observar la eficiencia de las consultas ejecutadas.\n- A Query Profile defines the hardware specifications: El perfil de consulta no define las especificaciones del hardware.\n- A Query Profile can help determine the number of virtual warehouses available: Los perfiles de consulta no muestran el número de almacenes disponibles.\n- A Query Profile automatically scales: Los perfiles de consulta no escalan automáticamente el almacén virtual.", "reference": "https://www.chaosgenius.io/blog/snowflake-warehouse-sizes"}, {"id": 1066, "area": "Data Loading and Unloading", "question": "Which transformation is supported by a COPY INTO [table] command?", "options": ["A) Filter using a WHERE clause", "B) Filter using a LIMIT keyword", "C) Cast using a SELECT statement", "D) Order using an ORDER BY Clause"], "chooseN": 1, "correct": ["Cast using a SELECT statement"], "explanation": "- Cast using a SELECT statement: El comando COPY INTO [table] permite realizar 'casts' usando una sentencia SELECT durante la carga de datos.\n- Filter using a WHERE clause: No es posible utilizar cláusulas WHERE dentro de un COPY INTO.\n- Filter using a LIMIT keyword: No se puede usar LIMIT en la carga de datos con COPY INTO.\n- Order using an ORDER BY Clause: ORDER BY tampoco es soportado en la transformación de datos durante la carga.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-transform"}, {"id": 1067, "area": "Account Access and Security", "question": "How can a Snowflake administrator determine which user has accessed a database object that contains sensitive information?", "options": ["A) Review the granted privileges to the database object.", "B) Review the row access policy for the database object.", "C) Query the ACCESS_HISTORY view in the ACCOUNT_USAGE schema.", "D) Query the REPLICATION_USAGE_HISTORY view in the ORGANIZATION_USAGE schema."], "chooseN": 1, "correct": ["Query the ACCESS_HISTORY view in the ACCOUNT_USAGE schema."], "explanation": "- Query the ACCESS_HISTORY view in the ACCOUNT_USAGE schema: La vista ACCESS_HISTORY permite ver el historial de acceso de usuarios a objetos sensibles.\n- Review the granted privileges: Revisar privilegios otorgados no da detalles sobre quién accedió al objeto.\n- Review the row access policy: Las políticas de acceso no muestran información de los accesos reales.\n- Query the REPLICATION_USAGE_HISTORY view: Esta vista no está relacionada con los accesos a objetos de bases de datos.", "reference": "https://theinformationlab.nl/2022/10/04/history-access-in-snowflake"}, {"id": 1068, "area": "Account Access and Security", "question": "How does conditional data masking work in Snowflake?", "options": ["A) It selectively masks plain text data.", "B) It selectively masks multiple columns.", "C) It masks all values in a given column.", "D) It selectively masks a column value based on another column."], "chooseN": 1, "correct": ["It selectively masks a column value based on another column."], "explanation": "- It selectively masks a column value based on another column: Snowflake permite el enmascaramiento condicional basado en los valores de otra columna.\n- It selectively masks plain text data: No se limita solo a texto plano; el enmascaramiento depende de las condiciones definidas.\n- It selectively masks multiple columns: El enmascaramiento condicional es específico para columnas individuales, no múltiples a la vez.\n- It masks all values in a given column: El enmascaramiento puede ser condicional, no necesariamente para todos los valores de la columna.", "reference": "https://community.snowflake.com/s/article/How-to-conditionally-mask-a-column-in-a-table-based-on-a-subquery-from-a-different-table"}, {"id": 1069, "area": "Performance Concepts", "question": "If a virtual warehouse runs for 61 seconds, shuts down, and then restarts and runs for 30 seconds, for how many seconds is it billed?", "options": ["A) 60", "B) 91", "C) 120", "D) 121"], "chooseN": 1, "correct": ["121"], "explanation": "- 121: Según la documentación de Snowflake, si un warehouse corre durante 61 segundos, se cobra por esos 61 segundos. Cuando se reinicia y corre por menos de 60 segundos, se factura por un mínimo de 60 segundos. En este caso, se suma 60 (segundos del segundo inicio) + 1 (segundo adicional tras los 61 segundos iniciales) = 121 segundos.\n\n- **60**: Incorrecto, ya que se cobra por el tiempo total, no solo la primera ejecución.\n- **91**: Incorrecto, la facturación mínima por segundo después del minuto no aplica aquí.\n- **120**: Incorrecto, ya que no considera el segundo adicional en la primera ejecución.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-considerations#how-are-credits-charged-for-warehouses, https://docs.snowflake.com/en/user-guide/cost-understanding-compute"}, {"id": 1070, "area": "Data Loading and Unloading", "question": "What function, combined with the copy command, should be used to unload data from a relational table into a JSON file?", "options": ["A) LATERAL", "B) CAST", "C) FLATTEN", "D) OBJECT_CONSTRUCT"], "chooseN": 1, "correct": ["OBJECT_CONSTRUCT"], "explanation": "- OBJECT_CONSTRUCT: El uso de la función OBJECT_CONSTRUCT junto con el comando COPY permite convertir las filas de una tabla relacional en una columna de tipo VARIANT y descargarlas en un archivo JSON.\n\n- **LATERAL**: Incorrecto, LATERAL es usado principalmente para consultas complejas con subconsultas.\n- **CAST**: Incorrecto, CAST convierte tipos de datos, no transforma las filas en un archivo JSON.\n- **FLATTEN**: Incorrecto, FLATTEN se utiliza para trabajar con datos semi-estructurados, pero no para este propósito.", "reference": "https://docs.snowflake.com/en/user-guide/data-unload-considerations"}, {"id": 1071, "area": "Snowflake Data Cloud Features & Architecture", "question": "What is the primary purpose of a directory table in Snowflake?", "options": ["A) To store actual data from external stages", "B) To automatically expire file URLs for security", "C) To manage user privileges and access control", "D) To store file-level metadata about data files in a stage"], "chooseN": 1, "correct": ["To store file-level metadata about data files in a stage"], "explanation": "- To store file-level metadata about data files in a stage: Una 'directory table' almacena metadatos sobre los archivos en una etapa, como su tamaño, timestamp de modificación y URL del archivo.\n\n- **To store actual data from external stages**: Incorrecto, ya que una 'directory table' no almacena los datos reales, solo los metadatos.\n- **To automatically expire file URLs for security**: Incorrecto, expirar URLs no es la función principal de estas tablas.\n- **To manage user privileges and access control**: Incorrecto, la gestión de privilegios se realiza a través de roles y permisos.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-dirtables"}, {"id": 1072, "area": "Data Protection and Data Sharing", "question": "Which Snowflake table objects can be shared with other accounts? (Choose two.)", "options": ["A) Temporary tables", "B) Permanent tables", "C) Transient tables", "D) External tables", "E) User-Defined Table Functions (UDTFs)"], "chooseN": 2, "correct": ["Permanent tables", "External tables"], "explanation": "- **Permanent tables y External tables**: Snowflake permite compartir 'permanent tables' y 'external tables' con otras cuentas utilizando la función de 'Secure Data Sharing'.\n\n- **Temporary tables**: Incorrecto, las tablas temporales no se pueden compartir entre cuentas.\n- **Transient tables**: Incorrecto, no está claro si se pueden compartir, pero no es una opción válida.\n- **User-Defined Table Functions (UDTFs)**: Incorrecto, las funciones definidas por el usuario no son tablas, por lo que no se incluyen en esta categoría.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-intro"}, {"id": 1073, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which metadata table will store the storage utilization information even for dropped tables?", "options": ["A) DATABASE_STORAGE_USAGE_HISTORY", "B) TABLE_STORAGE_METRICS", "C) STORAGE_DAILY_HISTORY", "D) STAGE_STORAGE_USAGE_HISTORY"], "chooseN": 1, "correct": ["TABLE_STORAGE_METRICS"], "explanation": "- TABLE_STORAGE_METRICS: Esta tabla de metadatos almacena información sobre la utilización de almacenamiento a nivel de tabla, incluso para las tablas que han sido eliminadas, pero que todavía están generando costos de almacenamiento.\n\n- **DATABASE_STORAGE_USAGE_HISTORY**: Incorrecto, esta tabla está relacionada con el uso de almacenamiento a nivel de base de datos.\n- **STORAGE_DAILY_HISTORY**: Incorrecto, esta tabla almacena información diaria del uso de almacenamiento, pero no específicamente de tablas eliminadas.\n- **STAGE_STORAGE_USAGE_HISTORY**: Incorrecto, esta tabla almacena información del uso de almacenamiento en stages.", "reference": "https://docs.snowflake.com/en/sql-reference/info-schema/table_storage_metrics"}, {"id": 1074, "area": "Account Access and Security", "question": "How is role hierarchy established in Snowflake?", "options": ["A) By assigning users to roles", "B) By default when a role is created", "C) By granting one role to another role", "D) By transferring ownership of one role to another role"], "chooseN": 1, "correct": ["By granting one role to another role"], "explanation": "- By granting one role to another role: La jerarquía de roles se establece otorgando un rol a otro, creando una relación 'padre-hijo' entre los roles.\n\n- **By assigning users to roles**: Incorrecto, esto solo asigna permisos a los usuarios, no establece jerarquía entre roles.\n- **By default when a role is created**: Incorrecto, la jerarquía no se establece automáticamente al crear un rol.\n- **By transferring ownership of one role to another role**: Incorrecto, la transferencia de propiedad no crea jerarquía de roles.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/grant-role"}, {"id": 1075, "area": "Data Loading and Unloading", "question": "What commands can be used to see what files are stored in a stage? (Choose two.)", "options": ["A) LIST", "B) SELECT", "C) LS", "D) GET", "E) DESCRIBE"], "chooseN": 2, "correct": ["LIST", "LS"], "explanation": "- LIST y LS: Los comandos LIST y LS en Snowflake se usan para listar los archivos almacenados en una etapa. LS es simplemente un alias de LIST.\n\n- **SELECT**: Incorrecto, este comando se usa para realizar consultas sobre tablas o vistas.\n- **GET**: Incorrecto, GET se usa para descargar archivos de una etapa.\n- **DESCRIBE**: Incorrecto, este comando proporciona detalles sobre objetos como tablas, pero no lista archivos en una etapa.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-local-file-system-list"}, {"id": 1076, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which stages are created by default, with no need to use the CREATE STAGE command? (Choose two.)", "options": ["A) External stage", "B) Internal stage", "C) Named stage", "D) Table stage", "E) User stage"], "chooseN": 2, "correct": ["Table stage", "User stage"], "explanation": "- Table stage y User stage: Las etapas de tabla y usuario se crean automáticamente por defecto en Snowflake. La etapa de usuario está asociada a cada usuario, y la etapa de tabla está asociada a cada tabla para cargar archivos.\n\n- **External stage**: Incorrecto, las etapas externas deben crearse explícitamente.\n- **Internal stage**: Incorrecto, aunque las etapas internas existen, se refieren a aquellas creadas manualmente o predeterminadas como las de usuario o tabla.\n- **Named stage**: Incorrecto, las etapas nombradas deben crearse explícitamente.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-local-file-system-create-stage"}, {"id": 1077, "area": "Snowflake Data Cloud Features & Architecture", "question": "While working with unstructured data, which file function generates a Snowflake-hosted file URL to a staged file using the stage name and relative file path as inputs?", "options": ["A) BUILD_STAGE_FILE_URL", "B) GET_ABSOLUTE_PATH", "C) BUILD_SCOPED_FILE_URL", "D) GET_PRESIGNED_URL"], "chooseN": 1, "correct": ["BUILD_STAGE_FILE_URL"], "explanation": "BUILD_STAGE_FILE_URL is the correct function because Snowflake’s documentation says it \"Generates a Snowflake file URL to a staged file using the stage name and relative file path as inputs.\" BUILD_SCOPED_FILE_URL is different because it generates a scoped Snowflake file URL.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/build_stage_file_url"}, {"id": 1078, "area": "Account Access and Security", "question": "Who can create and manage reader accounts? (Choose two.)", "options": ["A) A user with ACCOUNTADMIN role", "B) A user with SECURITYADMIN role", "C) A user with SYSADMIN role", "D) A user with ORGADMIN role", "E) A user with CREATE ACCOUNT privilege"], "chooseN": 2, "correct": ["A user with ACCOUNTADMIN role", "A user with CREATE ACCOUNT privilege"], "explanation": "- A user with ACCOUNTADMIN role y A user with CREATE ACCOUNT privilege: El rol ACCOUNTADMIN o cualquier usuario con el privilegio CREATE ACCOUNT puede crear y gestionar cuentas de lector en Snowflake.\n\n- **A user with SECURITYADMIN role**: Incorrecto, este rol gestiona privilegios de seguridad, pero no puede crear cuentas de lector.\n- **A user with SYSADMIN role**: Incorrecto, este rol gestiona recursos del sistema, pero no cuentas de lector.\n- **A user with ORGADMIN role**: Incorrecto, este rol gestiona la organización en general, pero no específicamente cuentas de lector.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-reader-create"}, {"id": 1079, "area": "Data Loading and Unloading", "question": "Which command allows for continuous loading of data files as soon as they are available in a stage?", "options": ["A) COPY INTO [table]", "B) PUT", "C) CREATE PIPE", "D) GET"], "chooseN": 1, "correct": ["CREATE PIPE"], "explanation": "- CREATE PIPE: El comando CREATE PIPE permite la carga continua de archivos de datos tan pronto como están disponibles en una etapa, usando Snowpipe para la ingesta automática de datos.\n\n- **COPY INTO [table]**: Incorrecto, COPY INTO se usa para copiar datos de manera manual, no continua.\n- **PUT**: Incorrecto, PUT sube archivos a una etapa, pero no habilita la carga automática continua.\n- **GET**: Incorrecto, GET se utiliza para descargar archivos de una etapa, no para cargar datos.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/create-pipe"}, {"id": 1080, "area": "Data Protection and Data Sharing", "question": "What is an advantage of using database roles instead of granting privileges on objects directly to a share in Snowflake?", "options": ["A) Easier management of cross-region data sharing", "B) Greater flexibility in including objects from multiple databases", "C) More control over object-level access for different user groups", "D) Reduction in the number of shares required for different objects in the same database"], "chooseN": 1, "correct": ["More control over object-level access for different user groups"], "explanation": "- More control over object-level access for different user groups: Usar 'Database roles' permite asignar diferentes niveles de acceso a objetos compartidos según el grupo de usuarios, lo que facilita el control del acceso.\n- **Easier management of cross-region data sharing**: Este no es el principal beneficio de usar 'database roles'; la gestión de compartición de datos entre regiones es una funcionalidad separada.\n- **Greater flexibility in including objects from multiple databases**: Los 'database roles' no están enfocados en incluir objetos de varias bases de datos, sino en controlar el acceso.\n- **Reduction in the number of shares required for different objects in the same database**: Usar 'database roles' no afecta directamente la cantidad de shares necesarios.", "reference": "https://community.snowflake.com/s/article/How-to-use-Database-Roles-in-a-Data-Share"}, {"id": 1081, "area": "Account Access and Security", "question": "What is the order of precedence (highest to lowest) of network policies when applied at the account, user, and security integrations layers?", "options": ["A) Account, user, security integration", "B) Account, security integration, user", "C) User, security integration, account", "D) User, account, security integration"], "chooseN": 1, "correct": ["Account, user, security integration"], "explanation": "Snowflake documents that network policies can be applied at the account, user, or security integration level. Account-level policies are the most general, user-level policies override account-level policies, and security-integration-level policies are the most specific and override both. Therefore, the documented hierarchy is account, user, security integration.", "reference": "https://docs.snowflake.com/en/user-guide/network-policies#network-policy-precedence"}, {"id": 1082, "area": "Performance Concepts", "question": "Which type of Snowflake virtual warehouse provides 16 times the memory for each node, and is recommended for larger workloads like Machine Learning (ML) training?", "options": ["A) A size 6XL warehouse", "B) A standard warehouse", "C) A multi-cluster warehouse", "D) A Snowpark-optimized warehouse"], "chooseN": 1, "correct": ["A Snowpark-optimized warehouse"], "explanation": "- A Snowpark-optimized warehouse: El almacén virtual optimizado para Snowpark está diseñado para satisfacer las necesidades de memoria intensivas, como los entrenamientos de ML. Proporciona 16 veces más memoria por nodo en comparación con un almacén estándar, lo que lo hace ideal para estas cargas de trabajo.\n- **A size 6XL warehouse**: Aunque 6XL es un tamaño grande de almacén, no tiene las mismas optimizaciones de memoria que el almacén optimizado para Snowpark.\n- **A standard warehouse**: Un almacén estándar no proporciona la memoria adicional necesaria para tareas intensivas como el entrenamiento de ML.\n- **A multi-cluster warehouse**: Los almacenes de múltiples clústeres están diseñados para manejar picos de carga concurrente, no específicamente para optimizar la memoria como lo hace el almacén Snowpark.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-overview.html#snowpark-optimized-virtual-warehouses"}, {"id": 1083, "area": "Performance Concepts", "question": "Which common query issues can be identified by the Query Profile? (Choose two.)", "options": ["A) Insufficient credit quota", "B) Inefficient query pruning", "C) Excessive query pruning", "D) Exploding joins", "E) Credit usage that exceeds a set threshold"], "chooseN": 2, "correct": ["Inefficient query pruning", "Exploding joins"], "explanation": "- Inefficient query pruning: La Query Profile en Snowflake puede identificar problemas de 'pruning' ineficiente, que ocurre cuando el sistema no puede reducir el conjunto de datos de forma óptima, lo que afecta el rendimiento de la consulta.\n- Exploding joins: Este problema ocurre cuando una consulta genera un número excesivo de combinaciones de filas, lo que puede ser detectado a través del Query Profile.\n- **Insufficient credit quota**: El perfil de consulta no analiza el uso de créditos o cuotas, ya que está más orientado al análisis de problemas de rendimiento en las consultas.\n- **Excessive query pruning**: Aunque el pruning es un concepto clave, no se considera un problema que sea 'excesivo'. El problema es cuando el pruning es ineficiente.\n- **Credit usage that exceeds a set threshold**: La Query Profile no monitorea el uso de créditos en las consultas, se enfoca más en aspectos de rendimiento y optimización.", "reference": "https://docs.snowflake.com/en/user-guide/ui-query-profile#common-query-problems-identified-by-query-profile"}, {"id": 1084, "area": "Data Transformations", "question": "In Snowflake, what allows users to perform recursive queries?", "options": ["A) QUALIFY", "B) LATERAL", "C) PIVOT", "D) CONNECT BY"], "chooseN": 1, "correct": ["CONNECT BY"], "explanation": "- CONNECT BY: El comando 'CONNECT BY' en Snowflake permite realizar consultas recursivas, lo que es útil para trabajar con estructuras jerárquicas o de árbol. Esto es esencial para consultar datos que requieren auto-referencias o relaciones jerárquicas.\n- **QUALIFY**: Este es un comando que se utiliza para filtrar resultados basados en las funciones analíticas, pero no admite consultas recursivas.\n- **LATERAL**: Aunque útil para unirse a subconsultas, 'LATERAL' no es adecuado para consultas recursivas.\n- **PIVOT**: El comando 'PIVOT' se utiliza para rotar filas en columnas, no para consultas recursivas.", "reference": "https://docs.snowflake.com/en/sql-reference/constructs/connect-by"}, {"id": 1085, "area": "Account Access and Security", "question": "A user wants to create objects within a schema but wants to restrict other users’ ability to grant privileges on these objects. What configuration should be used to create the schema?", "options": ["A) Use a regular (non-managed) schema.", "B) Use a managed access schema.", "C) Use a transient schema.", "D) Set the Default_DDL_Collation parameter."], "chooseN": 1, "correct": ["Use a managed access schema."], "explanation": "- Use a managed access schema: En un esquema de acceso administrado ('managed access schema'), sólo los administradores del esquema pueden otorgar privilegios en los objetos creados dentro del esquema. Esto proporciona un mayor control sobre el acceso a los objetos dentro del esquema.\n- **Use a regular (non-managed) schema**: Un esquema regular permite que los propietarios de los objetos dentro del esquema otorguen privilegios, lo cual no es deseable si el objetivo es restringir este tipo de acceso.\n- **Use a transient schema**: Un esquema transitorio no tiene relación directa con el control de privilegios, su principal característica es no tener soporte para el almacenamiento a largo plazo de datos.\n- **Set the Default_DDL_Collation parameter**: Este parámetro está relacionado con la ordenación de texto y no con la administración de privilegios dentro del esquema.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-privileges"}, {"id": 1086, "area": "Performance Concepts", "question": "What is the MOST cost-effective way to resolve memory spillage in a virtual warehouse?", "options": ["A) Enable automatic clustering.", "B) Enable the query acceleration service.", "C) Enable the search optimization service.", "D) Convert to a Snowpark-optimized warehouse."], "chooseN": 1, "correct": ["Convert to a Snowpark-optimized warehouse."], "explanation": "- Convert to a Snowpark-optimized warehouse: Un Snowpark-optimized warehouse proporciona más memoria por nodo, lo que puede resolver problemas de 'memory spillage' sin necesidad de aumentar el tamaño del warehouse. Esto es más rentable que incrementar la potencia de cómputo de manera permanente.\n- **Enable automatic clustering**: El clustering automático está relacionado con el mantenimiento de la estructura de datos y no resuelve directamente los problemas de memoria.\n- **Enable the query acceleration service**: Este servicio agrega recursos temporales de CPU y memoria durante la ejecución de consultas intensivas, pero puede no ser la opción más rentable para problemas continuos de falta de memoria.\n- **Enable the search optimization service**: Este servicio optimiza las búsquedas, pero no afecta directamente la asignación de memoria en los warehouses.", "reference": "https://docs.snowflake.com/en/user-guide/performance-query-warehouse-memory"}, {"id": 1087, "area": "Data Protection and Data Sharing", "question": "What objects in Snowflake are supported by Dynamic Data Masking? (Choose two.)", "options": ["A) Views", "B) Materialized views", "C) Tables", "D) External tables", "E) Future grants"], "chooseN": 2, "correct": ["Views", "Tables"], "explanation": "- Views: Snowflake admite el uso de Dynamic Data Masking en columnas de vistas para aplicar políticas de enmascaramiento de datos, proporcionando una mayor seguridad a nivel de columna.\n- Tables: Las tablas también son compatibles con Dynamic Data Masking, permitiendo enmascarar datos sensibles en consultas a tiempo de ejecución.\n- Materialized views: Las vistas materializadas no son compatibles con Dynamic Data Masking, ya que estas vistas almacenan datos físicos en lugar de ser consultadas en tiempo real.\n- External tables: Las tablas externas no soportan el enmascaramiento dinámico, ya que no están gestionadas de la misma forma que las tablas internas en Snowflake.\n- Future grants: Las concesiones futuras no son objetos que puedan utilizar Dynamic Data Masking.", "reference": "https://docs.snowflake.com/en/user-guide/security-column-ddm-intro"}, {"id": 1088, "area": "Snowflake Data Cloud Features & Architecture", "question": "A user has created a dashboard in Snowflake and wants to share it with colleagues. How can the dashboard be shared?", "options": ["A) By creating a private Data Exchange", "B) By using the share option within Snowsight", "C) By using a Direct Share with another account", "D) By creating a listing on Snowflake Marketplace"], "chooseN": 1, "correct": ["By using the share option within Snowsight"], "explanation": "- By using the share option within Snowsight: Snowsight permite compartir fácilmente paneles de control (dashboards) con otros usuarios dentro de la organización, utilizando la opción de compartir en la propia interfaz.\n- By creating a private Data Exchange: Un intercambio de datos privado se utiliza principalmente para compartir datos entre organizaciones, no paneles de control.\n- By using a Direct Share with another account: El uso de Direct Share está orientado a compartir bases de datos y tablas, no paneles de control en Snowsight.\n- By creating a listing on Snowflake Marketplace: Snowflake Marketplace está diseñado para compartir datos de manera pública, pero no es un método adecuado para compartir un panel privado con colegas.", "reference": "https://docs.snowflake.com/en/user-guide/ui-snowsight-dashboards#share-dashboards, https://www.chaosgenius.io/blog/snowflake-snowsight-guide/"}, {"id": 1089, "area": "Data Protection and Data Sharing", "question": "When would Snowsight automatically detect if a target account is in a different region and enable cross-cloud auto-fulfillment?", "options": ["A) When using a paid listing on the Snowflake Marketplace", "B) When using a private listing on the Snowflake Marketplace", "C) When using a personalized listing on the Snowflake Marketplace", "D) When using a Direct Share with another account"], "chooseN": 1, "correct": ["When using a private listing on the Snowflake Marketplace"], "explanation": "Cross-cloud auto-fulfillment is documented as required when a data product is shared through a private listing and the sharing spans multiple regions. The documentation does not state that paid listings are the trigger; public listings are only recommended for auto-fulfillment.", "reference": "https://other-docs.snowflake.com/en/collaboration/provider-listings-auto-fulfillment#how-cross-cloud-auto-fulfillment-works"}, {"id": 1090, "area": "Data Transformations", "question": "Which languages are supported for writing user-defined functions (UDFs) in Snowflake? (Choose two.)", "options": ["A) JavaScript", "B) SQL", "C) Python", "D) R", "E) Java"], "chooseN": 2, "correct": ["JavaScript", "SQL"], "explanation": "- JavaScript: Snowflake soporta el lenguaje JavaScript para escribir funciones definidas por el usuario (UDFs).\n- SQL: Snowflake también permite el uso de SQL para definir UDFs, facilitando el trabajo directamente en el entorno de consulta.\n- Python: Aunque Snowflake está trabajando en soporte para Python, no es uno de los lenguajes soportados para UDFs en la versión actual.\n- R: R no está soportado para escribir UDFs en Snowflake.\n- Java: Java no se utiliza directamente para UDFs en Snowflake.", "reference": "https://docs.snowflake.com/en/developer-guide/udf/udf-overview"}, {"id": 1091, "area": "Account Access and Security", "question": "Which task privilege does a Snowflake role need in order to suspend or resume a task?", "options": ["A) USAGE", "B) OPERATE", "C) MONITOR", "D) OWNERSHIP"], "chooseN": 1, "correct": ["OPERATE"], "explanation": "- OPERATE: El privilegio 'OPERATE' permite a un rol ejecutar acciones operativas en una tarea, como suspender, reanudar y ejecutar la tarea. Este privilegio es necesario para gestionar el estado de las tareas dentro de Snowflake.\n- USAGE: El privilegio 'USAGE' permite acceder a los objetos, pero no a realizar acciones operativas sobre las tareas.\n- MONITOR: El privilegio 'MONITOR' se utiliza para supervisar el estado y el rendimiento de las tareas, pero no para suspender o reanudar.\n- OWNERSHIP: Aunque el privilegio 'OWNERSHIP' también permite gestionar las tareas, no es la respuesta más específica para la acción de suspender o reanudar, siendo 'OPERATE' la opción correcta para estas acciones.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/alter-task#:~:text=Resuming%20or%20suspending%20a%20task%20(using%20ALTER%20TASK%20%E2%80%A6%20RESUME%20or%20ALTER%20TASK%20%E2%80%A6%20SUSPEND%2C%20respectively)%20requires%20either%20the%20OWNERSHIP%20or%20OPERATE%20privilege%20on%20the%20task"}, {"id": 1092, "area": "Data Loading and Unloading", "question": "What is a directory table in Snowflake?", "options": ["A) A separate database object that is used to store file-level metadata.", "B) An object layered on a stage that is used to store file-level metadata.", "C) A database object with grantable privileges for unstructured data tasks.", "D) A Snowflake table specifically designed for storing unstructured files."], "chooseN": 1, "correct": ["An object layered on a stage that is used to store file-level metadata."], "explanation": "- An object layered on a stage that is used to store file-level metadata.: En Snowflake, una tabla de directorio es un objeto implícito que se superpone a un stage y se utiliza para almacenar metadatos a nivel de archivo sobre los archivos de datos en el stage. No es un objeto de base de datos separado.\n- A separate database object that is used to store file-level metadata.: Esto no es correcto ya que la tabla de directorio no es un objeto de base de datos separado, sino un objeto relacionado con el stage.\n- A database object with grantable privileges for unstructured data tasks.: Esta opción no describe correctamente una tabla de directorio, que no se basa en privilegios de base de datos.\n- A Snowflake table specifically designed for storing unstructured files.: Las tablas de directorio no están diseñadas para almacenar archivos no estructurados, sino para almacenar metadatos sobre archivos en un stage.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-dirtables#:~:text=using%20directory%20tables.-,What%20is%20a%20directory%20table%3F,-%C2%B6"}, {"id": 1093, "area": "Data Loading and Unloading", "question": "What factors impact storage costs in Snowflake? (Choose two.)", "options": ["A) The account type", "B) The storage file format", "C) The cloud region used by the account", "D) The type of data being stored", "E) The cloud platform being used"], "chooseN": 2, "correct": ["The cloud region used by the account", "The cloud platform being used"], "explanation": "- The cloud region used by the account: Los costos de almacenamiento pueden variar según la región geográfica en la que se aloje tu cuenta de Snowflake, ya que diferentes regiones pueden tener precios diferentes debido a factores como los costos de infraestructura local y la demanda.\n- The cloud platform being used: Snowflake opera en múltiples plataformas en la nube (AWS, Azure, Google Cloud), y cada una de estas plataformas tiene su propio modelo de precios para el almacenamiento, lo que puede afectar el costo total de almacenamiento en Snowflake.\n- The account type: Aunque el tipo de cuenta (Capacidad o Bajo Demanda) puede influir en la disponibilidad de recursos de cómputo y niveles de rendimiento, no afecta directamente los costos de almacenamiento.\n- The storage file format: El formato de archivo de almacenamiento no impacta los costos en Snowflake, ya que Snowflake abstrae los formatos de archivo en su capa de almacenamiento, optimizándolos internamente para rendimiento y compresión.\n- The type of data being stored: El tipo de datos almacenados no afecta directamente los costos, ya que los costos de almacenamiento en Snowflake son generales y no dependen del tipo de datos.", "reference": "https://docs.snowflake.com/en/user-guide/cost-understanding-data-storage"}, {"id": 1094, "area": "Account Access and Security", "question": "Which ACCOUNT_USAGE schema database role provides visibility into policy-related information?", "options": ["A) USAGE_VIEWER", "B) GOVERNANCE_VIEWER", "C) OBJECT_VIEWER", "D) SECURITY_VIEWER"], "chooseN": 1, "correct": ["GOVERNANCE_VIEWER"], "explanation": "- GOVERNANCE_VIEWER: El rol 'GOVERNANCE_VIEWER' proporciona visibilidad en la información relacionada con políticas en Snowflake.\n- USAGE_VIEWER: Este rol se centra en la visibilidad de la información de uso y no en la información relacionada con políticas.\n- OBJECT_VIEWER: El rol 'OBJECT_VIEWER' está diseñado para proporcionar visibilidad en objetos específicos, pero no en información sobre políticas.\n- SECURITY_VIEWER: Aunque este rol proporciona visibilidad en temas de seguridad, no está específicamente orientado a la visibilidad de la información relacionada con políticas.", "reference": "https://docs.snowflake.com/en/sql-reference/snowflake-db-roles"}, {"id": 1095, "area": "Performance Concepts", "question": "How should clustering be used to optimize the performance of queries that run on a very large table?", "options": ["A) Manually re-cluster the table regularly.", "B) Choose one high cardinality column as the clustering key.", "C) Use the column that is most-frequently used in query select clauses as the clustering key.", "D) Assess the average table depth to identify how clustering is impacting the query."], "chooseN": 1, "correct": ["Assess the average table depth to identify how clustering is impacting the query."], "explanation": "The correct answer is: Assess the average table depth to identify how clustering is impacting the query.. The docs state 'a column with very high cardinality is also typically not a good candidate to use as a clustering key directly,' contradicting answer B. The docs recommend assessing clustering depth as an indicator. Answer D aligns with the recommended monitoring approach. Reference: https://docs.snowflake.com/en/user-guide/tables-clustering-keys#strategies-for-selecting-clustering-keys", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-keys#strategies-for-selecting-clustering-keys"}, {"id": 1096, "area": "Account Access and Security", "question": "Which privilege must be granted by one role to another role, and cannot be revoked?", "options": ["A) MONITOR", "B) OPERATE", "C) OWNERSHIP", "D) ALL"], "chooseN": 1, "correct": ["OWNERSHIP"], "explanation": "- OWNERSHIP: El privilegio 'OWNERSHIP' en Snowflake es un tipo especial de privilegio que solo puede ser otorgado de un rol a otro y no puede ser revocado. Esto asegura que el rol receptor tenga el control completo sobre el objeto, incluyendo la capacidad de transferir el ownership a otros roles.\n- MONITOR: El privilegio 'MONITOR' se puede otorgar y revocar según las necesidades, y no tiene las restricciones de revocación como el 'OWNERSHIP'.\n- OPERATE: 'OPERATE' permite la ejecución de acciones operacionales en un objeto, pero no tiene las restricciones de revocación que tiene 'OWNERSHIP'.\n- ALL: Aunque 'ALL' puede incluir diversos privilegios, su revocación es posible en cualquier momento, a diferencia del privilegio 'OWNERSHIP'.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/grant-ownership"}, {"id": 1097, "area": "Performance Concepts", "question": "How can performance be optimized for a query that returns a small amount of data from a very large base table?", "options": ["A) Use clustering keys", "B) Create materialized views", "C) Use the search optimization service", "D) Use the query acceleration service"], "chooseN": 1, "correct": ["Use the search optimization service"], "explanation": "The correct answer is: Use the search optimization service. The Search Optimization Service docs state it is designed for 'Selective point lookup queries on tables. A point lookup query returns only one or a small number of distinct rows.' This matches returning a small amount of data from a very large table. Clustering keys are better for range-based queries. The correct answer is C. Reference: https://docs.snowflake.com/en/user-guide/search-optimization-service", "reference": "https://docs.snowflake.com/en/user-guide/query-acceleration-service"}, {"id": 1098, "area": "Data Transformations", "question": "A column named “Data” contains VARIANT data and stores values as follows:\n\n{\n\"Employee\": {\n    id : 100,\n    name : John,\n    location : \"New York\"\n    }\n}\n\nHow will Snowflake extract the employee’s name from the column data?", "options": ["A) Data:employee.name", "B) DATA:employee.name", "C) data:Employee.name", "D) data:employee.name"], "chooseN": 1, "correct": ["data:Employee.name"], "explanation": "- data:Employee.name: En Snowflake, los nombres de las columnas SQL son insensibles a mayusculas (data, Data, DATA funcionan igual), pero los nombres de los campos en datos semiestructurados (JSON/VARIANT) son SENSIBLES a mayusculas y minusculas. Como el JSON contiene la clave `\"Employee\"` con E mayuscula, debemos usar exactamente `Employee` para acceder al campo. La sintaxis correcta es `data:Employee.name`.\n- Data:employee.name: Aunque `Data` como nombre de columna es valido (case-insensitive), `employee` en minusculas no coincide con la clave JSON `\"Employee\"` (case-sensitive), por lo que retornaria NULL.\n- DATA:employee.name: Mismo problema que la anterior - `employee` no coincide con `\"Employee\"`.\n- data:employee.name: Incorrecto porque `employee` (minusculas) no coincide con la clave JSON `\"Employee\"` (mayuscula). Los campos JSON son case-sensitive.", "reference": "https://docs.snowflake.com/en/user-guide/querying-semistructured#traversing-semi-structured-data"}, {"id": 1099, "area": "Data Transformations", "question": "Use of which Snowflake function is recommended when unloading data from a relational table into a JSON file?", "options": ["A) TO_JSON", "B) TO_VARIANT", "C) OBJECT_INSERT", "D) OBJECT_CONSTRUCT"], "chooseN": 1, "correct": ["OBJECT_CONSTRUCT"], "explanation": "- OBJECT_CONSTRUCT: La función `OBJECT_CONSTRUCT` en Snowflake se recomienda para crear objetos JSON a partir de columnas de una tabla relacional. Esta función permite estructurar datos en formato JSON de manera efectiva.\n- TO_JSON: Aunque `TO_JSON` puede convertir datos en formato JSON, no es la función ideal para estructurar datos cuando se descargan desde una tabla relacional a un archivo JSON.\n- TO_VARIANT: `TO_VARIANT` convierte datos en el tipo de datos VARIANT de Snowflake, que no es específico para crear archivos JSON.\n- OBJECT_INSERT: `OBJECT_INSERT` se utiliza para insertar pares clave-valor en un objeto VARIANT o JSON, pero no es la función principal recomendada para estructurar datos cuando se descarga desde una tabla relacional.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/object_construct"}, {"id": 1100, "area": "Data Loading and Unloading", "question": "Which command should be used to generate a single file when unloading data from a Snowflake table into a file?", "options": ["A) PARTITION BY", "B) MAX_FILE_SIZE = 0", "C) SINGLE = TRUE", "D) OVERWRITE = TRUE"], "chooseN": 1, "correct": ["SINGLE = TRUE"], "explanation": "- SINGLE = TRUE: El comando `SINGLE = TRUE` se utiliza para generar un único archivo cuando se descarga datos desde una tabla en Snowflake. Esto es útil para consolidar todos los datos en un solo archivo en lugar de varios archivos.\n- PARTITION BY: `PARTITION BY` se utiliza para dividir datos en particiones, lo que resultaría en múltiples archivos en lugar de uno solo.\n- MAX_FILE_SIZE = 0: `MAX_FILE_SIZE = 0` no es un comando válido para controlar la cantidad de archivos generados; se usa para definir el tamaño máximo de los archivos.\n- OVERWRITE = TRUE: `OVERWRITE = TRUE` se usa para sobrescribir archivos existentes, pero no controla la cantidad de archivos generados.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-location#unloading-data"}, {"id": 1101, "area": "Data Transformations", "question": "Which function can be used to convert semi-structured data into rows and columns?", "options": ["A) TABLE", "B) FLATTEN", "C) PARSE_JSON", "D) JSON_EXTRACT_PATH_TEXT"], "chooseN": 1, "correct": ["FLATTEN"], "explanation": "- FLATTEN: La función `FLATTEN` se utiliza para convertir datos semiestructurados en una representación relacional, expandiendo arrays y objetos en filas y columnas.\n- TABLE: `TABLE` no convierte datos semiestructurados en filas y columnas. Es más una construcción de Snowflake para referirse a tablas o vistas.\n- PARSE_JSON: `PARSE_JSON` convierte cadenas de texto en datos semiestructurados JSON, pero no convierte datos semiestructurados en filas y columnas.\n- JSON_EXTRACT_PATH_TEXT: `JSON_EXTRACT_PATH_TEXT` extrae valores de un documento JSON según una ruta especificada, pero no convierte datos semiestructurados en filas y columnas.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/flatten.html"}, {"id": 1102, "area": "Account Access and Security", "question": "What user setting can be configured to disable Multi-Factor Authentication (MFA) for a Snowflake user? (Choose two.)", "options": ["A) DISABLE_MFA", "B) MINS_TO_BYPASS_MFA", "C) PASSWORD", "D) MINS_TO_UNLOCK", "E) MUST_CHANGE_PASSWORD"], "chooseN": 2, "correct": ["DISABLE_MFA", "MINS_TO_BYPASS_MFA"], "explanation": "- DISABLE_MFA: Este ajuste permite deshabilitar completamente MFA para un usuario en Snowflake.\n- MINS_TO_BYPASS_MFA: Este ajuste permite especificar un tiempo en minutos durante el cual se puede omitir la autenticación multifactor (MFA).\n- MINS_TO_UNLOCK: Este ajuste desbloquea la cuenta de un usuario después de un tiempo determinado, pero no está relacionado con la desactivación de MFA.\n- PASSWORD: Este ajuste gestiona las contraseñas de los usuarios, pero no afecta la configuración de MFA.\n- MUST_CHANGE_PASSWORD: Este ajuste obliga al usuario a cambiar su contraseña, pero no desactiva MFA.", "reference": "https://docs.snowflake.com/en/user-guide/security-mfa#managing-mfa-for-an-account-and-users"}, {"id": 1103, "area": "Data Protection and Data Sharing", "question": "Which table type has a Fail-safe period of 7 days?", "options": ["A) Temporary table", "B) Transient table", "C) Permanent table", "D) External table"], "chooseN": 1, "correct": ["Permanent table"], "explanation": "- Permanent table: Las tablas permanentes en Snowflake tienen un período de Fail-safe de 7 días, lo que garantiza que los datos pueden recuperarse incluso después de que se eliminen o modifiquen.\n- Temporary table: Las tablas temporales no tienen un período de Fail-safe ya que son eliminadas al final de la sesión.\n- Transient table: Las tablas transitorias tienen un período de Fail-safe de 1 día, no 7 días.\n- External table: Las tablas externas no tienen un período de Fail-safe ya que los datos residen fuera de Snowflake.", "reference": "https://docs.snowflake.com/en/user-guide/tables-fail-safe.html"}, {"id": 1104, "area": "Account Access and Security", "question": "How does Snowflake enable OAuth?", "options": ["A) By creating an external integration", "B) By configuring a security integration", "C) By establishing IP allowed lists and IP blocked lists", "D) By using SnowSQL to enable an external OAuth using the Snowflake protocol"], "chooseN": 1, "correct": ["By configuring a security integration"], "explanation": "- By configuring a security integration: Snowflake habilita OAuth configurando una integración de seguridad. Esta integración define los ajustes y parámetros necesarios para que Snowflake interactúe con un servidor de autorización OAuth 2.0, permitiendo a los usuarios autenticarse y autorizar el acceso a los recursos de Snowflake mediante tokens OAuth.\n- By creating an external integration: Aunque Snowflake usa integraciones externas para algunos propósitos, la habilitación de OAuth específicamente se hace mediante una integración de seguridad.\n- By establishing IP allowed lists and IP blocked lists: Las listas de IP permitidas y bloqueadas no están relacionadas con la habilitación de OAuth.\n- By using SnowSQL to enable an external OAuth using the Snowflake protocol: SnowSQL no se utiliza para habilitar OAuth; la habilitación se realiza a través de la configuración de una integración de seguridad.", "reference": "https://docs.snowflake.com/en/user-guide/oauth-intro"}, {"id": 1105, "area": "Performance Concepts", "question": "Which type of workload traditionally benefits from the use of the query acceleration service?", "options": ["A) Workloads with a predictable data volume for each query", "B) Workloads that include on-demand data analyses", "C) Queries with small scans and non-selective filters", "D) Queries that do not have filters or aggregation"], "chooseN": 1, "correct": ["Workloads that include on-demand data analyses"], "explanation": "- Workloads that include on-demand data analyses: El servicio de aceleración de consultas está diseñado para mejorar el rendimiento de cargas de trabajo que incluyen análisis de datos bajo demanda, que a menudo involucran consultas complejas que necesitan ser ejecutadas rápidamente y de manera eficiente. Este servicio acelera el procesamiento de consultas al asignar recursos adicionales, reduciendo los tiempos de respuesta y mejorando el rendimiento para consultas ad-hoc e interactivas.\n- Workloads with a predictable data volume for each query: Las cargas de trabajo con un volumen de datos predecible para cada consulta no son el principal objetivo del servicio de aceleración de consultas.\n- Queries with small scans and non-selective filters: Las consultas con escaneos pequeños y filtros no selectivos no son el tipo de carga de trabajo que se beneficia principalmente del servicio de aceleración de consultas.\n- Queries that do not have filters or aggregation: Las consultas sin filtros ni agregación no son el tipo de carga de trabajo que el servicio de aceleración de consultas está diseñado para mejorar.", "reference": "https://docs.snowflake.com/en/user-guide/query-acceleration"}, {"id": 1106, "area": "Data Loading and Unloading", "question": "Which Snowflake object is supported by both database replication and replication groups?", "options": ["A) Pipes", "B) Users", "C) Stages", "D) Materialized views"], "chooseN": 1, "correct": ["Materialized views"], "explanation": "The correct answer is: Materialized views. The replication doc states for Pipes: 'Supported for replication and failover groups only. Not supported for database replication.' Materialized views are listed as replicated under database replication (no caveat) and are also included when databases are part of replication groups. The correct answer is D (Materialized views), not A (Pipes). Reference: https://docs.snowflake.com/en/user-guide/account-replication-intro#replicated-database-objects", "reference": "https://docs.snowflake.com/en/user-guide/data-replication.html"}, {"id": 1107, "area": "Data Loading and Unloading", "question": "When unloading data, which combination of parameters should be used to differentiate between empty strings and NULL values? (Choose two.)", "options": ["A) ESCAPE_UNENCLOSED_FIELD", "B) REPLACE_INVALID_CHARACTERS", "C) FIELD_OPTIONALLY_ENCLOSED_BY", "D) EMPTY_FIELD_AS_NULL", "E) SKIP_BLANK_LINES"], "chooseN": 2, "correct": ["FIELD_OPTIONALLY_ENCLOSED_BY", "EMPTY_FIELD_AS_NULL"], "explanation": "- FIELD_OPTIONALLY_ENCLOSED_BY: Este parámetro especifica un carácter que envuelve el campo. Usando este parámetro, se puede asegurar que las cadenas vacías estén encerradas dentro del carácter especificado (por ejemplo, comillas dobles), permitiendo diferenciarlas de los valores NULL.\n- EMPTY_FIELD_AS_NULL: Este parámetro determina cómo manejar los campos vacíos durante la operación de descarga. Cuando se establece en TRUE, los campos vacíos se tratan como valores NULL. Esto ayuda a distinguir entre cadenas vacías reales y NULLs en los datos descargados.\n- ESCAPE_UNENCLOSED_FIELD: Este parámetro está relacionado con el escape de caracteres en campos no envueltos, pero no afecta la diferenciación entre cadenas vacías y NULL.\n- REPLACE_INVALID_CHARACTERS: Este parámetro reemplaza caracteres inválidos, pero no se utiliza para diferenciar entre cadenas vacías y NULL.\n- SKIP_BLANK_LINES: Este parámetro omite líneas en blanco durante la descarga, pero no influye en la diferenciación entre cadenas vacías y NULL.", "reference": "https://docs.snowflake.com/en/user-guide/data-unload-considerations"}, {"id": 1108, "area": "Account Access and Security", "question": "Which role must be used to create resource monitors?", "options": ["A) SECURITYADMIN", "B) ACCOUNTADMIN", "C) SYSADMIN", "D) ORGADMIN"], "chooseN": 1, "correct": ["ACCOUNTADMIN"], "explanation": "- ACCOUNTADMIN: El rol 'ACCOUNTADMIN' en Snowflake tiene los privilegios necesarios para crear y gestionar monitores de recursos. Los monitores de recursos se utilizan para gestionar y controlar el uso de recursos (como créditos de cómputo) dentro de la cuenta de Snowflake. El rol 'ACCOUNTADMIN' tiene el nivel más alto de privilegios administrativos necesarios para realizar esta tarea.\n- SECURITYADMIN: El rol 'SECURITYADMIN' se centra en la gestión de la seguridad y no tiene los privilegios necesarios para crear monitores de recursos.\n- SYSADMIN: El rol 'SYSADMIN' tiene privilegios para gestionar objetos de base de datos y roles, pero no para crear monitores de recursos.\n- ORGADMIN: El rol 'ORGADMIN' gestiona la administración de organizaciones, pero no está involucrado en la creación de monitores de recursos.", "reference": "https://docs.snowflake.com/en/user-guide/resource-monitors.html"}, {"id": 1109, "area": "Data Loading and Unloading", "question": "What step does Snowflake recommend when loading data from a stage?", "options": ["A) Use PURGE when using the COPY INTO command.", "B) Use REMOVE when using the COPY INTO command.", "C) Use the LOAD HISTORY function to view the status of loaded files.", "D) Use the COPY HISTORY function to update the status of loaded files."], "chooseN": 1, "correct": ["Use the LOAD HISTORY function to view the status of loaded files."], "explanation": "- Use the LOAD HISTORY function to view the status of loaded files.: Snowflake recomienda usar la función LOAD HISTORY (a través de la vista INFORMATION_SCHEMA.LOAD_HISTORY o consultando la función de tabla COPY_HISTORY) para ver el estado de los archivos cargados. Esto asegura que los archivos se carguen correctamente y ayuda a verificar errores durante el proceso de carga.\n- Use PURGE when using the COPY INTO command.: El comando PURGE se usa para eliminar archivos de un stage, no para ver el estado de los archivos cargados.\n- Use REMOVE when using the COPY INTO command.: El comando REMOVE se utiliza para eliminar archivos de un stage después de que se han cargado, pero no para ver el estado de los archivos cargados.\n- Use the COPY HISTORY function to update the status of loaded files.: La función COPY HISTORY se usa para obtener información sobre las cargas anteriores, no para actualizar el estado de los archivos cargados.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/load_history.html"}, {"id": 1110, "area": "Data Protection and Data Sharing", "question": "How can a user MINIMIZE Continuous Data Protection costs when using large, high-churn, dimension tables?", "options": ["A) Create transient tables and periodically copy them to permanent tables.", "B) Create temporary tables and periodically copy them to permanent tables.", "C) Create regular tables with extended Time Travel and Fail-safe settings.", "D) Create regular tables with default Time Travel and Fail-safe settings."], "chooseN": 1, "correct": ["Create transient tables and periodically copy them to permanent tables."], "explanation": "- Create transient tables and periodically copy them to permanent tables.: Para minimizar los costos de Continuous Data Protection (CDP) con tablas grandes y de alta rotación, se recomienda crear estas tablas como transitorias con retención de Time Travel en cero (DATA_RETENTION_TIME_IN_DAYS=0) y luego copiarlas periódicamente en una tabla permanente.\n- Create temporary tables and periodically copy them to permanent tables.: Las tablas temporales no están diseñadas para este propósito específico, ya que se eliminan al final de la sesión.\n- Create regular tables with extended Time Travel and Fail-safe settings.: Las tablas con configuraciones extendidas de Time Travel y Fail-safe pueden resultar en costos elevados de CDP.\n- Create regular tables with default Time Travel and Fail-safe settings.: Las configuraciones predeterminadas pueden no ser suficientes para minimizar los costos de CDP para tablas de alta rotación.", "reference": "https://docs.snowflake.com/en/user-guide/tables-storage-considerations"}, {"id": 1111, "area": "Data Transformations", "question": "Which Snowsight feature can be used to perform data manipulations and transformations using a programming language?", "options": ["A) SnowSQL", "B) Dashboards", "C) Python worksheets", "D) Provider Studio"], "chooseN": 1, "correct": ["Python worksheets"], "explanation": "- Python worksheets: En Snowsight, las 'Python worksheets' permiten a los usuarios realizar manipulaciones y transformaciones de datos utilizando el lenguaje de programación Python, lo que es ideal para tareas complejas y personalizadas.\n- SnowSQL: SnowSQL es una herramienta de línea de comandos para ejecutar consultas SQL en Snowflake, pero no está diseñada para transformaciones utilizando lenguajes de programación.\n- Dashboards: Los Dashboards son para visualizar datos y crear informes interactivos, pero no para realizar transformaciones de datos con lenguajes de programación.\n- Provider Studio: No es una característica de Snowsight; este término no está relacionado con la manipulación de datos en Snowflake.", "reference": "https://docs.snowflake.com/en/user-guide/snowsight-overview"}, {"id": 1112, "area": "Data Protection and Data Sharing", "question": "In Snowflake's data security framework, how does column-level security contribute to the protection of sensitive information? (Choose two.)", "options": ["A) Implementation of column-level security will optimize query performance.", "B) Column-level security supports encryption of the entire database.", "C) Column-level security ensures that only the table owner can access the data.", "D) Column-level security limits access to specific columns within a table based on user privileges.", "E) Column-level security allows the application of a masking policy to a column within a table or view."], "chooseN": 2, "correct": ["Column-level security limits access to specific columns within a table based on user privileges.", "Column-level security allows the application of a masking policy to a column within a table or view."], "explanation": "- Column-level security limits access to specific columns within a table based on user privileges.: La seguridad a nivel de columna en Snowflake permite limitar el acceso a columnas específicas dentro de una tabla en función de los privilegios del usuario, protegiendo así la información sensible.\n- Column-level security allows the application of a masking policy to a column within a table or view.: También permite la aplicación de políticas de enmascaramiento a columnas específicas dentro de una tabla o vista, lo que ayuda a proteger datos sensibles al ocultar información según el contexto del usuario.\n- Implementation of column-level security will optimize query performance.: La implementación de la seguridad a nivel de columna no está diseñada para optimizar el rendimiento de las consultas, sino para proteger la información.\n- Column-level security supports encryption of the entire database.: La seguridad a nivel de columna no proporciona cifrado para toda la base de datos; eso se maneja a través de otras características de seguridad en Snowflake.\n- Column-level security ensures that only the table owner can access the data.: No garantiza que solo el propietario de la tabla pueda acceder a los datos, sino que controla el acceso a nivel de columna en función de los privilegios del usuario.", "reference": "https://docs.snowflake.com/en/user-guide/security-column.html"}, {"id": 1113, "area": "Performance Concepts", "question": "How does Snowflake utilize clustering information to improve query performance?", "options": ["A) It prunes unnecessary micro-partitions based on clustering metadata.", "B) It compresses the data within micro-partitions for faster querying.", "C) It automatically allocates additional resources to improve query execution.", "D) It organizes clustering information to speed-up data retrieval from storage."], "chooseN": 1, "correct": ["It prunes unnecessary micro-partitions based on clustering metadata."], "explanation": "- It prunes unnecessary micro-partitions based on clustering metadata.: Snowflake utiliza la información de clustering para identificar y eliminar particiones micro no relevantes durante la ejecución de consultas, mejorando significativamente el rendimiento al reducir la cantidad de datos escaneados.\n- It compresses the data within micro-partitions for faster querying.: Aunque Snowflake puede comprimir datos, la mejora de rendimiento relacionada con la información de clustering se centra en la poda de particiones, no en la compresión de datos.\n- It automatically allocates additional resources to improve query execution.: La asignación de recursos adicionales no está directamente relacionada con la información de clustering; en cambio, el clustering se enfoca en optimizar el acceso a los datos.\n- It organizes clustering information to speed-up data retrieval from storage.: La organización de la información de clustering se usa para la poda de particiones, no para la organización general de la información para la recuperación de datos.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-keys.html"}, {"id": 1114, "area": "Data Loading and Unloading", "question": "How can staged files be removed during data loading once the files have loaded successfully?", "options": ["A) Use the DROP command.", "B) Use the PURGE copy option.", "C) Use the FORCE = TRUE parameter.", "D) Use the LOAD_UNCERTAIN_FILES copy option."], "chooseN": 1, "correct": ["Use the PURGE copy option."], "explanation": "- Use the PURGE copy option.: La opción PURGE se utiliza para eliminar los archivos de etapa después de que se haya completado la carga de datos correctamente. Esto asegura que los archivos no permanezcan en el almacenamiento de etapa, lo que ayuda a gestionar el espacio y evitar cargos innecesarios.\n- Use the DROP command.: El comando DROP no se utiliza para eliminar archivos de etapa después de una carga de datos. Es más comúnmente usado para eliminar objetos como tablas o bases de datos.\n- Use the FORCE = TRUE parameter.: El parámetro FORCE = TRUE se utiliza para forzar la carga de datos a pesar de ciertos errores, pero no está relacionado con la eliminación de archivos de etapa.\n- Use the LOAD_UNCERTAIN_FILES copy option.: La opción LOAD_UNCERTAIN_FILES se usa para manejar archivos que pueden no cumplir con el esquema esperado, no para eliminar archivos de etapa.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-overview.html"}, {"id": 1115, "area": "Snowflake Data Cloud Features & Architecture", "question": "What objects can be cloned within Snowflake? (Choose two.)", "options": ["A) Schemas", "B) Users", "C) External tables", "D) Internal named stages", "E) External named stages"], "chooseN": 2, "correct": ["Schemas", "External named stages"], "explanation": "- Schemas: Schemas can be cloned in Snowflake using the CLONE command.\n- External named stages: External named stages can also be cloned in Snowflake. Internal named stages are not separate from schemas and thus fall under schemas. Cloning users and external tables is not supported.\n- Users: Users cannot be cloned.\n- External tables: External tables cannot be cloned directly.\n- Internal named stages: Internal named stages are not independently clonable; they are included under schemas.", "reference": "https://docs.snowflake.com/en/user-guide/object-clone.html"}, {"id": 1116, "area": "Data Transformations", "question": "What can be used to process unstructured data?", "options": ["A) External tables", "B) The COPY INTO command", "C) External functions", "D) Snowpipe"], "chooseN": 1, "correct": ["External functions"], "explanation": "- External functions: Snowflake permite el procesamiento de datos no estructurados mediante funciones externas, que pueden integrar y procesar datos desde fuentes externas como servicios web.\n- External tables: Las tablas externas se utilizan para acceder a datos almacenados fuera de Snowflake, pero no procesan datos no estructurados directamente.\n- The COPY INTO command: El comando COPY INTO se utiliza para cargar datos desde archivos a Snowflake, pero no está diseñado para procesar datos no estructurados.\n- Snowpipe: Snowpipe se usa para la carga continua de datos en Snowflake, no para el procesamiento de datos no estructurados.", "reference": "https://docs.snowflake.com/en/user-guide/external-functions.html"}, {"id": 1117, "area": "Performance Concepts", "question": "Which type of workload is recommended for Snowpark-optimized virtual warehouses?", "options": ["A) Workloads with ad hoc analytics", "B) Workloads that have large memory requirements", "C) Workloads with unpredictable data volumes for each query", "D) Workloads that are queried with small table scans and selective filters"], "chooseN": 1, "correct": ["Workloads that have large memory requirements"], "explanation": "- Workloads that have large memory requirements: Los almacenes virtuales optimizados para Snowpark están diseñados para manejar cargas de trabajo que requieren grandes cantidades de memoria, lo que les permite procesar datos complejos de manera más eficiente.\n- Workloads with ad hoc analytics: Aunque Snowpark puede manejar análisis ad hoc, este no es el caso específico recomendado para almacenes optimizados para Snowpark.\n- Workloads with unpredictable data volumes for each query: La variabilidad en los volúmenes de datos no es un punto fuerte específico de los almacenes optimizados para Snowpark.\n- Workloads that are queried with small table scans and selective filters: Las consultas con pequeñas exploraciones de tablas y filtros selectivos no son el enfoque principal para estos almacenes optimizados.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-snowpark-optimized#when-to-use-a-snowpark-optimized-warehouse"}, {"id": 1118, "area": "Data Loading and Unloading", "question": "What is the benefit of using the STRIP_OUTER_ARRAY parameter with the COPY INTO [table] command when loading data from a JSON file into a table?", "options": ["A) It flattens multiple arrays into a single array.", "B) It removes the outer array structure and loads separate rows of data.", "C) It transforms a pivoted table into an array.", "D) It tokenizes each data string using the defined delimiters."], "chooseN": 1, "correct": ["It removes the outer array structure and loads separate rows of data."], "explanation": "- It removes the outer array structure and loads separate rows of data.: El parámetro `STRIP_OUTER_ARRAY` se utiliza para eliminar la estructura del array externo en un archivo JSON, permitiendo que los datos se carguen como filas separadas en la tabla.\n- It flattens multiple arrays into a single array.: Este parámetro no se encarga de aplanar arrays múltiples.\n- It transforms a pivoted table into an array.: La transformación de una tabla pivotada a un array no es una función del parámetro `STRIP_OUTER_ARRAY`.\n- It tokenizes each data string using the defined delimiters.: La tokenización de cadenas de datos con delimitadores no está relacionada con el parámetro `STRIP_OUTER_ARRAY`.", "reference": "https://docs.snowflake.com/en/sql-reference/copy-into-table#parameters"}, {"id": 1119, "area": "Performance Concepts", "question": "A query containing a WHERE clause is running longer than expected. The Query Profile shows that all micro-partitions are being scanned. How should this query be optimized?", "options": ["A) Create a view on the table.", "B) Add a clustering key to the table.", "C) Add a LIMIT clause to the query.", "D) Add a Dynamic Data Masking policy to the table."], "chooseN": 1, "correct": ["Add a clustering key to the table."], "explanation": "- Add a clustering key to the table.: Agregar una 'clustering key' mejora el rendimiento de las consultas al reducir la cantidad de micro-particiones que se deben escanear, ya que organiza los datos de manera más eficiente según las columnas de la clave de clustering.\n- Create a view on the table.: Crear una vista no optimiza el escaneo de micro-particiones y no afecta directamente al rendimiento de la consulta.\n- Add a LIMIT clause to the query.: Agregar una cláusula LIMIT solo restringe la cantidad de resultados devueltos, pero no mejora el rendimiento del escaneo de micro-particiones.\n- Add a Dynamic Data Masking policy to the table.: La política de enmascaramiento dinámico de datos no afecta el rendimiento de la consulta ni el escaneo de micro-particiones.", "reference": "https://docs.snowflake.com/en/user-guide/querying-clustering-keys.html"}, {"id": 1120, "area": "Account Access and Security", "question": "Which access control entity in Snowflake can be created as part of a hierarchy within an account?", "options": ["A) Securable object", "B) Role", "C) Privilege", "D) User"], "chooseN": 1, "correct": ["Role"], "explanation": "- Role: Snowflake allows the creation of roles as part of a hierarchy within an account. Roles can inherit permissions from other roles, making them the correct access control entity to be used in a hierarchical structure.\n- Securable object: Securable objects are resources to which access is granted, not an entity that manages or is part of an access control hierarchy.\n- Privilege: Privileges are specific actions that can be performed on securable objects, but they are assigned to roles, not organized hierarchically.\n- User: Users are individual entities with access to Snowflake, but they are not part of a hierarchical structure for access control.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-overview.html"}, {"id": 1121, "area": "Account Access and Security", "question": "When an object is created in Snowflake, who owns the object?", "options": ["A) The public role", "B) The user's default role", "C) The current active primary role", "D) The owner of the parent schema"], "chooseN": 1, "correct": ["The current active primary role"], "explanation": "- The current active primary role: Cuando se crea un objeto en Snowflake, la propiedad recae sobre el rol activo principal actual en la sesión del usuario. Este rol es el que tiene la autoridad de propiedad sobre el nuevo objeto.\n- The public role: El rol público tiene permisos mínimos y no se le otorga propiedad de nuevos objetos.\n- The user's default role: Aunque el rol predeterminado del usuario puede tener permisos, no es necesariamente el rol que posee el objeto, ya que la propiedad la asume el rol activo actual.\n- The owner of the parent schema: El propietario del esquema principal tiene control sobre los objetos dentro del esquema, pero no posee automáticamente nuevos objetos creados.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-privileges.html#role-ownership"}, {"id": 1122, "area": "Account Access and Security", "question": "What is the MINIMUM Snowflake edition that must be used in order to see the ACCESS_HISTORY view?", "options": ["A) Standard", "B) Enterprise", "C) Business Critical", "D) Virtual Private Snowflake (VPS)"], "chooseN": 1, "correct": ["Enterprise"], "explanation": "- Enterprise: La vista **ACCESS_HISTORY** está disponible en la edición Enterprise de Snowflake y superiores. Esta vista permite a los usuarios revisar detalles sobre los accesos a objetos y la actividad de consulta, lo que es crucial para la gestión avanzada de seguridad y auditoría.\n- Standard: La edición Standard no proporciona acceso a la vista ACCESS_HISTORY, ya que esta característica es parte de las funcionalidades avanzadas ofrecidas a partir de la edición Enterprise.\n- Business Critical: Aunque Business Critical incluye acceso a la vista ACCESS_HISTORY, no es la edición mínima, ya que Enterprise también lo permite.\n- Virtual Private Snowflake (VPS): VPS incluye características adicionales de seguridad, pero no es la edición mínima requerida para acceder a esta vista.", "reference": "https://docs.snowflake.com/en/user-guide/data-access-history.html"}, {"id": 1123, "area": "Account Access and Security", "question": "Which role is responsible for managing the billing and credit data within Snowflake?", "options": ["A) ORGADMIN", "B) ACCOUNTADMIN", "C) SYSADMIN", "D) SECURITYADMIN"], "chooseN": 1, "correct": ["ACCOUNTADMIN"], "explanation": "- ACCOUNTADMIN: El rol **ACCOUNTADMIN** es el responsable de gestionar los datos de facturación y crédito en Snowflake. Es el rol más alto en la jerarquía y tiene acceso a la gestión de todo el entorno de la cuenta.\n- ORGADMIN: Este rol está más relacionado con la gestión de varias cuentas, pero no con la administración directa de los datos de facturación en una cuenta.\n- SYSADMIN: El rol **SYSADMIN** gestiona principalmente objetos como warehouses y bases de datos, pero no la facturación.\n- SECURITYADMIN: **SECURITYADMIN** gestiona los privilegios de seguridad, pero no tiene control sobre los datos de facturación.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-considerations"}, {"id": 1124, "area": "Data Loading and Unloading", "question": "What can be used to identify the database, schema, stage, and file path to a set of files, and to allow a role that has sufficient privileges on the stage to access the files?", "options": ["A) A scoped URL", "B) A file URL", "C) A pre-signed URL", "D) A directory table"], "chooseN": 1, "correct": ["A file URL"], "explanation": "- A file URL: Un **file URL** identifica la base de datos, esquema, stage y la ruta de los archivos. Proporciona un enlace permanente que requiere un rol con privilegios suficientes sobre el stage (USAGE para external stages, READ para internal stages) para acceder a los archivos.\n- A scoped URL: Proporciona acceso temporal (24h) codificando la ubicacion del archivo, pero esta asociado a un usuario especifico y un resultado de consulta.\n- A pre-signed URL: Genera una URL HTTPS temporal accesible sin autenticacion de Snowflake. No requiere privilegios sobre el stage y es ideal para compartir publico, pero no identifica la estructura database/schema/stage.\n- A directory table: Las directory tables listan archivos en un stage pero no proporcionan URLs de acceso directo.", "reference": "https://docs.snowflake.com/en/user-guide/unstructured-intro"}, {"id": 1125, "area": "Data Loading and Unloading", "question": "Which command is used to remove files from either external cloud storage or an internal stage?", "options": ["A) DELETE", "B) REMOVE", "C) TRUNCATE", "D) DROP"], "chooseN": 1, "correct": ["REMOVE"], "explanation": "- REMOVE: El comando **REMOVE** en Snowflake se usa específicamente para eliminar archivos de un almacenamiento en la nube externo o de un stage interno. Esto es correcto para la gestión de archivos en stages.\n- DELETE: El comando **DELETE** es usado para eliminar filas de una tabla, no para manejar archivos en un stage.\n- TRUNCATE: El comando **TRUNCATE** elimina todas las filas de una tabla, pero no es aplicable para eliminar archivos en stages.\n- DROP: **DROP** elimina objetos como tablas o esquemas, pero no se utiliza para archivos en stages.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/remove.html"}, {"id": 1126, "area": "Performance Concepts", "question": "How does Snowflake recommend defining a clustering key on a high-cardinality column that includes a 15 digit ID numbered column, ID_NUMBER?", "options": ["A) TRUNC(ID_NUMBER, -6)", "B) TRUNC(ID_NUMBER, 5)", "C) ID_NUMBER*100", "D) TO_CHAR(ID_NUMBER)"], "chooseN": 1, "correct": ["TRUNC(ID_NUMBER, -6)"], "explanation": "- TRUNC(ID_NUMBER, -6): Snowflake recomienda truncar un número de alta cardinalidad, como un ID de 15 dígitos, a los 6 dígitos más significativos. Esto ayuda a mejorar la eficiencia de las consultas al reducir la granularidad del clustering y agrupar los datos de manera más uniforme.\n- TRUNC(ID_NUMBER, 5): Truncar el ID en este valor no sería eficiente, ya que no refleja la granularidad adecuada para mejorar el rendimiento.\n- ID_NUMBER*100: Multiplicar el ID no es una práctica recomendada para el clustering en Snowflake y podría aumentar la cardinalidad.\n- TO_CHAR(ID_NUMBER): Convertir el ID a una cadena de texto no ayuda a mejorar el clustering y puede empeorar el rendimiento de las consultas.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-keys.html#choosing-clustering-keys"}, {"id": 1127, "area": "Data Loading and Unloading", "question": "While unloading data into a stage, how can the user ensure that the output will be a single file?", "options": ["A) Use the COPY option FILES=SINGLE.", "B) Use the COPY option SINGLE=TRUE.", "C) Use the GET option SINGLE=TRUE.", "D) Use the GET option FILES=SINGLE."], "chooseN": 1, "correct": ["Use the COPY option SINGLE=TRUE."], "explanation": "- Use the COPY option SINGLE=TRUE.: Para garantizar que la salida sea un solo archivo al descargar datos en un stage, se debe usar la opción COPY con **SINGLE=TRUE**. Esto permite a Snowflake consolidar todos los datos en un solo archivo, en lugar de generar varios archivos.\n- Use the COPY option FILES=SINGLE.: Esta opción no es válida en Snowflake. **FILES=SINGLE** no es un parámetro reconocido en el contexto de la descarga de datos.\n- Use the GET option SINGLE=TRUE.: El comando **GET** se utiliza para copiar datos desde un stage a un cliente local, no para controlar la cantidad de archivos al descargar datos en un stage.\n- Use the GET option FILES=SINGLE.: De manera similar, esta opción no es válida porque el comando GET no controla cómo se descargan los archivos en un stage.", "reference": "https://docs.snowflake.com/en/user-guide/data-unload-considerations.html"}, {"id": 1128, "area": "Performance Concepts", "question": "Which query types will have significant performance improvement when run using the search optimization service? (Choose two.)", "options": ["A) Range searches", "B) Equality searches", "C) Substring searches", "D) Queries with IN predicates", "E) Queries with aggregation"], "chooseN": 2, "correct": ["Equality searches", "Queries with IN predicates"], "explanation": "- Equality searches: Las consultas que utilizan búsquedas de igualdad se benefician significativamente del servicio de optimización de búsqueda en Snowflake, ya que este servicio está diseñado específicamente para acelerar las consultas que buscan valores exactos.\n- Queries with IN predicates: Las consultas que utilizan predicados **IN** también muestran una mejora en el rendimiento al emplear el servicio de optimización de búsqueda, ya que este servicio optimiza la búsqueda de múltiples valores específicos dentro de un conjunto de resultados.\n- Range searches: Aunque las búsquedas por rango pueden beneficiarse de otras optimizaciones, no están diseñadas para aprovechar el servicio de optimización de búsqueda de manera significativa.\n- Substring searches: Las búsquedas de subcadenas no se optimizan utilizando este servicio, ya que no se enfocan en la igualdad o los predicados **IN**.\n- Queries with aggregation: Las consultas de agregación no están dentro de los tipos que el servicio de optimización de búsqueda acelera específicamente.", "reference": "https://docs.snowflake.com/en/user-guide/search-optimization/point-lookup-queries"}, {"id": 1129, "area": "Performance Concepts", "question": "Which Query Profile operator is considered a DML operator?", "options": ["A) ExternalScan", "B) Flatten", "C) Merge", "D) Sort"], "chooseN": 1, "correct": ["Merge"], "explanation": "- Merge: El operador **Merge** es un operador DML (Data Manipulation Language) que combina los resultados de una operación de selección con la actualización o inserción de datos en una tabla existente. Este tipo de operador es comúnmente utilizado en operaciones DML como **INSERT**, **UPDATE**, **DELETE** y **MERGE** en Snowflake.\n- ExternalScan: Este operador no está relacionado con las operaciones DML. Se utiliza para leer datos de fuentes externas.\n- Flatten: El operador **Flatten** se usa para expandir datos anidados, no es un operador DML.\n- Sort: El operador **Sort** organiza los datos, pero no manipula ni modifica los datos existentes, por lo tanto, no es un operador DML.", "reference": "https://docs.snowflake.com/en/user-guide/querying-dml.html"}, {"id": 1130, "area": "Data Protection and Data Sharing", "question": "Masking policies are created at what level in Snowflake?", "options": ["A) Table", "B) Column", "C) Schema", "D) Database"], "chooseN": 1, "correct": ["Column"], "explanation": "- Column: Las políticas de enmascaramiento en Snowflake se crean a nivel de columna. Estas políticas se aplican directamente a las columnas para controlar qué datos son visibles para los usuarios con diferentes niveles de privilegio.\n- Table: No se pueden crear políticas de enmascaramiento a nivel de tabla; siempre se deben definir a nivel de columna individual.\n- Schema: Aunque las políticas pueden estar asociadas a esquemas, su aplicación directa es a nivel de columna, no de esquema completo.\n- Database: Las políticas de enmascaramiento no se definen a nivel de base de datos; están asociadas a columnas dentro de tablas.", "reference": "https://docs.snowflake.com/en/user-guide/security-column-level-security-masking.html"}, {"id": 1131, "area": "Performance Concepts", "question": "What would cause different results to be returned when running the same query twice?", "options": ["A) SAMPLE is used and the seed is set.", "B) SAMPLE is used and the seed is not set.", "C) Fraction-based sampling is used.", "D) Fixed-size sampling is used."], "chooseN": 1, "correct": ["SAMPLE is used and the seed is not set."], "explanation": "- SAMPLE is used and the seed is not set.: Cuando se utiliza la cláusula **SAMPLE** sin un valor de semilla, Snowflake selecciona aleatoriamente un subconjunto de filas, lo que puede provocar resultados diferentes cada vez que se ejecuta la consulta.\n- SAMPLE is used and the seed is set.: Si se especifica un valor de semilla con **SAMPLE**, los mismos resultados se devolverán en ejecuciones repetidas, ya que la semilla asegura que el muestreo sea determinista.\n- Fraction-based sampling is used.: Aunque el muestreo basado en fracciones selecciona un porcentaje de filas, no necesariamente genera diferentes resultados a menos que la semilla no esté establecida.\n- Fixed-size sampling is used.: El muestreo de tamaño fijo selecciona un número fijo de filas, pero el uso de una semilla haría que los resultados fueran consistentes entre ejecuciones.", "reference": "https://docs.snowflake.com/en/sql-reference/constructs/sample.html"}, {"id": 1132, "area": "Data Transformations", "question": "What are type predicates used for?", "options": ["A) Extracting data from a VARIANT column", "B) Casting a value in a VARIANT column to a particular data type", "C) Determining if a value in a VARIANT column is a particular data type", "D) Manipulating objects and arrays in a VARIANT column"], "chooseN": 1, "correct": ["Determining if a value in a VARIANT column is a particular data type"], "explanation": "- Determining if a value in a VARIANT column is a particular data type: Los predicados de tipo en Snowflake se utilizan para determinar si un valor en una columna **VARIANT** tiene un tipo de dato específico, como **IS_INTEGER**, **IS_STRING**, etc. Esto permite a los usuarios verificar el tipo de los datos antes de proceder con la manipulación o conversión.\n- Extracting data from a VARIANT column: La extracción de datos de una columna VARIANT se realiza mediante funciones como **GET** o **SELECT**, no mediante predicados de tipo.\n- Casting a value in a VARIANT column to a particular data type: El casting de valores en una columna VARIANT se realiza con la función **CAST**, no con predicados de tipo.\n- Manipulating objects and arrays in a VARIANT column: Para manipular objetos y arreglos en una columna VARIANT, se utilizan funciones como **ARRAY_AGG**, no predicados de tipo.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/type-predicate-functions.html"}, {"id": 1133, "area": "Performance Concepts", "question": "Which table function is used to perform additional processing on the results of a previously-run query?", "options": ["A) QUERY_HISTORY", "B) RESULT_SCAN", "C) DESCRIBE_RESULTS", "D) QUERY_HISTORY_BY_SESSION"], "chooseN": 1, "correct": ["RESULT_SCAN"], "explanation": "- RESULT_SCAN: La función **RESULT_SCAN** se utiliza para acceder y procesar los resultados de una consulta previamente ejecutada en Snowflake. Esta función toma un identificador de consulta y permite volver a usar el resultado para procesamiento adicional sin volver a ejecutar la consulta original.\n- QUERY_HISTORY: **QUERY_HISTORY** proporciona un registro de las consultas ejecutadas, pero no permite acceder a los resultados de las mismas.\n- DESCRIBE_RESULTS: Esta función se utiliza para describir los metadatos de los resultados, pero no permite procesar los resultados de una consulta previa.\n- QUERY_HISTORY_BY_SESSION: Similar a **QUERY_HISTORY**, esta función muestra el historial de consultas para una sesión específica, pero no permite acceder a los resultados de consultas anteriores.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/result_scan.html"}, {"id": 1134, "area": "Account Access and Security", "question": "Which actions can be performed using a resource monitor in Snowflake? (Choose two.)", "options": ["A) Monitor the performance of individual queries in real-time.", "B) Automatically allocate more storage space to a virtual warehouse.", "C) Modify the queries being executed within a virtual warehouse.", "D) Suspend a virtual warehouse when its credit usage reaches a defined limit.", "E) Trigger a notification to account administrators when credit usage reaches a specified threshold."], "chooseN": 2, "correct": ["Suspend a virtual warehouse when its credit usage reaches a defined limit.", "Trigger a notification to account administrators when credit usage reaches a specified threshold."], "explanation": "- Suspend a virtual warehouse when its credit usage reaches a defined limit.: Los monitores de recursos en Snowflake se utilizan para controlar el uso de créditos. Una de sus funciones principales es suspender automáticamente un almacén virtual cuando su uso de créditos alcanza un límite definido, ayudando a evitar sobrecostos.\n- Trigger a notification to account administrators when credit usage reaches a specified threshold.: Los monitores de recursos también pueden configurar alertas que notifiquen a los administradores de cuentas cuando el uso de créditos alcanza un umbral predefinido, permitiendo así una gestión proactiva del consumo.\n- Monitor the performance of individual queries in real-time.: Los monitores de recursos no se utilizan para monitorear el rendimiento de consultas individuales en tiempo real; esta funcionalidad es parte de las herramientas de monitoreo de consultas.\n- Automatically allocate more storage space to a virtual warehouse.: Un monitor de recursos no asigna automáticamente más espacio de almacenamiento. El almacenamiento es administrado de manera separada y no se controla mediante monitores de recursos.\n- Modify the queries being executed within a virtual warehouse.: Los monitores de recursos no modifican las consultas que se ejecutan en un almacén virtual; su función principal es monitorear y gestionar el uso de créditos.", "reference": "https://docs.snowflake.com/en/user-guide/resource-monitors.html"}, {"id": 1135, "area": "Account Access and Security", "question": "Which Snowflake native tool can be used to diagnose and troubleshoot network connections?", "options": ["A) SnowSQL", "B) Snowflake Python connector", "C) Snowsight", "D) SnowCD"], "chooseN": 1, "correct": ["SnowCD"], "explanation": "- SnowCD: **SnowCD** (Snowflake Connectivity Diagnostic Tool) es la herramienta nativa de Snowflake disenada especificamente para diagnosticar problemas de conectividad de red. Verifica la accesibilidad a las URLs de Snowflake y diagnostica problemas de conexion.\n- SnowSQL: **SnowSQL** es una herramienta CLI para ejecutar consultas SQL en Snowflake, no para diagnosticar conectividad de red.\n- Snowflake Python connector: Este conector se utiliza para conectar aplicaciones Python a Snowflake, pero no es una herramienta de diagnostico de red.\n- Snowsight: **Snowsight** es la interfaz web de Snowflake para el analisis de datos y no se utiliza para diagnosticar problemas de conectividad de red.", "reference": "https://docs.snowflake.com/en/user-guide/client-connectivity-troubleshooting/snowflake-tools"}, {"id": 1136, "area": "Data Transformations", "question": "Why would a Snowflake user load JSON data into a VARIANT column instead of a string column?", "options": ["A) A VARIANT column is more secure than a string column.", "B) A VARIANT column compresses data and a string column does not.", "C) A VARIANT column can be used to create a data hierarchy and a string column cannot.", "D) A VARIANT column will have a better query performance than a string column."], "chooseN": 1, "correct": ["A VARIANT column can be used to create a data hierarchy and a string column cannot."], "explanation": "- A VARIANT column can be used to create a data hierarchy and a string column cannot.: Los datos JSON se pueden almacenar en una columna **VARIANT** debido a que este tipo de columna puede mantener la estructura jerárquica de los datos, permitiendo consultas flexibles y eficientes sobre los datos semiestructurados. Una columna de tipo **string** simplemente almacenaría los datos JSON como una cadena, sin la capacidad de reconocer y manejar esa jerarquía.\n- A VARIANT column is more secure than a string column.: La seguridad de las columnas VARIANT y string no difiere significativamente; la diferencia principal radica en cómo los datos son manejados y consultados.\n- A VARIANT column compresses data and a string column does not.: Aunque Snowflake aplica compresión en todos los tipos de datos, la compresión no es la razón principal para usar una columna VARIANT en lugar de una string.\n- A VARIANT column will have a better query performance than a string column.: Las columnas VARIANT no necesariamente ofrecen un rendimiento de consulta superior en todos los casos, pero permiten consultas más eficientes sobre datos semiestructurados debido a la flexibilidad de su formato.", "reference": "https://docs.snowflake.com/en/sql-reference/data-types-variant.html"}, {"id": 1137, "area": "Data Loading and Unloading", "question": "How can a 5 GB table be downloaded into a single file MOST efficiently?", "options": ["A) Keep the default MAX_FILE_SIZE to 16 MB.", "B) Set the default MAX_FILE_SIZE to 5 GB.", "C) Set the SINGLE parameter to TRUE.", "D) Use a regular expression in the stage specifications of the COPY command."], "chooseN": 1, "correct": ["Set the SINGLE parameter to TRUE."], "explanation": "- Set the SINGLE parameter to TRUE.: El parámetro **SINGLE=TRUE** en Snowflake garantiza que los datos se descarguen en un solo archivo, lo que es eficiente cuando se necesita un solo archivo para una tabla de 5 GB. Esto es especialmente útil en operaciones de exportación.\n- Keep the default MAX_FILE_SIZE to 16 MB.: El tamaño predeterminado de archivo de 16 MB no es eficiente para descargar grandes tablas en un solo archivo, ya que dividiría la tabla en muchos archivos pequeños.\n- Set the default MAX_FILE_SIZE to 5 GB.: Aunque esto ajusta el tamaño máximo del archivo, no garantiza que los datos se descarguen en un solo archivo, ya que este ajuste no tiene la misma función que el parámetro **SINGLE**.\n- Use a regular expression in the stage specifications of the COPY command.: Las expresiones regulares se utilizan para filtrar archivos o datos, no para controlar el tamaño o número de archivos durante una exportación.", "reference": "https://docs.snowflake.com/en/user-guide/data-unload-considerations.html"}, {"id": 1138, "area": "Account Access and Security", "question": "Which security models are used in Snowflake to manage access control? (Choose two.)", "options": ["A) Discretionary Access Control (DAC)", "B) Identity Access Management (IAM)", "C) Mandatory Access Control (MAC)", "D) Role-Based Access Control (RBAC)", "E) Security Assertion Markup Language (SAML)"], "chooseN": 2, "correct": ["Discretionary Access Control (DAC)", "Role-Based Access Control (RBAC)"], "explanation": "- Discretionary Access Control (DAC): En Snowflake, el modelo de **Discretionary Access Control (DAC)** se usa para que los propietarios de los objetos decidan quién puede acceder a los mismos. Este enfoque permite a los usuarios asignar permisos de manera discrecional.\n- Role-Based Access Control (RBAC): Snowflake implementa ampliamente **Role-Based Access Control (RBAC)**, donde el acceso y los permisos se asignan en función de roles, y los usuarios heredan permisos de estos roles.\n- Identity Access Management (IAM): Aunque IAM es un modelo común en muchas plataformas en la nube, no es el modelo principal de control de acceso utilizado en Snowflake. Snowflake integra IAM para autenticación, pero el control de acceso se gestiona principalmente con RBAC y DAC.\n- Mandatory Access Control (MAC): **MAC** es un modelo de seguridad estricto utilizado en sistemas de alta seguridad, pero no es el enfoque de Snowflake, que se basa más en RBAC y DAC.\n- Security Assertion Markup Language (SAML): **SAML** es un protocolo utilizado para la autenticación y federación de identidad, no es un modelo de control de acceso utilizado directamente en Snowflake.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-overview.html, https://docs.snowflake.com/en/user-guide/security-access-control.html"}, {"id": 1139, "area": "Data Protection and Data Sharing", "question": "Which Snowflake governance feature allows users to assign metadata labels to improve data governance and database access control?", "options": ["A) Secure functions", "B) Secure views", "C) Object tagging", "D) Row-level security"], "chooseN": 1, "correct": ["Object tagging"], "explanation": "- Object tagging: La característica de **Object tagging** en Snowflake permite a los usuarios asignar etiquetas de metadatos a objetos como tablas, vistas y esquemas. Esto mejora la gobernanza de datos y facilita el control de acceso a nivel de base de datos al proporcionar visibilidad y organización de los datos mediante etiquetas personalizadas.\n- Secure functions: Las **Secure functions** se utilizan para proteger la lógica dentro de funciones definidas por el usuario, pero no son directamente relacionadas con la gobernanza a través de etiquetas de metadatos.\n- Secure views: Las **Secure views** limitan el acceso a los datos subyacentes, pero no gestionan la gobernanza a través de etiquetas de metadatos.\n- Row-level security: La **Row-level security** proporciona control de acceso basado en filas dentro de una tabla, pero no está relacionada con el etiquetado de objetos para gobernanza de datos.", "reference": "https://docs.snowflake.com/en/user-guide/object-tagging"}, {"id": 1140, "area": "Data Protection and Data Sharing", "question": "What is the MINIMUM Snowflake edition that supports database replication?", "options": ["A) Standard", "B) Enterprise", "C) Business Critical", "D) Virtual Private Snowflake (VPS)"], "chooseN": 1, "correct": ["Standard"], "explanation": "Database replication in Snowflake is available in all editions, including Standard Edition. This allows replicating databases across multiple accounts, including across different regions and cloud platforms. However, failover and failback capabilities for business continuity and disaster recovery require the Business Critical Edition or higher.", "reference": "https://docs.snowflake.com/en/user-guide/db-replication-intro"}, {"id": 1141, "area": "Data Loading and Unloading", "question": "Which Snowflake function and command combination should be used to convert rows in a relational table to a single VARIANT column, and unload the rows into a file in JSON format? (Choose two.)", "options": ["A) PUT", "B) GET", "C) COPY", "D) EXPORT", "E) OBJECT_CONSTRUCT"], "chooseN": 2, "correct": ["COPY", "OBJECT_CONSTRUCT"], "explanation": "- COPY: El comando **COPY** se utiliza para exportar datos desde Snowflake a archivos externos. En este caso, se usa para descargar los datos en un archivo en formato JSON.\n- OBJECT_CONSTRUCT: La función **OBJECT_CONSTRUCT** convierte filas de una tabla relacional en un solo valor de tipo **VARIANT**, lo que permite que las filas se representen en formato JSON.\n- PUT: El comando **PUT** se usa para cargar archivos desde el sistema local a un stage en Snowflake, no para descargar datos.\n- GET: El comando **GET** se utiliza para descargar archivos desde un stage a un sistema local, pero no está relacionado con la conversión de filas a formato VARIANT o JSON.\n- EXPORT: **EXPORT** no es un comando utilizado en Snowflake. El comando correcto para descargar datos es **COPY**.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/object_construct.html, https://docs.snowflake.com/en/sql-reference/sql/copy-into-location.html"}, {"id": 1142, "area": "Data Loading and Unloading", "question": "What Snowflake recommendation is designed to ensure that staged data is only loaded once?", "options": ["A) Partitioning staged data files", "B) Loading only the most recently-staged data files", "C) Removing data files after loading", "D) Identifying and removing duplicates after each data load"], "chooseN": 1, "correct": ["Removing data files after loading"], "explanation": "- Removing data files after loading: Snowflake recomienda eliminar los archivos de datos del stage después de cargarlos exitosamente, para asegurar que los datos no se carguen más de una vez. Esto previene la duplicación durante futuras cargas de datos.\n- Partitioning staged data files: La partición de archivos de datos en el stage no garantiza que los datos se carguen solo una vez; es más una estrategia de rendimiento.\n- Loading only the most recently-staged data files: Cargar solo los archivos más recientes puede no prevenir la duplicación si los archivos anteriores no se eliminan.\n- Identifying and removing duplicates after each data load: Aunque la identificación y eliminación de duplicados es útil, no es una recomendación principal para evitar que los datos se carguen más de una vez. La eliminación de archivos después de la carga es más eficiente.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-considerations.html#ensuring-that-data-is-loaded-once"}, {"id": 1143, "area": "Account Access and Security", "question": "Which privilege grants the ability to set a column-level security masking policy on a table or view column?", "options": ["A) APPLY", "B) CREATE", "C) SET", "D) MODIFY"], "chooseN": 1, "correct": ["APPLY"], "explanation": "- APPLY: El privilegio **APPLY** es el que se utiliza para asignar políticas de enmascaramiento de seguridad a nivel de columna en Snowflake. Este privilegio permite al usuario aplicar una política de enmascaramiento en columnas de tablas o vistas.\n- CREATE: El privilegio **CREATE** permite crear objetos en Snowflake, pero no se utiliza para asignar políticas de enmascaramiento a columnas.\n- SET: **SET** no es un privilegio válido para aplicar políticas de enmascaramiento de datos en Snowflake.\n- MODIFY: El privilegio **MODIFY** permite modificar datos en una tabla, pero no está relacionado con la aplicación de políticas de enmascaramiento.", "reference": "https://docs.snowflake.com/en/user-guide/security-column-level-security-masking.html"}, {"id": 1144, "area": "Data Protection and Data Sharing", "question": "When sharing data in Snowflake, what privileges does a Provider need to grant along with a share? (Choose two.)", "options": ["A) USAGE on the specific tables in the database.", "B) MODIFY on the specific tables in the database.", "C) SELECT on the specific tables in the database.", "D) USAGE on the database and the schema containing the tables to share.", "E) OPERATE on the database and the schema containing the tables to share."], "chooseN": 2, "correct": ["SELECT on the specific tables in the database.", "USAGE on the database and the schema containing the tables to share."], "explanation": "- SELECT on the specific tables in the database.: El privilegio **SELECT** permite que los consumidores de datos accedan y consulten las tablas compartidas. Este es uno de los privilegios clave necesarios para compartir datos en Snowflake.\n- USAGE on the database and the schema containing the tables to share.: El privilegio **USAGE** debe otorgarse tanto a la base de datos como al esquema que contiene las tablas compartidas, lo que permite a los consumidores de datos acceder a estos objetos.\n- USAGE on the specific tables in the database.: El privilegio **USAGE** se otorga a la base de datos y el esquema, no a las tablas individuales.\n- MODIFY on the specific tables in the database.: El privilegio **MODIFY** no es necesario para compartir datos, ya que los consumidores de datos no necesitan modificar las tablas compartidas.\n- OPERATE on the database and the schema containing the tables to share.: El privilegio **OPERATE** no está relacionado con el acceso o la consulta de datos compartidos.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-intro.html"}, {"id": 1145, "area": "Performance Concepts", "question": "How can the Query Profile be used to troubleshoot a problematic query?", "options": ["A) It will indicate if a virtual warehouse memory is too small to run the query.", "B) It will indicate if a user lacks the privileges needed to run the query.", "C) It will indicate if a virtual warehouse is in auto-scale mode.", "D) It will indicate if the user has enough Snowflake credits to run the query."], "chooseN": 1, "correct": ["It will indicate if a virtual warehouse memory is too small to run the query."], "explanation": "- It will indicate if a virtual warehouse memory is too small to run the query.: El **Query Profile** en Snowflake proporciona detalles sobre el uso de recursos durante la ejecución de una consulta. Si la memoria del almacén virtual es insuficiente, el perfil de la consulta mostrará información sobre la falta de recursos, lo que puede ayudar a identificar la causa de un rendimiento lento o fallos en la consulta.\n- It will indicate if a user lacks the privileges needed to run the query.: El perfil de consulta no muestra problemas relacionados con permisos de usuario; los errores de privilegios se notifican de manera diferente en Snowflake.\n- It will indicate if a virtual warehouse is in auto-scale mode.: El perfil de consulta no indica si el almacén virtual está en modo de autoescalado. Esto se gestiona desde la configuración del almacén.\n- It will indicate if the user has enough Snowflake credits to run the query.: Los créditos de Snowflake disponibles no se muestran en el perfil de consulta. La falta de créditos impide la ejecución de consultas, pero no se refleja en el perfil.", "reference": "https://docs.snowflake.com/en/user-guide-ui-query-profile.html"}, {"id": 1146, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which data type can be used for floating-point numbers without losing precision?", "options": ["A) BINARY", "B) VARIANT", "C) INTEGER", "D) DOUBLE"], "chooseN": 1, "correct": ["DOUBLE"], "explanation": "- DOUBLE: El tipo de datos **DOUBLE** se utiliza en Snowflake para representar números de punto flotante con alta precisión. Snowflake implementa este tipo de datos con doble precisión, lo que permite trabajar con decimales sin perder precisión significativa en los cálculos.\n- BINARY: El tipo **BINARY** se utiliza para almacenar datos binarios en Snowflake, no es adecuado para números de punto flotante.\n- VARIANT: Aunque **VARIANT** puede almacenar números de punto flotante, no es un tipo de datos específicamente diseñado para manejar estos números con alta precisión.\n- INTEGER: **INTEGER** se utiliza para representar números enteros, no para números de punto flotante.", "reference": "https://docs.snowflake.com/en/sql-reference/data-types-numeric.html"}, {"id": 1147, "area": "Data Protection and Data Sharing", "question": "Which data sharing option allows a Snowflake user to set up and manage a group of accounts and offer a share to that group?", "options": ["A) Free listing", "B) Paid listing", "C) Direct share", "D) Data Exchange"], "chooseN": 1, "correct": ["Data Exchange"], "explanation": "- Data Exchange: La opción de **Data Exchange** en Snowflake permite a los usuarios establecer y gestionar un grupo de cuentas para compartir datos dentro de una comunidad gestionada. Esto facilita la distribución de datos a varios consumidores dentro de un marco controlado.\n- Free listing: El **Free listing** se refiere a la opción de compartir datos públicamente de forma gratuita, pero no implica la gestión de un grupo de cuentas como lo hace el **Data Exchange**.\n- Paid listing: El **Paid listing** permite la venta de datos a través del marketplace de Snowflake, pero no ofrece la gestión de un grupo de cuentas como el **Data Exchange**.\n- Direct share: **Direct share** permite compartir datos directamente con una cuenta, pero no con un grupo de cuentas, lo cual es posible con **Data Exchange**.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-intro.html"}, {"id": 1148, "area": "Data Loading and Unloading", "question": "What kind of authentication do Snowpipe REST endpoints use?", "options": ["A) OAuth", "B) Key-based", "C) Username and password", "D) Single Sign-On (SSO)"], "chooseN": 1, "correct": ["Key-based"], "explanation": "- Key-based: Los endpoints REST de Snowpipe utilizan autenticación basada en claves. Snowflake emplea claves privadas para autenticar solicitudes de clientes externos a los endpoints de Snowpipe.\n- OAuth: Aunque **OAuth** es un método común de autenticación, no es el utilizado para los endpoints REST de Snowpipe.\n- Username and password: Snowpipe no utiliza autenticación basada en **username and password** para sus endpoints REST, ya que se requiere una autenticación más segura mediante claves.\n- Single Sign-On (SSO): **SSO** es un mecanismo de autenticación para acceder a aplicaciones, pero no es el método utilizado para autenticar los endpoints REST de Snowpipe.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-snowpipe-rest-apis.html#label-snowpipe-rest-auth"}, {"id": 1149, "area": "Data Transformations", "question": "What are the possible values within a METADATA$ACTION column in a Snowflake stream? (Choose two.)", "options": ["A) INSERT", "B) UPDATE", "C) DELETE", "D) TRUNCATE", "E) UPSERT"], "chooseN": 2, "correct": ["INSERT", "DELETE"], "explanation": "- INSERT: El valor **INSERT** en la columna **METADATA$ACTION** indica que una nueva fila fue insertada en la tabla monitoreada por el stream. Este valor se utiliza para rastrear cambios en los datos.\n- DELETE: El valor **DELETE** en la columna **METADATA$ACTION** se usa para indicar que una fila fue eliminada de la tabla monitoreada por el stream.\n- UPDATE: Aunque **UPDATE** parece ser un valor posible, no es directamente registrado como una acción en la columna **METADATA$ACTION**; en su lugar, las actualizaciones se manejan como eliminaciones seguidas de inserciones.\n- TRUNCATE: **TRUNCATE** no es un valor registrado en **METADATA$ACTION**; es una operación que afecta a toda la tabla y no se refleja en los streams.\n- UPSERT: **UPSERT** no es un valor válido en **METADATA$ACTION**; las operaciones de upsert se registran como combinaciones de inserciones y eliminaciones.", "reference": "https://docs.snowflake.com/en/user-guide/streams.html#metadata-columns"}, {"id": 1150, "area": "Data Protection and Data Sharing", "question": "What is the MINIMUM Snowflake edition that offers data protection for extremely sensitive data, such as Protected Health Information (PHI)?", "options": ["A) Standard", "B) Enterprise", "C) Business Critical", "D) Virtual Private Snowflake (VPS)"], "chooseN": 1, "correct": ["Business Critical"], "explanation": "- Business Critical: La edición **Business Critical** de Snowflake es la mínima que proporciona características avanzadas de seguridad, incluyendo soporte para datos altamente sensibles como la Información de Salud Protegida (PHI), cumpliendo con normativas como HIPAA.\n- Standard: La edición **Standard** no incluye los controles de seguridad avanzados necesarios para proteger datos altamente sensibles como PHI.\n- Enterprise: Aunque la edición **Enterprise** ofrece ciertas mejoras de seguridad en comparación con la edición **Standard**, no es suficiente para cumplir con los requisitos estrictos de protección de datos sensibles como PHI.\n- Virtual Private Snowflake (VPS): **VPS** es una opción aún más avanzada que **Business Critical**, pero no es la edición mínima requerida para la protección de datos sensibles.", "reference": "https://docs.snowflake.com/en/user-guide/security-intro.html"}, {"id": 1151, "area": "Data Loading and Unloading", "question": "What takes the highest precedence in Snowflake file format options, when specified in multiple locations during data loading?", "options": ["A) The stage definition", "B) The table definition", "C) The use of a COPY INTO statement"], "chooseN": 1, "correct": ["The use of a COPY INTO statement"], "explanation": "- The use of a COPY INTO statement: En Snowflake, los parámetros de formato de archivo especificados directamente en la sentencia **COPY INTO** tienen la mayor precedencia sobre los valores definidos en la etapa o la tabla. Esto permite ajustar dinámicamente cómo se cargan los datos.\n- The stage definition: Aunque los parámetros definidos en una etapa son importantes, pueden ser anulados por las configuraciones especificadas en la sentencia **COPY INTO**.\n- The table definition: La definición de la tabla no afecta los parámetros de formato de archivo en la carga de datos; se aplican los formatos definidos en la etapa o la sentencia **COPY INTO**.\n- The use of a COPY INTO statement: Aunque esta opción es correcta, se repite dos veces, y debe estar presente solo una vez como la respuesta correcta.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-considerations.html#file-format-options-precedence"}, {"id": 1152, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which service or tool is a Command Line Interface (CLI) client used for connecting to Snowflake to execute SQL queries?", "options": ["A) Snowsight", "B) SnowCD", "C) Snowpark", "D) SnowSQL"], "chooseN": 1, "correct": ["SnowSQL"], "explanation": "- SnowSQL: **SnowSQL** es el cliente de interfaz de línea de comandos (CLI) de Snowflake, utilizado para conectarse a una cuenta de Snowflake y ejecutar consultas SQL. Es una herramienta versátil para ejecutar comandos y manejar interacciones SQL con Snowflake.\n- Snowsight: **Snowsight** es la interfaz gráfica de usuario de Snowflake, no una herramienta de línea de comandos.\n- SnowCD: **SnowCD** no es un cliente de línea de comandos relacionado con Snowflake para la ejecución de consultas SQL.\n- Snowpark: **Snowpark** es una herramienta de desarrollo de Snowflake para procesar datos utilizando lenguajes como Java y Python, pero no es una interfaz de línea de comandos.", "reference": "https://docs.snowflake.com/en/user-guide/snowsql.html"}, {"id": 1153, "area": "Snowflake Data Cloud Features & Architecture", "question": "What Snowflake objects can contain custom application logic written in JavaScript? (Choose two.)", "options": ["A) Stored procedures", "B) Stages", "C) Tasks", "D) Views", "E) User-Defined Functions (UDFs)"], "chooseN": 2, "correct": ["Stored procedures", "User-Defined Functions (UDFs)"], "explanation": "- Stored procedures: Las **Stored procedures** en Snowflake pueden contener lógica personalizada escrita en JavaScript, lo que permite realizar operaciones más complejas y control de flujo dentro de la base de datos.\n- User-Defined Functions (UDFs): Las **User-Defined Functions (UDFs)** también soportan lógica personalizada escrita en JavaScript, lo que permite extender la funcionalidad de Snowflake mediante funciones definidas por el usuario.\n- Stages: Los **Stages** se utilizan para almacenar datos cargados o descargados, pero no pueden contener lógica de aplicación en JavaScript.\n- Tasks: Las **Tasks** en Snowflake son objetos utilizados para programar consultas o procedimientos almacenados, pero no contienen lógica en JavaScript directamente.\n- Views: Las **Views** solo representan una vista lógica de los datos y no soportan lógica personalizada escrita en JavaScript.", "reference": "https://docs.snowflake.com/en/sql-reference/stored-procedures-usage.html, https://docs.snowflake.com/en/sql-reference/udf-js.html"}, {"id": 1154, "area": "Account Access and Security", "question": "What is the MINIMUM Snowflake edition required to use the column-level security feature?", "options": ["A) Standard", "B) Enterprise", "C) Business Critical", "D) Virtual Private Snowflake (VPS)"], "chooseN": 1, "correct": ["Enterprise"], "explanation": "- Enterprise: La edición mínima de Snowflake que admite la seguridad a nivel de columna, incluida la aplicación de políticas de enmascaramiento, es la edición **Enterprise**. Esto proporciona características avanzadas de seguridad para proteger los datos a nivel de columna.\n- Standard: La edición **Standard** no admite seguridad a nivel de columna. Esta funcionalidad está disponible solo en ediciones superiores.\n- Business Critical: Aunque la edición **Business Critical** admite la seguridad a nivel de columna, no es la edición mínima requerida, ya que la edición **Enterprise** también proporciona esta funcionalidad.\n- Virtual Private Snowflake (VPS): **VPS** es la opción más avanzada, pero no es necesaria para usar la seguridad a nivel de columna.", "reference": "https://docs.snowflake.com/en/user-guide/security-column-level-security.html"}, {"id": 1155, "area": "Account Access and Security", "question": "Which command should be used to assign a key to a Snowflake user who needs to connect using key pair authentication?", "options": ["A) ALTER USER jsmith SET RSA_P8_KEY='MIIBIjANBgkqh...';", "B) ALTER USER jsmith SET ENCRYPTED_KEY='MIIBIjANBgkqh...';", "C) ALTER USER jsmith SET RSA_PRIVATE_KEY='MIIBIjANBgkqh...';", "D) ALTER USER jsmith SET RSA_PUBLIC_KEY='MIIBIjANBgkqh...';"], "chooseN": 1, "correct": ["ALTER USER jsmith SET RSA_PUBLIC_KEY='MIIBIjANBgkqh...';"], "explanation": "- ALTER USER jsmith SET RSA_PUBLIC_KEY='MIIBIjANBgkqh...';: Para la autenticación con pares de claves en Snowflake, se debe configurar la clave pública en la cuenta de usuario utilizando este comando. Esto permite que el usuario se autentique mediante su clave privada correspondiente.\n- ALTER USER jsmith SET RSA_P8_KEY='MIIBIjANBgkqh...';: **RSA_P8_KEY** no es una opción válida en el contexto de la configuración de autenticación basada en clave pública en Snowflake.\n- ALTER USER jsmith SET ENCRYPTED_KEY='MIIBIjANBgkqh...';: **ENCRYPTED_KEY** no es el comando adecuado para configurar la autenticación con clave pública.\n- ALTER USER jsmith SET RSA_PRIVATE_KEY='MIIBIjANBgkqh...';: Snowflake solo requiere la clave pública del usuario, no la clave privada, que nunca debe almacenarse en el sistema.", "reference": "https://docs.snowflake.com/en/user-guide/key-pair-auth.html#configuring-key-pair-authentication"}, {"id": 1156, "area": "Data Protection and Data Sharing", "question": "Secured Data Sharing is allowed for which Snowflake database objects? (Choose two.)", "options": ["A) Tables", "B) User-Defined Table Functions (UDTFs)", "C) Secure views", "D) Stored procedures", "E) Worksheets"], "chooseN": 2, "correct": ["Tables", "Secure views"], "explanation": "- Tables: Las **Tables** se pueden compartir de manera segura usando el modelo de **Secure Data Sharing** de Snowflake. Esto permite a los proveedores compartir datos sin necesidad de copiar o mover los datos subyacentes.\n- Secure views: Las **Secure views** también se pueden compartir utilizando **Secure Data Sharing**, lo que permite controlar el acceso a los datos subyacentes mientras se proporciona visibilidad controlada a los consumidores de datos.\n- User-Defined Table Functions (UDTFs): Las **UDTFs** no están habilitadas para el uso de **Secure Data Sharing**.\n- Stored procedures: Las **Stored procedures** no se pueden compartir mediante **Secure Data Sharing**.\n- Worksheets: Los **Worksheets** no son objetos de base de datos y no están cubiertos por las capacidades de **Secure Data Sharing**.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-secure.html"}, {"id": 1157, "area": "Performance Concepts", "question": "What optional properties can a Snowflake user set when creating a virtual warehouse? (Choose two.)", "options": ["A) Auto-suspend", "B) Cache size", "C) Default role", "D) Resource monitor", "E) Storage size"], "chooseN": 2, "correct": ["Auto-suspend", "Resource monitor"], "explanation": "- Auto-suspend: El parámetro **Auto-suspend** es una propiedad opcional que se puede configurar al crear un almacén virtual en Snowflake. Controla después de cuánto tiempo de inactividad el almacén debe suspenderse automáticamente, lo que ayuda a optimizar el uso de recursos y minimizar costos.\n- Resource monitor: Los usuarios pueden asignar un **Resource monitor** a un almacén virtual para controlar el uso de créditos y asegurarse de que el almacén no exceda ciertos límites de gasto.\n- Cache size: El tamaño de la caché no es una propiedad configurable directamente por el usuario en Snowflake para un almacén virtual.\n- Default role: El rol predeterminado se asigna a nivel de usuario y no es una propiedad que se configure al crear un almacén virtual.\n- Storage size: El tamaño de almacenamiento no es una propiedad opcional que se configure directamente al crear un almacén virtual, ya que los almacenes virtuales gestionan la computación, no el almacenamiento.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-using.html#modifying-warehouse-properties"}, {"id": 1158, "area": "Data Loading and Unloading", "question": "What is the purpose of the use of the VALIDATE command?", "options": ["A) To view any queries that encountered an error", "B) To verify that a SELECT query will run without error", "C) To prevent a PUT statement from running if an error occurs", "D) To see all errors from a previously run COPY INTO"], "chooseN": 1, "correct": ["To see all errors from a previously run COPY INTO"], "explanation": "- To see all errors from a previously run COPY INTO: El comando **VALIDATE** en Snowflake se utiliza para verificar y ver todos los errores de una operación **COPY INTO** que se haya ejecutado anteriormente. Esto es útil para depurar y solucionar problemas con la carga de datos.\n- To view any queries that encountered an error: El comando **VALIDATE** no se utiliza para mostrar errores de consultas generales, sino específicamente para las operaciones de carga de datos con **COPY INTO**.\n- To verify that a SELECT query will run without error: El comando **VALIDATE** no se usa para validar consultas SELECT antes de ejecutarlas.\n- To prevent a PUT statement from running if an error occurs: **VALIDATE** no está relacionado con las operaciones **PUT**; su propósito es verificar los errores en las operaciones **COPY INTO**.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/validate.html"}, {"id": 1159, "area": "Data Loading and Unloading", "question": "Which function is used to unload a relational table into a JSON file?", "options": ["A) PARSE_JSON", "B) JSON_EXTRACT_PATH_TEXT", "C) OBJECT_CONSTRUCT", "D) TO_JSON"], "chooseN": 1, "correct": ["OBJECT_CONSTRUCT"], "explanation": "- OBJECT_CONSTRUCT: The **OBJECT_CONSTRUCT** function converts rows from a relational table into VARIANT objects in JSON format. Using OBJECT_CONSTRUCT(*), each column becomes a key-value pair. It is the key function for unloading relational tables into JSON files via COPY INTO.\n- PARSE_JSON: **PARSE_JSON** parses text strings in JSON format and converts them to VARIANT, but it is not used for converting relational tables to JSON.\n- JSON_EXTRACT_PATH_TEXT: **JSON_EXTRACT_PATH_TEXT** extracts a specific value from a VARIANT/JSON column as text, but does not convert tables.\n- TO_JSON: **TO_JSON** serializes an existing VARIANT value into a JSON string, but does not convert relational rows to JSON objects.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/object_construct.html"}, {"id": 1160, "area": "Data Protection and Data Sharing", "question": "How can the ACCESS_HISTORY view in the ACCOUNT_USAGE schema be used to review the data governance settings for an account? (Choose two.)", "options": ["A) Identify queries run by a particular user.", "B) Identify access to the roles given to a user.", "C) Identify SQL statements that failed to run.", "D) Identify objects that were modified by a query.", "E) Identify object dependencies."], "chooseN": 2, "correct": ["Identify queries run by a particular user.", "Identify objects that were modified by a query."], "explanation": "- Identify queries run by a particular user: La vista ACCESS_HISTORY registra las consultas ejecutadas por usuarios especificos (query_id, query_start_time, user_name), lo cual es clave para la gobernanza de datos.\n- Identify objects that were modified by a query: ACCESS_HISTORY incluye la columna objects_modified que permite identificar que objetos fueron modificados por consultas, incluyendo operaciones DML y DDL.\n- Identify access to the roles given to a user: Esto se verifica mediante la vista GRANTS o SHOW GRANTS, no ACCESS_HISTORY.\n- Identify SQL statements that failed to run: ACCESS_HISTORY no captura consultas fallidas, solo registra consultas ejecutadas exitosamente.\n- Identify object dependencies: La dependencia de objetos se analiza mediante OBJECT_DEPENDENCIES, no ACCESS_HISTORY.", "reference": "https://docs.snowflake.com/en/user-guide/access-history.html"}, {"id": 1161, "area": "Data Loading and Unloading", "question": "Which command is used to unload data from a Snowflake table into a Snowflake stage?", "options": ["A) GET", "B) CREATE STAGE", "C) COPY INTO", "D) PUT"], "chooseN": 1, "correct": ["COPY INTO"], "explanation": "- COPY INTO: El comando 'COPY INTO' se usa para descargar datos desde una tabla de Snowflake a una etapa (stage). \n- GET**: 'GET' se utiliza para descargar archivos de un stage a un sistema local, no para descargar datos desde tablas a stages. \n- CREATE STAGE**: Este comando crea una etapa, pero no realiza la operación de descarga. \n- PUT**: 'PUT' se usa para cargar archivos en una etapa desde un sistema local, no para descargar datos.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-location.html"}, {"id": 1162, "area": "Account Access and Security", "question": "What should an account administrator do to help a user log into Snowflake, if the user cannot authenticate using Multi-Factor Authentication (MFA)?", "options": ["A) Set DISABLE_MFA to TRUE for the user.", "B) Set MINS_TO_BYPASS_MFA equal to 0 for the user.", "C) Set ALLOW_ID_TOKEN to FALSE for the user.", "D) Set ALLOW_CLIENT_MFA_CACHING to FALSE for the user."], "chooseN": 1, "correct": ["Set DISABLE_MFA to TRUE for the user."], "explanation": "- Set DISABLE_MFA to TRUE for the user: Esta opción desactiva temporalmente la autenticación de múltiples factores (MFA) para el usuario, permitiéndole iniciar sesión. \n- Set MINS_TO_BYPASS_MFA equal to 0 for the user**: Esto no soluciona el problema de autenticación del usuario. \n- Set ALLOW_ID_TOKEN to FALSE for the user**: Este parámetro está relacionado con la autenticación de tokens, no directamente con MFA. \n- Set ALLOW_CLIENT_MFA_CACHING to FALSE for the user**: Desactivar la caché de MFA no resolverá el problema de autenticación en este caso.", "reference": "https://docs.snowflake.com/en/user-guide/security-mfa.html"}, {"id": 1163, "area": "Data Protection and Data Sharing", "question": "Which command can be executed from a reader account?", "options": ["A) INSERT", "B) CREATE SHARE", "C) SHOW PROCEDURES", "D) COPY INTO"], "chooseN": 1, "correct": ["COPY INTO"], "explanation": "- COPY INTO: Los usuarios de cuentas lectoras pueden ejecutar 'COPY INTO <location>' para exportar datos desde Snowflake a un archivo. Este comando está permitido en las reader accounts.\n- INSERT: Los usuarios de cuentas lectoras no tienen permisos de escritura, por lo que no pueden insertar datos.\n- CREATE SHARE: La creación de 'shares' está limitada a cuentas no lectoras.\n- SHOW PROCEDURES: No es posible visualizar procedimientos desde una cuenta lectora.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-intro.html"}, {"id": 1164, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which command line parameter value can be pre-specified as an environment variable in SnowSQL?", "options": ["A) HOST", "B) VARIABLE", "C) OPTION", "D) MFA-PASSCODE"], "chooseN": 1, "correct": ["HOST"], "explanation": "- HOST: El valor de 'HOST' se puede predefinir como una variable de entorno en SnowSQL para especificar el host de la cuenta de Snowflake. \n- VARIABLE**: No es una opción válida como variable de entorno en este contexto. \n- OPTION**: Las opciones de línea de comandos no pueden predefinirse como variables de entorno. \n- MFA-PASSCODE**: Aunque se usa para MFA, no puede predefinirse como una variable de entorno.", "reference": "https://docs.snowflake.com/en/user-guide/snowsql-config.html"}, {"id": 1165, "area": "Data Loading and Unloading", "question": "Which command is used to determine the file name of each row of data from a staged file?", "options": ["A) SHOW FILE FORMATS", "B) SELECT METADATA$FILE_CONTENT_KEY", "C) SELECT METADATA$FILE_ROW_NUMBER", "D) SELECT METADATA$FILENAME"], "chooseN": 1, "correct": ["SELECT METADATA$FILENAME"], "explanation": "- SELECT METADATA$FILENAME: Este comando permite obtener el nombre del archivo para cada fila cargada desde un archivo en una etapa. \n- SHOW FILE FORMATS**: Solo muestra los formatos de archivos disponibles. \n- SELECT METADATA$FILE_CONTENT_KEY**: Este metadato no está relacionado con los nombres de archivos. \n- SELECT METADATA$FILE_ROW_NUMBER**: Proporciona el número de fila, pero no el nombre del archivo.", "reference": "https://docs.snowflake.com/en/user-guide/querying-metadata.html"}, {"id": 1166, "area": "Performance Concepts", "question": "Which Snowflake feature improves the performance of point lookup queries?", "options": ["A) Materialized views", "B) Automatic clustering", "C) Query acceleration service", "D) Search optimization service"], "chooseN": 1, "correct": ["Search optimization service"], "explanation": "- Search optimization service: Este servicio está diseñado específicamente para optimizar las consultas de búsqueda puntual, mejorando el rendimiento. \n- Materialized views**: Las vistas materializadas optimizan las consultas precomputadas, pero no son ideales para búsquedas puntuales. \n- Automatic clustering**: Ayuda a mantener la organización de los datos, pero no optimiza directamente las consultas de búsqueda puntual. \n- Query acceleration service**: Acelera las consultas complejas, pero no está especializado en búsquedas puntuales.", "reference": "https://docs.snowflake.com/en/user-guide/search-optimization-service.html"}, {"id": 1167, "area": "Snowflake Data Cloud Features & Architecture", "question": "What is the impact of selecting one Snowflake edition over another? (Choose two.)", "options": ["A) The edition will impact the unit costs for storage.", "B) The edition will impact which regions can be accessed by the accounts.", "C) The edition will determine the unit costs for the compute credits.", "D) The edition will impact the total allowed storage space.", "E) The edition will set a limit on the number of compute credits that can be consumed."], "chooseN": 2, "correct": ["The edition will impact the unit costs for storage.", "The edition will determine the unit costs for the compute credits."], "explanation": "- The edition will impact the unit costs for storage: Las ediciones de Snowflake afectan los costos unitarios de almacenamiento. Ediciones superiores pueden ofrecer precios de almacenamiento más bajos. \n- The edition will determine the unit costs for the compute credits: El costo de los créditos de cómputo también varía según la edición seleccionada. Ediciones superiores suelen ofrecer créditos de cómputo a precios más económicos. \n- The edition will impact which regions can be accessed by the accounts**: Las ediciones no determinan las regiones accesibles; las regiones están disponibles para todas las ediciones. \n- The edition will impact the total allowed storage space**: El espacio total permitido de almacenamiento no está restringido por la edición, ya que Snowflake ofrece almacenamiento ilimitado. \n- The edition will set a limit on the number of compute credits that can be consumed**: No hay un límite en la cantidad de créditos de cómputo que se pueden consumir según la edición.", "reference": "https://docs.snowflake.com/en/user-guide/intro-editions.html"}, {"id": 1168, "area": "Account Access and Security", "question": "In a managed access schema, only the schema owner or a role with what privilege can help centralize privilege management?", "options": ["A) USAGE", "B) OPERATE", "C) MANAGE GRANTS", "D) IMPORTED PRIVILEGES"], "chooseN": 1, "correct": ["MANAGE GRANTS"], "explanation": "- MANAGE GRANTS: En un esquema de acceso gestionado, el privilegio 'MANAGE GRANTS' permite a los propietarios de esquemas o roles autorizados gestionar los privilegios de forma centralizada. Este privilegio es crucial para garantizar un control estricto de acceso en el esquema.\n- USAGE: Este privilegio solo otorga acceso al objeto pero no permite gestionar permisos.\n- OPERATE: No es un privilegio aplicable a la gestión de permisos en un esquema.\n- IMPORTED PRIVILEGES: Este privilegio está relacionado con el acceso a privilegios importados de otras bases de datos, no con la gestión de privilegios en el esquema.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-privileges.html#managed-access-schemas"}, {"id": 1169, "area": "Data Transformations", "question": "A Snowflake user wants to design a series of transformations that need to be executed in a specific order, on a given schedule. What Snowflake objects should be used?", "options": ["A) Pipes", "B) Tasks", "C) Streams", "D) Sequences"], "chooseN": 1, "correct": ["Tasks"], "explanation": "- Tasks: Los 'Tasks' en Snowflake permiten programar y ejecutar una serie de transformaciones en un orden específico y en base a un horario definido. Esta es la solución ideal para este caso.\n- Pipes: Los 'Pipes' son utilizados para la ingesta de datos continua desde un stage a una tabla, no para ejecutar transformaciones.\n- Streams: Los 'Streams' se utilizan para rastrear cambios en tablas (CDC - Change Data Capture), pero no ejecutan transformaciones directamente.\n- Sequences: Las 'Sequences' se usan para generar valores únicos, como identificadores incrementales, y no están diseñadas para programar transformaciones.", "reference": "https://docs.snowflake.com/en/user-guide/tasks-intro.html"}, {"id": 1170, "area": "Data Loading and Unloading", "question": "Which command should be used to drop files from an internal or external stage?", "options": ["A) DELETE", "B) DROP", "C) REMOVE", "D) TRUNCATE"], "chooseN": 1, "correct": ["REMOVE"], "explanation": "- REMOVE: El comando 'REMOVE' en Snowflake se utiliza específicamente para eliminar archivos de un stage interno o externo. Es el comando correcto en este caso.\n- DELETE: Este comando es para eliminar filas en una tabla, no para eliminar archivos de un stage.\n- DROP: 'DROP' se utiliza para eliminar objetos como tablas, vistas o stages completos, pero no para eliminar archivos individuales dentro de un stage.\n- TRUNCATE: 'TRUNCATE' se usa para eliminar todos los datos de una tabla, no tiene relación con stages o archivos.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/remove.html"}, {"id": 1171, "area": "Performance Concepts", "question": "Which parameters can be used together to ensure that a virtual warehouse never has a backlog of queued SQL statements? (Choose two.)", "options": ["A) STATEMENT_QUEUED_TIMEOUT_IN_SECONDS", "B) STATEMENT_TIMEOUT_IN_SECONDS", "C) DATA_RETENTION_TIME_IN_DAYS", "D) MAX_CONCURRENCY_LEVEL", "E) MAX_DATA_EXTENSION_TIME_IN_DAYS"], "chooseN": 2, "correct": ["STATEMENT_QUEUED_TIMEOUT_IN_SECONDS", "MAX_CONCURRENCY_LEVEL"], "explanation": "- STATEMENT_QUEUED_TIMEOUT_IN_SECONDS: Este parámetro controla cuánto tiempo una declaración puede permanecer en cola antes de ser cancelada automáticamente, lo que ayuda a evitar acumulaciones de consultas.\n- MAX_CONCURRENCY_LEVEL: Este parámetro establece el número máximo de consultas concurrentes que puede manejar un warehouse, permitiendo optimizar el flujo de trabajo y evitar acumulaciones.\n- STATEMENT_TIMEOUT_IN_SECONDS: Este parámetro controla el tiempo máximo que una declaración puede ejecutarse antes de ser cancelada, pero no gestiona las declaraciones en cola.\n- DATA_RETENTION_TIME_IN_DAYS: Este parámetro está relacionado con la retención de datos para Time Travel y Fail-safe, no con la gestión de consultas en cola.\n- MAX_DATA_EXTENSION_TIME_IN_DAYS: Este parámetro está relacionado con la extensión del tiempo de retención de datos y no afecta las consultas en cola.", "reference": "https://docs.snowflake.com/en/sql-reference/parameters.html"}, {"id": 1172, "area": "Performance Concepts", "question": "What action should be taken if a large number of concurrent queries are queued in a virtual warehouse?", "options": ["A) Scale-up by resizing the warehouse.", "B) Scale-out with a multi-cluster warehouse.", "C) Disable auto-suspend on the warehouse.", "D) Enable auto-resume on the warehouse."], "chooseN": 1, "correct": ["Scale-out with a multi-cluster warehouse."], "explanation": "- Scale-out with a multi-cluster warehouse: Configurar un multi-cluster warehouse permite a Snowflake escalar horizontalmente, añadiendo más clústeres para manejar un mayor número de consultas concurrentes y reducir los tiempos de espera.\n- Scale-up by resizing the warehouse: Escalar verticalmente aumentando el tamaño del warehouse puede mejorar el rendimiento de consultas individuales, pero no aborda directamente el problema de consultas en cola debido a concurrencia.\n- Disable auto-suspend on the warehouse: Deshabilitar la suspensión automática no resuelve problemas de consultas en cola; esto solo mantiene el warehouse activo continuamente.\n- Enable auto-resume on the warehouse: La reanudación automática asegura que el warehouse se reactive cuando reciba consultas, pero no soluciona problemas de concurrencia y consultas en cola.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-multi-cluster.html"}, {"id": 1173, "area": "Account Access and Security", "question": "Which feature is supported in column-level security in Snowflake?", "options": ["A) Object tagging", "B) Data classification", "C) External tokenization", "D) Tag-based masking policies"], "chooseN": 1, "correct": ["External tokenization"], "explanation": "External tokenization is supported in Snowflake column-level security. Column-level security allows a masking policy to be applied to a column in a table or view, and Snowflake explicitly lists External Tokenization as one of the two column-level security features, along with Dynamic Data Masking. External Tokenization tokenizes data before loading it into Snowflake and detokenizes it at query runtime.", "reference": "https://docs.snowflake.com/en/user-guide/security-column.html"}, {"id": 1174, "area": "Account Access and Security", "question": "A network policy applied at the user level takes precedence over a network policy applied to what Snowflake object?", "options": ["A) A role", "B) An account", "C) A database", "D) An organization"], "chooseN": 1, "correct": ["An account"], "explanation": "- An account: En Snowflake, una política de red aplicada a nivel de usuario tiene prioridad sobre la política de red aplicada a nivel de cuenta. Esto permite configuraciones específicas de red para usuarios individuales, anulando la configuración de nivel de cuenta si existen conflictos.\n- A role: Las políticas de red no se aplican directamente a roles, sino a usuarios o cuentas.\n- A database: Las políticas de red no se configuran a nivel de base de datos en Snowflake.\n- An organization: Snowflake no implementa políticas de red directamente a nivel de organización; estas se aplican a cuentas o usuarios.", "reference": "https://docs.snowflake.com/en/user-guide/network-policies.html"}, {"id": 1175, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which Snowflake storage object can be used to store data beyond a single session and will not incur Fail-safe costs?", "options": ["A) Permanent table", "B) External table", "C) Temporary table", "D) Transient table"], "chooseN": 1, "correct": ["Transient table"], "explanation": "- Transient table: Las tablas transitorias almacenan datos más allá de una sola sesión y no incurren en costos de Fail-safe, ya que no tienen un periodo de Fail-safe asociado.\n- Permanent table: Las tablas permanentes incluyen soporte para Time Travel y Fail-safe, lo que genera costos adicionales.\n- External table: Las tablas externas no almacenan datos dentro de Snowflake, sino que hacen referencia a datos almacenados externamente, por lo que no son aplicables a este caso.\n- Temporary table: Las tablas temporales solo duran la duración de una sesión y no están diseñadas para almacenar datos más allá de esta.", "reference": "https://docs.snowflake.com/en/user-guide/tables-intro.html#transient-tables"}, {"id": 1176, "area": "Data Protection and Data Sharing", "question": "Which data sharing mechanism can be used to share data privately or publicly within the Snowflake Marketplace?", "options": ["A) Listing", "B) Direct share", "C) Reader account", "D) Data Exchange"], "chooseN": 1, "correct": ["Listing"], "explanation": "- Listing: Los 'Listings' se utilizan para compartir datos de forma privada o pública dentro del Snowflake Marketplace, permitiendo a los proveedores de datos publicar sus datos para que otros puedan acceder fácilmente.\n- Direct share: Los 'Direct shares' se utilizan para compartir datos de manera privada entre cuentas específicas, pero no están integrados con el Marketplace.\n- Reader account: Las cuentas de lector permiten compartir datos con organizaciones que no son clientes de Snowflake, pero no están diseñadas para compartir datos públicamente o a través del Marketplace.\n- Data Exchange: Los 'Data Exchanges' son plataformas privadas para compartir datos entre miembros de una organización o ecosistema específico, pero no son públicos ni integrados con el Marketplace.", "reference": "https://docs.snowflake.com/en/user-guide/data-marketplace.html#listings"}, {"id": 1177, "area": "Snowflake Data Cloud Features & Architecture", "question": "What metrics will the SHOW TABLES command in Snowsight provide?", "options": ["A) Time Travel bytes", "B) Active bytes", "C) Fail-safe bytes", "D) Retained for clone bytes"], "chooseN": 1, "correct": ["Active bytes"], "explanation": "- Active bytes: Muestra la cantidad de datos activos en la tabla, que es la única métrica proporcionada por el comando SHOW TABLES en Snowsight.\n\n- Time Travel bytes: No es una métrica proporcionada por el comando SHOW TABLES.\n\n- Fail-safe bytes: Esta métrica tampoco se muestra en los resultados de SHOW TABLES.\n\n- Retained for clone bytes: No es una métrica reportada por SHOW TABLES en Snowsight.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/show-tables.html"}, {"id": 1178, "area": "Data Loading and Unloading", "question": "An external stage, my_stage contains many directories, including one, app_files that contains CSV files. How can all the CSV files from this directory be moved into table my_table without scanning files that are not needed?", "options": ["A) COPY INTO my_table FROM @my_stage PATTERN='.*[.]csv';", "B) COPY INTO my_table FROM @my_stage/app_files PATTERN='.*[.]csv';", "C) COPY INTO my_table FROM @my_stage/app_files PATTERN='.*[.]txt';", "D) COPY INTO my_table FROM @my_stage PATTERN='.*[.]txt';"], "chooseN": 1, "correct": ["COPY INTO my_table FROM @my_stage/app_files PATTERN='.*[.]csv';"], "explanation": "- **COPY INTO my_table FROM @my_stage/app_files PATTERN='.*[.csv';]**: La opción correcta es usar la ruta específica del directorio 'app_files' junto con el patrón para seleccionar solo los archivos CSV dentro de ese directorio. Esto evita que se escaneen archivos no deseados en otros directorios.\n- **COPY INTO my_table FROM @my_stage PATTERN='.*[.csv';]**: Aunque este comando selecciona archivos CSV, no limita la búsqueda al directorio 'app_files', lo que puede resultar en una carga innecesaria de archivos de otros directorios.\n- **COPY INTO my_table FROM @my_stage/app_files PATTERN='.*[.txt';]**: Este comando buscaría archivos .txt en lugar de archivos .csv, por lo que no es adecuado para el caso descrito.\n- **COPY INTO my_table FROM @my_stage PATTERN='.*[.txt';]**: Al igual que el anterior, este comando busca archivos .txt en todo el stage, lo que no es lo que se requiere.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-stage.html"}, {"id": 1179, "area": "Performance Concepts", "question": "Using which object-level parameters will help limit query processing and concurrency slowdowns? (Choose two.)", "options": ["A) MULTI_STATEMENT_COUNT", "B) ENABLE_QUERY_ACCELERATION", "C) STATEMENT_TIMEOUT_IN_SECONDS", "D) STATEMENT_QUEUED_TIMEOUT_IN_SECONDS", "E) QUERY_ACCELERATION_MAX_SCALE_FACTOR"], "chooseN": 2, "correct": ["STATEMENT_TIMEOUT_IN_SECONDS", "STATEMENT_QUEUED_TIMEOUT_IN_SECONDS"], "explanation": "- STATEMENT_TIMEOUT_IN_SECONDS: Este parámetro limita el tiempo que una consulta puede ejecutarse, lo que ayuda a prevenir que consultas largas ralenticen el rendimiento general del sistema.\n- STATEMENT_QUEUED_TIMEOUT_IN_SECONDS: Establece un tiempo máximo para que una consulta espere en la cola antes de ser cancelada, ayudando a evitar que las consultas en cola ralenticen el rendimiento general debido a la congestión de la cola.\n- MULTI_STATEMENT_COUNT: Este parámetro controla el número de declaraciones en un solo bloque de código, pero no está directamente relacionado con la limitación de la lentitud de procesamiento de las consultas o la concurrencia.\n- ENABLE_QUERY_ACCELERATION: Aunque habilitar la aceleración de consultas puede mejorar el rendimiento, no es un parámetro de nivel de objeto que limite específicamente el procesamiento de consultas o la concurrencia.\n- QUERY_ACCELERATION_MAX_SCALE_FACTOR: Este parámetro controla el factor de escala para la aceleración de consultas, pero no tiene un impacto directo en la limitación de la lentitud de procesamiento de consultas o la concurrencia.", "reference": "https://docs.snowflake.com/en/sql-reference/parameters.html"}, {"id": 1180, "area": "Performance Concepts", "question": "The ORDERS table contains 12,000 rows.\n\nWhich query will return 10 rows that are randomly sampled from the table every time the query is run?", "options": ["A) SELECT * FROM ORDERS FETCH 10;", "B) SELECT * FROM ORDERS LIMIT 10;", "C) SELECT * FROM ORDERS SAMPLE (10);", "D) SELECT * FROM ORDERS TABLESAMPLE (10 ROWS);"], "chooseN": 1, "correct": ["SELECT * FROM ORDERS TABLESAMPLE (10 ROWS);"], "explanation": "- SELECT * FROM ORDERS TABLESAMPLE (10 ROWS);: Utiliza `TABLESAMPLE`, que permite extraer filas de manera aleatoria. La opción `10 ROWS` garantiza que se seleccionarán aproximadamente 10 filas en cada ejecución.\n- SELECT * FROM ORDERS FETCH 10;: `FETCH` se usa para limitar filas devueltas en combinación con `ORDER BY`, pero no realiza un muestreo aleatorio.\n- SELECT * FROM ORDERS LIMIT 10;: `LIMIT` restringe el número de filas devueltas, pero devuelve siempre las mismas 10 filas a menos que se combine con `ORDER BY RANDOM()`.\n- SELECT * FROM ORDERS SAMPLE (10);: `SAMPLE (10)` toma un porcentaje de filas en lugar de un número exacto, lo que no garantiza exactamente 10 filas.", "reference": "https://docs.snowflake.com/en/sql-reference/constructs/sample.html"}, {"id": 1181, "area": "Data Transformations", "question": "Which function will convert semi-structured data to a relational data representation?", "options": ["A) PARSE_JSON", "B) FLATTEN", "C) OBJECT_CONSTRUCT", "D) OBJECT_AGG"], "chooseN": 1, "correct": ["FLATTEN"], "explanation": "- FLATTEN: La función `FLATTEN` convierte datos semiestructurados (como JSON o ARRAY) en un formato tabular, expandiendo los elementos en múltiples filas.\n- PARSE_JSON: Convierte una cadena JSON en un objeto Snowflake VARIANT, pero no lo transforma en una estructura relacional.\n- OBJECT_CONSTRUCT: Construye un objeto a partir de pares clave-valor, pero no lo convierte en una tabla.\n- OBJECT_AGG: Agrega pares clave-valor en un solo objeto, pero no ayuda a convertir los datos en un formato tabular.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/flatten.html"}, {"id": 1182, "area": "Snowflake Data Cloud Features & Architecture", "question": "What triggers the automated maintenance of a table's clustering key after it has been defined?", "options": ["A) A scheduled task established by the ORGADMIN.", "B) A time-based schedule set by the user.", "C) A Snowflake determination based on the table size.", "D) A Snowflake determination that the table will benefit from maintenance."], "chooseN": 1, "correct": ["A Snowflake determination that the table will benefit from maintenance."], "explanation": "- A Snowflake determination that the table will benefit from maintenance.: Snowflake automáticamente reorganiza los micro-partitions cuando determina que el rendimiento de las consultas se beneficiará de una mejor organización de los datos.\n- A scheduled task established by the ORGADMIN.: No hay opción para que un ORGADMIN programe tareas de mantenimiento de clustering en Snowflake.\n- A time-based schedule set by the user.: Snowflake no permite a los usuarios programar explícitamente el mantenimiento del clustering.\n- A Snowflake determination based on the table size.: Aunque el tamaño del conjunto de datos influye, no es el único criterio; Snowflake analiza patrones de acceso y fragmentación para decidir cuándo ejecutar mantenimiento.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-keys.html"}, {"id": 1183, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which Snowflake object will consume credits during automatic background maintenance?", "options": ["A) View", "B) Table", "C) External table", "D) Materialized view"], "chooseN": 1, "correct": ["Materialized view"], "explanation": "- Materialized view: Los `Materialized Views` en Snowflake requieren mantenimiento automático para mantenerse actualizados con los cambios en la tabla base. Este proceso consume créditos.\n- View: Las `Views` estándar no almacenan datos ni requieren mantenimiento, por lo que no consumen créditos.\n- Table: Aunque Snowflake realiza ciertas optimizaciones automáticas en tablas (como clustering automático), estas optimizaciones no siempre generan costos de créditos directos.\n- External table: Las `External Tables` referencian datos almacenados fuera de Snowflake (como en S3), por lo que Snowflake no las mantiene automáticamente ni consume créditos por mantenimiento.", "reference": "https://docs.snowflake.com/en/user-guide/views-materialized.html"}, {"id": 1184, "area": "Account Access and Security", "question": "Snowflake users can create a resource monitor at which levels? (Choose two.)", "options": ["A) User level", "B) Pipe level", "C) Account level", "D) Cloud services level", "E) Virtual warehouse level"], "chooseN": 2, "correct": ["Account level", "Virtual warehouse level"], "explanation": "- Account level: Los monitores de recursos pueden aplicarse a nivel de cuenta para rastrear y limitar el uso total de créditos.\n- Virtual warehouse level: También se pueden establecer monitores de recursos en un `Virtual Warehouse` específico para controlar su consumo de créditos.\n- User level: No se pueden configurar monitores de recursos a nivel de usuario.\n- Pipe level: Los `Pipes` no están sujetos a monitores de recursos, ya que Snowflake gestiona su ejecución y costos de manera separada.\n- Cloud services level: No hay una opción para configurar monitores de recursos específicamente para servicios en la nube.", "reference": "https://docs.snowflake.com/en/user-guide/resource-monitors.html"}, {"id": 1185, "area": "Account Access and Security", "question": "Which Snowflake objects can be secured to protect data privacy? (Choose two.)", "options": ["A) Schemas", "B) Stages", "C) Views", "D) Materialized views", "E) Tags"], "chooseN": 2, "correct": ["Views", "Materialized views"], "explanation": "- Views: Las `Views` pueden usarse para restringir el acceso a datos específicos aplicando filtrado o enmascaramiento, asegurando la privacidad de los datos.\n- Materialized views: Al igual que las `Views`, las `Materialized Views` pueden usarse para restringir datos sensibles y mejorar el rendimiento sin exponer tablas completas.\n- Schemas: Aunque los `Schemas` pueden tener permisos, no son una herramienta específica para la protección de privacidad de datos.\n- Stages: Los `Stages` son ubicaciones de almacenamiento intermedio para datos, pero no ofrecen mecanismos específicos de seguridad para proteger la privacidad.\n- Tags: Los `Tags` ayudan a la clasificación de datos, pero no proporcionan seguridad ni control de acceso.", "reference": "https://docs.snowflake.com/en/user-guide/views-introduction.html, https://docs.snowflake.com/en/user-guide/views-materialized.html"}, {"id": 1186, "area": "Performance Concepts", "question": "How does Snowflake optimize queries on tables by leveraging the sorting and storage of data within micro-partitions?", "options": ["A) The data is pruned by column to eliminate unnecessary micro-partitions, then the rows within the remaining micro-partitions are filtered.", "B) The data is pruned by micro-partitions based on column values, then rows within the remaining micro-partitions are filtered.", "C) Any micro-partitions that are not needed for the query are pruned, then the data within the remaining micro-partitions is pruned by column.", "D) The data within micro-partitions is sorted by rows, then the columns are filtered based on the query conditions."], "chooseN": 1, "correct": ["The data is pruned by micro-partitions based on column values, then rows within the remaining micro-partitions are filtered."], "explanation": "- The data is pruned by micro-partitions based on column values, then rows within the remaining micro-partitions are filtered.: Snowflake almacena los datos en `micro-partitions` y usa metadatos de las columnas para realizar `partition pruning`, eliminando aquellas particiones que no cumplen con las condiciones de la consulta antes de procesar las filas restantes.\n- The data is pruned by column to eliminate unnecessary micro-partitions, then the rows within the remaining micro-partitions are filtered.: El `pruning` se realiza a nivel de micro-partitions primero, no a nivel de columnas.\n- Any micro-partitions that are not needed for the query are pruned, then the data within the remaining micro-partitions is pruned by column.: El `pruning` no ocurre directamente a nivel de columna dentro de las micro-particiones.\n- The data within micro-partitions is sorted by rows, then the columns are filtered based on the query conditions.: Snowflake no almacena los datos ordenados por filas, sino que utiliza un enfoque de micro-particiones optimizado para columnas.", "reference": "https://docs.snowflake.com/en/user-guide/tables-micro-partitions.html"}, {"id": 1187, "area": "Performance Concepts", "question": "Which resource monitor setting will cancel all active queries in a virtual warehouse when the threshold is met?", "options": ["A) NOTIFY", "B) NOTIFY_USERS", "C) SUSPEND", "D) SUSPEND_IMMEDIATE"], "chooseN": 1, "correct": ["SUSPEND_IMMEDIATE"], "explanation": "- SUSPEND_IMMEDIATE: Este parámetro suspende inmediatamente todas las consultas activas en el warehouse cuando se alcanza el umbral del monitor de recursos, lo que ayuda a evitar que se sobrepasen los límites de uso de recursos.\n- NOTIFY: 'NOTIFY' solo envía una notificación cuando se alcanza un umbral, pero no suspende ni cancela consultas activas.\n- NOTIFY_USERS: Similar a 'NOTIFY', 'NOTIFY_USERS' envía notificaciones a los usuarios, pero no cancela las consultas activas.\n- SUSPEND: 'SUSPEND' suspende el warehouse, pero no necesariamente cancela las consultas activas de inmediato.", "reference": "https://docs.snowflake.com/en/user-guide/resource-monitors.html"}, {"id": 1188, "area": "Account Access and Security", "question": "What role should be used when creating a new user?", "options": ["A) ORGADMIN", "B) SECURITYADMIN", "C) USERADMIN", "D) SYSADMIN"], "chooseN": 1, "correct": ["USERADMIN"], "explanation": "- USERADMIN: El rol 'USERADMIN' es el rol adecuado para crear y gestionar usuarios en Snowflake. Este rol permite la administración de usuarios, sus roles y permisos asociados.\n- ORGADMIN: 'ORGADMIN' es un rol de nivel organizacional más alto, pero no está diseñado específicamente para la creación de usuarios.\n- SECURITYADMIN: 'SECURITYADMIN' está orientado a la gestión de roles y permisos de seguridad, no es el rol ideal para crear usuarios.\n- SYSADMIN: 'SYSADMIN' se centra en la gestión de recursos y objetos de bases de datos, no es adecuado para la creación de usuarios.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-roles.html"}, {"id": 1189, "area": "Performance Concepts", "question": "Which ACCOUNT_USAGE view will identify long-running queries?", "options": ["A) DATA_TRANSFER_HISTORY", "B) TASK_HISTORY", "C) QUERY_HISTORY", "D) METERING_DAILY_HISTORY"], "chooseN": 1, "correct": ["QUERY_HISTORY"], "explanation": "- QUERY_HISTORY: La vista 'QUERY_HISTORY' en el esquema 'ACCOUNT_USAGE' proporciona información detallada sobre las consultas, incluidas las que están en ejecución durante períodos prolongados, lo que permite identificar consultas de larga duración.\n- DATA_TRANSFER_HISTORY: Esta vista muestra información sobre la transferencia de datos, no sobre las consultas.\n- TASK_HISTORY: 'TASK_HISTORY' proporciona información sobre las tareas programadas, no sobre las consultas individuales.\n- METERING_DAILY_HISTORY: Esta vista ofrece información sobre el consumo de recursos de Snowflake a nivel diario, pero no se centra en las consultas individuales.", "reference": "https://docs.snowflake.com/en/sql-reference/account-usage/query-history.html"}, {"id": 1190, "area": "Data Protection and Data Sharing", "question": "When sharing data among multiple Snowflake accounts, what charges are incurred by a data consumer when viewing shared data using their own account?", "options": ["A) Cloud services charges", "B) Compute charges", "C) Data storage charges", "D) Data egress charges"], "chooseN": 1, "correct": ["Compute charges"], "explanation": "- Compute charges: Cuando un consumidor de datos accede a datos compartidos utilizando su propia cuenta, incurre en cargos de cómputo, ya que están utilizando recursos de cómputo para procesar y consultar los datos compartidos.\n- Cloud services charges: Los cargos de servicios en la nube son generales y no se aplican directamente a la visualización de datos compartidos en este caso.\n- Data storage charges: Los cargos de almacenamiento solo se aplican al propietario de los datos en su cuenta, no al consumidor de datos.\n- Data egress charges: Los cargos de egreso de datos solo se aplican cuando los datos se transfieren fuera de la red de Snowflake, lo cual no es el caso cuando se consultan datos compartidos dentro de la misma plataforma.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-consumers.html"}, {"id": 1191, "area": "Performance Concepts", "question": "What is the MINIMUM Snowflake edition required to use the query acceleration service?", "options": ["A) Standard", "B) Enterprise", "C) Business Critical", "D) Virtual Private Snowflake (VPS)"], "chooseN": 1, "correct": ["Enterprise"], "explanation": "- Enterprise: La edición mínima de Snowflake requerida para utilizar el servicio de aceleración de consultas es la edición 'Enterprise', que incluye funcionalidades avanzadas como la aceleración de consultas.\n- Standard: La edición 'Standard' no incluye la funcionalidad de aceleración de consultas, que solo está disponible en ediciones superiores.\n- Business Critical: Aunque 'Business Critical' ofrece características adicionales de seguridad y cumplimiento, la funcionalidad de aceleración de consultas está disponible en la edición 'Enterprise'.\n- Virtual Private Snowflake (VPS): 'VPS' es una oferta de Snowflake para aislamiento de datos y no está directamente relacionada con la disponibilidad de la aceleración de consultas.", "reference": "https://docs.snowflake.com/en/user-guide/acceleration-service.html"}, {"id": 1192, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which objects can be cloned in Snowflake? (Choose two.)", "options": ["A) Virtual warehouses", "B) Internal named stages", "C) External named stages", "D) Dynamic tables", "E) External tables"], "chooseN": 2, "correct": ["Internal named stages", "External named stages"], "explanation": "Snowflake documentation explicitly supports cloning external named stages individually and cloning internal named stages with the INCLUDE INTERNAL STAGES clause. The marked answer is incorrect because it excludes external named stages and incorrectly says they cannot be cloned.", "reference": "https://docs.snowflake.com/en/user-guide/cloning.html"}, {"id": 1193, "area": "Snowflake Data Cloud Features & Architecture", "question": "What happens to foreign key constraints when a table is cloned to another database?", "options": ["A) All referenced tables will be cloned.", "B) The cloned table will reference the primary key in the source table.", "C) The cloned table will lose all references to the primary key.", "D) The cloned table will lose all references to the foreign and primary keys."], "chooseN": 1, "correct": ["The cloned table will reference the primary key in the source table."], "explanation": "When a table with foreign key constraints is cloned to another database, the cloned table maintains the foreign key references pointing to the primary key in the source table. The constraints are preserved during cloning — they are not lost. However, if the referenced table doesn't exist in the target database, the foreign key will still reference the original source table.", "reference": "https://docs.snowflake.com/en/user-guide/cloning.html#cloning-limitations"}, {"id": 1194, "area": "Account Access and Security", "question": "What step must be taken to ensure that a user can only access Snowsight from a specific location, or when working from home?", "options": ["A) Use a company Virtual Private Network (VPN) connection.", "B) Use Multi-Factor Authentication (MFA).", "C) Use Single Sign-On (SSO).", "D) Add the user's IP address to the network policy allowed list."], "chooseN": 1, "correct": ["Add the user's IP address to the network policy allowed list."], "explanation": "- Add the user's IP address to the network policy allowed list: Esta opción es correcta ya que mediante la inclusión de la IP en la lista de permitidos se restringe el acceso a ubicaciones específicas. Las demás opciones se centran en la autenticación o conexiones seguras, pero no limitan geográficamente el acceso.", "reference": "https://docs.snowflake.com/en/user-guide/network-policies.html"}, {"id": 1195, "area": "Data Loading and Unloading", "question": "What actions will trigger a data pipe to load? (Choose two.)", "options": ["A) Use of an INSERT statement", "B) Use of a COPY INTO [table] statement", "C) Use of the insertFiles REST endpoint", "D) Use of the insertReport REST endpoint", "E) Set the pipe parameter to auto-ingest"], "chooseN": 2, "correct": ["Use of the insertFiles REST endpoint", "Set the pipe parameter to auto-ingest"], "explanation": "- Use of the insertFiles REST endpoint & Set the pipe parameter to auto-ingest: Estas opciones son correctas porque activan el mecanismo de auto-ingestión de data pipes, mientras que las otras no están diseñadas para disparar la carga automática.", "reference": "https://docs.snowflake.com/en/user-guide/data-pipes-auto-ingest.html"}, {"id": 1196, "area": "Performance Concepts", "question": "What does a Query Profile metric that shows excessive spillage indicate?", "options": ["A) Poor query optimization", "B) Expired temporary tables", "C) Improper virtual warehouse sizing", "D) Improper Common Table Expressions (CTEs)"], "chooseN": 1, "correct": ["Improper virtual warehouse sizing"], "explanation": "Excessive spillage in the Query Profile indicates that the virtual warehouse does not have sufficient memory to process the data. When data spills to local or remote disk, query performance degrades significantly. Snowflake recommends using a larger warehouse to address this, as larger warehouses have more memory and compute resources. This is a warehouse sizing issue, not a query optimization problem.", "reference": "https://docs.snowflake.com/en/user-guide/query-profile.html"}, {"id": 1197, "area": "Performance Concepts", "question": "A query is using more credits than expected. The Query Profile shows that a majority of the query execution is spent on remote disk I/O. How can this be prevented in the future?", "options": ["A) Convert the virtual warehouse to Maximized mode.", "B) Increase the size of the virtual warehouse.", "C) Increase the auto suspend time in the virtual warehouse.", "D) Increase the number of clusters in the virtual warehouse."], "chooseN": 1, "correct": ["Increase the size of the virtual warehouse."], "explanation": "- Increase the size of the virtual warehouse: Ampliar el tamaño del warehouse mejora la capacidad de procesamiento y reduce la dependencia de I/O en disco remoto. Las demás opciones no abordan directamente el cuello de botella de I/O.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses.html"}, {"id": 1198, "area": "Data Transformations", "question": "In a SPLIT_PART function, what will the returned value be if the partNumber is out of range?", "options": ["A) −1", "B) An empty string", "C) The full string", "D) An error"], "chooseN": 1, "correct": ["An empty string"], "explanation": "- An empty string: Cuando el número de parte está fuera de rango, la función SPLIT_PART devuelve una cadena vacía. Las otras opciones no reflejan el comportamiento documentado.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/split_part.html"}, {"id": 1199, "area": "Data Loading and Unloading", "question": "From which locations can data files be downloaded using the GET command? (Choose two.)", "options": ["A) External stage", "B) Table stage", "C) User stage", "D) Directory table", "E) Permanent table"], "chooseN": 2, "correct": ["Table stage", "User stage"], "explanation": "- Table stage & User stage: Estas ubicaciones soportan la descarga de archivos mediante el comando GET. Las otras opciones no son compatibles para este fin según la documentación de Snowflake.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/get.html"}, {"id": 1200, "area": "Data Protection and Data Sharing", "question": "What Snowflake features are recommended to restrict unauthorized users from accessing Personal Identifiable Information (PI)? (Choose two.)", "options": ["A) Dynamic Data Masking", "B) Transient tables", "C) Secure views", "D) Multi-Factor Authentication (MFA)", "E) Data encryption"], "chooseN": 2, "correct": ["Dynamic Data Masking", "Secure views"], "explanation": "- Dynamic Data Masking & Secure views: Estas características ayudan a proteger datos sensibles al enmascararlos y restringir la visibilidad, mientras que las demás opciones no se enfocan directamente en la protección de PI a nivel de datos.", "reference": "https://docs.snowflake.com/en/user-guide/security-dynamic-data-masking.html, https://docs.snowflake.com/en/user-guide/views-secure.html"}, {"id": 1201, "area": "Performance Concepts", "question": "Which Snowflake keywords help retrieve data without the need to completely scan a table? (Choose two.)", "options": ["A) TOP [n]", "B) LIMIT", "C) FETCH", "D) SAMPLE", "E) TABLESAMPLE"], "chooseN": 2, "correct": ["SAMPLE", "TABLESAMPLE"], "explanation": "- SAMPLE & TABLESAMPLE: Estas palabras clave permiten obtener subconjuntos de datos sin escanear toda la tabla, optimizando el rendimiento de las consultas. Las demás opciones se utilizan para limitar resultados pero no evitan el escaneo completo.", "reference": "https://docs.snowflake.com/en/sql-reference/constructs/tablesample.html"}, {"id": 1202, "area": "Account Access and Security", "question": "A security review identified several roles that are no longer being used. Which of the roles can be dropped?", "options": ["A) ACCOUNTADMIN", "B) USERADMIN", "C) FINANCEADMIN", "D) PUBLIC"], "chooseN": 1, "correct": ["FINANCEADMIN"], "explanation": "- FINANCEADMIN: Los roles específicos y personalizados, como FINANCEADMIN, pueden eliminarse si no se utilizan, mientras que los roles integrados (ACCOUNTADMIN, USERADMIN, PUBLIC) son necesarios para la administración y operación de Snowflake.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-overview.html"}, {"id": 1203, "area": "Snowflake Data Cloud Features & Architecture", "question": "A complex query has been running in Snowsight for more than one hour. At the same time, several other queries from other worksheets ran successfully. What is FASTEST way to cancel the long-running query?", "options": ["A) Immediately suspend the virtual warehouse that the query is running on.", "B) Return to the worksheet and abort the query.", "C) Set the auto_suspend virtual warehouse property to 0.", "D) Find the query in the query activity view and cancel the query."], "chooseN": 1, "correct": ["Find the query in the query activity view and cancel the query."], "explanation": "- Find the query in the query activity view and cancel the query: Cancelar la consulta desde la vista de actividad es la forma más directa y controlada de detener una consulta problemática sin afectar a otras operaciones del sistema.", "reference": "https://docs.snowflake.com/en/user-guide/snowsight-cancel-queries.html"}, {"id": 1204, "area": "Performance Concepts", "question": "How can a Snowflake user automate virtual warehouse operations for optimal credit consumption? (Choose two.)", "options": ["A) Auto-resume when a query is in a queue.", "B) Auto-resume after a set time period.", "C) Auto-suspend while the query is being written.", "D) Auto-suspend after a set time period.", "E) Auto-suspend after a specified period of inactivity."], "chooseN": 2, "correct": ["Auto-resume when a query is in a queue.", "Auto-suspend after a specified period of inactivity."], "explanation": "- Auto-resume when a query is in a queue & Auto-suspend after a specified period of inactivity: Estas configuraciones permiten que el warehouse se active cuando es necesario y se suspenda automáticamente tras la inactividad, optimizando el uso de créditos. Las otras opciones no garantizan un manejo tan preciso.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-auto-suspend-resume.html"}, {"id": 1205, "area": "Data Protection and Data Sharing", "question": "Which data protection feature should only be used when all other data recovery options have been attempted?", "options": ["A) Time Travel", "B) Cloning", "C) Replication", "D) Fail-safe"], "chooseN": 1, "correct": ["Fail-safe"], "explanation": "- Fail-safe: Fail-safe es la última opción de recuperación de datos en Snowflake y se utiliza únicamente cuando las demás alternativas, como Time Travel y Cloning, han sido agotadas.", "reference": "https://docs.snowflake.com/en/user-guide/data-protection-failsafe.html"}, {"id": 1206, "area": "Performance Concepts", "question": "A single cluster virtual warehouse has no free resources. What will happen to new queries that are run against this warehouse?", "options": ["A) The queries will be assigned to another virtual warehouse.", "B) The queries will be skipped.", "C) The queries will be placed in a queue.", "D) The warehouse will automatically resize and execute the queries."], "chooseN": 1, "correct": ["The queries will be placed in a queue."], "explanation": "- The queries will be placed in a queue: Cuando un warehouse de clúster único está ocupado, las consultas entrantes se encolan hasta que se liberen recursos. Las otras opciones no reflejan el comportamiento predeterminado documentado.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses.html#query-queuing"}, {"id": 1207, "area": "Performance Concepts", "question": "How does the search optimization service improve query performance?", "options": ["A) By clustering the tables", "B) By creating a persistent data structure", "C) By using caching", "D) By optimizing the use of micro-partitions"], "chooseN": 1, "correct": ["By creating a persistent data structure"], "explanation": "The search optimization service creates and maintains a persistent data structure called a search access path. This structure tracks which values of a table's columns might be found in each micro-partition, allowing micro-partitions to be skipped when scanning the table. Clustering organizes data but is a separate feature. Caching is a different layer. Micro-partition optimization is not the mechanism used by the search optimization service.", "reference": "https://docs.snowflake.com/en/user-guide/search-optimization-service"}, {"id": 1208, "area": "Data Loading and Unloading", "question": "Use of what parameter will allow files to be loaded even if the file metadata has expired?", "options": ["A) MATCH_BY_COLUMN_NAME = CASE_INSENSITIVE", "B) ENFORCE_LENGTH = TRUE", "C) PURGE = TRUE", "D) LOAD_UNCERTAIN_FILES = TRUE"], "chooseN": 1, "correct": ["LOAD_UNCERTAIN_FILES = TRUE"], "explanation": "- LOAD_UNCERTAIN_FILES = TRUE: Este parámetro permite la carga de archivos incluso cuando su metadata ha expirado, lo que no ocurre con las otras opciones que tienen funciones diferentes.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-location.html"}, {"id": 1209, "area": "Data Protection and Data Sharing", "question": "How can a Data Exchange Administrator provide a user with account access to a Data Exchange?", "options": ["A) Grant the user the USERADMIN role.", "B) Add the user to the Data Exchange.", "C) Enable the IMPORT SHARE privilege and grant this privilege to the user.", "D) Create a new database for the Data Exchange and provide access to the user."], "chooseN": 1, "correct": ["Add the user to the Data Exchange."], "explanation": "- Add the user to the Data Exchange: La acción de agregar directamente al usuario al Data Exchange es el método correcto para otorgar acceso, mientras que las otras opciones no son apropiadas para este escenario específico.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-intro.html"}, {"id": 1210, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which features can be used with the Snowflake Standard edition? (Choose two.)", "options": ["A) Materialized views", "B) External functions", "C) Multi-cluster virtual warehouses", "D) Fail-safe", "E) Row-level security"], "chooseN": 2, "correct": ["Fail-safe", "External functions"], "explanation": "Fail-safe (7 dias de proteccion adicional) esta incluido en todas las ediciones de Snowflake, incluida Standard Edition. Las External functions estan disponibles en Standard Edition y permiten invocar codigo externo mediante servicios remotos (API integrations). Materialized views requieren Enterprise Edition o superior. Multi-cluster virtual warehouses requieren Enterprise Edition o superior. Row-level security requiere Enterprise Edition o superior.", "reference": "https://docs.snowflake.com/en/user-guide/intro-edition-limitations.html"}, {"id": 1211, "area": "Data Protection and Data Sharing", "question": "Which function will generate a URL that can be accessed by a non-Snowflake user?", "options": ["A) GET_PRESIGNED_URL", "B) GET_STAGE_LOCATION", "C) BUILD_SCOPED_FILE_URL", "D) BUILD_STAGE_FILE_URL"], "chooseN": 1, "correct": ["GET_PRESIGNED_URL"], "explanation": "- GET_PRESIGNED_URL: Esta función genera una URL prefirmada que permite el acceso a usuarios externos, mientras que las otras funciones no cumplen esta función.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/get_presigned_url.html"}, {"id": 1212, "area": "Data Loading and Unloading", "question": "What are valid values for the FIELD_OPTIONALLY_ENCLOSED_BY option in the COPY INTO [location] command used during data unloading? (Choose two.)", "options": ["A) Single quote character (')", "B) NULL", "C) 'NULL'", "D) NONE", "E) 'NONE'"], "chooseN": 2, "correct": ["Single quote character (')", "NONE"], "explanation": "- Single quote character (') & NONE: Estas opciones son las aceptadas por la función FIELD_OPTIONALLY_ENCLOSED_BY durante la operación de unloading. Las demás opciones no cumplen con los valores válidos según la documentación.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-location.html"}, {"id": 1213, "area": "Snowflake Data Cloud Features & Architecture", "question": "What identifiers are supported when creating a Snowflake account hostname? (Choose two.)", "options": ["A) Cloud region", "B) Snowflake domain", "C) Account name", "D) Account locator", "E) Account cloud platform"], "chooseN": 2, "correct": ["Account name", "Account locator"], "explanation": "The correct answer is: Account name, Account locator. The docs state: 'Snowflake supports two formats to use as the account identifier in your hostname: Account name (preferred) and Account locator.' Cloud region is a qualifier appended to account locator, not an independent identifier format. The correct answers are C (Account name) and D (Account locator), not A (Cloud region) and D. Reference: https://docs.snowflake.com/en/user-guide/admin-account-identifier", "reference": "https://docs.snowflake.com/en/user-guide/admin-account-parameters.html"}, {"id": 1214, "area": "Performance Concepts", "question": "Which virtual warehouse auto-suspend configurations will result in a warehouse that runs continually, 24 hours a day, 7 days a week? (Choose two.)", "options": ["A) −1", "B) 0", "C) 86400", "D) 172800", "E) NULL"], "chooseN": 2, "correct": ["0", "NULL"], "explanation": "The correct answer is: 0, NULL. The CREATE WAREHOUSE docs state AUTO_SUSPEND valid values are 'Any integer 0 or greater, or NULL' and 'Setting a 0 or NULL value means the warehouse never suspends.' -1 is NOT valid. The correct answers are B (0) and E (NULL). Reference: https://docs.snowflake.com/en/sql-reference/sql/create-warehouse", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-auto-suspend-resume.html"}, {"id": 1215, "area": "Data Transformations", "question": "What kind of value does a User-Defined Function (UDF) return? (Choose two.)", "options": ["A) Dictionary", "B) List", "C) Object", "D) Scalar", "E) Tabular"], "chooseN": 2, "correct": ["Scalar", "Tabular"], "explanation": "- Scalar & Tabular: En Snowflake, los UDF pueden devolver valores escalares o tabulares. Las otras opciones no son tipos de retorno soportados en la definición de UDF.", "reference": "https://docs.snowflake.com/en/sql-reference/udf.html"}, {"id": 1216, "area": "Data Protection and Data Sharing", "question": "Which command can be performed on a Snowflake secure view?", "options": ["A) SELECT", "B) INSERT", "C) UPDATE", "D) DELETE"], "chooseN": 1, "correct": ["SELECT"], "explanation": "- SELECT: Las vistas seguras en Snowflake permiten únicamente operaciones de lectura (SELECT) para proteger la integridad y confidencialidad de los datos, impidiendo modificaciones.", "reference": "https://docs.snowflake.com/en/user-guide/views-secure.html"}, {"id": 1217, "area": "Data Protection and Data Sharing", "question": "Which database objects can be shared with Secure Data Sharing? (Choose two.)", "options": ["A) Views", "B) Materialized views", "C) External stages", "D) External tables", "E) Dynamic tables"], "chooseN": 2, "correct": ["Views", "Dynamic tables"], "explanation": "Per the docs, Dynamic tables are shareable with Secure Data Sharing, so the marked pair is incomplete. If two options must be chosen from the list, 'Views' and 'Dynamic tables' are the best-supported pair, although External tables are also shareable and the question is ambiguous.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-secure.html"}, {"id": 1218, "area": "Data Protection and Data Sharing", "question": "When a transient table in Snowflake is dropped, what happens to the table?", "options": ["A) The table is no longer available for use.", "B) The table can be undropped using Fail-safe.", "C) The table can be recovered for 1 day only and after that it is no longer available.", "D) The table can be recovered only with the assistance of Snowflake Support."], "chooseN": 1, "correct": ["The table can be recovered for 1 day only and after that it is no longer available."], "explanation": "- The table can be recovered for 1 day only and after that it is no longer available: Las tablas transitorias en Snowflake tienen Time Travel de 1 día por defecto (configurable entre 0-1 día), permitiendo su recuperación durante ese período. Después del período de Time Travel, la tabla ya no es recuperable ya que las transient tables NO tienen Fail-safe.", "reference": "https://docs.snowflake.com/en/user-guide/tables-transient.html"}, {"id": 1219, "area": "Data Protection and Data Sharing", "question": "A data provider needs to securely collaborate with data consumers who do not reside in the same region. What Snowflake sharing mechanism should be used?", "options": ["A) Direct share", "B) Data Exchange", "C) Data replication", "D) Listing"], "chooseN": 1, "correct": ["Listing"], "explanation": "For securely collaborating with data consumers in different regions, a Listing with Cross-Cloud Auto-Fulfillment is the recommended mechanism. Auto-fulfillment automatically replicates the data product to consumer regions as needed, without manual replication setup. Direct shares are limited to the same region. Data Exchanges are private hubs for groups but don't inherently solve cross-region. Data replication is a lower-level mechanism, not a sharing mechanism itself.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-intro.html"}, {"id": 1220, "area": "Snowflake Data Cloud Features & Architecture", "question": "A user needs to know the maximum value of a date field in a table, and runs the following query:\n\nselect max(o_orderdate) from ORDERS;\n\nWhich part of Snowflake architecture will this query use?", "options": ["A) Database Storage", "B) Query Processing", "C) Cloud Services", "D) Compute"], "chooseN": 1, "correct": ["Cloud Services"], "explanation": "- Cloud Services: Consultas simples de agregacion como SELECT MAX(columna) pueden resolverse directamente desde los metadatos almacenados en la capa de Cloud Services, sin necesidad de utilizar un virtual warehouse (capa de Compute). Snowflake almacena estadisticas como MIN, MAX y COUNT en los metadatos de las micro-particiones, permitiendo responder estas consultas de forma instantanea.\n- Database Storage: La capa de almacenamiento guarda los datos fisicos pero no procesa consultas.\n- Query Processing: El Query Processing (Compute) se utiliza para consultas complejas, pero las consultas basadas en metadatos se resuelven en Cloud Services.\n- Compute: Sinonimo de Query Processing. No es necesario para esta consulta simple basada en metadatos.", "reference": "https://docs.snowflake.com/en/user-guide/intro-key-concepts#cloud-services, https://docs.snowflake.com/en/user-guide/cost-understanding-compute#cloud-service-credit-usage"}, {"id": 1221, "area": "Data Protection and Data Sharing", "question": "A Snowflake user accidentally deleted a table. The table no longer exists but the session is within the data retention period. How can the table be restored using the LEAST amount of operational overhead?", "options": ["A) Clone the table schema as it existed before the table was dropped.", "B) Clone the database as it existed before the table was dropped.", "C) Recreate the table and reload the data.", "D) Run the UNDROP command against the table."], "chooseN": 1, "correct": ["Run the UNDROP command against the table."], "explanation": "- Run the UNDROP command against the table: Snowflake permite recuperar una tabla eliminada si aún está dentro del período de retención de datos.\n- Clone the table schema: Solo clona la estructura, no los datos.\n- Clone the database: Puede restaurar los datos, pero con mayor sobrecarga.\n- Recreate and reload: No es necesario si se puede usar UNDROP.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/undrop-table"}, {"id": 1222, "area": "Snowflake Data Cloud Features & Architecture", "question": "When cloning a schema, which Snowflake object will not be included in the clone?", "options": ["A) An external stage", "B) A named internal stage", "C) A task", "D) A User-Defined Function (UDF)"], "chooseN": 1, "correct": ["A named internal stage"], "explanation": "- A named internal stage: Snowflake no clona los 'Named Internal Stages' cuando se clona un esquema o una base de datos. Estos deben ser creados nuevamente en el esquema clonado.\n- An external stage: A diferencia de los 'Named Internal Stages', los 'External Stages' sí son clonados.\n- A task: Las tareas programadas (Tasks) sí son clonadas junto con el esquema.\n- A User-Defined Function (UDF): Las funciones definidas por el usuario (UDFs) también son clonadas.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/create-clone#:~:text=statement%20is%20executed.-,Not%20cloned,Internal%20(Snowflake)%20stages,-Pipes"}, {"id": 1223, "area": "Account Access and Security", "question": "Which command will change the name of shared database role r1 to r4?", "options": ["A) ALTER ROLE d1.r1 RENAME TO d1.r4;", "B) ALTER ROLE d1.r1 RENAME TO d2.r4;", "C) ALTER DATABASE ROLE d1.r1 RENAME TO d2.r4;", "D) ALTER DATABASE ROLE d1.r1 RENAME TO d1.r4;"], "chooseN": 1, "correct": ["ALTER DATABASE ROLE d1.r1 RENAME TO d1.r4;"], "explanation": "- ALTER DATABASE ROLE d1.r1 RENAME TO d1.r4: Es el comando correcto para renombrar un rol dentro de la misma base de datos.\n- ALTER ROLE: No es el comando adecuado para roles de base de datos.\n- ALTER DATABASE ROLE ... TO d2.r4: No se puede cambiar de base de datos.\n- ALTER ROLE d1.r1 RENAME TO d2.r4: Incorrecto para roles de base de datos.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/alter-database-role"}, {"id": 1224, "area": "Performance Concepts", "question": "What does the Remote Disk I/O statistic in the Query Profile indicate?", "options": ["A) Time spent reading from the result cache.", "B) Time spent reading from the virtual warehouse cache.", "C) Time when the query processing was blocked by remote disk access.", "D) The level of network activity between the Cloud Services layer and the virtual warehouse."], "chooseN": 1, "correct": ["Time when the query processing was blocked by remote disk access."], "explanation": "- Time when the query processing was blocked by remote disk access: Indica el tiempo en que Snowflake tuvo que acceder a almacenamiento remoto, impactando el rendimiento.\n- Result cache: No está relacionado con el acceso a disco.\n- Virtual warehouse cache: Se almacena en memoria, no en disco remoto.\n- Network activity: No mide actividad de red entre capas.", "reference": "https://docs.snowflake.com/en/user-guide/query-profile-storage"}, {"id": 1225, "area": "Performance Concepts", "question": "Use of which virtual warehouse or warehouse configuration will improve the performance of workloads that have large memory requirements, such as Machine Learning (ML) training using a stored procedure?", "options": ["A) Snowpark-optimized warehouse", "B) Standard warehouse", "C) Multi-cluster warehouse", "D) Serverless compute"], "chooseN": 1, "correct": ["Snowpark-optimized warehouse"], "explanation": "- Snowpark-optimized warehouse: Este tipo de warehouse está diseñado específicamente para cargas de trabajo que requieren un uso intensivo de memoria, como el entrenamiento de modelos de Machine Learning en Snowflake.\n- **Standard warehouse**: No está optimizado para operaciones de ML que demandan grandes cantidades de memoria.\n- **Multi-cluster warehouse**: Mejora la escalabilidad pero no está diseñado específicamente para cargas de ML de alto consumo de memoria.\n- **Serverless compute**: Está más orientado a tareas bajo demanda y optimización de costos, no a cargas de ML con alto uso de memoria.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-overview.html"}, {"id": 1226, "area": "Account Access and Security", "question": "Which role has the privileges to describe a share?", "options": ["A) ORGADMIN", "B) SECURITYADMIN", "C) SYSADMIN", "D) ACCOUNTADMIN"], "chooseN": 1, "correct": ["ACCOUNTADMIN"], "explanation": "- ACCOUNTADMIN: Es el único rol con privilegios para describir un recurso compartido en Snowflake. Cualquier otro rol intentándolo generará un error.\n- **ORGADMIN**: Gestiona configuraciones organizativas pero no privilegios sobre los recursos compartidos.\n- **SECURITYADMIN**: Maneja políticas de seguridad, pero no tiene acceso a la descripción de shares.\n- **SYSADMIN**: Puede gestionar bases de datos y esquemas, pero no tiene acceso específico a la descripción de shares.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/desc-share"}, {"id": 1227, "area": "Data Protection and Data Sharing", "question": "This command is executed:\nCREATE TABLE new_table CLONE existing_table COPY GRANTS;\n\nWhat will happen to the privileges of any cloned objects?", "options": ["A) The clone will only inherit SELECT privileges from the source object.", "B) The clone will inherit all privileges, including OWNERSHIP, from the source object.", "C) The clone will inherit all privileges except OWNERSHIP from the source object.", "D) The clone will not inherit any privileges from the source object."], "chooseN": 1, "correct": ["The clone will inherit all privileges except OWNERSHIP from the source object."], "explanation": "- The clone will inherit all privileges except OWNERSHIP from the source object.: Al usar COPY GRANTS en un CLONE, se copian todos los privilegios del objeto original, excepto el de OWNERSHIP.\n- **The clone will only inherit SELECT privileges**: Se copian más privilegios, no solo SELECT.\n- **The clone will inherit all privileges, including OWNERSHIP**: OWNERSHIP no se hereda con COPY GRANTS.\n- **The clone will not inherit any privileges**: COPY GRANTS asegura que se copien los privilegios, excepto OWNERSHIP.", "reference": "https://docs.snowflake.com/en/user-guide/object-clone"}, {"id": 1228, "area": "Performance Concepts", "question": "Where does Snowflake store the data output from a query that was executed in the past 24 hours?", "options": ["A) In a micro-partition", "B) In a remote disk", "C) In the result cache layer", "D) In the local disk cache layer"], "chooseN": 1, "correct": ["In the result cache layer"], "explanation": "- In the result cache layer: Snowflake almacena los resultados de consultas recientes en la capa de caché de resultados, permitiendo reutilizarlos sin recalcular.\n- **In a micro-partition**: Los micro-partitions almacenan datos en tablas, no resultados de consultas.\n- **In a remote disk**: Snowflake usa almacenamiento remoto, pero la caché de resultados no se guarda ahí.\n- **In the local disk cache layer**: Snowflake usa caching en memoria y almacenamiento distribuido, no en disco local.", "reference": "https://docs.snowflake.com/en/user-guide/querying-persisted-results.html"}, {"id": 1229, "area": "Account Access and Security", "question": "What is the default authenticator while using the JDBC driver connection in Snowflake?", "options": ["A) externalbrowser", "B) snowflake", "C) username_password_mfa", "D) snowflake_jwt"], "chooseN": 1, "correct": ["snowflake"], "explanation": "- snowflake: El autenticador predeterminado al conectarse a Snowflake mediante JDBC es 'snowflake'. Esta opción utiliza autenticación estándar con nombre de usuario y contraseña.\n\n- **externalbrowser**: Esta opción es válida, pero no es la predeterminada. Se usa para autenticación mediante un navegador web.\n\n- **snowlake**: Parece un error tipográfico de 'snowflake', por lo que no es una opción válida.\n\n- **username_password_mfa**: Requiere autenticación multifactor, pero no es la opción predeterminada.\n\n- **snowflake_jwt**: Se usa para autenticación basada en tokens JWT, pero no es la configuración por defecto.", "reference": "https://docs.snowflake.com/en/developer-guide/jdbc/jdbc-parameters#authenticator"}, {"id": 1230, "area": "Snowflake Data Cloud Features & Architecture", "question": "When will Snowflake charge credits for the use of the Cloud Services layer?", "options": ["A) Credits will be charged whenever the Cloud Services layer is used.", "B) Credits will be charged only when running a Snowflake-provisioned compute warehouse COMPUTE_WH.", "C) Credits will be charged when the daily consumption of cloud services resources exceeds 10% of the daily warehouse usage.", "D) Credits will be charged only when a virtual warehouse consumes serverless compute services."], "chooseN": 1, "correct": ["Credits will be charged when the daily consumption of cloud services resources exceeds 10% of the daily warehouse usage."], "explanation": "- Credits will be charged when the daily consumption of cloud services resources exceeds 10% of the daily warehouse usage.: Snowflake aplica la regla del 10%: solo cobra creditos adicionales por Cloud Services cuando el consumo diario de estos recursos supera el 10% del uso diario del warehouse. Por debajo de ese umbral, el uso de Cloud Services esta incluido.\n\n- Credits will be charged whenever the Cloud Services layer is used.: Incorrecto. Snowflake no cobra por todo uso de Cloud Services; existe el umbral del 10% que actua como ajuste automatico.\n\n- Credits will be charged only when running a Snowflake-provisioned compute warehouse COMPUTE_WH.: Incorrecto. El cobro de Cloud Services no depende de un warehouse especifico.\n\n- Credits will be charged only when a virtual warehouse consumes serverless compute services.: Incorrecto. Cloud Services y serverless compute son capas diferentes con modelos de cobro distintos.", "reference": "https://docs.snowflake.com/en/user-guide/credits"}, {"id": 1231, "area": "Account Access and Security", "question": "What is the primary purpose of using a masking policy in Snowflake?", "options": ["A) To protect sensitive data from unauthorized access when queries are run.", "B) To automatically encrypt sensitive data when data is stored in Snowflake.", "C) To protect multiple columns that have different data types in a given table.", "D) To protect both column-level and row-level data."], "chooseN": 1, "correct": ["To protect sensitive data from unauthorized access when queries are run."], "explanation": "- To protect sensitive data from unauthorized access when queries are run.: Las políticas de enmascaramiento en Snowflake están diseñadas para ocultar datos sensibles en función de los permisos del usuario que ejecuta la consulta.\n\n- **To automatically encrypt sensitive data when data is stored in Snowflake.**: Snowflake proporciona cifrado de datos en reposo y en tránsito, pero el enmascaramiento de datos no implica cifrado.\n\n- **To protect multiple columns that have different data types in a given table.**: Si bien una política de enmascaramiento se puede aplicar a múltiples columnas, su propósito principal es el control de acceso, no la gestión de tipos de datos.\n\n- **To protect both column-level and row-level data.**: El enmascaramiento de datos se aplica a nivel de columna, mientras que el control de acceso a nivel de fila se gestiona con políticas de acceso a filas.", "reference": "https://docs.snowflake.com/en/user-guide/security-column-level-security-masking-policies.html"}, {"id": 1232, "area": "Performance Concepts", "question": "How can the performance of queries run on external tables be optimized?", "options": ["A) Cluster the tables", "B) Create materialized views on the tables", "C) Use the metadata cache", "D) Enable the search optimization service"], "chooseN": 1, "correct": ["Create materialized views on the tables"], "explanation": "- Create materialized views on the tables: Snowflake permite la creacion de vistas materializadas sobre tablas externas para mejorar el rendimiento de las consultas. Las MVs precomputan y almacenan resultados, reduciendo la necesidad de acceder al almacenamiento externo.\n\n- Use the metadata cache: Aunque Snowflake usa metadatos en cache para mejorar algunas consultas, no es la estrategia principal para optimizar el rendimiento en tablas externas.\n\n- Cluster the tables: No es posible definir clustering keys en tablas externas en Snowflake.\n\n- Enable the search optimization service: El Search Optimization Service no se aplica a tablas externas, solo a tablas nativas de Snowflake.", "reference": "https://docs.snowflake.com/en/user-guide/tables-external-intro"}, {"id": 1233, "area": "Snowflake Data Cloud Features & Architecture", "question": "What are the recommended alternative data types in Snowflake for unsupported large object data types such as BLOB and CLOB? (Choose two.)", "options": ["A) VARIANT", "B) ARRAY", "C) BINARY", "D) OBJECT", "E) VARCHAR"], "chooseN": 2, "correct": ["BINARY", "VARCHAR"], "explanation": "- BINARY: Snowflake recomienda este tipo de dato para almacenar información binaria.\n- VARCHAR: Se recomienda para almacenar texto largo.\n- *VARIANT*: Aunque es flexible, no es la mejor opción para datos binarios o largos.\n- *ARRAY*: No es adecuado para BLOB o CLOB.\n- *OBJECT*: Es adecuado para almacenar datos semiestructurados, no BLOBs o CLOBs.", "reference": "https://docs.snowflake.com/en/sql-reference/data-types"}, {"id": 1234, "area": "Account Access and Security", "question": "A network policy set at which level will override all other network policies?", "options": ["A) Account", "B) User", "C) Security integration", "D) Database"], "chooseN": 1, "correct": ["Security integration"], "explanation": "- Security integration: Segun la documentacion de Snowflake, las network policies aplicadas a una security integration tienen la mayor prioridad y sobreescriben las politicas a nivel de usuario y de cuenta. El orden de precedencia es: Security integration > User > Account.\n- User: Una politica de red a nivel de usuario sobreescribe la politica a nivel de cuenta, pero es sobreescrita por una politica de security integration.\n- Account: Es la politica mas general. Se aplica a toda la cuenta pero puede ser sobreescrita tanto a nivel de usuario como de security integration.\n- Database: Las bases de datos no soportan network policies en Snowflake.", "reference": "https://docs.snowflake.com/en/user-guide/network-policies.html"}, {"id": 1235, "area": "Data Protection and Data Sharing", "question": "A company needs to share sales data with multiple marketing agency partners. Which Snowflake data share mechanism is recommended for this use case?", "options": ["A) A shared Amazon S3 bucket", "B) Direct share", "C) A reader account", "D) Data Exchange"], "chooseN": 1, "correct": ["Direct share"], "explanation": "Direct share is the recommended choice here because Snowflake documents it as the mechanism to share data with one or more accounts in the same region. Reader accounts are for consumers who do not already have a Snowflake account, and Data Exchange is for managing a group of invited accounts/listings.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-intro.html"}, {"id": 1236, "area": "Account Access and Security", "question": "Which role can create and manage Snowflake accounts?", "options": ["A) SYSADMIN", "B) ACCOUNTADMIN", "C) ORGADMIN", "D) SECURITYADMIN"], "chooseN": 1, "correct": ["ORGADMIN"], "explanation": "- ORGADMIN: El rol 'ORGADMIN' tiene permisos completos para gestionar cuentas dentro de la organización de Snowflake, incluyendo la creación y administración de cuentas.\n- **[SYSADMIN]**: El rol 'SYSADMIN' está más centrado en la administración de objetos dentro de Snowflake, como bases de datos, esquemas y tablas, pero no tiene permisos para gestionar cuentas.\n- **[ACCOUNTADMIN]**: Aunque el rol 'ACCOUNTADMIN' tiene privilegios significativos dentro de Snowflake, no se encarga de la gestión de cuentas a nivel organizacional.\n- **[SECURITYADMIN]**: El rol 'SECURITYADMIN' está enfocado en la administración de seguridad y roles, pero no tiene permisos para crear o gestionar cuentas.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-roles.html"}, {"id": 1237, "area": "Account Access and Security", "question": "Which security feature is available in all Snowflake editions?", "options": ["A) Data masking policies", "B) Object-level access control", "C) Object tagging", "D) Customer-managed encryption keys"], "chooseN": 1, "correct": ["Object-level access control"], "explanation": "- Object-level access control: El control de acceso a nivel de objeto está disponible en todas las ediciones de Snowflake, lo que permite a los usuarios gestionar permisos sobre objetos como tablas, vistas, y esquemas.\n- **[Data masking policies]**: Las políticas de enmascaramiento de datos no están disponibles en todas las ediciones, solo en ediciones Enterprise y superiores.\n- **[Object tagging]**: El etiquetado de objetos no está disponible en todas las ediciones, siendo una característica exclusiva de las ediciones Enterprise y superiores.\n- **[Customer-managed encryption keys]**: La gestión de claves de cifrado por parte del cliente es una característica de la edición Enterprise y superiores.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control.html"}, {"id": 1238, "area": "Data Transformations", "question": "A table named car_sales contains a single VARIANT column named src. Below is the output of the query SELECT * FROM car_sales;\n\nWhich queries will return the element 'phone number' from the data? (Choose two.)", "options": ["A) SELECT src:customer.’phone number’ FROM car_sales;", "B) SELECT SRC:customer.\"phone number\" FROM car_sales;", "C) SELECT src:customer.\"phone number\" FROM car_sales;", "D) SELECT SRC:customer.phone number FROM car_sales;", "E) SELECT SRC:CUSTOMER.\"phone number\" FROM car_sales;"], "chooseN": 2, "correct": ["SELECT SRC:customer.\"phone number\" FROM car_sales;", "SELECT src:customer.\"phone number\" FROM car_sales;"], "explanation": "- SELECT SRC:customer.\"phone number\" FROM car_sales;: La sintaxis correcta para acceder a un campo dentro de un objeto VARIANT en Snowflake es utilizando la notación de comillas dobles para los nombres con espacios.\n\n- SELECT src:customer.\"phone number\" FROM car_sales;: Al usar 'src' en minúsculas y la notación correcta de comillas dobles, esta consulta también es válida.\n\n- **SELECT src:customer.’phone number’ FROM car_sales;**: El uso de comillas simples en esta consulta no es válido para acceder a elementos en un objeto VARIANT.\n\n- **SELECT SRC:customer.phone number FROM car_sales;**: El uso de espacios sin comillas es incorrecto para acceder a campos con espacios en sus nombres.\n\n- **SELECT SRC:CUSTOMER.\"phone number\" FROM car_sales;**: Aunque el uso de comillas dobles es correcto, 'SRC' debe coincidir con el caso exacto de la columna (por lo general, Snowflake es sensible al caso).", "reference": "https://docs.snowflake.com/en/sql-reference/data-types/variant.html"}, {"id": 1239, "area": "Data Loading and Unloading", "question": "Which strings will be converted to TRUE using the TO_BOOLEAN() or CAST() functions when unloading data? (Choose two.)", "options": ["A) 0", "B) n", "C) no", "D) on", "E) yes"], "chooseN": 2, "correct": ["on", "yes"], "explanation": "- on: La cadena 'on' se convierte a TRUE cuando se utiliza la función TO_BOOLEAN() o CAST() en Snowflake.\n- yes: La cadena 'yes' también se convierte a TRUE en este caso.\n- **[0]**: '0' no se convierte a TRUE, sino a FALSE.\n- **[n]**: 'n' no se convierte a TRUE; en su lugar, Snowflake la interpretará como FALSE.\n- **[no]**: Similar a 'n', 'no' se interpretará como FALSE.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/to_boolean"}, {"id": 1240, "area": "Account Access and Security", "question": "Which authentication method requires access to a secure file that is only stored on the user's local device?", "options": ["A) Password authentication", "B) Key-pair authentication", "C) Multi-Factor Authentication (MFA)", "D) Federated authentication"], "chooseN": 1, "correct": ["Key-pair authentication"], "explanation": "- Key-pair authentication: La autenticación por par de claves (pública/privada) requiere un archivo seguro (la clave privada) almacenado en el dispositivo local del usuario.\n- **[Password authentication]**: La autenticación por contraseña no depende de un archivo seguro en el dispositivo local.\n- **[Multi-Factor Authentication (MFA)]**: MFA utiliza múltiples factores para verificar la identidad del usuario, pero no requiere un archivo local.\n- **[Federated authentication]**: La autenticación federada depende de un proveedor de identidad externo, pero no requiere un archivo seguro local.", "reference": "https://docs.snowflake.com/en/user-guide/security-auth-methods.html"}, {"id": 1241, "area": "Account Access and Security", "question": "Which drivers or connectors are supported by Snowflake? (Choose two.)", "options": ["A) Perl Connector", "B) MongoDB Rust Driver", "C) Go Snowflake Driver", "D) Cobol Driver", "E) Snowflake Connector for Python"], "chooseN": 2, "correct": ["Go Snowflake Driver", "Snowflake Connector for Python"], "explanation": "- Go Snowflake Driver: El controlador de Snowflake para Go es compatible con Snowflake.\n- Snowflake Connector for Python: El conector de Snowflake para Python también es una opción válida y soportada.\n- **[Perl Connector]**: Snowflake no tiene soporte nativo para un conector de Perl.\n- **[MongoDB Rust Driver]**: Aunque MongoDB y Rust son tecnologías populares, no están soportadas por Snowflake directamente.\n- **[Cobol Driver]**: Cobol no es un lenguaje o tecnología soportada para conectarse directamente a Snowflake.", "reference": "https://docs.snowflake.com/en/user-guide/connectors.html"}, {"id": 1242, "area": "Data Loading and Unloading", "question": "If a source table is updated while cloning is in progress, what data will be included in the cloned table?", "options": ["A) All data from the timestamp when the user runs the query.", "B) All data from the timestamp when the user session was created.", "C) All data from the timestamp when the clone statement was initiated.", "D) All data from the timestamp when the clone statement was completed."], "chooseN": 1, "correct": ["All data from the timestamp when the clone statement was initiated."], "explanation": "- All data from the timestamp when the clone statement was initiated.: Durante la operación de clonación, el dato incluido en la tabla clonada corresponde a la versión de los datos en el momento en que se inició la operación de clonación.\n- **[All data from the timestamp when the user runs the query.]**: Este timestamp no está relacionado con el inicio de la operación de clonación.\n- **[All data from the timestamp when the user session was created.]**: El inicio de la sesión del usuario no determina qué datos se clonarán.\n- **[All data from the timestamp when the clone statement was completed.]**: El proceso de clonación se basa en el momento en que se inicia, no cuando se completa.", "reference": "https://docs.snowflake.com/en/user-guide/object-clone.html"}, {"id": 1243, "area": "Data Protection and Data Sharing", "question": "The CUSTOMER table in the T1 database is accidentally dropped.\n\nWhich privileges are required to restore this table? (Choose two.)", "options": ["A) SELECT privilege on the CUSTOMER table", "B) OWNERSHIP privilege on the CUSTOMER table", "C) All privileges on the CUSTOMER table", "D) All privileges on the T1 database", "E) CREATE TABLE privilege on the T1 database"], "chooseN": 2, "correct": ["OWNERSHIP privilege on the CUSTOMER table", "CREATE TABLE privilege on the T1 database"], "explanation": "- OWNERSHIP privilege on the CUSTOMER table: Se requiere el privilegio de propiedad (OWNERSHIP) para restaurar la tabla que fue eliminada accidentalmente.\n- CREATE TABLE privilege on the T1 database: También se requiere el privilegio de crear tablas en la base de datos T1 para restaurar la tabla.\n- **[SELECT privilege on the CUSTOMER table]**: El privilegio de solo lectura (SELECT) no es suficiente para restaurar la tabla eliminada.\n- **[All privileges on the CUSTOMER table]**: Aunque tener todos los privilegios sobre la tabla podría ayudar en algunos contextos, no es suficiente para realizar la restauración.\n- **[All privileges on the T1 database]**: Tener todos los privilegios sobre la base de datos no es necesario para restaurar la tabla eliminada.", "reference": "https://docs.snowflake.com/en/user-guide/privileges.html"}, {"id": 1244, "area": "Data Protection and Data Sharing", "question": "Which ACCOUNT_USAGE view can be used to identify the masking policy assigned to an object?", "options": ["A) ACCESS_HISTORY", "B) OBJECT_DEPENDENCIES", "C) POLICY_REFERENCES", "D) TAG_REFERENCES"], "chooseN": 1, "correct": ["POLICY_REFERENCES"], "explanation": "- POLICY_REFERENCES: La vista POLICY_REFERENCES en ACCOUNT_USAGE proporciona la información sobre las políticas de enmascaramiento asignadas a los objetos en Snowflake.\n- **[ACCESS_HISTORY]**: Esta vista muestra el historial de acceso a los objetos, no las políticas de enmascaramiento.\n- **[OBJECT_DEPENDENCIES]**: Esta vista proporciona información sobre las dependencias de objetos, pero no sobre las políticas de enmascaramiento.\n- **[TAG_REFERENCES]**: Esta vista se refiere a las etiquetas aplicadas a los objetos, no a las políticas de enmascaramiento.", "reference": "https://docs.snowflake.com/en/sql-reference/account-usage/policy-references.html"}, {"id": 1245, "area": "Data Transformations", "question": "A stream object will advance its offset when it is used in which statement?", "options": ["A) SELECT", "B) INSERT", "C) CREATE", "D) COPY INTO [location]"], "chooseN": 1, "correct": ["INSERT"], "explanation": "- INSERT: El offset del stream avanzará cuando se utilice en una sentencia INSERT, ya que se consumen los datos de cambio.\n- **[SELECT]**: Una sentencia SELECT no avanzará el offset del stream, ya que solo consulta los datos sin consumirlos.\n- **[CREATE]**: La sentencia CREATE no afectará al offset del stream.\n- **[COPY INTO [location]]**: El comando COPY INTO tampoco avanzará el offset del stream, ya que no consume los datos directamente.", "reference": "https://docs.snowflake.com/en/user-guide/streams-intro.html"}, {"id": 1246, "area": "Snowflake Data Cloud Features & Architecture", "question": "Where is metadata management handled in Snowflake?", "options": ["A) Cloud Services", "B) Compute", "C) Database Storage", "D) Query Processing"], "chooseN": 1, "correct": ["Cloud Services"], "explanation": "- Cloud Services: La gestión de metadatos en Snowflake se maneja en el componente de Cloud Services, que es responsable de coordinar las operaciones de los otros componentes.\n- **[Compute]**: El componente de cómputo se encarga de ejecutar consultas, pero no maneja la gestión de metadatos.\n- **[Database Storage]**: El almacenamiento de base de datos está relacionado con la persistencia de los datos, no con la gestión de los metadatos.\n- **[Query Processing]**: El procesamiento de consultas se encarga de ejecutar las consultas SQL, pero no maneja la gestión de metadatos.", "reference": "https://docs.snowflake.com/en/user-guide/architecture.html"}, {"id": 1247, "area": "Account Access and Security", "question": "What does an integration between Snowflake and Microsoft Private Link or AWS PrivateLink support?", "options": ["A) The isolation of data within a Snowflake account.", "B) The use of Secure Data Sharing among Snowflake accounts.", "C) A Virtual Private Network (VPN) between a user and Snowflake.", "D) A secure, direct connection to Snowflake that does not use the internet."], "chooseN": 1, "correct": ["A secure, direct connection to Snowflake that does not use the internet."], "explanation": "- A secure, direct connection to Snowflake that does not use the internet.: AWS PrivateLink y Microsoft Private Link permiten conexiones seguras sin exponer datos a la Internet pública.\n- **The isolation of data within a Snowflake account.**: No está relacionado con la integración de PrivateLink.\n- **The use of Secure Data Sharing among Snowflake accounts.**: Secure Data Sharing usa enlaces internos de Snowflake y no depende de PrivateLink.\n- **A Virtual Private Network (VPN) between a user and Snowflake.**: PrivateLink no crea una VPN, sino una conexión privada.", "reference": "https://docs.snowflake.com/en/user-guide/admin-security-privatelink.html"}, {"id": 1248, "area": "Data Loading and Unloading", "question": "Which type of URL gives permanent access to files in cloud storage?", "options": ["A) Pre-signed URL", "B) Account URL", "C) Scoped URL", "D) File URL"], "chooseN": 1, "correct": ["File URL"], "explanation": "A File URL provides permanent access to files in cloud storage. It is generated using BUILD_STAGE_FILE_URL and does not expire. Users access the file by sending the File URL in a GET request with an authorization token. In contrast:\n- Pre-signed URL: Temporary access with configurable expiration (default 3600 seconds).\n- Scoped URL: Temporary user-based access for 24 hours.\n- Account URL: References the Snowflake account, not specific files.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-s3-presigned-url.html"}, {"id": 1249, "area": "Data Protection and Data Sharing", "question": "Which Snowflake data governance feature supports resource usage monitoring?", "options": ["A) Data classification", "B) Column lineage", "C) Access history", "D) Object tagging"], "chooseN": 1, "correct": ["Data classification"], "explanation": "Data classification is the best match because Snowflake documents it as tracking sensitive data for compliance, discovery, protection, and resource usage. Access history is for auditing user access history, not resource usage monitoring.", "reference": "https://docs.snowflake.com/en/user-guide/access-history.html"}, {"id": 1250, "area": "Performance Concepts", "question": "Which steps will help optimize query performance? (Choose two.)", "options": ["A) Using the query acceleration service", "B) Clustering a table", "C) Indexing a column", "D) Increasing the size of the micro-partitions", "E) Decreasing the size of the virtual warehouse"], "chooseN": 2, "correct": ["Using the query acceleration service", "Clustering a table"], "explanation": "- Using the query acceleration service: Permite acelerar consultas complejas.\n- Clustering a table: Mejora la eficiencia de búsqueda en columnas clave.\n- **Indexing a column**: Snowflake no usa índices tradicionales.\n- **Increasing the size of the micro-partitions**: No es posible, ya que Snowflake usa micro-particiones optimizadas automáticamente.\n- **Decreasing the size of the virtual warehouse**: Puede reducir costos, pero disminuiría el rendimiento.", "reference": "https://docs.snowflake.com/en/user-guide/query-acceleration-service.html, https://docs.snowflake.com/en/user-guide/tables-clustering-keys.html"}, {"id": 1251, "area": "Data Transformations", "question": "Which functions can be used to identify the data type stored in a VARIANT column? (Choose two.)", "options": ["A) IS_NULL_VALUE", "B) IS_DATE_VALUE", "C) IS_GEOGRAPHY", "D) IS_XML", "E) IS_JSON"], "chooseN": 2, "correct": ["IS_NULL_VALUE", "IS_DATE_VALUE"], "explanation": "- IS_NULL_VALUE: Funcion valida de Snowflake que verifica si un valor VARIANT es un JSON null (diferente de SQL NULL). Util para identificar valores nulos en datos semi-estructurados.\n- IS_DATE_VALUE: Funcion valida de Snowflake que verifica si un valor almacenado en un VARIANT puede convertirse a tipo DATE. Permite identificar si el dato es de tipo fecha.\n- IS_GEOGRAPHY: Esta funcion no existe como funcion estandar de Snowflake para VARIANT.\n- IS_XML: Esta funcion no existe en Snowflake. Para validar XML se utiliza CHECK_XML.\n- IS_JSON: Esta funcion no existe en Snowflake. Para validar JSON se utiliza CHECK_JSON.\n\nLas funciones IS_* validas de Snowflake para VARIANT incluyen: IS_ARRAY, IS_BINARY, IS_BOOLEAN, IS_CHAR, IS_DATE, IS_DATE_VALUE, IS_DECIMAL, IS_DOUBLE, IS_INTEGER, IS_NULL_VALUE, IS_OBJECT, IS_REAL, IS_TIME, IS_TIMESTAMP_LTZ, IS_TIMESTAMP_NTZ, IS_TIMESTAMP_TZ.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/is_null_value, https://docs.snowflake.com/en/sql-reference/functions/is_date_value"}, {"id": 1252, "area": "Data Protection and Data Sharing", "question": "What is the MINIMUM Snowflake edition that supports data sharing?", "options": ["A) Standard", "B) Enterprise", "C) Business Critical", "D) Virtual Private Snowflake (VPS)"], "chooseN": 1, "correct": ["Standard"], "explanation": "- Standard: Snowflake permite compartir datos entre cuentas de Snowflake a partir de la edición Standard...", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-intro.html"}, {"id": 1253, "area": "Data Protection and Data Sharing", "question": "Who can access the data published in a Data Exchange?", "options": ["A) Only the data provider who published the data", "B) Any Snowflake user, regardless of their role or permissions", "C) Any user who has been provided with a unique Data Exchange URL", "D) Only the users that the data provider has invited to the Data Exchange"], "chooseN": 1, "correct": ["Only the users that the data provider has invited to the Data Exchange"], "explanation": "- Only the users that the data provider has invited to the Data Exchange: El intercambio de datos en Snowflake requiere que el proveedor invite explícitamente a los usuarios...", "reference": "https://docs.snowflake.com/en/user-guide/data-exchange.html"}, {"id": 1254, "area": "Data Protection and Data Sharing", "question": "How can data be shared between two users who have different Snowflake accounts?", "options": ["A) Create a share with the same name as the original database.", "B) Create a share and ensure the proper role is assigned to the share.", "C) Ensure both users’ accounts are using the same cloud provider and region.", "D) Use the PUT command to create a shared account."], "chooseN": 1, "correct": ["Create a share and ensure the proper role is assigned to the share."], "explanation": "- Create a share and ensure the proper role is assigned to the share.: En Snowflake, se utiliza el objeto 'SHARE' para compartir datos entre cuentas...", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-provider.html"}, {"id": 1255, "area": "Performance Concepts", "question": "Which view will show the MOST recent information about table-level storage utilization?", "options": ["A) The TABLE_STORAGE_METRICS view in a Snowflake data share", "B) The TABLE_STORAGE_METRICS view in the ACCOUNT_USAGE schema", "C) The TABLE_STORAGE_METRICS view in the INFORMATION_SCHEMA", "D) The STORAGE_USAGE_HISTORY view in the INFORMATION_SCHEMA"], "chooseN": 1, "correct": ["The TABLE_STORAGE_METRICS view in the INFORMATION_SCHEMA"], "explanation": "- The TABLE_STORAGE_METRICS view in the INFORMATION_SCHEMA: Esta vista proporciona detalles sobre el uso de almacenamiento a nivel de tabla en tiempo real...", "reference": "https://docs.snowflake.com/en/sql-reference/account-usage/table-storage-metrics.html"}, {"id": 1256, "area": "Performance Concepts", "question": "A user executed a SELECT query in Snowsight which returned a 1 GB result set. The user then downloads the files. What will occur?", "options": ["A) The result set will be successfully downloaded from Snowsight.", "B) The result set will be automatically compressed and the data will be downloaded as individual files.", "C) The download will fail because the result set needs to be broken up into files no greater than 50 MB before downloading.", "D) The download will result in an error because the filters of the SELECT query need to be changed so that Snowsight returns a smaller result set."], "chooseN": 1, "correct": ["The result set will be successfully downloaded from Snowsight."], "explanation": "The correct answer is: The result set will be successfully downloaded from Snowsight.. The official doc states: 'Snowflake does not limit the size of files exported for query results.' There is no 50 MB limit. A 1 GB result set will be downloaded successfully. The correct answer is A, not C. Reference: https://docs.snowflake.com/en/user-guide/ui-snowsight-query#download-your-results", "reference": "https://docs.snowflake.com/en/user-guide/ui-snowsight-download-results.html"}, {"id": 1257, "area": "Data Loading and Unloading", "question": "Which command can be used to unload data into an external named stage in Snowflake?", "options": ["A) PUT", "B) CREATE [object]", "C) COPY INTO [table]", "D) COPY INTO [location]"], "chooseN": 1, "correct": ["COPY INTO [location]"], "explanation": "- **COPY INTO [location]**: This is the correct command for unloading data from Snowflake into an external stage.\n- *A*: The PUT command is used for uploading files, not unloading data.\n- *B*: CREATE [object] is not related to unloading data.\n- *C*: COPY INTO [table] is used for loading data into Snowflake, not unloading.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-location.html"}, {"id": 1258, "area": "Data Loading and Unloading", "question": "Which file format option should be used when unloading data into a stage to create a CSV or a JSON file?", "options": ["A) PARSE_HEADER", "B) TRIM_SPACE", "C) FILE_EXTENSION", "D) SKIP_HEADER"], "chooseN": 1, "correct": ["FILE_EXTENSION"], "explanation": "FILE_EXTENSION is a COPY INTO option that specifies the extension for files unloaded to a stage (e.g., .csv or .json). SKIP_HEADER is a CSV format option used during data loading to skip header rows, not for unloading. PARSE_HEADER is for loading data with automatic column detection. TRIM_SPACE controls whitespace trimming during loading.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/create-file-format"}, {"id": 1259, "area": "Performance Concepts", "question": "When creating a virtual warehouse, what setting should be used to avoid both over-provisioning resources and auto-scaling when there is increased concurrency?", "options": ["A) WAREHOUSE_SIZE = LARGE", "B) WAREHOUSE_TYPE = SNOWPARK-OPTIMIZED", "C) MAX_CLUSTER_COUNT = 10", "D) ENABLE_QUERY_ACCELERATION = TRUE"], "chooseN": 1, "correct": ["ENABLE_QUERY_ACCELERATION = TRUE"], "explanation": "The Query Acceleration Service (QAS) offloads portions of query processing to shared serverless compute resources, handling concurrency spikes without provisioning additional warehouse clusters. This avoids both over-provisioning and auto-scaling. MAX_CLUSTER_COUNT = 10 enables multi-cluster auto-scaling, which the question explicitly asks to avoid. WAREHOUSE_SIZE = LARGE only changes the fixed size and does not address concurrency. SNOWPARK-OPTIMIZED is a warehouse type for memory-intensive workloads, not a concurrency solution.", "reference": "https://docs.snowflake.com/en/user-guide/query-acceleration-service"}, {"id": 1260, "area": "Data Protection and Data Sharing", "question": "What is the MINIMUM Snowflake edition required to add masking policies to selectively mask plain-text data in a table or in view columns at query time?", "options": ["A) Standard", "B) Enterprise", "C) Business Critical", "D) Virtual Private Snowflake (VPS)"], "chooseN": 1, "correct": ["Enterprise"], "explanation": "- Enterprise: Segun la documentacion oficial de Snowflake, Dynamic Data Masking requiere la edicion Enterprise como minimo. La documentacion indica: 'Para implementar una politica de masking, debe utilizar una cuenta de edicion Enterprise o superior.'\n- Standard: La edicion Standard no incluye Dynamic Data Masking.\n- Business Critical: Aunque Business Critical si incluye masking policies, no es la edicion MINIMA requerida. Enterprise es suficiente.\n- Virtual Private Snowflake (VPS): VPS incluye masking policies, pero es la edicion mas alta y no es la minima requerida.", "reference": "https://docs.snowflake.com/en/user-guide/security-column-ddm-intro, https://docs.snowflake.com/en/user-guide/intro-editions#enterprise-edition"}, {"id": 1261, "area": "Data Loading and Unloading", "question": "Which command can be used to determine if data from a file has been previously loaded?", "options": ["A) COPY_HISTORY", "B) DATA_TRANSFER_HISTORY", "C) WAREHOUSE_LOAD_HISTORY", "D) STAGE_STORAGE_USAGE_HISTORY"], "chooseN": 1, "correct": ["COPY_HISTORY"], "explanation": "- COPY_HISTORY: El comando COPY_HISTORY permite revisar el historial de cargas de datos, lo que ayuda a verificar si los datos de un archivo han sido previamente cargados. Las otras opciones no están diseñadas para realizar esta función.", "reference": "https://docs.snowflake.com/en/user-guide/data-loading-history.html"}, {"id": 1262, "area": "Performance Concepts", "question": "What does Snowflake recommend when configuring the auto-suspend parameter for a virtual warehouse?", "options": ["A) Set auto-suspend to the maximum possible duration for optimal resource utilization.", "B) Enable auto-suspend to a high value to maximize warehouse availability.", "C) Enable auto-suspend to a low value to minimize credit consumption during inactivity.", "D) Disable auto-suspend to ensure continuous availability of the warehouse."], "chooseN": 1, "correct": ["Enable auto-suspend to a low value to minimize credit consumption during inactivity."], "explanation": "- Enable auto-suspend to a low value to minimize credit consumption during inactivity.: Esta es la recomendación de Snowflake para minimizar el consumo de créditos cuando el almacén está inactivo. Las otras opciones no abordan la optimización de los recursos durante la inactividad.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-auto-suspend.html"}, {"id": 1263, "area": "Data Loading and Unloading", "question": "Which URL identifies the database, schema, stage, and file path to a set of files for accessing the unstructured data files in Snowflake?", "options": ["A) Scoped URL", "B) File URL", "C) Pre-signed URL", "D) HTTPS URL"], "chooseN": 1, "correct": ["File URL"], "explanation": "- File URL: Un 'File URL' es el tipo de URL que Snowflake usa para acceder a archivos de datos no estructurados almacenados en una etapa. Las otras opciones no son utilizadas específicamente para este propósito.", "reference": "https://docs.snowflake.com/en/user-guide/stages-file-format.html"}, {"id": 1264, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which Snowflake feature or service is primarily used for managing and monitoring data and user activities?", "options": ["A) Snowsight", "B) SnowSQL", "C) Snowflake Marketplace", "D) Streamlit"], "chooseN": 1, "correct": ["Snowsight"], "explanation": "- Snowsight: Snowsight es la interfaz de usuario y herramienta de análisis de Snowflake utilizada para gestionar y monitorear datos y actividades de los usuarios. Las otras opciones no se utilizan principalmente para este propósito.", "reference": "https://docs.snowflake.com/en/user-guide/snowsight.html"}, {"id": 1265, "area": "Data Loading and Unloading", "question": "Which URL type should be used for custom applications that need to access unstructured data files?", "options": ["A) Scoped URL", "B) File URL", "C) Pre-signed URL", "D) Relative URL"], "chooseN": 1, "correct": ["File URL"], "explanation": "The correct answer is: File URL. The docs state File URL is 'Ideal for custom applications that require access to unstructured data files.' Pre-signed URL is described as ideal for BI applications or reporting tools. The correct answer is B (File URL), not C (Pre-signed URL). Reference: https://docs.snowflake.com/en/user-guide/unstructured-intro", "reference": "https://docs.snowflake.com/en/sql-reference/functions/get_presigned_url"}, {"id": 1266, "area": "Data Transformations", "question": "When would creating and using a standard view be preferable to using a materialized view?", "options": ["A) The underlying query of the view takes a lot of time to run.", "B) The underlying query of the view is resource-intensive.", "C) The underlying query of the view is run on large data sets.", "D) The view results change often."], "chooseN": 1, "correct": ["The view results change often."], "explanation": "- The view results change often.: Cuando los resultados de la vista cambian frecuentemente, una vista estándar es más adecuada, ya que las vistas materializadas no se actualizan automáticamente con cada cambio. Las otras opciones hacen que las vistas materializadas sean más apropiadas.", "reference": "https://docs.snowflake.com/en/user-guide/views.html"}, {"id": 1267, "area": "Account Access and Security", "question": "When using a direct share, what privileges does a role need to control access to the objects that are in a share that is using database roles? (Choose two.)", "options": ["A) CREATE PIPE", "B) CREATE STREAM", "C) CREATE TASK", "D) CREATE SHARE", "E) CREATE DATABASE"], "chooseN": 2, "correct": ["CREATE SHARE", "CREATE DATABASE"], "explanation": "- **CREATE SHARE y CREATE DATABASE**: Para controlar el acceso a los objetos en una compartición utilizando roles de base de datos, es necesario tener los privilegios de 'CREATE SHARE' y 'CREATE DATABASE'. Las otras opciones no son relevantes en este caso.", "reference": "https://docs.snowflake.com/en/user-guide/shares-privileges.html"}, {"id": 1268, "area": "Data Protection and Data Sharing", "question": "What actions can be performed by consumers of shared databases? (Choose two.)", "options": ["A) Create a clone of the database.", "B) Edit the comments for the database.", "C) Query Time Travel data on the database.", "D) Create streams on objects in the database.", "E) Query data from the objects in the database."], "chooseN": 2, "correct": ["Query data from the objects in the database.", "Create streams on objects in the database."], "explanation": "Consumers of shared databases can:\n- Query data from shared objects: This is the primary action available to consumers.\n- Create streams on shared objects: Consumers can create streams in their own databases to track DML changes on shared tables or views (requires the provider to enable change tracking).\nConsumers cannot clone shared databases, edit comments, or query Time Travel data on shared objects.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-consumers.html"}, {"id": 1269, "area": "Account Access and Security", "question": "A Snowflake user is actively logged into Snowflake when a user-level network policy is assigned to that user.\n\nWhat will Snowflake do if the user's IP address does not match the user-level network policy rules?", "options": ["A) Log the user out.", "B) Deactivate the network policy.", "C) Prevent the user from executing additional queries.", "D) Allow the user to continue until the session or login token expires."], "chooseN": 1, "correct": ["Prevent the user from executing additional queries."], "explanation": "The correct answer is: Prevent the user from executing additional queries.. The doc states: 'when a user-level network policy is associated with the user and the user is already logged into Snowflake, if the user's network location does not match the user-level network policy rules, Snowflake prevents the user from executing further queries.' The correct answer is C, not D. Reference: https://docs.snowflake.com/en/user-guide/network-policies#activate-network-policies-for-individual-users", "reference": "https://docs.snowflake.com/en/user-guide/security-network-policies.html"}, {"id": 1270, "area": "Account Access and Security", "question": "At what level is the ALLOW_CLIENT_MFA_CACHING parameter configurable in Snowflake?", "options": ["A) User", "B) Session", "C) Account", "D) Virtual warehouse"], "chooseN": 1, "correct": ["Account"], "explanation": "- Account: El parámetro ALLOW_CLIENT_MFA_CACHING se configura a nivel de la cuenta para habilitar el almacenamiento en caché de la autenticación multifactorial (MFA). Las otras opciones no son aplicables para este parámetro.", "reference": "https://docs.snowflake.com/en/user-guide/security-mfa.html"}, {"id": 1271, "area": "Data Protection and Data Sharing", "question": "How can data be securely shared across regions and cloud platforms in Snowflake?", "options": ["A) Use Cross-Cloud Auto-Fulfillment.", "B) Use replication.", "C) Use the CREATE SHARE command.", "D) Use the GRANT command to share selected objects."], "chooseN": 1, "correct": ["Use replication."], "explanation": "Replication is the documented method to securely share data across regions and cloud platforms. The Snowflake docs on cross-region sharing are built around replication groups. CREATE SHARE only works for sharing within the same region (direct shares). Cross-Cloud Auto-Fulfillment via listings is a newer alternative. The GRANT command manages privileges, not cross-region sharing.", "reference": "https://docs.snowflake.com/en/user-guide/replication-intro.html"}, {"id": 1272, "area": "Performance Concepts", "question": "What factors affect how many credits will be charged for virtual warehouse usage? (Choose two.)", "options": ["A) Number of queries being run", "B) Number of users running queries", "C) Snowflake edition being used", "D) Size of the warehouse", "E) Length of time the warehouse runs"], "chooseN": 2, "correct": ["Size of the warehouse", "Length of time the warehouse runs"], "explanation": "- **Size of the warehouse y Length of time the warehouse runs]**: El tamaño del almacén y el tiempo de ejecución son los factores principales que afectan la cantidad de créditos utilizados. Las otras opciones no afectan tanto el uso de créditos.", "reference": "https://docs.snowflake.com/en/user-guide/credits-usage.html"}, {"id": 1273, "area": "Performance Concepts", "question": "What privilege is required to view the load statistics on a virtual warehouse?", "options": ["A) MODIFY", "B) OPERATE", "C) MONITOR", "D) USAGE"], "chooseN": 1, "correct": ["MONITOR"], "explanation": "- MONITOR: El privilegio 'MONITOR' es el necesario para ver las estadísticas de carga de un almacén virtual. Las otras opciones no permiten ver esta información.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-usage.html"}, {"id": 1274, "area": "Performance Concepts", "question": "Which command will indicate whether a materialized view is being used in a query?", "options": ["A) SHOW", "B) DESCRIBE", "C) EXPLAIN", "D) USE"], "chooseN": 1, "correct": ["EXPLAIN"], "explanation": "- EXPLAIN: El comando `EXPLAIN` en Snowflake permite analizar el plan de ejecución de una consulta, lo que incluye la verificación de si una vista materializada está siendo utilizada en la consulta. Esto es útil para la optimización del rendimiento y para entender cómo Snowflake ejecuta la consulta.\n- **SHOW**: El comando `SHOW` se usa para listar objetos dentro de Snowflake (como tablas, vistas o usuarios), pero no proporciona información sobre el uso de vistas materializadas en una consulta.\n- **DESCRIBE**: `DESCRIBE` proporciona detalles sobre la estructura de un objeto, como una tabla o una vista, pero no muestra si una vista materializada ha sido utilizada en una consulta específica.\n- **USE**: `USE` cambia el contexto de base de datos o esquema en Snowflake, pero no ofrece información sobre vistas materializadas en consultas.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/explain"}, {"id": 1275, "area": "Performance Concepts", "question": "A size X-Small virtual warehouse ran for 90 seconds, and was shut down. The warehouse was then run for another 30 seconds before being shut down again.\n\nHow many seconds will be billed?", "options": ["A) 90 seconds", "B) 120 seconds", "C) 150 seconds", "D) 180 seconds"], "chooseN": 1, "correct": ["150 seconds"], "explanation": "Snowflake factura los warehouses por segundo con un minimo de 60 segundos por cada inicio/reanudacion. Primera ejecucion: 90 segundos -> se facturan 90 segundos (ya supera el minimo de 60s). Segunda ejecucion: 30 segundos -> se facturan 60 segundos (minimo por inicio). Total facturado: 90 + 60 = 150 segundos.", "reference": "https://docs.snowflake.com/en/user-guide/cost-understanding-overall"}, {"id": 1276, "area": "Performance Concepts", "question": "Which virtual warehouse configuration is recommended specifically for a steady workload that has no execution lag?", "options": ["A) AUTO_RESUME = FALSE", "B) AUTO_SUSPEND = 0", "C) STATEMENT_TIMEOUT_IN_SECONDS = 3600", "D) MIN_CLUSTER_COUNT = 1 - MAX_CLUSTER_COUNT = 3"], "chooseN": 1, "correct": ["AUTO_SUSPEND = 0"], "explanation": "- AUTO_SUSPEND = 0: Configurar `AUTO_SUSPEND = 0` significa que el warehouse virtual no se suspenderá automáticamente. Esto es ideal para cargas de trabajo constantes sin interrupciones, ya que evita la latencia asociada con la reactivación del warehouse tras una suspensión.\n- **AUTO_RESUME = FALSE**: Deshabilitar `AUTO_RESUME` impediría que el warehouse se reactive automáticamente cuando se ejecuten nuevas consultas, lo que podría causar retrasos en la ejecución.\n- **STATEMENT_TIMEOUT_IN_SECONDS = 3600**: Este parámetro solo controla el tiempo máximo permitido para la ejecución de una consulta antes de ser cancelada, sin relación directa con evitar lag en una carga de trabajo continua.\n- **MIN_CLUSTER_COUNT = 1 - MAX_CLUSTER_COUNT = 3**: Configurar múltiples clústeres permite escalar horizontalmente, pero no garantiza la eliminación del lag en cargas de trabajo constantes. El tiempo de reactivación del warehouse aún podría generar retrasos si se suspende.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/create-warehouse"}, {"id": 1277, "area": "Account Access and Security", "question": "Which role allows a Snowflake user to view table-level storage utilization information from the TABLE_STORAGE_METRICS view by default?", "options": ["A) ACCOUNTADMIN", "B) SECURITYADMIN", "C) SYSADMIN", "D) USERADMIN"], "chooseN": 1, "correct": ["ACCOUNTADMIN"], "explanation": "- ACCOUNTADMIN: Este rol tiene los privilegios más altos en Snowflake y, por defecto, permite acceder a la vista TABLE_STORAGE_METRICS para visualizar información de uso de almacenamiento a nivel de tabla.\n- **SECURITYADMIN**: Aunque gestiona permisos y accesos, no tiene acceso predeterminado a métricas de almacenamiento.\n- **SYSADMIN**: Se enfoca en la administración de objetos dentro del sistema, pero no incluye acceso automático a métricas de almacenamiento.\n- **USERADMIN**: Su rol se centra en la gestión de usuarios y roles, sin acceso a métricas de almacenamiento.", "reference": "https://docs.snowflake.com/en/sql-reference/info-schema/table_storage_metrics"}, {"id": 1278, "area": "Data Transformations", "question": "This statement is run:\n\nSELECT { 'key' : { 'subkey': 'value' }} mycolumn;\n\nWhat notations will retrieve the 'value' from the VARIANT column? (Choose two.)", "options": ["A) mycolumn.key.subkey", "B) mycolumn.key:subkey", "C) mycolumn:key.subkey", "D) mycolumn['key'].subkey", "E) mycolumn:key:subkey"], "chooseN": 2, "correct": ["mycolumn:key.subkey", "mycolumn:key:subkey"], "explanation": "Snowflake documentation supports nested semi-structured access using `:<level1>.<level2>` and also supports `:` as a path separator in path notation. Therefore `mycolumn:key.subkey` and `mycolumn:key:subkey` are the best matches from the options.", "reference": "https://docs.snowflake.com/en/user-guide/querying-semistructured#traversing-semi-structured-data"}, {"id": 1279, "area": "Performance Concepts", "question": "Which multi-cluster virtual warehouse setting will help process queued queries as quickly as possible?", "options": ["A) An economy scaling policy", "B) A standard scaling policy", "C) Maximized mode", "D) Auto-scale mode"], "chooseN": 1, "correct": ["Auto-scale mode"], "explanation": "- Auto-scale mode: Esta opción permite que Snowflake inicie automáticamente clústeres adicionales según la carga de trabajo, reduciendo significativamente el tiempo de espera de las consultas en cola.\n- **An economy scaling policy**: Prioriza la optimización de costos sobre el rendimiento, lo que puede provocar mayor latencia en la ejecución de consultas en cola.\n- **A standard scaling policy**: Aunque es más rápido que el modo Economy, la política estándar no es la más eficiente cuando se trata de reducir el tiempo de espera, ya que Snowflake prioriza la conservación de créditos en lugar de lanzar nuevos clústeres de inmediato.\n- **Maximized mode**: No es una configuración específica para la escalabilidad automática en Snowflake; el auto-scale mode es la mejor opción para minimizar el tiempo en cola.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-multicluster#enabling-multi-cluster-warehouses"}, {"id": 1280, "area": "Performance Concepts", "question": "Which Snowflake tool provides detailed execution statistics of a query with no cost to the user?", "options": ["A) Query Profile", "B) Query History", "C) Visualization Chart", "D) Query Acceleration Service"], "chooseN": 1, "correct": ["Query Profile"], "explanation": "- Query Profile: Snowflake proporciona 'Query Profile' para analizar en detalle la ejecución de una consulta, incluyendo estadísticas de rendimiento y optimización. Aunque la ejecución de la consulta consume créditos, el perfilado en sí no tiene costo adicional.\n- **Query History**: Permite ver el historial de consultas ejecutadas, pero no ofrece estadísticas detalladas de ejecución como lo hace 'Query Profile'.\n- **Visualization Chart**: No es una herramienta específica de Snowflake para el análisis de ejecución de consultas.\n- **Query Acceleration Service**: Este servicio se enfoca en acelerar consultas grandes mediante la optimización automática, pero no proporciona estadísticas detalladas de ejecución.", "reference": "https://docs.snowflake.com/en/user-guide/ui-query-profile"}, {"id": 1281, "area": "Performance Concepts", "question": "How can a Snowflake user access near real-time metrics that can be used to identify queries affected by disk spilling?", "options": ["A) Use a load monitoring chart.", "B) Review the history section of the Query Profile.", "C) Implement a Snowsight dashboard.", "D) Use a worksheet."], "chooseN": 1, "correct": ["Review the history section of the Query Profile."], "explanation": "- Review the history section of the Query Profile.: La sección de historial del 'Query Profile' en Snowflake permite analizar métricas en tiempo casi real sobre la ejecución de consultas, incluyendo el 'disk spilling', que ocurre cuando los datos no caben en memoria y deben ser escritos en disco, afectando el rendimiento.\n- **Use a load monitoring chart.**: No es una herramienta específica de Snowflake para identificar problemas de 'disk spilling' en consultas individuales.\n- **Implement a Snowsight dashboard.**: Snowsight permite monitorear algunas métricas generales, pero no proporciona detalles de bajo nivel sobre el uso del disco en consultas individuales.\n- **Use a worksheet.**: Los 'worksheets' permiten ejecutar consultas y scripts en Snowflake, pero no ofrecen información detallada sobre métricas de ejecución.", "reference": "https://docs.snowflake.com/en/user-guide/ui-query-profile#query-profile-overview"}, {"id": 1282, "area": "Data Loading and Unloading", "question": "Which table type is used in the file processing pipeline to process unstructured data in Snowflake?", "options": ["A) Temporary", "B) Directory", "C) Standard", "D) Transient"], "chooseN": 1, "correct": ["Directory"], "explanation": "Directory tables are implicit objects layered on a stage that store file-level metadata about data files. They are specifically designed for building file processing pipelines for unstructured data in Snowflake. Combined with streams and tasks, directory tables track new files on a stage and trigger automated processing. Standard tables are the default type for structured data. Temporary tables only exist within a session. Transient tables do not maintain Time Travel history but are not designed for unstructured file processing.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-dirtables-pipeline"}, {"id": 1283, "area": "Performance Concepts", "question": "Which metrics in the QUERY_HISTORY Account Usage View can be used to assess the pruning efficiency of a query? (Choose two.)", "options": ["A) EXECUTION_TIME", "B) PARTITIONS_TOTAL", "C) COMPILATION_TIME", "D) TOTAL_ELAPSED_TIME", "E) PARTITIONS_SCANNED"], "chooseN": 2, "correct": ["PARTITIONS_TOTAL", "PARTITIONS_SCANNED"], "explanation": "- PARTITIONS_TOTAL: Este valor representa el número total de particiones disponibles para la consulta. Es útil para evaluar la eficiencia del 'pruning', ya que se compara con las particiones realmente escaneadas.\n- PARTITIONS_SCANNED: Indica cuántas particiones se han leído efectivamente durante la ejecución de la consulta. Cuanto menor sea este número en comparación con PARTITIONS_TOTAL, más eficiente será el pruning de la consulta.\n- **EXECUTION_TIME**: Representa el tiempo total de ejecución de la consulta, pero no proporciona información específica sobre la eficiencia del pruning.\n- **COMPILATION_TIME**: Mide el tiempo de compilación de la consulta antes de ejecutarse, sin relación directa con la eficiencia del pruning.\n- **TOTAL_ELAPSED_TIME**: Es el tiempo total que tomó la consulta desde su inicio hasta su finalización, incluyendo compilación y ejecución, pero no se enfoca en la eficiencia del pruning.", "reference": "https://docs.snowflake.com/en/sql-reference/account-usage/query_history"}, {"id": 1284, "area": "Data Protection and Data Sharing", "question": "How should a data provider securely share Snowflake objects with a data consumer who does not have a Snowflake account?", "options": ["A) Give the consumer owner's rights on the provider's Snowflake account.", "B) Unload the data into the consumer's cloud storage.", "C) Create a reader account for the consumer.", "D) Create and replicate a share, then give the consumer access to the replication."], "chooseN": 1, "correct": ["Create a reader account for the consumer."], "explanation": "- Create a reader account for the consumer.: Snowflake permite a los proveedores de datos crear 'Reader Accounts' para consumidores que no tienen una cuenta de Snowflake. Esto les permite acceder de forma segura a los datos sin necesidad de gestionar su propia infraestructura en Snowflake.\n- **Give the consumer owner's rights on the provider's Snowflake account.**: Compartir el control total de la cuenta Snowflake con el consumidor no es una práctica segura ni recomendada.\n- **Unload the data into the consumer's cloud storage.**: Si bien exportar los datos a un almacenamiento externo es una opción, no es la solución más segura ni eficiente en comparación con un 'Reader Account', que permite un acceso más controlado y directo a los datos en Snowflake.\n- **Create and replicate a share, then give the consumer access to the replication.**: La replicación de shares solo funciona entre cuentas Snowflake existentes, por lo que no es una opción viable para consumidores sin cuenta en Snowflake.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-reader-accounts"}, {"id": 1285, "area": "Data Loading and Unloading", "question": "When unloading Snowflake relational data to a Parquet file format, why should the PARTITION BY clause be used?", "options": ["A) It will provide a mechanism to encrypt each micro-partition with a unique key.", "B) It will guarantee data integrity by splitting the data into smaller, manageable chunks.", "C) It will increase storage efficiency by automatically compressing data based on access patterns.", "D) It will optimize query performance by filtering relevant partitions without scanning the entire dataset."], "chooseN": 1, "correct": ["It will optimize query performance by filtering relevant partitions without scanning the entire dataset."], "explanation": "- It will optimize query performance by filtering relevant partitions without scanning the entire dataset.: La cláusula PARTITION BY en la exportación a formato Parquet permite organizar los datos en particiones lógicas, facilitando la recuperación eficiente mediante 'pruning'. Esto mejora el rendimiento de las consultas al evitar la exploración de datos innecesarios.\n- **It will provide a mechanism to encrypt each micro-partition with a unique key.**: La partición de datos no está relacionada con la encriptación de micro-particiones.\n- **It will guarantee data integrity by splitting the data into smaller, manageable chunks.**: La integridad de los datos no depende de la partición, sino de la estructura y el manejo adecuado de los archivos Parquet.\n- **It will increase storage efficiency by automatically compressing data based on access patterns.**: Si bien Parquet usa compresión eficiente, la cláusula PARTITION BY no está directamente relacionada con la compresión basada en patrones de acceso.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-location#partition-by-clause, https://www.snowflake.com/guides/what-parquet"}, {"id": 1286, "area": "Performance Concepts", "question": "How can a user access information about a query execution plan without consuming virtual warehouse compute resources?", "options": ["A) Use the EXPLAIN function.", "B) Review the Query Profile metrics.", "C) Review the data in the Account_Usage view.", "D) Use the Snowsight dashboard."], "chooseN": 1, "correct": ["Use the EXPLAIN function."], "explanation": "- Use the EXPLAIN function.: El comando `EXPLAIN` en Snowflake permite obtener el plan de ejecución lógico de una consulta sin ejecutarla, lo que significa que no consume recursos de un warehouse virtual. Sin embargo, sí utiliza créditos de servicio en la nube para la compilación de la consulta.\n- **Review the Query Profile metrics.**: Aunque el Query Profile proporciona información detallada sobre la ejecución de una consulta, requiere que la consulta haya sido ejecutada previamente, lo que implica el uso de recursos del warehouse.\n- **Review the data in the Account_Usage view.**: La vista `Account_Usage` almacena datos históricos sobre consultas ejecutadas, pero no permite visualizar un plan de ejecución antes de la ejecución de una consulta.\n- **Use the Snowsight dashboard.**: Snowsight proporciona herramientas de monitoreo y visualización, pero no permite acceder a planes de ejecución de consultas sin consumir recursos de computación.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/explain"}, {"id": 1287, "area": "Data Loading and Unloading", "question": "If a query is being used to unload a 1 TB table into a stage, which DML operator will be shown in the Query Profile?", "options": ["A) INSERT", "B) UNLOAD", "C) COPY", "D) UPDATE"], "chooseN": 1, "correct": ["COPY"], "explanation": "- COPY: En Snowflake, la operación `COPY INTO` se utiliza para exportar datos desde una tabla a un 'stage'. En el Query Profile, la operación mostrada para esta acción es `COPY`, ya que `COPY INTO` es el comando estándar para la descarga de datos en Snowflake.\n- **INSERT**: `INSERT` es una operación DML utilizada para agregar datos a una tabla, no para exportarlos.\n- **UNLOAD**: Aunque el término 'unload' describe el proceso de exportación, no es un operador específico que aparezca en el Query Profile de Snowflake.\n- **UPDATE**: `UPDATE` es una operación DML utilizada para modificar datos en una tabla, pero no está relacionada con la descarga de datos a un stage.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-location"}, {"id": 1288, "area": "Account Access and Security", "question": "At what levels can network policies be defined in Snowflake? (Choose two.)", "options": ["A) User", "B) Account", "C) Table", "D) Schema", "E) Database"], "chooseN": 2, "correct": ["User", "Account"], "explanation": "- User: Las políticas de red en Snowflake se pueden definir a nivel de usuario, permitiendo restringir el acceso según la dirección IP del cliente que intenta conectarse.\n- Account: También se pueden establecer a nivel de cuenta para aplicar restricciones de acceso de manera global a todos los usuarios dentro de la cuenta de Snowflake.\n- **Table**: Las políticas de red no se pueden aplicar a nivel de tabla, ya que están diseñadas para controlar el acceso a Snowflake, no a datos específicos dentro de una tabla.\n- **Schema**: No es un nivel válido para definir políticas de red en Snowflake.\n- **Database**: Aunque las bases de datos contienen esquemas y tablas, las políticas de red no se definen a este nivel.", "reference": "https://docs.snowflake.com/en/user-guide/network-policies"}, {"id": 1289, "area": "Data Loading and Unloading", "question": "A Snowflake table that is loaded using a Kafka connector has a schema consisting of which two VARIANT columns? (Choose two.)", "options": ["A) RECORD_TIMESTAMP", "B) RECORD_CONTENT", "C) RECORD_KEY", "D) RECORD_SESSION", "E) RECORD_METADATA"], "chooseN": 2, "correct": ["RECORD_CONTENT", "RECORD_METADATA"], "explanation": "- RECORD_CONTENT: Esta columna VARIANT contiene el mensaje Kafka completo que se carga en Snowflake. Es una de las columnas clave en la integración de Kafka con Snowflake.\n- RECORD_METADATA: Esta columna VARIANT almacena metadatos sobre el mensaje, como el tema desde el cual se leyó el mensaje y otros detalles de Kafka.\n- **RECORD_TIMESTAMP**: No es una columna estándar en la estructura de Snowflake cuando se usa el conector de Kafka.\n- **RECORD_KEY**: Aunque los mensajes Kafka tienen claves, esta columna no forma parte de la estructura estándar en Snowflake para el conector de Kafka.\n- **RECORD_SESSION**: No existe una columna con este nombre en el esquema de carga de datos desde Kafka a Snowflake.", "reference": "https://docs.snowflake.com/en/user-guide/kafka-connector-overview"}, {"id": 1290, "area": "Performance Concepts", "question": "When working with table MY_TABLE that contains 10 rows, which sampling query will always return exactly 5 rows?", "options": ["A) SELECT * FROM MY_TABLE SAMPLE SYSTEM (5);", "B) SELECT * FROM MY_TABLE SAMPLE BERNOULLI (5);", "C) SELECT * FROM MY_TABLE SAMPLE (5 ROWS);", "D) SELECT * FROM MY_TABLE SAMPLE SYSTEM (1) SEED (5);"], "chooseN": 1, "correct": ["SELECT * FROM MY_TABLE SAMPLE (5 ROWS);"], "explanation": "- SELECT * FROM MY_TABLE SAMPLE (5 ROWS);: Este método garantiza exactamente 5 filas en el resultado porque la cláusula SAMPLE con la opción 'ROWS' selecciona un número fijo de filas de la tabla.\n- **SELECT * FROM MY_TABLE SAMPLE SYSTEM (5);**: Utiliza un método de muestreo basado en el sistema, que selecciona un porcentaje aproximado de filas en lugar de un número exacto.\n- **SELECT * FROM MY_TABLE SAMPLE BERNOULLI (5);**: Similar al método SYSTEM, el muestreo Bernoulli selecciona aproximadamente el porcentaje especificado de filas, sin garantizar un número exacto.\n- **SELECT * FROM MY_TABLE SAMPLE SYSTEM (1) SEED (5);**: Aunque el uso de SEED hace que el muestreo sea reproducible, sigue sin garantizar exactamente 5 filas, ya que el porcentaje se aplica sobre el total de filas de manera probabilística.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/select.html#sampling-rows"}, {"id": 1291, "area": "Data Loading and Unloading", "question": "How can files in a stage be loaded after the file metadata has expired? (Choose two.)", "options": ["A) Set the LOAD_UNCERTAIN_FILES option to TRUE.", "B) Remove the files from the stage and reload them.", "C) Set the FORCE parameter to TRUE.", "D) Truncate the target table and reload the files.", "E) Use the ALTER TABLE...REFRESH command."], "chooseN": 2, "correct": ["Set the LOAD_UNCERTAIN_FILES option to TRUE.", "Set the FORCE parameter to TRUE."], "explanation": "- Set the LOAD_UNCERTAIN_FILES option to TRUE.: Esta opción permite volver a cargar archivos cuando Snowflake ya no puede determinar si los archivos han sido cargados previamente debido a la expiración de los metadatos.\n- Set the FORCE parameter to TRUE.: La opción `FORCE = TRUE` en el comando `COPY INTO` obliga a la recarga de archivos, incluso si ya se han cargado previamente.\n- **Remove the files from the stage and reload them.**: Aunque eliminar y volver a cargar los archivos en el stage puede funcionar, no es un enfoque eficiente ni necesario en la mayoría de los casos.\n- **Truncate the target table and reload the files.**: Truncar la tabla de destino no afecta la capacidad de Snowflake para determinar si los archivos en el stage ya fueron cargados.\n- **Use the ALTER TABLE...REFRESH command.**: Este comando se usa para actualizar metadatos de tablas externas y no es aplicable a la recarga de archivos en un stage.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-table#force-load"}, {"id": 1292, "area": "Snowflake Data Cloud Features & Architecture", "question": "How should a Snowflake user access a third-party SaaS service to process unstructured data?", "options": ["A) Use internal functions.", "B) Use external functions.", "C) Use process functions.", "D) Use an API gateway."], "chooseN": 1, "correct": ["Use external functions."], "explanation": "- Use external functions.: Las funciones externas en Snowflake permiten interactuar con servicios de terceros, incluidas plataformas SaaS, llamando a API externas desde dentro de Snowflake. Esto facilita el procesamiento de datos no estructurados utilizando herramientas especializadas fuera de Snowflake.\n- **Use internal functions.**: Las funciones internas son funciones nativas de Snowflake y no permiten conectarse a servicios externos.\n- **Use process functions.**: No existe un concepto de 'process functions' en Snowflake.\n- **Use an API gateway.**: Aunque un API gateway puede ser parte de la arquitectura de integración, Snowflake permite conectarse directamente a servicios externos mediante funciones externas, sin necesidad de configurar un API gateway manualmente.", "reference": "https://docs.snowflake.com/en/sql-reference/external-functions"}, {"id": 1293, "area": "Snowflake Data Cloud Features & Architecture", "question": "What statement describes Snowflake data architecture?", "options": ["A) NoSQL warehouse as a service", "B) Single-node, isolated data", "C) Multi-cluster, shared data", "D) Centralized data storage and processing"], "chooseN": 1, "correct": ["Multi-cluster, shared data"], "explanation": "- Multi-cluster, shared data: Snowflake usa una arquitectura de datos basada en almacenamiento centralizado y múltiples clústeres de cómputo que pueden escalar de manera independiente. Esto permite el procesamiento simultáneo de múltiples cargas de trabajo sin afectar el rendimiento.\n- **NoSQL warehouse as a service**: Snowflake es un almacén de datos basado en SQL, diseñado para consultas estructuradas y procesamiento analítico de datos, no un sistema NoSQL.\n- **Single-node, isolated data**: Snowflake no utiliza una arquitectura de nodo único; está diseñado para escalabilidad masiva y procesamiento distribuido en la nube.\n- **Centralized data storage and processing**: Aunque Snowflake tiene almacenamiento centralizado en la nube, el cómputo es independiente y distribuido en múltiples clústeres, lo que permite un mejor rendimiento y escalabilidad.", "reference": "https://docs.snowflake.com/en/user-guide/intro-key-concepts"}, {"id": 1294, "area": "Account Access and Security", "question": "Which command will list all of the dropped accounts in an organization that have not been deleted?", "options": ["A) SHOW MANAGED ACCOUNTS;", "B) SHOW ORGANIZATION ACCOUNTS;", "C) SHOW ORGANIZATION ACCOUNTS HISTORY;", "D) SHOW ORGANIZATION ACCOUNTS LIKE 'myaccounts%';"], "chooseN": 1, "correct": ["SHOW ORGANIZATION ACCOUNTS HISTORY;"], "explanation": "- SHOW ORGANIZATION ACCOUNTS HISTORY;: Este comando muestra todas las cuentas de la organización, incluyendo aquellas que han sido eliminadas pero aún no han sido completamente borradas de Snowflake. Es la mejor opción para obtener un historial completo de cuentas.\n- **SHOW MANAGED ACCOUNTS;**: Este comando solo lista las cuentas gestionadas dentro de un proveedor de cuentas administradas en Snowflake, no todas las cuentas de una organización.\n- **SHOW ORGANIZATION ACCOUNTS;**: Aunque este comando muestra las cuentas activas en la organización, no incluye necesariamente las cuentas eliminadas.\n- **SHOW ORGANIZATION ACCOUNTS LIKE 'myaccounts%';**: Esta opción es un filtro aplicado sobre `SHOW ORGANIZATION ACCOUNTS`, pero no garantiza la visibilidad de cuentas eliminadas.", "reference": "https://docs.snowflake.com/en/release-notes/bcr-bundles/2024_06/bcr-1712"}, {"id": 1295, "area": "Account Access and Security", "question": "What privileges are required to activate a network policy for an individual user within a Snowflake account?", "options": ["A) A user with a role that has been granted the global ATTACH POLICY privilege", "B) A user with a role that has been granted the CREATE SESSION POLICY privilege", "C) A user with a role that has been granted the CREATE NETWORK POLICY privilege", "D) A user with a role that has been granted the OWNERSHIP privilege on both the user and the network policy"], "chooseN": 1, "correct": ["A user with a role that has been granted the OWNERSHIP privilege on both the user and the network policy"], "explanation": "- A user with a role that has been granted the OWNERSHIP privilege on both the user and the network policy: Para activar una política de red para un usuario en Snowflake, la función utilizada debe tener el privilegio de 'OWNERSHIP' tanto sobre el usuario como sobre la política de red. Esto permite asociar la política de red a un usuario específico dentro de la cuenta.\n- **A user with a role that has been granted the global ATTACH POLICY privilege**: Snowflake no define un privilegio 'ATTACH POLICY' a nivel global.\n- **A user with a role that has been granted the CREATE SESSION POLICY privilege**: 'CREATE SESSION POLICY' está relacionado con la creación de políticas de sesión, pero no con la activación de políticas de red para usuarios individuales.\n- **A user with a role that has been granted the CREATE NETWORK POLICY privilege**: Este privilegio permite crear nuevas políticas de red, pero no concede automáticamente la capacidad de asignarlas a usuarios específicos.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/alter-user.html#setting-a-network-policy-for-a-user"}, {"id": 1296, "area": "Account Access and Security", "question": "How does Snowflake use Multi-Factor Authentication (MFA)?", "options": ["A) MFA is an integrated feature powered by the Duo Security service.", "B) MFA is enabled by default for any user having the ACCOUNTADMIN role.", "C) An MFA login is designed to log in to Snowflake only through Snowsight.", "D) MFA is enabled by default for each user and does not require activation."], "chooseN": 1, "correct": ["MFA is an integrated feature powered by the Duo Security service."], "explanation": "- MFA is an integrated feature powered by the Duo Security service.: Snowflake ofrece autenticación multifactor (MFA) integrada con Duo Security, lo que permite a los administradores de cuenta agregar una capa adicional de seguridad para los usuarios que acceden a la plataforma.\n- **MFA is enabled by default for any user having the ACCOUNTADMIN role.**: MFA no se habilita automáticamente para los usuarios con el rol ACCOUNTADMIN; debe activarse manualmente.\n- **An MFA login is designed to log in to Snowflake only through Snowsight.**: Aunque Snowflake admite el acceso a través de Snowsight, MFA no está restringido solo a esta interfaz; también se puede usar en otros métodos de autenticación.\n- **MFA is enabled by default for each user and does not require activation.**: MFA no está habilitado por defecto para todos los usuarios; los administradores deben activarlo manualmente para cada usuario.", "reference": "https://docs.snowflake.com/en/user-guide/security-mfa"}, {"id": 1297, "area": "Data Loading and Unloading", "question": "Which command is used to download data from Snowflake to a client machine?", "options": ["A) COPY INTO [location]", "B) PUT", "C) DROP", "D) GET"], "chooseN": 1, "correct": ["GET"], "explanation": "- GET: El comando `GET` en Snowflake se utiliza para descargar archivos desde un 'stage' de Snowflake a una máquina cliente. Este comando es parte de SnowSQL y permite recuperar datos previamente almacenados en un 'stage'.\n- **COPY INTO [location]**: Este comando se usa para exportar datos desde una tabla en Snowflake a un 'stage' o almacenamiento externo, pero no descarga directamente archivos a una máquina cliente.\n- **PUT**: `PUT` se usa para cargar archivos desde una máquina local a un 'stage' de Snowflake, pero no para descargar datos.\n- **DROP**: `DROP` es un comando utilizado para eliminar objetos en Snowflake, como tablas o vistas, y no está relacionado con la descarga de datos.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/get"}, {"id": 1298, "area": "Performance Concepts", "question": "Which function, when added to a SELECT statement, will return a randomly-selected, specified number of rows from a table?", "options": ["A) AVERAGE([num] ROWS)", "B) MEDIAN([num] ROWS)", "C) SAMPLE([num] ROWS)", "D) RANDOM([num] ROWS)"], "chooseN": 1, "correct": ["SAMPLE([num] ROWS)"], "explanation": "- **SAMPLE([num ROWS)]**: La función `SAMPLE([num] ROWS)` permite seleccionar aleatoriamente un número específico de filas de una tabla en Snowflake. Esto es útil para análisis exploratorios y pruebas con subconjuntos de datos.\n- **AVERAGE([num] ROWS)**: No es una función válida en Snowflake para obtener una muestra aleatoria de filas.\n- **MEDIAN([num] ROWS)**: `MEDIAN` es una función de agregación utilizada para calcular la mediana de un conjunto de valores, pero no devuelve filas aleatorias.\n- **RANDOM([num] ROWS)**: No existe una función `RANDOM` en Snowflake para seleccionar filas aleatorias.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/select.html#sampling-rows"}, {"id": 1299, "area": "Data Protection and Data Sharing", "question": "Which Snowflake data governance feature supports the tracking of sensitive data for compliance, discovery, protection, and resource usage?", "options": ["A) Row access policies", "B) Data classification", "C) Object dependencies", "D) Object tagging"], "chooseN": 1, "correct": ["Object tagging"], "explanation": "- Object tagging: Snowflake permite a los usuarios asignar etiquetas (`tags`) a objetos dentro del sistema para rastrear datos sensibles y cumplir con requisitos de gobernanza, auditoría y cumplimiento normativo. Esto facilita la identificación y gestión de datos críticos en la plataforma.\n- **Row access policies**: Estas políticas controlan el acceso a filas específicas dentro de una tabla, pero no proporcionan capacidades de rastreo y cumplimiento normativo a nivel de objeto.\n- **Data classification**: Aunque Snowflake ofrece capacidades para clasificar datos, la funcionalidad específica para rastreo y gobernanza está mejor soportada mediante etiquetas de objetos (`tags`).\n- **Object dependencies**: Las dependencias de objetos ayudan a entender cómo están relacionados los diferentes elementos dentro de Snowflake, pero no están diseñadas para el rastreo de datos sensibles.", "reference": "https://docs.snowflake.com/en/user-guide/object-tagging.html"}, {"id": 1300, "area": "Account Access and Security", "question": "When an ACCOUNTADMIN gives a user a custom role, what privilege or privileges is the user granted by default?", "options": ["A) All privileges that have been granted to the ACCOUNTADMIN", "B) All privileges on objects allowed by the custom role", "C) Access to the PUBLIC role", "D) Access to all the objects owned by the USERADMIN role"], "chooseN": 1, "correct": ["Access to the PUBLIC role"], "explanation": "- Access to the PUBLIC role: En Snowflake, cuando se asigna un rol personalizado a un usuario, este obtiene automáticamente acceso al rol PUBLIC, que contiene privilegios básicos.\n- *All privileges that have been granted to the ACCOUNTADMIN*: Un rol personalizado no hereda automáticamente todos los privilegios del ACCOUNTADMIN.\n- *All privileges on objects allowed by the custom role*: Un usuario solo recibe los privilegios explícitos asignados al rol.\n- *Access to all the objects owned by the USERADMIN role*: Los objetos propiedad de USERADMIN no son accesibles a menos que sean concedidos explícitamente.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-overview.html"}, {"id": 1301, "area": "Performance Concepts", "question": "Which query metric can be used to monitor the health of a large table?", "options": ["A) Clustering depth", "B) Clustering key", "C) Total partition count", "D) Total number of rows"], "chooseN": 1, "correct": ["Clustering depth"], "explanation": "- Clustering depth: Este métrico mide qué tan bien organizados están los datos en una tabla grande con respecto a su clave de clustering. Un alto valor puede indicar la necesidad de reclustering.\n- *Clustering key*: Es un concepto importante, pero no es una métrica de salud, sino una definición que afecta el clustering.\n- *Total partition count*: No es un indicador directo del rendimiento de la tabla.\n- *Total number of rows*: Aunque importante, no mide la calidad del clustering o la fragmentación.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering.html"}, {"id": 1302, "area": "Data Loading and Unloading", "question": "What function should be used to convert JSON NULL values to SQL NULL values when loading data into a Snowflake table?", "options": ["A) STRIP_OUTER_ARRAYS", "B) STRIP_NULL_VALUE", "C) FLATTEN", "D) PARSE_JSON"], "chooseN": 1, "correct": ["STRIP_NULL_VALUE"], "explanation": "- STRIP_NULL_VALUE: Esta opción se usa para eliminar valores NULL de JSON y convertirlos en SQL NULL.\n- *STRIP_OUTER_ARRAYS*: Se usa para eliminar corchetes exteriores en JSON, no para manejar valores NULL.\n- *FLATTEN*: Se usa para expandir estructuras JSON anidadas en múltiples filas.\n- *PARSE_JSON*: Convierte cadenas JSON en el tipo VARIANT, pero no gestiona NULLs de la misma manera.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/strip_null_value.html"}, {"id": 1303, "area": "Data Transformations", "question": "What is the recommended way to insert a VARIANT value into a Snowflake table?", "options": ["A) Use a SELECT statement to convert data to a VARIANT data type before inserting it.", "B) Use the TO_VARIANT function in the INSERT statement.", "C) Cast the data to a VARIANT data type within the INSERT statement.", "D) Use a subquery to convert the data to a VARIANT data type and then insert it."], "chooseN": 1, "correct": ["Use the TO_VARIANT function in the INSERT statement."], "explanation": "- Use the TO_VARIANT function in the INSERT statement.: La función TO_VARIANT es la forma recomendada de convertir datos a tipo VARIANT en Snowflake.\n- *Use a SELECT statement to convert data to a VARIANT data type before inserting it.*: No es necesario usar SELECT, ya que la conversión puede hacerse directamente en el INSERT.\n- *Cast the data to a VARIANT data type within the INSERT statement.*: Snowflake no permite casting directo a VARIANT.\n- *Use a subquery to convert the data to a VARIANT data type and then insert it.*: No es el enfoque más eficiente.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/to_variant.html"}, {"id": 1304, "area": "Account Access and Security", "question": "Which process does Snowflake follow when a stored procedure with owner's rights is called within a session?", "options": ["A) The procedure will be run with the privileges of the caller.", "B) The owner can set the caller's session variables.", "C) The owner will inherit the caller's current virtual warehouse.", "D) The owner can view the caller's session variables."], "chooseN": 1, "correct": ["The owner can set the caller's session variables."], "explanation": "- The owner can set the caller's session variables.: En Snowflake, cuando se ejecuta un procedimiento almacenado con derechos de propietario, este puede modificar variables de sesión del usuario que lo invoca.\n- *The procedure will be run with the privileges of the caller.*: No aplica en procedimientos con derechos de propietario.\n- *The owner will inherit the caller's current virtual warehouse.*: No hay herencia automática del warehouse.\n- *The owner can view the caller's session variables.*: Los valores de sesión no son visibles automáticamente para el propietario.", "reference": "https://docs.snowflake.com/en/developer-guide/stored-procedures.html"}, {"id": 1305, "area": "Data Protection and Data Sharing", "question": "Which view can be used to track the read and write operations that have been performed on a table?", "options": ["A) COPY_HISTORY", "B) ACCESS_HISTORY", "C) QUERY_HISTORY", "D) TASK_HISTORY"], "chooseN": 1, "correct": ["ACCESS_HISTORY"], "explanation": "- ACCESS_HISTORY: Esta vista proporciona detalles sobre las operaciones de acceso a los objetos en Snowflake, incluyendo lecturas y escrituras.\n- *COPY_HISTORY*: Solo rastrea operaciones COPY INTO.\n- *QUERY_HISTORY*: Muestra información sobre las consultas, pero no específicamente sobre las lecturas y escrituras en una tabla.\n- *TASK_HISTORY*: Rastrea la ejecución de tareas programadas, pero no el acceso a tablas.", "reference": "https://docs.snowflake.com/en/sql-reference/account-usage/access_history.html"}, {"id": 1306, "area": "Data Loading and Unloading", "question": "What object does Snowflake recommend using when planning to unload similarly-formatted data on a regular basis?", "options": ["A) Stream", "B) Task", "C) Storage integration", "D) Named file format"], "chooseN": 1, "correct": ["Named file format"], "explanation": "- Named file format: Permite definir un formato preconfigurado para exportaciones consistentes y eficientes.\n- *Stream*: Se usa para el rastreo de cambios en los datos, no para exportaciones regulares.\n- *Task*: Se usa para programar trabajos, pero no es un formato de archivo.\n- *Storage integration*: Facilita la conexión con almacenamiento externo, pero no gestiona formatos de archivo.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/create-file-format.html"}, {"id": 1307, "area": "Data Transformations", "question": "How should the SPLIT_TO_TABLE([string], [delimiter]) function be called?", "options": ["A) SELECT SPLIT_TO_TABLE(COL1, '.') FROM DUAL;", "B) SELECT SPLIT_TO_TABLE('a.b.c', '.');", "C) SELECT * FROM TABLE(SPLIT_TO_TABLE('a.b.c', '.'));", "D) SELECT * FROM SPLIT_TO_TABLE('a.b.c', '.');"], "chooseN": 1, "correct": ["SELECT * FROM TABLE(SPLIT_TO_TABLE('a.b.c', '.'));"], "explanation": "- SELECT * FROM TABLE(SPLIT_TO_TABLE('a.b.c', '.'));: La sintaxis correcta para convertir una cadena en una tabla en Snowflake.\n- *SELECT SPLIT_TO_TABLE(COL1, '.') FROM DUAL;*: Snowflake no usa DUAL como en Oracle.\n- *SELECT SPLIT_TO_TABLE('a.b.c', '.');*: Falta la función TABLE para generar filas.\n- *SELECT * FROM SPLIT_TO_TABLE('a.b.c', '.');*: La función debe estar dentro de TABLE para ser utilizada correctamente.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/split_to_table.html"}, {"id": 1308, "area": "Data Transformations", "question": "Which configuration of the function PARSE_JSON( [expr] ) will retrieve a valid SQL NULL value?", "options": ["A) SELECT parse_json(NULL)", "B) SELECT parse_json('null')", "C) SELECT parse_json('[ null ]')", "D) SELECT parse_json('{\"a\": null}'):a"], "chooseN": 1, "correct": ["SELECT parse_json(NULL)"], "explanation": "PARSE_JSON(NULL) returns a valid SQL NULL because the input is a SQL NULL. The docs confirm: 'If the input is NULL, the function returns NULL.' In contrast, parse_json('null') returns a VARIANT containing JSON null (not SQL NULL). parse_json('[ null ]') returns an ARRAY containing a JSON null element. parse_json('{\"a\": null}'):a returns a JSON null from the object.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/parse_json.html"}, {"id": 1309, "area": "Data Protection and Data Sharing", "question": "What is the MINIMUM Snowflake edition that supports the periodic rekeying of encrypted data?", "options": ["A) Standard", "B) Enterprise", "C) Business Critical", "D) Virtual Private Snowflake (VPS)"], "chooseN": 1, "correct": ["Enterprise"], "explanation": "The Enterprise Edition is the minimum Snowflake edition that supports periodic rekeying of encrypted data. Periodic rekeying automatically re-encrypts data on a regular basis for enhanced security, enabled via ALTER ACCOUNT SET PERIODIC_DATA_REKEYING = TRUE. Standard Edition does not include this advanced encryption feature. Business Critical adds additional security like Tri-Secret Secure and customer-managed keys.", "reference": "https://docs.snowflake.com/en/user-guide/security-encryption.html"}, {"id": 1310, "area": "Data Loading and Unloading", "question": "While preparing to unload data in Snowflake, the file format option can be specified in which commands? (Choose two.)", "options": ["A) GET", "B) CREATE STAGE", "C) PUT", "D) COPY INTO [location]", "E) CREATE PIPE"], "chooseN": 2, "correct": ["CREATE STAGE", "COPY INTO [location]"], "explanation": "- CREATE STAGE: Al crear un 'stage', se puede especificar una opción de formato de archivo para controlar cómo se cargarán o descargarán los datos.\n\n- **COPY INTO [location]**: Este comando permite descargar datos desde una tabla Snowflake a una ubicación externa, y se puede especificar un formato de archivo durante la operación.\n\n- **GET**: Este comando se utiliza para recuperar datos desde un 'stage' a una máquina local, pero no admite la especificación de formatos de archivo.\n\n- **PUT**: Este comando se utiliza para cargar datos desde una máquina local a un 'stage' de Snowflake, pero tampoco admite formatos de archivo.\n\n- **CREATE PIPE**: Aunque permite cargar datos automáticamente desde un 'stage' a una tabla, los formatos de archivo no se especifican en este comando directamente.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/create-stage.html, https://docs.snowflake.com/en/sql-reference/sql/copy-into-location.html"}, {"id": 1311, "area": "Performance Concepts", "question": "Which Query Profile operator provides information on pruning efficiency?", "options": ["A) TableScan", "B) ExternalScan", "C) InternalObject", "D) Generator"], "chooseN": 1, "correct": ["TableScan"], "explanation": "- TableScan: Este operador muestra información sobre el escaneo de tablas y la eficiencia del pruning (recorte de particiones no necesarias), que es clave para optimizar el rendimiento de las consultas en Snowflake.\n\n- **ExternalScan**: Este operador escanea datos externos, pero no proporciona información específica sobre el pruning.\n\n- **InternalObject**: No es un operador relacionado con el escaneo o el pruning de datos.\n\n- **Generator**: Se utiliza para generar datos y no tiene relación con la eficiencia de pruning.", "reference": "https://docs.snowflake.com/en/user-guide/querying-query-profile.html"}, {"id": 1312, "area": "Snowflake Data Cloud Features & Architecture", "question": "What metadata is stored for each micro-partition? (Choose two.)", "options": ["A) The number of distinct values", "B) The clustering key used in the table", "C) The average depth of values for each of the columns", "D) The range of values for each of the columns in the full table", "E) The minimum and maximum values for each of the columns"], "chooseN": 2, "correct": ["The number of distinct values", "The minimum and maximum values for each of the columns"], "explanation": "- The number of distinct values: Snowflake almacena metadatos sobre el número de valores distintos por columna en cada micro-partición para ayudar en la optimización de consultas.\n\n- The range of values for each of the columns in the full table: Snowflake registra estos valores para cada micro-partición, lo que permite un pruning eficiente al limitar el escaneo solo a micro-particiones relevantes.\n\n- **The clustering key used in the table**: Snowflake no almacena un 'clustering key' explícito como parte de los metadatos de las micro-particiones.\n\n- **The average depth of values for each of the columns**: Este tipo de metadato no es registrado por Snowflake.\n\n- **The range of values for each of the columns in the full table**: Snowflake maneja rangos a nivel de micro-partición, no de toda la tabla.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-keys.html"}, {"id": 1313, "area": "Account Access and Security", "question": "Which role has the HIGHEST precedence among roles that will serve as the owners of securable objects?", "options": ["A) USERADMIN", "B) SYSADMIN", "C) SECURITYADMIN", "D) ACCOUNTADMIN"], "chooseN": 1, "correct": ["ACCOUNTADMIN"], "explanation": "- ACCOUNTADMIN: Esta es la función de más alto nivel en Snowflake, que tiene la autoridad para administrar todos los objetos de la cuenta y controlar los privilegios asignados.\n\n- **USERADMIN**: Aunque gestiona usuarios y roles, no tiene la misma autoridad sobre los objetos que ACCOUNTADMIN.\n\n- **SYSADMIN**: Esta función puede crear y administrar objetos, pero no tiene control total sobre toda la cuenta.\n\n- **SECURITYADMIN**: Se centra en la administración de políticas de seguridad, pero no tiene la mayor precedencia para ser el propietario de objetos en comparación con ACCOUNTADMIN.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-overview.html"}, {"id": 1314, "area": "Data Protection and Data Sharing", "question": "How is data protected in Snowflake throughout its lifecycle? (Choose two.)", "options": ["A) Users are responsible for encrypting data before uploading to Snowflake.", "B) Snowflake automatically tags and masks Personal Identifiable Information (PII).", "C) Snowflake automatically encrypts data locally before copying the data to the cloud over an encrypted connection.", "D) Snowflake automatically rotates keys pairs regularly, using a hierarchical key model stored in a hardware security module.", "E) Users are responsible for uploading and configuring key pair rotation schedules and key sizes to encrypt stored data."], "chooseN": 2, "correct": ["Snowflake automatically encrypts data locally before copying the data to the cloud over an encrypted connection.", "Snowflake automatically rotates keys pairs regularly, using a hierarchical key model stored in a hardware security module."], "explanation": "- Snowflake automatically encrypts data locally before copying the data to the cloud over an encrypted connection.: Snowflake cifra automáticamente todos los datos en tránsito y en reposo, asegurando su protección durante toda su vida útil.\n\n- Snowflake automatically rotates keys pairs regularly, using a hierarchical key model stored in a hardware security module.: Snowflake emplea un modelo de claves jerárquicas con rotación regular para mejorar la seguridad de los datos.\n\n- **Users are responsible for encrypting data before uploading to Snowflake.**: Snowflake se encarga de la encriptación, no es responsabilidad del usuario.\n\n- **Snowflake automatically tags and masks Personal Identifiable Information (PII).**: Snowflake ofrece herramientas para políticas de enmascaramiento, pero no etiqueta ni enmascara datos automáticamente.\n\n- **Users are responsible for uploading and configuring key pair rotation schedules and key sizes to encrypt stored data.**: La rotación de claves y la encriptación son administradas automáticamente por Snowflake.", "reference": "https://docs.snowflake.com/en/user-guide/security-encryption.html"}, {"id": 1315, "area": "Performance Concepts", "question": "Which Snowflake virtual warehouse configuration enables horizontal scaling?", "options": ["A) Increasing the WAREHOUSE_SIZE.", "B) Increasing the MAX_CLUSTER_COUNT.", "C) Increasing the MAX_CONCURRENCY_LEVEL.", "D) Increasing the MIN_CLUSTER_COUNT."], "chooseN": 1, "correct": ["Increasing the MAX_CLUSTER_COUNT."], "explanation": "- Increasing the MAX_CLUSTER_COUNT.: Esto permite escalar horizontalmente, agregando más clústeres al almacén virtual para manejar cargas más altas de manera eficiente.\n\n- **Increasing the WAREHOUSE_SIZE.**: Cambiar el tamaño de un almacén ajusta el escalado vertical (más recursos por nodo), pero no escala horizontalmente.\n\n- **Increasing the MAX_CONCURRENCY_LEVEL.**: Ajustar este parámetro mejora la concurrencia de consultas pero no aumenta el número de clústeres.\n\n- **Increasing the MIN_CLUSTER_COUNT.**: Configurar un número mínimo de clústeres solo garantiza una cantidad mínima activa, pero no controla la escalabilidad horizontal.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-multicluster.html"}, {"id": 1316, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which Snowflake objects can execute both DDL and DML statements?", "options": ["A) External functions", "B) Stored procedures", "C) User-Defined Functions (UDFs)", "D) User-Defined Table Functions (UDTFs)"], "chooseN": 1, "correct": ["Stored procedures"], "explanation": "- Stored procedures: Las stored procedures pueden ejecutar tanto sentencias DDL (Definición de Datos) como DML (Manipulación de Datos), lo que permite automatizar tareas y manipular objetos y datos dentro de Snowflake.\n\n- **External functions**: Estas funciones solo permiten llamadas externas para la ejecución de código personalizado, pero no soportan la ejecución de DDL o DML.\n\n- **User-Defined Functions (UDFs)**: Las UDFs están diseñadas para la manipulación y transformación de datos, pero no pueden ejecutar DDL ni DML.\n\n- **User-Defined Table Functions (UDTFs)**: Similar a las UDFs, las UDTFs generan resultados tabulares pero no ejecutan DDL o DML.", "reference": "https://docs.snowflake.com/en/user-guide/stored-procedures-introduction.html"}, {"id": 1317, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which object consumes Snowflake credits for its maintenance?", "options": ["A) Materialized view", "B) View", "C) External table", "D) Table"], "chooseN": 1, "correct": ["Materialized view"], "explanation": "- Materialized view: Las materialized views consumen créditos para su mantenimiento debido a que se deben actualizar de manera periódica para reflejar cambios en la tabla base, asegurando que los datos estén precomputados y listos para consultas.\n\n- **View**: Las vistas estándar no consumen créditos porque simplemente definen una consulta lógica sobre los datos, sin almacenar datos físicos ni requerir mantenimiento adicional.\n\n- **External table**: Las tablas externas no almacenan datos en Snowflake y no requieren mantenimiento que consuma créditos.\n\n- **Table**: Las tablas estándar solo consumen créditos cuando se cargan o consultan, pero no durante el mantenimiento.", "reference": "https://docs.snowflake.com/en/user-guide/views-materialized.html"}, {"id": 1318, "area": "Account Access and Security", "question": "When connecting to Snowflake using SnowSQL, what are ways to explicitly specify the password? (Choose two.)", "options": ["A) Use public and private key pair authentication", "B) Run a web-based authorization flow", "C) Use an OAuth token", "D) Enter through an interactive prompt", "E) Specify using SNOWSQL_PWD environment variables"], "chooseN": 2, "correct": ["Enter through an interactive prompt", "Specify using SNOWSQL_PWD environment variables"], "explanation": "- Enter through an interactive prompt: SnowSQL permite a los usuarios ingresar manualmente la contraseña cuando se conectan, lo que es una forma explícita de proporcionar credenciales de acceso.\n- Specify using SNOWSQL_PWD environment variables: Se puede definir la contraseña de Snowflake en la variable de entorno `SNOWSQL_PWD`, lo que permite establecer credenciales sin necesidad de ingresarlas manualmente en cada sesión.\n- **Use public and private key pair authentication**: Este método se basa en claves en lugar de contraseñas, por lo que no es una forma explícita de especificar la contraseña.\n- **Run a web-based authorization flow**: Los flujos de autorización web, como OAuth o SSO, no requieren que el usuario ingrese explícitamente una contraseña en SnowSQL.\n- **Use an OAuth token**: OAuth permite autenticación basada en tokens en lugar de contraseñas, por lo que no es una opción válida para este caso.", "reference": "https://docs.snowflake.com/en/user-guide/snowsql-start.html#connection-options"}, {"id": 1319, "area": "Performance Concepts", "question": "A team is developing a machine learning model by training on the latest Snowflake features. The training is taking much longer than expected to complete.\n\nWhich step will accelerate the model training?", "options": ["A) Increase the size of the virtual warehouse.", "B) Add additional clusters to the virtual warehouse.", "C) Use a Snowpark-optimized virtual warehouse.", "D) Enable the query acceleration service."], "chooseN": 1, "correct": ["Use a Snowpark-optimized virtual warehouse."], "explanation": "- Use a Snowpark-optimized virtual warehouse.: Un warehouse optimizado para Snowpark está diseñado específicamente para cargas de trabajo intensivas en procesamiento, como el entrenamiento de modelos de machine learning. Estas instancias están optimizadas para maximizar el rendimiento en cálculos ML complejos, lo que acelera significativamente el proceso.\n- **Increase the size of the virtual warehouse.**: Aumentar el tamaño del warehouse puede mejorar el rendimiento de consultas SQL tradicionales, pero no es la mejor opción para cargas de trabajo de Snowpark y machine learning.\n- **Add additional clusters to the virtual warehouse.**: Agregar más clústeres es útil para manejar concurrencia en consultas, pero no mejora el rendimiento del entrenamiento de modelos de machine learning en Snowpark.\n- **Enable the query acceleration service.**: Este servicio está diseñado para mejorar la ejecución de consultas en grandes conjuntos de datos, pero no acelera específicamente el entrenamiento de modelos de machine learning.", "reference": "https://docs.snowflake.com/en/developer-guide/snowpark/optimized-warehouses"}, {"id": 1320, "area": "Data Protection and Data Sharing", "question": "Which object can be shared using Secure Data Sharing?", "options": ["A) Secure view", "B) Materialized view", "C) External function", "D) User-Defined Function (UDF)"], "chooseN": 1, "correct": ["Secure view"], "explanation": "The correct answer is: Secure view. Answer A (Secure view) is correctly marked. However, the explanation incorrectly states UDFs cannot be shared. The official doc lists 'User-defined functions (UDFs) (secure and non-secure)' as shareable objects. The explanation must be corrected. Reference: https://docs.snowflake.com/en/user-guide/data-sharing-intro", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-intro"}, {"id": 1321, "area": "Account Access and Security", "question": "How is Single Sign-On (SSO) authentication used in Snowflake?", "options": ["A) SSO is an authentication method which uses a pair of keys, a public key and a private key, to verify the identity of a user.", "B) SSO is an authentication method that uses a username and password in the API request header.", "C) SSO is an authentication method that allows a user to sign into multiple applications with a single set of credentials.", "D) SSO is an integrated Snowflake feature, powered by the Duo Security service, which is managed completely by Snowflake."], "chooseN": 1, "correct": ["SSO is an authentication method that allows a user to sign into multiple applications with a single set of credentials."], "explanation": "- SSO is an authentication method that allows a user to sign into multiple applications with a single set of credentials.: Single Sign-On (SSO) en Snowflake permite a los usuarios autenticarse una sola vez y obtener acceso a múltiples aplicaciones sin necesidad de volver a ingresar credenciales. Snowflake admite la integración con proveedores de identidad (IdPs) como Okta, Azure AD y otros.\n- **SSO is an authentication method which uses a pair of keys, a public key and a private key, to verify the identity of a user.**: Este método corresponde a la autenticación basada en claves públicas y privadas, no a SSO.\n- **SSO is an authentication method that uses a username and password in the API request header.**: Esta es una forma de autenticación básica mediante credenciales, pero no es SSO.\n- **SSO is an integrated Snowflake feature, powered by the Duo Security service, which is managed completely by Snowflake.**: Aunque Snowflake soporta MFA con Duo Security, SSO no es administrado completamente por Snowflake, sino que se integra con proveedores de identidad externos.", "reference": "https://docs.snowflake.com/en/user-guide/oauth-snowflake-sso"}, {"id": 1322, "area": "Data Transformations", "question": "Which clause is used to define a function that may return different values for different rows?", "options": ["A) IMMUTABLE", "B) RETURNS", "C) COMMENT", "D) VOLATILE"], "chooseN": 1, "correct": ["VOLATILE"], "explanation": "- VOLATILE: La cláusula `VOLATILE` se usa en Snowflake para definir funciones que pueden devolver diferentes valores para distintas filas, incluso cuando se les proporcionan los mismos parámetros de entrada. Esto es común en funciones que dependen de variables dinámicas, como el tiempo actual o datos aleatorios.\n- **IMMUTABLE**: Una función marcada como `IMMUTABLE` siempre devuelve el mismo resultado para los mismos valores de entrada, lo que significa que no cambiará su salida entre diferentes filas.\n- **RETURNS**: La cláusula `RETURNS` define el tipo de dato de salida de una función, pero no controla si la función devuelve valores diferentes para distintas filas.\n- **COMMENT**: `COMMENT` se usa para agregar descripciones a objetos en Snowflake, pero no afecta la forma en que una función devuelve valores.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/create-function#function-volatility"}, {"id": 1323, "area": "Performance Concepts", "question": "In Snowflake, where can query pruning information statistics be identified?", "options": ["A) Partitions scanned", "B) Bytes scanned", "C) Bytes spilled to remote storage", "D) Percentage scanned from cache"], "chooseN": 1, "correct": ["Partitions scanned"], "explanation": "- Partitions scanned: En Snowflake, la eficiencia del 'query pruning' se mide observando la cantidad de particiones escaneadas en comparación con el total disponible. Cuantas menos particiones sean escaneadas, más eficiente será la consulta.\n- **Bytes scanned**: Indica la cantidad de datos leídos durante la ejecución de la consulta, pero no proporciona información específica sobre la eficiencia del pruning.\n- **Bytes spilled to remote storage**: Muestra cuántos datos se han desbordado al almacenamiento remoto debido a la falta de memoria, pero no está directamente relacionado con el pruning.\n- **Percentage scanned from cache**: Indica qué porcentaje de los datos se obtuvo desde la caché, lo que mejora el rendimiento, pero no mide la efectividad del pruning.", "reference": "https://docs.snowflake.com/en/user-guide/querying-pruning"}, {"id": 1324, "area": "Data Protection and Data Sharing", "question": "How does the authorization associated with a pre-signed URL work for an unstructured file?", "options": ["A) Anyone who has the URL can access the referenced file for the life of the token.", "B) Only the user who generates the URL can use the URL to access the referenced file.", "C) Only the users who have roles with sufficient privileges on the URL can access the referenced file.", "D) The role specified in the GET REST API call must have sufficient privileges on the stage to access the referenced file using the URL."], "chooseN": 1, "correct": ["Anyone who has the URL can access the referenced file for the life of the token."], "explanation": "- Anyone who has the URL can access the referenced file for the life of the token.: En Snowflake, las URL pre-firmadas permiten el acceso a archivos no estructurados sin necesidad de autenticación adicional. Cualquier persona con la URL válida puede acceder al archivo mientras el token siga siendo válido.\n- **Only the user who generates the URL can use the URL to access the referenced file.**: La URL no está restringida solo al usuario que la generó; cualquier persona con la URL puede acceder al archivo.\n- **Only the users who have roles with sufficient privileges on the URL can access the referenced file.**: Las URL pre-firmadas no dependen de privilegios de roles en Snowflake para su uso.\n- **The role specified in the GET REST API call must have sufficient privileges on the stage to access the referenced file using the URL.**: Aunque los privilegios de roles son importantes para la generación de la URL, una vez generada, cualquier persona con la URL puede acceder al archivo.", "reference": "https://docs.snowflake.com/en/user-guide/pre-signed-urls"}, {"id": 1325, "area": "Snowflake Data Cloud Features & Architecture", "question": "What will happen if the volume of data stored in Snowflake increases over time?", "options": ["A) Snowflake will automatically increase the size of the virtual warehouse used to run queries against the storage data.", "B) The number of clusters in the active virtual warehouse being used will scale automatically to accommodate the increased storage data volume.", "C) As the stored data volume increases, the warehouse performance will decline.", "D) The warehouse performance and size will not be affected when the volume of stored data increases."], "chooseN": 1, "correct": ["The warehouse performance and size will not be affected when the volume of stored data increases."], "explanation": "- The warehouse performance and size will not be affected when the volume of stored data increases.: En Snowflake, el almacenamiento y el cómputo están desacoplados. A diferencia de sistemas tradicionales, el aumento en el volumen de datos almacenados no afecta el rendimiento del warehouse porque Snowflake usa una arquitectura de almacenamiento basada en micro-particiones y optimización de consulta.\n- **Snowflake will automatically increase the size of the virtual warehouse used to run queries against the storage data.**: Snowflake no ajusta automáticamente el tamaño del warehouse en función del almacenamiento; los usuarios deben escalar manualmente el warehouse si es necesario.\n- **The number of clusters in the active virtual warehouse being used will scale automatically to accommodate the increased storage data volume.**: El escalado automático de clústeres solo ocurre si el warehouse está configurado con auto-scaling, pero esto se aplica a la concurrencia de consultas, no al volumen de datos almacenados.\n- **As the stored data volume increases, the warehouse performance will decline.**: El rendimiento del warehouse no se ve afectado directamente por el volumen de almacenamiento, ya que Snowflake optimiza la recuperación de datos mediante 'pruning' y otras técnicas de optimización.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-overview, https://docs.snowflake.com/en/user-guide/architecture"}, {"id": 1326, "area": "Data Protection and Data Sharing", "question": "What can a reader account user do when accessing shared data? (Choose two.)", "options": ["A) Insert new data using the COPY INTO [location] command.", "B) Execute secure User-Defined Functions (UDFs).", "C) Remove records using the DELETE command.", "D) Select data from secure views.", "E) Modify records using the UPDATE and MERGE commands."], "chooseN": 2, "correct": ["Execute secure User-Defined Functions (UDFs).", "Select data from secure views."], "explanation": "- Execute secure User-Defined Functions (UDFs).: Un usuario de cuenta de lectura puede ejecutar UDFs seguros, ya que estas funciones se utilizan en operaciones de consulta sin modificar datos.\n- Select data from secure views.: Los usuarios de cuentas de lectura tienen permisos para seleccionar datos, incluyendo vistas seguras.\n- ****: Las otras opciones implican operaciones de modificación o inserción de datos, lo cual no está permitido en una cuenta de solo lectura.", "reference": "https://docs.snowflake.com/en/user-guide/sharing-consumer-read-only.html"}, {"id": 1327, "area": "Snowflake Data Cloud Features & Architecture", "question": "What is a fundamental characteristic of Snowflake micro-partitions?", "options": ["A) They can be read directly as files.", "B) They serve as an index for Snowflake tables.", "C) They are sized based on Time Travel requirements.", "D) Once established, they cannot be changed."], "chooseN": 1, "correct": ["Once established, they cannot be changed."], "explanation": "A fundamental characteristic of Snowflake micro-partitions is that they are immutable — once established, they cannot be changed. When data is modified (INSERT, UPDATE, DELETE), Snowflake creates new micro-partitions rather than modifying existing ones. Micro-partitions are 50-500 MB in size (before compression) and enable efficient DML and fine-grained pruning. They do not serve as indexes, are not sized based on Time Travel requirements, and cannot be read directly as files.", "reference": "https://docs.snowflake.com/en/user-guide/tables-micro-partitions.html"}, {"id": 1328, "area": "Performance Concepts", "question": "What happens when a multi-cluster virtual warehouse is resized?", "options": ["A) The auto-suspend feature is automatically enabled for inactive clusters.", "B) The scaling policy of the warehouse is updated.", "C) The new size applies to all clusters within that warehouse configuration.", "D) The minimum and maximum number of clusters is automatically adjusted."], "chooseN": 1, "correct": ["The new size applies to all clusters within that warehouse configuration."], "explanation": "- The new size applies to all clusters within that warehouse configuration.: Al redimensionar un multi-cluster virtual warehouse, el nuevo tamaño se aplica a todos los clústeres de la configuración.\n- ****: Las demás opciones no describen el comportamiento real documentado para esta operación.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-multi-cluster.html"}, {"id": 1329, "area": "Data Loading and Unloading", "question": "Using which copy option when unloading data allows users to include a Universally Unique Identifier (UUID) in the names of unloaded files?", "options": ["A) VALIDATION_MODE", "B) SINGLE", "C) HEADER", "D) INCLUDE_QUERY_ID"], "chooseN": 1, "correct": ["INCLUDE_QUERY_ID"], "explanation": "- INCLUDE_QUERY_ID: Esta opción permite incluir un identificador único (UUID) en los nombres de los archivos descargados.\n- ****: Las otras opciones no ofrecen la funcionalidad de agregar un UUID.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into.html"}, {"id": 1330, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which Snowflake objects use storage? (Choose two.)", "options": ["A) Regular table", "B) Regular view", "C) Cached query result", "D) Materialized view", "E) External table"], "chooseN": 2, "correct": ["Regular table", "Materialized view"], "explanation": "- Regular table: Las tablas regulares almacenan datos físicamente.\n- Materialized view: Las vistas materializadas almacenan resultados precomputados y requieren almacenamiento.\n- ****: Las vistas regulares y los resultados de consultas en caché no utilizan almacenamiento de forma permanente.", "reference": "https://docs.snowflake.com/en/user-guide/tables-views.html"}, {"id": 1331, "area": "Account Access and Security", "question": "What type of policy states that each object within Snowflake has a unique owner who can grant access to that object?", "options": ["A) Role-Based Access Control (RBAC)", "B) Discretionary Access Control (DAC)", "C) Mandatory Access Control (MAC)", "D) Rule-Based Access Control (RuBAC)"], "chooseN": 1, "correct": ["Discretionary Access Control (DAC)"], "explanation": "- Discretionary Access Control (DAC): En DAC, cada objeto tiene un propietario único que tiene la facultad de otorgar accesos según su criterio.\n- ****: RBAC, MAC y RuBAC se basan en otros principios para el control de acceso y no se centran en la propiedad individual del objeto.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control.html"}, {"id": 1332, "area": "Performance Concepts", "question": "Which Snowflake multi-cluster virtual warehouse scaling policy or mode will MINIMIZE query queuing by prioritizing the startup of additional clusters?", "options": ["A) Economy policy", "B) Standard policy", "C) Auto-scale mode", "D) Maximized mode"], "chooseN": 1, "correct": ["Standard policy"], "explanation": "The Standard scaling policy minimizes query queuing by prioritizing the startup of additional clusters. When queries start to queue, the Standard policy immediately starts new clusters. The Economy policy conserves credits by waiting before starting clusters. Maximized mode runs all allocated clusters at all times (no dynamic startup). Auto-scale mode is the operating mode that enables scaling, not a specific policy.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-multi-cluster.html"}, {"id": 1333, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which default warehouse configuration has the highest precedence whenever a new session is created by a user?", "options": ["A) Default warehouse for the user", "B) Default warehouse in the configuration file of the client utilities", "C) Default warehouse specified on a CLI or in drivers/connectors parameters", "D) Default warehouse of the role assigned to the user"], "chooseN": 1, "correct": ["Default warehouse for the user"], "explanation": "Snowflake’s documented precedence for a new session is: default warehouse for the user first, then the client utility configuration file, and finally the CLI/driver/connector parameters. Therefore, the highest-precedence default warehouse is the default warehouse for the user.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses.html"}, {"id": 1334, "area": "Account Access and Security", "question": "What type of authentication is recommended when creating a Snowflake service account that will connect to a third-party application?", "options": ["A) Username and password", "B) Key-pair authentication", "C) Multi-Factor Authentication (MFA)", "D) Single Sign-on (SSO)"], "chooseN": 1, "correct": ["Key-pair authentication"], "explanation": "- Key-pair authentication: Se recomienda la autenticación mediante par de claves para cuentas de servicio, ya que ofrece mayor seguridad y es adecuada para conexiones no interactivas.\n- ****: Las otras opciones no son recomendadas para el contexto de cuentas de servicio en Snowflake.", "reference": "https://docs.snowflake.com/en/user-guide/key-pair-auth.html"}, {"id": 1335, "area": "Performance Concepts", "question": "Which type of query would benefit from enabling the query acceleration service on the virtual warehouse?", "options": ["A) Queries with no filters or aggregation", "B) Queries that are queued in the warehouse", "C) Queries that use more resources than the typical query", "D) Queries that contain a high cardinality GROUP BY expression"], "chooseN": 1, "correct": ["Queries that contain a high cardinality GROUP BY expression"], "explanation": "- Queries that contain a high cardinality GROUP BY expression: Este tipo de consulta se beneficia de la aceleración debido al alto costo computacional al agrupar datos con alta cardinalidad.\n- ****: Las otras opciones no representan escenarios en los que la aceleración aporte mejoras significativas.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-query-acceleration.html"}, {"id": 1336, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which table function will return the output of a previously-run command?", "options": ["A) FLATTEN", "B) QUERY_HISTORY", "C) TASK_HISTORY", "D) RESULT_SCAN"], "chooseN": 1, "correct": ["RESULT_SCAN"], "explanation": "- RESULT_SCAN: Esta función devuelve el resultado de un comando previamente ejecutado, facilitando el acceso a datos ya consultados.\n- ****: Las otras funciones tienen propósitos distintos y no permiten recuperar el resultado de comandos anteriores.", "reference": "https://docs.snowflake.com/en/sql-reference/functions/result_scan.html"}, {"id": 1337, "area": "Data Loading and Unloading", "question": "How can a relational table be unloaded into a JSON file?", "options": ["A) Use the OBJECT_CONSTRUCT function in conjunction with the COPY INTO [location] command.", "B) Use the COPY INTO [location] command with the file_format set as JSON.", "C) Use the PUT command with the file_format set as JSON.", "D) Use the GET command with the file_format set as JSON."], "chooseN": 1, "correct": ["Use the OBJECT_CONSTRUCT function in conjunction with the COPY INTO [location] command."], "explanation": "- **Use the OBJECT_CONSTRUCT function in conjunction with the COPY INTO [location command.]**: Para exportar una tabla relacional a formato JSON, primero se deben convertir las filas a objetos JSON utilizando OBJECT_CONSTRUCT, y luego exportar con COPY INTO. Ejemplo: COPY INTO @stage FROM (SELECT OBJECT_CONSTRUCT(*) FROM tabla) FILE_FORMAT = (TYPE = JSON).\n- **Use the COPY INTO [location command with the file_format set as JSON.]**: COPY INTO con formato JSON requiere que los datos de origen sean de tipo VARIANT/OBJECT. Una tabla relacional con columnas regulares necesita OBJECT_CONSTRUCT para convertir las filas a JSON.\n- Use the PUT command with the file_format set as JSON.: PUT se utiliza para subir archivos a un stage, no para exportar datos de tablas.\n- Use the GET command with the file_format set as JSON.: GET se utiliza para descargar archivos desde un stage al sistema local, no para exportar datos de tablas.", "reference": "https://docs.snowflake.com/en/user-guide/data-unload-considerations#unloading-relational-tables, https://docs.snowflake.com/en/sql-reference/functions/object_construct"}, {"id": 1338, "area": "Account Access and Security", "question": "When do Snowflake object owners lose their ability to make grant decisions?", "options": ["A) When the object owner has been granted a database role.", "B) When the object owner has been granted an account role.", "C) When the object is part of a managed access schema.", "D) When the object is part of a regular schema."], "chooseN": 1, "correct": ["When the object is part of a managed access schema."], "explanation": "- When the object is part of a managed access schema.: En un esquema de acceso gestionado, la capacidad del propietario para otorgar permisos es transferida a una administración centralizada.\n- ****: Las otras opciones no afectan la habilidad del propietario para realizar decisiones de acceso de la misma manera.", "reference": "https://docs.snowflake.com/en/user-guide/security-access-control-managed.html"}, {"id": 1339, "area": "Data Loading and Unloading", "question": "Which command allows a user to unload data from a Snowflake database table into one or more files in a Snowflake or external stage?", "options": ["A) GET", "B) LIST", "C) PUT", "D) COPY INTO [location]"], "chooseN": 1, "correct": ["COPY INTO [location]"], "explanation": "- **COPY INTO [location]**: Este comando se utiliza para descargar datos de una tabla en archivos ubicados en un stage de Snowflake o externo.\n- ****: Los otros comandos no permiten la descarga de datos de esta manera.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/copy-into-location.html"}, {"id": 1340, "area": "Data Loading and Unloading", "question": "Which Snowflake feature enables loading data from cloud storage as soon as files are available in a stage?", "options": ["A) COPY_INTO [location] command", "B) Data replication", "C) Snowpipe", "D) Direct share"], "chooseN": 1, "correct": ["Snowpipe"], "explanation": "- Snowpipe: Snowpipe permite la carga automática de datos desde el almacenamiento en la nube tan pronto como los archivos están disponibles en un stage.\n- ****: Las otras opciones no ofrecen esta funcionalidad de carga automatizada.", "reference": "https://docs.snowflake.com/en/user-guide/data-load-snowpipe-intro.html"}, {"id": 1341, "area": "Data Transformations", "question": "Which JSON paths are considered to be equivalent in Snowflake? (Choose two.)", "options": ["A) src['customer']['EMAIL']", "B) src['CUSTOMER']['Email']", "C) SRC:Customer.Email", "D) src:customer.email", "E) SRC:customer.email"], "chooseN": 2, "correct": ["src:customer.email", "SRC:customer.email"], "explanation": "The correct answer is: src:customer.email, SRC:customer.email. The docs state that column names before ':' are case-insensitive (converted to uppercase), but element names AFTER ':' are CASE-SENSITIVE. So 'SRC:Customer.Email' accesses elements 'Customer'.'Email' while 'src:customer.email' accesses 'customer'.'email' -- these are DIFFERENT. D (src:customer.email) and E (SRC:customer.email) are equivalent because only the column name differs. Correct answers are D+E, not C+D. Reference: https://docs.snowflake.com/en/user-guide/querying-semistructured-data", "reference": "https://docs.snowflake.com/en/user-guide/querying-semistructured-data.html"}, {"id": 1342, "area": "Account Access and Security", "question": "Which privilege is required for a user to be able to view a resource monitor?", "options": ["A) USAGE", "B) SELECT", "C) MONITOR", "D) OPERATE"], "chooseN": 1, "correct": ["MONITOR"], "explanation": "- MONITOR: Se requiere el privilegio MONITOR para visualizar un resource monitor en Snowflake.\n- ****: Los privilegios USAGE, SELECT y OPERATE no otorgan el acceso necesario para ver los resource monitors.", "reference": "https://docs.snowflake.com/en/user-guide/resource-monitors.html"}, {"id": 1343, "area": "Data Protection and Data Sharing", "question": "What happens when a table or schema with a standard retention period is dropped?", "options": ["A) The object is immediately removed from the system.", "B) The object is instantaneously moved to Fail-safe.", "C) The object is retained but all associated data is immediately purged.", "D) The object is retained for the data retention period."], "chooseN": 1, "correct": ["The object is retained for the data retention period."], "explanation": "- The object is retained for the data retention period.: Al eliminar una tabla o esquema, el objeto se conserva durante el período de retención configurado, permitiendo la recuperación mediante Time Travel.\n- ****: Las otras opciones no reflejan el comportamiento documentado en Snowflake.", "reference": "https://docs.snowflake.com/en/user-guide/data-time-travel.html"}, {"id": 1344, "area": "Snowflake Data Cloud Features & Architecture", "question": "When cloning tables, which INFORMATION_SCHEMA view will show different columns for owned storage and referenced storage?", "options": ["A) DATABASE_STORAGE_USAGE_HISTORY", "B) STAGE_STORAGE_USAGE_HISTORY", "C) TABLE_STORAGE_METRICS", "D) STORAGE_USAGE"], "chooseN": 1, "correct": ["TABLE_STORAGE_METRICS"], "explanation": "- TABLE_STORAGE_METRICS: Esta vista ofrece métricas detalladas del almacenamiento de las tablas, diferenciando entre el almacenamiento propio y el referenciado en tablas clonadas.\n- ****: Las otras vistas no proporcionan esta distinción.", "reference": "https://docs.snowflake.com/en/sql-reference/info-schema/table_storage_metrics.html"}, {"id": 1345, "area": "Performance Concepts", "question": "Based on a review of a Query Profile, which scenarios will benefit the MOST from the use of a data clustering key? (Choose two.)", "options": ["A) A column that appears most frequently in ORDER BY operations", "B) A column that appears most frequently in WHERE operations", "C) A column that appears most frequently in GROUP BY operations", "D) A column that appears most frequently in AGGREGATE operations", "E) A column that appears most frequently in JOIN operations"], "chooseN": 2, "correct": ["A column that appears most frequently in ORDER BY operations", "A column that appears most frequently in WHERE operations"], "explanation": "Snowflake documents that clustering keys are most beneficial for selective filters (WHERE) and for queries that sort data (ORDER BY). JOIN predicates can also be considered, but only as a secondary factor when there is room for additional clustering keys.", "reference": "https://docs.snowflake.com/en/user-guide/tables-clustering-keys.html"}, {"id": 1346, "area": "Data Protection and Data Sharing", "question": "When working with dimension tables that change frequently, what is the recommended way to manage costs?", "options": ["A) Keep the Time Travel retention period for the dimension tables to 7 days or less.", "B) Make the dimension tables transient with a retention period of 0 days, and backup the table daily to a permanent table. Delete all but the latest backup.", "C) Make the dimension tables transient and back-up the data daily into a permanent table using cloning.", "D) Make the dimension tables permanent with a retention period of 7 days. Replicate the database to a secondary database once a week."], "chooseN": 1, "correct": ["Make the dimension tables transient and back-up the data daily into a permanent table using cloning."], "explanation": "- Make the dimension tables transient and back-up the data daily into a permanent table using cloning.: Utilizar tablas transitorias elimina los costos asociados a Time Travel y Fail-safe, mientras que la clonación permite respaldos eficientes sin duplicación física de datos.\n- ****: Las otras opciones no optimizan de manera efectiva los costos en escenarios de cambios frecuentes.", "reference": "https://docs.snowflake.com/en/user-guide/tables-transient.html"}, {"id": 1347, "area": "Account Access and Security", "question": "What Snowflake privilege should be granted to allow a non-ACCOUNTADMIN access to billing information?", "options": ["A) OPERATE", "B) MONITOR USAGE", "C) OWNERSHIP", "D) USAGE"], "chooseN": 1, "correct": ["MONITOR USAGE"], "explanation": "- MONITOR USAGE: Este privilegio permite a los usuarios no ACCOUNTADMIN acceder a la información de facturación sin otorgarles permisos administrativos completos.\n- ****: Los otros privilegios no proporcionan el nivel de acceso requerido para visualizar la facturación.", "reference": "https://docs.snowflake.com/en/user-guide/roles-privileges.html"}, {"id": 1348, "area": "Snowflake Data Cloud Features & Architecture", "question": "A stream can be created on which Snowflake objects to record data manipulation language (DML) changes? (Choose two.)", "options": ["A) Databases", "B) Standard tables", "C) Standard views", "D) Schemas", "E) Pipes"], "chooseN": 2, "correct": ["Standard tables", "Standard views"], "explanation": "- Standard tables: Los streams se pueden crear sobre tablas para capturar cambios DML (inserciones, actualizaciones y eliminaciones).\n- Standard views: Aunque menos común, en ciertos escenarios se permite crear streams en vistas que reflejen cambios en los datos subyacentes.\n- ****: Las bases de datos, esquemas y pipes no son objetos diseñados para registrar cambios DML mediante streams.", "reference": "https://docs.snowflake.com/en/user-guide/streams-intro.html"}, {"id": 1349, "area": "Data Loading and Unloading", "question": "When creating a file format to load JSON data into Snowflake, what command will remove brackets ([]) from the data?", "options": ["A) STRIP_NULL_VALUES = TRUE", "B) REPLACE_INVALID_CHARACTERS = TRUE", "C) TRIM_SPACE = TRUE", "D) STRIP_OUTER_ARRAY = TRUE"], "chooseN": 1, "correct": ["STRIP_OUTER_ARRAY = TRUE"], "explanation": "- STRIP_OUTER_ARRAY = TRUE: Esta opción elimina los corchetes externos de los datos JSON durante el proceso de carga, facilitando su procesamiento.\n- ****: Las otras opciones no realizan la eliminación de los corchetes externos.", "reference": "https://docs.snowflake.com/en/sql-reference/sql/create-file-format.html"}, {"id": 1350, "area": "Performance Concepts", "question": "What virtual warehouse feature or setting will reduce the performance impact when running larger-than-average queries, by offloading portions of the query processing work to shared compute resources?", "options": ["A) Using a multi-cluster virtual warehouse", "B) Using the query acceleration service", "C) Using the search optimization service", "D) Disabling auto-suspend"], "chooseN": 1, "correct": ["Using the query acceleration service"], "explanation": "The query acceleration service offloads portions of query processing to shared serverless compute resources, which speeds up the processing of larger-than-average queries while reducing demand on the warehouse's compute resources. This is exactly what the question describes. Multi-cluster warehouses handle concurrency (multiple users), not individual query optimization. The search optimization service improves point lookup queries, not general query offloading.", "reference": "https://docs.snowflake.com/en/user-guide/warehouses-query-acceleration.html"}, {"id": 1351, "area": "Snowflake Data Cloud Features & Architecture", "question": "Which schema-level objects allow the user to periodically perform an action under specific conditions, based on data within Snowflake?", "options": ["A) Alerts", "B) External tables", "C) Secure views", "D) Materialized views"], "chooseN": 1, "correct": ["Alerts"], "explanation": "- Alerts: Las alertas en Snowflake permiten definir condiciones y ejecutar acciones periódicas cuando se cumplen ciertos criterios en los datos.\n- ****: Los otros objetos están orientados a la visualización o almacenamiento de datos, no a la ejecución de acciones basadas en condiciones.", "reference": "https://docs.snowflake.com/en/user-guide/alerts.html"}, {"id": 1352, "area": "Account Access and Security", "question": "Which privilege must be granted to show data categories in a Data Exchange?", "options": ["A) MONITOR PRIVILEGE", "B) USAGE PRIVILEGE", "C) OWNERSHIP PRIVILEGE", "D) IMPORTED PRIVILEGES"], "chooseN": 1, "correct": ["USAGE PRIVILEGE"], "explanation": "- USAGE PRIVILEGE: Este privilegio permite a los usuarios visualizar las categorías de datos dentro de un Data Exchange.\n- ****: Los otros privilegios no confieren el acceso específico requerido para mostrar dicha información.", "reference": "https://docs.snowflake.com/en/user-guide/data-sharing-exchange.html"}];

async function seed() {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    const schema = fs.readFileSync(__dirname + '/../db/schema.sql', 'utf8');
    await client.query(schema);
    let inserted = 0;
    for (const q of questions) {
      await client.query(
        `INSERT INTO questions (id, area, question, options, choose_n, correct, explanation, reference)
         VALUES ($1, $2, $3, $4, $5, $6, $7, $8)
         ON CONFLICT (id) DO UPDATE SET
           area = EXCLUDED.area,
           question = EXCLUDED.question,
           options = EXCLUDED.options,
           choose_n = EXCLUDED.choose_n,
           correct = EXCLUDED.correct,
           explanation = EXCLUDED.explanation,
           reference = EXCLUDED.reference`,
        [q.id, q.area, q.question, JSON.stringify(q.options), q.chooseN,
         JSON.stringify(q.correct), q.explanation, q.reference]
      );
      inserted++;
    }
    await client.query('COMMIT');
    console.log(`Seeded ${inserted} questions OK.`);
  } catch (err) {
    await client.query('ROLLBACK');
    console.error('Seed failed:', err);
    process.exit(1);
  } finally {
    client.release();
    pool.end();
  }
}

seed();
